window.HADITH_CACHE["muslim_9"] = {"4501":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ زَكَرِيَّاءَ عَنْ الشَّعْبِيِّ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ وَالْمَوْتُ قَبْلَ لِقَاءِ اللَّهِحَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ حَدَّثَنِي شُرَيْحُ بْنُ هَانِئٍ أَنَّ عَائِشَةَ أَخْبَرَتْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Ali bin Mushir] dari [Zakariya] dari [Asy Sya'bi] dari [Syuraih bin Hani'] dari ['Aisyah] dia berkata; 'Rasulullah shallaallahu'alaihi wa sallam bersabda: \"Barang siapa yang mencintai untuk bertemu dengan Allah maka Allah senang bertemu dengannya, dan barang siapa yang benci untuk bertemu dengan Allah maka Allah pun benci bertemu dengannya. Dan kematian itu sebelum bertemu dengan Allah.\" Telah menceritakan kepada kami tentang hadits tersebut [Ishaq bin Ibrahim] telah mengabarkan kepada kami ['Isa bin Yunus] telah menceritakan kepada kami [Zakaria] dari ['Amir] telah menceritakan kepadaku [Syuraih bin Hani'] bahwasanya ['Aisyah] mengabarkan kepadanya bahwasanya Rasulullah shallallahu 'alaihi wasallam berkata dengan perkataan seperti itu."},"4502":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ أَخْبَرَنَا عَبْثَرٌ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُقَالَ فَأَتَيْتُ عَائِشَةَ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ سَمِعْتُ أَبَا هُرَيْرَةَ يَذْكُرُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا إِنْ كَانَ كَذَلِكَ فَقَدْ هَلَكْنَا فَقَالَتْ إِنَّ الْهَالِكَ مَنْ هَلَكَ بِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا ذَاكَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ وَلَيْسَ مِنَّا أَحَدٌ إِلَّا وَهُوَ يَكْرَهُ الْمَوْتَ فَقَالَتْ قَدْ قَالَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ بِالَّذِي تَذْهَبُ إِلَيْهِ وَلَكِنْ إِذَا شَخَصَ الْبَصَرُ وَحَشْرَجَ الصَّدْرُ وَاقْشَعَرَّ الْجِلْدُ وَتَشَنَّجَتْ الْأَصَابِعُ فَعِنْدَ ذَلِكَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنِي جَرِيرٌ عَنْ مُطَرِّفٍ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ عَبْثَرٍ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amr Al Asy'atsi] telah mengabarkan kepada kami ['Abtsar] dari [Mutharrif] dari ['Amir] dari [Syuraih bin Hani'] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa senang berjumpa dengan Allah, maka Allah pun senang berjumpa dengannya; dan barangsiapa yang benci berjumpa dengan Allah, maka Allah pun benci berjumpa dengannya.\" Syuraih berkata; Aku kemudian menemui Aisyah, lalu aku bertanya; \"Wahai Ummul Mukminin! Aku mendengar Abu Hurairah menyebutkan suatu hadits dari Rasulullah shallallahu 'alaihi wasallam. Jika demikian sungguh kita akan binasa!\" Aisyah berkata; sesungguhnya orang yang binasa itu adalah orang yang dikatakan binasa oleh Rasulullah. Lalu Aisyah bertanya, \"Apa yang dikatakanya itu?\" Syuraikh menjawab; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Siapa senang berjumpa dengan Allah, Allah pun senang berjumpa dengannya dan barangsiapa benci berjumpa dengan Allah, Allah pun benci berjumpa dengannya'. Tetapi tidak ada seorangpun di antara kita kecuali benci dengan kamatian!\" Ia (Aisyah) berkata; \"Sungguh hal itu telah disabdakan oleh Rasulullah shallallahu 'alaihi wasallam, dan tidak seperti yang kamu pahami, tetapi -yang dimaksud adalah- tatkala pandangan terangkat, dada berdetak dan dada menggigil, saat itulah orang yang senang berjumpa dengan Allah, maka Allah pun senang berjumpa dengannya; dan barangsiapa benci berjumpa dengan Allah, maka Allah pun benci berjumpa dengannya?!\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepadaku [Jarir] dari [Mutharrif] dengan sanad ini seperti hadits 'Abtsar."},"4503":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو عَامِرٍ الْأَشْعَرِيُّ وَأَبُو كُرَيْبٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu 'Amir Al Asy'ari] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Siapa senang berjumpa dengan Allah, Allah pun senang berjumpa dengannya dan barangsiapa benci berjumpa dengan Allah, Allah pun benci berjumpa dengannya'."},"4504":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَقُولُ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ إِذَا دَعَانِي","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala]; telah menceritakan kepada kami [Waki'] dari [Ja'far bin Burqan] dari [Yazid bin Al Asham] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman: 'Aku sesuai dengan prasangka hamba-Ku terhadap-ku, Aku akan bersamanya jika ia berdoa kepada-Ku.\""},"4505":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارِ بْنِ عُثْمَانَ الْعَبْدِيُّ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ وَابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ وَهُوَ التَّيْمِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ إِذَا تَقَرَّبَ عَبْدِي مِنِّي شِبْرًا تَقَرَّبْتُ مِنْهُ ذِرَاعًا وَإِذَا تَقَرَّبَ مِنِّي ذِرَاعًا تَقَرَّبْتُ مِنْهُ بَاعًا أَوْ بُوعًا وَإِذَا أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةًحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الْقَيْسِيُّ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ إِذَا أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar bin 'Utsman Al 'Abdi] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu 'Adi] dari [Sulaiman At Taimi] dari [Anas bin Malik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Allah Subhanahu wa Ta'ala telah berfirman: 'Aku bergantung pada sangkaan hamba-Ku kepada-Ku dan Aku akan bersama hamba-Ku ketika ia mengingat-Ku. Apabila ia mengingat-Ku dalam dirinya, maka Aku akan mengingatnya dalam diri-Ku. Apabila ia mengingat-Ku di tengah orang banyak, maka Aku juga akan mengingatnya di tengah orang banyak yang lebih baik daripada mereka. Apabila ia mendekat kepada-Ku sejengkal, maka Aku akan mendekat kepadanya sehasta. Apabila ia mendekat kepada-Ku sehasta, maka Aku akan mendekat kepadanya sedepa. Apabila ia datang kepada-Ku dengan berjalan, maka Aku akan datang kepadanya dengan berlari.' Telah menceritakan kepada kami [Muhammad bin 'Abdul A'la Al Qaisi] telah menceritakan kepada kami [Mu'tamir] dari [bapaknya] dengan sanad ini dan tidak menyebutkan kalimat; 'Apabila ia datang kepada-Ku dengan berjalan, maka Aku akan datang kepadanya dengan berlari.'"},"4506":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَنَا عِنْدَ ظَنِّ عَبْدِي وَأَنَا مَعَهُ حِينَ يَذْكُرُنِي فَإِنْ ذَكَرَنِي فِي نَفْسِهِ ذَكَرْتُهُ فِي نَفْسِي وَإِنْ ذَكَرَنِي فِي مَلَإٍ ذَكَرْتُهُ فِي مَلَإٍ خَيْرٍ مِنْهُ وَإِنْ اقْتَرَبَ إِلَيَّ شِبْرًا تَقَرَّبْتُ إِلَيْهِ ذِرَاعًا وَإِنْ اقْتَرَبَ إِلَيَّ ذِرَاعًا اقْتَرَبْتُ إِلَيْهِ بَاعًا وَإِنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] -dan lafadh ini milik Abu Kuraib- mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman; 'Bagi hamba-Ku adalah sebagaimana perasangkanya kepada-Ku, dan Aku akan bersamanya selama ia berdoa kepada-Ku. Jika ia mengingat-Ku dalam dirinya maka Aku akan mengingatnya dalam diri-Ku, jika ia mengingat-Ku dalam sekumpulan orang maka Aku akan mengingatnya dalam sekumpulan yang lebih baik dan lebih bagus darinya. Jika ia mendekat kepada-Ku satu jengkal maka Aku akan mendekat kepada-Nya satu hasta, jika ia mendekat kepada-Ku satu hasta maka Aku akan mendekat kepadanya satu depa, dan jika ia mendatangi-Ku dengan berjalan maka Aku akan mendatanginya dengan berlari.\""},"4507":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا وَأَزِيدُ وَمَنْ جَاءَ بِالسَّيِّئَةِ فَجَزَاؤُهُ سَيِّئَةٌ مِثْلُهَا أَوْ أَغْفِرُ وَمَنْ تَقَرَّبَ مِنِّي شِبْرًا تَقَرَّبْتُ مِنْهُ ذِرَاعًا وَمَنْ تَقَرَّبَ مِنِّي ذِرَاعًا تَقَرَّبْتُ مِنْهُ بَاعًا وَمَنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً وَمَنْ لَقِيَنِي بِقُرَابِ الْأَرْضِ خَطِيئَةً لَا يُشْرِكُ بِي شَيْئًا لَقِيتُهُ بِمِثْلِهَا مَغْفِرَةًقَالَ إِبْرَاهِيمُ حَدَّثَنَا الْحَسَنُ بْنُ بِشْرٍ حَدَّثَنَا وَكِيعٌ بِهَذَا الْحَدِيثِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ فَلَهُ عَشْرُ أَمْثَالِهَا أَوْ أَزِيدُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Allah Azza wa Jalla berfirman: \"Barang siapa berbuat kebaikan, maka baginya sepuluh kebaikan yang semisalnya dan terkadang Aku tambahkan lagi. Dan Barangsiapa yang berbuat keburukan, maka balasannya adalah keburukan yang serupa atau Aku mengampuninya. Barangsiapa mendekat kepada-Ku satu jengkal maka Aku akan mendekat kepada-Nya satu hasta, jika ia mendekat kepada-Ku satu hasta maka Aku akan mendekat kepadanya satu depa, dan jika ia mendatangi-Ku dengan berjalan maka Aku akan mendatanginya dengan berlari. Dan barangsiapa yang bertemu dengan-Ku dengan membawa kesalahan sebesar isi bumi tanpa menyekutukan-Ku dengan yang lainnya, maka Aku akan menemuinya dengan ampunan sebesar itu pula.\" Ibrahim berkata; telah menceritakan kepada kami Al Hasan bin Bisyr telah menceritakan kepada kami Waki' dengan hadits ini. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dengan sanad ini dengan Hadits yang serupa. Hanya saja dia berkata dengan lafazh; 'maka baginya sepuluh kebaikan yang semisalnya bahkan lebih.'"},"4508":{"ar":"حَدَّثَنَا أَبُو الْخَطَّابِ زِيَادُ بْنُ يَحْيَى الْحَسَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ عَادَ رَجُلًا مِنْ الْمُسْلِمِينَ قَدْ خَفَتَ فَصَارَ مِثْلَ الْفَرْخِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كُنْتَ تَدْعُو بِشَيْءٍ أَوْ تَسْأَلُهُ إِيَّاهُ قَالَ نَعَمْ كُنْتُ أَقُولُ اللَّهُمَّ مَا كُنْتَ مُعَاقِبِي بِهِ فِي الْآخِرَةِ فَعَجِّلْهُ لِي فِي الدُّنْيَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ لَا تُطِيقُهُ أَوْ لَا تَسْتَطِيعُهُ أَفَلَا قُلْتَ اللَّهُمَّ{ آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }قَالَ فَدَعَا اللَّهَ لَهُ فَشَفَاهُحَدَّثَنَاه عَاصِمُ بْنُ النَّضْرِ التَّيْمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ{ وَقِنَا عَذَابَ النَّارِ }وَلَمْ يَذْكُرْ الزِّيَادَةَ و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى رَجُلٍ مِنْ أَصْحَابِهِ يَعُودُهُ وَقَدْ صَارَ كَالْفَرْخِ بِمَعْنَى حَدِيثِ حُمَيْدٍ غَيْرَ أَنَّهُ قَالَ لَا طَاقَةَ لَكَ بِعَذَابِ اللَّهِ وَلَمْ يَذْكُرْ فَدَعَا اللَّهَ لَهُ فَشَفَاهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا سَالِمُ بْنُ نُوحٍ الْعَطَّارُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abul Khaththab Ziyad bin Yahya Al Hassani] telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Humaid] dari [Tsabit] dari [Anas] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah menjenguk seorang laki-laki muslim yang sedang sakit parah sampai kurus dan lemah seperti seekor burung kecil. Kemudian Rasulullah bertanya kepadanya: \"Apakah kamu pernah berdoa ataupun memohon sesuatu kepada Allah?\" Sahabat tersebut menjawab; 'Ya, saya pernah berdoa; 'Ya Allah ya Tuhanku, apa yang akan Engkau siksakan kepadaku di akhirat kelak, maka segerakanlah siksa tersebut di dunia ini! ' Mendengar pengakuannya itu, Rasulullah pun berkata: 'Subhanallah, mengapa kamu berdoa seperti itu. Tentu kamu tidak akan tahan. Mengapa kamu tidak berdoa: 'Ya Allah, berilah kami kebaikan di dunia dan kebaikan di akhirat serta peliharalah kami dari siksa neraka.' Anas berkata; 'Lalu Rasulullah berdoa kepada Allah untuk sahabat tersebut dan akhirnya Allah pun menyembuhkannya.' Telah menceritakannya kepada kami ['Ashim bin An Nadhr At Taimi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Humaid] dengan sanad ini sampai perkataannya 'dan selamatkan kami dari api neraka' dan tidak menyebutkan tambahannya. Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah menjenguk seseorang dari para sahabatnya yang sakit, hingga orang itu seakan-akan seperti burung kecil. -sebagaimana yang semakna dengan Hadits Humaid.- hanya ada sedikit tambahan, beliau bersabda: 'kamu tidak akan mampu menghadapi adzab Allah, ' -tanpa menyebutkan kalimat; 'lalu beliau mendo'akannya hingga dia sembuh kembali.' Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Salim bin Nuh Al 'Aththar] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini."},"4509":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلَّهِ تَبَارَكَ وَتَعَالَى مَلَائِكَةً سَيَّارَةً فُضُلًا يَتَتَبَّعُونَ مَجَالِسَ الذِّكْرِ فَإِذَا وَجَدُوا مَجْلِسًا فِيهِ ذِكْرٌ قَعَدُوا مَعَهُمْ وَحَفَّ بَعْضُهُمْ بَعْضًا بِأَجْنِحَتِهِمْ حَتَّى يَمْلَئُوا مَا بَيْنَهُمْ وَبَيْنَ السَّمَاءِ الدُّنْيَا فَإِذَا تَفَرَّقُوا عَرَجُوا وَصَعِدُوا إِلَى السَّمَاءِ قَالَ فَيَسْأَلُهُمْ اللَّهُ عَزَّ وَجَلَّ وَهُوَ أَعْلَمُ بِهِمْ مِنْ أَيْنَ جِئْتُمْ فَيَقُولُونَ جِئْنَا مِنْ عِنْدِ عِبَادٍ لَكَ فِي الْأَرْضِ يُسَبِّحُونَكَ وَيُكَبِّرُونَكَ وَيُهَلِّلُونَكَ وَيَحْمَدُونَكَ وَيَسْأَلُونَكَ قَالَ وَمَاذَا يَسْأَلُونِي قَالُوا يَسْأَلُونَكَ جَنَّتَكَ قَالَ وَهَلْ رَأَوْا جَنَّتِي قَالُوا لَا أَيْ رَبِّ قَالَ فَكَيْفَ لَوْ رَأَوْا جَنَّتِي قَالُوا وَيَسْتَجِيرُونَكَ قَالَ وَمِمَّ يَسْتَجِيرُونَنِي قَالُوا مِنْ نَارِكَ يَا رَبِّ قَالَ وَهَلْ رَأَوْا نَارِي قَالُوا لَا قَالَ فَكَيْفَ لَوْ رَأَوْا نَارِي قَالُوا وَيَسْتَغْفِرُونَكَ قَالَ فَيَقُولُ قَدْ غَفَرْتُ لَهُمْ فَأَعْطَيْتُهُمْ مَا سَأَلُوا وَأَجَرْتُهُمْ مِمَّا اسْتَجَارُوا قَالَ فَيَقُولُونَ رَبِّ فِيهِمْ فُلَانٌ عَبْدٌ خَطَّاءٌ إِنَّمَا مَرَّ فَجَلَسَ مَعَهُمْ قَالَ فَيَقُولُ وَلَهُ غَفَرْتُ هُمْ الْقَوْمُ لَا يَشْقَى بِهِمْ جَلِيسُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Maimun] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Suhail] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Sesungguhnya Allah Yang Maha Suci dan Maha Tinggi mempunyai beberapa malaikat yang terus berkeliling mencari majelis dzikir. Apabila mereka telah menemukan majelis dzikir tersebut, maka mereka terus duduk di situ dengan menyelimutkan sayap sesama mereka hingga memenuhi ruang antara mereka dan langit yang paling bawah. Apabila majelis dzikir itu telah usai, maka mereka juga berpisah dan naik ke langit.' Kemudian Rasulullah meneruskan sabdanya: 'Selanjutnya mereka ditanya Allah Subhanahu wa Ta'ala, Dzat Yang sebenarnya Maha Tahu tentang mereka: 'Kalian datang dari mana? ' Mereka menjawab; 'Kami datang dari sisi hamba-hamba-Mu di bumi yang selalu bertasbih, bertakbir, bertahmid, dan memohon kepada-Mu ya Allah.' Lalu Allah Subhanahu wa Ta'ala bertanya: 'Apa yang mereka minta? ' Para malaikat menjawab; 'Mereka memohon surga-Mu ya Allah.' Allah Subhanahu wa Ta'ala bertanya lagi: 'Apakah mereka pernah melihat surga-Ku? ' Para malaikat menjawab; 'Belum. Mereka belum pernah melihatnya ya Allah.' Allah Subhanahu wa Ta'ala berkata: 'Bagaimana seandainya mereka pernah melihat surga-Ku? ' Para malaikat berkata; 'Mereka juga memohon perlindungan kepada-Mu ya Allah.' Allah Subhanahu wa Ta'ala balik bertanya: 'Dari apa mereka meminta perlindungan kepada-Ku? ' Para malaikat menjawab; 'Mereka meminta perlindungan kepada-Mu dari neraka-Mu ya Allah.' Allah Subhanahu wa Ta'ala bertanya: 'Apakah mereka pernah melihat neraka-Ku? ' Para malaikat menjawab; 'Belum. Mereka belum pernah melihat neraka-Mu ya Allah.' Allah Subhanahu wa Ta'ala berkata: 'Bagaimana seandainya mereka pernah melihat neraka-Ku? ' Para malaikat berkata; 'Ya Allah, sepertinya mereka juga memohon ampun (beristighfar) kepada-Mu? ' Maka Allah Subhanahu wa Ta'ala menjawab: 'Ketahuilah hai para malaikat-Ku, sesungguhnya Aku telah mengampuni mereka, memberikan apa yang mereka minta, dan melindungi mereka dari neraka.' Para malaikat berkata; 'Ya Allah, di dalam majelis mereka itu ada seorang hamba yang berdosa dan kebetulan hanya lewat lalu duduk bersama mereka.' Maka Allah menjawab: 'Ketahuilah bahwa sesungguhnya Aku akan mengampuni orang tersebut. Sesungguhnya mereka itu adalah suatu kaum yang teman duduknya tak bakalan celaka karena mereka.'"},"4510":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ وَهُوَ ابْنُ صُهَيْبٍ قَالَ سَأَلَ قَتَادَةُ أَنَسًاأَيُّ دَعْوَةٍ كَانَ يَدْعُو بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ قَالَ كَانَ أَكْثَرُ دَعْوَةٍ يَدْعُو بِهَا يَقُولُ اللَّهُمَّ{ آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }قَالَ وَكَانَ أَنَسٌ إِذَا أَرَادَ أَنْ يَدْعُوَ بِدَعْوَةٍ دَعَا بِهَا فَإِذَا أَرَادَ أَنْ يَدْعُوَ بِدُعَاءٍ دَعَا بِهَا فِيهِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abdul Aziz] yaitu lbnu Shuhaib dia berkata; \"Pada suatu ketika, Qatadah pernah bertanya kepada Anas; 'Hai Anas, doa apa yang sering diucapkan Rasulullah? ' [Anas] menjawab; 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam sering membaca doa yang berbunyi: 'Ya Allah, berilah kami kebaikan di dunia dan kebaikan di akhirat, serta peliharalah kami dari siksa api neraka.' Perawi hadits ini berkata; 'Ketika Anas hendak berdoa, maka ia senantiasa membaca doa tersebut. Dan ketika ia hendak membaca doa yang lain, maka ia selalu menyertakan doa tersebut.'"},"4511":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ{ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz], [bapakku] telah menceritakan kepada kami; telah menceritakan kepada kami [Syu'bah] dari [Tsabit] dari [Anas] dia berkata; Rasulullah Shallallahu'alaihi wasallam banyak berdo'a dengan, \"Ya Allah, Rabb kami, berikanlah kebaikan di dunia dan di akhirat, dan jagalah kami dari siksa neraka\"."},"4512":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ فِي يَوْمٍ مِائَةَ مَرَّةٍ كَانَتْ لَهُ عَدْلَ عَشْرِ رِقَابٍ وَكُتِبَتْ لَهُ مِائَةُ حَسَنَةٍ وَمُحِيَتْ عَنْهُ مِائَةُ سَيِّئَةٍ وَكَانَتْ لَهُ حِرْزًا مِنْ الشَّيْطَانِ يَوْمَهُ ذَلِكَ حَتَّى يُمْسِيَ وَلَمْ يَأْتِ أَحَدٌ أَفْضَلَ مِمَّا جَاءَ بِهِ إِلَّا أَحَدٌ عَمِلَ أَكْثَرَ مِنْ ذَلِكَ وَمَنْ قَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ فِي يَوْمٍ مِائَةَ مَرَّةٍ حُطَّتْ خَطَايَاهُ وَلَوْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku membacakan kepada [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Barangsiapa yang mengucapkan Laa ilaaha ilIallaahu wahdah, Iaa syariikalahu lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadiir' (Tiada tuhan selain Allah, Dialah Tuhan Yang Maha Esa. Tidak ada sekutu bagi-Nya, Dialah yang memiliki alam semesta dan segala puji hanya bagi-Nya. Allah adalah Maha Kuasa atas segaIa sesuatu) dalam sehari seratus kali, maka orang tersebut akan mendapat pahala sama seperti orang yang memerdekakan seratus orang budak dicatat seratus kebaikan untuknya, dihapus seratus keburukan untuknya. Pada hari itu ia akan terjaga dari godaan syetan sampai sore hari dan tidak ada orang lain yang melebihi pahalanya, kecuali orang yang membaca lebih banyak dan itu. Barang siapa membaca Subhaanallaah wa bi hamdihi (Maha Suci Allah dan segala puji bagi-Nya) seratus kali dalam sehari, maka dosanya akan dihapus, meskipun sebanyak buih lautan.\""},"4513":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ الْأُمَوِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ عَنْ سُهَيْلٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يُصْبِحُ وَحِينَ يُمْسِي سُبْحَانَ اللَّهِ وَبِحَمْدِهِ مِائَةَ مَرَّةٍ لَمْ يَأْتِ أَحَدٌ يَوْمَ الْقِيَامَةِ بِأَفْضَلَ مِمَّا جَاءَ بِهِ إِلَّا أَحَدٌ قَالَ مِثْلَ مَا قَالَ أَوْ زَادَ عَلَيْهِ","id":"Telah menceritakan kepadaku [Muhammad bin 'Abdul Malik Al Umawi] telah menceritakan kepada kami ['Abdul 'Aziz bin Al Mukhtar] dari [Suhail] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barang siapa, ketika pagi dan sore, membaca doa; Maha Suci Allah dan segala puji bagi-Nya sebanyak seratus kali, maka pada hari kiamat tidak ada orang lain yang melebihi pahalanya kecuali orang yang juga pernah mengucapkan bacaan seperti itu atau lebih dan itu.'\""},"4514":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ أَبُو أَيُّوبَ الْغَيْلَانِيُّ حَدَّثَنَا أَبُو عَامِرٍ يَعْنِي الْعَقَدِيَّ حَدَّثَنَا عُمَرُ وَهُوَ ابْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ عَشْرَ مِرَارٍ كَانَ كَمَنْ أَعْتَقَ أَرْبَعَةَ أَنْفُسٍ مِنْ وَلَدِ إِسْمَعِيلَو قَالَ سُلَيْمَانُ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عُمَرُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ رَبِيعِ بْنِ خُثَيْمٍ بِمِثْلِ ذَلِكَ قَالَ فَقُلْتُ لِلرَّبِيعِ مِمَّنْ سَمِعْتَهُ قَالَ مِنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ فَأَتَيْتُ عَمْرَو بْنَ مَيْمُونٍ فَقُلْتُ مِمَّنْ سَمِعْتُهُ قَالَ مِنْ ابْنِ أَبِي لَيْلَى قَالَ فَأَتَيْتُ ابْنَ أَبِي لَيْلَى فَقُلْتُ مِمَّنْ سَمِعْتُهُ قَالَ مِنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ يُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin 'Ubaidullah Abu Ayyub Al Ghailani] telah menceritakan kepada kami [Abu 'Amir Al 'Aqdi] telah menceritakan kepada kami ['Umar bin Abu Zaidah] dari [Abu Ishaq] dari ['Amru bin Maimun] dia berkata; \"Barangsiapa yang mengucapkan Laa ilaaha ilIallaahu wahdah, Iaa syariikalahu lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadiir' (Tiada tuhan selain Allah, Dialah Tuhan Yang Maha Esa. Tidak ada sekutu bagi-Nya, Dialah yang memiliki alam semesta dan segala puji hanya bagi-Nya. Allah adalah Maha Kuasa atas segaIa sesuatu) sebanyak sepuluh kali, maka baginya pahala sebagaimana memerdekakan empat orang dari keturunan ismail. Dan berkata [Sulaiman] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami ['Umar] telah menceritakan kepada kami ['Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari [Rabi' bin Khutsaim] dengan hadits tersebut, dia berkata; maka aku bertanya kepada Ar Rabi', 'dari mana kamu mendengarnya? ' Dia menjawab; 'Dari ['Amru bin Maimun], perawi berkata; maka aku mendatangi 'Amru bin Maimun, dan bertanya; 'dari mana engkau mendengar hadits itu? ' dia menjawab; dari [Ibnu Abu Laila], perawi berkata; maka aku menemui Ibnu Abu Laila dan aku tanyakan kepadanya; 'dari mana engkau mendengar hadits itu? ' dia menjawab dari [Abu Ayyub Al Anshari] ia menceritakannya dari Rasulullah shallallahu 'alaihi wasallam."},"4515":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ وَمُحَمَّدُ بْنُ طَرِيفٍ الْبَجَلِيُّ قَالُوا حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَتَانِ خَفِيفَتَانِ عَلَى اللِّسَانِ ثَقِيلَتَانِ فِي الْمِيزَانِ حَبِيبَتَانِ إِلَى الرَّحْمَنِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ سُبْحَانَ اللَّهِ الْعَظِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] dan [Zuhair bin Harb] dan [Abu Kuraib] dan [Muhammad bin Tharif Al Bajali] mereka berkata; telah menceritakan kepada kami [Ibnu Fudhail] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Dua kalimat yang ringan diucapkan tetapi berat timbangannya dan disenangi oleh Allah Subhanahu wa Ta'ala Yang Maha Pengasih yaitu, Subhanallah wa bihamdihi subhaanallaahil azhim (Maha Suci Allah dengan segala pujian-Nya dan Maha Suci Allah Yang Maha Agung).\""},"4516":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ أَقُولَ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] mereka berdua berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Sesungguhnya membaca doa, Maha Suci Allah, segala puji bagi Allah, tiada Tuhan selain Allah, dan Allah Maha Besar adalah lebih aku cintai daripada segala sesuatu yang terkena oleh sinar matahari.'\""},"4517":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَابْنُ نُمَيْرٍ عَنْ مُوسَى الْجُهَنِيِّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا مُوسَى الْجُهَنِيُّ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَلِّمْنِي كَلَامًا أَقُولُهُ قَالَ قُلْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ اللَّهُ أَكْبَرُ كَبِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا سُبْحَانَ اللَّهِ رَبِّ الْعَالَمِينَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ الْعَزِيزِ الْحَكِيمِ قَالَ فَهَؤُلَاءِ لِرَبِّي فَمَا لِي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاهْدِنِي وَارْزُقْنِيقَالَ مُوسَى أَمَّا عَافِنِي فَأَنَا أَتَوَهَّمُ وَمَا أَدْرِي وَلَمْ يَذْكُرْ ابْنُ أَبِي شَيْبَةَ فِي حَدِيثِهِ قَوْلَ مُوسَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Ali bin Mushir] dan [Ibnu Numair] dari [Musa Al Juhani] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] -dan lafadh ini miliknya- Telah menceritakan kepada kami [Bapakku] telah menceritakan kepada kami [Musa Al Juhani] dari [Mush'ab bin Sa'd] dari [Bapaknya] dia berkata; \"Pada suatu hari seorang Arab badui datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; 'Ya Rasulullah, ajarkanlah kepada saya suatu bacaan yang layak untuk saya baca! ' Rasulullah shallallahu 'alaihi wasallam berkata: 'Ucapkanlah, Laa ilaaha illallaahu wahdahuu laa syarikalah. Allaahu Akbaar kabiiran walhamdulillaahi katsiiran. Subhaanallahi Rabbil 'aalamiin. Laa haula walaa quwwataa Illa billaahil 'aziizil hakim. (Tiada tuhan selain Allah, Yang Maha Esa, tidak ada sekutu bagi-Nya. Allah Maha Besar, segala puji bagi-Nya. Maha Suci Allah, Tuhan alam semesta. Tiada daya dan kekuatan kecuali dengan pertolongan Allah Yang Maha Perkasa dan Maha Bijaksana). Orang Arab badui itu berkata; 'Ya Rasulullah, itukan bacaan yang ditujukan untuk Allah, lalu apa bacaan untuk diri saya? ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Allaahummaghfir lii warhamnii wahdinii warzuqnii'. (Ya Allah, ampunilah aku, kasihanilah aku, tunjukkanlah aku, dan anugerahkanlah aku rizki). Musa Al Juhani berkata; 'Saya meragukan kata-kata \"Aafini\" dan tidak tahu asal-usulnya.' Namun Ibnu Abu Syaibah di dalam Haditsnya tidak menyebutkan perkataan Abu Musa ini."},"4518":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُ مَنْ أَسْلَمَ يَقُولُ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاهْدِنِي وَارْزُقْنِي","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari] telah menceritakan kepada kami ['Abdul Wahid bin Ziyad]; telah menceritakan kepada kami [Abu Malik Al Asyja'i] dari [bapaknya], dia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada orang yang baru masuk Islam dengan do'a; Allaahummaghfir lii warhamnii wahdinii warzuqnii'. (Ya Allah, ampunilah aku, kasihanilah aku, tunjukkanlah aku, dan anugerahkanlah aku rizki)."},"4519":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَزْهَرَ الْوَاسِطِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ عَنْ أَبِيهِ قَالَكَانَ الرَّجُلُ إِذَا أَسْلَمَ عَلَّمَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ ثُمَّ أَمَرَهُ أَنْ يَدْعُوَ بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَاهْدِنِي وَعَافِنِي وَارْزُقْنِي","id":"Telah menceritakan kepada kami [Sa'id bin Azhar Al Wasithi] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Abu Malik Al Asyja'i] dari [bapaknya], dia berkata; Apabila ada seseorang yang masuk Islam, Nabi shallallahu 'alaihi wasallam mengajarinya tentang shalat kemudian disuruh untuk membaca do'a: Allaahummaghfir lii warhamnii wahdinii wa'aafini warzuqnii'. (Ya Allah, ampunilah aku, kasihanilah aku, tunjukkanlah aku, sehatkanlah aku dan anugerahkanlah aku rizki)."},"4520":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَبُو مَالِكٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ أَقُولُ حِينَ أَسْأَلُ رَبِّي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَعَافِنِي وَارْزُقْنِي وَيَجْمَعُ أَصَابِعَهُ إِلَّا الْإِبْهَامَ فَإِنَّ هَؤُلَاءِ تَجْمَعُ لَكَ دُنْيَاكَ وَآخِرَتَكَ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abu Malik] dari [bapaknya] bahwasanya dia mendengar Nabi shallallahu 'alaihi wasallam ketika beliau didatangi oleh seorang laki-laki dan kemudian laki-laki tersebut bertanya; \"Ya Rasulullah, apa yang sebaiknya saya ucapkan ketika saya memohon kepada Allah Yang Maha Mulia dan Maha Agung?\" Rasulullah shallallahu 'alaihi wasallam menjawab: 'Ketika kamu memohon kepada Allah, maka ucapkanlah doa sebagai berikut; 'Ya Allah, ampunilah aku, kasihanilah aku, selamatkanlah aku, dan berikanlah rezeki kepadaku! ' (Saat itu beliau menggenggam jari-jari beliau kecuali ibu jari), karena sesungguhnya doa-doa tersebut mencakup dunia dan akhiratmu.'"},"4521":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مَرْوَانُ وَعَلِيُّ بْنُ مُسْهِرٍ عَنْ مُوسَى الْجُهَنِيِّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا مُوسَى الْجُهَنِيُّ عَنْ مُصْعَبِ بْنِ سَعْدٍ حَدَّثَنِي أَبِي قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيَعْجِزُ أَحَدُكُمْ أَنْ يَكْسِبَ كُلَّ يَوْمٍ أَلْفَ حَسَنَةٍ فَسَأَلَهُ سَائِلٌ مِنْ جُلَسَائِهِ كَيْفَ يَكْسِبُ أَحَدُنَا أَلْفَ حَسَنَةٍ قَالَ يُسَبِّحُ مِائَةَ تَسْبِيحَةٍ فَيُكْتَبُ لَهُ أَلْفُ حَسَنَةٍ أَوْ يُحَطُّ عَنْهُ أَلْفُ خَطِيئَةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Marwan] dan ['Ali bin Mushar] dari [Musa Al Juhani] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] - dan lafadh ini miliknya - [bapakku] telah menceritakan kepada kami, telah menceritakan kepada kami [Musa Al Juhani] dari [Mush'ab bin Sa'd] Telah menceritakan kepadaku [Bapakku] dia berkata; \"Kami pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam. Setelah itu beliau bertanya: 'Apakah mampu salah seorang dari kalian memperoleh seribu kebaikan dalam sehari? ' Lalu salah seorang dari para sahabat bertanya; 'Ya Rasulullah, bagaimana mungkin seseorang akan mampu meraih seribu kebaikan dalam sehari? ' Rasulullah berkata: 'Ketahuilah bahwa orang yang bertasbih seratus kali akan dicatat seribu kebaikan untuknya dan dihapus seribu kesalahan darinya.'"},"4522":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ وَاللَّفْظُ لِيَحْيَى قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيَا نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ وَمَنْ يَسَّرَ عَلَى مُعْسِرٍ يَسَّرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ وَاللَّهُ فِي عَوْنِ الْعَبْدِ مَا كَانَ الْعَبْدُ فِي عَوْنِ أَخِيهِ وَمَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ وَمَا اجْتَمَعَ قَوْمٌ فِي بَيْتٍ مِنْ بُيُوتِ اللَّهِ يَتْلُونَ كِتَابَ اللَّهِ وَيَتَدَارَسُونَهُ بَيْنَهُمْ إِلَّا نَزَلَتْ عَلَيْهِمْ السَّكِينَةُ وَغَشِيَتْهُمْ الرَّحْمَةُ وَحَفَّتْهُمْ الْمَلَائِكَةُ وَذَكَرَهُمْ اللَّهُ فِيمَنْ عِنْدَهُ وَمَنْ بَطَّأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَاه نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أُسَامَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ أَبِي صَالِحٍ وَفِي حَدِيثِ أَبِي أُسَامَةَ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ صَخَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي مُعَاوِيَةَ غَيْرَ أَنَّ حَدِيثَ أَبِي أُسَامَةَ لَيْسَ فِيهِ ذِكْرُ التَّيْسِيرِ عَلَى الْمُعْسِرِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Al 'Ala Al Hamdani] -dan lafadh ini milik Yahya- dia berkata; telah mengabarkan kepada kami, dan berkata yang lainnya, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Barang siapa membebaskan seorang mukmin dari suatu kesulitan dunia, maka Allah akan membebaskannya dari suatu kesulitan pada hari kiamat. Barang siapa memberi kemudahan kepada orang yang berada dalam kesulitan, maka Allah akan memberikan kemudahan di dunia dan akhirat. Barang siapa menutupi aib seorang muslim, maka Allah akan menutup aibnya di dunia dan akhirat. Allah akan selalu menolong hamba-Nya selama hamba tersebut menolong saudaranya sesama muslim. Barang siapa menempuh jalan untuk mencari ilmu, maka Allah akan memudahkan jalan ke surga baginya. Tidaklah sekelompok orang berkumpul di suatu masjid (rumah Allah) untuk membaca Al Qur'an, melainkan mereka akan diliputi ketenangan, rahmat, dan dikelilingi para malaikat, serta Allah akan menyebut-nyebut mereka pada malaikat-malaikat yang berada di sisi-Nya. Barang siapa yang ketinggalan amalnya, maka nasabnya tidak juga meninggikannya.' Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] telah menceritakan kepada kami [Bapakku] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakannya kepada kami [Nashr bin 'Ali Al Jahdhami] telah menceritakan kepada kami [Abu Usamah] mereka berkata; telah menceritakan kepada kami [Al A'masy] -telah menceritakan kepada kami Ibnu Numair- dari [Abu Shalih]. Sebagaimana di dalam hadits Abu Usamah Telah menceritakan kepada kami Abu Shalih dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkata dengan lantang, -sebagaimana Hadits Abu Mu'awiyah, hanya saja di dalam Hadits Abu Usamah tidak disebutkan; memberi kemudahan kepada orang yang kesusahan.'"},"4523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ أَنَّهُ قَالَأَشْهَدُ عَلَى أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُمَا شَهِدَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَقْعُدُ قَوْمٌ يَذْكُرُونَ اللَّهَ عَزَّ وَجَلَّ إِلَّا حَفَّتْهُمْ الْمَلَائِكَةُ وَغَشِيَتْهُمْ الرَّحْمَةُ وَنَزَلَتْ عَلَيْهِمْ السَّكِينَةُ وَذَكَرَهُمْ اللَّهُ فِيمَنْ عِنْدَهُو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا شُعْبَةُ فِي هَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] aku mendengar [Abu Ishaq] bercerita dari [Al A'raj Abu Muslim] bahwasanya dia berkata; 'aku bersaksi atas [Abu Hurairah] dan [Abu Sa'id Al Khudri] bahwasanya keduanya menyaksikan Nabi shallallahu 'alaihi wasallam bersabda: 'Tidaklah suatu kaum yang duduk berkumpul untuk mengingat Allah, kecuali dinaungi oleh para malaikat, dilimpahkan kepada mereka rahmat, akan diturunkan kepada mereka ketenangan, dan Allah Azza Wa jalla akan menyebut-nyebut mereka di hadapan para makhluk yang ada di sisi-Nya. Dan telah menceritakannya kepadaku [Zuhair bin Harb] telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Syu'bah] dalam sanad ini dengan Hadits yang serupa."},"4524":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ عَنْ أَبِي نَعَامَةَ السَّعْدِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ خَرَجَ مُعَاوِيَةُ عَلَى حَلْقَةٍ فِي الْمَسْجِدِ فَقَالَ مَا أَجْلَسَكُمْ قَالُوا جَلَسْنَا نَذْكُرُ اللَّهَ قَالَ آللَّهِ مَا أَجْلَسَكُمْ إِلَّا ذَاكَ قَالُوا وَاللَّهِ مَا أَجْلَسَنَا إِلَّا ذَاكَ قَالَ أَمَا إِنِّي لَمْ أَسْتَحْلِفْكُمْ تُهْمَةً لَكُمْ وَمَا كَانَ أَحَدٌ بِمَنْزِلَتِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَلَّ عَنْهُ حَدِيثًا مِنِّيوَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى حَلْقَةٍ مِنْ أَصْحَابِهِ فَقَالَ مَا أَجْلَسَكُمْ قَالُوا جَلَسْنَا نَذْكُرُ اللَّهَ وَنَحْمَدُهُ عَلَى مَا هَدَانَا لِلْإِسْلَامِ وَمَنَّ بِهِ عَلَيْنَا قَالَ آللَّهِ مَا أَجْلَسَكُمْ إِلَّا ذَاكَ قَالُوا وَاللَّهِ مَا أَجْلَسَنَا إِلَّا ذَاكَ قَالَ أَمَا إِنِّي لَمْ أَسْتَحْلِفْكُمْ تُهْمَةً لَكُمْ وَلَكِنَّهُ أَتَانِي جِبْرِيلُ فَأَخْبَرَنِي أَنَّ اللَّهَ عَزَّ وَجَلَّ يُبَاهِي بِكُمْ الْمَلَائِكَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Marhum bin 'Abdul 'Aziz] dari [Abu Na'amah As Sa'di] dari [Abu 'Utsman] dari [Abu Sa'id Al Khudri] dia berkata; \"Pada suatu hari Mu'awiyah melewati sebuah halaqah (majlis) di masjid. Kemudian ia bertanya; 'Majelis apakah ini? ' Mereka menjawab; 'Kami duduk di sini untuk berzikir kepada Allah Azza wa Jalla.' Mu'awiyah bertanya lagi; 'Demi Allah, benarkah kalian duduk-duduk di sini hanya untuk itu? ' Mereka menjawab; 'Demi Allah, kami duduk hanya untuk itu.' Kata [Mu'awiyah] selanjutnya; 'Sungguh saya tidak menyuruh kalian bersumpah karena mencurigai kalian. Karena tidak ada orang yang menerima hadits dari Rasulullah shallallahu 'alaihi wasallam yang lebih sedikit daripada saya.' Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah melewati halaqah para sahabatnya. Lalu Rasulullah shallallahu 'alaihi wasallam bertanya: 'Majelis apa ini? ' Mereka menjawab; 'Kami duduk untuk berzikir kepada Allah dan memuji-Nya atas hidayah-Nya berupa Islam dan anugerah-Nya kepada kami.' Rasulullah shallallahu 'alaihi wasallam bertanya lagi: 'Demi Allah, apakah kalian duduk di sini hanya untuk ini? ' Mereka menjawab; 'Demi Allah, kami duduk-duduk di sini hanya untuk ini.' Kata Rasulullah selanjutnya: 'Sungguh aku menyuruh kalian bersumpah bukan karena mencurigai kalian. Tetapi karena aku pernah didatangi Jibril alaihis-salam. Kemudian ia memberitahukan kepadaku bahwasanya Allah Azza wa Jalla membanggakan kalian di hadapan para malaikat.'"},"4525":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو الرَّبِيعِ الْعَتَكِيُّ جَمِيعًا عَنْ حَمَّادٍ قَالَ يَحْيَى أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَبِي بُرْدَةَ عَنْ الْأَغَرِّ الْمُزَنِيِّ وَكَانَتْ لَهُ صُحْبَةٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهُ لَيُغَانُ عَلَى قَلْبِي وَإِنِّي لَأَسْتَغْفِرُ اللَّهَ فِي الْيَوْمِ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah bin Sa'id] dan [Abu Ar Rabi' Al 'Ataki] semuanya dari [Hammad], Yahya berkata; telah mengabarkan kepada kami Hammad bin Zaid dari [Tsabit] dari [Abu Burdah] dari [Al Aghar Al Muzanni], -salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, - Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hatiku tidak pernah lalai dari dzikir kepada Allah, susungguhnya Aku beristighfar seratus kali dalam sehari.\""},"4526":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي بُرْدَةَ قَالَ سَمِعْتُ الْأَغَرَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ ابْنَ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى اللَّهِ فَإِنِّي أَتُوبُ فِي الْيَوْمِ إِلَيْهِ مِائَةَ مَرَّةٍحَدَّثَنَاه عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ كُلُّهُمْ عَنْ شُعْبَةَ فِي هَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari ['Amru bin Murrah] dari [Abu Burdah] dia berkata; \"Saya pernah mendengar [Al Agharr], salah seorang sahabat Rasulullah, memberitahukan Ibnu Umar, bahwasanya Rasulullah bersabda: 'Wahai manusia, bertaubatlah kepada Allah, karena aku bertaubat seratus kali dalam sehari.' \" Telah menceritakannya kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepadaku [Bapakku]. Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Abu Dawud] dan ['Abdurrahman bin Mahdi] semuanya dari [Syu'bah] dengan sanad ini."},"4527":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي سُلَيْمَانَ بْنَ حَيَّانَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنِي أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا حَفْصٌ يَعْنِي ابْنَ غِيَاثٍ كُلُّهُمْ عَنْ هِشَامٍ ح و حَدَّثَنِي أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لَهُ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَابَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا تَابَ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Sulaiman bin Hayyan] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Mu'awiyah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Hafsh bin Ghiyats] semuanya dari [Hisyam] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Abu Khaitsamah Zuhair bin Harb] -dan lafadh ini miliknya- telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Hisyam bin Hasan] dari [Muhammad bin Sirin] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Barangsiapa bertaubat sebelum matahari terbit dari barat (kiamat), maka Allah masih akan menerima taubatnya.'\""},"4528":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ وَأَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَجَعَلَ النَّاسُ يَجْهَرُونَ بِالتَّكْبِيرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّهَا النَّاسُ ارْبَعُوا عَلَى أَنْفُسِكُمْ إِنَّكُمْ لَيْسَ تَدْعُونَ أَصَمَّ وَلَا غَائِبًا إِنَّكُمْ تَدْعُونَ سَمِيعًا قَرِيبًا وَهُوَ مَعَكُمْ قَالَ وَأَنَا خَلْفَهُ وَأَنَا أَقُولُ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ أَلَا أَدُلُّكَ عَلَى كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ فَقُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ قُلْ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِحَدَّثَنَا ابْنُ نُمَيْرٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَبُو سَعِيدٍ الْأَشَجُّ جَمِيعًا عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ عَاصِمٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dan [Abu Mu'awiyah] dari ['Ashim] dari [Abu 'Utsman] dari [Abu Musa] dia berkata; \"Kami pernah menyertai Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Tiba-tiba, ada beberapa orang sahabat bertakbir dengan suara keras. Mendengar suara takbir yang keras itu, Rasulullah pun berkata: 'Saudara-saudara sekalian, rendahkanlah suara kalian! Sesungguhnya kalian tidak berdoa kepada Dzat yang tuli dan jauh. Tetapi kalian berdoa kepada Tuhan Yang Maha Mendengar dan Maha Dekat. Dia selalu beserta kalian.' Abu Musa berkata; 'Pada saat itu saya sedang berada di belakang Rasulullah shallallahu 'alaihi wasallam sambil membaca; 'Laa haula wa laa quwwata ilIa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AlIah). Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Hai Abdullah bin Qais, inginkah aku tunjukkan kepadamu salah satu perbendaharaan surga? ' Saya menjawab; 'Tentu ya Rasulullah.' Rasulullah bersabda: 'Ucapkanlah, Laa haula wala quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AIIah).\" Telah menceritakan kepada kami [Ibnu Numair] dan [Ishaq bin Ibrahim] dan [Abu Sa'id Al Asyaj] semuanya dari [Hafsh bin Ghiyats] dari ['Ashim] melalui sanad ini dengan Hadits yang serupa."},"4529":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَىأَنَّهُمْ كَانُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يَصْعَدُونَ فِي ثَنِيَّةٍ قَالَ فَجَعَلَ رَجُلٌ كُلَّمَا عَلَا ثَنِيَّةً نَادَى لَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ قَالَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ لَا تُنَادُونَ أَصَمَّ وَلَا غَائِبًا قَالَ فَقَالَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ مِنْ كَنْزِ الْجَنَّةِ قُلْتُ مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِو حَدَّثَنَاه مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ أَبِي مُوسَى قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ وَأَبُو الرَّبِيعِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَذَكَرَ نَحْوَ حَدِيثِ عَاصِمٍ و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الثَّقَفِيُّ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَذَكَرَ الْحَدِيثَ وَقَالَ فِيهِ وَالَّذِي تَدْعُونَهُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ عُنُقِ رَاحِلَةِ أَحَدِكُمْ وَلَيْسَ فِي حَدِيثِهِ ذِكْرُ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Abu Kamil Fudhail bin Husain] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [At Taimi] dari [Abu 'Utsman] dari [Abu Musa] bahwa para sahabat pernah menyertai Rasulullah shallallahu 'alaihi wasallam, dan ketika para sahabat sedang menaiki jalan setapak di antara dua gunung, salah seorang dari mereka setiap naik keatas berseru; 'Laa Ilaaha Illa Allah wallahu Akbar.' (tidak ada Ilah selain Allah yang maha Agung). Abu Musa berkata; lalu Rasulullah shallallahu 'alaihi wasallam berkata: 'Sesungguhnya kalian tidak berseru kepada Dzat yang tuli dan jauh.' Abu Musa berkata; kemudian beliau berseru; 'Hai Abu Musa atau hai Abdullah bin Qais, inginkah aku tunjukkan kepadamu salah satu perbendaharaan surga? ' Saya menjawab; 'Apa itu ya Rasulullah? ' Rasulullah bersabda: Laa haula wala quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AIIah).\" Dan telah menceritakannya kepada kami [Muhammad bin 'Abdul A'la] telah menceritakan kepada kami [Al Mu'tamir] dari [Bapaknya] telah menceritakan kepada kami [Abu 'Utsman] dari [Abu Musa] dia berkata; 'ketika Rasulullah shallallahu 'alaihi wasallam, -lalu dia menyebutkan Hadits yang serupa.- telah menceritakan kepada kami [Khalaf bin Hisyam] dan [Abu Ar Rabi'] mereka berdua berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu 'Utsman] dari [Abu Musa] dia berkata; kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, -lalu dia menyebutkan seperti hadits 'Ashim.- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Ats Tsaqafi] telah menceritakan kepada kami [Khalid Al Hadza] dari [Abu 'Utsman] dari [Abu Musa] dia berkata; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan, -kemudian dia menyebutkan hadits tersebut, dan di dalamnya berkata; Dzat yang kamu seru itu lebih dekat dari leher hewan yang tunggangi salah seorang kalian. Dan di dalamnya tidak menyebutkan kalimat; 'Laa haula wala quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AIIah).\""},"4530":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا عُثْمَانُ وَهُوَ ابْنُ غِيَاثٍ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ مِنْ كُنُوزِ الْجَنَّةِ أَوْ قَالَ عَلَى كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ فَقُلْتُ بَلَى فَقَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadhr bin Syumail] telah menceritakan kepada kami ['Utsman bin Ghiyats] telah menceritakan kepada kami [Abu 'Utsman] dari [Abu Musa Al Asy'ari] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Maukah aku tunjukkan kepadamu salah satu perbendaharaan surga? ' Saya menjawab; 'Tentu ya Rasulullah? ' Rasulullah bersabda: Laa haula wala quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AIIah).\""},"4531":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي ��َكْرٍ أَنَّهُقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَبِيرًا وَقَالَ قُتَيْبَةُ كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي رَجُلٌ سَمَّاهُ وَعَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقَولُ إِنَّ أَبَا بَكْرٍ الصِّدِّيقَ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي يَا رَسُولَ اللَّهِ دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي وَفِي بَيْتِي ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ اللَّيْثِ غَيْرَ أَنَّهُ قَالَ ظُلْمًا كَثِيرًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abul Khair] dari ['Abdullah bin 'Amr] dari [Abu Bakar Ash-Shiddiq radliallahu 'anhu] bahwa ia pernah berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Ajari aku suatu doa yang dapat aku panjatkan dalam shalatku.\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Ucapkanlah, (Ya Allah, aku telah berbuat aniaya kepada diriku sendiri dengan aniaya yang besar, -Qutaibah berkata; yang banyak-, dan tidak ada yang mengampuni dosa-dosa selain Engkau, ampunilah aku dengan ampunan dari sisi-Mu, serta kasihinilah aku. Sesungguhnya Engkau Maha Pengampun lagi Maha Penyayang.\" Dan telah menceritakannya kepadaku [Abu Ath Thahir] telah mengabarkan kepada kami ['Abdullah bin Wahb] telah mengabarkan kepadaku seorang laki-laki yang dia sebutkan, dan ['Amr bin Al Harits] dari [Yazid bin Abu Habib] dari [Abul Khair] bahwasanya ia mendengar ['Abdullah bin 'Amru bin Al 'Ash] berkata; bahwa [Abu Bakr Ash Shiddiq] dia berkata kepada Rasulullah: \"Ajari aku suatu doa yang dapat aku panjatkan dalam shalatku dan aku panjatkan di rumahku, -lalu dian menyebutkan Hadits yang sama dengan Hadits Al Laits. Namun dia menyebutkan dengan kalimat; 'zhulman katsiran' (dengan aniaya yang banyak)."},"4532":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَا حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الدَّعَوَاتِ اللَّهُمَّ فَإِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَفِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَمِنْ شَرِّ فِتْنَةِ الْغِنَى وَمِنْ شَرِّ فِتْنَةِ الْفَقْرِ وَأَعُوذُ بِكَ مِنْ شَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ فَإِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَأْثَمِ وَالْمَغْرَمِو حَدَّثَنَاه أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] -dan lafadh ini milik Abu Bakr- mereka berdua berkata; telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari ['Aisyah] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah membaca doa yang berbunyi: \"Ya Allah, sesungguhnya aku berlindung kepada-Mu dari fitnah api neraka dan siksanya, dari fitnah kubur dan siksanya, dari fitnah kekayaan, dari fitnah kefakiran, dan aku berlindung kepada-Mu ya Allah dari fitnah Dajjal. Ya Allah, hapuskanlah dosaku dengan air salju dan air embun, bersihkanlah hatiku dari segala kesalahan sebagaimana Engkau bersihkan kain putih dari noda. Ya Allah, jauhkanlah antara aku dan dosaku sebagaimana Engkau jauhkan antara timur dengan barat. Ya Allah, sesungguhnya aku berlindung kepada-Mu dari kemalasan dan kepikunan serta dari dosa dan lilitan hutang.\" Dan telah menceritakannya kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Hisyam] dengan sanad ini."},"4533":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ وَأَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْجُبْنِ وَالْهَرَمِ وَالْبُخْلِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِو حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُعْتَمِرٌ كِلَاهُمَا عَنْ التَّيْمِيِّ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّ يَزِيدَ لَيْسَ فِي حَدِيثِهِ قَوْلُهُ وَمِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا ابْنُ مُبَارَكٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ تَعَوَّذَ مِنْ أَشْيَاءَ ذَكَرَهَا وَالْبُخْلِ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; dan telah mengabarkan kepada kami [Sulaiman At Taimi] telah menceritakan kepada kami [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berdoa: 'Ya Allah, aku berlindung kepada-Mu dari kelemahan, kemalasan, rasa takut, kepikunan, dan kekikiran. Dan aku juga berlindung kepada-Mu dari siksa kubur serta bencana kehidupan dan kematian.'\" Dan telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Yazid bin Zurai'] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin 'Abdul A'la] telah menceritakan kepada kami [Mu'tamir], keduanya dari [At Taimi] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa. Namun Yazid di dalam Haditsnya tidak menyebutkan sabda Nabi shallallahu 'alaihi wasallam; serta fitnah kehidupan dan kematian.' Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah mengabarkan kepada kami [Ibnul Mubarak] dari [Sulaiman At Taimi] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam bahwa beliau berlindung dari beberapa hal yang beliau sebutkan, dan dari kekikiran."},"4534":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ الْعَبْدِيُّ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ الْعَمِّيُّ حَدَّثَنَا هَارُونُ الْأَعْوَرُ حَدَّثَنَا شُعَيْبُ بْنُ الْحَبْحَابِ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهَؤُلَاءِ الدَّعَوَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَالْكَسَلِ وَأَرْذَلِ الْعُمُرِ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Nafi' Al 'Abdi] telah menceritakan kepada kami [Bahz bin Asad Al 'Ammi]; telah menceritakan kepada kami [Harun Al A'war] telah menceritakan kepada kami [Syu'aib bin Al Habhab] dari [Anas] dia berkata; bahwa Nabi Allah shallallahu 'alaihi wasallam berdo'a dengan do'a: \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI WAL KASALI WA ARDZALIL 'UMURI WA 'ADZAABIL QABRI WA FITNATIL MAHYAA WAL MAMAATI (Ya Allah, sesungguhnya aku berlindung kepada-Mu dari kekikiran, kemalasan, umur yang menjadikan pikun, siksa kubur dan fitnah dunia dan fitnah kematian).\""},"4535":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي سُمَيٌّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ سُوءِ الْقَضَاءِ وَمِنْ دَرَكِ الشَّقَاءِ وَمِنْ شَمَاتَةِ الْأَعْدَاءِ وَمِنْ جَهْدِ الْبَلَاءِقَالَ عَمْرٌو فِي حَدِيثِهِ قَالَ سُفْيَانُ أَشُكُّ أَنِّي زِدْتُ وَاحِدَةً مِنْهَا","id":"Telah menceritakan kepadaku ['Amr An Naqid] dan [Zuhair bin Harb] mereka berdua berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah menceritakan kepadaku [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] bahwasanya Nabi shallallahu 'alaihi wasallam pernah berdoa untuk berlindung dari takdir buruk, kesialan, dan cacian musuh (karena kemalangan diri), dan dari ujian yang memayahkan. Amru mengatakan dalam haditsnya; \"Sufyan berkata; 'Saya merasa ragu bahwasanya saya telah menambah salah satu kata dalam hadits tersebut.'\""},"4536":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ وَاللَّفْظُ لَهُ أَخْبَرَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ الْحَارِثِ بْنِ يَعْقُوبَ أَنَّ يَعْقُوبَ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ أَنَّهُ سَمِعَ بُسْرَ بْنَ سَعِيدٍ يَقُولُ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُ سَمِعْتُ خَوْلَةَ بِنْتَ حَكِيمٍ السُّلَمِيَّةَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَزَلَ مَنْزِلًا ثُمَّ قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْ مَنْزِلِهِ ذَلِكَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin Rumh] -dan lafadh ini miliknya-; telah mengabarkan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Al Harits bin Ya'qub] bahwasanya [Ya'qub bin 'Abdullah] menceritakan kepadanya bahwasanya ia mendengar [Busr bin Sa'id] berkata; aku mendengar [Sa'd bin Abi Waqqash] berkata; aku mendengar [Khaulah bintu Hakim As Sulamiyyah] berkata; aku mendengar Rasululullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang singgah pada suatu tempat kemudian dia berdo'a: 'A'AUUDZU BI KALIMAATILLAHIT TAAMMAH MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat Allah yang sempurna dari kejelekan apa saja yang Dia ciptakan), ' niscaya tidak akan ada yang membahayakannya hingga di pergi dari tempat itu.\""},"4537":{"ar":"و حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَأَبُو الطَّاهِرِ كِلَاهُمَا عَنْ ابْنِ وَهْبٍ وَاللَّفْظُ لِهَارُونَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ وَأَخْبَرَنَا عَمْرٌو وَهُوَ ابْنُ الْحَارِثِ أَنَّ يَزِيدَ بْنَ أَبِي حَبِيبٍ وَالْحَارِثَ بْنَ يَعْقُوبَ حَدَّثَاهُ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ السُّلَمِيَّةِ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا نَزَلَ أَحَدُكُمْ مَنْزِلًا فَلْيَقُلْ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ فَإِنَّهُ لَا يَضُرُّهُ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْهُ","id":"Dan telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Abu Ath Thahir] keduanya dari [Ibnu Wahb] -dan lafadh ini milik Harun-; telah menceritakan kepada kami 'Abdullah bin Wahb dia berkata; dan telah mengabarkan kepada kami ['Amru bin Al Harits] bahwasanya [Yazid bin Abu Habib] dan [Al Harits bin Ya'qub] menceritakannya kepada kami dari [Ya'qub bin 'Abdullah bin Al Asyaj] dari [Busr bin Sa'id] dari [Sa'd bin Abi Waqqash] dari [Khaulah bintu Hakim As Sulamiyyah] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Apabila salah seorang dari kalian singgah di suatu tempat maka hendaklah dia berdo'a: 'A'AUUDZU BI KALIMAATILLAHIT TAAMMAH MIN SYARRI MAA KHALAQ (AKu berlindung dengan kalimat Allah yang sempurna dari kejelekan apa saja yang Dia ciptakan), ' niscaya tidak akan ada yang membahayakannya hingga di pergi dari tempat itu.\""},"4538":{"ar":"قَالَ يَعْقُوبُ وَقَالَ الْقَعْقَاعُ بْنُ حَكِيمٍ عَنْ ذَكْوَانَ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا لَقِيتُ مِنْ عَقْرَبٍ لَدَغَتْنِي الْبَارِحَةَ قَالَ أَمَا لَوْ قُلْتَ حِينَ أَمْسَي��تَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ لَمْ تَضُرَّكَو حَدَّثَنِي عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَخْبَرَنِي اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرٍ عَنْ يَعْقُوبَ أَنَّهُ ذَكَرَ لَهُ أَنَّ أَبَا صَالِحٍ مَوْلَى غَطَفَانَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُا قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ لَدَغَتْنِي عَقْرَبٌ بِمِثْلِ حَدِيثِ ابْنِ وَهْبٍ","id":"(Dan telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Abu Ath Thahir] keduanya dari [Ibnu Wahb] -dan lafadh ini milik Harun-; telah menceritakan kepada kami 'Abdullah bin Wahb dia berkata; dan telah mengabarkan kepada kami ['Amru bin Al Harits] bahwasanya [Yazid bin Abu Habib] dan [Al Harits bin Ya'qub] menceritakannya kepada kami dari) [Ya'qub] dan berkata [Al Qa'qa' bin Hakim] dari [Dzakwan Abu Shalih] dari [Abu Hurairah] bahwasanya ia berkata; 'ada seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; \"Ketika aku tidur tadi malam ada seekor kalajengking yang menyengatku, \" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya diwaktu sore kamu mengucapkan: 'A'AUUDZU BI KALIMAATILLAHIT TAAMMAH MIN SYARRI MAA KHALAQ (AKu berlindung dengan kalimat Allah yang sempurna dari kejelekan apa saja yang Dia ciptakan), ' niscaya tidak akan ada yang membahayakanmu.\" Dan telah menceritakan kepadaku ['Isa bin Hammad Al Mishri] telah mengabarkan kepadaku [Al Laits] dari [Yazid bin Abu Habib] dari [Ja'far] dari [Ya'qub] bahwasanya dia menyebutkan kepadanya bahwa [Abu Shalih] -budak- Ghatafan mengabarkan kepadanya, ia mendengar [Abu Hurairah] berkata; seseorang berkata; Ya Rasulullah, seekor kalajengking menyengatku, -sebagaimana Hadits Ibnu Wahab."},"4539":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِعُثْمَانَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ حَدَّثَنِي الْبَرَاءُ بْنُ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَخَذْتَ مَضْجَعَكَ فَتَوَضَّأْ وُضُوءَكَ لِلصَّلَاةِ ثُمَّ اضْطَجِعْ عَلَى شِقِّكَ الْأَيْمَنِ ثُمَّ قُلْ اللَّهُمَّ إِنِّي أَسْلَمْتُ وَجْهِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ وَاجْعَلْهُنَّ مِنْ آخِرِ كَلَامِكَ فَإِنْ مُتَّ مِنْ لَيْلَتِكَ مُتَّ وَأَنْتَ عَلَى الْفِطْرَةِ قَالَ فَرَدَّدْتُهُنَّ لِأَسْتَذْكِرَهُنَّ فَقُلْتُ آمَنْتُ بِرَسُولِكَ الَّذِي أَرْسَلْتَ قَالَ قُلْ آمَنْتُ بِنَبِيِّكَ الَّذِي أَرْسَلْتَو حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ إِدْرِيسَ قَالَ سَمِعْتُ حُصَيْنًا عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ غَيْرَ أَنَّ مَنْصُورًا أَتَمُّ حَدِيثًا وَزَادَ فِي حَدِيثِ حُصَيْنٍ وَإِنْ أَصْبَحَ أَصَابَ خَيْرًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] -dan lafadh ini milik 'Utsman- [Ishaq] berkata; telah mengabarkan kepada kami, dan ['Utsman] berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'd bin 'Ubaidah] telah menceritakan kepadaku [Al Barra' bin 'Azib] bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Apabila kamu hendak tidur, maka berwudhulah sebagaimana kamu berwudhu untuk shalat. Setelah itu berbaringlah dengan miring ke kanan, lalu berdoalah: ' ALOOHUMMA INNII ASLAMTU WAJHII ILAIKA, WAFAWWADHTU AMRII ILAIKA, WA-ALJA'TU ZHOHRII ILAIKA ROGHBATAN WAROHBATAN ILAIKA, LAA MALJA'A WALAA MANJAA MINKA ILLAA ILAIKA, AAMANTU BIKITAABIKALLADZII ANZALTA, WABINABIYYIKALLADZII ARSALTA 'Ya AIlah ya Tuhanku, aku Pasrahkan wajahku kepada-Mu, aku serahkan urusanku kepada-Mu dan aku serahkan punggungku kepada-Mu dengan berharap-harap cemas, karena tidak ada tempat berlindung dan tempat yang aman dari adzab-Mu kecuali dengan berlindung kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan dan aku beriman kepada Nabi-Mu yang telah Engkau utus.' Jadikan bacaan tersebut sebagai penutup ucapanmu menjelang tidur. Apabila kamu meninggal dunia pada malam itu, maka kamu meninggal dalam kesucian diri (fitrah).\" Al Barra' berkata; 'Saya mengulang-ulang bacaan tersebut agar hafal dan saya ucapkan; 'Saya beriman kepada rasul-Mu yang telah Engkau utus.' Lalu Nabi Muhammad shallallahu 'alaihi wasallam berkata: 'Ucapkanlah; 'Saya beriman kepada Nabi-Mu yang telah Engkau utus.'\" Dan telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] telah menceritakan kepada kami ['Abdullah bin Idris] dia berkata; aku mendengar [Hushain] dari [Sa'd bin 'Ubaidah] dari [Al Barra' bin 'Azib] dari Nabi shallallahu 'alaihi wasallam mengenai Hadits ini. Namun Hadits Manshur lebih lengkap dari ini. Dan di dalam Hadits Hushain ada tambahan; 'apabila dia bangun kembali di pagi hari, maka dia telah memperoleh kebaikan.'"},"4540":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ يُحَدِّثُ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا إِذَا أَخَذَ مَضْجَعَهُ مِنْ اللَّيْلِ أَنْ يَقُولَ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَوَجَّهْتُ وَجْهِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِرَسُولِكَ الَّذِي أَرْسَلْتَ فَإِنْ مَاتَ مَاتَ عَلَى الْفِطْرَةِوَلَمْ يَذْكُرْ ابْنُ بَشَّارٍ فِي حَدِيثِهِ مِنْ اللَّيْلِ حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِب�� قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ يَا فُلَانُ إِذَا أَوَيْتَ إِلَى فِرَاشِكَ بِمِثْلِ حَدِيثِ عَمْرِو بْنِ مُرَّةَ غَيْرَ أَنَّهُ قَالَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مُتَّ مِنْ لَيْلَتِكَ مُتَّ عَلَى الْفِطْرَةِ وَإِنْ أَصْبَحْتَ أَصَبْتَ خَيْرًا حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ أَنَّهُ سَمِعَ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُا أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا بِمِثْلِهِ وَلَمْ يَذْكُرْ وَإِنْ أَصْبَحْتَ أَصَبْتَ خَيْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnu Basysyar] telah menceritakan kepada kami ['Abdurrahman] dan [Abu Dawud] mereka berdua berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; aku mendengar [Sa'd bin 'Ubaidah] menceritakan dari [Al Barra' bin 'Azib] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah menyuruh seseorang apabila dia hendak tidur, untuk mengucapkan; \"ALLOOHUMMA ASLAMTU NAFSII ILAIKA, WAWAJJAHTU WAJHII ILAIKA, WA-ALJA'TU ZHOHRII ILAIKA, WAFAWWADHTU AMRII ILAIKA ROGHBATAN WAROHBATAN ILAIKA, LAA MALJA'A WALAA MANJAA MINKA ILLAA ILAIKA, AAMANTU BIKITAABIKALLADZII ANZALTA WABIROSUULIKALLADZII ARSALTA \"Ya AIlah ya Tuhanku, aku berserah diri kepada-Mu, aku serahkan urusanku kepada-Mu dengan berharap-harap cemas, karena tidak ada tempat berlindung dan tempat yang aman dari adzab-Mu kecuali dengan berlindung kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan dan aku beriman kepada Rasul-Mu yang telah Engkau utus.\" Apabila dia meninggal dunia pada malam itu, maka dia meninggal dalam kesucian diri (fitrah). Namun [Ibnu Basyar] di dalam Haditsnya tidak menyebutkan lafazh; 'di waktu malam.' Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Al Barra' bin 'Azib] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang: Hai fulan, apabila kamu hendak tidur -sebagaimana Hadits Amru bin Murrah- namun dia menggunakan lafazh; dan aku beriman kepada Nabi-Mu yang telah Engkau utus.' Apabila kamu meninggal dunia pada malam itu, maka kamu meninggal dalam kesucian diri (fitrah). 'Dan apabila kamu bangun kembali di pagi hari, maka kamu telah memperoleh kebaikan.' Telah menceritakan kepada kami [Ibnu Al Mutsanna] dan [Ibnu Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] bahwasanya ia mendengar [Al Barra' bin 'Azib] berkata; Rasulullah shallallahu 'alaihi wasallam menyuruh seseorang, -dengan Hadits yang serupa.- namun dia tidak menyebutkan kalimat; 'Dan apabila kamu bangun kembali di pagi hari, maka kamu telah memperoleh kebaikan.'"},"4541":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ أَبَي بَكْرِ بْنِ أَبِي مُوسَى عَنْ الْبَرَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَخَذَ مَضْجَعَهُ قَالَ اللَّهُمَّ بِاسْمِكَ أَحْيَا وَبِاسْمِكَ أَمُوتُ وَإِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Bapakku] telah menceritakan kepada kami [Syu'bah] dari ['Abdullah bin Abus Safar] dari [Abu Bakr bin Abu Musa] dari [Al Barra'] bahwasanya Nabi shallallahu 'alaihi wasallam apabila Rasulullah shallallahu 'alaihi wasallam hendak tidur, maka beliau membaca doa: \"ALLOOHUMMA, BISMIKALLOOHUMMA AHYAA WABISMIKA AMUUTU\" Ya Allah, dengan nama-Mu aku hidup dan dengan nama-Mu aku mati.\" Apabila bangun dari tidur, maka beliau membaca doa: 'ALHAMDU LILLAAHIL LADZII AHYAANAA BA'DA MAA AMAATANAA WAILAIHINNUSYUURU' Segala puji bagi Allah yang telah menghidupkan kami kembali setelah mematikan kami dan hanya kepada-Nyalah tempat kami kembali.'"},"4542":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ وَأَبُو بَكْرِ بْنُ نَافِعٍ قَالَا حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ أَمَرَ رَجُلًا إِذَا أَخَذَ مَضْجَعَهُ قَالَ اللَّهُمَّ خَلَقْتَ نَفْسِي وَأَنْتَ تَوَفَّاهَا لَكَ مَمَاتُهَا وَمَحْيَاهَا إِنْ أَحْيَيْتَهَا فَاحْفَظْهَا وَإِنْ أَمَتَّهَا فَاغْفِرْ لَهَا اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَافِيَةَ فَقَالَ لَهُ رَجُلٌ أَسَمِعْتَ هَذَا مِنْ عُمَرَ فَقَالَ مِنْ خَيْرٍ مِنْ عُمَرَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ نَافِعٍ فِي رِوَايَتِهِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ وَلَمْ يَذْكُرْ سَمِعْتُ","id":"Telah menceritakan kepada kami ['Uqbah bin Mukram Al 'Ammi] dan [Abu Bakr bin Nafi'] mereka berdua berkata; telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Khalid] dia berkata; aku mendengar ['Abdullah bin Al Harits] bercerita dari ['Abdullah bin 'Umar] bahwasanya dia pernah memerintahkan seseorang yang hendak tidur untuk membaca doa; \"ALLOOHUMMA KHOLAQTA NAFSII, WA ANTA TAWAFFAAHAA LAKA, MAMAATUHAA WAMAHYAAHAA, IN-AHYAITAHAA FAHFAZH-HAA WAIN AMATTAHAA FAGHFIRLAHAA, ALLOOHUMMA INNII AS-AULKA AL'AAFIYATA \"Ya Allah, Engkau telah menciptakan diriku dan Engkaulah yang akan mematikannya. Matiku dan hidupku hanyalah untuk-Mu. Apabila Engkau menghidupkan diriku, maka jagalah. Dan apabila Engkau mematikan diriku, maka ampunilah. Ya Allah, aku memohon kepada-Mu kesehatan yang sempurna.\" Abdullah bin Umar pernah ditanya oleh seseorang; 'Hai Abdullah, apakah kamu mendengar bacaan doa ini dari Umar? ' Abdullah bin Umar menjawab; 'Saya memperolehnya dari orang yang Iebih mulia dan utama dari Umar yaitu Rasululiah shallallahu 'alaihi wasallam.' Ibnu Nafi' berkata dalam riwayatnya dari 'Abdullah bin Al Harits tanpa menyebutkan lafazh; 'Sami'tu (aku mendengar)."},"4543":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ قَالَ كَانَ أَبُو صَالِحٍيَأْمُرُنَا إِذَا أَرَادَ أَحَدُنَا أَنْ يَنَامَ أَنْ يَضْطَجِعَ عَلَى شِقِّهِ الْأَيْمَنِ ثُمَّ يَقُولُ اللَّهُمَّ رَبَّ السَّمَاوَاتِ وَرَبَّ الْأَرْضِ وَرَبَّ الْعَرْشِ الْعَظِيمِ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ فَالِقَ الْحَبِّ وَالنَّوَى وَمُنْزِلَ التَّوْرَاةِ وَالْإِنْجِيلِ وَالْفُرْقَانِ أَعُوذُ بِكَ مِنْ شَرِّ كُلِّ شَيْءٍ أَنْتَ آخِذٌ بِنَاصِيَتِهِ اللَّهُمَّ أَنْتَ الْأَوَّلُ فَلَيْسَ قَبْلَكَ شَيْءٌ وَأَنْتَ الْآخِرُ فَلَيْسَ بَعْدَكَ شَيْءٌ وَأَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَيْءٌ وَأَنْتَ الْبَاطِنُ فَلَيْسَ دُونَكَ شَيْءٌ اقْضِ عَنَّا الدَّيْنَ وَأَغْنِنَا مِنْ الْفَقْرِ وَكَانَ يَرْوِي ذَلِكَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَو حَدَّثَنِي عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي الطَّحَّانَ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا إِذَا أَخَذْنَا مَضْجَعَنَا أَنْ نَقُولَ بِمِثْلِ حَدِيثِ جَرِيرٍ وَقَالَ مِنْ شَرِّ كُلِّ دَابَّةٍ أَنْتَ آخِذٌ بِنَاصِيَتِهَا و حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا ابْنُ أَبِي عُبَيْدَةَ حَدَّثَنَا أَبِي كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ أَتَتْ فَاطِمَةُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ خَادِمًا فَقَالَ لَهَا قُولِي اللَّهُمَّ رَبَّ السَّمَاوَاتِ السَّبْعِ بِمِثْلِ حَدِيثِ سُهَيْلٍ عَنْ أَبِيهِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dia berkata; \" [Abu Shalih] pernah menganjurkan kami yaitu, apabila salah seorang dari kami hendak tidur, maka hendaknya ia berbaring dengan cara miring ke kanan seraya membaca doa; ALLOOHUMMA ROBBAS SAMAAWAATI WA ROBBAL ARDH, WAROBBAL'ARSYIL'AZHIIMII, ROBBANAA WAROBBA KULLI SYAI'IN, FAALIQOL HABBI WAN NAWAA, WAMUNZILAT TAUROOTI WAL INJIIL, WAL FURQOON, A'UUDZU BIKA MIN SYARRI KULLI SYAI'IN ANTA AAKHIDZUN BINAASHIYATIHI, ALLOOHUMMA ANTAL AWWALU FALAISA QOBLAKA SYAI'UN, WA ANTAL AAKHIRU FALAISA BA'DAKA SYAI\"UN, WA ANTAZH ZHOOHIRU FALAISA FAUQOKA SYAI'UN, WA ANTAL BAATHINU FALAISA DUUNAKA SYAI'UN, IQDHI'ANNAA ADDAINA, WA AGHNINAA MINAL FAQRI 'Ya Allah, Tuhan langit dan bumi, Tuhan yang menguasai arasy yang agung, Tuhan kami dan Tuhan segala sesuatu, Tuhan yang membelah dan menumbuhkan biji-bijian, Tuhan yang menurunkan kitab Taurat, Injil, dan Al Qur'an. Sesungguhnya aku berlindung kepada-Mu dari kejahatan segala sesuatu, karena segala sesuatu itu berada dalam genggaman-Mu. Ya Allah, Engkaulah Tuhan Yang Awal, maka tidak ada sesuatu pun yang mendahului-Mu. Ya Allah, Engkaulah Tuhan Yang Akhir, maka tidak ada sesuatu setelah-Mu. Ya Allah, Engkaulah Yang Zhahir, maka tidak ada yang menutupi-Mu. Ya Allah, Engkaulah Tuhan Yang Bathin, maka tidak ada yang samar dari-Mu. Ya Allah, lunaskanlah hutang-hutang kami dan bebaskanlah kami dari kefakiran.' Abu Shalih meriwayatkan hadits ini dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam. Dan telah menceritakan kepadaku ['Abdul Hamid bin Bayan Al Wasithi] telah menceritakan kepada kami [Khalid Ath Thahhan] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] dia berkata; Apabila kami hendak tidur, maka Rasulullah shallallahu 'alaihi wasallam menyuruh kami untuk mengucapkan, -sebagaimana Hadits Jarir. Dan menggunakan kalimat; -'ALLOOHUMMA INNIII A'UUDZUBIKA MIN SYARRI KULLI SYAI\"IN ANTA AAKHIDZUN BINAASHIYATIHI \"Sesungguhnya aku berlindung kepada-Mu dari kejahatan setiap binatang, karena setiap binatang itu berada dalam genggaman-Mu.'- Dan telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah menceritakan kepada kami [Abu Usamah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami [Ibnu Abu 'Ubaidah] telah menceritakan kepada kami [Bapakku], keduanya dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; suatu ketika Fathimah menemui Nabi shallallahu 'alaihi wasallam menanyakan kepadanya tentang seorang pembantu yang dapat membantu perkerjaan di rumahnya. Lalu beliau bersabda kepadanya: 'Ya Allah, Tuhan langit dan bumi, ' -sebagaimana Hadits Suhail dari Bapaknya."},"4544":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَوَى أَحَدُكُمْ إِلَى فِرَاشِهِ فَلْيَأْخُذْ دَاخِلَةَ إِزَارِهِ فَلْيَنْفُضْ بِهَا فِرَاشَهُ وَلْيُسَمِّ اللَّهَ فَإِنَّهُ لَا يَعْلَمُ مَا خَلَفَهُ بَعْدَهُ عَلَى فِرَاشِهِ فَإِذَا أَرَادَ أَنْ يَضْطَجِعَ فَلْيَضْطَجِعْ عَلَى شِقِّهِ الْأَيْمَنِ وَلْيَقُلْ سُبْحَانَكَ اللَّهُمَّ رَبِّي بِكَ وَضَعْتُ جَنْبِي وَبِكَ أَرْفَعُهُ إِنْ أَمْسَكْتَ نَفْسِي فَاغْفِرْ لَهَا وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا تَحْفَظُ بِهِ عِبَادَكَ الصَّالِحِينَو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ بِهَذَا الْإِسْنَادِ وَقَالَ ثُمَّ لْيَقُلْ بِاسْمِكَ رَبِّي وَضَعْتُ جَنْبِي فَإِنْ أَحْيَيْتَ نَفْسِي فَارْحَمْهَا","id":"Dan telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Anas bin 'Iyadh] telah menceritakan kepada kami ['Ubaidulah] telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari [Bapaknya] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Apabila seseorang hendak berbaring, maka hendaklah ia mengambil alat pembersih untuk membersihkan alas tidurnya dan sebutlah nama Allah, karena ia tidak tahu apa yang terdapat di atas kasurnya setelah dipakai tidur. Apabila seseorang hendak tidur, maka hendaknya ia tidur dengan miring ke kanan dan mengucapkan doa: \"SUBHAANAKA, ALLOOHUMMA ROBBII, BIKA WADHO'TU JANBII, WABIKA ARFA'UHU, IN AMSAKTA NAFSII FAGHFIR LAHAA WAIN ARSALTAHAA, FAHFAZH-HAA BIMAA TAHFAZHU BIHI 'IBAADAKASH SHOOLIHIINA' 'Maha suci Engkau ya Allah, Tuhanku. Dengan nama-Mu aku baringkan tubuhku dan karena-Mu lah aku bangun dari tidur. Apabila Engkau mematikanku, maka berilah ampunan dan apabila Engkau menghidupkanku, maka peliharalah sebagaimana Engkau memelihara hamba-hamba-Mu yang shalih.' Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah] dari ['Ubaidullah bin 'Umar] dengan sanad ini. Dan beliau bersabda: kemudian ucapkanlah; \"BISMIKA ROBBII WADHO'TU JANBII FAIN AHYAITA NAFSII FARHAMHAA 'Dengan menyebut nama-Mu, ya Rabbku aku letakkan pinggangku ini, apabila Engkau hendak menghidupkan jiwaku, maka rahmatilah ia.'"},"4545":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَوَى إِلَى فِرَاشِهِ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنَا وَسَقَانَا وَكَفَانَا وَآوَانَا فَكَمْ مِمَّنْ لَا كَافِيَ لَهُ وَلَا مُؤْوِيَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwasanya Rasulullah shallallahu 'alaihi wasallam apabila berbaring di tempat tidur, maka beliau mengucapkan doa: \" ALHAMDU LIILAAHIL LADZII ATH'AMANAA WASAQOONAA WAKFAAANAA WA-A-WAANAA WASAQOONAA WAKAFAANAA WA-AWAANAA, FAKAM MIMMAN LAA KAAFIYA LAHU WALAA MU\"WIYA Segala puji bagi Allah yang telah memberi kami makan dan minum, serta mencukupi kebutuhan kami dan memberikan kami tempat berlindung, karena masih banyak orang yang tidak mempunyai kecukupan dan tempat berlindung.\""},"4546":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِيَحْيَى قَالَا أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ الْأَشْجَعِيِّ قَالَ سَأَلْتُ عَائِشَةَعَمَّا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ اللَّهَ قَالَتْ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Ishaq bin Ibrahim] -dan lafadh ini milik Yahya- mereka berkata; telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Hilal] dari [Farwah bin Naufal Al Asyja'i] dia berkata; \"Saya pernah bertanya kepada Aisyah tentang doa yang pernah diucapkan oleh Rasulullah shallallahu 'alaihi wasallam memohon kepada Allah Azza wa Jalla. Maka [Aisyah] menjawab; 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah berdoa sebagai berikut: \"ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA MIN SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukan perbuatan yang telah aku lakukan dan yang belum aku lakukan).'"},"4547":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ هِلَالٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَ سَأَلْتُ عَائِشَةَعَنْ دُعَاءٍ كَانَ يَدْعُو بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَشَرِّ مَا لَمْ أَعْمَلْحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ جَبَلَةَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ كِلَاهُمَا عَنْ شُعْبَةَ عَنْ حُصَيْنٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ فِي حَدِيثِ مُحَمَّدِ بْنِ جَعْفَرٍ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] mereka berkata; telah menceritakan kepada kami ['Abdullah bin Idris] dari [Hushain] dari [Hilal] dari [Farwah bin Naufal] dia berkata; Aku bertanya kepada [Aisyah] tentang do'a yang biasa dibaca oleh Nabi shallallahu 'alaihi wasallam, maka dia menjawab; Beliau membaca: \"ALLAHUMMA INNI A'UUDZU BIKA MIN SYARRI MAA 'AMILTU WA SYARRI MAA LAM A'MAL (Ya Allah, aku berlindung kepada-Mu dari keburukan perbuatan yang telah aku lakukan dan yang belum aku lakukan).' Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] mereka berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Muhammad bin 'Amru bin Jabalah] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya dari [Syu'bah] dari [Hushain] melalui sanad ini dengan Hadits yang serupa. Hanya saja di dalam Hadits Muhammad bin Ja'far menggunakan kalimat; WA MIN SYARRI MAA LAM A'MAL (Dan aku berlindung kepada-Mu dari keburukan perbuatan yang belum aku lakukan)."},"4548":{"ar":"حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ حَدَّثَنِي ابْنُ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ اللَّهُمَّ إِنِّي أَعُوذُ بِعِزَّتِكَ لَا إِلَهَ إِلَّا أَنْتَ أَنْ تُضِلَّنِي أَنْتَ الْحَيُّ الَّذِي لَا يَمُوتُ وَالْجِنُّ وَالْإِنْسُ يَمُوتُونَ","id":"Telah menceritakan kepadaku [Hajjaj bin Asy Sya'ir] telah menceritakan kepada kami ['Abdullah bin 'Amr Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Al Husain] telah menceritakan kepadaku [Ibnu Buraidah] dari [Yahya bin Ya'mar] dari [Ibnu 'Abbas] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah berdoa: \"ALLAHUMMA LAKA ASLAMTU WABIKA AAMANTU, WA'ALAIKA TAWAKKALTU WAILAIKA ANABTU WABIKA KHASHAMTU, INNII A'UUDZU BI'IZZATIKA LAA-ILAAHA-ILLAA ANTA ANTUDHILLANII, ANTAL HAYYUL LADZII LAA YAMUUTU WAL JINNU WAL INSU YAMUUTUNNA \"Ya Allah, sesunguhnya hanya kepada-Mu lah aku berserah diri, hanya kepada-Mu lah aku beriman, hanya kepada-Mu lah aku bertawakal, hanya kepada-Mu lah aku kembali, dan hanya karena-Mu lah aku memusuhi musuh-musuh-Mu. Ya Allah, sesungguhnya aku berlindung kepada keagungan-Mu yang tiada Tuhan selain Engkau- dari Engkau menyesatkanku. Engkaulah yang hidup dan tidak akan pernah mati, sedangkan jin dan manusia pasti akan mati.\""},"4549":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَانَ فِي سَفَرٍ وَأَسْحَرَ يَقُولُ سَمِعَ سَامِعٌ بِحَمْدِ اللَّهِ وَحُسْنِ بَلَائِهِ عَلَيْنَا رَبَّنَا صَاحِبْنَا وَأَفْضِلْ عَلَيْنَا عَائِذًا بِاللَّهِ مِنْ النَّارِ","id":"Telah menceritakan kepadaku [Abu Ath Thahir] telah mengabarkan kepada kami ['Abdullah bin Wahb] telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam apabila dalam perjalanan dan telah memasuki saat menjelang fajar, maka beliau akan mengucapkan: \"SAMI'A SAAMI'UN BIHAMDILLAAHI WAHUSNI BALAA'IHI 'ALAINAA ROBBANAA SHOOHIBNAA WA AFDHIL 'ALAINAA 'AAIDZAN BILLAAHI MINAN NAARI \"Allah Maha Mendengar dan Dia-lah yang menciptakan pendengaran. Dengan memuji Allah dan dengan ujian-Nya yang baik kepada kami ya Tuhan kami, temanilah kami dan berikanlah kemurahan kepada kami.\" Rasulullah shallallahu 'alaihi wasallam mengucapkan doa tersebut dengan memohon perlindungan kepada Allah dari siksa neraka."},"4550":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ دِينَارٍ حَدَّثَنَا أَبُو قَطَنٍ عَمْرُو بْنُ الْهَيْثَمِ الْقُطَعِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ الْمَاجِشُونِ عَنْ قُدَامَةَ بْنِ مُوسَى عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ أَصْلِحْ لِي دِينِي الَّذِي هُوَ عِصْمَةُ أَمْرِي وَأَصْلِحْ لِي دُنْيَايَ الَّتِي فِيهَا مَعَاشِي وَأَصْلِحْ لِي آخِرَتِي الَّتِي فِيهَا مَعَادِي وَاجْعَلْ الْحَيَاةَ زِيَادَةً لِي فِي كُلِّ خَيْرٍ وَاجْعَلْ الْمَوْتَ رَاحَةً لِي مِنْ كُلِّ شَرٍّ","id":"Telah menceritakan kepada kami [Ibrahim bin Dinar] telah menceritakan kepada kami [Abu Qathan 'Amru bin Al Haitsam Al Qutha'i] dari ['Abdul 'Aziz bin 'Abdullah bin Abu Salamah Al Majisyun] dari [Qudamah bin Musa] dari [Abu Shalih As Samman] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berdoa sebagai berikut: \"ALLOOHUMMA ASHLIH LII DIINII ALLADZII HUWA 'ISHMATU AMRII, WA ASHLIH LII DUN-YAAYA ALLATII FIIHAA MA'AASYII, WA ASH-LIH LII AAKHIROTII ALLATII FIIHAA Meriwayatkan'AADZII, WAJ'ALIL HAYAATA ZIYAADATAN LII FII KULLI KHOIRIN, WAJ'ALIL MAUTA ROOHATAN LII MIN KULLI SYARRIN \"Ya Allah ya Tuhanku, perbaikilah bagiku agamaku sebagai benteng urusanku; perbaikilah bagiku duniaku yang menjadi tempat kehidupanku; perbaikilah bagiku akhiratku yang menjadi tempat kembaliku! Jadikanlah ya Allah kehidupan ini mempunyai nilai tambah bagiku dalam segala kebaikan dan jadikanlah kematianku sebagai kebebasanku dari segala kejahatan!\""},"4551":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْهُدَى وَالتُّقَى وَالْعَفَافَ وَالْغِنَىو حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ ابْنَ الْمُثَنَّى قَالَ فِي رِوَايَتِهِ وَالْعِفَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abul Ahwash] dari ['Abdullah] dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau pernah berdoa: \"ALLOOHUMMA INNII AS-ALUKALHUDAA WATTUQOO WAL'AFAAFA WALGHINAA \"Ya Allah ya Tuhanku, sesungguhnya aku memohon kepada-Mu petunjuk, ketakwaan, terhindar dari perbuatan yang tidak baik, dan kecukupan (tidak minta-minta,).\" Dan telah menceritakan kepada kami [Ibnu Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Abu Ishaq] melalui jalur ini dengan Hadits yang serupa. Namun Ibnu Mutsanna di dalam riwayatnya mengatakan lafazh; wal 'iffah (dan harga diri)."},"4552":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لِابْنِ نُمَيْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ وَعَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَلَا أَقُولُ لَكُمْ إِلَّا كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْجُبْنِ وَالْبُخْلِ وَالْهَرَمِ وَعَذَابِ الْقَبْرِ اللَّهُمَّ آتِ نَفْسِي تَقْوَاهَا وَزَكِّهَا أَنْتَ خَيْرُ مَنْ زَكَّاهَا أَنْتَ وَلِيُّهَا وَمَوْلَاهَا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ دَعْوَةٍ لَا يُسْتَجَابُ لَهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ishaq bin Ibrahim] dan [Muhammad bin 'Abdullah bin Numair] -dan lafadh ini milik Ibnu Numair- Ishaq berkata; Telah mengabarkan kepada kami, sedangkan yang lainnya berkata; Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Ashim] dari [Abdullah bin Al Harits] dan dari [Abu Utsman An Nahdi] dari [Zaid bin Arqam] dia berkata; \"Saya tidak akan mengatakan kepada kalian kecuali seperti apa yang pernah diucapkan Rasulullah shallallahu 'alaihi wasallam dalam doanya yang berbunyi: \"ALLOOHUMMA INNII A'UUDZU BIKA MINAL 'AJZI WAL KASALI, WAL JUBNI WAL BUKHLI WAL HAROMI, WA'ADZAABIL QOBRI, ALLOOHUMMA AATI NAFSII TAQWAAHAA, WAZAKKIHAA ANTA KHOIRU MAN ZAKKAAHAA, ANTA WALIYYUHAA WAMAULAAHAA, ALLOOHUMMA INNII A'UUDZU BIKA MIN 'ILMIN LAA YANFA'U WAMIN QOLBIN LAA YAKHSYA'U WAMIN NAFSIN LAA TASYBA'U WAMIN DA'WATIN LAA YUSTAJAABA LAHU' Ya Allah ya Tuhanku, aku berlindung kepada-Mu dari kelemahan, kemalasan, ketakutan, kekikiran, kepikunan, dan siksa kubur. Ya Allah ya Tuhanku, berikanlah ketakwaan kepada jiwaku, sucikanlah ia, sesungguhnya Engkaulah sebaik-baik Dzat yang dapat mensucikannya, Engkaulah yang menguasai dan yang menjaganya. Ya Allah ya Tuhanku, sesungguhnya aku berlindung kepada-Mu dari ilmu yang tidak berguna, hati yang tidak khusyu', diri yang tidak pernah puas, dan doa yang tidak terkabulkan.'\""},"4553":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمْسَى قَالَ أَمْسَيْنَا وَأَمْسَى الْمُلْكُ لِلَّهِ وَالْحَمْدُ لِلَّهِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ قَالَ أُرَاهُ قَالَ فِيهِنَّ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ رَبِّ أَسْأَلُكَ خَيْرَ مَا فِي هَذِهِ اللَّيْلَةِ وَخَيْرَ مَا بَعْدَهَا وَأَعُوذُ بِكَ مِنْ شَرِّ مَا فِي هَذِهِ اللَّيْلَةِ وَشَرِّ مَا بَعْدَهَا رَبِّ أَعُوذُ بِكَ مِنْ الْكَسَلِ وَسُوءِ الْكِبَرِ رَبِّ أَعُوذُ بِكَ مِنْ عَذَابٍ فِي النَّارِ وَعَذَابٍ فِي الْقَبْرِ وَإِذَا أَصْبَحَ قَالَ ذَلِكَ أَيْضًا أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim bin Suwaid] dari ['Abdurrahman bin Yazid] dari ['Abdullah] dia berkata; \"Apabila sore hari, Rasulullah shallallahu 'alaihi wasallam mengucapkan do'a yang berbunyi: 'AMSAINAA WA AMSAL MULKU LILLAAH, WALHAMDULILLAAH, LAA-ILAAHA ILLALLAH, WAHDAHUU LAA SYARIIKA LAHU \"Kami memasuki sore hari dan pada sore ini jagad raya tetap milik Allah. Segala puji bagi Allah tiada Tuhan selain Allah, Dialah yang Esa, tiada sekutu bagi-Nya. Abdullah berkata; beliau juga mengucapkan: 'WALAHUL HAMDU WAHUWA 'ALAA KULLISYAIN QODIIRUN, ROBBII AS'ALUKA KHOIRO MAA FII HADZIHILLAILATA WAKHOIRO MAA BA'DAHAA WA A'UUDZUBIKA MIN SYARRI MAA FII HAADZIHILLAILATI WASYARRI MAA BA'DAHAAA, ROBBI A'UUDZUBIKA MINAL KASALI WASUU'IL KIBARI, ROBBI A'UUDZUBIKA MIN 'ADZAABIKA MIN 'ADZAABIN FINNAARI WA'ADZAABIN FIL QOBRI Bagi-Nyalah semua kekuasaan dan pujian, dan Dialah yang berkuasa atas segala sesuatu. Ya Allah, aku mohon kepada-Mu dari kebaikan malam ini dan kebaikan sesudahnya. Aku berlindung kepada-Mu dari kejahatan yang ada pada malam ini dan kejahatan sesudahnya. Dan aku berlindung kepada-Mu dari kemalasan, kesengsaraan di masa tua. Ya Allah, Aku berlindung kepada-Mu dari adzab neraka dan adzab di dalam kubur. 'Apabila pagi hari, Rasulullah shallallahu 'alaihi wasallam juga mengucapkan doa tersebut dengan diganti bagian pertamanya menjadi Ashbahnaa wa ashbahal mulku Iillah (Kami memasuki pagi hari dan pada pagi hari ini jagad raya dan seisinya tetap menjadi milik Allah).'"},"4554":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمْسَى قَالَ أَمْسَيْنَا وَأَمْسَى الْمُلْكُ لِلَّهِ وَالْحَمْدُ لِلَّهِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ خَيْرِ هَذِهِ اللَّيْلَةِ وَخَيْرِ مَا فِيهَا وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا فِيهَا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَسُوءِ الْكِبَرِ وَفِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِقَالَ الْحَسَنُ بْنُ عُبَيْدِ اللَّهِ وَزَادَنِي فِيهِ زُبَيْدٌ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَفَعَهُ أَنَّهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim bin Suwaid] dari ['Abdurrahman bin Yazid] dari ['Abdullah] dia berkata; \"Apabila sore hari, Rasulullah shallallahu 'alaihi wasallam mengucapkan doa yang berbunyi: AMSAINAA WA AMSAL MULKU LILLAAHI, WALHAMDU LILLAAH, LAA-ILAAHA ILLALLAH, WAHDAHU LAA SYARIIKA LAH, ALLOOHUMMA INNII AS'ALUKA MIN KHOIRI HAADZIHILLAILATI WAKHOIRI MAA FIIHAA WA A'UUDZU BIKA MIN SYARRIHAA WASYARRI MAA FIIHAA, ALLOOHUMMA INNII A'UUZDUBIKA MINAL KASALI WALHAROMI WASUU'IL KIBRI WAFITNATID DUN-YAA WA'ADZAABIL QOBRI\" 'Kami memasuki sore hari dan pada sore ini jagad raya tetap milik Allah. Segala puji bagi Allah tiada Tuhan selain Allah, Dialah yang Esa, tiada sekutu bagi-Nya. Ya Allah, aku mohon kepada-Mu dari kebaikan malam ini dan kebaikan yang ada di dalamnya. Aku berlindung kepada-Mu dari kejahatan di malam ini dan kejahatan yang ada di dalamnya. Ya Allah, aku berlindung kepada-Mu dari kemalasan, kepikunan, kesengsaraan di masa tua, fitnah dunia dan adzab kubur.' [Al Hasan bin Ubaidillah] berkata; ' [Zubaid] menambah kepada saya tentang hadits tersebut dari [Ibrahim bin Suwaid] dari [Abdurrahman bin Yazid] dari [Abdullah] sebagai hadits marfu' bahwasanya Rasulullah shallallahu 'alaihi wasallam membaca doa yang berbunyi: 'LAA-ILAAHA ILLALLOOH WAHDAHUU LAA SYARIIKA LAHU, LAHUL MULKU WALAHUL HAMDU WAHUWA 'ALAA KULLI SYAI'IN QODIIRUN Tiada Tuhan selain Allah. Dialah satu-satunya. Tiada sekutu bagi-Nya, jagad raya hanyalah milik-Nya. Segala puji hanya bagi-Nya dan Dia Maha Kuasa atas segala sesuatu.'"},"4555":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ عَاصِمَ بْنَ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ اللَّهُمَّ اهْدِنِي وَسَدِّدْنِي وَاذْكُرْ بِالْهُدَى هِدَايَتَكَ الطَّرِيقَ وَالسَّدَادِ سَدَادَ السَّهْمِو حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ إِدْرِيسَ أَخْبَرَنَا عَاصِمُ بْنُ كُلَيْبٍ بِهَذَا الْإِسْنَادِ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْهُدَى وَالسَّدَادَ ثُمَّ ذَكَرَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] telah menceritakan kepada kami [Ibnu Idris] dia berkata; aku mendengar ['Ashim bin Kulaib] dari [Abu Burdah] dari ['Ali] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda kepada saya: \"Hai Ali, ucapkanlah doa. ALOOHUMMAH DINII WASADDIDNII WADZKUR BILHUDAA HIDAAYATAKATH THORIIQO WASSADAADI SADAADAS SAHMI \"Ya Allah, berikanlah petunjuk kepadaku. Berilah aku jalan yang lurus. Jadikan petunjuk-Mu sebagai jalanku dan kelurusan hidupku selurus anak panah.\" Telah menceritakan kepada kami [Ibnu Numair] Telah menceritakan kepada kami [Abdullah] yaitu Ibnu Idris Telah mengabarkan kepada kami ['Ashim bin Kulaib] melalui jalur ini, dia berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: 'Katakanlah; Ya Allah aku memohon kepada-Mu petunjuk dan kelurusan hidup, -lalu dia menyebutkan Hadits yang serupa.-"},"4556":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَعَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي عُمَرَ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ عِنْدِهَا بُكْرَةً حِينَ صَلَّى الصُّبْحَ وَهِيَ فِي مَسْجِدِهَا ثُمَّ رَجَعَ بَعْدَ أَنْ أَضْحَى وَهِيَ جَالِسَةٌ فَقَالَ مَا زِلْتِ عَلَى الْحَالِ الَّتِي فَارَقْتُكِ عَلَيْهَا قَالَتْ نَعَمْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ قُلْتُ بَعْدَكِ أَرْبَعَ كَلِمَاتٍ ثَلَاثَ مَرَّاتٍ لَوْ وُزِنَتْ بِمَا قُلْتِ مُنْذُ الْيَوْمِ لَوَزَنَتْهُنَّ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ عَدَدَ خَلْقِهِ وَرِضَا نَفْسِهِ وَزِنَةَ عَرْشِهِ وَمِدَادَ كَلِمَاتِهِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ عَنْ مُحَمَّدِ بْنِ بِشْرٍ عَنْ مِسْعَرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي رِشْدِينَ عَنْ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَ قَالَتْ مَرَّ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ صَلَّى صَلَاةَ الْغَدَاةِ أَوْ بَعْدَ مَا صَلَّى الْغَدَاةَ فَذَكَرَ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan ['Amru An Naqid] dan [Ibnu Abu 'Umar] -dan lafadh ini milik Ibnu Abu 'Umar- mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin 'Abdurrahman] -budak- keluarga Thalhah dari [Kuraib] dari [Ibnu 'Abbas] dari [Juwairiyah] bahwasanya Nabi shallallahu 'alaihi wasallam keluar dari rumah Juwairiyah pada pagi hari usai shalat Subuh dan dia tetap di tempat shalatnya. Tak lama kemudian Rasulullah shallallahu 'alaihi wasallam kembali setelah terbit fajar (pada waktu dhuha), sedangkan Juwairiyah masih duduk di tempat shalatnya. Setelah itu, Rasulullah menyapanya: \"Ya Juwairiyah, kamu masih belum beranjak dari tempat shalatmu?\" Juwairiyah menjawab; 'Ya. Saya masih di sini, di tempat semula ya Rasulullah.' Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: 'Setelah keluar tadi, aku telah mengucapkan empat rangkaian kata-kata -sebanyak tiga kali- yang kalimat tersebut jika dibandingkan dengan apa yang kamu baca seharian tentu akan sebanding, yaitu 'SUBHAANALLOOHI WABIHAMDIHI, 'ADA KHOLQIHI WARIDHOO NAFSIHI WAZINATA 'ARSYIHI WAMIDAADA KALIMAATIHI.\"Maha Suci Allah dengan segala puji bagi-Nya sebanyak hitungan makhluk-Nya, menurut keridlaan-Nya, menurut arasy-Nya dan sebanyak tinta kalimat-Nya.' Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] dan [Ishaq] dari [Muhammad bin Bisyr] dari [Mis'ar] dari [Muhammad bin 'Abdurrahman] dari [Abu Risydin] dari [Ibnu 'Abbas] dari [Juwairiyah] dia berkata; bahwa suatu ketika Rasulullah shallallahu 'alaihi wasallam melewatiku ketika beliau usai shalat shubuh. -lalu dia menyebutkan redaksi yang serupa. Namun beliau dengan menggunakan kalimat; 'SUBHANALLAH 'ADADA KHALQIHI, SUBHANALLAH RIDHO NAFSIHI, SUBHANALLAH ZINATA 'ARSYIHI, SUBHANALLAH MIDADA KALIMAATIHI. Maha suci Allah sebanyak hitungan makhluk-Nya. Maha Suci Allah menurut keridlaan-Nya. Maha Suci Allah menurut kebesaran arasy-Nya. Maha Suci Allah sebanyak paparan kelimat-Nya.'"},"4557":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى حَدَّثَنَا عَلِيٌّأَنَّ فَاطِمَةَ اشْتَكَتْ مَا تَلْقَى مِنْ الرَّحَى فِي يَدِهَا وَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْيٌ فَانْطَلَقَتْ فَلَمْ تَجِدْهُ وَلَقِيَتْ عَائِشَةَ فَأَخْبَرَتْهَا فَلَمَّا جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ عَائِشَةُ بِمَجِيءِ فَاطِمَةَ إِلَيْهَا فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْنَا وَقَدْ أَخَذْنَا مَضَاجِعَنَا فَذَهَبْنَا نَقُومُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَكَانِكُمَا فَقَعَدَ بَيْنَنَا حَتَّى وَجَدْتُ بَرْدَ قَدَمِهِ عَلَى صَدْرِي ثُمَّ قَالَ أَلَا أُعَلِّمُكُمَا خَيْرًا مِمَّا سَأَلْتُمَا إِذَا أَخَذْتُمَا مَضَاجِعَكُمَا أَنْ تُكَبِّرَا اللَّهَ أَرْبَعًا وَثَلَاثِينَ وَتُسَبِّحَاهُ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدَاهُ ثَلَاثًا وَثَلَاثِينَ فَهْوَ خَيْرٌ لَكُمَا مِنْ خَادِمٍو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ كُلُّهُمْ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِ مُعَاذٍ أَخَذْتُمَا مَضْجَعَكُمَا مِنْ اللَّيْلِ و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعُبَيْدُ بْنُ يَعِيشَ عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِ الْحَكَمِ عَنْ ابْنِ أَبِي لَ��ْلَى وَزَادَ فِي الْحَدِيثِ قَالَ عَلِيٌّ مَا تَرَكْتُهُ مُنْذُ سَمِعْتُهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهُ وَلَا لَيْلَةَ صِفِّينَ قَالَ وَلَا لَيْلَةَ صِفِّينَ وَفِي حَدِيثِ عَطَاءٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى قَالَ قُلْتُ لَهُ وَلَا لَيْلَةَ صِفِّينَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -lafazh ini milik Ibnu Mutsanna keduanya berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dia berkata; Aku mendengar [Ibnu Abu Laila] Telah menceritakan kepada kami [Ali] bahwasanya Fatimah merasa sakit tangannya karena menumbuk tepung dan ketika itu ada seorang pelayan yang menawarkan dirinya kepada Rasulullah shallallahu 'alaihi wasallam. Fatimah datang menemui Rasulullah untuk meminta seorang pembantu. Tetapi ia tidak berhasil menemui Rasulullah dan hanya bertemu dengan Aisyah. Kemudian Fatimah menitip pesan kepada Aisyah untuk disampaikan kepada Rasulullah. Ketika Rasulullah tiba di rumah, Aisyah pun memberitahu beliau tentang kedatangan Fatimah. Ali bin Abu Thalib berkata; \"Lalu Rasulullah pergi ke rumah kami ketika kami tengah berbaring hendak tidur. Maka kami segera bangun, tetapi beliau mencegahnya seraya berkata: 'Tetaplah di tempat kalian! ' Kemudian Rasulullah duduk di antara kami hingga saya merasakan dinginnya telapak kaki beliau yang menyentuh dada saya. Setelah itu, Rasulullah bersabda: 'Inginkah kalian berdua aku ajarkan sesuatu yang lebih baik daripada apa yang kalian minta? Apabila kalian berbaring hendak tidur, maka bacalah takbir tiga puluh empat kali, tasbih tiga puluh tiga kali, dan tahmid tiga puluh tiga kali. Sesungguhnya yang demikian itu lebih baik bagi kalian daripada seorang pembantu.' Telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] Telah menceritakan kepada kami [Waki'] Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] Telah menceritakan kepada kami [Bapakku] Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepada kami [Ibnu Al Mutsanna] Telah menceritakan kepada kami [Ibnu Abu Adi] seluruhnya dari [Syu'bah] melalui sanad ini. Di dalam Hadits Mu'adz dengan menggunakan kalimat; Apabila 'kalian berbaring hendak tidur dimalam hari.' Telah menceritakan kepadaku [Zuhair bin Harb] Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah bin Abu Yazid] dari [Mujahid] dari [Ibnu Abu laila] dari [Ali bin Abu Thalib] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakannya kepada kami [Muhammad bin Abdullah bin Numair] dan [Ubaid bin Ya'isy] dari [Abdullah bin Numair] Telah menceritakan kepada kami [Abdul Malik] dari [Atha bin Abu Rabah] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ali] dari Nabi shallallahu 'alaihi wasallam yang sama dengan Hadits Al Hakam dari Ibnu Abu Laila. Di dalamnya ada tambahan; Ali berkata; 'Saya tidak pernah meninggalkan bacaan tersebut semenjak saya mendengarnya dari Rasulullah.' Seseorang bertanya kepadanya; 'Hai Ali, apakah kamu juga tidak meninggalkan doa ini pada malam perang Shiffin? ' Ali menjawab; 'Ya. Saya tidak pernah meninggalkan bacaan ini pada malam perang Shiffin sekalipun.' Sedangkan di dalam Hadits Atha dari Mujahid dari Ibnu Abu Laila dia berkata; aku bertanya kepada Ali; 'Apakah kamu juga tidak meninggalkan doa ini pada malam perang Shiffin? '"},"4558":{"ar":"حَدَّثَنِي أُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ فَاطِمَةَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ خَادِمًا وَشَكَتْ الْعَمَلَ فَقَالَ مَا أَلْفَيْتِيهِ عِنْدَنَا قَالَ أَلَا أَدُلُّكِ عَلَى مَا هُوَ خَيْرٌ لَكِ مِنْ خَادِمٍ تُسَبِّحِينَ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدِينَ ثَلَاثًا وَثَلَاثِينَ وَتُكَبِّرِينَ أَرْبَعًا وَثَلَاثِينَ حِينَ تَأْخُذِينَ مَضْجَعَكِو حَدَّثَنِيهِ أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا حَبَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سُهَيْلٌ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepadaku [Umayyah bin Bistham Al 'Aisyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh bin Al Qasim] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] bahwasanya Fathimah datang kepada Nabi shallallahu 'alaihi wasallam meminta seorang khadam (pelayan/pembantu) dan mengadukan bahwa dia terlalu payah bekerja. Jawab Nabi shallallahu 'alaihi wasallam: 'Engkau tidak akan mendapatkannya dari kami. Maukah engkau ku tunjukkan sesuatu yang lebih baik dari pada seorang khadam? Bacalah tasbih tiga puluh tiga kali, dan tahmid tiga puluh tiga kali, dan takbir tiga puluh empat kali ketika hendak tidur.' Dan telah menceritakannya kepadaku [Ahmad Ibnu Sa'id Ad Darimi] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Suhail] dengan sanad ini."},"4559":{"ar":"حَدَّثَنِي قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ صِيَاحَ الدِّيَكَةِ فَاسْأَلُوا اللَّهَ مِنْ فَضْلِهِ فَإِنَّهَا رَأَتْ مَلَكًا وَإِذَا سَمِعْتُمْ نَهِيقَ الْحِمَارِ فَتَعَوَّذُوا بِاللَّهِ مِنْ الشَّيْطَانِ فَإِنَّهَا رَأَتْ شَيْطَانًا","id":"Telah menceritakan kepadaku [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Apabila kamu mendengar kokok ayam jantan, maka mohonlah kemurahan dari Allah Subhanahu wa Ta'ala, karena pada saat itu ayam tersebut sedang melihat malaikat. Sebaliknya, apabila kamu mendengar ringkikan keledai, maka berlindunglah kepada Allah dari segala kejahatan syetan. Karena pada saat itu, keledai tersebut melihat syetan.\""},"4560":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَاللَّفْظُ لِابْنِ سَعِيدٍ قَالُوا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ عِنْدَ الْكَرْبِ لَا إِلَهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَاوَاتِ وَرَبُّ الْأَرْضِ وَرَبُّ الْعَرْشِ الْكَرِيمِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَحَدِيثُ مُعَاذِ بْنِ هِشَامٍ أَتَمُّ و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَبَا الْعَالِيَةِ الرِّيَاحِيَّ حَدَّثَهُمْ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهِنَّ وَيَقُولُهُنَّ عِنْدَ الْكَرْبِ فَذَكَرَ بِمِثْلِ حَدِيثِ مُعَاذِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ قَتَادَةَ غَيْرَ أَنَّهُ قَالَ رَبُّ السَّمَاوَاتِ وَالْأَرْضِ و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنِي يُوسُفُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا حَزَبَهُ أَمْرٌ قَالَ فَذَكَرَ بِمِثْلِ حَدِيثِ مُعَاذٍ عَنْ أَبِيهِ وَزَادَ مَعَهُنَّ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْكَرِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] dan ['Ubaidullah bin Sa'id] -dan lafadh ini milik Ibnu Sa'id- mereka berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Abul 'Aliyah] dari [Ibnu 'Abbas] bahwasanya Nabi shallallahu 'alaihi wasallam pernah berdoa ketika dalam kesulitan yaitu: \"LAA-ILAAHA ILLALLOOHUL 'AZHIIMUL HALIIM, LAA-ILAAHA ILLALLOOH ROBBUL'ARSYIL 'AZHIIM, LAA-ILAAHA ILLALLAH ROBBUSSAMAAWAATI WAROBBUL ARDHI WAROBBUL'ARSYIL KARIIMI \"Tiada sesembahan yang hak selain Allah Yang Maha Agung dan Maha Penyantun. Tiada Tuhan selain Allah, Tuhan Penguasa arsy yang agung. Tiada sesembahan yang hak selain Allah, Tuhan langit dan bumi serta Tuhan arasy yang mulia.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Hisyam] dengan sanad ini. Dan hadits Mu'adz bin Hisyam lebih sempurna. Dan telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Muhammad bin Bisyr Al 'Abdi] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] bahwasanya [Abul 'Aliyah Ar Riyahi] bercerita kepada mereka dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berdo'a dengan do'a tersebut ketika dalam kesulitan, -lalu dia menyebutkan redaksi yang sama dengan Hadits Mu'adz bin Hisyam dari Bapaknya dari Qatadah- namun dengan kalimat; 'Rabbus samawati wal Ardli' Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepadaku [Yusuf bin 'Abdullah bin Al Harits] dari [Abul 'Aliyah] dari [Ibnu 'Abbas] bahwasanya Nabi shallallahu 'alaihi wasallam Apabila menghadapi suatu masalah beliau mengucapkan; -lalu disebutkan redaksi yang serupa dengan Hadits Mu'adz dari Bapaknya, dengan tambahan; 'Laailaaha Illallah Rabbul Arsyil Karim.'"},"4561":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي عَبْدِ اللَّهِ الْجِسْرِيِّ عَنْ ابْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْكَلَامِ أَفْضَلُ قَالَ مَا اصْطَفَى اللَّهُ لِمَلَائِكَتِهِ أَوْ لِعِبَادِهِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu 'Abdullah Al Jisri] dari [Ibnu Ash Shamit] dari [Abu Dzar] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah ditanya orang: 'Apakah ucapan dzikir yang paling afdlal (utama), ya Rasulullah? ' Jawab beliau: 'Yaitu ucapan dzikir yang dipilihkan Allah bagi para malaikat-Nya dan hamba-hamba-Nya, ialah; Subhanalahi wa bihamdihi (Maha Suci Allah dan Maha Terpuji Dia).'"},"4562":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ عَنْ شُعْبَةَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عَبْدِ اللَّهِ الْجِسْرِيِّ مِنْ عَنَزَةَ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكَ بِأَحَبِّ الْكَلَامِ إِلَى اللَّهِ قُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِأَحَبِّ الْكَلَامِ إِلَى اللَّهِ فَقَالَ إِنَّ أَحَبَّ الْكَلَامِ إِلَى اللَّهِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Abu Bukair] dari [Syu'bah] dari [Al Jurairi] dari [Abu 'Abdullah Al Jisri] dari 'Anazah dari ['Abdullah bin Ash Shamit] dari [Abu Dzar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah bertanya kepada saya: 'Hai Abu Dzarr, maukah kamu aku beritahukan tentang ucapan yang disenangi Allah? ' Saya menjawab; 'Ya, saya mau ya Rasulullah. Beritahukanlah kepada saya tentang ucapan yang disenangi Allah.' Kemudian beliau bersabda: 'Sesungguhnya ucapan yang paling disukai Allah Azza Wa Jalla adalah Subhaanallahu wa bihamdih' (Mahasuci Allah dengan segala puji bagi-Nya).'"},"4563":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ عُمَرَ بْنِ حَفْصٍ الْوَكِيعِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا أَبِي عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ بْنِ كَرِيزٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ مُسْلِمٍ يَدْعُو لِأَخِيهِ بِظَهْرِ الْغَيْبِ إِلَّا قَالَ الْمَلَكُ وَلَكَ بِمِثْلٍ","id":"Telah menceritakan kepadaku [Ahmad bin 'Umar bin Hafsh Al Waki'i] telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami [bapakku] dari [Thalhah bin 'Ubaidullah bin Kariz] dari [Ummu Ad Darda'] dari [Abu Ad Darda'] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak ada seorang muslim pun yang mendoakan kebaikan bagi saudaranya (sesama muslim) yang berjauhan, melainkan malaikat akan mendoakannya pula: 'Dan bagimu kebaikan yang sama.'"},"4564":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا مُوسَى بْنُ سَرْوَانَ الْمُعَلِّمُ حَدَّثَنِي طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ بْنِ كَرِيزٍ قَالَ حَدَّثَتْنِي أُمُّ الدَّرْدَاءِ قَالَتْحَدَّثَنِي سَيِّدِي أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ دَعَا لِأَخِيهِ بِظَهْرِ الْغَيْبِ قَالَ الْمَلَكُ الْمُوَكَّلُ بِهِ آمِينَ وَلَكَ بِمِثْلٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadhr bin Syumail] telah menceritakan kepada kami [Musa bin Sarwan Al Mu'allim] telah menceritakan kepadaku [Thalhah bin 'Ubaidullah bin Kariz] dia berkata; telah menceritakan kepadaku [Ummu Ad Darda'] dia berkata; [Sayyidi (suamiku)] telah menceritakan kepadaku bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mendoakan kebaikan bagi saudaranya (sesama muslim) yang berjauhan, melainkan malaikat akan berkata; 'Amiin dan bagimu kebaikan yang sama.'"},"4565":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ صَفْوَانَ وَهُوَ ابْنُ عَبْدِ اللَّهِ بْنِ صَفْوَانَ وَكَانَتْ تَحْتَهُ الدَّرْدَاءُقَالَ قَدِمْتُ الشَّامَ فَأَتَيْتُ أَبَا الدَّرْدَاءِ فِي مَنْزِلِهِ فَلَمْ أَجِدْهُ وَوَجَدْتُ أُمَّ الدَّرْدَاءِ فَقَالَتْ أَتُرِيدُ الْحَجَّ الْعَامَ فَقُلْتُ نَعَمْ قَالَتْ فَادْعُ اللَّهَ لَنَا بِخَيْرٍ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ دَعْوَةُ الْمَرْءِ الْمُسْلِمِ لِأَخِيهِ بِظَهْرِ الْغَيْبِ مُسْتَجَابَةٌ عِنْدَ رَأْسِهِ مَلَكٌ مُوَكَّلٌ كُلَّمَا دَعَا لِأَخِيهِ بِخَيْرٍ قَالَ الْمَلَكُ الْمُوَكَّلُ بِهِ آمِينَ وَلَكَ بِمِثْلٍ قَالَ فَخَرَجْتُ إِلَى السُّوقِ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَقَالَ لِي مِثْلَ ذَلِكَ يَرْوِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami ['Isa bin Yunus] telah menceritakan kepada kami ['Abdul Malik bin Abu Sulaiman] dari [Abu Az Zubair] dari [Shafwan bin 'Abdullah bin Shafwan] dan riwayat selanjutnya adalah dari [Ummu Darda'], dia berkata; \"Saya pernah pergi ke Syam dan mengunjungi Abu Darda' di rumahnya. Namun saya tidak bertemu dengannya, lalu saya pergi menjumpai Ummu Darda'. Setelah itu, Ummu Darda' bertanya kepada saya; 'Hai Shafwan, apakah kamu akan pergi haji pada tahun ini? ' Saya pun menjawab; 'Ya.' Ummu Darda' berkata; 'Mohonkanlah kepada Allah kebaikan untuk kami, karena Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Doa seorang muslim untuk saudaranya sesama muslim dari kejauhan tanpa diketahui olehnya akan dikabulkan. Di atas kepalanya ada malaikat yang telah diutus, dan setiap kali ia berdoa untuk kebaikan, maka malaikat yang diutus tersebut akan mengucapkan 'Amin dan kamu juga akan mendapatkan seperti itu.' Shafwan berkata; 'Setelah itu saya pergi ke pasar dan di sana saya bertemu dengan [Abu Darda']. Ternyata ia pun mengatakan seperti itu kepada saya yang diriwayatkannya dari Nabi Muhammad shallallahu 'alaihi wasallam. Dan telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari ['Abdul Malik bin Abu Sulaiman] melalui sanad ini dengan Hadits yang serupa. dia berkata; dari Shafwan bin 'Abdullah bin Shafwan."},"4566":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَاللَّفْظُ لِابْنِ نُمَيْرٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ وَمُحَمَّدُ بْنُ بِشْرٍ عَنْ زَكَرِيَّاءَ بْنِ أَبِي زَائِدَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيَرْضَى عَنْ الْعَبْدِ أَنْ يَأْكُلَ الْأَكْلَةَ فَيَحْمَدَهُ عَلَيْهَا أَوْ يَشْرَبَ الشَّرْبَةَ فَيَحْمَدَهُ عَلَيْهَاو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ حَدَّثَنَا زَكَرِيَّاءُ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Numair] -dan lafadh ini milik Ibnu Numair- mereka berkata; telah menceritakan kepada kami [Abu Usamah] dan [Muhammad bin Bisyr] dari [Zakariya bin Abu Zaidah] dari [Sa'id bin Abu Burdah] dari [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya Allah Ta'ala sangat suka kepada hamba-Nya yang mengucapkan tahmid (Alhamdulillah) sesudah makan dan minum.\" Dan telah menceritakannya kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] telah menceritakan kepada kami [Zakariya] dengan sanad ini."},"4567":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى ابْنِ أَزْهَرَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسْتَجَابُ لِأَحَدِكُمْ مَا لَمْ يَعْجَلْ فَيَقُولُ قَدْ دَعَوْتُ فَلَا أَوْ فَلَمْ يُسْتَجَبْ لِي","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; aku membacakan kepada [Malik] dari [Ibnu Syihab] dari [Abu 'Ubaid] maula Ibnu Azhar dari [Abu Hurairah] bahwasanya Rasululullah shallallahu 'alaihi wasallam bersabda: Doa seseorang dari kalian akan senantiasa dikabulkan selama ia tidak tergesa-gesa hingga mengatakan; 'Aku telah berdoa kepada Rabbku, namun tidak atau belum juga dikabulkan untukku'."},"4568":{"ar":"حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ لَيْثٍ حَدَّثَنِي أَبِي عَنْ جَدِّي حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ حَدَّثَنِي أَبُو عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَكَانَ مِنْ الْقُرَّاءِ وَأَهْلِ الْفِقْهِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْتَجَابُ لِأَحَدِكُمْ مَا لَمْ يَعْجَلْ فَيَقُولُ قَدْ دَعَوْتُ رَبِّي فَلَمْ يَسْتَجِبْ لِي","id":"Telah menceritakan kepadaku ['Abdul Malik bin Syu'aib bin Laits] telah menceritakan kepadaku [bapakku] dari [kakekku]; telah menceritakan kepadaku ['Uqail bin Khalid] dari [Ibnu Syihab] bahwasanya ia berkata; Telah menceritakan kepadaku [Abu Ubaid] budak Abdurrahman bin Auf yang mana dia termasuk dari para Qari (penghafal qur'an) dan Ahli fikih, dia berkata; Aku mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Doa seseorang dari kalian akan senantiasa dikabulkan selama ia tidak tergesa-gesa hingga mengatakan; 'Aku telah berdoa kepada Rabbku, namun Dia belum juga mengabulkan untukku'."},"4569":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مُعَاوِيَةُ وَهُوَ ابْنُ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَزَالُ يُسْتَجَابُ لِلْعَبْدِ مَا لَمْ يَدْعُ بِإِثْمٍ أَوْ قَطِيعَةِ رَحِمٍ مَا لَمْ يَسْتَعْجِلْ قِيلَ يَا رَسُولَ اللَّهِ مَا الِاسْتِعْجَالُ قَالَ يَقُولُ قَدْ دَعَوْتُ وَقَدْ دَعَوْتُ فَلَمْ أَرَ يَسْتَجِيبُ لِي فَيَسْتَحْسِرُ عِنْدَ ذَلِكَ وَيَدَعُ الدُّعَاءَ","id":"Telah menceritakan kepadaku [Abu Ath Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Mu'awiyah bin Shalih] dari [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Doa seseorang senantiasa akan dikabulkan selama ia tidak berdoa untuk perbuatan dosa ataupun untuk memutuskan tali silaturahim dan tidak tergesa-gesa.\" Seorang sahabat bertanya; 'Ya Rasulullah, apakah yang dimaksud dengan tergesa-gesa? ' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Yang dimaksud dengan tergesa-gesa adalah apabila orang yang berdoa itu mengatakan; 'Aku telah berdoa dan terus berdoa tetapi belum juga dikabulkan'. Setelah itu, ia merasa putus asa dan tidak pernah berdoa lagi.'"},"4570":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ الْعَنْبَرِيُّ ح و حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ كُلُّهُمْ عَنْ سُلَيْمَانَ التَّيْمِيِّ ح و حَدَّثَنَا أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ وَاللَّفْظُ لَهُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْتُ عَلَى بَابِ الْجَنَّةِ فَإِذَا عَامَّةُ مَنْ دَخَلَهَا الْمَسَاكِينُ وَإِذَا أَصْحَابُ الْجَدِّ مَحْبُوسُونَ إِلَّا أَصْحَابَ النَّارِ فَقَدْ أُمِرَ بِهِمْ إِلَى النَّارِ وَقُمْتُ عَلَى بَابِ النَّارِ فَإِذَا عَامَّةُ مَنْ دَخَلَهَا النِّسَاءُ","id":"Telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammad bin Salamah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Mu'adz bin Mu'adz Al 'Anbari] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Muhammad bin 'Abdul A'la] telah menceritakan kepada kami [Mu'tamir] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] semuanya dari [Sulaiman At Taimi] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Abu Kamil Fudhail bin Husain] -dan lafadh ini miliknya-; telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [At Taimi] dari [Abu 'Utsman] dari [Usamah bin Zaid] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Aku berdiri di pintu surga, maka kulihat orang-orang yang masuk ke dalamnya kebanyakan dari orang-orang miskin. Sedangkan orang-orang yang bernasib baik di dunia mereka tertahan di luar. Kecuali penduduk neraka mereka langsung diperintahkan masuk ke neraka. Dan aku berdiri pula di pintu neraka, kulihat orang yang masuk kebanyakannya ialah kaum wanita.'"},"4571":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُاقَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَ وَاطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الثَّقَفِيُّ أَخْبَرَنَا أَيُّوبُ بِهَذَا الْإِسْنَادِ و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعَ فِي النَّارِ فَذَكَرَ بِمِثْلِ حَدِيثِ أَيُّوبَ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ سَمِعَ أَبَا رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Abu Raja' Al 'Utharidi] dia berkata; aku mendengar [Ibnu 'Abbas] berkata; Muhammad shallallahu 'alaihi wasallam bersabda: 'Aku melihat surga, maka terlihat olehku kebanyakan penghuninya ialah orang yang miskin. Dan aku menengok pula ke neraka, maka kelihatan olehku kebanyakan penghuninya ialah kaum wanita.' Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Ats Tsaqafi] telah mengabarkan kepada kami [Ayyub] dengan sanad ini. Dan telah menceritakan kepada kami [Syaiban bin Furrukh] telah menceritakan kepada kami [Abul Asyhab] telah menceritakan kepada kami [Abu Raja'] dari [Ibnu 'Abbas] bahwasanya Nabi shallallahu 'alaihi wasallam menengok ke neraka, -lalu dia menyebutkan redaksi yang serupa dengan Hadits Ayyub. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] dari [Sa'id bin Abu 'Arubah] dia mendengar [Abu Raja'] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: -dengan redaksi yang sama.-"},"4572":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَ��ِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَكَانَ لِمُطَرِّفِ بْنِ عَبْدِ اللَّهِ امْرَأَتَانِ فَجَاءَ مِنْ عِنْدِ إِحْدَاهُمَا فَقَالَتْ الْأُخْرَى جِئْتَ مِنْ عِنْدِ فُلَانَةَ فَقَالَ جِئْتُ مِنْ عِنْدِ عِمْرَانَ بْنِ حُصَيْنٍ فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَقَلَّ سَاكِنِي الْجَنَّةِ النِّسَاءُو حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ بْنِ عَبْدِ الْحَمِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ أَنَّهُ كَانَتْ لَهُ امْرَأَتَانِ بِمَعْنَى حَدِيثِ مُعَاذٍ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dia berkata; [Muthatrrif bin 'Abdullah] memiliki dua orang istri, suatu ketika dia pulang dari salah satu istrinya, lalu salah satu istrinya lagi bertanya kepadanya; Apakah kamu baru pulang dari fulanah? Dia menjawab: Aku baru dari ['Imran bin Hushain], dia telah menceritakan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bahwa kaum wanita adalah penghuni surga yang paling sedikit.\" Dan telah menceritakan kepada kami [Muhammad bin Al Walid bin 'Abdul Hamid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dia berkata; aku mendengar [Mutharrif] bercerita bahwasanya ia memiliki dua orang istri, -yang semakna dengan hadits Mu'adz.-"},"4573":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ أَبُو زُرْعَةَ حَدَّثَنَا ابْنُ بُكَيْرٍ حَدَّثَنِي يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكَانَ مِنْ دُعَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ زَوَالِ نِعْمَتِكَ وَتَحَوُّلِ عَافِيَتِكَ وَفُجَاءَةِ نِقْمَتِكَ وَجَمِيعِ سَخَطِكَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin 'Abdul Karim Abu Zur'ah] telah menceritakan kepada kami [Ibnu Bukair] telah menceritakan kepadaku [Ya'qub bin 'Abdurrahman] dari [Musa bin 'Uqbah] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar] dia berkata; \"Diantara doa Rasulullah shallallahu 'alaihi wasallam adalah: 'ALLOOHUMMA INNII A'UUDZU BIKA MIN ZAWAALI NI'MATIKA, WATAHAWWULI 'AAFIYATIKA, WAFAJAA'ATI NIQMATIKA, WAJAMII'I SAKHOTHIKA \"Ya Allah, sesungguhnya aku berlindung kepada-Mu dari hilangnya kenikmatan yang telah Engkau berikan, dari lepasnya kesehatan yang telah Engkau anugerahkan, dari siksa-Mu yang datang secara tiba-tiba, dan dari segala kemurkaan-Mu.'\""},"4574":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ وَمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَرَكْتُ بَعْدِي فِتْنَةً هِيَ أَضَرُّ عَلَى الرِّجَالِ مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Sufyan] dan [Mu'tamir bin Sulaiman] dari [Sulaiman At Taimi] dari [Abu 'Utsman An Nahdi] dari [Usamah bin Zaid] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sepeninggalku, tidak ada (sumber) bencana yang lebih besar bagi laki-laki selain dari pada wanita.'"},"4575":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى جَمِيعًا عَنْ الْمُعْتَمِرِ قَالَ ابْنُ مُعَاذٍ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ قَالَ أَبِي حَدَّثَنَا أَبُو عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدِ بْنِ حَارِثَةَ وَسَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ أَنَّهُمَا حَدَّثَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا تَرَكْتُ بَعْدِي فِي النَّاسِ فِتْنَةً أَضَرَّ عَلَى الرِّجَالِ مِنْ النِّسَاءِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ كُلُّهُمْ عَنْ سُلَيْمَانَ التَّيْمِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] dan [Suwaid bin Sa'id] dan [Muhammad bin 'Abdul A'la] semuanya dari [Mu'tamir], Ibnu Mu'adz berkata; telah menceritakan kepada kami Al Mu'tamir bin Sulaiman dia berkata; [Bapakku] berkata; telah menceritakan kepada kami [Abu 'Utsman] dari [Usamah bin Zaid bin Haritsah] dan [Sa'id bin Zaid bin 'Amru bin Nufail] bahwasanya keduanya menceritakan kepada kami dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Sepeninggalku, tidak ada (sumber) bencana yang lebih besar bagi laki-laki selain dari pada wanita.' Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Numair] dia berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] semuanya dari [Sulaiman At Taimi] melalui sanad ini, dengan Hadits yang serupa."},"4576":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مَسْلَمَةَ قَالَ سَمِعْتُ أَبَا نَضْرَةَ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدُّنْيَا حُلْوَةٌ خَضِرَةٌ وَإِنَّ اللَّهَ مُسْتَخْلِفُكُمْ فِيهَا فَيَنْظُرُ كَيْفَ تَعْمَلُونَ فَاتَّقُوا الدُّنْيَا وَاتَّقُوا النِّسَاءَ فَإِنَّ أَوَّلَ فِتْنَةِ بَنِي إِسْرَائِيلَ كَانَتْ فِي النِّسَاءِوَفِي حَدِيثِ ابْنِ بَشَّارٍ لِيَنْظُرَ كَيْفَ تَعْمَلُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Maslamah] dia berkata; aku mendengar [Abu Nadlrah] bercerita dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dunia itu manis. Dan sesungguhnya Allah telah menguasakannya kepadamu sekalian. Kemudian Allah menunggu (memperhatikan) apa yang kamu kerjakan (di dunia itu). Karena itu takutilah dunia dan takutilah wanita, karena sesungguhnya sumber bencana Bani Isarail adalah wanita.\" Sedangkan di dalam Hadits Ibnu Basyar menggunakan kalimat; 'liyandlur kaifa ta'malun.' (Kemudian Allah (memperhatikan) apa yang kamu kerjakan (di dunia itu).'"},"4577":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ الْمُسَيَّبِيُّ حَدَّثَنِي أَنَسٌ يَعْنِي ابْنَ عِيَاضٍ أَبَا ضَمْرَةَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ بَيْنَمَا ثَلَاثَةُ نَفَرٍ يَتَمَشَّوْنَ أَخَذَهُمْ الْمَطَرُ فَأَوَوْا إِلَى غَارٍ فِي جَبَلٍ فَانْحَطَّتْ عَلَى فَمِ غَارِهِمْ صَخْرَةٌ مِنْ الْجَبَلِ فَانْطَبَقَتْ عَلَيْهِمْ فَقَالَ بَعْضُهُمْ لِبَعْضٍ انْظُرُوا أَعْمَالًا عَمِلْتُمُوهَا صَالِحَةً لِلَّهِ فَادْعُوا اللَّهَ تَعَالَى بِهَا لَعَلَّ اللَّهَ يَفْرُجُهَا عَنْكُمْ فَقَالَ أَحَدُهُمْ اللَّهُمَّ إِنَّهُ كَانَ لِي وَالِدَانِ شَيْخَانِ كَبِيرَانِ وَامْرَأَتِي وَلِي صِبْيَةٌ صِغَارٌ أَرْعَى عَلَيْهِمْ فَإِذَا أَرَحْتُ عَلَيْهِمْ حَلَبْتُ فَبَدَأْتُ بِوَالِدَيَّ فَسَقَيْتُهُمَا قَبْلَ بَنِيَّ وَأَنَّهُ نَأَى بِي ذَاتَ يَوْمٍ الشَّجَرُ فَلَمْ آتِ حَتَّى أَمْسَيْتُ فَوَجَدْتُهُمَا قَدْ نَامَا فَحَلَبْتُ كَمَا كُنْتُ أَحْلُبُ فَجِئْتُ بِالْحِلَابِ فَقُمْتُ عِنْدَ رُءُوسِهِمَا أَكْرَهُ أَنْ أُوقِظَهُمَا مِنْ نَوْمِهِمَا وَأَكْرَهُ أَنْ أَسْقِيَ الصِّبْيَةَ قَبْلَهُمَا وَالصِّبْيَةُ يَتَضَاغَوْنَ عِنْدَ قَدَمَيَّ فَلَمْ يَزَلْ ذَلِكَ دَأْبِي وَدَأْبَهُمْ حَتَّى طَلَعَ الْفَجْرُ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا مِنْهَا فُرْجَةً نَرَى مِنْهَا السَّمَاءَ فَفَرَجَ اللَّهُ مِنْهَا فُرْجَةً فَرَأَوْا مِنْهَا السَّمَاءَ وَقَالَ الْآخَرُ اللَّهُمَّ إِنَّهُ كَانَتْ لِيَ ابْنَةُ عَمٍّ أَحْبَبْتُهَا كَأَشَدِّ مَا يُحِبُّ الرِّجَالُ النِّسَاءَ وَطَلَبْتُ إِلَيْهَا نَفْسَهَا فَأَبَتْ حَتَّى آتِيَهَا بِمِائَةِ دِينَارٍ فَتَعِبْتُ حَتَّى جَمَعْتُ مِائَةَ دِينَارٍ فَجِئْتُهَا بِهَا فَلَمَّا وَقَعْتُ بَيْنَ رِجْلَيْهَا قَالَتْ يَا عَبْدَ اللَّهِ اتَّقِ اللَّهَ وَلَا تَفْتَحْ الْخَاتَمَ إِلَّا بِحَقِّهِ فَقُمْتُ عَنْهَا فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا مِنْهَا فُرْجَةً فَفَرَجَ لَهُمْ وَقَالَ الْآخَرُ اللَّهُمَّ إِنِّي كُنْتُ اسْتَأْجَرْتُ أَجِيرًا بِفَرَقِ أَرُزٍّ فَلَمَّا قَضَى عَمَلَهُ قَالَ أَعْطِنِي حَقِّي فَعَرَضْتُ عَلَيْهِ فَرَقَهُ فَرَغِبَ عَنْهُ فَلَمْ أَزَلْ أَزْرَعُهُ حَتَّى جَمَعْتُ مِنْهُ بَقَرًا وَرِعَاءَهَا فَجَاءَنِي فَقَالَ اتَّقِ اللَّهَ وَلَا تَظْلِمْنِي حَقِّي قُلْتُ اذْهَبْ إِلَى تِلْكَ الْبَقَرِ وَرِعَائِهَا فَخُذْهَا فَقَالَ اتَّقِ اللَّهَ وَلَا تَسْتَهْزِئْ بِي فَقُلْتُ إِنِّي لَا أَسْتَهْزِئُ بِكَ خُذْ ذَلِكَ الْبَقَرَ وَرِعَاءَهَا فَأَخَذَهُ فَذَهَبَ بِهِ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا مَا بَقِيَ فَفَرَجَ اللَّهُ مَا بَقِيَو حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ ح و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنِي أَبُو كُرَيْبٍ وَمُحَمَّدُ بْنُ طَرِيفٍ الْبَجَلِيُّ قَالَا حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا أَبِي وَرَقَبَةُ بْنُ مَسْقَلَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَحَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالُوا حَدَّثَنَا يَعْقُوبُ يَعْنُونَ ابْنَ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ كُلُّهُمْ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ أَبِي ضَمْرَةَ عَنْ مُوسَى بْنِ عُقْبَةَ وَزَادُوا فِي حَدِيثِهِمْ وَخَرَجُوا يَمْشُونَ وَفِي حَدِيثِ صَالِحٍ يَتَمَاشَوْنَ إِلَّا عُبَيْدَ اللَّهِ فَإِنَّ فِي حَدِيثِهِ وَخَرَجُوا وَلَمْ يَذْكُرْ بَعْدَهَا شَيْئًا حَدَّثَنِي مُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ وَعَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ بِهْرَامَ وَأَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ ابْنُ سَهْلٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ انْطَلَقَ ثَلَاثَةُ رَهْطٍ مِمَّنْ كَانَ قَبْلَكُمْ حَتَّى آوَاهُمْ الْمَبِيتُ إِلَى غَارٍ وَاقْتَصَّ الْحَدِيثَ بِمَعْنَى حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ غَيْرَ أَنَّهُ قَالَ قَالَ رَجُلٌ مِنْهُمْ اللَّهُمَّ كَانَ لِي أَبَوَانِ شَيْخَانِ كَبِيرَانِ فَكُنْتُ لَا أَغْبِقُ قَبْلَهُمَا أَهْلًا وَلَا مَالًا وَقَالَ فَامْتَنَعَتْ مِنِّي حَتَّى أَلَمَّتْ بِهَا سَنَةٌ مِنْ السِّنِينَ فَجَاءَتْنِي فَأَعْطَيْتُهَا عِشْرِينَ وَمِائَةَ دِينَارٍ وَقَالَ فَثَمَّرْتُ أَجْرَهُ حَتَّى كَثُرَتْ مِنْهُ الْأَمْوَالُ فَارْتَعَجَتْ وَقَالَ فَخَرَجُوا مِنْ الْغَارِ يَمْشُونَ","id":"Telah menceritakan kepadaku [Muhammad bin Ishaq Al Musayyabi]; telah menceritakan kepadaku [Anas bin 'Iyadl Abu Dlamrah] dari [Musa bin 'Uqbah] dari [Nafi'] dari ['Abdullah bin 'Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Ketika tiga orang laki-laki sedang berjalan, tiba-tiba hujan turun hingga mereka berlindung ke dalam sebuah gua yang terdapat di suatu gunung. Tanpa diduga sebelumnya, ada sebuah batu besar jatuh menutup mulut goa dan mengurung mereka di dalamnya. Kemudian salah seorang dari mereka berkata kepada temannya yang lain; 'lngat-ingatlah amal shalih yang pernah kalian lakukan hanya karena mencari ridla Allah semata. Setelah itu, berdoa dan memohonlah pertolongan kepada Allah dengan perantaraan amal shalih tersebut, mudah-mudahan Allah akan menghilangkan kesulitan kalian. Tak lama kemudian salah seorang dari mereka berkata; 'Ya Allah ya Tuhanku, dulu saya mempunyai dua orang tua yang sudah lanjut usia. Selain itu, saya juga mempunyai seorang istri dan beberapa orang anak yang masih kecil. Saya menghidupi mereka dengan menggembalakan ternak. Apabila pulang dari menggembala, saya pun segera memerah susu dan saya dahulukan untuk kedua orang tua saya. Lalu saya berikan air susu tersebut kepada kedua orang tua saya sebelum saya berikan kepada anak-anak saya. Pada suatu ketika, tempat penggembalaan saya jauh, hingga saya pun baru pulang pada sore hari. Kemudian saya dapati kedua orang tua saya sedang tertidur pulas. Lalu, seperti biasa, saya segera memerah susu dan setelah itu saya membawanya ke kamar kedua orang tua saya. Saya berdiri di dekat keduanya serta tidak membangunkan mereka dari tidur. Akan tetapi, saya juga tidak ingin memberikan air susu tersebut kepada anak-anak saya sebelum diminum oleh kedua orang tua saya, meskipun mereka, anak-anak saya, telah berkerumun di telapak kaki saya untuk meminta minum karena rasa lapar yang sangat. Keadaan tersebut saya dan anak-anak saya jalankan dengan sepenuh hati hingga terbit fajar. Ya Allah, jika Engkau tahu bahwasanya saya melakukan perbuatan tersebut hanya untuk mengharap ridla-Mu, maka bukakanlah suatu celah untuk kami hingga kami dapat melihat cahaya! ' Akhirnya Allah Subhanahu wa Ta'ala membuka celah lubang gua tersebut, berkat adanya amal perbuatan baik tersebut, hingga mereka dapat melihat langit. Salah seorang dari mereka berdiri sambil berkata; 'Ya Allah ya Tuhanku, dulu saya mempunyai seorang sepupu perempuan (anak perempuan paman) yang saya sukai sebagaimana sukanya kaum laki-laki yang menggebu-gebu terhadap kaum wanita. Pada suatu ketika saya pernah mengajaknya untuk berbuat mesum, tetapi ia menolak hingga saya dapat memberinya uang seratus dinar. Setelah bersusah payah mengumpulkan uang seratus dinar, akhirnya saya pun mampu memberikan uang tersebut kepadanya. Ketika saya berada diantara kedua pahanya (telah siap untuk menggaulinya), tiba-tiba ia berkata; 'Hai hamba Allah, takutlah kepada Allah dan janganlah kamu membuka cincin (menggauliku) kecuali setelah menjadi hakmu.' Lalu saya bangkit dan meninggalkannya. Ya Allah ya Tuhanku, sesungguhnya Engkau pun tahu bahwasanya saya melakukan hal itu hanya untuk mengharapkan ridhla-Mu. Oleh karena itu, bukakanlah suatu celah lubang untuk kami! ' Akhirnya Allah Subhanahu wa Ta'ala membukakan sedikit celah lubang lagi untuk mereka bertiga. Seorang lagi berdiri dan berkata; 'Ya Allah ya Tuhanku, dulu saya pernah menyuruh seseorang untuk mengerjakan sawah saya dengan cara bagi hasil. Ketika ia telah menyelesaikan pekerjaannya, ia pun berkata; 'Berikanlah hak saya kepada saya! ' Namun saya tidak dapat memberikan kepadanya haknya tersebut hingga ia merasa sangat jengkel. Setelah itu, saya pun menanami sawah saya sendiri hingga hasilnya dapat saya kumpulkan untuk membeli beberapa ekor sapi dan menggaji beberapa penggembalanya. Selang berapa lama kemudian, orang yang haknya dahulu tidak saya berikan datang kepada saya dan berkata; 'Takutlah kamu kepada Allah dan janganlah berbuat zhalim terhadap hak orang lain! ' Lalu saya berkata kepada orang tersebut; 'Pergilah ke beberapa ekor sapi beserta para penggembalanya itu dan ambillah semuanya untukmu! ' Orang tersebut menjawab; 'Takutlah kepada Allah dan janganlah kamu mengolok-olok saya! ' Kemudian saya katakan lagi kepadanya; 'Sungguh saya tidak bermaksud mengolok-olokmu. Oleh karena itu, ambillah semua sapi itu beserta para pengggembalanya untukmu! ' Akhirnya orang tersebut memahaminya dan membawa pergi semua sapi itu. Ya Allah, sesungguhnya Engkau telah mengetahui bahwa apa yang telah saya lakukan dahulu adalah hanya untuk mencari ridla-Mu. Oleh karena itu, bukalah bagian pintu goa yang belum terbuka! ' Akhirnya Allah pun membukakan sisanya, hingga mereka dapat keluar dari dalam goa yang tertutup oleh batu besar tersebut.\" Dan telah menceritakan kepada kami [Ishaq bin Manshur] dan [Abad bin Humaid] keduanya berkata; Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] Telah mengabarkan kepadaku [Musa bin Uqbah] Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepadaku [Suwaid bin Sa'id] Telah menceritakan kepada kami [Ali bin Mushir] dari [Ubaidullah] Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepadaku [Abu Kuraib] dan [Muhammad bin Tharif Al Bajali] keduanya berkata; Telah menceritakan kepada kami [Ibnu Fudlail] Telah menceritakan kepada kami [Bapakku] dan [Raqabahh bin Masqalah] Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepadaku [Zuhair bin Harb] dan [Hasan Al Hulwani] dan [Abad bin Humaid] mereka berkata; Telah menceritakan kepada kami [Ya'qub] yaitu Ibnu Ibrahim bin Sa'ad, telah menceritakan kepada kami [Bapakku] dari [Shalih bin Kaisan] semuanya dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam yang semakna dengan Hadits Abu Dlamrah dari Musa bin Uqbah, dan mereka menambahkan di dalam Haditsnya; 'kemudian mereka berjalan keluar.' Sedangkan di dalam Hadits Abu Shalih dengan menggunakan lafazh; 'Yatamasyauna' (saling berjalan). Kecuali Ubaidullah yang di dalam Haditsnya hanya menggunakan lafazh; wa kharaju saja tanpa ada kalimat setelahnya. Telah menceritakan kepadaku [Muhammad bin Sahl At Tamimi] dan ['Abdullah bin 'Abdurrahman bin Bihram] dan [Abu Bakr bin Ishaq]; [Ibnu Sahl] berkata; telah menceritakan kepada kami, dan berkata yang lain; telah mengabarkan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Salim bin 'Abdullah] bahwasanya ['Abdullah bin 'Umar] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Ada tiga orang utusan sebelum kalian, hingga akhirnya mereka bermalam di sebuah gua.' Lalu dia menceritakan Hadits tersebut yang semakna dengan Hadits Nafi dari Ibnu Umar. Namun dia berkata dengan redaksi; 'salah seorang dari mereka berkata; Ya Allah, aku mempunya kedua orang tua yang sudah tua renta, aku tidak pernah memberikan air minum disore hari kepada keluargaku atau hewan ternakku sebelum memberikan kepada keduanya terlebih dahulu. -Juga dengan redaksi; - lalu wanita itu menolakku hingga suatu ketika terjadi musim paceklik, dan wanita itu datang kembali kepadaku, kemudian aku memberinya uang sebesar seratus dua puluh dinar.' -Juga dengan redaksi; - 'lalu aku mengumpulkan upahnya, hingga aku merasa kaget, karena uang tersebut sudah berkembang menjadi banyak. -Juga dengan redaksi; - 'kemudian mereka berjalan keluar dari gua.'"},"4578":{"ar":"حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ حَيْثُ يَذْكُرُنِي وَاللَّهِ لَلَّهُ أَفْرَحُ بِتَوْبَةِ عَبْدِهِ مِنْ أَحَدِكُمْ يَجِدُ ضَالَّتَهُ بِالْفَلَاةِ وَمَنْ تَقَرَّبَ إِلَيَّ شِبْرًا تَقَرَّبْتُ إِلَيْهِ ذِرَاعًا وَمَنْ تَقَرَّبَ إِلَيَّ ذِرَاعًا تَقَرَّبْتُ إِلَيْهِ بَاعًا وَإِذَا أَقْبَلَ إِلَيَّ يَمْشِي أَقْبَلْتُ إِلَيْهِ أُهَرْوِلُ","id":"Telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepada kami [Hafsh bin Maisarah] telah menceritakan kepadaku [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: 'Allah ta'ala berfirman: Aku bersama persangkaan hamba-Ku kepada-Ku, dan Aku bersamanya ketika dia mengingat-Ku. Demi Allah, Allah Ta'ala sangat gembira menerima taubat seseorang kamu, melebihi kegembiraan seseorang yang menemukan kembali barangnya yang hilang di suatu tempat yang luas. Barangsiapa mendekat kepada-Ku sejengkal, maka Aku akan mendekat kepadanya sehasta. Apabila ia mendekat kepada-Ku sehasta, maka Aku akan mendekat kepadanya sedepa. Apabila ia datang kepada-Ku dengan berjalan, maka Aku akan datang kepadanya dengan berlari.'"},"4579":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ الْقَعْنَبِيُّ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ أَحَدِكُمْ مِنْ أَحَدِكُمْ بِضَالَّتِهِ إِذَا وَجَدَهَاو حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ","id":"Telah menceritakan kepadaku ['Abdullah bin Maslamah bin Qa'nab Al Qa'nabi] telah menceritakan kepada kami [Al Mughirah bin 'Abdurrahman Al Hizami] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Allah Ta'ala sangat gembira menerima taubat seseorang kamu, melebihi kegembiraan seseorang yang menemukan kembali barangnya yang hilang.\" Dan telah menceritakan kepada kami [Muhammad bin Rafi'] Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang semakna."},"4580":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِعُثْمَانَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ قَالَدَخَلْتُ عَلَى عَبْدِ اللَّهِ أَعُودُهُ وَهُوَ مَرِيضٌ فَحَدَّثَنَا بِحَدِيثَيْنِ حَدِيثًا عَنْ نَفْسِهِ وَحَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ الْمُؤْمِنِ مِنْ رَجُلٍ فِي أَرْضٍ دَوِّيَّةٍ مَهْلِكَةٍ مَعَهُ رَاحِلَتُهُ عَلَيْهَا طَعَامُهُ وَشَرَابُهُ فَنَامَ فَاسْتَيْقَظَ وَقَدْ ذَهَبَتْ فَطَلَبَهَا حَتَّى أَدْرَكَهُ الْعَطَشُ ثُمَّ قَالَ أَرْجِعُ إِلَى مَكَانِيَ الَّذِي كُنْتُ فِيهِ فَأَنَامُ حَتَّى أَمُوتَ فَوَضَعَ رَأْسَهُ عَلَى سَاعِدِهِ لِيَمُوتَ فَاسْتَيْقَظَ وَعِنْدَهُ رَاحِلَتُهُ وَعَلَيْهَا زَادُهُ وَطَعَامُهُ وَشَرَابُهُ فَاللَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ الْعَبْدِ الْمُؤْمِنِ مِنْ هَذَا بِرَاحِلَتِهِ وَزَادِهِو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ قُطْبَةَ بْنِ عَبْدِ الْعَزِيزِ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَقَالَ مِنْ رَجُلٍ بِدَاوِيَّةٍ مِنْ الْأَرْضِ و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا عُمَارَةُ بْنُ عُمَيْرٍ قَالَ سَمِعْتُ الْحَارِثَ بْنَ سُوَيْدٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ حَدِيثَيْنِ أَحَدُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ عَنْ نَفْسِهِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ الْمُؤْمِنِ بِمِثْلِ حَدِيثِ جَرِيرٍ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] -dan lafadh ini milik 'Utsman- Ishaq berkata; telah mengabarkan kepada kami, dan 'Utsman berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Al Harits bin Suwaid] dia berkata; \"Saya pernah datang berkunjung ke rumah Abdullah untuk menjenguknya ketika ia sedang sakit. Lalu ia menuturkan kepada saya tentang dua hal: yang satu tentang dirinya dan yang satu lagi mengenai Rasulullah shallallahu 'alaihi wasallam.\" [Abdullah] berkata; 'Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Allah merasa bergembira karena taubatnya seorang hamba yang beriman melebihi kegembiraan seseorang berada di gurun sahara yang mencekam dengan ditemani hewan tunggangannya serta perbekalan makanan dan minuman, kemudian ia tertidur. Ketika ia terbangun dari tidurnya, ternyata hewan tunggangannya terlepas dengan membawa perbekalan makanan dan minumannya. Kemudian orang tersebut mencari hewan tunggangannya tersebut ke sana kemari hingga ia merasa haus. Setelah itu, ia pun berkata; 'Sebaiknya aku kembali saja ke tempat tidurku semula sampai aku mati.' Tak lama kemudian orang tersebut telah membaringkan tubuhnya dengan meletakkan kepalanya di atas lengannya dan bersiap-siap untuk mati. Ketika ia terbangun, ternyata hewan tunggangannya itu telah berada di sisinya dengan membawa bekal makanan dan minumannya. Sunguh ke gembiraan Allah karena taubatnya seorang hamba-Nya yang beriman melebihi kegembiraan orang yang hewan tunggangannya terlepas lalu kembali dengan membawa perbekalan makanan dan minumannya ini.\" Dan telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Quthbah bin 'Abdul 'Aziz] dari [Al A'masy] dengan sanad ini, dan dia berkata; dari seorang laki-laki yang berada di sebuah gurun yang mencekam.' Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami ['Umarah bin 'Umair] dia berkata; aku mendengar [Al Harits bin Suwaid] dia berkata; telah menceritakan kepadaku ['Abdullah] mengenai dua buah hadits. Salah satunya dari Rasulullah shallallahu 'alaihi wasallam, sedangkan yang satu lagi tentang dirinya. Dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Allah sangat gembira dengan taubatnya seorang hamba yang beriman'. -yang serupa dengan Hadits Jarir.-"},"4581":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا أَبُو يُونُسَ عَنْ سِمَاكٍ قَالَخَطَبَ النُّعْمَانُ بْنُ بَشِيرٍ فَقَالَ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ مِنْ رَجُلٍ حَمَلَ زَادَهُ وَمَزَادَهُ عَلَى بَعِيرٍ ثُمَّ سَارَ حَتَّى كَانَ بِفَلَاةٍ مِنْ الْأَرْضِ فَأَدْرَكَتْهُ الْقَائِلَةُ فَنَزَلَ فَقَالَ تَحْتَ شَجَرَةٍ فَغَلَبَتْهُ عَيْنُهُ وَانْسَلَّ بَعِيرُهُ فَاسْتَيْقَظَ فَسَعَى شَرَفًا فَلَمْ يَرَ شَيْئًا ثُمَّ سَعَى شَرَفًا ثَانِيًا فَلَمْ يَرَ شَيْئًا ثُمَّ سَعَى شَرَفًا ثَالِثًا فَلَمْ يَرَ شَيْئًا فَأَقْبَلَ حَتَّى أَتَى مَكَانَهُ الَّذِي قَالَ فِيهِ فَبَيْنَمَا هُوَ قَاعِدٌ إِذْ جَاءَهُ بَعِيرُهُ يَمْشِي حَتَّى وَضَعَ خِطَامَهُ فِي يَدِهِ فَلَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ الْعَبْدِ مِنْ هَذَا حِينَ وَجَدَ بَعِيرَهُ عَلَى حَالِهِقَالَ سِمَاكٌ فَزَعَمَ الشَّعْبِيُّ أَنَّ النُّعْمَانَ رَفَعَ هَذَا الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا أَنَا فَلَمْ أَسْمَعْهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Abu Yunus] dari [Simak] dia berkata; [An Nu'man bin Basyir] berkhuthbah, maka dia berkata; Sungguh kegembiraan Allah karena taubatnya hamba-Nya melebihi kegembiraan salah seorang dari kalian yang pada suatu ketika dia membawa perbekalan dan minumannya di atas unta lalu dia berjalan di padang pasir yang luas. kemudian dia beristirahat sejenak dan tidur di bawah pohon. Tiba-tiba untanya lepas, dia pun mencarinya ke perbukitan, namun dia tidak melihat sesuatu sama sekali, kemudian ia mencari lagi di perbukitan yang lain, namun juga tidak melihatnya, ia pun naik lagi keperbukitan yang lain, tapi tetap tidak menemukan sesuatupun. Akhirnya dia kembali ke tempat istirahatnya. Tatkala dia sedang duduk, tiba-tiba untanya datang kepadanya seraya menyerahkan tali kekangnya ke tangannya. Maka sungguh kegembiraan Allah dengan taubatnya seorang hambanya melebihi kegembiraan orang ini ketika dia mendapatkan untanya kembali dalam keadaan seperti semula. [Simak] berkata; [Sya'bi] mengira bahwa Nu'man telah menyandarkan Hadits ini kepada Nabi shallallahu 'alaihi wasallam, adapun saya belum pernah mendengarnya demikian."},"4582":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَجَعْفَرُ بْنُ حُمَيْدٍ قَالَ جَعْفَرٌ حَدَّثَنَا و قَالَ يَحْيَى أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ عَنْ إِيَادٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ تَقُولُونَ بِفَرَحِ رَجُلٍ انْفَلَتَتْ مِنْهُ رَاحِلَتُهُ تَجُرُّ زِمَامَهَا بِأَرْضٍ قَفْرٍ لَيْسَ بِهَا طَعَامٌ وَلَا شَرَابٌ وَعَلَيْهَا لَهُ طَعَامٌ وَشَرَابٌ فَطَلَبَهَا حَتَّى شَقَّ عَلَيْهِ ثُمَّ مَرَّتْ بِجِذْلِ شَجَرَةٍ فَتَعَلَّقَ زِمَامُهَا فَوَجَدَهَا مُتَعَلِّقَةً بِهِ قُلْنَا شَدِيدًا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ مِنْ الرَّجُلِ بِرَاحِلَتِهِقَالَ جَعْفَرٌ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Ja'far bin Humaid], berkata Ja'far; telah menceritakan kepada kami, dan berkata Yahya; telah mengabarkan kepada kami ['Ubaidullah bin Iyad bin Laqith] dari [Iyad] dari [Al Barra bin 'Azib] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Bagaimana pendapat kalian tentang kegembiraan seseorang yang kehilangan hewan tunggangannya ketika dia membawanya ke sebuah padang pasir yang tandus, tidak ada air minun dan tidak ada pula makanan, padahal di atas unta tersebut ada air minum dan makanan. Kemudian ia pun mencarinya hingga sangat kepayahan. Tatkala ia melewati sebatang pohon, dia menemukan hewan tersebut terikat di sana?\" Maka kami mengatakan; 'Tentu orang itu sangat gembira sekali ya Rasulullah.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah lebih gembira dengan taubat hambanya dari seseorang yang menemukan hewan tunggangannya kembali.\" Ja'far berkata; telah menceritakan kepada kami 'Ubaidullah bin Iyad dari bapaknya."},"4583":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ وَهُوَ عَمُّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ حِينَ يَتُوبُ إِلَيْهِ مِنْ أَحَدِكُمْ كَانَ عَلَى رَاحِلَتِهِ بِأَرْضِ فَلَاةٍ فَانْفَلَتَتْ مِنْهُ وَعَلَيْهَا طَعَامُهُ وَشَرَابُهُ فَأَيِسَ مِنْهَا فَأَتَى شَجَرَةً فَاضْطَجَعَ فِي ظِلِّهَا قَدْ أَيِسَ مِنْ رَاحِلَتِهِ فَبَيْنَا هُوَ كَذَلِكَ إِذَا هُوَ بِهَا قَائِمَةً عِنْدَهُ فَأَخَذَ بِخِطَامِهَا ثُمَّ قَالَ مِنْ شِدَّةِ الْفَرَحِ اللَّهُمَّ أَنْتَ عَبْدِي وَأَنَا رَبُّكَ أَخْطَأَ مِنْ شِدَّةِ الْفَرَحِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Zuhair bin Harb] mereka berdua berkata; telah menceritakan kepada kami ['Umar bin Yunus] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepada kami [Ishaq bin 'Abdullah bin Abu Thalhah] telah menceritakan kepada kami [Anas bin Malik] -dan dia adalah pamannya- dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sungguh kegembiraan Allah karena taubatnya hamba-Nya melebihi kegembiraan salah seorang dari kalian terhadap hewan tunggangannya di sebuah padang pasir yang luas, namun tiba-tiba hewan tersebut lepas, padahal di atasnya ada makanan dan minuman hingga akhirnya dia merasa putus asa untuk menemukannya kembali. kemudian ia beristirahat di bawah pohon, namun di saat itu, tiba-tiba dia mendapatkan untanya sudah berdiri di sampingnya. Ia pun segera mengambil tali kekangnya kemudian berkata; 'Ya Allah Engkau hambaku dan aku ini Tuhan-Mu.' Dia telah salah berdo'a karena terlalu senang.'"},"4584":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَلَّهُ أَشَدُّ فَرَحًا بِتَوْبَةِ عَبْدِهِ مِنْ أَحَدِكُمْ إِذَا اسْتَيْقَظَ عَلَى بَعِيرِهِ قَدْ أَضَلَّهُ بِأَرْضِ فَلَاةٍو حَدَّثَنِيهِ أَحْمَدُ الدَّارِمِيُّ حَدَّثَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sungguh ke gembiraan Allah karena taubatnya hamba-Nya melebihi kegembiraan salah seorang dari kalian ketika bangun dari tidurnya lalu menemukan hewan tunggangannya yang telah hilang di padang pasir yang luas. Dan telah menceritakannya kepada kami [Ahmad Ad Darimi] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam yang serupa dengannya."},"4585":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ مُحَمَّدِ بْنِ قَيْسٍ قَاصِّ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي صِرْمَةَ عَنْ أَبِي أَيُّوبَأَنَّهُ قَالَ حِينَ حَضَرَتْهُ الْوَفَاةُ كُنْتُ كَتَمْتُ عَنْكُمْ شَيْئًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنَّكُمْ تُذْنِبُونَ لَخَلَقَ اللَّهُ خَلْقًا يُذْنِبُونَ يَغْفِرُ لَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Muhammad bin Qais] menceritakan kepada 'Umar bin 'Abdul 'Aziz dari [Abu Shirmah] dari [Abu Ayyub] bahwasanya dia berkata ketika menjelang kematiannya; Aku telah menyembunyikan kepada kalian perkara yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya kamu sekalian tidak mempunyai dosa sedikit niscaya Allah akan menciptakan suatu kaum yang melakukan dosa untuk diberikan ampunan kepada mereka.\""},"4586":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عِيَاضٌ وَهُوَ ابْنُ عَبْدِ اللَّهِ الْفِهْرِيُّ حَدَّثَنِي إِبْرَاهِيمُ بْنُ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ أَبِي صِرْمَةَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَوْ أَنَّكُمْ لَمْ تَكُنْ لَكُمْ ذُنُوبٌ يَغْفِرُهَا اللَّهُ لَكُمْ لَجَاءَ اللَّهُ بِقَوْمٍ لَهُمْ ذُنُوبٌ يَغْفِرُهَا لَهُمْ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku ['Iyadl bin 'Abdullah Al Fihri] telah menceritakan kepadaku [Ibrahim bin 'Ubaid bin Rifa'ah] dari [Muhammad bin Ka'b Al Qurazhi] dari [Abu Shirmah] dari [Abu Ayyub Al Anshari] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Seandainya kamu sekalian tidak mempunyai dosa sedikit pun yang patut diampuni Allah, niscaya Allah akan mendatangkan suatu kaum yang melakukan dosa untuk diberikan ampunan bagi mereka.\""},"4587":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ جَعْفَرٍ الْجَزَرِيِّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ لَمْ تُذْنِبُوا لَذَهَبَ اللَّهُ بِكُمْ وَلَجَاءَ بِقَوْمٍ يُذْنِبُونَ فَيَسْتَغْفِرُونَ اللَّهَ فَيَغْفِرُ لَهُمْ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ja'far Al Jazari] dari [Yazid bin Al Asham] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Demi Dzat yang jiwaku di tangannya, seandainya kamu sekalian tidak berbuat dosa sama sekali, niscaya Allah akan memusnahkan kalian. Setelah itu, Allah akan mengganti kalian dengan umat yang pernah berdosa. Kemudian mereka akan memohon ampunan kepada Allah dan Allah pun pasti akan mengampuni mereka.'\""},"4588":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّيْمِيُّ وَقَطَنُ بْنُ نُسَيْرٍ وَاللَّفْظُ لِيَحْيَى أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ إِيَاسٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ حَنْظَلَةَ الْأُسَيِّدِيِّ قَالَ وَكَانَ مِنْ كُتَّابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَقِيَنِي أَبُو بَكْرٍ فَقَالَ كَيْفَ أَنْتَ يَا حَنْظَلَةُ قَالَ قُلْتُ نَافَقَ حَنْظَلَةُ قَالَ سُبْحَانَ اللّ��هِ مَا تَقُولُ قَالَ قُلْتُ نَكُونُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُذَكِّرُنَا بِالنَّارِ وَالْجَنَّةِ حَتَّى كَأَنَّا رَأْيُ عَيْنٍ فَإِذَا خَرَجْنَا مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَافَسْنَا الْأَزْوَاجَ وَالْأَوْلَادَ وَالضَّيْعَاتِ فَنَسِينَا كَثِيرًا قَالَ أَبُو بَكْرٍ فَوَاللَّهِ إِنَّا لَنَلْقَى مِثْلَ هَذَا فَانْطَلَقْتُ أَنَا وَأَبُو بَكْرٍ حَتَّى دَخَلْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ نَافَقَ حَنْظَلَةُ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا ذَاكَ قُلْتُ يَا رَسُولَ اللَّهِ نَكُونُ عِنْدَكَ تُذَكِّرُنَا بِالنَّارِ وَالْجَنَّةِ حَتَّى كَأَنَّا رَأْيُ عَيْنٍ فَإِذَا خَرَجْنَا مِنْ عِنْدِكَ عَافَسْنَا الْأَزْوَاجَ وَالْأَوْلَادَ وَالضَّيْعَاتِ نَسِينَا كَثِيرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنْ لَوْ تَدُومُونَ عَلَى مَا تَكُونُونَ عِنْدِي وَفِي الذِّكْرِ لَصَافَحَتْكُمْ الْمَلَائِكَةُ عَلَى فُرُشِكُمْ وَفِي طُرُقِكُمْ وَلَكِنْ يَا حَنْظَلَةُ سَاعَةً وَسَاعَةً ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Taimi] dan [Qathan bin Nusair] -dan lafadh ini milik Yahya- telah mengabarkan kepada kami [Ja'far bin Sulaiman] dari [Sa'id bin Iyas Al Jurairi] dari [Abu 'Utsman An Nahdi] dari [Hanzhalah Al Usayyidi] dia berkata; (salah seorang juru tulis Rasulullah shallallahu 'alaihi wasallam) dia berkata; \"Saya pernah berjumpa dengan Abu Bakar dan ia berkata kepada saya; 'Bagaimanakah keadaanmu ya Hanzhalah? ' Saya (Hanzhalah) menjawab; 'Hanzhalah telah menjadi orang munafik.' Abu Bakar terperanjat seraya berkata; 'Subhanallah, apa maksud ucapanmu tadi hai Hanzhalah? ' Saya menjawab; 'Ketahuilah olehmu hai Abu Bakar, ketika kami berada di sisi Rasulullah, beliau sering mengingatkan kami tentang siksa neraka dan nikmat surga hingga seolah-olah kami melihatnya dengan mata kepala kami sendiri. Akan tetapi, ketika kami keluar dari sisi Rasulullah, maka kami pun berlaku kasar dan jahat kepada isteri dan anak-anak kami serta sering melakukan perbuatan yang tidak berguna. Jadi, kami ini sering lengah.' Abu Bakar berkata; 'Demi Allah, kami juga sering berbuat seperti itu hai Hanzhalah.' Kemudian saya dan Abu Bakar pergi menuju ke rumah Rasulullah shallallahu 'alaihi wasallam. Sesampainya di sana, saya berkata; 'Ya Rasulullah, Hanzhalah telah menjadi munafik.' Rasulullah shallallahu 'alaihi wasallam bertanya: 'Apa maksudmu hai Hanzhalah? ' Saya meneruskan ucapan saya; 'Ya Rasulullah, ketika saya berada di sisi engkau, kemudian engkau menerangkan kepada saya tentang siksa neraka dan nikmat surga, seolah-olah saya melihatnya dengan mata kepala saya sendiri. Akan tetapi, ketika saya telah keluar dari sisi engkau, maka saya pun berlaku kasar kepada istri dan anak-anak saya serta sering melakukan perbuatan yang tidak berguna. Jadi saya sering bersikap Iengah.' Mendengar pernyataan tersebut, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Demi Dzat yang jiwaku ditangan-Nya, sungguh jika kamu senantiasa menetapi apa yang kamu lakukan ketika kamu berada di sisiku dan ketika kamu berzikir, niscaya para malaikat akan menjabat tanganmu dalam setiap langkah dan perjalananmu. Tetapi, tentunya yang demikian itu dilakukan sedikit demi sedikit (dari waktu-kewaktu, secara berkala, tidak spontanitas).' Beliau mengulangi kata-kata itu tiga kali."},"4589":{"ar":"حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ سَمِعْتُ أَبِي يُحَدِّثُ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ حَنْظَلَةَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَعَظَنَا فَذَكَّرَ النَّارَ قَالَ ثُمَّ جِئْتُ إِلَى الْبَيْتِ فَضَاحَكْتُ الصِّبْيَانَ وَلَاعَبْتُ الْمَرْأَةَ قَالَ فَخَرَجْتُ فَلَقِيتُ أَبَا بَكْرٍ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ وَأَنَا قَدْ فَعَلْتُ مِثْلَ مَا تَذْكُرُ فَلَقِينَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ نَافَقَ حَنْظَلَةُ فَقَالَ مَهْ فَحَدَّثْتُهُ بِالْحَدِيثِ فَقَالَ أَبُو بَكْرٍ وَأَنَا قَدْ فَعَلْتُ مِثْلَ مَا فَعَلَ فَقَالَ يَا حَنْظَلَةُ سَاعَةً وَسَاعَةً وَلَوْ كَانَتْ تَكُونُ قُلُوبُكُمْ كَمَا تَكُونُ عِنْدَ الذِّكْرِ لَصَافَحَتْكُمْ الْمَلَائِكَةُ حَتَّى تُسَلِّمَ عَلَيْكُمْ فِي الطُّرُقِحَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا سُفْيَانُ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ حَنْظَلَةَ التَّمِيمِيِّ الْأُسَيِّدِيِّ الْكَاتِبِ قَالَ كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَّرَنَا الْجَنَّةَ وَالنَّارَ فَذَكَرَ نَحْوَ حَدِيثِهِمَا","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami ['Abdush Shamad] Aku mendengar [bapakku] bercerita; telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu 'Utsman An Nahdi] dari [Hanzhalah] dia berkata; Ketika kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, beliau biasa mengingatkan kami dan menuturkan tentang neraka. Hanzhalah berkata; Namun ketika aku sudah kembali ke rumah, aku tertawa bersama anak-anakku dan bermain-main bersama istri. Hanzhalah berkata; maka aku pun keluar dan bertemu dengan Abu Bakar, lalu aku ceritakan kebiasaanku kepadanya. Abu Bakr menjawab; Demikian juga saya biasa melakukan hal itu. Lalu kami bertemu dengan Rasulullah, maka aku berkata; 'Ya Rasulullah, Hanzhalah telah munafik! Beliau bertanya: 'Kenapa demikian wahai Hanzhalah? ' aku pun menuturkan kebiasaanku pada beliau, maka beliau bersabda: \"Wahai Hanzhalah, perbaharuilah iman secara berkala (dari waktu ke waktu, secara bertahap, tidak spontanitas), sekiranya keadaan kalian adalah sebagaimana keadaan kalian saat bersamaku, niscaya para malaikat akan menyalami kalian hingga ketika di perjalanan kalian.\" Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Al Fudlail bin Dukain] telah menceritakan kepada kami [Sufyan] dari [Sa'id Al Jurairi] dari [Abu 'Utsman An Nahdi] dari [Hanzhalah At Tamimi Al Usayyidil Al Katib] dia berkata; Ketika kami bersama Rasulullah, beliau biasa mengingatkan kami tentang surga dan neraka. -Selanjutnya sebagaimana Hadits keduanya.-"},"4590":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ سَبَقَتْ رَحْمَتِي غَضَبِي","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, Allah Azza Wa Jalla berfirman: \"Sesungguhnya rahmat-Ku telah mendahului murka-Ku.\""},"4591":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا أَبُو ضَمْرَةَ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَطَاءِ بْنِ مِينَاءَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَضَى اللَّهُ الْخَلْقَ كَتَبَ فِي كِتَابِهِ عَلَى نَفْسِهِ فَهُوَ مَوْضُوعٌ عِنْدَهُ إِنَّ رَحْمَتِي تَغْلِبُ غَضَبِي","id":"Telah menceritakan kepada kami ['Ali bin Khasyram] telah mengabarkan kepada kami [Abu Dhamrah] dari [Al Harits bin 'Abdurrahman] dari ['Atha bin Mina] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam telah bersabda: \"Ketika Allah menciptakan makhluk, maka Dia membuat ketentuan terhadap diri-Nya sendiri yang tersimpan disisi-Nya, Sesungguhnya rahmat-Ku melebihi murka-Ku.\""},"4592":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ جَعَلَ اللَّهُ الرَّحْمَةَ مِائَةَ جُزْءٍ فَأَمْسَكَ عِنْدَهُ تِسْعَةً وَتِسْعِينَ وَأَنْزَلَ فِي الْأَرْضِ جُزْءًا وَاحِدًا فَمِنْ ذَلِكَ الْجُزْءِ تَتَرَاحَمُ الْخَلَائِقُ حَتَّى تَرْفَعَ الدَّابَّةُ حَافِرَهَا عَنْ وَلَدِهَا خَشْيَةَ أَنْ تُصِيبَهُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya At Tujibi] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwasanya [Sa'id bin Al Musayyab] telah mengabarkan kepadanya bahwasanya [Abu Hurairah] dia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala menjadikan sifat rahmat seratus bagian. Maka dipeganglah disisi-Nya sembilan puluh sembilan bagian dan diturunkan-Nya satu bagian ke bumi. Dari yang satu bagian inilah seluruh makhluk berkasih sayang sesamanya, sehingga seekor hewan mengangkat kakinya karena takut anaknya akan terinjak olehnya.\""},"4593":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلَّهِ مِائَةَ رَحْمَةٍ أَنْزَلَ مِنْهَا رَحْمَةً وَاحِدَةً بَيْنَ الْجِنِّ وَالْإِنْسِ وَالْبَهَائِمِ وَالْهَوَامِّ فَبِهَا يَتَعَاطَفُونَ وَبِهَا يَتَرَاحَمُونَ وَبِهَا تَعْطِفُ الْوَحْشُ عَلَى وَلَدِهَا وَأَخَّرَ اللَّهُ تِسْعًا وَتِسْعِينَ رَحْمَةً يَرْحَمُ بِهَا عِبَادَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami ['Abdul Malik] dari ['Atha] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah memiliki seratus rahmat. Dari seratus rahmat tersebut, hanya satu yang di turunkan Allah kepada jin, manusia, hewan jinak dan buas. Dengan rahmat tersebut mereka saling mengasihi dan menyayangi, dan dengan rahmat itu pula binatang buas dapat menyayangi anaknya. Adapun Sembilan puluh sembilan rahmat Allah yang lain, maka hal itu ditangguhkan Allah. Karena Allah hanya akan memberikannya kepada para hamba-Nya yang shalih pada hari kiamat kelak.\""},"4594":{"ar":"حَدَّثَنِي الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ حَدَّثَنَا أَبُو عُثْمَانَ النَّهْدِيُّ عَنْ سَلْمَانَ الْفَارِسِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ مِائَةَ رَحْمَةٍ فَمِنْهَا رَحْمَةٌ بِهَا يَتَرَاحَمُ الْخَلْقُ بَيْنَهُمْ وَتِسْعَةٌ وَتِسْعُونَ لِيَوْمِ الْقِيَامَةِو حَدَّثَنَاه مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepadaku [Al Hakam bin Musa] telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Sulaiman At Taimi] telah menceritakan kepada kami [Abu 'Utsman An Nahdi] dari [Salman Al Farisi] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah memiliki seratus rahmat. Satu rahmat di antaranya untuk seluruh makhluk agar berkasih kasihan sesama mereka (di dunia), sedang yang sembilan puluh sembilan dipersiapkan untuk hari kiamat kelak.\" Dan telah menceritakannya kepada kami [Muhammad bin 'Abdil A'la] telah menceritakan kepada kami [Mu'tamir] dari [bapaknya] dengan sanad ini."},"4595":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَمُحَمَّدُ بْنُ سَهْلٍ التَّمِيمِيُّ وَاللَّفْظُ لِحَسَنٍ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْيٍ فَإِذَا امْرَأَةٌ مِنْ السَّبْيِ تَبْتَغِي إِذَا وَجَدَتْ صَبِيًّا فِي السَّبْيِ أَخَذَتْهُ فَأَلْصَقَتْهُ بِبَطْنِهَا وَأَرْضَعَتْهُ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرَوْنَ هَذِهِ الْمَرْأَةَ طَارِحَةً وَلَدَهَا فِي النَّارِ قُلْنَا لَا وَاللَّهِ وَهِيَ تَقْدِرُ عَلَى أَنْ لَا تَطْرَحَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَرْحَمُ بِعِبَادِهِ مِنْ هَذِهِ بِوَلَدِهَا","id":"Telah menceritakan kepadaku [Al Hasan bin 'Ali Al Hulwani] dan [Muhammad bin Sahl At Tamimi] -dan lafadh ini milik Hasan-; telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] telah menceritakan kepadaku [Zaid bin Aslam] dari [bapaknya] dari ['Umar bin Al Khaththab] bahwasanya dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memperoleh beberapa orang tawanan perang. Tiba-tiba ada seorang perempuan dari mereka mencari bayinya dalam kelompok tawanan itu, maka ia mengambil dan membuainya serta menyusuinya. Melihat hal itu Rasulullah shallallahu 'alaihi wasallam bertanya kepada kami: 'Menurut kalian, apakah perempuan itu tega melemparkan bayinya ke dalam api? ' Kami menjawab; 'Demi Allah, sesungguhnya ia tidak akan tega melemparkan anaknya ke dalam api selama ia masih sanggup menghindarkannya dari api tersebut.' Lalu Rasulullah bersabda: 'Sungguh, kasih sayang Allah terhadap hamba-Nya melebihi kasih sayang perempuan itu terhadap anaknya.'\""},"4596":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ جَمِيعًا عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنِي الْعَلَاءُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ الْمُؤْمِنُ مَا عِنْدَ اللَّهِ مِنْ الْعُقُوبَةِ مَا طَمِعَ بِجَنَّتِهِ أَحَدٌ وَلَوْ يَعْلَمُ الْكَافِرُ مَا عِنْدَ اللَّهِ مِنْ الرَّحْمَةِ مَا قَنَطَ مِنْ جَنَّتِهِ أَحَدٌ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] semuanya dari [Isma'il bin Ja'far]. Ibnu Ayyub berkata; telah menceritakan kepada kami Isma'il, telah mengabarkan kepadaku [Al 'Ala] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Seandainya orang mukmin mengetahui siksa Allah Subhanahu wa Ta'ala, niscaya tidak ada seorang mukmin pun yang menginginkan surga-Nya. Dan seandainya orang kafir itu mengetahui rahmat Allah, maka niscaya tidak ada seorang kafir pun yang berputus asa untuk mengharapkan surga-Nya.\""},"4597":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مَرْزُوقِ بْنِ بِنْتِ مَهْدِيِّ بْنِ مَيْمُونٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَجُلٌ لَمْ يَعْمَلْ حَسَنَةً قَطُّ لِأَهْلِهِ إِذَا مَاتَ فَحَرِّقُوهُ ثُمَّ اذْرُوا نِصْفَهُ فِي الْبَرِّ وَنِصْفَهُ فِي الْبَحْرِ فَوَاللَّهِ لَئِنْ قَدَرَ اللَّهُ عَلَيْهِ لَيُعَذِّبَنَّهُ عَذَابًا لَا يُعَذِّبُهُ أَحَدًا مِنْ الْعَالَمِينَ فَلَمَّا مَاتَ الرَّجُلُ فَعَلُوا مَا أَمَرَهُمْ فَأَمَرَ اللَّهُ الْبَرَّ فَجَمَعَ مَا فِيهِ وَأَمَرَ الْبَحْرَ فَجَمَعَ مَا فِيهِ ثُمَّ قَالَ لِمَ فَعَلْتَ هَذَا قَالَ مِنْ خَشْيَتِكَ يَا رَبِّ وَأَنْتَ أَعْلَمُ فَغَفَرَ اللَّهُ لَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Marzuq bin Binti Mahdi bin Maimun] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Dahulu ada seorang laki-laki yang tidak pernah berbuat baik sama sekali. Lalu ia berpesan kepada istri dan keluarganya; 'Wahai keluargaku, apabila aku meninggal dunia, maka bakarlah mayatku! Setelah itu, buanglah sebagian tubuhku di daratan dan sebagian lagi di lautan. Demi Allah, jika Allah menakdirkan niscaya Dia akan menyiksaku dengan siksaan yang tidak pernah Dia timpakan kepada makhluk lain di dunia ini.' Ketika orang tersebut meninggal, maka keluarganya pun melaksanakan pesannya, yaitu membakar jasadnya dan membuang sebagian ke daratan dan sebagian ke lautan. Kemudian Allah Subhanahu Wa Ta'ala memerintahkan daratan agar menyatukan jasad orang tersebut dan Allah pun memerintahkan lautan agar menyatukan jasad orang itu. Setelah jasad terkumpul menjadi satu kembali di alam barzakh, maka Allah pun bertanya kepadanya: 'Hai hamba-Ku, mengapa kamu memerintahkan keluargamu untuk melakukan tindakan seperti itu? ' Orang laki-laki itu menjawab; 'Ya Allah ya Tuhanku, aku lakukan itu karena aku takut akan siksa-Mu, sedangkan Engkau adalah Dzat Yang Maha Tahu.' Akhirnya Allah pun mengampuninya.\""},"4598":{"ar":"قَالَ الزُّهْرِيُّ وَحَدَّثَنِي حُمَيْدٌ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دَخَلَتْ امْرَأَةٌ النَّارَ فِي هِرَّةٍ رَبَطَتْهَا فَلَا هِيَ أَطْعَمَتْهَا وَلَا هِيَ أَرْسَلَتْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ حَتَّى مَاتَتْ هَزْلًاقَالَ الزُّهْرِيُّ ذَلِكَ لِئَلَّا يَتَّكِلَ رَجُلٌ وَلَا يَيْأَسَ رَجُلٌ حَدَّثَنِي أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي الزُّبَيْدِيُّ قَالَ الزُّهْرِيُّ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَسْرَفَ عَبْدٌ عَلَى نَفْسِهِ بِنَحْوِ حَدِيثِ مَعْمَرٍ إِلَى قَوْلِهِ فَغَفَرَ اللَّهُ لَهُ وَلَمْ يَذْكُرْ حَدِيثَ الْمَرْأَةِ فِي قِصَّةِ الْهِرَّةِ وَفِي حَدِيثِ الزُّبَيْدِيِّ قَالَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِكُلِّ شَيْءٍ أَخَذَ مِنْهُ شَيْئًا أَدِّ مَا أَخَذْتَ مِنْهُ","id":"(Telah menceritakan kepada kami [Muhammad bin Rafi'] dan ['Abd bin Humaid], 'Abd berkata; telah mengabarkan kepada kami, dan Ibnu Rafi' berkata; -dan lafadh ini miliknya-; telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dia berkata;) [Az Zuhri] berkata; dan telah menceritakan kepadaku [Humaid] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam dia berkata; \"Seorang wanita masuk neraka karena seekor kucing yang diikatnya hingga akhirnya mati. Dia tidak memberinya makan, dan tidak pula membiarkannya lepas hingga mencari makan dari serangga-serangga bumi.\" Az Zuhri berkata; hal itu supaya seseorang tidak berdiam diri tanpa beramal (pasrah), dan tidak pula berputus asa. Telah menceritakan kepadaku [Abu Ar Rabi' Sulaiman bin Dawud] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepadaku [Az Zubaidi], [Az Zuhri] berkata; telah menceritakan kepadaku [Humaid bin 'Abdurrahman bin 'Auf] dari [Abu Hurairah] dia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba telah melampaui batas atas dirinya. -sebagaimana Hadits Ma'mar. dan di dalam Hadits Az Zubaidi dia berkata; maka Allah ta'ala berfirman kepada setiap sesuatu yang telah mengambil dari yang bukan miliknya: \"Tunaikan apa yang telah kamu ambil darinya.\""},"4599":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ سَمِعَ عُقْبَةَ بْنَ عَبْدِ الْغَافِرِ يَقُولُ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا فِيمَنْ كَانَ قَبْلَكُمْ رَاشَهُ اللَّهُ مَالًا وَوَلَدًا فَقَالَ لِوَلَدِهِ لَتَفْعَلُنَّ مَا آمُرُكُمْ بِهِ أَوْ لَأُوَلِّيَنَّ مِيرَاثِي غَيْرَكُمْ إِذَا أَنَا مُتُّ فَأَحْرِقُونِي وَأَكْثَرُ عِلْمِي أَنَّهُ قَالَ ثُمَّ اسْحَقُونِي وَاذْرُونِي فِي الرِّيحِ فَإِنِّي لَمْ أَبْتَهِرْ عِنْدَ اللَّهِ خَيْرًا وَإِنَّ اللَّهَ يَقْدِرُ عَلَيَّ أَنْ يُعَذِّبَنِي قَالَ فَأَخَذَ مِنْهُمْ مِيثَاقًا فَفَعَلُوا ذَلِكَ بِهِ وَرَبِّي فَقَالَ اللَّهُ مَا حَمَلَكَ عَلَى مَا فَعَلْتَ فَقَالَ مَخَافَتُكَ قَالَ فَمَا تَلَافَاهُ غَيْرُهَاو حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ قَالَ لِي أَبِي حَدَّثَنَا قَتَادَةُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ بْنُ عَبْدِ الرَّحْمَنِ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا أَبُو عَوَانَةَ كِلَاهُمَا عَنْ قَتَادَةَ ذَكَرُوا جَمِيعًا بِإِسْنَادِ شُعْبَةَ نَحْوَ حَدِيثِهِ وَفِي حَدِيثِ شَيْبَانَ وَأَبِي عَوَانَةَ أَنَّ رَجُلًا مِنْ النَّاسِ رَغَسَهُ اللَّهُ مَالًا وَوَلَدًا وَفِي حَدِيثِ التَّيْمِيِّ فَإِنَّهُ لَمْ يَبْتَئِرْ عِنْدَ اللَّهِ خَيْرًا قَالَ فَسَّرَهَا قَتَادَةُ لَمْ يَدَّخِرْ عِنْدَ اللَّهِ خَيْرًا وَفِي حَدِيثِ شَيْبَانَ فَإِنَّهُ وَاللَّهِ مَا ابْتَأَرَ عِنْدَ اللَّهِ خَيْرًا وَفِي حَدِيثِ أَبِي عَوَانَةَ مَا امْتَأَرَ بِالْمِيمِ","id":"Telah menceritakan kepadaku ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia mendengar ['Uqbah bin 'Abdul Ghafir] berkata; aku mendengar [Abu Sa'id Al Khudri] bercerita dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau menyebutkan; \"Ada seseorang sebelum kalian yang Allah berikan kepadanya harta dan anak. Sebelum ajalnya tiba, dia berkata kepada anaknya; 'Kamu harus melaksanakan apa yang aku perintahkan atau kamu adalah orang yang berhak menerima warisanku dari yang lainnya. Apabila aku meninggal maka bakarlah jasadku Abu Sa'id berkata; menurutku dia berkata; hingga jika aku telah menjadi arang hancurkanlah dan taburkanlah di angin. Karena sungguh aku tidak mempunyai amalan kebaikan yang banyak di sisi Allah. Dan sungguh Allah maha kuasa untuk menyiksaku. Nabi bersabda: \"Lalu ia mengambil janji anak-anaknya untuk melakukan hal itu, dan demi Rabbku, mereka pun melaksanakannya. Lalu Allah berfirman kepadanya: \"Wahai hamba-Ku, apa yang mendorongmu untuk melakukan seperti itu?\" ia menjawab, \"Wahai Rabb, aku takut kepada-Mu, Beliau bersabda: \"Ia tidak pernah melakukan amalan selain itu hingga dengannya Allah memberinya rahmat.\" Dan telah menceritakannya kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dia berkata; berkata kepadaku [bapakku] telah menceritakan kepada kami [Qatadah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Syaiban bin 'Abdurrahman] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Abu 'Awanah] keduanya dari [Qatadah], mereka semua menyebutkan dengan sanad Syu'bah dengan Hadits yang serupa. Di dalam Hadits Syaiban dan Abu 'Awanah disebutkan dengan lafazh; ' Ada seseorang yang Allah beri harta dan anak.\" Sedangkan di Hadits At Taimi disebutkan dengan lafazh; 'Lam Yabta ir.' (tidak mempunyai investasi kebaikan) Dia berkata; Qatadah menafsirkannya dengan; 'tidak mempunyai tabungan amal kebaikan di sisi Allah.' Adapun di Hadits Ibnu Syaiban menggunakan lafazh; mab ta'ara (simpanan). Dan di Hadits Abu 'Awanah dengan lafazh; 'mam ta'ara.' (Tidak mempunyai isvestasi kebaikan)."},"4600":{"ar":"حَدَّثَنِي عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَحْكِي عَنْ رَبِّهِ عَزَّ وَجَلَّ قَالَ أَذْنَبَ عَبْدٌ ذَنْبًا فَقَالَ اللَّهُمَّ اغْفِرْ لِي ذَنْبِي فَقَالَ تَبَارَكَ وَتَعَالَى أَذْنَبَ عَبْدِي ذَنْبًا فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِالذَّنْبِ ثُمَّ عَادَ فَأَذْنَبَ فَقَالَ أَيْ رَبِّ اغْفِرْ لِي ذَنْبِي فَقَالَ تَبَارَكَ وَتَعَالَى عَبْدِي أَذْنَبَ ذَنْبًا فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِالذَّنْبِ ثُمَّ عَادَ فَأَذْنَبَ فَقَالَ أَيْ رَبِّ اغْفِرْ لِي ذَنْبِي فَقَالَ تَبَارَكَ وَتَعَالَى أَذْنَبَ عَبْدِي ذَنْبًا فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِالذَّنْبِ اعْمَلْ مَا شِئْتَ فَقَدْ غَفَرْتُ لَكَ قَالَ عَبْدُ الْأَعْلَى لَا أَدْرِي أَقَالَ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ اعْمَلْ مَا شِئْتَقَالَ أَبُو أَحْمَدَ حَدَّثَنِي مُحَمَّدُ بْنُ زَنْجُويَةَ الْقُرَشِيُّ الْقُشَيْرِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ النَّرْسِيُّ بِهَذَا الْإِسْنَادِ حَدَّثَنِي عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنِي أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ قَالَ كَانَ بِالْمَدِينَةِ قَاصٌّ يُقَالُ لَهُ عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ قَالَ فَسَمِعْتُهُ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ عَبْدًا أَذْنَبَ ذَنْبًا بِمَعْنَى حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ وَذَكَرَ ثَلَاثَ مَرَّاتٍ أَذْنَبَ ذَنْبًا وَفِي الثَّالِثَةِ قَدْ غَفَرْتُ لِعَبْدِي فَلْيَعْمَلْ مَا شَاءَ","id":"Telah menceritakan kepadaku ['Abdul A'la bin Hammad] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari ['Abdurrahman bin Abu 'Amrah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dari apa yang telah dikhabarkan oleh Allah Subhanahu Wa Ta'ala, beliau bersabda: \"Dahulu, ada seorang yang telah berbuat dosa. Setelah itu, ia berdoa dan bermunajat; 'Ya Allah, ampunilah dosaku! ' Kemudian Allah Subhanahu Wa Ta'ala berfirman: 'Sesungguhnya hamba-Ku mengaku telah berbuat dosa, dan ia mengetahui bahwasanya ia mempunyai Tuhan yang dapat mengampuni dosa atau memberi siksa karena dosa.' Kemudian orang tersebut berbuat dosa lagi dan ia berdoa; 'Ya Allah, ampunilah dosaku! ' Maka Allah Subhanahu Wa Ta'ala berfirman: 'Hamba-Ku telah berbuat dosa, dan ia mengetahui bahwasanya ia mempunyai Tuhan yang mengampuni dosa atau menyiksa hamba-Nya karena dosa. Oleh karena, berbuatlah sekehendakmu, karena Aku pasti akan mengampunimu (jika kamu bertaubat).' Abdul A'la berkata; 'Saya tidak mengetahui apakah Rasulullah shallallahu 'alaihi wasallam berkata: 'Berbuatlah sekehendakmu' pada kali yang ketiga atau ke empat.\" Abu Ahmad berkata; telah menceritakan kepadaku Muhammad bin Zanjuyah Al Qurasyi Al Qusyairi telah menceritakan kepada kami 'Abdul A'la bin Hammad An Narsi dengan sanad ini. Telah menceritakan kepadaku ['Abd bin Humaid] telah menceritakan kepadaku [Abul Walid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Ishaq bin 'Abdullah bin Abu Thalhah] dia berkata; Dulu, di Madinah ada seorang yang berkisah, dia biasa dipanggil dengan [Abdurrahman bin Abu Amrah] dia berkata; aku mendengarnya berkata; aku mendengar [Abu Hurairah] berkata; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: Seorang hamba melakukan dosa..-yang semakna dengan Hadits Hammad bin Salamah dengan menyebutkan lafazh; - 'telah melakukan dosa, ' sebanyak tiga kali. Dan di ketiga kalinya beliau menyebutkan; 'Aku (Allah) telah mengampuni hambaku, maka berbuatlah sekehendaknya.'"},"4601":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا عُبَيْدَةَ يُحَدِّثُ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَبْسُطُ يَدَهُ بِاللَّيْلِ لِيَتُوبَ مُسِيءُ النَّهَارِ وَيَبْسُطُ يَدَهُ بِالنَّهَارِ لِيَتُوبَ مُسِيءُ اللَّيْلِ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَاو حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; aku mendengar [Abu 'Ubaidah] bercerita dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Allah Subhanahu Wa Ta'ala akan senantiasa membuka lebar-lebar tangan-Nya pada malam hari untuk menerima taubat orang yang berbuat dosa pada siang hari dan Allah senantiasa akan membuka tangan-Nya pada siang hari untuk menerima taubat orng yang berbuat dosa pada malam hari, dan yang demikian terus berlaku hingga matahari terbit dari barat.\" Dan telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] dengan sanad ini yang serupa dengan Hadits tersebut."},"4602":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ مَدَحَ نَفْسَهُ وَلَيْسَ أَحَدٌ أَغْيَرَ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ حَرَّمَ الْفَوَاحِشَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, dan 'Utsman berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari ['Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; 'Tidak ada yang lebih suka dipuji selain dari Allah Subhanahu Wa Ta'ala. Karena itu Dia memuji diri-Nya sendiri. Dan tidak ada yang lebih pencemburu dari Allah. Karena itulah Dia mengharamkan segala yang keji.'\""},"4603":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لَهُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَحَدٌ أَغْيَرَ مِنْ اللَّهِ وَلِذَلِكَ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] dan [Abu Kuraib] mereka berdua berkata; telah menceritakan kepada kami [Abu Mu'awiyah]. Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] -dan lafadh ini miliknya-; telah menceritakan kepada kami ['Abdullah bin Numair] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang lebih pencemburu dari Allah. Karena itulah Dia mengharamkan segala yang keji baik yang nampak maupun yang tidak nampak. Dan tidak ada yang lebih suka dipuji selain Allah.\""},"4604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُا قُلْتُ لَهُ آنْتَ سَمِعْتَهُ مِنْ عَبْدِ اللَّهِ قَالَ نَعَمْ وَرَفَعَهُأَنَّهُ قَالَ لَا أَحَدٌ أَغْيَرَ مِنْ اللَّهِ وَلِذَلِكَ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ وَلِذَلِكَ مَدَحَ نَفْسَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; aku mendengar [Abu Wail] berkata; aku mendengar ['Abdullah bin Mas'ud] berkata tentang suatu Hadits, lalu aku tanyakan kepadanya; apakah kamu mendengarnya dari Abdullah? Dia menjawab; Ya, secara marfu' dia berkata; \"Tidak ada yang lebih pencemburu dari Allah. Karena itulah Dia mengharamkan segala yang keji baik yang nampak maupun yang tidak nampak. Dan tidak ada yang lebih suka dipuji selain Allah karena itulah Dia memuji diri-Nya.\""},"4605":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مَالِكِ بْنِ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ عَزَّ وَجَلَّ مِنْ أَجْلِ ذَلِكَ مَدَحَ نَفْسَهُ وَلَيْسَ أَحَدٌ أَغْيَرَ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ حَرَّمَ الْفَوَاحِشَ وَلَيْسَ أَحَدٌ أَحَبَّ إِلَيْهِ الْعُذْرُ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ أَنْزَلَ الْكِتَابَ وَأَرْسَلَ الرُّسُلَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ishaq bin Ibrahim], Ishaq berkata; telah mengabarkan kepada kami, dan berkata yang lain; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Malik bin Al Harits] dari ['Abdurrahman bin Yazid] dari ['Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; 'Tidak ada seorang pun di dunia ini yang melebihi kesukaan Allah Subhanahu Wa Ta'ala terhadap pujian. Oleh karena itu, dia memuji diri-Nya sendiri. Tidak ada seorang pun yang melebihi kecemburuan Allah. Oleh karena itu, dia mengharamkan keburukan. Dan tidak ada seorang pun yang melebihi kesukaan Allah Azza wa Jalla terhadap pembebasan dosa. Oleh karena itu, Dia menurunkan kitab suci dan mengutus para rasul.'\""},"4606":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ ابْنِ عُلَيَّةَ عَنْ حَجَّاجِ بْنِ أَبِي عُثْمَانَ قَالَ قَالَ يَحْيَى وَحَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَغَارُ وَإِنَّ الْمُؤْمِنَ يَغَارُ وَغَيْرَةُ اللَّهِ أَنْ يَأْتِيَ الْمُؤْمِنُ مَا حَرَّمَ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Amr An Naqid] telah menceritakan kepada kami [Isma'il bin Ibrahim bin 'Ulayyah] dari [Hajjaj bin Abu 'Utsman] dia berkata; [Yahya] berkata; dan telah menceritakan kepadaku [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Sesungguhnya Allah memiliki kecemburuan dan orang mukmin juga memiliki kecemburuan. Kecemburuan Allah adalah apabila seorang mukmin mengerjakan apa yang di haramkan oleh Allah.'\""},"4607":{"ar":"قَالَ يَحْيَى وَحَدَّثَنِي أَبُو سَلَمَةَ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ حَدَّثَتْهُ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ شَيْءٌ أَغْيَرَ مِنْ اللَّهِ عَزَّ وَجَلَّحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ وَحَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ رِوَايَةِ حَجَّاجٍ حَدِيثَ أَبِي هُرَيْرَةَ خَاصَّةً وَلَمْ يَذْكُرْ حَدِيثَ أَسْمَاءَ","id":"\n(Telah menceritakan kepada kami ['Amr An Naqid] telah menceritakan kepada kami [Isma'il bin Ibrahim bin 'Ulayyah] dari [Hajjaj bin Abu 'Utsman] [Yahya] berkata; dan telah menceritakan kepadaku [Abu Salamah] bahwasanya ['Urwah bin Az Zubair] menceritakan kepadanya, [Asma bintu Abu Bakr] menceritakan kepadanya, ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorangpun yang lebih cemburu selain Allah Azza Wa Jalla. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Aban bin Yazid] dan [Harb bin Syaddad] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam yang serupa dengan riwayat Hajjaj, yaitu Hadits Abu Hurairah secara khusus, dan dia tidak menyebutkan Hadits Asma`.'"},"4608":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ هِشَامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عُرْوَةَ عَنْ أَسْمَاءَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا شَيْءَ أَغْيَرُ مِنْ اللَّهِ عَزَّ وَجَلَّ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari ['Urwah] dari [Asma'] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada sesuatu yang lebih cemburu selain Allah Azza Wa Jalla.\""},"4609":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ يَغَارُ وَاللَّهُ أَشَدُّ غَيْرًاو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ الْعَلَاءَ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari [Al 'Ala] dari [bapaknya] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin itu pencemburu, dan Allah itu lebih pencemburu lagi.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Al 'Ala] dengan sanad ini."},"4610":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ الْجَحْدَرِيُّ كِلَاهُمَا عَنْ يَزِيدَ بْنِ زُرَيْعٍ وَاللَّفْظُ لِأَبِي كَامِلٍ حَدَّثَنَا يَزِيدُ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَجُلًا أَصَابَ مِنْ امْرَأَةٍ قُبْلَةً فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ قَالَ فَنَزَلَتْ{ أَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }قَالَ فَقَالَ الرَّجُلُ أَلِيَ هَذِهِ يَا رَسُولَ اللَّهِ قَالَ لِمَنْ عَمِلَ بِهَا مِنْ أُمَّتِيحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ ابْنِ مَسْعُودٍ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّهُ أَصَابَ مِنْ امْرَأَةٍ إِمَّا قُبْلَةً أَوْ مَسًّا بِيَدٍ أَوْ شَيْئًا كَأَنَّهُ يَسْأَلُ عَنْ كَفَّارَتِهَا قَالَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ يَزِيدَ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ بِهَذَا الْإِسْنَادِ قَالَ أَصَابَ رَجُلٌ مِنْ امْرَأَةٍ شَيْئًا دُونَ الْفَاحِشَةِ فَأَتَى عُمَرَ بْنَ الْخَطَّابِ فَعَظَّمَ عَلَيْهِ ثُمَّ أَتَى أَبَا بَكْرٍ فَعَظَّمَ عَلَيْهِ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بِمِثْلِ حَدِيثِ يَزِيدَ وَالْمُعْتَمِرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Kamil Fudhail bin Husain Al Jahdari] keduanya dari [Yazid bin Zurai'] - dan lafadh ini milik Abu Kamil-; telah menceritakan kepada kami Yazid telah menceritakan kepada kami [At Taimi] dari [Abu 'Utsman] dari ['Abdullah bin Mas'ud] bahwasanya seorang lelaki pernah mencium seorang wanita, lalu dia menemui Nabi shallallahu 'alaihi wasallam dan mengabarkannya kepada Nabi shallallahu 'alaihi wasallam. Maka turunlah ayat: \"Dan dirikanlah shalat itu pada kedua tepi siang (pagi dan petang) dan pada bagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.\" (QS Hud; 114). Abdullah berkata; laki-laki itu bertanya; \"Wahai Rasulullah, apakah ayat ini untukku?\" Beliau menjawab: \"Ayat tersebut adalah untuk orang-orang yang melakukannya dari ummatku.\" Telah menceritakan kepada kami [Muhammad bin 'Abdul A'la] telah menceritakan kepada kami [Mu'tamir] dari [bapaknya] telah menceritakan kepada kami [Abu 'Utsman] dari [Ibnu Mas'ud] bahwasanya seorang laki-laki menemui Nabi shallallahu 'alaihi wasallam dan menceritakan bahwa dirinya telah menyentuh seorang wanita, baik itu berupa ciuman atau setuhan tangan, seperitinya dia bertanya kepada Nabi shallallahu 'alaihi wasallam tentang kafarahnya (penghapus). Ibnu Mas'ud berkata; maka turunlah ayat -sebagaimana dalam Hadits Yazid. Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Sulaiman At Taimi] dengan sanad ini, dia berkata; 'Seorang laki-laki pernah melakukan perbuatan dosa kecil terhadap seorang wanita, lalu dia menemui Umar bin Khaththab, maka Umar menganggapnya telah melakukan dosa besar. Lalu dia menemui Abu Bakr, ia pun menganggapnya telah melakukan dosa besar. Kemudian dia mendatangi Nabi shallallahu 'alaihi wasallam -lalu perawi menyebutkan sebagaimana Hadits Yazid dan Mu'tamir.-"},"4611":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لِيَحْيَى قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي عَالَجْتُ امْرَأَةً فِي أَقْصَى الْمَدِينَةِ وَإِنِّي أَصَبْتُ مِنْهَا مَا دُونَ أَنْ أَمَسَّهَا فَأَنَا هَذَا فَاقْضِ فِيَّ مَا شِئْتَ فَقَالَ لَهُ عُمَرُ لَقَدْ سَتَرَكَ اللَّهُ لَوْ سَتَرْتَ نَفْسَكَ قَالَ فَلَمْ يَرُدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَقَامَ الرَّجُلُ فَانْطَلَقَ فَأَتْبَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا دَعَاهُ وَتَلَا عَلَيْهِ هَذِهِ الْآيَةَ{ أَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }فَقَالَ رَجُلٌ مِنْ الْقَوْمِ يَا نَبِيَّ اللَّهِ هَذَا لَهُ خَاصَّةً قَالَ بَلْ لِلنَّاسِ كَافَّةًحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ بْنُ عَبْدِ اللَّهِ الْعِجْلِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ إِبْرَاهِيمَ يُحَدِّثُ عَنْ خَالِهِ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ أَبِي الْأَحْوَصِ وَقَالَ فِي حَدِيثِهِ فَقَالَ مُعَاذٌ يَا رَسُولَ اللَّهِ هَذَا لِهَذَا خَاصَّةً أَوْ لَنَا عَامَّةً قَالَ بَلْ لَكُمْ عَامَّةً","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah bin Sa'id] dan [Abu Bakr bin Abu Syaibah] -dan lafadh ini milik Yahya- Yahya berkata; telah mengabarkan kepada kami, dan yang lain berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Ibrahim] dari ['Alqamah] dan [Al Aswad] dari ['Abdullah] dia berkata; dari Abdullah, dia berkata; \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam lalu dia berkata; 'Ya Rasulullah! Aku telah berdosa, karena aku bermesraan dengan seorang perempuan di pinggir kota Madinah. Aku telah berbuat dosa dengannya selain bersetubuh. Maka hukumlah aku dengan hukuman apa saja yang anda hendaki. Maka Umar bin Khaththab berkata kepadanya; 'Seandainya engkau menutup rahasia dirimu, niscaya Allah telah menutupi kesalahanmu itu.' Kata Abdullah; 'Nabi shallallahu 'alaihi wasallam tidak membantah sedikitpun ucapan Umar tersebut.' Maka berdirilah laki-laki itu kemudian pergi. Lalu Nabi shallallahu 'alaihi wasallam menyuruh seseorang menyusul dan memanggilnya kembali. Kemudian beliau bacakan kepadanya ayat ini: 'Dan dirikanlah shalat pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya segala perbuatan yang baik menghapuskan (dosa) segala perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.' (QS Hud: 114). Maka bertanyalah seseorang dari suatu kaum yang hadir; 'Ya Nabiyullah! Apakah ayat itu ditujukan khusus baginya? ' Jawab Nabi shallallahu 'alaihi wasallam: 'Bahkan untuk seluruh umat manusia.' Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu An Nu'man Al Hakim bin 'Abdullah Al 'Ijli] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dia berkata; aku mendengar [Ibrahim] bercerita dari pamannya [Al Aswad] dari ['Abdullah] dari Nabi shallallahu 'alaihi wasallam yang semakna dengan hadits Abul Ahwash dia berkata di dalam Haditsnya; Mu'adz berkata; Ya Rasulullah, apakah ayat ini khusus untuk orang itu atau untuk kita semua? Beliau menjawab: 'Bahkan untuk kalian semua.'"},"4612":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ قَالَ وَحَضَرَتْ الصَّلَاةُ فَصَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَى الصَّلَاةَ قَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْ فِيَّ كِتَابَ اللَّهِ قَالَ هَلْ حَضَرْتَ الصَّلَاةَ مَعَنَا قَالَ نَعَمْ قَالَ قَدْ غُفِرَ لَكَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Ali Al Hulwani] telah menceritakan kepada kami ['Amr bin 'Ashim] telah menceritakan kepada kami [Hammam] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas] dia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata; 'Ya, Rasulullah! Aku telah melanggar hukum atas diriku (hukumlah aku)! ' Anas berkata; 'Ketika itu telah masuk waktu shalat, maka dia pun shalat bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam. Setelah selesai shalat dia berkata lagi kepada beliau; 'Ya, Rasulullah! Aku telah melanggar hukum atas diriku sesuai dengan Kitab Allah.' Nabi shallallahu 'alaihi wasallam bertanya: 'Apakah engkau tadi shalat bersama-sama kami? ' jawabnya; 'Ya! ' Nabi shallallahu 'alaihi wasallam bersabda: 'Allah telah mengampuni kamu.'"},"4613":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا شَدَّادٌ حَدَّثَنَا أَبُو أُمَامَةَ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَنَحْنُ قُعُودٌ مَعَهُ إِذْ جَاءَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَعَادَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ فَسَكَتَ عَنْهُ وَأُقِيمَتْ الصَّلَاةُ فَلَمَّا انْصَرَفَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو أُمَامَةَ فَاتَّبَعَ الرَّجُلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ انْصَرَفَ وَاتَّبَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْظُرُ مَا يَرُدُّ عَلَى الرَّجُلِ فَلَحِقَ الرَّجُلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ قَالَ أَبُو أُمَامَةَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ حِينَ خَرَجْتَ مِنْ بَيْتِكَ أَلَيْسَ قَدْ تَوَضَّأْتَ فَأَحْسَنْتَ الْوُضُوءَ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ ثُمَّ شَهِدْتَ الصَّلَاةَ مَعَنَا فَقَالَ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ قَدْ غَفَرَ لَكَ حَدَّكَ أَوْ قَالَ ذَنْبَكَ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami] dan [Zuhair bin Harb] -dan lafadh ini milik Zuhair- mereka berdua berkata; telah menceritakan kepada kami ['Umar bin Yunus] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepada kami [Syaddad] telah menceritakan kepada kami [Abu Umamah] dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam berada di masjid, sedangkan kami tengah duduk-duduk dan bercengkrama dengan beliau, tiba-tiba ada seorang laki-laki yang datang dan berkata; 'Ya Rasulullah, saya telah berbuat dosa. Oleh karena itu, berilah saya hukuman! ' Tetapi Rasulullah hanya terdiam saja. Setelah itu, orang tersebut mengulangi lagi ucapannya; 'Ya Rasulullah, saya telah berbuat dosa. Oleh karena itu, berilah saya hukuman.' Namun Rasulullah hanya terdiam saja. Tak lama kemudian, dilaksanakan shalat berjama'ah. Abu Umamah berkata; 'Ketika Rasulullah shallallahu 'alaihi wasallam pulang ke rumah, orang tersebut tetap mengikutinya untuk mengetahui jawaban kepada orang laki-laki tersebut. Rasulullah shallallahu 'alaihi wasallam menjawab pertanyaan orang tersebut: 'Tahukah kamu bahwasanya kamu keluar dari rumah, bukankah kamu telah berwudlu dengan sebaik-baiknya? ' Laki-laki itu menjawab; 'Benar ya Rasulullah.' Kemudian Rasulullah melanjutkan sabdanya: 'Setelah itu, bukankah kamu telah mengikuti shalat berjamaah bersama kami? ' Laki-laki itu menjawab; 'Benar ya Rasulullah.' Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya Allah telah mengampuni hukuman bagimu, atau dia berkata, dosamu.'\""},"4614":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي الصِّدِّيقِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ قَالَ كَانَ فِيمَنْ كَانَ قَبْلَكُمْ رَجُلٌ قَتَلَ تِسْعَةً وَتِسْعِينَ نَفْسًا فَسَأَلَ عَنْ أَعْلَمِ أَهْلِ الْأَرْضِ فَدُلَّ عَلَى رَاهِبٍ فَأَتَاهُ فَقَالَ إِنَّهُ قَتَلَ تِسْعَةً وَتِسْعِينَ نَفْسًا فَهَلْ لَهُ مِنْ تَوْبَةٍ فَقَالَ لَا فَقَتَلَهُ فَكَمَّلَ بِهِ مِائَةً ثُمَّ سَأَلَ عَنْ أَعْلَمِ أَهْلِ الْأَرْضِ فَدُلَّ عَلَى رَجُلٍ عَالِمٍ فَقَالَ إِنَّهُ قَتَلَ مِائَةَ نَفْسٍ فَهَلْ لَهُ مِنْ تَوْبَةٍ فَقَالَ نَعَمْ وَمَنْ يَحُولُ بَيْنَهُ وَبَيْنَ التَّوْبَةِ انْطَلِقْ إِلَى أَرْضِ كَذَا وَكَذَا فَإِنَّ بِهَا أُنَاسًا يَعْبُدُونَ اللَّهَ فَاعْبُدْ اللَّهَ مَعَهُمْ وَلَا تَرْجِعْ إِلَى أَرْضِكَ فَإِنَّهَا أَرْضُ سَوْءٍ فَانْطَلَقَ حَتَّى إِذَا نَصَفَ الطَّرِيقَ أَتَاهُ الْمَوْتُ فَاخْتَصَمَتْ فِيهِ مَلَائِكَةُ الرَّحْمَةِ وَمَلَائِكَةُ الْعَذَابِ فَقَالَتْ مَلَائِكَةُ الرَّحْمَةِ جَاءَ تَائِبًا مُقْبِلًا بِقَلْبِهِ إِلَى اللَّهِ وَقَالَتْ مَلَائِكَةُ الْعَذَابِ إِنَّهُ لَمْ يَعْمَلْ خَيْرًا قَطُّ فَأَتَاهُمْ مَلَكٌ فِي صُورَةِ آدَمِيٍّ فَجَعَلُوهُ بَيْنَهُمْ فَقَالَ قِيسُوا مَا بَيْنَ الْأَرْضَيْنِ فَإِلَى أَيَّتِهِمَا كَانَ أَدْنَى فَهُوَ لَهُ فَقَاسُوهُ فَوَجَدُوهُ أَدْنَى إِلَى الْأَرْضِ الَّتِي أَرَادَ فَقَبَضَتْهُ مَلَائِكَةُ الرَّحْمَةِ قَالَ قَتَادَةُ فَقَالَ الْحَسَنُ ذُكِرَ لَنَا أَنَّهُ لَمَّا أَتَاهُ الْمَوْتُ نَأَى بِصَدْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -dan lafadh ini miliki Ibnul Mutsanna- mereka berdua berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Abu Ash Shiddiq] dari [Abu Sa'id Al Khudri] bahwasanya Nabiyullah shallallahu 'alaihi wasallam telah bersabda: \"Pada jaman dahulu ada seorang laki-laki yang telah membunuh sembilan puluh sembilan orang. Kemudian orang tersebut mencari orang alim yang banyak ilmunya. Lalu ditunjukan kepada seorang rahib dan ia pun langsung mendatanginya. Kepada rahib tersebut ia berterus terang bahwasanya ia telah membunuh sembilan puluh sembilan orang dan apakah taubatnya itu akan diterima? Ternyata rahib itu malahan menjawab; 'Tidak. Taubatmu tidak akan diterima.' Akhirnya laki-laki itu langsung membunuh sang rahib hingga genaplah kini seratus orang yang telah dibunuhnya. Kemudian laki-laki itu mencari orang lain lagi yang paling banyak ilmunya. Lalu ditunjukan kepadanya seorang alim yang mempunyai ilmu yang banyak. Kepada orang alim tersebut, laki-laki itu berkata; 'Saya telah membunuh seratus orang dan apakah taubat saya akan diterima? ' Orang alim itu menjawab; 'Ya. Tidak ada penghalang antara taubatmu dan dirimu. Pergilah ke daerah ini dan itu, karena di sana banyak orang yang beribadah kepada Allah Subhanahu Wa Ta'ala. Setelah itu, beribadahlah kamu kepada Allah bersama mereka dan janganlah kamu kembali ke daerahmu, karena daerahmu itu termasuk lingkungan yang buruk.' Maka berangkatlah laki-laki itu ke daerah yang telah ditunjukan tersebut. Di tengah perjalanan menuju ke sana laki-laki itu meninggal dunia. Lalu malaikat Rahmat dan Azab saling berbantahan. Malaikat Rahmat berkata; 'Orang laki-laki ini telah berniat pergi ke suatu wilayah untuk bertaubat dan beribadah kepada Allah dengan sepenuh hati.' Malaikat Azab membantah; 'Tetapi, bukankah ia belum berbuat baik sama sekali.' Akhirnya datanglah seorang malaikat yang berwujud manusia menemui kedua malaikat yang sedang berbantahan itu. Maka keduanya meminta keputusan kepada malaikat yang berwujud manusia dengan cara yang terbaik. Orang tersebut berkata; 'Ukurlah jarak yang terdekat dengan orang yang meninggal dunia ini dari tempat berangkatnya hingga ke tempat tujuannya. Mana yang terdekat, maka itulah keputusannya.' Ternyata dari hasil pengukuran mereka itu terbukti bahwa orang laki-laki tersebut meninggal dunia lebih dekat ke tempat tujuannya. Dengan demikian orang tersebut berada dalam genggaman malaikat Rahmat.' Qatadah berkata; 'Al Hasan berkata; 'Seseorang telah berkata pada kami bahwasanya laki-laki itu meninggal dunia dalam kondisi jatuh terlungkup.'"},"4615":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ أَنَّهُ سَمِعَ أَبَا الصِّدِّيقِ النَّاجِيَّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا قَتَلَ تِسْعَةً وَتِسْعِينَ نَفْسًا فَجَعَلَ يَسْأَلُ هَلْ لَهُ مِنْ تَوْبَةٍ فَأَتَى رَاهِبًا فَسَأَلَهُ فَقَالَ لَيْسَتْ لَكَ تَوْبَةٌ فَقَتَلَ الرَّاهِبَ ثُمَّ جَعَلَ يَسْأَلُ ثُمَّ خَرَجَ مِنْ قَرْيَةٍ إِلَى قَرْيَةٍ فِيهَا قَوْمٌ صَالِحُونَ فَلَمَّا كَانَ فِي بَعْضِ الطَّرِيقِ أَدْرَكَهُ الْمَوْتُ فَنَأَى بِصَدْرِهِ ثُمَّ مَاتَ فَاخْتَصَمَتْ فِيهِ مَلَائِكَةُ الرَّحْمَةِ وَمَلَائِكَةُ الْعَذَابِ فَكَانَ إِلَى الْقَرْيَةِ الصَّالِحَةِ أَقْرَبَ مِنْهَا بِشِبْرٍ فَجُعِلَ مِنْ أَهْلِهَاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ مُعَاذِ بْنِ مُ��َاذٍ وَزَادَ فِيهِ فَأَوْحَى اللَّهُ إِلَى هَذِهِ أَنْ تَبَاعَدِي وَإِلَى هَذِهِ أَنْ تَقَرَّبِي","id":"Telah menceritakan kepadaku ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] bahwasanya ia mendengar [Abu Ash Shiddiq An Naji] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam bahwasanya ada seorang laki-laki yang telah membunuh sembilan puluh sembilan orang, lalu ia bertanya apakah masih ada pintu taubat untuknya?\" kemudian ia menemui seorang rahib dan bertanya kepadanya. Dia menjawab; 'Tidak ada pintu taubat untukmu.' Lalu ia membunuh rahib tersebut. Kemudian ia terus bertanya, hingga keluar dari desanya menuju desa yang lain yang di dalamnya terdapat orang-orang shalih. Namun ketika di tengah perjalanan, ajal menjemputnya. Ia pun meninggal dalam keadaan telungkup.\"Lalu Malaikat rahmat dan Malaikat azab saling berebut, setelah diukur jarak perjalanannya ternyata ia lebih dekat sejengkal dengan desa yang baik, maka ia pun digolongkan sebagai penghuni desa tersebut. Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abu 'Adi] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dengan sanad ini seperti hadits Mu'adz bin Mu'adz di dalamnya ada tambahan; 'Maka Allah mewahyukan kepada desa ini untuk menjauh sedangkan ke desa yang satunya lagi diperintahkan agar mendekat.'"},"4616":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ دَفَعَ اللَّهُ عَزَّ وَجَلَّ إِلَى كُلِّ مُسْلِمٍ يَهُودِيًّا أَوْ نَصْرَانِيًّا فَيَقُولُ هَذَا فِكَاكُكَ مِنْالنَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Thalhah bin Yahya] dari [Abu Burdah] dari [Abu Musa] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Pada hari kiamat kelak, Allah Subhanahu wa Ta'ala akan menyerahkan seorang Yahudi ataupun seorang Nasrani kepada setiap orang muslim. Kemudian Allah Subhanahu wa Ta'ala akan berkata; 'Inilah penebusmu dari siksa api neraka.'\""},"4617":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ أَنَّ عَوْنًا وَسَعِيدَ بْنَ أَبِي بُرْدَةَ حَدَّثَاهُ أَنَّهُمَا شَهِدَا أَبَا بُرْدَةَ يُحَدِّثُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ رَجُلٌ مُسْلِمٌ إِلَّا أَدْخَلَ اللَّهُ مَكَانَهُ النَّارَ يَهُودِيًّا أَوْ نَصْرَانِيًّاقَالَ فَاسْتَحْلَفَهُ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ ثَلَاثَ مَرَّاتٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَلَفَ لَهُ قَالَ فَلَمْ يُحَدِّثْنِي سَعِيدٌ أَنَّهُ اسْتَحْلَفَهُ وَلَمْ يُنْكِرْ عَلَى عَوْنٍ قَوْلَهُ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى جَمِيعًا عَنْ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ عَفَّانَ وَقَالَ عَوْنُ بْنُ عُتْبَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] bahwasanya ['Aun] dan [Sa'id bin Abu Burdah] telah menceritakan kepada [Qatadah] bahwa keduanya menyaksikan [Abu Burdah] bercerita kepada 'Umar bin 'Abdul 'Aziz dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidaklah seorang muslim meninggal kecuali Allah akan memasukkan (memperlihatkan) ke dalam tempatnya neraka Yahudi atau Nashrani.\" Qatadah berkata; Maka Umar bin Abdul Aziz meminta Abu Burdah agar bersumpah atas nama Allah yang tidak ada Ilah selainnya sebanyak tiga kali jika ia memang benar telah mendengar bapaknya bercerita kepadanya tentang Hadits tersebut dari Rasulullah shallallahu 'alaihi wasallam. Qatadah berkata; Abu Burda pun bersumpah kepadanya. Qatadah berkata; Namun Sa'id tidak menceritakan kepadaku bahwa Umar meminta sumpah kepada Abu Darda, tapi dia juga tidak mengingkari perkataan Aun. Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Al Mutsanna] semuanya dari ['Abdush Shamad bin 'Abdul Warits] telah mengabarkan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dengan sanad ini seperti hadits 'Affan dan telah berkata 'Aun bin 'Utbah."},"4618":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَبَّادِ بْنِ جَبَلَةَ بْنِ أَبِي رَوَّادٍ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ حَدَّثَنَا شَدَّادٌ أَبُو طَلْحَةَ الرَّاسِبِيُّ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجِيءُ يَوْمَ الْقِيَامَةِ نَاسٌ مِنْ الْمُسْلِمِينَ بِذُنُوبٍ أَمْثَالِ الْجِبَالِ فَيَغْفِرُهَا اللَّهُ لَهُمْ وَيَضَعُهَا عَلَى الْيَهُودِ وَالنَّصَارَىفِيمَا أَحْسِبُ أَنَا قَالَ أَبُو رَوْحٍ لَا أَدْرِي مِمَّنْ الشَّكُّ قَالَ أَبُو بُرْدَةَ فَحَدَّثْتُ بِهِ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ فَقَالَ أَبُوكَ حَدَّثَكَ هَذَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amru bin 'Abbad bin Jabalah bin Abu Rawwad] Telah menceritakan kepada kami [Harami Ibnu 'Umarah] telah menceritakan kepada kami [Syaddad Abu Thalhah Ar Rasibi] dari [Ghailan bin Jarir] dari [Abu Burdah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Di hari kiamat kelak, sekelompok dari kaum muslimin akan datang membawa dosa mereka sebesar gunung. Lalu Allah mengampuni dosa-dosanya, kemudian dibebankan-Nya kepada orang-orang Yahudi dan Nasrani.\" (Itu menurut perkiraanku). Rauh berkata; 'aku tidak tahu dari siapa keraguan ini.' Abu Burdah berkata; Maka hal ini aku ceritakan kepada Umar bin Abdul Aziz. Lalu dia bertanya; 'Apakah Bapakmu menceritakan hal ini dari Nabi shallallahu 'alaihi wasallam? aku menjawab; 'Ya.'"},"4619":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ قَتَادَةَ عَنْ صَفْوَانَ بْنِ مُحْرِزٍقَالَ قَالَ رَجُلٌ لِابْنِ عُمَرَ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي النَّجْوَى قَالَ سَمِعْتُهُ يَقُولُ يُدْنَى الْمُؤْمِنُ يَوْمَ الْقِيَامَةِ مِنْ رَبِّهِ عَزَّ وَجَلَّ حَتَّى يَضَعَ عَلَيْهِ كَنَفَهُ فَيُقَرِّرُهُ بِذُنُوبِهِ فَيَقُولُ هَلْ تَعْرِفُ فَيَقُولُ أَيْ رَبِّ أَعْرِفُ قَالَ فَإِنِّي قَدْ سَتَرْتُهَا عَلَيْكَ فِي الدُّنْيَا وَإِنِّي أَغْفِرُهَا لَكَ الْيَوْمَ فَيُعْطَى صَحِيفَةَ حَسَنَاتِهِ وَأَمَّا الْكُفَّارُ وَالْمُنَافِقُونَ فَيُنَادَى بِهِمْ عَلَى رُءُوسِ الْخَلَائِقِ هَؤُلَاءِ الَّذِينَ كَذَبُوا عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Hisyam Ad Dastawa'i] dari [Qatadah] dari [Shafwan bin Muhriz] dia berkata; \"Seorang laki-laki bertanya kepada Ibnu Umar; 'Bagaimana kamu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda tentang pernyataan Allah dengan berbisik? ' [Ibnu Umar] menjawab; 'Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat orang mukmin akan dihadapkan kepada Allah Azza Wa Jalla dengan sangat dekat sekali hingga tubuhnya menyentuh Allah. Setelah itu, Allah akan memberikan pengukuhan atas dosa-dosanya. Kemudian Allah akan bertanya: 'Apakah kamu tahu dosamu? ' Orang mukmin itu menjawab; 'Ya Tuhanku. Saya tahu dosa saya. Allah berfirman: Sesungguhnya Aku telah menyembunyikannya untukmu ketika di dunia dan pada hari ini Aku telah mengampunimu. Lalu orang mukmin itu diberi catatan amal baiknya. Sementara orang-orang kafir dan munafik akan di panggil dengan suara yang keras di hadapan semua makhluk: 'Mereka inilah orang-orang yang telah mendustakan Allah Azza Wa Jalla.'\""},"4620":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ سَرْحٍ مَوْلَى بَنِي أُمَيَّةَ أَخْبَرَنِي ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ ثُمَّ غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ تَبُوكَ وَهُوَ يُرِيدُ الرُّومَ وَنَصَارَى الْعَرَبِ بِالشَّامِ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍأَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ كَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ يُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ قَالَ كَعْبُ بْنُ مَالِكٍ لَمْ أَتَخَلَّفْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ غَزَاهَا قَطُّ إِلَّا فِي غَزْوَةِ تَبُوكَ غَيْرَ أَنِّي قَدْ تَخَلَّفْتُ فِي غَزْوَةِ بَدْرٍ وَلَمْ يُعَاتِبْ أَحَدًا تَخَلَّفَ عَنْهُ إِنَّمَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَ يُرِيدُونَ عِيرَ قُرَيْشٍ حَتَّى جَمَعَ اللَّهُ بَيْنَهُمْ وَبَيْنَ عَدُوِّهِمْ عَلَى غَيْرِ مِيعَادٍ وَلَقَدْ شَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْعَقَبَةِ حِينَ تَوَاثَقْنَا عَلَى الْإِسْلَامِ وَمَا أُحِبُّ أَنَّ لِي بِهَا مَشْهَدَ بَدْرٍ وَإِنْ كَانَتْ بَدْرٌ أَذْكَرَ فِي النَّاسِ مِنْهَا وَكَانَ مِنْ خَبَرِي حِينَ تَخَلَّفْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ أَنِّي لَمْ أَكُنْ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْهُ فِي تِلْكَ الْغَزْوَةِ وَاللَّهِ مَا جَمَعْتُ قَبْلَهَا رَاحِلَتَيْنِ قَطُّ حَتَّى جَمَعْتُهُمَا فِي تِلْكَ الْغَزْوَةِ فَغَزَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرٍّ شَدِيدٍ وَاسْتَقْبَلَ سَفَرًا بَعِيدًا وَمَفَازًا وَاسْتَقْبَلَ عَدُوًّا كَثِيرًا فَجَلَا لِلْمُسْلِمِينَ أَمْرَهُمْ لِيَتَأَهَّبُوا أُهْبَةَ غَزْوِهِمْ فَأَخْبَرَهُمْ بِوَجْهِهِمْ الَّذِي يُرِيدُ وَالْمُسْلِمُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَثِيرٌ وَلَا يَجْمَعُهُمْ كِتَابُ حَافِظٍ يُرِيدُ بِذَلِكَ الدِّيوَانَ قَالَ كَعْبٌ فَقَلَّ رَجُلٌ يُرِيدُ أَنْ يَتَغَيَّبَ يَظُنُّ أَنَّ ذَلِكَ سَيَخْفَى لَهُ مَا لَمْ يَنْزِلْ فِيهِ وَحْيٌ مِنْ اللَّهِ عَزَّ وَجَلَّ وَغَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْغَزْوَةَ حِينَ طَابَتْ الثِّمَارُ وَالظِّلَالُ فَأَنَا إِلَيْهَا أَصْعَرُ فَتَجَهَّزَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَ مَعَهُ وَطَفِقْتُ أَغْدُو لِكَيْ أَتَجَهَّزَ مَعَهُمْ فَأَرْجِعُ وَلَمْ أَقْضِ شَيْئًا وَأَقُولُ فِي نَفْسِي أَنَا قَادِرٌ عَلَى ذَلِكَ إِذَا أَرَدْتُ فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى اسْتَمَرَّ بِالنَّاسِ الْجِدُّ فَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَادِيًا وَالْمُسْلِمُونَ مَعَهُ وَلَمْ أَقْضِ مِنْ جَهَازِي شَيْئًا ثُمَّ غَدَوْتُ فَرَجَعْتُ وَلَمْ أَقْضِ شَيْئًا فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى أَسْرَعُوا وَتَفَارَطَ الْغَزْوُ فَهَمَمْتُ أَنْ أَرْتَحِلَ فَأُدْرِكَهُمْ فَيَا لَيْتَنِي فَعَلْتُ ثُمَّ لَمْ يُقَدَّرْ ذَلِكَ لِي فَطَفِقْتُ إِذَا خَرَجْتُ فِي النَّاسِ بَعْدَ خُرُوجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْزُنُنِي أَنِّي لَا أَرَى لِي أُسْوَةً إِلَّا رَجُلًا مَغْمُوصًا عَ��َيْهِ فِي النِّفَاقِ أَوْ رَجُلًا مِمَّنْ عَذَرَ اللَّهُ مِنْ الضُّعَفَاءِ وَلَمْ يَذْكُرْنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَلَغَ تَبُوكَ فَقَالَ وَهُوَ جَالِسٌ فِي الْقَوْمِ بِتَبُوكَ مَا فَعَلَ كَعْبُ بْنُ مَالِكٍ قَالَ رَجُلٌ مِنْ بَنِي سَلِمَةَ يَا رَسُولَ اللَّهِ حَبَسَهُ بُرْدَاهُ وَالنَّظَرُ فِي عِطْفَيْهِ فَقَالَ لَهُ مُعَاذُ بْنُ جَبَلٍ بِئْسَ مَا قُلْتَ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا عَلِمْنَا عَلَيْهِ إِلَّا خَيْرًا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَمَا هُوَ عَلَى ذَلِكَ رَأَى رَجُلًا مُبَيِّضًا يَزُولُ بِهِ السَّرَابُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْ أَبَا خَيْثَمَةَ فَإِذَا هُوَ أَبُو خَيْثَمَةَ الْأَنْصَارِيُّ وَهُوَ الَّذِي تَصَدَّقَ بِصَاعِ التَّمْرِ حِينَ لَمَزَهُ الْمُنَافِقُونَ فَقَالَ كَعْبُ بْنُ مَالِكٍ فَلَمَّا بَلَغَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ تَوَجَّهَ قَافِلًا مِنْ تَبُوكَ حَضَرَنِي بَثِّي فَطَفِقْتُ أَتَذَكَّرُ الْكَذِبَ وَأَقُولُ بِمَ أَخْرُجُ مِنْ سَخَطِهِ غَدًا وَأَسْتَعِينُ عَلَى ذَلِكَ كُلَّ ذِي رَأْيٍ مِنْ أَهْلِي فَلَمَّا قِيلَ لِي إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَظَلَّ قَادِمًا زَاحَ عَنِّي الْبَاطِلُ حَتَّى عَرَفْتُ أَنِّي لَنْ أَنْجُوَ مِنْهُ بِشَيْءٍ أَبَدًا فَأَجْمَعْتُ صِدْقَهُ وَصَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَادِمًا وَكَانَ إِذَا قَدِمَ مِنْ سَفَرٍ بَدَأَ بِالْمَسْجِدِ فَرَكَعَ فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ لِلنَّاسِ فَلَمَّا فَعَلَ ذَلِكَ جَاءَهُ الْمُخَلَّفُونَ فَطَفِقُوا يَعْتَذِرُونَ إِلَيْهِ وَيَحْلِفُونَ لَهُ وَكَانُوا بِضْعَةً وَثَمَانِينَ رَجُلًا فَقَبِلَ مِنْهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَانِيَتَهُمْ وَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ وَوَكَلَ سَرَائِرَهُمْ إِلَى اللَّهِ حَتَّى جِئْتُ فَلَمَّا سَلَّمْتُ تَبَسَّمَ تَبَسُّمَ الْمُغْضَبِ ثُمَّ قَالَ تَعَالَ فَجِئْتُ أَمْشِي حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ فَقَالَ لِي مَا خَلَّفَكَ أَلَمْ تَكُنْ قَدْ ابْتَعْتَ ظَهْرَكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي وَاللَّهِ لَوْ جَلَسْتُ عِنْدَ غَيْرِكَ مِنْ أَهْلِ الدُّنْيَا لَرَأَيْتُ أَنِّي سَأَخْرُجُ مِنْ سَخَطِهِ بِعُذْرٍ وَلَقَدْ أُعْطِيتُ جَدَلًا وَلَكِنِّي وَاللَّهِ لَقَدْ عَلِمْتُ لَئِنْ حَدَّثْتُكَ الْيَوْمَ حَدِيثَ كَذِبٍ تَرْضَى بِهِ عَنِّي لَيُوشِكَنَّ اللَّهُ أَنْ يُسْخِطَكَ عَلَيَّ وَلَئِنْ حَدَّثْتُكَ حَدِيثَ صِدْقٍ تَجِدُ عَلَيَّ فِيهِ إِنِّي لَأَرْجُو فِيهِ عُقْبَى اللَّهِ وَاللَّهِ مَا كَانَ لِي عُذْرٌ وَاللَّهِ مَا كُنْتُ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَقَدْ صَدَقَ فَقُمْ حَتَّى يَقْضِيَ اللَّهُ فِيكَ فَقُمْتُ وَثَارَ رِجَالٌ مِنْ بَنِي سَلِمَةَ فَاتَّبَعُونِي فَقَالُوا لِي وَاللَّهِ مَا عَلِمْنَاكَ أَذْنَبْتَ ذَنْبًا قَبْلَ هَذَا لَقَدْ عَجَزْتَ فِي أَنْ لَا تَكُونَ اعْتَذَرْتَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا اعْتَذَرَ بِهِ إِلَيْهِ الْمُخَلَّفُونَ فَقَدْ كَانَ كَافِيَكَ ذَنْبَكَ اسْتِغْفَارُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكَ قَالَ فَوَاللَّهِ مَا زَالُوا يُؤَنِّبُونَنِي حَتَّى أَرَدْتُ أَنْ أَرْجِعَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُكَذِّبَ نَفْسِي قَالَ ثُمَّ قُلْتُ لَهُمْ هَلْ لَقِيَ هَذَا مَعِي مِنْ أَحَدٍ قَالُوا نَعَمْ لَقِيَهُ مَعَكَ رَجُلَانِ قَالَا مِثْلَ مَا قُلْتَ فَقِيلَ لَهُمَا مِثْلَ مَا قِيلَ لَكَ قَالَ قُلْتُ مَنْ هُمَا قَالُوا مُرَارَةُ بْنُ الرَّبِيعَةَ الْعَامِرِيُّ وَهِلَالُ بْنُ أُمَيَّةَ الْوَاقِفِيُّ قَالَ فَذَكَرُوا لِي رَجُلَيْنِ صَالِحَيْنِ قَدْ شَهِدَا بَدْرًا فِيهِمَا أُسْوَةٌ قَالَ فَمَضَيْتُ حِينَ ذَكَرُوهُمَا لِي قَالَ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمِينَ عَنْ كَلَامِنَا أَيُّهَا الثَّلَاثَةُ مِنْ بَيْنِ مَنْ تَخَلَّفَ عَنْهُ قَالَ فَاجْتَنَبَنَا النَّاسُ وَقَالَ تَغَيَّرُوا لَنَا حَتَّى تَنَكَّرَتْ لِي فِي نَفْسِيَ الْأَرْضُ فَمَا هِيَ بِالْأَرْضِ الَّتِي أَعْرِفُ فَلَبِثْنَا عَلَى ذَلِكَ خَمْسِينَ لَيْلَةً فَأَمَّا صَاحِبَايَ فَاسْتَكَانَا وَقَعَدَا فِي بُيُوتِهِمَا يَبْكِيَانِ وَأَمَّا أَنَا فَكُنْتُ أَشَبَّ الْقَوْمِ وَأَجْلَدَهُمْ فَكُنْتُ أَخْرُجُ فَأَشْهَدُ الصَّلَاةَ وَأَطُوفُ فِي الْأَسْوَاقِ وَلَا يُكَلِّمُنِي أَحَدٌ وَآتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُسَلِّمُ عَلَيْهِ وَهُوَ فِي مَجْلِسِهِ بَعْدَ الصَّلَاةِ فَأَقُولُ فِي نَفْسِي هَلْ حَرَّكَ شَفَتَيْهِ بِرَدِّ السَّلَامِ أَمْ لَا ثُمَّ أُصَلِّي قَرِيبًا مِنْهُ وَأُسَارِقُهُ النَّظَرَ فَإِذَا أَقْبَلْتُ عَلَى صَلَاتِي نَظَرَ إِلَيَّ وَإِذَا الْتَفَتُّ نَحْوَهُ أَعْرَضَ عَنِّي حَتَّى إِذَا طَالَ ذَلِكَ عَلَيَّ مِنْ جَفْوَةِ الْمُسْلِمِينَ مَشَيْتُ حَتَّى تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ وَهُوَ ابْنُ عَمِّي وَأَحَبُّ النَّاسِ إِلَيَّ فَسَلَّمْتُ عَلَيْهِ فَوَاللَّهِ مَا رَدَّ عَلَيَّ السَّلَامَ فَقُلْتُ لَهُ يَا أَبَا قَتَادَةَ أَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمَنَّ أَنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ فَسَكَتَ فَعُدْتُ فَنَاشَدْتُهُ فَسَكَتَ فَعُدْتُ فَنَاشَدْتُهُ فَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ فَفَاضَتْ عَيْنَايَ وَتَوَلَّيْتُ حَتَّى تَسَوَّرْتُ الْجِدَارَ فَبَيْنَا أَنَا أَمْشِي فِي سُوقِ الْمَدِينَةِ إِذَا نَبَطِيٌّ مِنْ نَبَطِ أَهْلِ الشَّامِ مِمَّنْ قَدِمَ بِالطَّعَامِ يَبِيعُهُ بِالْمَدِينَةِ يَقُولُ مَنْ يَدُلُّ عَلَى كَعْبِ بْنِ مَالِكٍ قَالَ فَطَفِقَ النَّاسُ يُشِيرُونَ لَهُ إِلَيَّ حَتَّى جَاءَنِي فَدَفَعَ إِلَيَّ كِتَابًا مِنْ مَلِكِ غَسَّانَ وَكُنْتُ كَاتِبًا فَقَرَأْتُهُ فَإِذَا فِيهِ أَمَّا بَعْدُ فَإِنَّهُ قَدْ بَلَغَنَا أَنَّ صَاحِبَكَ قَدْ جَفَاكَ وَلَمْ يَجْعَلْكَ اللَّهُ بِدَارِ هَوَانٍ وَلَا مَضْيَعَةٍ فَالْحَقْ بِنَا نُوَاسِكَ قَالَ فَقُلْتُ حِينَ قَرَأْتُهَا وَهَذِهِ أَيْضَا مِنْ الْبَلَاءِ فَتَيَامَمْتُ بِهَا التَّنُّورَ ف","id":"Telah menceritakan kepadaku [Abu Ath Thahir Ahmad bin 'Amru bin 'Abdullah bin 'Amru bin Sarh] budak Bani Umayyah telah mengabarkan kepadaku [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berangkat ke perang Tabuk untuk menghadapi orang-orang Romawi dan orang-orang Arab yang beragama Nasrani di Syam.\" Ibnu Syihab berkata; 'Saya telah diceritakan oleh [Abdul Rahman bin Abdullah bin Ka'ab bin Malik], bahwa Abdullah bin Ka'ab bin Malik -Abdullah bin Ka'ab adalah salah seorang putra Ka'ab yang mendampingi Ka'ab ketika ia buta- ia berkata; 'Saya pernah mendengar [Ka'ab bin Malik] menceritakan peristiwa tentang dirinya ketika ia turut bersama Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk.' Ka'ab bin Malik berkata; 'Saya tidak pernah tertinggal menyertai Rasulullah shallallahu 'alaihi wasallam dalam peperangan yang beliau ikuti kecuali perang Tabuk, akan tetapi saya juga pernah tertinggal dalam perang Badar. Rasulullah shallallahu 'alaihi wasallam tidak pernah mencela seorang muslim yang tidak turut dalam perang Badar, yang demikian karena Rasulullah shallallahu 'alaihi wasallam dan kaum muslimin (dalam perang Badar ini) tujuan awal hanya ingin menyerang kaum kafir Quraisy yang sedang berada dalam perjalanan dengan mengendarai unta hingga Allah mempertemukan kaum muslimin dengan musuh mereka tanpa waktu yang di sepakati sebelumnya. Saat itu saya ikut serta bersama Rasulullah pada malam 'Aqabah ketika kami berjanji untuk membela Islam. Menurut saya, turut serta dalam perang Badar tidak sebanding dengan turut serta dalam malam Aqabah, meskipun perang Badar lebih populer kebanyakan orang. Di antara cerita ketika saya tidak turut serta bersama Rasulullah dalam perang Tabuk adalah sebagai berikut; 'Saya benar-benar tak berdaya dan tidak ada orang yang lebih banyak mempunyai keluasan daripada saya ketika saya tidak ikut serta dalam perang Tabuk tersebut. Demi Allah, sebelumnya saya tidak menyiapkan dua ekor hewan tunggangan sama sekali dalam pelbagai peperangan. Tetapi dalam perang Tabuk ini, saya menyiapkan dua ekor hewan tunggangan. Akhirnya Rasulullah shallallahu 'alaihi wasallam pergi berangkat ke perang Tabuk pada saat cuaca sangat panas. Dapat di katakan bahwasanya beliau menempuh perjalanan yang amat jauh dan penuh resiko serta menghadapi musuh yang berjumlah besar. Lalu Rasulullah shallallahu 'alaihi wasallam menjelaskan kepada kaum muslimin apa yang akan mereka hadapi bersamanya. Oleh karena itu, beliau memerintahkan kaum muslimin untuk mempersiapkan perbekalan perang yang cukup. Pada saat itu, kaum muslimin yang menyertai Rasulullah shallallahu 'alaihi wasallam banyak sekali tanpa ditunjuk melalui surat tugas untuk berperang. Ka'ab berkata; 'Ada seorang laki-laki yang tidak muncul karena ia ingin tidak turut serta berperang. Ia menduga bahwa ketidak turutannya itu tidak akan di ketahui oleh Rasulullah shallallahu 'alaihi wasallam -selama tidak ada wahyu yang turun mengenai dirinya dari Allah Azza Wa Jalla -. Rasulullah shallallahu 'alaihi wasallam pergi berperang ke perang tabuk ketika hasil panen buah sangat memuaskan, hingga saya harus memalingkan perhatian dari hasil panen tersebut. Rasulullah shallallahu 'alaihi wasallam dan kaum muslimin yang ikut serta sudah bersiap-siap dan saya pun segera pergi untuk mencari perbekalan bersama mereka. Lalu saya pulang tanpa memperoleh perbekalan sama sekali. Saya berkata dalam hati; 'Saya dapat mempersiapkan perbekalan sewaktu-waktu. Saya selalu dalam teka-teki antara ya dan tidak hingga orang-orang semakin siap.' Rasulullah shallallahu 'alaihi wasallam berangkat bersama kaum muslimin, sedangkan saya belum mempersiapkan perbekalan sama sekali. Akhirnya saya pergi, lalu saya pulang tanpa mempersiapkan sesuatu. Saya senantiasa berada dalam kebimbangan seperti itu antara turut serta berperang ataupun tidak, hingga pasukan kaum muslimin telah bergegas berangkat dan perang pun berkecamuk sudah. Kemudian saya ingin menyusul ke medan pertempuran -tetapi hal itu hanyalah angan-angan- dan akhirnya saya ditakdirkan untuk tidak ikut serta ke medan perang. Setelah Rasulullah shallallahu 'alaihi wasallam pergi ke medan perang tabuk, maka mulailah rasa sedih menyelimuti diri saya. Ketika keluar ke tengah-tengah masyarakat sekitar, saya menyadari bahwasanya tidak ada yang dapat saya temui kecuali orang-orang yang dalam kemunafikan atau orang-orang yang lemah yang diberikan uzur oleh Allah Azza Wa Jalla. Sementara itu, Rasulullah shallallahu 'alaihi wasallam tidak mengingat diri saya hingga beliau sampai di Tabuk. Kemudian, ketika beliau sedang duduk-duduk di tengah para sahabat, tiba-tiba beliau bertanya; 'Mengapa Ka'ab bin Malik tidak ikut serta bersama kita? ' Seorang sahabat dari Bani Salimah menjawab; 'Ya Rasulullah, sepertinya Ka'ab bin Malik lebih mementingkan dirinya sendiri daripada perjuangan ini? ' Mendengar ucapan sahabat tersebut, Muadz bin Jabal berkata; 'Hai sahabat, buruk sekali ucapanmu itu! Demi Allah ya Rasulullah, saya tahu bahwasanya Ka'ab bin Malik itu adalah orang yang baik.' Kemudian Rasulullah shallallahu 'alaihi wasallam diam. Ketika beliau terdiam seperti itu, tiba-tiba beliau melihat seorang laki-laki yang memakai helm besi yang sulit di kenali. Lalu Rasulullah shallallahu 'alaihi wasallam berkata: 'Kamu pasti Abu Khaitsamah? ' Ternyata orang tersebut adalah memang benar-benar Abu Khaitsamah Al Anshari, sahabat yang pernah menyedekahkan satu sha' kurma ketika ia dicaci maki oleh orang-orang munafik. Ka'ab bin Malik berkata; 'Ketika saya mendengar bahwasanya Rasulullah shallallahu 'alaihi wasallam telah bersiap-siap kembali dari perang Tabuk, maka saya pun diliputi kesedihan. Lalu saya mulai merancang alasan untuk berdusta. Saya berkata dalam hati; 'Alasan apa yang dapat menyelamatkan diri saya dari amarah Rasulullah? ' Untuk menghadapi hal tersebut, saya meminta pertolongan kepada keluarga yang dapat memberikan saran. Ketika ada seseorang yang berkata kepada saya bahwasanya Rasulullah shallallahu 'alaihi wasallam hampir tiba di kota Madinah, hilanglah alasan untuk berdusta dari benak saya. Akhirnya saya menyadari bahwasanya saya tidak dapat berbohong sedikitpun kepada Rasulullah shallallahu 'alaihi wasallam. Oleh karena itu, saya pun harus berkata jujur kepada beliau. Tak lama kemudian Rasulullah shallallahu 'alaihi wasallam tiba di kota Madinah. Seperti biasa, beliau langsung menuju Masjid - sebagaimana tradisi beliau setiap kali tiba dari bepergian ke suatu daerah - untuk melakukan shalat. Setelah melakukan shalat sunnah, Rasulullah shallallahu 'alaihi wasallam langsung bercengkrama bersama para sahabat. Setelah itu, datanglah beberapa orang sahabat yang tidak sempat ikut serta bertempur bersama kaum muslimin seraya menyampaikan berbagai alasan kepada beliau dengan bersumpah. Diperkirakan mereka yang tidak turut serta bertempur itu sekitar delapan puluh orang lebih. Ternyata Rasulullah menerima keterus terangan mereka yang tidak ikut serta berperang, membai'at mereka, memohon ampun untuk mereka, dan menyerahkan apa yang mereka sembunyikan dalam hati mereka kepada Allah. Selang beberapa saat kemudian, saya datang menemui Rasulullah shallallahu 'alaihi wasallam. Setelah saya memberi salam, beliau tersenyum seperti senyuman orang yang marah. Kemudian beliau pun berkata; 'Kemarilah! ' Lalu saya berjalan mendekati beliau hingga saya duduk tepat di hadapan beliau. Setelah itu Rasulullah shallallahu 'alaihi wasallam bertanya: 'Mengapa kamu tidak ikut serta bertempur bersama kami hai Ka'ab? Bukankah kamu telah berjanji untuk menyerahkan jiwa ragamu untuk Islam? ' Saya menjawab; 'Ya Rasulullah, demi Allah seandainya saya duduk di dekat orang selain diri engkau, niscaya saya yakin bahwasanya saya akan terbebaskan dari kemurkaannya karena alasan dan argumentasi yang saya sampaikan. Tetapi, demi Allah, saya tahu jika sekarang saya menyampaikan kepada engkau alasan yang penuh dusta hingga membuat engkau tidak marah, tentunya Allah lah yang membuat engkau marah kepada saya. Apabila saya mengemukakan kepada engkau ya Rasulullah alasan saya yang benar dan jujur, lalu engkau akan memarahi saya dengan alasan tersebut, maka saya pun akan menerimanya dengan senang hati. Biarkanlah Allah memberi hukuman kepada saya dengan ucapan saya yang jujur tersebut. Demi Allah, sesungguhya tidak ada uzur yang membuat saya tidak ikut serta berperang. Demi Allah, saya tidak berdaya sama sekali kala itu meskipun saya mempunyai peluang yang sangat longgar sekali untuk ikut berjuang bersama kaum muslimin.' Mendengar pengakuan yang tulus itu, Rasulullah pun berkata: 'Orang ini telah berkata jujur dan benar. Oleh karena itu, berdirilah hingga Allah memberimu keputusan.\" Akhirnya saya pun berdiri dan beranjak dari sisi beliau. Tak lama kemudian, ada beberapa orang dari Bani Salimah beramai-ramai mengikuti saya seraya berkata; 'Hai Ka'ab, demi Allah, sebelumnya kami tidak mengetahui bahwasanya kamu telah berbuat suatu kesalahan/dosa. Kamu benar-benar tidak mengemukakan alasan kepada Rasulullah sebagaimana alasan yang dikemukakan para sahabat lain yang tidak turut berperang. Sesungguhnya, hanya istighfar Rasulullah untukmulah yang menghapus dosamu.' Ka'ab bin Malik berkata setelah itu; 'Demi Allah, mereka selalu mencerca saya hingga saya ingin kembali lagi kepada Rasulullah shallallahu 'alaihi wasallam lalu saya dustakan diri saya.' Ka'ab bin Malik berkata; 'Apakah ada orang lain yang telah menghadap Rasulullah shallallahu 'alaihi wasallam seperti diri saya ini? ' Orang-orang Bani Salimah menjawab; 'Ya. Ada dua orang lagi seperti dirimu. Kedua orang tersebut mengatakan kepada Rasulullah seperti apa yang telah kamu utarakan dan Rasulullah pun menjawabnya seperti jawaban kepadamu.' Ka'ab bin Malik berkata; 'Lalu saya pun bertanya; 'Siapakah kedua orang tersebut hai para sahabat? ' Mereka, kaum Bani Salimah, menjawab; 'Kedua orang tersebut adalah Murarah bin Rabi'ah Al Amin dan Hilal bin Ummayah Al Waqifi.' Ka'ab bin Malik berkata; 'Kemudian mereka menyebutkan dua orang sahabat yang shalih yang ikut serta dalam perang Badar dan keduanya layak dijadikan suri tauladan yang baik. Setelah itu, saya pun berlalu ketika mereka menyebutkan dua orang tersebut kepada saya.' Ka'ab bin Malik berkata; 'Beberapa hari kemudian, Rasulullah shallallahu 'alaihi wasallam melarang kaum muslimin untuk berbicara dengan kami bertiga yang tidak ikut serta dalam perang Tabuk. Sejak saat itu, kaum muslimin mulai menjauhi dan berubah sikap terhadap kami bertiga hingga bumi ini terasa asing bagi kami. Sepertinya, bumi ini bukanlah bumi yang pernah saya huni sebelumnya dan hal itu berlangsung lima puluh malam lamanya.' Dua orang teman saya yang tidak ikut serta dalam perang Tabuk itu kini bersimpuh sedih di rumahnya sambil menangis, sedangkan saya adalah seorang anak muda yang tangguh dan tegar. Saya tetap bersikap wajar dan menjalankan aktivitas sehari-hari seperti biasanya. Saya tetap keluar dari rumah, pergi ke masjid untuk menghadiri shalat jama'ah bersama kaum muslimin lainnya, dan berjalan-jalan di pasar meskipun tidak ada seorang pun yang sudi berbicara dengan saya. Hingga pada suatu ketika saya menghampiri Rasulullah shallallahu 'alaihi wasallam sambil memberikan salam kepadanya ketika beliau berada di tempat duduknya usai shalat. Saya bertanya dalam hati; 'Apakah Rasulullah shallallahu 'alaihi wasallam akan menggerakkan bibirnya untuk menjawab salam ataukah tidak? Kemudian saya melaksanakan shalat di dekat Rasulullah sambil mencuri pandangan kepada beliau. Ketika saya telah bersiap untuk melaksanakan shalat, beliau memandang kepada saya. Dan ketika saya menoleh kepadanya, beliaupun mengalihkan pandangannya dari saya.' Setelah lama terisolisir dari pergaulan kaum muslimin, saya pun pergi berjalan-jalan hingga sampai di pagar kebun Abu Qatadah. Abu Qatadah adalah putera paman saya (sepupu saya) dan ia adalah orang yang saya sukai. Sesampainya di sana, saya pun mengucapkan salam kepadanya. Tetapi, demi Allah, sama sekali ia tidak menjawab salam saya. Akhirnya saya memberanikan diri untuk bertanya kepadanya; 'Hai Abu Qatadah, saya bersumpah kepadamu dengan nama Allah, apakah kamu tidak mengetahui bahwasanya saya sangat mencintai Allah dan Rasul-Nya? ' Ternyata Abu Qatadah hanya terdiam saja. Lalu saya ulangi lagi ucapan saya dengan bersumpah seperti yang pertama kali. Namun ia tetap saja terdiam. Kemudian saya ulangi ucapan saya dan ia pun menjawab; 'Sesungguhnya Allah dan Rasul-Nya lebih mengetahui tentang hal ini.' Mendengar ucapannya itu, berlinanglah air mata saya dan saya pun kembali ke rumah sambil menyusuri kebun tersebut. Ketika saya sedang berjalan-jalan di pasar Madinah, ada seorang laki-laki dari negeri Syam yang berjualan makanan di kota Madinah bertanya; 'Siapakah yang dapat menunjukkan kepada saya di mana Ka'ab bin Malik? ' Lalu orang-orang pun menunjukkan kepada saya hingga orang tersebut datang kepada saya sambil menyerahkan sepucuk surat kepada saya dari raja Ghassan. Karena saya dapat membaca dan menulis, maka saya pun memahami isi surat tersebut. Ternyata isi surat tersebut sebagai berikut; 'Kami mendengar bahwasanya temanmu (maksudnya adalah Rasulullah shallallahu 'alaihi wasallam) telah mengisolirmu dari pergaulan umum, sementara Tuhanmu sendiri tidaklah menyia-nyiakanmu seperti itu. Oleh karena itu, bergabunglah dengan kami, niscaya kami akan menolongmu.' Selesai membaca surat itu, saya pun berkata; 'Sebenarnya surat ini juga merupakan sebuah bencana juga bagi saya.' Lalu saya memasukkannya ke dalam pembakaran dan membakarnya hingga musnah. Setelah empat puluh hari lamanya dari pengucilan umum, ternyata wahyu Tuhan pun tidak juga turun. Hingga pada suatu ketika, seorang utusan Rasulullah shallallahu 'alaihi wasallam mendatangi saya sambil menyampaikan sebuah pesan; 'Hai Ka'ab, sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkanmu untuk menghindari istrimu.' Saya bertanya; 'Apakah saya harus menceraikan atau bagaimana? ' Utusan tersebut menjawab; 'Tidak usah kamu ceraikan. Tetapi, cukuplah kamu menghindarinya dan janganlah kamu mendekatinya.' Lalu saya katakan kepada istri saya; 'Wahai dinda, sebaiknya dinda pulang terlebih dahulu ke rumah orang tua dinda dan tinggallah bersama dengan mereka hingga Allah memberikan keputusan yang jelas dalam permasalahan ini.' Ka'ab bin Malik berkata; 'Tak lama kemudian istri Hilal bin Umayyah pergi mendatangi Rasulullah shallallahu 'alaihi wasallam sambil bertanya; 'Ya Rasulullah, Hilal bin Umayyah itu sudah lanjut usia dan lemah serta tidak mempunyai pembantu. Oleh karena itu, izinkanlah saya merawatnya.' Rasulullah shallallahu 'alaihi wasallam pun menjawab: 'Jangan. Sebaiknya kamu tidak usah menemaninya terlebih dahulu dan ia tidak boleh dekat denganmu untuk beberapa saat.' Isteri Hilal tetap bersikeras dan berkata; 'Demi Allah ya Rasullah, sekarang ia itu tidak mempunyai semangat hidup lagi. Ia senantiasa menangis, sejak mendapatkan permasalahan ini sampai sekarang.' Ka'ab bin Malik berkata; 'Beberapa orang dari keluarga saya berkata; 'Sebaiknya kamu meminta izin terlebih dahulu kepada Rasulullah dalam masalah istrimu ini. Karena Rasulullah shallallahu 'alaihi wasallam sendiri telah memberikan izin kepada Hilal bin Umayyah untuk merawat suaminya.' Ka'ab bin Malik berkata; 'Saya tidak akan meminta izin kepada Rasulullah shallallahu 'alaihi wasallam dalam persoalan istri saya ini. Karena, bagaimanapun, saya tidak akan tahu bagaimana jawaban Rasulullah nanti jika saya meminta izin kepada beliau sedangkan saya masih muda belia.' Ka'ab bin Malik berkata; 'Ternyata hal itu berlangsung selama sepuluh malam hingga dengan demikian lengkaplah sudah lima puluh malam bagi kami terhitung sejak kaum muslimin dilarang untuk berbicara kepada kami. Ka'ab bin Malik berkata; 'Lalu saya melakukan shalat fajar pada malam yang ke lima puluh di bagian belakang rumah. Ketika saya sedang duduk dalam shalat tersebut, diri saya diliputi penyesalan dan kesedihan. Sepertinya bumi yang luas ini terasa sempit bagi diri saya. Tiba-tiba saya mendengar seseorang berteriak dengan lantangnya menembus cakrawala; 'Hai Ka'ab bin Malik, bergembiralah! ' Maka saya pun tersungkur sujud dan mengetahui bahwasanya saya telah terbebas dari persoalan saya. Ka'ab bin Malik berkata; 'Kemudian Rasulullah shallallahu 'alaihi wasallam mengumumkan kepada kaum muslimin usai "},"4621":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ وَالسِّيَاقُ حَدِيثُ مَعْمَرٍ مِنْ رِوَايَةِ عَبْدٍ وَابْنِ رَافِعٍ قَالَ يُونُسُ وَمَعْمَرٌ جَمِيعًا عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَعُرْوَةُ بْنُ الزُّبَيْرِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ حَدِيثِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ مِمَّا قَالُوا وَكُلُّهُمْ حَدَّثَنِي طَائِفَةً مِنْ حَدِيثِهَا وَبَعْضُهُمْ كَانَ أَوْعَى لِحَدِيثِهَا مِنْ بَعْضٍ وَأَثْبَتَ اقْتِصَاصًا وَقَدْ وَعَيْتُ عَنْ كُلِّ وَاحِدٍ مِنْهُمْ الْحَدِيثَ الَّذِي حَدَّثَنِي وَبَعْضُ حَدِيثِهِمْ يُصَدِّقُ بَعْضًا ذَكَرُوا أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَخْرُجَ سَفَرًا أَقْرَعَ بَيْنَ نِسَائِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ قَالَتْ عَائِشَةُ فَأَقْرَعَ بَيْنَنَا فِي غَزْوَةٍ غَزَاهَا فَخَرَجَ فِيهَا سَهْمِي فَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ بَعْدَ مَا أُنْزِلَ الْحِجَابُ فَأَنَا أُحْمَلُ فِي هَوْدَجِي وَأُنْزَلُ فِيهِ مَسِيرَنَا حَتَّى إِذَا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوِهِ وَقَفَلَ وَدَنَوْنَا مِنْ الْمَدِينَةِ آذَنَ لَيْلَةً بِالرَّحِيلِ فَقُمْتُ حِينَ آذَنُوا بِالرَّحِيلِ فَمَشَيْتُ حَتَّى جَاوَزْتُ الْجَيْشَ فَلَمَّا قَضَيْتُ مِنْ شَأْنِي أَقْبَلْتُ إِلَى الرَّحْلِ فَلَمَسْتُ صَدْرِي فَإِذَا عِقْدِي مِنْ جَزْعِ ظَفَارِ قَدْ انْقَطَعَ فَرَجَعْتُ فَالْتَمَسْتُ عِقْدِي فَحَبَسَنِي ابْتِغَاؤُهُ وَأَقْبَلَ الرَّهْطُ الَّذِينَ كَانُوا يَرْحَلُونَ لِي فَحَمَلُوا هَوْدَجِي فَرَحَلُوهُ عَلَى بَعِيرِيَ الَّذِي كُنْتُ أَرْكَبُ وَهُمْ يَحْسِبُونَ أَنِّي فِيهِ قَالَتْ وَكَانَتْ النِّسَاءُ إِذْ ذَاكَ خِفَافًا لَمْ يُهَبَّلْنَ وَلَمْ يَغْشَهُنَّ اللَّحْمُ إِنَّمَا يَأْكُلْنَ الْعُلْقَةَ مِنْ الطَّعَامِ فَلَمْ يَسْتَنْكِرْ الْقَوْمُ ثِقَلَ الْهَوْدَجِ حِينَ رَحَلُوهُ وَرَفَعُوهُ وَكُنْتُ جَارِيَةً حَدِيثَةَ السِّنِّ فَبَعَثُوا الْجَمَلَ وَسَارُوا وَوَجَدْتُ عِقْدِي بَعْدَ مَا اسْتَمَرَّ الْجَيْشُ فَجِئْتُ مَنَازِلَهُمْ وَلَيْسَ بِهَا دَاعٍ وَلَا مُجِيبٌ فَتَيَمَّمْتُ مَنْزِلِي الَّذِي كُنْتُ فِيهِ وَظَنَنْتُ أَنَّ الْقَوْمَ سَيَفْقِدُونِي فَيَرْجِعُونَ إِلَيَّ فَبَيْنَا أَنَا جَالِسَةٌ فِي مَنْزِلِي غَلَبَتْنِي عَيْنِي فَنِمْتُ وَكَانَ صَفْوَانُ بْنُ الْمُعَطَّلِ السُّلَمِيُّ ثُمَّ الذَّكْوَانِيُّ قَدْ عَرَّسَ مِنْ وَرَاءِ الْجَيْشِ فَادَّلَجَ فَأَصْبَحَ عِنْدَ مَنْزِلِي فَرَأَى سَوَادَ إِنْسَانٍ نَائِمٍ فَأَتَانِي فَعَرَفَنِي حِينَ رَآنِي وَقَدْ كَانَ يَرَانِي قَبْلَ أَنْ يُضْرَبَ الْحِجَابُ عَلَيَّ فَاسْتَيْقَظْتُ بِاسْتِرْجَاعِهِ حِينَ عَرَفَنِي فَخَمَّرْتُ وَجْهِي بِجِلْبَابِي وَ وَاللَّهِ مَا يُكَلِّمُنِي كَلِمَةً وَلَا سَمِعْتُ مِنْهُ كَلِمَةً غَيْرَ اسْتِرْجَاعِهِ حَتَّى أَنَاخَ رَاحِلَتَهُ فَوَطِئَ عَلَى يَدِهَا فَرَكِبْتُهَا فَانْطَلَقَ يَقُودُ بِيَ الرَّاحِلَةَ حَتَّى أَتَيْنَا الْجَيْشَ بَعْدَ مَا نَزَلُوا مُوغِرِينَ فِي نَحْرِ الظَّهِيرَةِ فَهَلَكَ مَنْ هَلَكَ فِي شَأْنِي وَكَانَ الَّذِي تَوَلَّى كِبْرَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ فَقَدِمْنَا الْمَدِينَةَ فَاشْتَكَيْتُ حِينَ قَدِمْنَا الْمَدِينَةَ شَهْرًا وَالنَّاسُ يُفِيضُونَ فِي قَوْلِ أَهْلِ الْإِفْكِ وَلَا أَشْعُرُ بِشَيْءٍ مِنْ ذَلِكَ وَهُوَ يَرِيبُنِي فِي وَجَعِي أَنِّي لَا أَعْرِفُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللُّطْفَ الَّذِي كُنْتُ أَرَى مِنْهُ حِينَ أَشْتَكِي إِنَّمَا يَدْخُلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُسَلِّمُ ثُمَّ يَقُولُ كَيْفَ تِيكُمْ فَذَاكَ يَرِيبُنِي وَلَا أَشْعُرُ بِالشَّرِّ حَتَّى خَرَجْتُ بَعْدَ مَا نَقَهْتُ وَخَرَجَتْ مَعِي أُمُّ مِسْطَحٍ قِبَلَ الْمَنَاصِعِ وَهُوَ مُتَبَرَّزُنَا وَلَا نَخْرُجُ إِلَّا لَيْلًا إِلَى لَيْلٍ وَذَلِكَ قَبْلَ أَنْ نَتَّخِذَ الْكُنُفَ قَرِيبًا مِنْ بُيُوتِنَا وَأَمْرُنَا أَمْرُ الْعَرَبِ الْأُوَلِ فِي التَّنَزُّهِ وَكُنَّا نَتَأَذَّى بِالْكُنُفِ أَنْ نَتَّخِذَهَا عِنْدَ بُيُوتِنَا فَانْطَلَقْتُ أَنَا وَأُمُّ مِسْطَحٍ وَهِيَ بِنْتُ أَبِي رُهْمِ بْنِ الْمُطَّلِبِ بْنِ عَبْدِ مَنَافٍ وَأُمُّهَا ابْنَةُ صَخْرِ بْنِ عَامِرٍ خَالَةُ أَبِي بَكْرٍ الصِّدِّيقِ وَابْنُهَا مِسْطَحُ بْنُ أُثَاثَةَ بْنِ عَبَّادِ بْنِ الْمُطَّلِبِ فَأَقْبَلْتُ أَنَا وَبِنْتُ أَبِي رُهْمٍ قِبَلَ بَيْتِي حِينَ فَرَغْنَا مِنْ شَأْنِنَا فَعَثَرَتْ أُمُّ مِسْطَحٍ فِي مِرْطِهَا فَقَالَتْ تَعِسَ مِسْطَحٌ فَقُلْتُ لَهَا بِئْسَ مَا قُلْتِ أَتَسُبِّينَ رَجُلًا قَدْ شَهِدَ بَدْرًا قَالَتْ أَيْ هَنْتَاهْ أَوْ لَمْ تَسْمَعِي مَا قَالَ قُلْتُ وَمَاذَا قَالَ قَالَتْ فَأَخْبَرَتْنِي بِقَوْلِ أَهْلِ الْإِفْكِ فَازْدَدْتُ مَرَضًا إِلَى مَرَضِي فَلَمَّا رَجَعْتُ إِلَى بَيْتِي فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ ثُمَّ قَالَ كَيْفَ تِيكُمْ قُلْتُ أَتَأْذَنُ لِي أَنْ آتِيَ أَبَوَيَّ قَالَتْ وَأَنَا حِينَئِذٍ أُرِيدُ أَنْ أَتَيَقَّنَ الْخَبَرَ مِنْ قِبَلِهِمَا فَأَذِنَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُ أَبَوَيَّ فَقُلْتُ لِأُمِّي يَا أُمَّتَاهْ مَا يَتَحَدَّثُ النَّاسُ فَقَالَتْ يَا بُنَيَّةُ هَوِّنِي عَلَيْكِ فَوَاللَّهِ لَقَلَّمَا كَانَتْ امْرَأَةٌ قَطُّ وَضِيئَةٌ عِنْدَ رَجُلٍ يُحِبُّهَا وَلَهَا ضَرَائِرُ إِلَّا كَثَّرْنَ عَلَيْهَا قَالَتْ قُلْتُ سُبْحَانَ اللَّهِ وَقَدْ تَحَدَّثَ النَّاسُ بِهَذَا قَالَتْ فَبَكَيْتُ تِلْكَ اللَّيْلَةَ حَتَّى أَصْبَحْتُ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ ثُمَّ أَصْبَحْتُ أَبْكِي وَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَأُسَامَةَ بْنَ زَيْدٍ حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْتَشِيرُهُمَا فِي فِرَاقِ أَهْلِهِ قَالَتْ فَأَمَّا أُسَامَةُ بْنُ زَيْدٍ فَأَشَارَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالَّذِي يَعْلَمُ مِنْ بَرَاءَةِ أَهْلِهِ وَبِالَّذِي يَعْلَمُ فِي نَفْسِهِ لَهُمْ مِنْ الْوُدِّ فَقَالَ يَا رَسُولَ اللَّهِ هُمْ أَهْلُكَ وَلَا نَعْلَمُ إِلَّا خَيْرًا وَأَمَّا عَلِيُّ بْنُ أَبِي طَالِبٍ فَقَالَ لَمْ يُضَيِّقْ اللَّهُ عَلَيْكَ وَالنِّسَاءُ سِوَاهَا كَثِيرٌ وَإِنْ تَسْأَلْ الْجَارِيَةَ تَصْدُقْكَ قَالَتْ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرِيرَةَ فَقَالَ أَيْ بَرِيرَةُ هَلْ رَأَيْتِ مِنْ شَيْءٍ يَرِيبُكِ مِنْ عَائِشَةَ قَالَتْ لَهُ بَرِيرَةُ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنْ رَأَيْتُ عَلَيْهَا أَمْرًا قَطُّ أَغْمِصُهُ عَلَيْهَا أَكْثَرَ مِنْ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ عَجِينِ أَهْلِهَا فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ قَالَتْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَاسْتَعْذَرَ مِنْ عَبْدِ اللَّهِ بْنِ أُبَيٍّ ابْنِ سَلُولَ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَا مَعْشَرَ الْمُسْلِمِينَ مَنْ يَعْذِرُنِي مِنْ رَجُلٍ قَدْ بَلَغَ أَذَاهُ فِي أَهْلِ بَيْتِي فَوَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي إِلَّا خَيْرًا وَلَقَدْ ذَكَرُوا رَجُلًا مَا عَلِمْتُ عَلَيْهِ إِلَّا خَيْرًا وَمَا كَانَ يَدْخُلُ عَلَى أَهْلِي إِلَّا مَعِي فَقَامَ سَعْدُ بْنُ مُعَاذٍ الْأَنْصَارِيُّ فَقَالَ أَنَا أَعْذِرُكَ مِنْهُ يَا رَسُولَ اللَّهِ إِنْ كَانَ مِنْ الْأَوْسِ ضَرَبْنَا عُنُقَهُ وَإِنْ كَانَ مِنْ إِخْوَانِنَا الْخَزْرَجِ أَمَرْتَنَا فَفَعَلْنَا أَمْرَكَ قَالَتْ فَقَامَ سَعْدُ بْنُ عُبَادَةَ وَهُوَ سَيِّدُ الْخَزْرَجِ وَكَانَ رَجُلًا صَالِحًا وَلَكِنْ اجْتَهَلَتْهُ الْحَمِيَّةُ فَقَالَ لِسَعْدِ بْنِ مُعَاذٍ كَذَبْتَ لَعَمْرُ اللَّهِ لَا تَقْتُلُهُ وَلَا تَقْدِرُ عَلَى قَتْلِهِ فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ وَهُوَ ابْنُ عَمِّ سَعْدِ بْنِ مُعَاذٍ فَقَالَ لِسَعْدِ بْنِ عُبَادَةَ كَذَبْتَ لَعَمْرُ اللَّهِ لَنَقْتُلَنَّهُ فَإِنَّكَ مُنَافِقٌ تُجَادِلُ عَنْ الْمُنَافِقِينَ فَثَارَ الْحَيَّانِ الْأَوْسُ وَالْخَزْرَجُ حَتَّى هَمُّوا أَنْ يَقْتَتِلُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ عَلَى الْمِنْبَرِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا وَسَكَتَ قَالَتْ وَبَكَيْتُ يَوْمِي ذَلِكَ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ ثُمَّ بَكَيْتُ لَيْلَتِي الْمُقْبِلَةَ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ وَأَبَوَايَ يَظُنَّانِ أَنَّ الْبُكَاءَ فَالِقٌ كَبِدِي فَبَيْنَمَا هُمَا جَالِسَانِ عِنْدِي وَأَنَا أَبْكِي اسْتَأْذَنَتْ عَلَيَّ امْرَأَةٌ مِنْ الْأَنْصَارِ فَأَذِنْتُ لَهَا فَجَلَسَتْ تَبْكِي قَالَتْ فَبَيْنَا نَحْنُ عَلَى ذَلِكَ دَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ ثُمَّ جَلَسَ قَالَتْ وَلَمْ يَجْلِسْ عِنْدِي مُنْذُ قِيلَ لِي مَا قِيلَ وَقَدْ لَبِثَ شَهْرًا لَا يُوحَى إِلَيْهِ فِي شَأْنِي بِشَيْءٍ قَالَتْ فَتَشَهَّدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ و","id":"Telah menceritakan kepada kami [Hibban bin Musa] Telah mengabarkan kepada kami [Abdullah bin Al Mubarak] Telah menceritakan kepada kami [Yunus bin Yazid Al Aili] Demikian juga diriwayatkan dari jalur lainnya, Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Muhammad bin Rafi'] serta ['Abad bin Humaid]. Ibnu Rafi' berkata; Telah menceritakan kepada kami. Sedangkan yang lainnya berkata; Telah mengabarkan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar], yang mana jalur Haditsnya adalah riwayat dari 'Abd dan Ibnu Rafi'. Yunus dan Ma'mar berkata; secara keseluruhan dari [Az Zuhri] Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Urwah bin Zubair], [AlQamah bin Waqqash], [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] dari Hadits [Aisyah] -istri Rasulullah shallallahu 'alaihi wasallam- tatkala orang yang menyebarkan isu bohong berkata semaunya tentanya dengan apa yang mereka katakan, Lalu Allah menjelaskan kesucian dirinya dari tuduhan tersebut. Ada sekelompok orang yang menceritakan kepadaku mengenai kejadian tersebut, sebagian mereka menerima cerita kajadian tersebut dari sebagian yang lain, sehingga kisah tersebut seolah-olah menjadi kuat, hingga saya hafal perkataan dari setiap yang mereka ceritakan kepadaku dan sebagian cerita membenarkan yang lain. Dari Urwah ia menceritakan kepadaku dari Aisyah istri Nabi shallallahu 'alaihi wasallam berkata; apabila Rasulullah shallaallahu 'alaihi wa sallam hendak berpergian, beliau mengundi di antara isteri-isterinya. Barang siapa yang keluar undiannya, dialah yang ikut pergi bersama Rasulullah shallaallahu 'alaihi wa sallam.\" Aisyah berkata; \"Kemudian beliau mengundi di antara kami pada suatu peperangan dan keluarlah undian anak panahku, sehingga aku pergi bersama Rasulullah shallaallahu 'alaihi wa sallam. Kejadian tersebut setelah diturunkannya ayat tentang hijab. Lalu saya dibawa di sekedupku. Di tengah perjalanan, saya turun hingga Rasulullah shallaallahu 'alaihi wa sallam selesai dari sebuah peperangan dan beliau pun kembali ke Madinah. Pada suatu malam saya berada bersama kelompok kaum muslimin. Tatkala mereka tertidur, saya bangun dan berjalan hingga aku mendahului mereka. Setelah saya selesai menunaikan urusanku, saya kembali bergabung dengan kelompok kaum muslimin. Tatkala saya meraba dadaku, ternyata kalungku yang berasal dari Zhafar, Yaman, putus. Maka saya kembali dan mencari kalungku, pencarian itu membuatku terlambat. Dan, sekelompok orang yang membawa sekedupku telah berangkat, mereka berjalan dengan meletakkan sekedupku di atas untaku yang biasa saya kendarai. Mereka mengira bila aku sudah berada di dalamnya.\" Aisyah berkata; \"Tatkala itu, isteri-isteri beliau kurus-kurus dan ringan, karena tidak pernah makan daging. Tetapi, mereka hanya memakan makanan ringan. Sehingga, tidak ada orang yang curiga terhadap beratnya sekedup tersebut, ketika mereka berjalan dan mengangkatnya. Terlebih, kala itu aku masih kecil. Akhirnya merekapun membawa unta-untanya dan berjalan (meneruskan perjalanan). Saya mendapatkan kalungku tatkala bala tentara telah berlalu. Sehingga, ketika saya mendatangi tempat duduk mereka, tidak ada seorang pun yang memanggil dan tidak ada pula orang yang menjawab. Lalu saya kembali ke tempat dudukku di tempat saya duduk. Saya berharap ada suatu kaum (dari tentara kaum muslimin) yang menemukanku dan kembali menjemputku. Tatkala saya duduk di tempat dudukku, saya merasa ngantuk dan tertidur. Sedangkan Shafwan bin Mu'atthal Assulami dan orang-orang Dzakwan tinggal di belakang pasukan (memeriksa bila ada yang ketinggalan). Mereka berjalan diawal malam dan di pagi harinya mereka sampai di tempat dudukku. Shafwan bin al Mu'atthal Assulami melihat ada seseorang yang masih tertidur, maka dia mendatangiku dan dia telah mengenaliku tatkala dia melihatku. Yang demikian karena dia telah melihatku sebelum diwajibkan memakai hijab atasku. Seketika saya terbangun dan saya mendengar dia beristirja' (mengucapkan, inna lillahi wa inna ilaihi raaji'un) tatkala ia mengetahuiku. Saya langsung menutupi wajahku dengan jilbabku. Demi Allah, dia tidak berbicara sepatah katapun dan saya sama sekali tidak mendengar satu patah kata pun kecuali kata istirja'nya. Akhirnya ia pun merundukkan untanya dan saya pun menaikinya. Lalu ia pergi dan menuntun unta (yang saya naiki) hingga kami berhasil menyusul pasukan kaum muslimin setelah mereka berisitirahat di pantai Azhzhariah. Celakalah orang yang telah berburuk sangka pada urusanku. Ketika itu, orang yang paling terlihat kesombongannya adalah Abdullah bin Ubay bin Salul. Akhirnya, saya pun sampai di Madinah. Setelah kedatangan kami, saya mendadak sakit hampir selama satu bulan, sementara orang-orang terus larut membicarakan tuduhan (yang ditujukan kepadaku), padahal aku tidak sedikit pun merasa melakukan hal itu. Sehingga, beliau pun meragukan sakitku. Saya tidak lagi tahu kelembutan Rasulullah shallaallahu 'alaihi wa sallam yang pernah aku lihat darinya sebelumnya. Tatkala aku sakit, Rasulullah shallaallahu 'alaihi wa sallam masuk dan memberi salam seraya bertanya; \"Bagaimana denganmu?\" Seolah-olah tatkala itu beliau meragukanku, sementara saya tidak merasa telah melakukan kejelekan tersebut. Setelah saya merasa mulai sembuh, saya keluar bersama Ummu Misthah ke tempat tertutup untuk buang air, kami tidak pernah keluar kecuali di malam hari hingga malam lagi. Tempat tertutup tersebut dibuat di dekat rumah-rumah kami. Urusan kami seperti para pendahulu orang-orang Arab, kami biasa membuat tempat tertutup untuk buang air di rumah. Kemudian saya dan Ummu Misthah -dia adalah anak perempuannya Abu Ruhmi bin al Muthallib bin Abdi Manaf dan ibunya adalah anak perempuannya Shakhr bin Amir, bibinya Abu Bakr ash Shidiq dan anaknya adalah Misthah bin Utsabah bin Abbad bin al Muthallib- kembali ke rumahku setelah urusan kami selesai. Tatkala itu, Ummu Misthah terpeleset karena menginjak atau terjerat kainnya. Ketika itu ia berkata; \"Celaka Misthah.\" Saya bertanya kepadanya; \"Alangkah jeleknya apa yang telah kamu katakan, engkau mencela orang yang telah ikut perang Badar?.\" Dia berkata; \"Ya, apakah kamu tidak mendengar apa yang dia katakan?\" saya berkata; \"Apa yang telah dia katakan?\" maka dia mengabarkan kepadaku dengan perkataan orang-orang yang menuduhku. Tatkala itu saya bertambah sakit dan ketika saya kembali ke rumahku, Rasulullah shallaallahu 'alaihi wa sallam menemuiku dan mengucapkan salam. Kemudian beliau bersabda: \"Bagaimana keadaanmu?\" Saya berkata; \"Apakah engkau mengizinkanku untuk mendatangi kedua orang tuaku?\" ia berkata; \"Ketika itu saya ingin meyakinkan kabar tersebut dari mereka berdua. Akhirnya, Rasulullah shallaallahu 'alaihi wa sallam pun mengizinkanku. Lalu saya mendatangi kedua orang tuaku, saya bertanya kepada ibuku; \"Wahai ibuku, apa yang sedang dibicarakan oleh orang-orang?\" ia menjawab; \"Wahai anakku, semoga urusanmu dimudahkan, demi Allah, tidaklah seorang wanita yang jelas-jelas dicintai suaminya sedang ia mempunyai madu (isteri suami lainnya), kecuali mereka (isteri-isteri suami lainnya) akan memperbanyak tuduhan atas diri wanita tersebut.\" ia berkata; \"Maha Suci Allah, apakah ini yang dibicarakan oleh orang-orang?\" ia berkata; \"Pada malam itu juga aku menangis, hingga di pagi harinya air mataku tidak lagi bisa mengalir karena habis dan saya tidak bercelak ketika tidur. Ketika di pagi harinya, saya menangis. Dan, ketika itu Rasulullah shallaallahu 'alaihi wa sallam memanggil Ali bin Abi Thalib dan Usamah bin Zaid untuk mengajak keduanya bermusyawarah dalam rangka memisahkan isterinya selama wahyu belum turun.\" Aisyah berkata; \"Adapun Usamah bin Zaid, dia menunjuki kepada Rasulullah shallaallahu 'alaihi wa sallam dengan apa yang ia ketahui akan jauhnya istri beliau dari perbuatan tersebut dan dengan apa yang ia ketahui tentang kecintaannya kepada beliau. Usamah berkata; 'Wahai Rasulullah! Mereka adalah isteri-isterimu, kami tidak mengetahui kecuali kebaikan.' Adapun Ali bin Abi Thalib, ia berkata; \"Allah 'azza wajalla tidak akan memberi kesempitan kepadamu, kan wanita selainnya masih banyak juga. Dan sungguh, jika engkau bertanya kepada budakmu, pasti dia akan jujur'.\" Aisyah berkata; \"Kemudian Rasulullah shallaallahu 'alaihi wa sallam memanggil Barirah, beliau bertanya: \"Wahai Barirah! Apakah engkau melihat ada sesuatu yang meragukan bagimu dari diri Aisyah?\" Barirah menjawab; \"Demi Dzat yang mengutusmu dengan kebenaran, saya tidak melihat pada dirinya suatu yang kurang selain tak lebih saat ia masih kecil umurnya, ia ketiduran dari menunggu adonan tepung di keluarganya lantas ada binatang jinak yang memakan tepung itu.\" kemudian Rasulullah shallaallahu 'alaihi wa sallam berdiri dan meminta argumentasi dari seorang lelaki yang bernama Abdullah bin Ubai bin Salul. Tatkala Rasulullah shallaallahu 'alaihi wa sallam berada di atas mimbar, Rasulullah shallaallahu 'alaihi wa sallam bersabda: \"Wahai seluruh kaum muslimin, siapakah yang mau memberiku argumentasi dari seorang lelaki yang telah menyakiti keluargaku. Sungguh demi Allah, saya tidak mengetahui sesuatupun dari keluargaku kecuali kebaikan. Mereka telah menceritakan mengenai seorang lelaki yang saya tidak mengetahui dari dirinya kecuali kebaikan. Dan tidaklah ada orang yang menemui isteriku kecuali ia bersamaku.\" Sa'ad bin Mu'adz al Anshari berkata; \"Wahai Rasulullah! aku akan menolongmu darinya. Bila ada orang dari bani Aus di penggal lehernya, sekalipun dari saudara kami dari bani Khazraj, bila engkau memerintahkan kami maka kami akan melaksanakan perintahmu.\" Seketika itu juga Sa'ad bin Ubadah -dia adalah pemimpin dari bani Khazraj, ia adalah seorang lelaki yang shalih. Hanya saja, ia masih memiliki sikap fanatis- berkata kepada Sa'ad bin Mu'ad; \"Demi Allah, engkau tidak akan bisa membunuhnya dan tidak akan mampu untuk membunuhnya.\" Maka berdirilah Usaid bin Hudlair dan dia adalah keponakan Sa'ad bin Mu'adz, ia berkata kepada Sa'ad bin Ubadah; \"Engkau bohong, sungguh kami akan membunuhnya karena kamu seorang yang munafik yang memperdebatkan orang-orang munafik.\" Keadaan pun semakin memanas antara bani Aus dan Khazraj, hingga mereka ingin saling bunuh membunuh sedangkan Rasulullah shallaallahu 'alaihi wa sallam masih tetap berdiri di atas mimbar. Kemudian Rasulullah shallaallahu 'alaihi wa sallam menenangkan mereka, hingga mereka terdiam dan beliaupun terdiam. Pada hari itu, aku pun menangis hingga air mataku habis dan aku tidak memakai celak tatkala tidur. Malam berikutnya, aku masih menangis hingga air mataku habis dan aku tidak memakai celak ketika tidur. Kedua orang tuaku mengira tangisanku akan dapat membelah hatiku. Aisyah berakta; \"Lalu keduanya duduk di sisiku sementara saya masih terus menangis. Ketika itu, ada seorang wanita Anshar yang meminta izin kepadaku untuk menemuiku, akupun mengizinkannya. Ia pun duduk dan ikut menangis bersamaku. Tatkala kami dalam kondisi seperti itu, Rasulullah shallaallahu 'alaihi wa sallam masuk menemui kami, beliau mengucapkan salam lantas beliau duduk.\" Ia berkata; \"Beliau tidak pernah duduk di sisiku selama satu bulan, sejak wahyu tidak diturunkan kepadanya mengenai urusanku.\" Ia berkata; \"Rasulullah shallaallahu 'alaihi wa sallam pun bersaksi, seraya mengucapkan salam sambil duduk. beliau bersabda: \"Amma ba'd, Wahai Aisyah, sesungguhnya telah sampai kepadaku berita begini dan begini, sungguh jika engkau terlepas dari hal itu karena tidak melakukannya, semoga Allah Azzawajalla menjauhkanmu. Jika kamu melakukan dosa tersebut, minta ampunlah kepada Allah dan bertaubatlah kepada-Nya. Karena, seorang hamba yang mengakui dosanya kemudian bertaubat maka Allah akan menerima taubatnya.\" Aisyah berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam selesai berkata, air mataku semakin deras mengalir hingga tidak terasa lagi tetesan air mata tersebut.\" Saya berkata kepada ayahku; \"Jawablah apa yang telah dikatakan Rasulullah shallaallahu 'alaihi wa sallam mengenai diriku.\" Ayahku berkata; \"Saya tidak tahu, demi Allah, saya tidak akan berbicara kepada Rasulullah shallaallahu 'alaihi wa sallam.\" Lalu saya berkata kepada ibuku; \"Jawablah apa yang telah dikatakan Rasulullah shallaallahu 'alaihi wa sallam mengenai diriku!\" ibuku berkata; \"Demi Allah, saya tidak tahu apa yang harus saya katakan kepada Rasulullah shallaallahu 'alaihi wa sallam.\" Aisyah berkata; saya berkata; \"Saya adalah seorang gadis yang masih kecil usianya, saya tidak banyak membaca Al-Qur'an. Demi Allah, sungguh aku mengetahui engkau telah mendengar hal ini hingga kamu merasa mantap dan percaya terhadap hal itu. Dan bila aku bicara kepada kalian; 'Sesungguhnya aku jauh dari perbuatan tersebut dan Allah Azzawajalla Maha Mengetahui bila aku jauh dari perbuatan tersebut. Maka, kalian juga tidak akan percaya terhadap hal itu. Jika saya mengaku kepada kalian dengan suatu perkara, sedang Allah Azzawajalla Maha Mengetahui bahwa aku jauh dari perbuatan tersebut, kalian pasti akan mempercayaiku. Demi Allah, sungguh tidak ada perkataan antara diriku dengan kalian kecuali sebagaimana yang dikatakan oleh Abu Yusuf; Sabar itu adalah baik dan Allah adalah tempat meminta pertolongan terhadap apa yang kalian tuduhkan'. (QS. Yusuf 18) \" Aisyah berkata; \"Kemudian saya merubah posisiku, aku berbaring di atas ranjangku.\" Ia berkata; \"Demi Allah, ketika itu saya mengetahui bahwa aku jauh dari perbuatan tersebut, dan Allah Azzawajalla akan menjauhkanku karena aku jauh dari perbuatan tersebut. Akan tetapi, demi Allah, saya tidak mengira akan turun wahyu pada perkaraku. Dan sungguh perkaraku jauh lebih remeh daripada Allah Azza wa jalla berfirman padaku dengan wahyu yang dibacakan. Harapan saya saat itu hanyalah berharap supaya pada mimpinya Rasulullah shallaallahu 'alaihi wa sallam diperlihatkan bahwa Allah Azzawajalla menjauhkan diriku dari perbuatan tersebut.\" Aisyah berkata; \"Demi Allah, tidaklah Rasulullah shallaallahu 'alaihi wa sallam keluar dari majelisnya, dan tidak ada seorang pun yang keluar dari penghuni rumah tersebut hingga Allah Azzawajalla menurunkan wahyu kepada Nabi-Nya. Sehingga, kondisi beliau berubah sebagaimana perubahan yang biasa terjadi tatkala wahyu turun, keringat beliau terus mengucur padahal hari itu adalah musim dingin. Hal itu karena begitu beratnya firman yang telah diturunkan kepadanya.\" Aisyah berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam mendapat kabar gembira tersebut, beliau tertawa dan kalimat yang pertama kali beliau katakan ketika itu adalah: \"Kabar gembira wahai Aisyah! Allah Azza wa jalla telah menjauhkanmu dari perbuatan tersebut.\" Kemudian ibuku berkata kepadaku; \"Berdirilah kepadanya.\" Aku berkata; \"Demi Allah, aku tidak akan berdiri kepadanya dan aku tidak akan memuji kecuali kepada Allah Azza wa jalla, Dia lah yang telah menurunkan wahyu yang menjelaskan akan jauhnya diriku. Allah Azzawajalla telah menurunkan ayat yang artinya: Sesungguhnya orang-orang yang membawa berita bohong itu adalah dari golongan kamu juga hingga sepuluh ayat (QS. Annuur 1-11). Allah Azzawajalla telah menurunkan beberapa ayat yang menjelaskan akan jauhnya diriku dari perbuatan tersebut.\" Aisyah berkata; \"Abu Bakr terbiasa berinfak kepada Misthah, karena ia adalah kerabatnya dan ia adalah seorang yang fakir. Ia berkata; 'Demi Allah, aku tidak akan pernah memberi bantuan untuknya selamanya setelah dia menuduh Aisyah.' Lalu Allah Azzawajalla menurunkan wahyu, yang artinya; Dan janganlah orang-orang yang mempunyai -sampai kepada firman-Nya- apakah kamu tidak ingin bahwa Allah mengampunimu\" (QS. Annur 22). Hibban bin Musa berkata, Abdullah bin Mubarok berkata: “Ayat ini merupakan ayat yang paling diharapkan di dalam kitabullah. Maka Abu Bakar berkata; 'Demi Allah, saya lebih senang bila Allah mengampuniku'. Kemudian ia kembali memberi bantuan kepada Misthah seperti biasa ia memberi bantuan kepadanya. Abu Bakar berkata; 'Sungguh, aku tidak akan menghentikan bantuan selama-lamanya'.\" Aisyah berkata; Rasulullah shallaallahu 'alaihi wa sallam bertanya kepada Zainab binti Jahsy, istri Nabi shallaallahu 'alaihi wa sallam, mengenai perkara yang terjadi padaku: \"Apa yang kamu ketahui, apa yang kamu lihat, atau berita apa yang telah sampai kepadamu?\" dia menjawab; \"Wahai Rasulullah! Saya selalu menjaga pendengaran dan penglihatanku, dan saya tidak mengetahui kecuali kebaikan.\" Aisyah berkata; \"Padahal Zaenab adalah isteri beliau yang dikenal selalu membanggakan diri di hadapanku,"},"4622":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ رَجُلًا كَانَ يُتَّهَمُ بِأُمِّ وَلَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ اذْهَبْ فَاضْرِبْ عُنُقَهُ فَأَتَاهُ عَلِيٌّ فَإِذَا هُوَ فِي رَكِيٍّ يَتَبَرَّدُ فِيهَا فَقَالَ لَهُ عَلِيٌّ اخْرُجْ فَنَاوَلَهُ يَدَهُ فَأَخْرَجَهُ فَإِذَا هُوَ مَجْبُوبٌ لَيْسَ لَهُ ذَكَرٌ فَكَفَّ عَلِيٌّ عَنْهُ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ لَمَجْبُوبٌ مَا لَهُ ذَكَرٌ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Hammad bin Salamah] Telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwa ada seorang laki laki yang dituduh berzina dengan istri Rasulullah shallallahu 'alaihi wasallam. maka Rasulullah shallallahu 'alaihi wasallam berkata kepada Ali: pergilah, dan penggallah lehernya (karena kemunafikannya). lalu Ali mendatanginya yang ternyata ia sedang mendinginkan dirinya dalam sebuah sumur kecil, Ali berkata padanya: Keluarlah! kemudian Ali menarik tangannya dan ternyata dia adalah seorang laki-laki yang terputus kemaluannya, Maka Ali pun tidak membunuhnya. Lalu Ali datang kepada Rasulullah shallallahu 'alaihi wasallam Seraya berkata; Ya Rasulullah sesungguhnya dia adalah laki laki yang terputus kemaluannya (tidak mempunyai kemaluan)."},"4623":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنَا أَبُو إِسْحَقَ أَنَّهُ سَمِعَ زَيْدَ بْنَ أَرْقَمَ يَقُولُاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ أَصَابَ النَّاسَ فِيهِ شِدَّةٌ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ لِأَصْحَابِهِ{ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ حَتَّى يَنْفَضُّوا }مِنْ حَوْلِهِ قَالَ زُهَيْرٌ وَهِيَ قِرَاءَةُ مَنْ خَفَضَ حَوْلَهُ وَقَالَ{ لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ }قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِذَلِكَ فَأَرْسَلَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَسَأَلَهُ فَاجْتَهَدَ يَمِينَهُ مَا فَعَلَ فَقَالَ كَذَبَ زَيْدٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَوَقَعَ فِي نَفْسِي مِمَّا قَالُوهُ شِدَّةٌ حَتَّى أَنْزَلَ اللَّهُ تَصْدِيقِي{ إِذَا جَاءَكَ الْمُنَافِقُونَ }قَالَ ثُمَّ دَعَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَسْتَغْفِرَ لَهُمْ قَالَ فَلَوَّوْا رُءُوسَهُمْ و قَوْله{ كَأَنَّهُمْ خُشُبٌ مُسَنَّدَةٌ }وَقَالَ كَانُوا رِجَالًا أَجْمَلَ شَيْءٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Zuhair bin Mu'awiyah] telah menceritakan kepada kami [Abu Ishaq] bahwasanya ia mendengar [Zaid bin Arqam] berkata; \"Pada suatu ketika, kami pernah pergi bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan jauh yang pada saat itu para sahabat banyak yang mengalami kesulitan. Kemudian Abdullah bin Ubay berkata kepada teman-temannya; 'Janganlah kalian memberikan perbelanjaan kepada orang-orang yang berada di sisi Rasulullah agar mereka meninggalkan Rasulullah.' Zuhair berkata; 'Lafaz 'Haulihi' (dengan kasrah pada huruf lam) yaitu menurut bacaan yang paling rajih. Abdullah bin Ubay berkata; 'Sesungguhnya jika kita telah kembali ke Madinah, maka orang-orang yang kuat benar-benar akan dapat mengusir orang-orang yang lemah.' (Qs.Al Munaafiquun (63): 8). Zaid bin Arqam berkata; 'Lalu saya pergi menghadap Nabi Muhammad shallallahu 'alaihi wasallam untuk memberitahukan tentang ucapan Abdullah bin Ubay tersebut kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus seseorang kepada Abdullah bin Ubay untuk menginterogasinya. Namun, ternyata Abdullah bin Ubay bersumpah bahwa ia tidak pernah berkata seperti itu! Dan ia berkata; 'Zaid telah membohongi Rasulullah shallallahu 'alaihi wasallam.' Zaid bin Arqam berkata; 'Tentu saja ucapan orang-orang munafiq itu membuat hati saya menjadi jengkel, hingga Allah Subhanahu wa Ta'ala menurunkan ayat yang membenarkan sikap saya yang berbunyi: 'Apabila orang-orang munafik datang kepadamu… (Qs. Al Munaafiquun (63): 1) '. Zaid bin Arqam berkata; 'Lalu Rasulullah shallallahu 'alaihi wasallam memanggil mereka, orang-orang munafik, untuk dimintakan ampunan kepada Allah, tetapi mereka malah membuang muka.' Allah Subhanahu wa Ta'ala berfirman: 'Orang-orang munafik itu seolah-olah kayu yang tersandar…' (Al Munaafiquun (63): 4). Zaid bin Arqam berkata; 'Mereka itu sebenarnya adalah orang-orang yang secara zhahir kelihatan mempesona.'"},"4624":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَأَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالَ ابْنُ عَبْدَةَ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو أَنَّهُ سَمِعَ جَابِرًا يَقُولُاأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرَ عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَأَخْرَجَهُ مِنْ قَبْرِهِ فَوَضَعَهُ عَلَى رُكْبَتَيْهِ وَنَفَثَ عَلَيْهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ فَاللَّهُ أَعْلَمُحَدَّثَنِي أَحْمَدُ بْنُ يُوسُفَ الْأَزْدِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُا جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ بَعْدَ مَا أُدْخِلَ حُفْرَتَهُ فَذَكَرَ بِمِثْلِ حَدِيثِ سُفْيَانَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ahmad bin 'Abdah Adh Dhabbi] -dan lafadh ini milik Ibnu Abu Syaibah- Ibnu Abdah berkata; Telah mengabarkan kepada kami, dan berkata yang lain; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] bahwasanya ia mendengar [Jabir] berkata; Nabi shallallahu 'alaihi wasallam mendatangi kuburan Abdullah bin Ubbay, setelah ia dimasukkan ke dalam kuburannya, lalu beliau memerintahkan untuk dikeluarkan, dan beliau meletakkannya di atas lutut beliau, kemudian beliau meniup sedikit air liur padanya dan memakaikan baju beliau.\" Wallahu A'lam. Telah menceritakan kepadaku [Ahmad bin Yusuf Al Azdi] telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku ['Amru bin Dinar] dia berkata; Aku mendengar [Jabir bin 'Abdullah] berkata; \"Nabi shallallahu 'alaihi wasallam mendatangi kuburan Abdullah bin Ubbay, setelah ia dimasukkan ke dalam kuburannya. -selanjutnya sebagaimana Hadits Sufyan."},"4625":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ ابْنِ مَسْعُودٍ قَالَاجْتَمَعَ عِنْدَ الْبَيْتِ ثَلَاثَةُ نَفَرٍ قُرَشِيَّانِ وَثَقَفِيٌّ أَوْ ثَقَفِيَّانِ وَقُرَشِيٌّ قَلِيلٌ فِقْهُ قُلُوبِهِمْ كَثِيرٌ شَحْمُ بُطُونِهِمْ فَقَالَ أَحَدُهُمْ أَتُرَوْنَ اللَّهَ يَسْمَعُ مَا نَقُولُ وَقَالَ الْآخَرُ يَسْمَعُ إِنْ جَهَرْنَا وَلَا يَسْمَعُ إِنْ أَخْفَيْنَا وَقَالَ الْآخَرُ إِنْ كَانَ يَسْمَعُ إِذَا جَهَرْنَا فَهُوَ يَسْمَعُ إِذَا أَخْفَيْنَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ وَلَا جُلُودُكُمْ }الْآيَةَو حَدَّثَنِي أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي سُلَيْمَانُ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ وَهْبِ بْنِ رَبِيعَةَ عَنْ عَبْدِ اللَّهِ ح و قَالَ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Umar Al Makki] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Ibnu Mas'ud] dia berkata; \"Ada tiga orang berkumpul di dekat Ka'bah, dua orang dari suku Quraisy dan satu lagi dari suku Tsaqafi atau sebaliknya. Ketiga-tiganya kurang terpelajar tetapi mereka gemuk-gemuk. Salah seorang dari mereka bertanya kepada temannya; 'Tahukah kamu bahwa Allah mendengar apa yang kita ucapkan? ' Jawab yang lain; 'Dia mendengar kalau kita bicara keras, dan tidak mendengar kalau kita bicara perlahan.' Kata orang yang ketiga; 'Jika Dia mendengar ketika kita berbicara keras tentu Dia mendengar juga ketika kita berbicara perlahan.' Lalu Allah Azza wa Jalla menurunkan ayat: 'Kamu sekali-kali tidak kalian tidak dapat menyembunyikan dari kesaksian pendengaran, penglihatan, dan kulitmu…'. (QS. Fushilat (41): 22). Dan telah menceritakan kepadaku [Abu Bakr bin Khallad Al Bahili] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Sulaiman] dari ['Umarah bin 'Umair] dari [Wahb bin Rabi'ah] dari ['Abdullah] Demikian juga diriwayatkan dari jalur lainnya, dan dia berkata; telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari ['Abdullah] dengan Hadits yang serupa."},"4626":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ وَهُوَ ابْنُ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى أُحُدٍ فَرَجَعَ نَاسٌ مِمَّنْ كَانَ مَعَهُ فَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ فِرْقَتَيْنِ قَالَ بَعْضُهُمْ نَقْتُلُهُمْ وَقَالَ بَعْضُهُمْ لَا فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dia berkata; aku mendengar ['Abdullah bin Yazid] bercerita dari [Zaid bin Tsabit] bahwa ketika Nabi shallallahu 'alaihi wasallam berangkat ke medan perang Uhud, beberapa orang yang ikut berangkat bersama-sama beliau pulang kembali di tengah perjalanan. Karena itu, para sahabat Nabi shallallahu 'alaihi wasallam berbeda pendapat mengenai mereka menjadi dua golongan: Sebagian mengatakan mereka harus diperangi dan sebagian lagi mengatakan jangan diperangi. Karena itu, turunlah ayat: 'Mengapa kamu menjadi dua golongan dalam (menghadapi) orang-orang munafik…' (QS. An Nisaa (4): 88). Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepadaku [Abu Bakr bin Nafi'] telah menceritakan kepada kami [Ghundar] keduanya dari [Syu'bah] melalui sanad ini dengan Hadits yang serupa."},"4627":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُأَنَّ مَرْوَانَ قَالَ اذْهَبْ يَا رَافِعُ لِبَوَّابِهِ إِلَى ابْنِ عَبَّاسٍ فَقُلْ لَئِنْ كَانَ كُلُّ امْرِئٍ مِنَّا فَرِحَ بِمَا أَتَى وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ يَفْعَلْ مُعَذَّبًا لَنُعَذَّبَنَّ أَجْمَعُونَ فَقَالَ ابْنُ عَبَّاسٍ مَا لَكُمْ وَلِهَذِهِ الْآيَةِ إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ الْكِتَابِ ثُمَّ تَلَا ابْنُ عَبَّاسٍ{ وَإِذْ أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ }هَذِهِ الْآيَةَ وَتَلَا ابْنُ عَبَّاسٍ{ لَا تَحْسَبَنَّ الَّذِينَ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }وَقَالَ ابْنُ عَبَّاسٍ سَأَلَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ فَكَتَمُوهُ إِيَّاهُ وَأَخْبَرُوهُ بِغَيْرِهِ فَخَرَجُوا قَدْ أَرَوْهُ أَنْ قَدْ أَخْبَرُوهُ بِمَا سَأَلَهُمْ عَنْهُ وَاسْتَحْمَدُوا بِذَلِكَ إِلَيْهِ وَفَرِحُوا بِمَا أَتَوْا مِنْ كِتْمَانِهِمْ إِيَّاهُ مَا سَأَلَهُمْ عَنْهُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin 'Abdullah] -dan lafadh ini milik Zuhair- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij]; telah mengabarkan kepadaku [Ibnu Abu Malikah] bahwasanya [Humaid bin 'Abdurrahman bin 'Auf] mengabarkan kepadanya bahwasanya Marwan berkata; \"Wahai Abu Rafi', katakan kepada kepada penjaga pintu agar dia pergi menemui Ibnu Abbas, tanyakan kepadanya; 'Apabila setiap orang dari kita yang merasa senang dengan apa yang dia kerjakan dan yang menyukai untuk dipuji terhadap apa yang belum dia kerjakan akan di adzab, dengan demikian berarti kita semua akan di adzab? [Ibnu Abbas] berkata; 'Apa hubungannya kalian dengan ayat ini? ' Ayat ini hanya di turunkan mengenai Ahlu kitab. Lalu Ibnu Abbas membaca ayat; \"Dan (ingatlah), ketika Allah mengambil janji dari orang-orang yang telah diberi (yaitu), \"Hendaklah kamu benar-benar menerangkannya (isi kitab itu) kepada manusia dan janganlah kamu menyembunyikannya. (QS. Ali Imran 187) \" Dan Ibnu Abbas membaca ayat; \"Dan janganlah sekali-kali kamu mengira bahwa orang yang gembira dengan apa yang telah mereka kerjakan dan mereka suka dipuji atas perbuatan yang tidak mereka lakukan. (QS. Ali'Imran 188) \" Ibnu Abbas berkata; Yaitu ketika nabi shallallahu 'alaihi wasallam menanyakan kepada mereka tentang sesuatu, namun mereka menyembunyikannya dan mengabarkan hal yang lain. Lalu mereka keluar. Sungguh aku melihat beliau diberitahu tentang yang beliau tanyakan kepada mereka hingga mereka ingin dipuji dengan apa yang telah mereka kabarkan itu dan mereka senang dengan apa yang telah mereka kerjakan dari menyembunyikan sesuatu yang beliau tanyakan.'"},"4628":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ بْنُ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ قَيْسٍ قَالَ قُلْتُ لِعَمَّارٍأَرَأَيْتُمْ صَنِيعَكُمْ هَذَا الَّذِي صَنَعْتُمْ فِي أَمْرِ عَلِيٍّ أَرَأْيًا رَأَيْتُمُوهُ أَوْ شَيْئًا عَهِدَهُ إِلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ كَافَّةً وَلَكِنْ حُذَيْفَةُ أَخْبَرَنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَصْحَابِي اثْنَا عَشَرَ مُنَافِقًا فِيهِمْ ثَمَانِيَةٌ{ لَا يَدْخُلُونَ الْجَنَّةَ حَتَّى يَلِجَ الْجَمَلُ فِي سَمِّ الْخِيَاطِ }ثَمَانِيَةٌ مِنْهُمْ تَكْفِيكَهُمُ الدُّبَيْلَةُ وَأَرْبَعَةٌلَمْ أَحْفَظْ مَا قَالَ شُعْبَةُ فِيهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Syu'bah bin Al Hajjaj] dari [Qatadah] dari [Abu Nadhrah] dari [Qais] dia berkata; Saya pernah bertanya kepada Ammar, 'Bagaimanakah pendapatmu tentang peperangan melawan Ali? Atau, bagaimana pesan Rasulullah yang telah disampaikan kepadamu? ' [Ammar] menjawab; 'Rasulullah shallallahu 'alaihi wasallam tidak pernah menyampaikan pesan kepada kami suatu pesan yang tidak beliau sampaikan juga kepada semua orang.' 'Saya diberitahu oleh [Hudzaifah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Di kalangan sahabatku ada dua belas orang munafik. Di antara mereka ada delapan orang yang tidak akan masuk surga hingga ada seekor unta yang dapat masuk ke dalam lubang jarum. Delapan orang di antara mereka pasti akan tertimpa Dubailah, sedangkan yang empat lagi aku tidak hafal apa yang dikatakan Syu'bah tentang mereka.' "},"4629":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ قُلْنَا لِعَمَّارٍأَرَأَيْتَ قِتَالَكُمْ أَرَأْيًا رَأَيْتُمُوهُ فَإِنَّ الرَّأْيَ يُخْطِئُ وَيُصِيبُ أَوْ عَهْدًا عَهِدَهُ إِلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ كَافَّةً وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي أُمَّتِي قَالَ شُعْبَةُ وَأَحْسِبُهُ قَالَ حَدَّثَنِي حُذَيْفَةُ وَقَالَ غُنْدَرٌ أُرَاهُ قَالَ فِي أُمَّتِي اثْنَا عَشَرَ مُنَافِقًا{ لَا يَدْخُلُونَ الْجَنَّةَ }وَلَا يَجِدُونَ رِيحَهَا{ حَتَّى يَلِجَ الْجَمَلُ فِي سَمِّ الْخِيَاطِ }ثَمَانِيَةٌ مِنْهُمْ تَكْفِيكَهُمُ الدُّبَيْلَةُ سِرَاجٌ مِنْ النَّارِ يَظْهَرُ فِي أَكْتَافِهِمْ حَتَّى يَنْجُمَ مِنْ صُدُورِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -dan lafadh ini milik Al Mutsanna- mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Nadlrah] dari [Qais bin 'Ubad] dia berkata; \"Saya pernah bertanya kepada Ammar, 'Bagaimanakah pendapatmu tentang peperanganmu? Sesungguhnya pendapat itu bisa salah dan bisa pula benar. Atau, bagaimana pesan Rasulullah yang telah disampaikan kepadamu? ' Ammar menjawab; 'Rasulullah shallallahu 'alaihi wasallam tidak pernah menyampaikan pesan kepada kami suatu pesan yang tidak beliau sampaikan juga kepada semua orang.' [Ammar] berkata; 'Sesungguhnya Rasulullah pernah bersabda: 'Sesungguhnya di kalangan umatku (Syu'bah) berkata; 'Menurut saya Ammar berkata; 'Saya diberitahu oleh [Hudzaifah] …' Ghundar berkata; 'Saya pernah melihat Rasulullah ketika beliau bersabda: '(Di kalangan umatku) ada dua belas orang munafik yang tidak akan masuk surga. Bahkan mereka tidak akan dapat mencium harumnya surga kecuali jika ada seekor unta yang dapat masuk ke dalam lubang jarum. Delapan orang di antara mereka pasti akan tertimpa Dubailah, yaitu pijaran api yang menyengat bagian belakang pundak sehingga tembus ke dada mereka.'"},"4630":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَصْعَدُ الثَّنِيَّةَ ثَنِيَّةَ الْمُرَارِ فَإِنَّهُ يُحَطُّ عَنْهُ مَا حُطَّ عَنْ بَنِي إِسْرَائِيلَ قَالَ فَكَانَ أَوَّلَ مَنْ صَعِدَهَا خَيْلُنَا خَيْلُ بَنِي الْخَزْرَجِ ثُمَّ تَتَامَّ النَّاسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُلُّكُمْ مَغْفُورٌ لَهُ إِلَّا صَاحِبَ الْجَمَلِ الْأَحْمَرِ فَأَتَيْنَاهُ فَقُلْنَا لَهُ تَعَالَ يَسْتَغْفِرْ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَاللَّهِ لَأَنْ أَجِدَ ضَالَّتِي أَحَبُّ إِلَيَّ مِنْ أَنْ يَسْتَغْفِرَ لِي صَاحِبُكُمْ قَالَ وَكَانَ رَجُلٌ يَنْشُدُ ضَالَّةً لَهُو حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا قُرَّةُ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَصْعَدُ ثَنِيَّةَ الْمُرَارِ أَوْ الْمَرَارِ بِمِثْلِ حَدِيثِ مُعَاذٍ غَيْرَ أَنَّهُ قَالَ وَإِذَا هُوَ أَعْرَابِيٌّ جَاءَ يَنْشُدُ ضَالَّةً لَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Qurrah bin Khalid] dari [Abu Az Zubair] dari [Jabir bin 'Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; 'Barangsiapa mendaki bukit Al Murar? Maka dosanya akan diampuni sebagaimana diampuninya dosa Bani Israil.' Jabir bin Abdullah berkata; 'Yang pertama kali mendaki bukit itu adalah pasukan berkuda kami dari Bani Khazraj. Setelah itu, barulah pasukan yang lain menyusul bersama-sama.' Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda; 'Dosa kalian akan diampuni, kecuali dosa pemilik unta merah.' Setelah itu kami pun pergi mendatangi pemilik unta merah itu sambil berkata; 'Ayo, mintalah kepada Rasulullah agar beliau memohonkan ampun untukmu! ' Ternyata sang pemilik unta merah itu menjawab; 'Sungguh aku lebih senang mendapatkan kembali untaku yang hilang daripada temanmu itu (Nabi Muhammad) memohonkan ampun untukku.' Jabir berkata; 'Ternyata orang tersebut sedang mencari untanya yang hilang.' Dan telah menceritakannya kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Qurrah] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir bin 'Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; 'Barangsiapa mendaki bukit Al Murar atau Al Marar? Sebagaimana Hadits Mu'adz hanya saja dia berkata dengan lafazh; dan ternyata orang itu seorang badui yang sedang mencari untanya yang hilang.'"},"4631":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ مِنَّا رَجُلٌ مِنْ بَنِي النَّجَّارِ قَدْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ وَكَانَ يَكْتُبُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ هَارِبًا حَتَّى لَحِقَ بِأَهْلِ الْكِتَابِ قَالَ فَرَفَعُوهُ قَالُوا هَذَا قَدْ كَانَ يَكْتُبُ لِمُحَمَّدٍ فَأُعْجِبُوا بِهِ فَمَا لَبِثَ أَنْ قَصَمَ اللَّهُ عُنُقَهُ فِيهِمْ فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا فَتَرَكُوهُ مَنْبُوذًا","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin Malik] dia berkata; \"Dulu ada seorang sahabat laki-laki dari Bani Najjar. Sahabat tersebut telah menghafal surah Al Baqarah dan surah Ali Imran. Selain itu, ia juga pernah menjadi juru tulis Rasulullah shallallahu 'alaihi wasallam. Hingga pada suatu hari ia melarikan diri dan bergabung dengan Ahli Kitab.\" Anas berkata; 'Ternyata orang-orang Ahli Kitab memuliakan dan menghormatinya. Mereka berkata; 'Sesungguhnya orang laki-laki ini pernah menjadi juru tulis Muhammad.' Maka semakin tambah hormatnya mereka kepada orang laki-laki itu. Tak lama kemudian, orang itu meninggal dunia di tengah-tengah orang-orang Ahli Kitab. Lalu mereka menggali tanah untuk menguburkannya. Tetapi kemudian, bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas, hingga mereka membiarkannya tergeletak."},"4632":{"ar":"حَدَّثَنِي عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو مُحَمَّدٍ النَّضْرُ بْنُ مُحَمَّدِ بْنِ مُوسَى الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ حَدَّثَنَا إِيَاسٌ حَدَّثَنِي أَبِي قَالَعُدْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مَوْعُوكًا قَالَ فَوَضَعْتُ يَدِي عَلَيْهِ فَقُلْتُ وَاللَّهِ مَا رَأَيْتُ كَالْيَوْمِ رَجُلًا أَشَدَّ حَرًّا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِأَشَدَّ حَرًّا مِنْهُ يَوْمَ الْقِيَامَةِ هَذَيْنِكَ الرَّجُلَيْنِ الرَّاكِبَيْنِ الْمُقَفِّيَيْنِ لِرَجُلَيْنِ حِينَئِذٍ مِنْ أَصْحَابِهِ","id":"Telah menceritakan kepadaku ['Abbas bin 'Abdul 'Azhim Al 'Anbari] telah menceritakan kepada kami [Abu Muhammad An Nadhr bin Muhammad bin Musa Al Yamani] telah menceritakan kepada kami ['Ikrimah] telah menceritakan kepada kami [Iyas] telah menceritakan kepadaku [bapakku], dia berkata; \"Kami pernah menjenguk seseorang yang menderita sakit panas dan demam bersama Rasulullah shallallahu 'alaihi wasallam.\" Salamah berkata; 'Saya sentuhkan kedua tangan saya pada tubuh orang itu sambil berkata; 'Demi Allah, saya tidak pernah melihat orang yang menderita sakit panas seperti ini.' Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Maukah kamu aku tunjukkan orang yang lebih panas daripada orang yang sakit panas ini pada hari kiamat kelak? Itulah dua orang laki-laki yang mengendarai hewan dengan berboncengan.' Pada saat itu, beliau menunjuk kepada dua orang sahabat yang menjadi orang munafik yang sedang berlalu."},"4633":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي الْمُغِيرَةُ يَعْنِي الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهُ لَيَأْتِي الرَّجُلُ الْعَظِيمُ السَّمِينُ يَوْمَ الْقِيَامَةِ لَا يَزِنُ عِنْدَ اللَّهِ جَنَاحَ بَعُوضَةٍ اقْرَءُوا{ فَلَا نُقِيمُ لَهُمْ يَوْمَ الْقِيَامَةِ وَزْنًا }","id":"Telah menceritakan kepadaku [Abu Bakr bin Ishaq] telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepadaku [Al Mughirah Al Hizami] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: Sungguh pada hari kiamat akan datang seseorang yang berbadan gemuk namun di sisi Allah timbangannya tidak dapat melebihi berat sayap seekor nyamuk. Bacalah ayat; …dan kami tidak memberikan penimbangan terhadap (amal) mereka pada hari kiamat (Al Kahfi: 105)."},"4634":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا فُضَيْلٌ يَعْنِي ابْنَ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ السَّلْمَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَجَاءَ حَبْرٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ أَوْ يَا أَبَا الْقَاسِمِ إِنَّ اللَّهَ تَعَالَى يُمْسِكُ السَّمَاوَاتِ يَوْمَ الْقِيَامَةِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَعٍ وَالْجِبَالَ وَالشَّجَرَ عَلَى إِصْبَعٍ وَالْمَاءَ وَالثَّرَى عَلَى إِصْبَعٍ وَسَائِرَ الْخَلْقِ عَلَى إِصْبَعٍ ثُمَّ يَهُزُّهُنَّ فَيَقُولُ أَنَا الْمَلِكُ أَنَا الْمَلِكُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَجُّبًا مِمَّا قَالَ الْحَبْرُ تَصْدِيقًا لَهُ ثُمَّ قَرَأَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّمَاوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ سُبْحَانَهُ وَتَعَالَى عَمَّا يُشْرِكُونَ }حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ جَرِيرٍ عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ قَالَ جَاءَ حَبْرٌ مِنْ الْيَهُودِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ فُضَيْلٍ وَلَمْ يَذْكُرْ ثُمَّ يَهُزُّهُنَّ وَقَالَ فَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ تَعَجُّبًا لِمَا قَالَ تَصْدِيقًا لَهُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }وَتَلَا الْآيَةَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdullah bin Yunus] telah menceritakan kepada kami [Fudhail bin 'Iyadl] dari [Manshur] dari [Ibrahim] dari ['Ubaidah As Salmani] dari ['Abdullah bin Mas'ud] dia berkata; \"Seorang pendeta datang kepada Nabi shallallahu 'alaihi wasallam lalu dia berkata; 'Wahai Muhammad, atau wahai Abu Qasim! Kelak di hari kiamat Allah Ta'ala memegang langit, bumi, gunung-gunung, pohon-pohon, air, binatang-binatang, dan seluruh makhluk dengan jari-Nya. Kemudian Dia goncangkan seluruhnya sambil berkata; 'Akulah Raja (Penguasa)! Akulah Raja! ' Rasulullah shallallahu 'alaihi wasallam pun tertawa mendengar pendeta itu dan membenarkannya. Kemudian beliau membaca ayat: 'Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya, padahal bumi seluruhnya dalam genggaman-Nya pada hari kiamat dan langit digulung-Nya dengan tangan kanan-Nya; Maha Suci Allah dan Maha Tinggi Dia dari apa yang mereka persekutukan.' (Az Zumar (39): 67). Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] keduanya dari [Jarir] dari [Manshur] dengan sanad ini, dia berkata; 'Seorang pendeta dari Yahudi datang kepada Nabi shallallahu 'alaihi wasallam -yang serupa dengan Hadits Fudlail namun dia tidak menyebutkan kalimat; 'kemudian Dia mengguncangkan seluruhnya.' Dan dia juga berkata; 'Sungguh aku melihat Rasulullah shallallahu 'alaihi wasallam tertawa hingga terlihat gigi seri beliau sebagai rasa takjub sekaligus membenarkannya. Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat; 'Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya (QS. Azzumar 67) ….dan seterusnya."},"4635":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ إِبْرَاهِيمَ يَقُولُ سَمِعْتُ عَلْقَمَةَ يَقُولُاقَالَ عَبْدُ اللَّهِ جَاءَ رَجُلٌ مِنْ أَهْلِ الْكِتَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَبَا الْقَاسِمِ إِنَّ اللَّهَ يُمْسِكُ السَّمَاوَاتِ عَلَى إِصْبَعٍ وَالْأَرْضِينَ عَلَى إِصْبَعٍ وَالشَّجَرَ وَالثَّرَى عَلَى إِصْبَعٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَنَا الْمَلِكُ قَالَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ ثُمَّ قَرَأَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِهِمْ جَمِيعًا وَالشَّجَرَ عَلَى إِصْبَعٍ وَالثَّرَى عَلَى إِصْبَعٍ وَلَيْسَ فِي حَدِيثِ جَرِيرٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ وَلَكِنْ فِي حَدِيثِهِ وَالْجِبَالَ عَلَى إِصْبَعٍ وَزَادَ فِي حَدِيثِ جَرِيرٍ تَصْدِيقًا لَهُ تَعَجُّبًا لِمَا قَالَ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dia berkata; aku mendengar [Ibrahim] berkata; aku mendengar ['Alqamah] berkata; ['Abdullah] berkata;; \"Seorang laki-laki dari ahlu kitab datang kepada Nabi shallallahu 'alaihi wasallam lalu dia berkata; 'Wahai Abu Qasim! Kelak di hari kiamat Allah Ta'ala memegang langit, bumi, pohon-pohon, binatang-binatang, dan seluruh makhluk dengan jari-Nya seraya berkata; 'Akulah Raja (Penguasa)! Akulah Raja! ' Abdullah berkata; 'Maka aku melihat Rasulullah shallallahu 'alaihi wasallam pun tertawa hingga nampak gigi serinya. Kemudian beliau membaca ayat: 'Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya. (QS. Azzumar 67).' Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] mereka berdua berkata; telah menceritakan kepada kami [Abu Mu'awiyah] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan ['Ali bin Khasyram] mereka berdua berkata; telah mengabarkan kepada kami ['Isa bin Yunus] Demikian juga diriwayatkan dari jalur lainnya, dan telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] semuanya dari [Al A'masy] dengan sanad ini. Namun di semua Hadits mereka disebutkan lafazh; 'pohon-pohon dan binatang binatang. sedangkan di dalam Hadits Jarir tidak di sebutkan; lafazh 'makhluk-makhluk' akan tetapi disebutkan lafazh gunung-gunung juga ada tambahan; sebagai pembenaran terhadapnya dan rasa kagum terhadap apa yang dia katakan.'"},"4636":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي ابْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ كَانَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْبِضُ اللَّهُ تَبَارَكَ وَتَعَالَى الْأَرْضَ يَوْمَ الْقِيَامَةِ وَيَطْوِي السَّمَاءَ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ مُلُوكُ الْأَرْضِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku [Ibnul Musayyab] bahwasanya [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kelak di hari kiamat Allah Tabaraka wa Ta'ala akan menggenggam bumi dan menggulung langit dengan tangan kanan-Nya. Kemudian Dia berfirman: 'Akulah Raja (penguasa)! Mana yang mengaku raja-raja di bumi? '\""},"4637":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ ��َخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطْوِي اللَّهُ عَزَّ وَجَلَّ السَّمَاوَاتِ يَوْمَ الْقِيَامَةِ ثُمَّ يَأْخُذُهُنَّ بِيَدِهِ الْيُمْنَى ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ الْجَبَّارُونَ أَيْنَ الْمُتَكَبِّرُونَ ثُمَّ يَطْوِي الْأَرَضِينَ بِشِمَالِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ الْجَبَّارُونَ أَيْنَ الْمُتَكَبِّرُونَ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari ['Umar bin Hamzah] dari [Salim bin 'Abdullah] telah mengabarkan kepadaku ['Abdullah bin 'Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Pada hari kiamat kelak, Allah Subhanahu wa Ta'ala akan melipat langit. Setelah itu, Allah akan menggenggamnya dengan tangan kanan-Nya sambil berkata: 'Akulah Sang Maha Raja. Di manakah sekarang orang-orang yang selalu berbuat sewenang-wenang? Dan di manakah orang-orang yang selalu sombong dan angkuh? ' Setelah itu, Allah akan melipat bumi dengan tangan kiri-Nya sambil berkata: 'Akulah Sang Maha Raja. Di manakah sekarang orang-orang yang sering berbuat sewenang-wenang? Di manakah orang-orang yang sombong? '\""},"4638":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبُو حَازِمٍ عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍأَنَّهُ نَظَرَ إِلَى عَبْدِ اللَّهِ بْنِ عُمَرَ كَيْفَ يَحْكِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْخُذُ اللَّهُ عَزَّ وَجَلَّ سَمَاوَاتِهِ وَأَرَضِيهِ بِيَدَيْهِ فَيَقُولُ أَنَا اللَّهُ وَيَقْبِضُ أَصَابِعَهُ وَيَبْسُطُهَا أَنَا الْمَلِكُ حَتَّى نَظَرْتُ إِلَى الْمِنْبَرِ يَتَحَرَّكُ مِنْ أَسْفَلِ شَيْءٍ مِنْهُ حَتَّى إِنِّي لَأَقُولُ أَسَاقِطٌ هُوَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَهُوَ يَقُولُ يَأْخُذُ الْجَبَّارُ عَزَّ وَجَلَّ سَمَاوَاتِهِ وَأَرَضِيهِ بِيَدَيْهِ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ يَعْقُوبَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] telah menceritakan kepadaku [Abu Hazim] dari ['Ubaidullah bin Miqsam] bahwsanya dia pernah bertanya kepda ['Abdulah bin 'Umar]; Apa yang diceritakan oleh Rasulullah shallallahu 'alaihi wasallam? Dia menjawab; Beliau bersabda: \"Allah Azza Wa Jalla, menggenggam langit dan bumi dengan tangan-Nya seraya berfirman: Akulah Allah. Kemudian Dia genggam dan bentangkan jari-jari-Nya seraya berseru: 'Akulah Raja. Ibnu Umar berkata: hingga aku melihat bagian bawah mimbar bergerak-gerak. Sampai-sampai aku bergumam; \"Apakah mimbar tersebut akan roboh bersama Rasulullah shallallahu 'alaihi wasallam? Telah menceritakan kepada kami [Sa'id bin Manshur] Telah menceritakan kepada kami [Abdul Aziz bin Abu hazim] telah menceritakan kepadaku [bapakku] dari ['Ubaidullah bin Miqsam] dari ['Abdullah bin 'Umar] dia berkata; aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas mimbar seraya bersabda: \"Dzat yang Maha Perkasa, menggenggam langit dan bumi dengan tangan-Nya. -lalu dia menyebutkan yang serupa dengan Hadits Ya'qub.-"},"4639":{"ar":"حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ عَنْ أَيُّوبَ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ مَوْلَى أُمِّ سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي فَقَالَ خَلَقَ اللَّهُ عَزَّ وَجَلَّ التُّرْبَةَ يَوْمَ السَّبْتِ وَخَلَقَ فِيهَا الْجِبَالَ يَوْمَ الْأَحَدِ وَخَلَقَ الشَّجَرَ يَوْمَ الِاثْنَيْنِ وَخَلَقَ الْمَكْرُوهَ يَوْمَ الثُّلَاثَاءِ وَخَلَقَ النُّورَ يَوْمَ الْأَرْبِعَاءِ وَبَثَّ فِيهَا الدَّوَابَّ يَوْمَ الْخَمِيسِ وَخَلَقَ آدَمَ عَلَيْهِ السَّلَام بَعْدَ الْعَصْرِ مِنْ يَوْمِ الْجُمُعَةِ فِي آخِرِ الْخَلْقِ فِي آخِرِ سَاعَةٍ مِنْ سَاعَاتِ الْجُمُعَةِ فِيمَا بَيْنَ الْعَصْرِ إِلَى اللَّيْلِقَالَ إِبْرَاهِيمُ حَدَّثَنَا الْبِسْطَامِيُّ وَهُوَ الْحُسَيْنُ بْنُ عِيسَى وَسَهْلُ بْنُ عَمَّارٍ وَإِبْرَاهِيمُ ابْنُ بِنْتِ حَفْصٍ وَغَيْرُهُمْ عَنْ حَجَّاجٍ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepadaku [Suraij bin Yunus] dan [Harun bin 'Abdullah] mereka berdua berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepada kami [Isma'il bin Umayyah] dari [Ayyub bin Khalid] dari ['Abdullah bin Rafi'] -budak- Ummu Salamah dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memegang tangannya, lalu beliau bersabda: 'Allah Azza wa Jalla menjadikan tanah pada hari Sabtu, menancapkan gunung pada hari Ahad, menumbuhkan pohon-pohon pada hari Senin, menjadikan bahan-bahan mineral pada hari Selasa, menjadikan cahaya pada hari Rabu, menebarkan binatang pada hari Kamis, dan menjadikan Adam 'Alaihis Salam pada hari Jum'at setelah ashar, yang merupakan penciptaan paling akhir yaitu saat-saat terakhir di hari jum'at antara waktu ashar hingga malam.\""},"4640":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو حَازِمِ بْنُ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ عَلَى أَرْضٍ بَيْضَاءَ عَفْرَاءَ كَقُرْصَةِ النَّقِيِّ لَيْسَ فِيهَا عَلَمٌ لِأَحَدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; telah menceritakan kepada kami [Khalid bin Makhlad] dari [Muhammad bin Ja'far bin Abu Katsir] telah menceritakan kepadaku [Abu Hazim bin Dinar] dari [Sahl bin Sa'd] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Pada hari kiamat kelak manusia akan dikumpulkan di bumi yang sangat putih berbentuk bulat pipih dan datar tanpa ada tanda bagi siapapun di atasnya.\""},"4641":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ عَزَّ وَجَلَّ{ يَوْمَ تُبَدَّلُ الْأَرْضُ غَيْرَ الْأَرْضِ وَالسَّمَاوَاتُ }فَأَيْنَ يَكُونُ النَّاسُ يَوْمَئِذٍ يَا رَسُولَ اللَّهِ فَقَالَ عَلَى الصِّرَاطِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Ali bin Mushir] dari [Dawud] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Azza Wa Jalla: 'Pada hari (ketika) bumi diganti dengan bumi yang lain dan begitu pula langit……' (QS. Ibrahim (14): 48), maka dimanakah umat manusia ketika itu, ya Rasulullah?\" Jawab beliau: 'Di Titian (shirath)! '"},"4642":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَكُونُ الْأَرْضُ يَوْمَ الْقِيَامَةِ خُبْزَةً وَاحِدَةً يَكْفَؤُهَا الْجَبَّارُ بِيَدِهِ كَمَا يَكْفَأُ أَحَدُكُمْ خُبْزَتَهُ فِي السَّفَرِ نُزُلًا لِأَهْلِ الْجَنَّةِ قَالَ فَأَتَى رَجُلٌ مِنْ الْيَهُودِ فَقَالَ بَارَكَ الرَّحْمَنُ عَلَيْكَ أَبَا الْقَاسِمِ أَلَا أُخْبِرُكَ بِنُزُلِ أَهْلِ الْجَنَّةِ يَوْمَ الْقِيَامَةِ قَالَ بَلَى قَالَ تَكُونُ الْأَرْضُ خُبْزَةً وَاحِدَةً كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَنَظَرَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ قَالَ أَلَا أُخْبِرُكَ بِإِدَامِهِمْ قَالَ بَلَى قَالَ إِدَامُهُمْ بَالَامُ وَنُونٌ قَالُوا وَمَا هَذَا قَالَ ثَوْرٌ وَنُونٌ يَأْكُلُ مِنْ زَائِدَةِ كَبِدِهِمَا سَبْعُونَ أَلْفًا","id":"Telah menceritakan kepada kami ['Abdul Malik bin Syu'aib bin Al Laits] telah menceritakan kepadaku [bapakku] dari [kakekku] telah menceritakan kepada kami [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Pada hari kiamat bumi itu akan seperti satu potong roti yang akan di ratakan oleh Allah dengan tangan-Nya hingga menjadi seimbang. Sebagaimana roti yang diratakan oleh salah seorang dari kalian diperjalanannya. sebagai hidangan bagi penghuni surga. Kemudian seorang laki-laki dari yahudi datang, ia berkata kepada beliau; \"semoga Allah memberkahi kepadamu wahai Abu Qasim, beliau berkata kepadanya; maukah kamu kuberitahu tentang hidangan penghuni surga pada hari kiamat? Dia menjawab; 'Ya.' Beliau bersabda: bumi akan menjadi satu potong roti -sebagaimana sabda Rasulullah shallallahu 'alaihi wasallam tadi.- maka Rasulullah shallallahu 'alaihi wasallam melihat kepada kami dan tertawa hingga terlihat gigi serinya. Beliau shallallahu 'alaihi wasallam bertanya; maukah kuberitahukan kepadamu tentang lauk pauk mereka. Dia menjawab; lauknya adalah balaam (bahasa Ibarahin) dan nun. Para sahabat bertanya; apakah itu? Beliau menjawab; yaitu seekor sapi, sedangkan nun adalah daging yang paling baik dari hatinya yang akan dimakan oleh tujuh puluh ribu penghuni surga yang masuk tanpa hisab."},"4643":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا قُرَّةُ حَدَّثَنَا مُحَمَّدٌ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَابَعَنِي عَشَرَةٌ مِنْ الْيَهُودِ لَمْ يَبْقَ عَلَى ظَهْرِهَا يَهُودِيٌّ إِلَّا أَسْلَمَ","id":"Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Qurrah] telah menceritakan kepada kami [Muhammad] dari [Abu Hurairah] berkata: \"Nabi Shallallahu 'alaihi wa Salam bersabda: 'Andai sepuluh orang Yahudi mengikutiku, tidaklah tersisa diatasnya (bumi) seorang Yahudi pun melainkan masuk Islam'.\""},"4644":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَمَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ وَهُوَ مُتَّكِئٌ عَلَى عَسِيبٍ إِذْ مَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ فَقَالُوا مَا رَابَكُمْ إِلَيْهِ لَا يَسْتَقْبِلُكُمْ بِشَيْءٍ تَكْرَهُونَهُ فَقَالُوا سَلُوهُ فَقَامَ إِلَيْهِ بَعْضُهُمْ فَسَأَلَهُ عَنْ الرُّوحِ قَالَ فَأَسْكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرُدَّ عَلَيْهِ شَيْئًا فَعَلِمْتُ أَنَّهُ يُوحَى إِلَيْهِ قَالَ فَقُمْتُ مَكَانِي فَلَمَّا نَزَلَ الْوَحْيُ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ كُنْتُ أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ بِنَحْوِ حَدِيثِ حَفْصٍ غَيْرَ أَنَّ فِي حَدِيثِ وَكِيعٍ{ وَمَا أ��وتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }وَفِي حَدِيثِ عِيسَى بْنِ يُونُسَ وَمَا أُوتُوا مِنْ رِوَايَةِ ابْنِ خَشْرَمٍ حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ إِدْرِيسَ يَقُولُ سَمِعْتُ الْأَعْمَشَ يَرْوِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَخْلٍ يَتَوَكَّأُ عَلَى عَسِيبٍ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِهِمْ عَنْ الْأَعْمَشِ وَقَالَ فِي رِوَايَتِهِ{ وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Giyats] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepadaku [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: \"Saat aku berjalan dengan nabi Shallallahu 'alaihi wa Salam disuatu ladang sementara beliau tengah bersandar, tiba-tiba beberapa orang Yahudi lewat, mereka saling berkata satu sama lain: 'Tanyakan padanya tentang ruh.' Mereka berkata: 'Apa yang meragukan kalian (hingga bertanya padanya) agar ia tidak menyambut dengan sesuatu yang tidak kalian sukai.' Mereka berkata, 'Bertanyalah padanya.' Kemudian sebagaian dari mereka menghampiri beliau lalu bertanya tentang ruh pada beliau'.\" Abdullah berkata: \"Nabi Shallallahu 'alaihi wa Salam diam dan tidak menjawab apa pun. Aku tahu beliau tengah diberi wahyu. Aku berdiri dari tempatku. Saat wahyu turun, beliau bersabda: 'Dan mereka bertanya kepadamu tentang roh. Katakanlah: 'Roh itu termasuk urusan Tuhan-ku, dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Sa'id Al Asyuj] telah menceritakan kepada kami [Waki']. Dan telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ali bin Khasyram] keduanya berkata: Telah mengkhabarkan kepada kami [Isa bin Yunus] keduanya dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata: Aku berjalan bersama nabi Shallallahu 'alaihi wa Salam di sebuah ladang Madinah, seperti hadits Hafsh, hanya saja dalam hadits Waki' disebutkan: \"Dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85) dan dalam hadits Isa bin Yunus disebutkan: \"Dan tidaklah kamu diberi.\" Dari Rasulullah Ibnu Khasyram. Telah menceritakan kepada kami [Abu Sa'id Al Asyujj] berkata: Aku mendengar [Abdullah bin Idris] berkata: Aku mendengar [Al A'masy] meriwayatkannya dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] berkata: Nabi Shallallahu 'alaihi wa Salam berada di kebun kurma, beliau telah bersandar pada pangkal kurma, Abdullah menyebut hadits yang sama seperti hadits dari Al A'masy dan ia berkata dalam riwayatnya: \"dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85) "},"4645":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ الْأَشَجُّ وَاللَّفْظُ لِعَبْدِ اللَّهِ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَنْ أَقْضِيَكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ فَقُلْتُ لَهُ إِنِّي لَنْ أَكْفُرَ بِمُحَمَّدٍ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ وَكِيعٌ كَذَا قَالَ الْأَعْمَشُ قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }إِلَى قَوْلِهِ{ وَيَأْتِينَا فَرْدًا }حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ وَكِيعٍ وَفِي حَدِيثِ جَرِيرٍ قَالَ كُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ عَمَلًا فَأَتَيْتُهُ أَتَقَاضَاهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abdullah bin Sa'id Al Asyujj], teks hadits milik Abdullah, keduanya berkata: Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Khabbab] berkata: Al 'Ash memiliki hutang padaku, aku mendatanginya untuk memperkarakannya, ia berkata padaku: Aku tidak akan membayar (hutang) mu sebelum kau kufur terhadap Muhammad. Aku berkata padanya: Aku tidak akan kufur terhadap Muhammad hingga kau mati lalu dibangkitkan lagi. Ia berkata: Bila kau bangkit lagi setelah mati, aku akan melunasi (hutang) mu bila aku kembali lagi ke harta dan anakku. Waki' berkata: Demikian Al A'masy berkata: Lalu ayat ini turun: \"Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: 'Pasti Aku akan diberi harta dan anak\" hingga firmanNya: \"Dan ia akan datang kepada kami dengan seorang diri.\" (Maryam: 77-80). Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah]. Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku]. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Jarir]. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan]. Semuanya dari [Al A'masy] dengan sanad ini seperti hadits Waki'. Dalam hadits Jarir disebutkan: Dimasa jahiliyah, aku budak milik Al Ash bin Wa`il, aku bekerja lalu mendatanginya untuk memperkarakannya."},"4646":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْحَمِيدِ الزِّيَادِيِّ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُاقَالَ أَبُو جَهْلٍ اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنْ السَّمَاءِ أَوْ ائْتِنَا بِعَذَابٍ أَلِيمٍ فَنَزَلَتْ{ وَمَا كَانَ اللَّهُ لِيُعَذِّبَهُمْ وَأَنْتَ فِيهِمْ وَمَا كَانَ اللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ وَمَا لَهُمْ أَلَّا يُعَذِّبَهُمْ اللَّهُ وَهُمْ يَصُدُّونَ عَنْ الْمَسْجِدِ الْحَرَامِ }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] telah menceritakan kepada kami [ayahku] dari [Syu'bah] dari [Abdul Hamid Az Ziyadi], ia mendengar [Anas bin Malik] berkata: Abu Jahal pernah berkata: Ya Allah, jika memang ini benar-benar berasal dariMu maka turunkanlah hujan batu atas kami dari langit atau datanglah adzab yang pedih kepada kami. Maka turunlah ayat: \"Dan Allah sekali-kali tidak akan mengazab mereka, sedang kamu berada di antara mereka. dan tidaklah (pula) Allah akan mengazab mereka, sedang mereka meminta ampun. Kenapa Allah tidak mengazab mereka padahal mereka menghalangi orang untuk (mendatangi) Masjidil haram.\" (Al Anfaal: 33) hingga akhir ayat."},"4647":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الْقَيْسِيُّ قَالَا حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ حَدَّثَنِي نُعَيْمُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو جَهْلٍ هَلْ يُعَفِّرُ مُحَمَّدٌ وَجْهَهُ بَيْنَ أَظْهُرِكُمْ قَالَ فَقِيلَ نَعَمْ فَقَالَ وَاللَّاتِ وَالْعُزَّى لَئِنْ رَأَيْتُهُ يَفْعَلُ ذَلِكَ لَأَطَأَنَّ عَلَى رَقَبَتِهِ أَوْ لَأُعَفِّرَنَّ وَجْهَهُ فِي التُّرَابِ قَالَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي زَعَمَ لِيَطَأَ عَلَى رَقَبَتِهِ قَالَ فَمَا فَجِئَهُمْ مِنْهُ إِلَّا وَهُوَ يَنْكُصُ عَلَى عَقِبَيْهِ وَيَتَّقِي بِيَدَيْهِ قَالَ فَقِيلَ لَهُ مَا لَكَ فَقَالَ إِنَّ بَيْنِي وَبَيْنَهُ لَخَنْدَقًا مِنْ نَارٍ وَهَوْلًا وَأَجْنِحَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ دَنَا مِنِّي لَاخْتَطَفَتْهُ الْمَلَائِكَةُ عُضْوًا عُضْوًا قَالَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ لَا نَدْرِي فِي حَدِيثِ أَبِي هُرَيْرَةَ أَوْ شَيْءٌ بَلَغَهُ{ كَلَّا إِنَّ الْإِنْسَانَ لَيَطْغَى أَنْ رَآهُ اسْتَغْنَى إِنَّ إِلَى رَبِّكَ الرُّجْعَى أَرَأَيْتَ الَّذِي يَنْهَى عَبْدًا إِذَا صَلَّى أَرَأَيْتَ إِنْ كَانَ عَلَى الْهُدَى أَوْ أَمَرَ بِالتَّقْوَى أَرَأَيْتَ إِنْ كَذَّبَ وَتَوَلَّى }يَعْنِي أَبَا جَهْلٍ{ أَلَمْ يَعْلَمْ بِأَنَّ اللَّهَ يَرَى كَلَّا لَئِنْ لَمْ يَنْتَهِ لَنَسْفَعًا بِالنَّاصِيَةِ نَاصِيَةٍ كَاذِبَةٍ خَاطِئَةٍ فَلْيَدْعُ نَادِيَهُ سَنَدْعُ الزَّبَانِيَةَ كَلَّا لَا تُطِعْهُ }زَادَ عُبَيْدُ اللَّهِ فِي حَدِيثِهِ قَالَ وَأَمَرَهُ بِمَا أَمَرَهُ بِهِ وَزَادَ ابْنُ عَبْدِ الْأَعْلَى{ فَلْيَدْعُ نَادِيَهُ }يَعْنِي قَوْمَهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] dan [Muhammad bin Abdula'la Al Qaisi] keduanya berkata: Telah menceritakan kepada kami [Al Mu'tamir] dari [ayahnya] telah menceritakan kepadaku [Nu'aim bin Abu Hind] dari [Abu Hazim] dari [Abu Hurairah] berkata: Abu Jahal berkata: Apakah Muhammad menundukkan wajahnya (di tanah) di tengah-tengah kalian? Ada yang menjawab: Ya. Ia berkata: Demi Lata dan Uzzah, bila aku melihatnya melakukan seperti itu, aku akan menginjak lehernya atau aku akan benamkan wajahnya di tanah. Abu Hurairah berkata: Ia kemudian mendatangi Rasulullah Shallallahu 'alaihi wa Salam saat beliau tengah shalat, ia hendak menginjak leher beliau. Tidak ada yang mengejutkan mereka selain ia (Abu Jahal) mundur dan melindungi diri dengan tangan. Ada yang bertanya padanya: Kamu kenapa? Ia menjawab: Antara aku dan dia ada parit dari api, huru hara dan banyak sayap. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Andai ia mendekatiku, malaikat akan menyambar anggota badannya satu per satu.\" Abu Hurairah berkata: Lalu Allah 'azza wajalla menurunkan -kami (Nu'aim) tidak tahu apakah ayat ini disebutkan dalam hadits Abu Hurairah ataukah Rasulullah yang ia (Abu Hazim) dengar-: \"Ketahuilah! Sesungguhnya manusia benar-benar melampaui batas, karena dia melihat dirinya serba cukup. Sesungguhnya hanya kepada Rabbmulah kembali(mu). Bagaimana pendapatmu tentang orang yang melarang, seorang hamba ketika mengerjakan shalat. Bagaimana pendapatmu jika orang yang melarang itu berada di atas kebenaran, atau dia menyuruh bertakwa (kepada Allah)? Bagaimana pendapatmu jika orang yang melarang itu mendustakan dan berpaling?\" yaitu Abu Jahal \"Tidaklah dia mengetahui bahwa sesungguhnya Allah melihat segala perbuatannya? Ketahuilah, sungguh jika dia tidak berhenti (berbuat demikian) niscaya kami tarik ubun-ubunnya, (yaitu) ubun-ubun orang yang mendustakan lagi durhaka. Maka biarlah dia memanggil golongannya (untuk menolongnya), kelak kami akan memanggil malaikat Zabaniyah. Sekali-kali jangan, janganlah kamu patuh kepadanya.\" (Al 'Alaq: 7-19) Abdullah menambahkan dalam haditsnya: Ia berkata: Rasulullah Shallallahu 'alaihi wa Salam memerintahkan Abu Jahal dengan sesuatu yang diperintahkan pada beliau. Ibnu Abdula'la menambahkan: \"Maka biarlah dia memanggil golongannya\" yaitu kaumnya."},"4648":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَكُنَّا عِنْدَ عَبْدِ اللَّهِ جُلُوسًا وَهُوَ مُضْطَجِعٌ بَيْنَنَا فَأَتَاهُ رَجُلٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ قَاصًّا عِنْدَ أَبْوَابِ كِنْدَةَ يَقُصُّ وَيَزْعُمُ أَنَّ آيَةَ الدُّخَانِ تَجِيءُ فَتَأْخُذُ بِأَنْفَاسِ الْكُفَّارِ وَيَأْخُذُ الْمُؤْمِنِينَ مِنْهُ كَهَيْئَةِ الزُّكَامِ فَقَالَ عَبْدُ اللَّهِ وَجَلَسَ وَهُوَ غَضْبَانُ يَا أَيَّهَا النَّاسُ اتَّقُوا اللَّهَ مَنْ عَلِمَ مِنْكُمْ شَيْئًا فَلْيَقُلْ بِمَا يَعْلَمُ وَمَنْ لَمْ يَعْلَمْ فَلْيَقُلْ اللَّهُ أَعْلَمُ فَإِنَّهُ أَعْلَمُ لِأَحَدِكُمْ أَنْ يَقُولَ لِمَا لَا يَعْلَمُ اللَّهُ أَعْلَمُ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ مَا أَسْأَلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَا أَنَا مِنْ الْمُتَكَلِّفِينَ }إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا رَأَى مِنْ النَّاسِ إِدْبَارًا فَقَالَ اللَّهُمَّ سَبْعٌ كَسَبْعِ يُوسُفَ قَالَ فَأَخَذَتْهُمْ سَنَةٌ حَصَّتْ كُلَّ شَيْءٍ حَتَّى أَكَلُوا الْجُلُودَ وَالْمَيْتَةَ مِنْ الْجُوعِ وَيَنْظُرُ إِلَى السَّمَاءِ أَحَدُهُمْ فَيَرَى كَهَيْئَةِ الدُّخَانِ فَأَتَاهُ أَبُو سُفْيَانَ فَقَالَ يَا مُحَمَّدُ إِنَّكَ جِئْتَ تَأْمُرُ بِطَاعَةِ اللَّهِ وَبِصِلَةِ ��لرَّحِمِ وَإِنَّ قَوْمَكَ قَدْ هَلَكُوا فَادْعُ اللَّهَ لَهُمْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ يَغْشَى النَّاسَ هَذَا عَذَابٌ أَلِيمٌ إِلَى قَوْلِهِ إِنَّكُمْ عَائِدُونَ }قَالَ أَفَيُكْشَفُ عَذَابُ الْآخِرَةِ{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }فَالْبَطْشَةُ يَوْمَ بَدْرٍ وَقَدْ مَضَتْ آيَةُ الدُّخَانِ وَالْبَطْشَةُ وَاللِّزَامُ وَآيَةُ الرُّومِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Jarir] dari [Manshur] dari [Abu Adh Dhuha] dari [Masruq] berkata: Kami duduk didekat [Abdullah] dan ia tengah berbaring. Seseorang mendatanginya lalu berkata: Hai Abu Abdurrahman, seseorang bercerita didekat pintu gerbang Kindah, ia mengira bahwa tanda-tanda (kebesaran berupa) kabut datang lalu merenggut nyawa orang-orang kafir, kabut itu mencabut nyawa orang-orang mu`min seperti kondisi selesma. Abdullah duduk kemudian berkata dengan marah: Wahai sekalian manusia, bertakwalah kepada Allah, barangsiapa diantara kalian yang mengetahui sesuatu, hendaklah mengatakan seperti yang ia ketahui dan barangsiapa diantara kalian tidak mengetahui, hendaklah mengucapkan: Allahu a'lam, karena orang yang paling tahu diantara kalian adalah yang mengatakan untuk sesuatu yang tidak ia ketahui: Allahu a'lam, karena Allah Azza wa Jalla berfirman kepada nabiNya: \"Katakanlah (hai Muhammad): \"Aku tidak meminta upah sedikitpun padamu atas da'wahku dan bukanlah Aku termasuk orang-orang yang mengada-adakan.\" (Shaad: 86) Saat Rasulullah Shallallahu 'alaihi wa Salam melihat orang-orang berpaling, beliau berdoa: \"Ya Allah, (turunkanlah) kelaparan seperti kelaparannya Yusuf.\" Masruq berkata: Mereka pun tertimpa kelaparan yang menyerang segala sesuatu hingga mereka makan kulit dan bangkai karena lapar. Seseorang dari mereka melihat ke langit seperti wujud kabut lalu mereka mendatangi Abu Sufyan, ia berkata: Hai Muhammad, kau datang memerintahkan untuk menaati Allah dan menyambung silaturrahim, kaummu telah binasa, berdoalah kepada Allah 'azza wajalla untuk mereka.\"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia. inilah azab yang pedih\" hingga fimranNya \"Sesungguhnya kamu akan kembali (ingkar).\" (Ad Dukhaan: 10-15) ia berkata: Apakah siksaan akhirat akan dihilangkan?\"(Ingatlah) hari (ketika) kami menghantam mereka dengan hantaman yang keras. Sesungguhnya kami adalah pemberi balasan.\" (Ad Dukhaan: 16) hantaman keras adalah perang Badar. Tanda-tanda asap, hantaman keras, kematian dan ayat tentang (kemenangan) Romawi telah berlalu."},"4649":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ ح و حَدَّثَنِي أَبُو سَعِيدٍ الْأَشَجُّ أَخْبَرَنَا وَكِيعٌ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِيَحْيَى قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمِ بْنِ صُبَيْحٍ عَنْ مَسْرُوقٍ قَالَجَاءَ إِلَى عَبْدِ اللَّهِ رَجُلٌ فَقَالَ تَرَكْتُ فِي الْمَسْجِدِ رَجُلًا يُفَسِّرُ الْقُرْآنَ بِرَأْيِهِ يُفَسِّرُ هَذِهِ الْآيَةَ{ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }قَالَ يَأْتِي النَّاسَ يَوْمَ الْقِيَامَةِ دُخَانٌ فَيَأْخُذُ بِأَنْفَاسِهِمْ حَتَّى يَأْخُذَهُمْ مِنْهُ كَهَيْئَةِ الزُّكَامِ فَقَالَ عَبْدُ اللَّهِ مَنْ عَلِمَ عِلْمًا فَلْيَقُلْ بِهِ وَمَنْ لَمْ يَعْلَمْ فَلْيَقُلْ اللَّهُ أَعْلَمُ مِنْ فِقْهِ الرَّجُلِ أَنْ يَقُولَ لِمَا لَا عِلْمَ لَهُ بِهِ اللَّهُ أَعْلَمُ إِنَّمَا كَانَ هَذَا أَنَّ قُرَيْشًا لَمَّا اسْتَعْصَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا عَلَيْهِمْ بِسِنِينَ كَسِنِي يُوسُفَ فَأَصَابَهُمْ قَحْطٌ وَجَهْدٌ حَتَّى جَعَلَ الرَّجُلُ يَنْظُرُ إِلَى السَّمَاءِ فَيَرَى بَيْنَهُ وَبَيْنَهَا كَهَيْئَةِ الدُّخَانِ مِنْ الْجَهْدِ وَحَتَّى أَكَلُوا الْعِظَامَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ اللَّهَ لِمُضَرَ فَإِنَّهُمْ قَدْ هَلَكُوا فَقَالَ لِمُضَرَ إِنَّكَ لَجَرِيءٌ قَالَ فَدَعَا اللَّهَ لَهُمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّا كَاشِفُوا الْعَذَابِ قَلِيلًا إِنَّكُمْ عَائِدُونَ }قَالَ فَمُطِرُوا فَلَمَّا أَصَابَتْهُمْ الرَّفَاهِيَةُ قَالَ عَادُوا إِلَى مَا كَانُوا عَلَيْهِ قَالَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ يَغْشَى النَّاسَ هَذَا عَذَابٌ أَلِيمٌ }{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }قَالَ يَعْنِي يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki']. Telah menceritakan kepadaku [Abu Sa'id Al Asyujj] dan [Waki']. Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir], semuanya dari [Al A'masy]. Telah menceritakan kepada kami [Yahya bin Abu Yahya] dan [Abu Kuraib], teks milik Yahya, keduanya berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim bin Shubaih] dari [Masruq] berkata: Seseorang mendatangi [Abdullah] lalu berkata: Aku meninggalkan seseorang di masjid yang menafsirkan ayat Al Qur'an berdasarkan pendapatnya: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia.\" (Ad Dukhaan: 10) ia berkata: Pada hari kiamat, kabut mendatangi manusia lalu mencabut nyawa mereka seperti wujud selesma. Setelah itu Abdullah berkata: Barangsiapa mengetahui sesuatu hendaklah disampaikan dan barangsiapa tidak tahu, hendaklah mengucapkan: Allahu a'lam. Salah satu pemahaman seseorang adalah dengan mengatakan Allahu a'lam untuk sesuatu yang tidak ia ketahui. Itu (kabut) terjadi saat kaum Quraisy mendurhakai nabi Shallallahu 'alaihi wa Salam. Beliau mendoakan mereka agar tertimpa kelaparan seperti kaum Yusuf. Mereka tertimpa kemarau dan keletihan hingga seseorang melihat ke langit, ia melihat seperti wujud kabut antara dirinya dan langit karena keletihan dan hingga mereka memakan tulang. Seseorang kemudian mendatangi nabi Shallallahu 'alaihi wa Salam dan berkata: Wahai Rasulullah, mintakan ampunan pada Allah untuk Mudlar karena mereka telah binasa. Beliau bersabda kepada Mudlar: \"Sesungguhnya kau gegabah.\" Abdullah berkata: Nabi Shallallahu 'alaihi wa Salam berdoa untuk mereka lalu Allah 'azza wajalla menurunkan: \"Sesungguhnya (kalau) kami akan melenyapkan siksaan itu agak sedikit. Sesungguhnya kamu akan kembali (ingkar).\" (Ad Dukhaan: 10-15) Abdullah berkata: Lalu mereka diberi hujan dan saat mereka mendapatkan kemakmuran, mereka kembali lagi seperti semula. Abdullah berkata: Lalu Allah 'azza wajalla menurunkan: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia. inilah azab yang pedih.\" (Ad Dukhaan: 10) Abdullah berkata: Yaitu perang Badar."},"4650":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَخَمْسٌ قَدْ مَضَيْنَ الدُّخَانُ وَاللِّزَامُ وَالرُّومُ وَالْبَطْشَةُ وَالْقَمَرُحَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Abdullah] berkata: Lima (tanda-tanda) Telah terjadi: kabut, kematian, (kemenangan) Romawi, hantaman keras dan (terbelahnya) bulan. Telah menceritakan kepada kami [Abu Sa'id Al Asyuj] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dengan sanad ini dengan matan serupa."},"4651":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لَهُ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَنُذِيقَنَّهُمْ مِنْ الْعَذَابِ الْأَدْنَى دُونَ الْعَذَابِ الْأَكْبَرِ }قَالَ مَصَائِبُ الدُّنْيَا وَالرُّومُ وَالْبَطْشَةُ أَوْ الدُّخَانُ شُعْبَةُ الشَّاكُّ فِي الْبَطْشَةِ أَوْ الدُّخَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mustanna] dan [Muhammad bin Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah]. Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], teks miliknya, telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Qatadah] dari [Azrah] dari [Al Hasan Al Urani] dari [Yahya bin Al Hazzar] dari [Abdurrahman bin Abi Laila] dari [Ubai bin Ka'ab] mengenai firman Allah 'azza wajalla: \"Dan Sesungguhnya kami merasakan kepada mereka sebahagian azab yang dekat (di dunia) sebelum azab yang lebih besar (di akhirat).\" (As Sajdah: 21) Ia berkata: Musibah-musibah dunia, Perang Romawi, hantaman keras atau munculnya kabut Syu'bah ragu pada hantaman ataukah munculnya kabut."},"4652":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَانْشَقَّ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِقَّتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْهَدُوا","id":"Telah menceritakan kepada kami [Amru An Naqid] dan [Zuhair bin Harb] keduanya berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Abi Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] berkata: Bulan terbelah dua bagian dimasa Rasulullah Shallallahu 'alaihi wa Salam, Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saksikan.\""},"4653":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ ح و حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي كِلَاهُمَا عَنْ الْأَعْمَشِ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ وَاللَّفْظُ لَهُ أَخْبَرَنَا ابْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى إِذَا انْفَلَقَ الْقَمَرُ فِلْقَتَيْنِ فَكَانَتْ فِلْقَةٌ وَرَاءَ الْجَبَلِ وَفِلْقَةٌ دُونَهُ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْهَدُوا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], [Abu Kuraib] dan [Ishaq bin Ibrahim] semuanya dari [Abu Mu'awiyah]. Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [ayahku], keduanya dari [Al A'masy]. Telah menceritakan kepada kami [Minjab bin Al Harits At Taimi], teks hadits miliknya, telah mengkhabarkan kepada kami [Ibnu Mushir] dari [Al A'masy] dari [Ibrahim] dari [Abu Ma'mar] dari [Abdullah bin Mas'ud] berkata: Saat kami bersama Rasulullah Shallallahu 'alaihi wa Salam di Mina, bulan terbelah menjadi dua bagian, salah satunya di belakang gunung dan yang lain di bawahnya, lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saksikan.\""},"4654":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَانْشَقَّ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِلْقَتَيْنِ فَسَتَرَ الْجَبَلُ فِلْقَةً وَكَانَتْ فِلْقَةٌ فَوْقَ الْجَبَلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اشْهَدْحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ و حَدَّثَنِيهِ بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ كِلَاهُمَا عَنْ شُعْبَةَ بِإِسْنَادِ ابْنِ مُعَاذٍ عَنْ شُعْبَةَ نَحْوَ حَدِيثِهِ غَيْرَ أَنَّ فِي حَدِيثِ ابْنِ أَبِي عَدِيٍّ فَقَالَ اشْهَدُوا اشْهَدُوا","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Ibrahim] dari [Abu Ma'mar] dari [Abdullah bin Mas'ud] berkata: Bulan terbelah dimasa Rasulullah Shallallahu 'alaihi wa Salam menjadi dua bagian, salah satunya menutupi gunung atau yang lainnya di atas gunung, kemudian Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ya Allah saksikanlah.\" Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Mujahid] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam seperti itu. Telah menceritakannya kepadaku [Bisyr bin Khalid] telah mengkhabarkan kepada kami [Muhammad bin Ja'far]. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi Adi], keduanya dari [Syu'bah] dengan sanad Ibnu Mu'adz dari Syu'bah seperti haditsnya, hanya saja dalam hadits Ibnu Abi Adi disebutkan: Lalu beliau bersabda: \"Saksikanlah, saksikanlah.\""},"4655":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ أَهْلَ مَكَّةَ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرِيَهُمْ آيَةً فَأَرَاهُمْ انْشِقَاقَ الْقَمَرِ مَرَّتَيْنِو حَدَّثَنِيهِ مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ بِمَعْنَى حَدِيثِ شَيْبَانَ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] dan [Abdu bin Humaid] keduanya berkata: Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Qatadah] dari [Anas], penduduk Makkah meminta Rasulullah Shallallahu 'alaihi wa Salam untuk memperlihatkan tanda-tanda kebesaran pada mereka lalu beliau memperlihatkan terbelahnya bulan pada mereka dua kali. Telah menceritakannya kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Qatadah] dari [Anas] dengan makna hadits Syaiban."},"4656":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَأَبُو دَاوُدَ ح و حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَأَبُو دَاوُدَ كُلُّهُمْ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَانْشَقَّ الْقَمَرُ فِرْقَتَيْنِوَفِي حَدِيثِ أَبِي دَاوُدَ انْشَقَّ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abu Dawud]. Telah menceritakan kepada kami [Ibnu Basyar] telah menceritakan kepada kami [Yahya bin Sa'id], [Muhammad bin Ja'far] dan [Abu Dawud], semuanya dari [Syu'bah] dari [Qatadah] dari [Anas] berkata: Bulan terbelah menjadi dua bagian. Dalam hadits Abu Dawud disebutkan: Bulan terbelah dimasa Rasulullah Shallallahu 'alaihi wa Salam."},"4657":{"ar":"حَدَّثَنَا مُوسَى بْنُ قُرَيْشٍ التَّمِيمِيُّ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرِ بْنِ مُضَرَ حَدَّثَنِي أَبِي حَدَّثَنَا جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ الْقَمَرَ انْشَقَّ عَلَى زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Quraisy At Taimi] telah menceritakan kepada kami [Ishaq bin Bukair bin Mudlar] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Ja'far bin Rabi'ah] dari [Irak bin Malik] dari [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] dari [Ibnu Abbas] berkata: Di masa Rasulullah Shallallahu 'alaihi wa Salam bulan pernah terbelah."},"4658":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَأَبُو أُسَامَةَ عَنْ الْأَعْمَشِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَحَدَ أَصْبَرُ عَلَى أَذًى يَسْمَعُهُ مِنْ اللَّهِ عَزَّ وَجَلَّ إِنَّهُ يُشْرَكُ بِهِ وَيُجْعَلُ لَهُ الْوَلَدُ ثُمَّ هُوَ يُعَافِيهِمْ وَيَرْزُقُهُمْحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ إِلَّا قَوْلَهُ وَيُجْعَلُ لَهُ الْوَلَدُ فَإِنَّهُ لَمْ يَذْكُرْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Abu Usamah] dari [Al A'masy] dari [Sa'id bin Jubair] dari [Abu Abdurrahman bin As Sulami] dari [Abu Musa] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada siapa pun yang lebih bersabar atas gangguan yang ia dengar melebihi Allah 'azza wajalla, ia disekutukan dan dianggap punya anak kemudian Ia memaafkan dan memberi mereka rizki.\" Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Abu Sa'id Al Asyaj] keduanya berkata: Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Sa'id bin Jubair] dari [Abu Abdurrahman As Sulami] dari [Abu Musa] dari nabi Shallallahu 'alaihi wa Salam sepertinya tapi ia tidak menyebut: Dianggap punya anak."},"4659":{"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ قَيْسٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحَدٌ أَصْبَرَ عَلَى أَذًى يَسْمَعُهُ مِنْ اللَّهِ تَعَالَى إِنَّهُمْ يَجْعَلُونَ لَهُ نِدًّا وَيَجْعَلُونَ لَهُ وَلَدًا وَهُوَ مَعَ ذَلِكَ يَرْزُقُهُمْ وَيُعَافِيهِمْ وَيُعْطِيهِمْ","id":"Telah menceritakan kepadaku [Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Al A'masy] telah menceritakan kepada kami [Sa'id bin Jubair] dari [Abu Abdurrahman As Sulami] berkata: [Abdullah bin Qais] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Tidak ada siapa pun yang lebih bersabar atas gangguan yang ia dengar melebihi Allah Ta'ala, mereka membuat tandingan untuknya dan menganggapNya punya anak, meski demikian Ia memberi mereka rizki, memaafkan dan memberi mereka.\""},"4660":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ تَبَارَكَ وَتَعَالَى لِأَهْوَنِ أَهْلِ النَّارِ عَذَابًا لَوْ كَانَتْ لَكَ الدُّنْيَا وَمَا فِيهَا أَكُنْتَ مُفْتَدِيًا بِهَا فَيَقُولُ نَعَمْ فَيَقُولُ قَدْ أَرَدْتُ مِنْكَ أَهْوَنَ مِنْ هَذَا وَأَنْتَ فِي صُلْبِ آدَمَ أَنْ لَا تُشْرِكَ أَحْسِبُهُ قَالَ وَلَا أُدْخِلَكَ النَّارَ فَأَبَيْتَ إِلَّا الشِّرْكَحَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ إِلَّا قَوْلَهُ وَلَا أُدْخِلَكَ النَّارَ فَإِنَّهُ لَمْ يَذْكُرْهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Ambari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Imran Al Jauni] dari [Anas bin Malik] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Allah Tabaraka wa Ta'ala bertanya kepada penduduk neraka yang siksanya paling ringan: 'Andai kau memiliki dunia seisinya, apa kau akan menebusnya? ' orang itu menjawab: 'Ya.' Allah berfirman: 'Aku telah menginginkan yang lebih ringan dari (siksaan) ini saat kau masih berada ditulang rusuk Adam agar kau tidak menyekutukan -saya (Anas) kira beliau bersabda: 'Dan Aku tidak memasukkanmu ke neraka, tapi kau enggan dan tetap menyekutukan.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Imran] berkata: Aku mendengar [Anas bin Malik] menceritakan dari nabi Shallallahu 'alaihi wa Salam sepertinya, hanya saja ia tidak menyebut: Dan Aku tidak memasukkanmu ke neraka."},"4661":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُقَالُ لِلْكَافِرِ يَوْمَ الْقِيَامَةِ أَرَأَيْتَ لَوْ كَانَ لَكَ مِلْءُ الْأَرْضِ ذَهَبًا أَكُنْتَ تَفْتَدِي بِهِ فَيَقُولُ نَعَمْ فَيُقَالُ لَهُ قَدْ سُئِلْتَ أَيْسَرَ مِنْ ذَلِكَو حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ ح و حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ يَعْنِي ابْنَ عَطَاءٍ كِلَاهُمَا عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ فَيُقَالُ لَهُ كَذَبْتَ قَدْ سُئِلْتَ مَا هُوَ أَيْسَرُ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar Al Qawariri], [Ishaq bin Ibrahim], [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], [Ishaq] berkata: Telah mengkhabarkan kepada kami dan yang lainnya berkata: Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [ayahku] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik] bahwa nabi Shallallahu 'alaihi wa Salam bersabda: \"Pada hari kiamat orang kafir ditanya: 'Andai kau memiliki emas sepenuh bumi, apa akan kau jadikan penebus? ' ia menjawab: 'Ya.' Dikatakan padanya: 'Kau pernah diminta yang lebih ringan darinya'.\" Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Rouh bin Ubadah]. Telah menceritakan kepadaku [Amru bin Zurarah] telah mengkhabarkan kepada kami [Abdulwahahb bin Atho`], keduanya dari [Sa'id bin Abu Urubah] dari [Qatadah] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam sepertinya, hanya saja ia berkata: Lalu dikatakan padanya: \"Kau pernah diminta sesuatu yang lebih ringan darinya.\""},"4662":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ كَيْفَ يُحْشَرُ الْكَافِرُ عَلَى وَجْهِهِ يَوْمَ الْقِيَامَةِ قَالَ أَلَيْسَ الَّذِي أَمْشَاهُ عَلَى رِجْلَيْهِ فِي الدُّنْيَا قَادِرًا عَلَى أَنْ يُمْشِيَهُ عَلَى وَجْهِهِ يَوْمَ الْقِيَامَةِقَالَ قَتَادَةُ بَلَى وَعِزَّةِ رَبِّنَا","id":"Telah menceritakan kepadaku [Zuhair bin Harb] dan [Abdu bin Humaid], teks milik Zuhair, keduanya berkata: Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik], seseorang bertanya: Wahai Rasulullah, bagaiaman orang kafir dikumpulkan (dengan berjalan) di atas wajahnya pada hari kiamat? Beliau menjawab: \"Bukankah Yang membuatnya berjalan dengan dua kaki di dunia mampu untuk membuatnya berjalan di atas wajahnya pada hari kiamat?\" Qatadah menjawab: Benar, demi kemuliaan Rabb kami."},"4663":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِأَنْعَمِ أَهْلِ الدُّنْيَا مِنْ أَهْلِ النَّارِ يَوْمَ الْقِيَامَةِ فَيُصْبَغُ فِي النَّارِ صَبْغَةً ثُمَّ يُقَالُ يَا ابْنَ آدَمَ هَلْ رَأَيْتَ خَيْرًا قَطُّ هَلْ مَرَّ بِكَ نَعِيمٌ قَطُّ فَيَقُولُ لَا وَاللَّهِ يَا ر��بِّ وَيُؤْتَى بِأَشَدِّ النَّاسِ بُؤْسًا فِي الدُّنْيَا مِنْ أَهْلِ الْجَنَّةِ فَيُصْبَغُ صَبْغَةً فِي الْجَنَّةِ فَيُقَالُ لَهُ يَا ابْنَ آدَمَ هَلْ رَأَيْتَ بُؤْسًا قَطُّ هَلْ مَرَّ بِكَ شِدَّةٌ قَطُّ فَيَقُولُ لَا وَاللَّهِ يَا رَبِّ مَا مَرَّ بِي بُؤْسٌ قَطُّ وَلَا رَأَيْتُ شِدَّةً قَطُّ","id":"Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Hammad bin Salamah] dari [Tsabit Al Banani] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Orang termewah sedunia yang termasuk penghuni neraka didatangkan pada hari kiamat lalu dicelupkan sekali ke neraka, setelah itu dikatakan padanya: 'Wahai anak cucu Adam, apa kau pernah melihat kebaikan sedikit pun, apa kau pernah merasakan kenikmatan sedikit pun? ' ia menjawab: 'Tidak, demi Allah, wahai Rabb.' Kemudian orang paling sengsara didunia yang termasuk penghuni surga didatangkan kemudian ditempatkan di surga sebentar, setelah itu dikatakan padanya: 'Hai anak cucu Adam, apa kau pernah melihat kesengsaraan sedikit pun, apa kau pernah merasa sengsara sedikit pun? ' ia menjawab: 'Tidak, demi Allah, wahai Rabb, aku tidak pernah merasa sengsara sedikit pun dan aku tidak pernah melihat kesengsaraan pun'.\""},"4664":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَظْلِمُ مُؤْمِنًا حَسَنَةً يُعْطَى بِهَا فِي الدُّنْيَا وَيُجْزَى بِهَا فِي الْآخِرَةِ وَأَمَّا الْكَافِرُ فَيُطْعَمُ بِحَسَنَاتِ مَا عَمِلَ بِهَا لِلَّهِ فِي الدُّنْيَا حَتَّى إِذَا أَفْضَى إِلَى الْآخِرَةِ لَمْ تَكُنْ لَهُ حَسَنَةٌ يُجْزَى بِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb], teks milik Zuhair, keduanya berkata: Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammam bin Yahya] dari [Qatadah] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah tidak menzhalimi kebaikan orang mu`min yang diberikan didunia dan akan dibalas diakhirat, sedangkan orang kafir diberi makan karena kebaikan-kebaikan yang dikerjakan karena Allah didunia hingga ia menuju akhirat tanpa memiliki suatu kebaikan pun yang bisa dibalas.\""},"4665":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ النَّضْرِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ حَدَّثَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْكَافِرَ إِذَا عَمِلَ حَسَنَةً أُطْعِمَ بِهَا طُعْمَةً مِنْ الدُّنْيَا وَأَمَّا الْمُؤْمِنُ فَإِنَّ اللَّهَ يَدَّخِرُ لَهُ حَسَنَاتِهِ فِي الْآخِرَةِ وَيُعْقِبُهُ رِزْقًا فِي الدُّنْيَا عَلَى طَاعَتِهِحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرُّزِّيُّ أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِهِمَا","id":"Telah menceritakan kepada kami [Ashim bin An Nadhr At Taimi] telah menceritakan kepada kami [Mu'tamir] berkata: Aku mendengar [ayahku] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] ia menceritakan dari Rasulullah Shallallahu 'alaihi wa Salam, bila orang kafir mengerjakan suatu kebaikan, dengan kebaikan itu ia diberi sesuap makanan dari dunia, sedangkan orang mu`min itu kebaikan-kebaikannya disimpan oleh Allah diakhirat dan ia diberi rizki di dunia karena ketaatannya. Telah menceritakan kepada kami [Muhammad bin Abdullah Ar Ruzzi] telah mengkhabarkan kepada kami [Abdulwahhab bin Atho`] dari [Sa'id] dari [Qatadah] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam dengan makna hadits mereka berdua."},"4666":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الزَّرْعِ لَا تَزَالُ الرِّيحُ تُمِيلُهُ وَلَا يَزَالُ الْمُؤْمِنُ يُصِيبُهُ الْبَلَاءُ وَمَثَلُ الْمُنَافِقِ كَمَثَلِ شَجَرَةِ الْأَرْزِ لَا تَهْتَزُّ حَتَّى تَسْتَحْصِدَحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ عَبْدِ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِ عَبْدِ الرَّزَّاقِ مَكَانَ قَوْلِهِ تُمِيلُهُ تُفِيئُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Perumpamaan orang mu`min seperti tanaman, angin senantiasa menerpanya dan orang mu`min itu akan senantiasa tertimpa musibah. Sedangkan perumpamaan orang munafik seperti pohon cedar, tidaklah ia bergerak hingga di ketam.\" Telah menceritakan kepada kami [Muhammad bin Rafi'] dan [Abdu bin Humaid] dari [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dengan sanad ini, hanya saja dalam hadits Abdurrazzaq menyebut TUFII'UHU sebagai ganti TIMIILUHU."},"4667":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا زَكَرِيَّاءُ بْنُ أَبِي زَائِدَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنِي ابْنُ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الْخَامَةِ مِنْ الزَّرْعِ تُفِيئُهَا الرِّيحُ تَصْرَعُهَا مَرَّةً وَتَعْدِلُهَا أُخْرَى حَتَّى تَهِيجَ وَمَثَلُ الْكَافِرِ كَمَثَلِ الْأَرْزَةِ الْمُجْذِيَةِ عَلَى أَصْلِهَا لَا يُفِيئُهَا شَيْءٌ حَتَّى يَكُونَ انْجِعَافُهَا مَرَّةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Muhammad bin Bisyr] keduanya berkata: Telah menceritakan kepada kami [Zakariya bin Abu Za`idah] dari [Sa'ad bin Ibrahim] telah menceritakan kepadaku [Ibnu Ka'ab bin Malik] dari [ayahnya, Ka'ab] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Perumpamaan mu`min itu seperti tanaman yang kuat dan lentur, angin menerpanya, kadang menundukkannya dan kadang membuatnya tegak hingga bergerak, dan perumpamaan orang kafir itu seperti pohon cedar yang dicabut dengan akar-akarnya, tidak ada sesuatu pun yang menerpanya hingga ia dicabut sekali saja.\""},"4668":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الْخَامَةِ مِنْ الزَّرْعِ تُفِيئُهَا الرِّيَاحُ تَصْرَعُهَا مَرَّةً وَتَعْدِلُهَا حَتَّى يَأْتِيَهُ أَجَلُهُ وَمَثَلُ الْمُنَافِقِ مَثَلُ الْأَرْزَةِ الْمُجْذِيَةِ الَّتِي لَا يُصِيبُهَا شَيْءٌ حَتَّى يَكُونَ انْجِعَافُهَا مَرَّةً وَاحِدَةًو حَدَّثَنِيهِ مُحَمَّدُ بْنُ حَاتِمٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ أَنَّ مَحْمُودًا قَالَ فِي رِوَايَتِهِ عَنْ بِشْرٍ وَمَثَلُ الْكَافِرِ كَمَثَلِ الْأَرْزَةِ وَأَمَّا ابْنُ حَاتِمٍ فَقَالَ مَثَلُ الْمُنَافِقِ كَمَا قَالَ زُهَيْرٌ و حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ وَعَبْدُ اللَّهِ بْنُ هَاشِمٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ ابْنُ هَاشِمٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ و قَالَ ابْنُ بَشَّارٍ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ وَقَالَا جَمِيعًا فِي حَدِيثِهِمَا عَنْ يَحْيَى وَمَثَلُ الْكَافِرِ مَثَلُ الْأَرْزَةِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Bisyr bin Ar Sari] dan [Abdurrahman bin Mahdi] keduanya berkata: telah menceritakan kepada kami [Sufyan] dari [Sa'id bin Ibrahim] dari [Abdurrahman bin Ka'ab bin Malik] dari [Ayahnya] ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan seorang mukmin seperti tanaman yang kuat dan lentur, ketika angin menerpanya, kadang menundukkannya dan kadang membuatnya tegak hingga waktunya tiba, dan perumpamaan orang kafir seperti pohon cedar yang dicabut dengan akar-akarnya, tidak ada sesuatu pun yang menerpanya hingga ia tercabut hanya sekali saja.\" telah menceritakannya kepadaku [Muhammad bin Hatim] dan [Mahmud bin Ghailan] keduanya berkata: telah menceritakan kepada kami [Bisyr bin As Sari] telah menceritakan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari [Abdullah bin Ka'ab bin Malik] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, hanya saja Mahmud menyebutkan dalam riwayatnya dari Bisyr; \"Dan perumpamaan orang kafir seperti pohon cedar, sementara Ibnu Hatim menyebutkan; \"Perumpamaan orang munafik.\" sebagaimana yang disebutkan oleh Zuhair. Dan telah menceritakannya kepada kami [Muhammad bin Basyar] dan [Abdullah bin Hasyim] keduanya berkata; telah menceritakan kepada kami [Yahya Al Qaththan] dari [Sufyan] dari [Sa'd bin Ibrahim]. [Ibnu Hasyim] berkata; dari [Abdullah bin Ka'ab bin Malik] dari [Ayahnya]. Ibnu Basyar mengatakan dari Ka'b bin Malik dari Ayahnya dari Nabi shallallahu 'alaihi wasallam seperti hadits mereka, dan mereka menyebutkan dalam haditsnya dari Yahya: \"Dan perumpamaan orang kafir itu seperti pohon cedar.\""},"4669":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَعَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ وَاللَّفْظُ لِيَحْيَى قَالُوا حَدَّثَنَا إِسْمَعِيلُ يَعْنُونَ ابْنَ جَعْفَرٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً لَا يَسْقُطُ وَرَقُهَا وَإِنَّهَا مَثَلُ الْمُسْلِمِ فَحَدِّثُونِي مَا هِيَ فَوَقَعَ النَّاسُ فِي شَجَرِ الْبَوَادِي قَالَ عَبْدُ اللَّهِ وَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَاسْتَحْيَيْتُ ثُمَّ قَالُوا حَدِّثْنَا مَا هِيَ يَا رَسُولَ اللَّهِ قَالَ فَقَالَ هِيَ النَّخْلَةُ قَالَ فَذَكَرْتُ ذَلِكَ لِعُمَرَ قَالَ لَأَنْ تَكُونَ قُلْتَ هِيَ النَّخْلَةُ أَحَبُّ إِلَيَّ مِنْ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub], [Qutaibah bin Sa'id] dan [Ali bin Hujr As Sa'di], teks milik Yahya, mereka berkata: Telah menceritakan kepada kami [Ismail bin Ja'far] telah mengkhabarkan kepadaku [Abdullah bin Dinar] ia mendengar [Abdullah bin Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Sesungguhnya di antara pepohonan ada sebuah pohon yang daunnya tidak gugur, itu seperti orang mu`min, katakan padaku pohon apa itu?\" Abdullah berkata: Orang-orang mengira pohon padang pasir sementara aku mengiranya pohon kurma. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Ia pohon kurma\" tapi aku malu mengatakannya. Abdullah berkata: Aku beritahu Umar apa yang aku kira lalu Umar berkata: Sungguh kau mengatakannya itu lebih aku sukai dari pada aku memiliki ini dan ini. "},"4670":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الْخَلِيلِ الضُّبَعِيِّ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا لِأَصْحَابِهِ أَخْبِرُونِي عَنْ شَجَرَةٍ مَثَلُهَا مَثَلُ الْمُؤْمِنِ فَجَعَلَ الْقَوْمُ يَذْكُرُونَ شَجَرًا مِنْ شَجَرِ الْبَوَادِي قَالَ ابْنُ عُمَرَ وَأُلْقِيَ فِي نَفْسِي أَوْ رُوعِيَ أَنَّهَا النَّخْلَةُ فَجَعَلْتُ أُرِيدُ أَنْ أَقُولَهَا فَإِذَا أَسْ��َانُ الْقَوْمِ فَأَهَابُ أَنْ أَتَكَلَّمَ فَلَمَّا سَكَتُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي عُمَرَ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ صَحِبْتُ ابْنَ عُمَرَ إِلَى الْمَدِينَةِ فَمَا سَمِعْتُهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا حَدِيثًا وَاحِدًا قَالَ كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِجُمَّارٍ فَذَكَرَ بِنَحْوِ حَدِيثِهِمَا و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ سَمِعْتُ ابْنَ عُمَرَ يَقُولُا أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجُمَّارٍ فَذَكَرَ نَحْوَ حَدِيثِهِمْ","id":"Telah menceritakan kepadaku [Muhammad bin Ubaid Al ghubari] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Abu Al Khalil Adh Dhuba'i] dari [Mujahid] dari [Ibnu Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam bertanya kepada para sahabat beliau pada suatu hari: \"Beritahukanlah padaku tentang sebuah pohon, perumpamaannya sama seperti orang mu`min.\" orang-orang menyebut salah satu pepohonan gurun lalu Ibnu Umar berkata: Hatiku mengatakan -atau mempertimbangkan pohon tersebut adalah pohon kurma, aku ingin mengatakannya tapi mereka semua orang-orang tua, aku segan berbicara. Saat mereka diam, Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Itu adalah pohon kurma.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Umar] keduanya berkata: telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Abi Najih] dari [Mujahid] berkata: Aku menemani Ibnu Umar ke Madinah, aku hanya mendengarnya menceritakan satu hadits saja dari Rasulullah Shallallahu 'alaihi wa Salam, ia berkata: Kami berada di dekat nabi Shallallahu 'alaihi wa Salam, beliau diberi daging kurma yang lunak lalu Ibnu Umar menyebutkan seperti hadits mereka berdua. Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Saif] berkata: Aku mendengar [Mujahid] berkata: Aku mendengar [Ibnu Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam diberi daging kurma yang lunak lalu ia menyebut seperti hadits mereka."},"4671":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَخْبِرُونِي بِشَجَرَةٍ شِبْهِ أَوْ كَالرَّجُلِ الْمُسْلِمِ لَا يَتَحَاتُّ وَرَقُهَا قَالَ إِبْرَاهِيمُ لَعَلَّ مُسْلِمًا قَالَ وَتُؤْتِي أُكُلَهَا وَكَذَا وَجَدْتُ عِنْدَ غَيْرِي أَيْضًا وَلَا تُؤْتِي أُكُلَهَا كُلَّ حِينٍ قَالَ ابْنُ عُمَرَ فَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ وَرَأَيْتُ أَبَا بَكْرٍ وَعُمَرَ لَا يَتَكَلَّمَانِ فَكَرِهْتُ أَنْ أَتَكَلَّمَ أَوْ أَقُولَ شَيْئًا فَقَالَ عُمَرُ لَأَنْ تَكُونَ قُلْتَهَا أَحَبُّ إِلَيَّ مِنْ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata: Kami berada di dekat Rasulullah Shallallahu 'alaihi wa Salam lalu beliau bertanya: \"Beritahukan padaku suatu pohon yang mirip orang muslim, daunnya tidak berguguran!\" Ibrahim berkata: Mungkin beliau menyebut: Muslim, beliau bersabda: \"Selalu berbuah\" -seperti ini yang aku temukan dalam riwayat yang lain: \"Dan ia tidak berbuah setiap waktu.\" Ibnu Umar berkata: Hatiku mengatakan bahwa pohon itu adalah pohon kurma. Aku melihat Abu Bakar dan Umar tidak berbicara sehingga aku tidak mau berbicara atau mengatakan apa pun. Umar berkata: Andai kau mengatakannya, itu lebih aku sukai dari ini dan ini."},"4672":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْ��َشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الشَّيْطَانَ قَدْ أَيِسَ أَنْ يَعْبُدَهُ الْمُصَلُّونَ فِي جَزِيرَةِ الْعَرَبِ وَلَكِنْ فِي التَّحْرِيشِ بَيْنَهُمْو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], berkata [Ishaq]: Telah mengkhabarkan kepada kami sedangkan [Utmsan] berkata: Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya setan telah putus asa untuk disembah orang-orang yang shalat dijazirah arab, tapi ia mengadu domba diantara mereka.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki']. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah], keduanya dari [Al A'masy] dengan sanad ini."},"4673":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ عَرْشَ إِبْلِيسَ عَلَى الْبَحْرِ فَيَبْعَثُ سَرَايَاهُ فَيَفْتِنُونَ النَّاسَ فَأَعْظَمُهُمْ عِنْدَهُ أَعْظَمُهُمْ فِتْنَةً","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], berkata [Ishaq]: Telah mengkhabarkan kepada kami, sedangkan [Utsman] berkata: Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: Sesungguhnya singgasana Iblis berada di atas laut, ia mengirim bala tentaranya kemudian mereka menggoda manusia. Yang paling agung bagi iblis adalah (setan) yang paling besar godaannya.\""},"4674":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَا أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ إِبْلِيسَ يَضَعُ عَرْشَهُ عَلَى الْمَاءِ ثُمَّ يَبْعَثُ سَرَايَاهُ فَأَدْنَاهُمْ مِنْهُ مَنْزِلَةً أَعْظَمُهُمْ فِتْنَةً يَجِيءُ أَحَدُهُمْ فَيَقُولُ فَعَلْتُ كَذَا وَكَذَا فَيَقُولُ مَا صَنَعْتَ شَيْئًا قَالَ ثُمَّ يَجِيءُ أَحَدُهُمْ فَيَقُولُ مَا تَرَكْتُهُ حَتَّى فَرَّقْتُ بَيْنَهُ وَبَيْنَ امْرَأَتِهِ قَالَ فَيُدْنِيهِ مِنْهُ وَيَقُولُ نِعْمَ أَنْتَقَالَ الْأَعْمَشُ أُرَاهُ قَالَ فَيَلْتَزِمُهُ","id":"Telah menceritakan kepada kami [Abu Kuraib, Muhammad bin Al Ala`] dan [Ishaq bin Ibrahim], teks milik Abu Kuraib, keduanya berkata: Telah mengkhabarkan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Iblis meletakkan singgasananya di atas air lalu mengirim bala tentaranya, (setan) yang kedudukannya paling rendah bagi Iblis adalah yang paling besar godaannya. Salah satu diantara mereka datang lalu berkata: 'Aku telah melakukan ini dan itu.' Iblis menjawab: 'Kau tidak melakukan apa pun.' Lalu yang lain datang dan berkata: 'Aku tidak meninggalkannya hingga aku memisahkannya dengan istrinya.' Beliau bersabda: \"Iblis mendekatinya lalu berkata: 'Bagus kamu.\" Al A'masy menyebutkan dalam riwayatnya: \"Iblis berkata: 'Tetaplah (menggodanya).\""},"4675":{"ar":"حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَبْعَثُ الشَّيْطَانُ سَرَايَاهُ فَيَفْتِنُونَ النَّاسَ فَأَعْظَمُهُمْ عِنْدَهُ مَنْزِلَةً أَعْظَمُهُمْ فِتْنَةً","id":"Telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Ma'qil] dari [Abu Az Zubair] dari [Jabir] ia mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Setan mengutus bala tentaranya lalu mereka menggoda manusia. Yang paling agung bagi iblis adalah (setan) yang paling besar godaannya.\""},"4676":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ وُكِّلَ بِهِ قَرِينُهُ مِنْ الْجِنِّ قَالُوا وَإِيَّاكَ يَا رَسُولَ اللَّهِ قَالَ وَإِيَّايَ إِلَّا أَنَّ اللَّهَ أَعَانَنِي عَلَيْهِ فَأَسْلَمَ فَلَا يَأْمُرُنِي إِلَّا بِخَيْرٍحَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِيَانِ ابْنَ مَهْدِيٍّ عَنْ سُفْيَانَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ عَمَّارِ بْنِ رُزَيْقٍ كِلَاهُمَا عَنْ مَنْصُورٍ بِإِسْنَادِ جَرِيرٍ مِثْلَ حَدِيثِهِ غَيْرَ أَنَّ فِي حَدِيثِ سُفْيَانَ وَقَدْ وُكِّلَ بِهِ قَرِينُهُ مِنْ الْجِنِّ وَقَرِينُهُ مِنْ الْمَلَائِكَةِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], berkata [Ishaq]: Telah mengkhabarkan kepada kami, sedangkan [Utsman] berkata: Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [ayahnya] dari [Abdullah bin Mas'ud] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang pun dari kalian melainkan dikuasai pendamping dari kalangan jin.\" Mereka bertanya: Tuan juga, wahai Rasulullah? beliau menjawab: \"Aku juga, hanya saja Allah membantuku mengalahkannya lalu ia masuk Islam, ia hanya memerintahkan kebaikan padaku.\" Telah menceritakan kepada kami [Ibnu Abi Al Mutsanna] dan [Ibnu Basyar] keduanya berkata: Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan]. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Ammar bin Ruzaiq] keduanya dari [Manshur] dengan sanad jarir seperti haditsnya, hanya saja dalam hadits Sufyan disebutkan: \"Melainkan dikuasai pendamping dari kalangan jin dan dari kalangan malaikat.\""},"4677":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ ابْنِ قُسَيْطٍ حَدَّثَهُ أَنَّ عُرْوَةَ حَدَّثَهُ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ عِنْدِهَا لَيْلًا قَالَتْ فَغِرْتُ عَلَيْهِ فَجَاءَ فَرَأَى مَا أَصْنَعُ فَقَالَ مَا لَكِ يَا عَائِشَةُ أَغِرْتِ فَقُلْتُ وَمَا لِي لَا يَغَارُ مِثْلِي عَلَى مِثْلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَدْ جَاءَكِ شَيْطَانُكِ قَالَتْ يَا رَسُولَ اللَّهِ أَوْ مَعِيَ شَيْطَانٌ قَالَ نَعَمْ قُلْتُ وَمَعَ كُلِّ إِنْسَانٍ قَالَ نَعَمْ قُلْتُ وَمَعَكَ يَا رَسُولَ اللَّهِ قَالَ نَعَمْ وَلَكِنْ رَبِّي أَعَانَنِي عَلَيْهِ حَتَّى أَسْلَمَ","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Abu Shakr] dari [Ibnu Qusaith] telah menceritakan kepadanya bahwa [Urwah] telah menceritakan kepadanya bahwa [Aisyah], istri nabi Shallallahu 'alaihi wa Salam, telah menceritakan kepadanya bahwa Rasulullah Shallallahu 'alaihi wa Salam keluar dari kediamannya pada suatu malam. Aisyah berkata: Aku merasa cemburu pada beliau lalu beliau datang dan aku melihat yang beliau lalukan. Beliau bertanya: \"Kau kenapa, wahai Aisyah?\" aku menjawab: Orang sepertiku mengapa tidak menyemburui orang seperti Tuan? Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Apa setanmu mendatangimu?\" Aisyah bertanya: Waha Rasulullah, apakah ada setan menyertaiku? Beliau menjawab: \"Ya.\" Aisyah bertanya: Juga menyertai semua manusia? Beliau menjawab: \"Ya.\" Ia bertanya: Menyertai Tuan juga? Beliau menjawab: \"Ya, hanya saja Rabbku menolongku mengalahkannya hingga ia masuk Islam.\""},"4678":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَنْ يُنْجِيَ أَحَدًا مِنْكُمْ عَمَلُهُ قَالَ رَجُلٌ وَلَا إِيَّاكَ يَا رَسُولَ اللَّهِ قَالَ وَلَا إِيَّايَ إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ مِنْهُ بِرَحْمَةٍ وَلَكِنْ سَدِّدُواو حَدَّثَنِيهِ يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ بِرَحْمَةٍ مِنْهُ وَفَضْلٍ وَلَمْ يَذْكُرْ وَلَكِنْ سَدِّدُوا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Bukair] dari [Busr bin Sa'id] dari [Abu Hurairah] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang pun dari kalian yang diselamatkan oleh amalnya.\" Seseorang bertanya: Tuan juga, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Allah melimpahkan rahmatNya padaku, tapi tujulah kebenaran.\" Telah menceritakannya kepadaku [Yunus bin Abdula'la Ash Shadafi] telah mengkhabarkan kepada kami [Abdullah bin Wahab] telah mengkhabarkan kepadaku [Amru bin Al Harits] dar [Bukair bin Al Asyuj] dengan sanad ini, hanya saja ia menyebutkan: \"Rahmat dan karuniaNya, \" dan tidak menyebut: \"Tapi tujulah kebenaran.\""},"4679":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ يُدْخِلُهُ عَمَلُهُ الْجَنَّةَ فَقِيلَ وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي رَبِّي بِرَحْمَةٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayub] dari [Muhammad] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada seorang pun yang dimasukkan surga oleh amalnya.\" Dikatakan: Tidak juga Tuan, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Rabbmu melimpahkan rahmat padaku.\""},"4680":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ مِنْكُمْ يُنْجِيهِ عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ مِنْهُ بِمَغْفِرَةٍ وَرَحْمَةٍوَقَالَ ابْنُ عَوْنٍ بِيَدِهِ هَكَذَا وَأَشَارَ عَلَى رَأْسِهِ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ مِنْهُ بِمَغْفِرَةٍ وَرَحْمَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abi Adi] dari [Ibnu Aun] dari [Muhammad] dari [Abu Hurairah] berkata: Nabi Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang pun dari kalian yang diselamatkan oleh amalnya.\" Seseorang bertanya: Tuan juga, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Allah melimpahkan ampunan dan rahmat padaku.\" Ibnu Aun menunjukkan tangan ke kepalanya dan berkata: Tidak juga aku, kecuali bila Allah melimpahkan ampunan dan rahmat padaku."},"4681":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ يُنْجِيهِ عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَدَارَكَنِيَ اللَّهُ مِنْهُ بِرَحْمَةٍ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang pun dari kalian yang diselamatkan oleh amalnya.\" Seseorang bertanya: Tuan juga, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila rahmat dariNya menjemputku.\""},"4682":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا أَبُو عَبَّادٍ يَحْيَى بْنُ عَبَّادٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يُدْخِلَ أَحَدًا مِنْكُمْ عَمَلُهُ الْجَنَّةَ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ مِنْهُ بِفَضْلٍ وَرَحْمَةٍ","id":"Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Abu Abbad Yahya bin Abbad] telah menceritakan kepada kami [Ibrahim bin Sa'ad] telah menceritakan kepada kami [Ibnu Syihab] dari [Abu 'Ubaid] budak Abdurrahman bin Auf, dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada seorang pun yang dimasukkan surga oleh amalnya.\" Dikatakan: Tidak juga Tuan, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Rabbmu melimpahkan karunia dan rahmat padaku.\""},"4683":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِبُوا وَسَدِّدُوا وَاعْلَمُوا أَنَّهُ لَنْ يَنْجُوَ أَحَدٌ مِنْكُمْ بِعَمَلِهِ قَالُوا يَا رَسُولَ اللَّهِ وَلَا أَنْتَ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ بِرَحْمَةٍ مِنْهُ وَفَضْلٍو حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ بِالْإِسْنَادَيْنِ جَمِيعًا كَرِوَايَةِ ابْنِ نُمَيْرٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَزَادَ وَأَبْشِرُوا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Mendekatlah, tujulah kebenaran dan ketahuilah bahwa sesungguhnya tidak seorang pun dari kalian yang selamat karena amalnya.\" Mereka bertanya: \"Tidak juga Tuan, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Rabbmu melimpahkan rahmat dan karunia padaku.\" Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dengan kedua dua sanad secara keseluruhan seperti riwayat Ibnu Numar. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya dan ia menambahi: \"Dan bergembiralah.\""},"4684":{"ar":"حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُدْخِلُ أَحَدًا مِنْكُمْ عَمَلُهُ الْجَنَّةَ وَلَا يُجِيرُهُ مِنْ النَّارِ وَلَا أَنَا إِلَّا بِرَحْمَةٍ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Ma'qil] dari [Abu Az Zubair] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Tidak seorang pun dari kalian yang dimasukkan surga oleh amalnya dan tidak juga diselamatkan dari neraka karenanya, tidak juga aku kecuali karena rahmat dari Allah.\""},"4685":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ وَاللَّفْظُ لَهُ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ يُحَدِّثُ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا كَانَتْ تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَدِّدُوا وَقَارِبُوا وَأَبْشِرُوا فَإِنَّهُ لَنْ يُدْخِلَ الْجَنَّةَ أَحَدًا عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِيَ اللَّهُ مِنْهُ بِرَحْمَةٍ وَاعْلَمُوا أَنَّ أَحَبَّ الْعَمَلِ إِلَى اللَّهِ أَدْوَمُهُ وَإِنْ قَلَّو حَدَّثَنَاه حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ عَنْ مُوسَى بْنِ عُقْبَةَ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ وَأَبْشِرُوا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Abdul Aziz bin Muhammad] telah mengkhabarkan kepada kami [Musa bin Uqbah]. Telah menceritakan kepadaku [Muhammad bin Hatim], teks hadits miliknya, telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa bin Uqbah] berkata: Aku mendengar [Abu Salamah bin Aburrahman bin Auf] menceritakan dari [Aisyah, istri nabi] Shallallahu 'alaihi wa Salam, ia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tujulah (kebenaran), mendekatlah dan bergembiralah bahwa sesungguhnya tidak seorang pun dari kalian yang dimasukkan surga oleh amalnya.\" Mereka bertanya: \"Tidak juga Tuan, wahai Rasulullah? beliau menjawab: \"Tidak juga aku, kecuali bila Rabbmu melimpahkan rahmat dan karunia padaku. Dan ketahuilah bahwa amal yang paling sukai Allah adalah yang paling rutin meski sedikit.\" Telah menceritakannya kepada kami [Hasan Al Hulwani] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [Abdul Aziz bin Al Muthallib] dari [Musa bin Uqbah] dengan sanad ini, mereka tidak menyebutkan: \"Dan bergembiralah.\""},"4686":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى حَتَّى انْتَفَخَتْ قَدَمَاهُ فَقِيلَ لَهُ أَتَكَلَّفُ هَذَا وَقَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ فَقَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu Awanah] dari [Ziyad bin Ilaqah] dari [Al Mughirah bin Syu'bah] nabi Shallallahu 'alaihi wa Salam shalat hingga kedua kaki beliau bengkak, dikatakan pada beliau: Apa Tuan memaksakan ini padahal Allah telah mengampuni dosa yang terlalu dan yang dikemudian. Beliau menyahut: \"Apakah aku tidak menjadi hamba yang bersyukur?\""},"4687":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ سَمِعَ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُاقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى وَرِمَتْ قَدَمَاهُ قَالُوا قَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Numair] keduanya berkata: Telah menceritakan kepada kami [Sufyan] dari [Ziyad bin Ilaqah] ia mendengar [Al Mughirah bin Syu'bah] berkata: Nabi Shallallahu 'alaihi wa Salam shalat malam hingga kedua kaki beliau bengkak, mereka berkata: Allah telah mengampuni dosa Tuan yang telah berlalu dan yang dikemudian. Beliau bersabda: \"Apakah aku tidak menjadi hamba yang bersyukur?\" "},"4688":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَهَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ ابْنِ قُسَيْطٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى قَامَ حَتَّى تَفَطَّرَ رِجْلَاهُ قَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ أَتَصْنَعُ هَذَا وَقَدْ غُفِرَ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ فَقَالَ يَا عَائِشَةُ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Harun bin Sa'id Al Aili] keduanya berkata: Telah menceritakan kepada kami [Ibnu Wahb] telah mengkhabarkan kepadaku [Abu Shakhr] dari [Ibnu Qusaith] dari [Urwah bin Az Zubair] dari [Aisyah] berkata: Bila shalat, Rasulullah Shallallahu 'alaihi wa Salam berdiri hingga kaki beliau bengkak. Aisyah berkata: Wahai Rasulullah, kenapa Tuan melakukan ini padahal Allah telah mengampuni dosa Tuan yang telah berlalu dan yang dikemudian. Beliau bersabda: \"Apakah aku tidak menjadi hamba yang bersyukur?\" "},"4689":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَكُنَّا جُلُوسًا عِنْدَ بَابِ عَبْدِ اللَّهِ نَنْتَظِرُهُ فَمَرَّ بِنَا يَزِيدُ بْنُ مُعَاوِيَةَ النَّخَعِيُّ فَقُلْنَا أَعْلِمْهُ بِمَكَانِنَا فَدَخَلَ عَلَيْهِ فَلَمْ يَلْبَثْ أَنْ خَرَجَ عَلَيْنَا عَبْدُ اللَّهِ فَقَالَ إِنِّي أُخْبَرُ بِمَكَانِكُمْ فَمَا يَمْنَعُنِي أَنْ أَخْرُجَ إِلَيْكُمْ إِلَّا كَرَاهِيَةُ أَنْ أُمِلَّكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الْأَيَّامِ مَخَافَةَ السَّآمَةِ عَلَيْنَاحَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا ابْنُ إِدْرِيسَ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ حَدَّثَنَا ابْنُ مُسْهِرٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَزَادَ مِنْجَابٌ فِي رِوَايَتِهِ عَنْ ابْنِ مُسْهِرٍ قَالَ الْأَعْمَشُ وَحَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah]. Telah menceritakan kepada kami [Ibnu Numair] dan teks hadits miliknya, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] berkata: Kami duduk di dekat pintu Abdullah seraya menantinya, lalu Yazid bin Mu'awiyah An Nakha'i melewati kami, kami berkata padanya: Beritahukan keberadaan kami padanya. Ia masuk, tidak lama kemudian [Abdullah] keluar lalu berkata: Aku telah diberitahu keberadaan kalian dan tidak ada yang menghalangiku untuk keluar menemui kalian kecuali karena aku tidak ingin membuat kalian jemu. Rasulullah Shallallahu 'alaihi wa Salam mengatur (penyampaian) nasehat bagi kami dalam beberapa hari karena khawatir kami jemu. Telah menceritakan kepada kami [Abu Sa'id Al Asyuj] telah menceritakan kepada kami [Ibnu Idris]. Telah menceritakan kepada kami [Minjab bin Al Harits At Taimi] telah menceritakan kepada kami [ibnu Mushir]. Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Khaysram] keduanya berkata: Telah mengkhabarkan kepada kami [Isa bin Yunus]. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan], semuanya dari [Al A'masy] dengan sanad ini dengan matan serupa. Minjab menambahkan dalam riwayatnya: Dari Ibnu Mushir. Al A'masy berkata: Telah menceritakan kepadaku [Amru bin Murrah] dari [Syaqiq] dari [Abdullah] sepertinya."},"4690":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَاللَّفْظُ لَهُ حَدَّثَنَا فُضَيْلُ بْنُ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ أَبِي وَائِلٍ قَالَكَانَ عَبْدُ اللَّهِ يُذَكِّرُنَا كُلَّ يَوْمِ خَمِيسٍ فَقَالَ لَهُ رَجُلٌ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّا نُحِبُّ حَدِيثَكَ وَنَشْتَهِيهِ وَلَوَدِدْنَا أَنَّكَ حَدَّثْتَنَا كُلَّ يَوْمٍ فَقَالَ مَا يَمْنَعُنِي أَنْ أُحَدِّثَكُمْ إِلَّا كَرَاهِيَةُ أَنْ أُمِلَّكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الْأَيَّامِ كَرَاهِيَةَ السَّآمَةِ عَلَيْنَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Jarir] dari [Manshur]. Telah menceritakan kepada kami [Ibnu Abi Umar], teks hadits miliknya, telah menceritakan kepada kami [Fudhail bin Iyadh] dari [Manshur] dari [Syaqiq Abu Wa`il] berkata: [Abdullah] menyampaikan nasehat untuk kami setiap hari kamis lalu seseorang berkata padanya: Hai Abu Abdurrahman, kami menyukai penyampaianmu. Kami ingin kau menceritakan kepada kami setiap hari. Abdullah berkata: Tidak ada yang menghalangiku untuk menceritakan kepada kalian selain karena aku tidak ingin membuat kalian jemu. Rasulullah Shallallahu 'alaihi wa Salam mengatur (penyampaian) nasehat pada kami dalam beberapa hari karena tidak mau membuat kami jemu."},"4691":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ وَحُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُفَّتْ الْجَنَّةُ بِالْمَكَارِهِ وَحُفَّتْ النَّارُ بِالشَّهَوَاتِو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنِي وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dan [Humaid] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Surga diliputi hal-hal yang tidak menyenangkan dan neraka diliputi syahwat.\" Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Syababah] telah menceritakan kepadaku [Warqa`] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"4692":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَزُهَيْرُ بْنُ حَرْبٍ قَالَ زُهَيْرٌ حَدَّثَنَا و قَالَ سَعِيدٌ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ مِصْدَاقُ ذَلِكَ فِي كِتَابِ اللَّهِ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }","id":"Telah menceritakan kepada kami [Sa'id bin Amru Al Asy'atsi] dan [Zuhair bin Harb], berkata [Zuhair]: Telah menceritakan kepada kami, sedangkan [Sa'id] berkata: Telah mengkhabarkan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Allah 'azza wajalla berfirman: 'Aku telah menyiapkan sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia untuk hamba-hambaKu yang shalih.' Pembenarnya ada didalam kitab Allah 'azza wajalla: \"Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (As Sajdah: 17)"},"4693":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ ذُخْرًا بَلْهَ مَا أَطْلَعَكُمْ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahab] telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] nabi Shallallahu 'alaihi wa Salam bersabda: \"Allah 'azza wajalla berfirman: 'Aku telah menyiapkan sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia untuk hamba-hambaKu yang shalih.' Sebagai simpanan, biarkan apa yang diperlihatkan Allah pada kalian.\""},"4694":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ ذُخْرًا بَلْهَ مَا أَطْلَعَكُمْ اللَّهُ عَلَيْهِ ثُمَّ قَرَأَ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: Telah menceritakan kepada kami [Abu Mu'awiyah]. Telah menceritakan kepada kami [Ibnu Numair], teks miliknya, telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah 'azza wajalla berfirman: 'Aku telah menyiapkan sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia untuk hamba-hambaKu yang shalih.' Sebagai simpanan, biarkan apa yang diperlihatkan Allah pada kalian.\" Setelah itu beliau membaca: \"Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang.\" (As Sajdah: 17) "},"4695":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَهَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي أَبُو صَخْرٍ أَنَّ أَبَا حَازِمٍ حَدَّثَهُ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ يَقُولُاشَهِدْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَجْلِسًا وَصَفَ فِيهِ الْجَنَّةَ حَتَّى انْتَهَى ثُمَّ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ حَدِيثِهِ فِيهَا مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ ثُمَّ اقْتَرَأَ هَذِهِ الْآيَةَ{ تَتَجَافَى جُنُوبُهُمْ عَنْ الْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفًا وَطَمَعًا وَمِمَّا رَزَقْنَاهُمْ يُنْفِقُونَ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Harun bin Sa'id Al Aili] keduanya berkata: Telah menceritakan kepada kami [Ibnu Wahab] telah menceritakan kepadaku [Abu Shakhr] bahwa [Abu Hazim] telah menceritakan kepadanya, ia berkata: Aku mendengar [Sahl bin Sa'id As Sa'idi] berkata: Aku menghadiri majlis Rasulullah Shallallahu 'alaihi wa Salam, dimajlis itu beliau menggambarkan surga hingga usai, diakhir pembicaraan beliau bersabda: \"Didalamnya ada sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia.\" Setelah itu beliau membaca: \"Lambung mereka jauh dari tempat tidurnyadan mereka selalu berdoa kepada Rabbnya dengan penuh rasa takut dan harap, serta mereka menafkahkan apa apa rezki yang kami berikan. Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (As Sajdah: 16-17) "},"4696":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ فِي الْجَنَّةِ لَشَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ سَنَةٍحَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَزَادَ لَا يَقْطَعُهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Sa'id bin Abu Sa'id Al Maburi] dari [ayahnya] dari [Abu Hurairah] dari Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda: \"Sesungguhnya di surga ada pohon, seorang pengendara berjalan di bawah naungannya selama seratus tahun.\" Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman Al Hizami] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya, ia menambahkan: \"Ia tidak juga sampai.\""},"4697":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا الْمَخْزُومِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَشَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hazhali] telah mengkhabarkan kepada kami [Al Makhzumi] telah menceritakan kepada kami [Wuhaid] dari [Abu Hazim] dari [Sahal bin Sa'id] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga itu terdapat sebuah pohon yang mana seorang penunggang kendaraan berjalan dengan bernaung di bawahnya selama seratus tahun, ia tidak juga sampai.\""},"4698":{"ar":"قَالَ أَبُو حَازِمٍ فَحَدَّثْتُ بِهِ النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ الزُّرَقِيَّ فَقَالَ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ شَجَرَةً يَسِيرُ الرَّاكِبُ الْجَوَادَ الْمُضَمَّرَ السَّرِيعَ مِائَةَ عَامٍ مَا يَقْطَعُهَا","id":"[Abu Hazim] berkata: Aku menceritakannya kepada [An Nu'man bin Abu Ayyasy Az Zuraqi], ia berkata: Telah menceritakan kepadaku [Abu Sa'id Al Khudri] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di dalam surga itu terdapat sebuah pohon yang mana seorang pengendara yang mahir dan penuh persiapan berjalan dengan cepat di bawah naungannya selama seratus tahun, ia tidak juga sampai.\""},"4699":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ سَهْمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ ح و حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَاللَّفْظُ لَهُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَقُولُ لِأَهْلِ الْجَنَّةِ يَا أَهْلَ الْجَنَّةِ فَيَقُولُونَ لَبَّيْكَ رَبَّنَا وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ فَيَقُولُ هَلْ رَضِيتُمْ فَيَقُولُونَ وَمَا لَنَا لَا نَرْضَى يَا رَبِّ وَقَدْ أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ خَلْقِكَ فَيَقُولُ أَلَا أُعْطِيكُمْ أَفْضَلَ مِنْ ذَلِكَ فَيَقُولُونَ يَا رَبِّ وَأَيُّ شَيْءٍ أَفْضَلُ مِنْ ذَلِكَ فَيَقُولُ أُحِلُّ عَلَيْكُمْ رِضْوَانِي فَلَا أَسْخَطُ عَلَيْكُمْ بَعْدَهُ أَبَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Sahm] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Malik bin Anas]. Telah menceritakan kepada kami [Harun bin Sa'id Al Aili], teks hadits miliknya, telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Malik bin Anas] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abu Sa'id Al Khudri] nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah bertanya kepada penduduk surga: 'Hai penduduk surga? ' mereka menjawab: Baik Rabb kami dan kebaikan ada ditanganMu.' Allah bertanya: 'Apa kalian ridha? ' mereka menjawab: 'Kenapa kami tidak ridha wahai Rabb, Kau telah memberi kami sesuatu yang tidak Kau berikan pada seorangpun dari makhlukMu.' Allah berfirman: 'Maukan kalian Aku beri yang lebih baik darinya? ' mereka bertanya: 'Wahai Rabb, apa yang lebih darinya? ' Allah berfirman: 'Aku halalkan keridhaanKu untuk kalian, Aku tidak akan murka pada kalian setelah itu selamanya'.\""},"4700":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْقَارِيَّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْلَ الْجَنَّةِ لَيَتَرَاءَوْنَ الْغُرْفَةَ فِي الْجَنَّةِ كَمَا تَرَاءَوْنَ الْكَوْكَبَ فِي السَّمَاءِقَالَ فَحَدَّثْتُ بِذَلِكَ النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ فَقَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُا كَمَا تَرَاءَوْنَ الْكَوْكَبَ الدُّرِّيَّ فِي الْأُفُقِ الشَّرْقِيِّ أَوْ الْغَرْبِيِّ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْمَخْزُومِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ أَبِي حَازِمٍ بِالْإِسْنَادَيْنِ جَمِيعًا نَحْوَ حَدِيثِ يَعْقُوبَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qari`] dari [Abu Hazim] dari [Sahl bin Sa'ad] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya penghuni surga saling melihat kamar-kamar di surga seperti melihat bintang di langit.\" Ia berkata: Lalu aku menceritakannya pada [An Nu'man bin Abu Ayyasy], ia berkata: Aku mendengar [Abu Sa'id Al Khudri] berkata: Seperti kalian melihat binatang terang diufuk timur atau barat. Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Al Makhzumi] telah menceritakan kepada kami [Wuhaib] dari [Abu Hazim] dengan kedua sanad sekaligus seperti hadits Ya'qub."},"4701":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ جَعْفَرِ بْنِ يَحْيَى بْنِ خَالِدٍ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَاللَّفْظُ لَهُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْلَ الْجَنَّةِ لَيَتَرَاءَوْنَ أَهْلَ الْغُرَفِ مِنْ فَوْقِهِمْ كَمَا تَتَرَاءَوْنَ الْكَوْكَبَ الدُّرِّيَّ الْغَابِرَ مِنْ الْأُفُقِ مِنْ الْمَشْرِقِ أَوْ الْمَغْرِبِ لِتَفَاضُلِ مَا بَيْنَهُمْ قَالُوا يَا رَسُولَ اللَّهِ تِلْكَ مَنَازِلُ الْأَنْبِيَاءِ لَا يَبْلُغُهَا غَيْرُهُمْ قَالَ بَلَى وَالَّذِي نَفْسِي بِيَدِهِ رِجَالٌ آمَنُوا بِاللَّهِ وَصَدَّقُوا الْمُرْسَلِينَ","id":"Telah menceritakan kepadaku [Abdullah bin Ja'far bin Yahya bin Khalid] telah menceritakan kepada kami [Ma'nu] telah menceritakan kepada kami [Malik]. Telah menceritakan kepadaku [Harun bin Sa'id Al Aili], teks hadits miliknya, telah menceritakan kepada kami [Abdullah bin Wahab] telah mengkhabarkan kepadaku [Malik bin Anas] dari [Shafwan bin Sulaim] dari [Atha` bin Yasar] dari [Abu Sa'id Al Khudri] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya penghuni surga benar-benar melihat penghuni kamar-kamar di atas mereka seperti kalian melihat bintang terang lewat dari ufuk timur atau barat karena perbedaan keutamaan diantara mereka.\" Mereka bertanya: Itu tempat-tempat para nabi yang tidak dicapai oleh selain mereka? Beliau menjawab: \"Tidak, demi Dzat yang jiwaku berada ditanganNya, mereka adalah orang-orang yang beriman kepada Allah dan membenarkan para rasul.\""},"4702":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ أَشَدِّ أُمَّتِي لِي حُبًّا نَاسٌ يَكُونُونَ بَعْدِي يَوَدُّ أَحَدُهُمْ لَوْ رَآنِي بِأَهْلِهِ وَمَالِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Diantara ummatku yang sangat mencintaiku adalah orang-orang sepeninggalku, salah seorang diantara mereka ingin melihatku dengan (mengorbankan) keluargan dan hartanya.\""},"4703":{"ar":"حَدَّثَنَا أَبُو عُثْمَانَ سَعِيدُ بْنُ عَبْدِ الْجَبَّارِ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَسُوقًا يَأْتُونَهَا كُلَّ جُمُعَةٍ فَتَهُبُّ رِيحُ الشَّمَالِ فَتَحْثُو فِي وُجُوهِهِمْ وَثِيَابِهِمْ فَيَزْدَادُونَ حُسْنًا وَجَمَالًا فَيَرْجِعُونَ إِلَى أَهْلِيهِمْ وَقَدْ ازْدَادُوا حُسْنًا وَجَمَالًا فَيَقُولُ لَهُمْ أَهْلُوهُمْ وَاللَّهِ لَقَدْ ازْدَدْتُمْ بَعْدَنَا حُسْنًا وَجَمَالًا فَيَقُولُونَ وَأَنْتُمْ وَاللَّهِ لَقَدْ ازْدَدْتُمْ بَعْدَنَا حُسْنًا وَجَمَالًا","id":"Telah menceritakan kepada kami [Abu Utsman Sa'id bin Abduljabbar Al Bashri] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Anas bin Malik] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada pasar, mereka mendatanginya setiap hari jum'at, angin dari utara berhembus lalu menerpa wajah-wajah mereka dan pakaian-pakaian mereka hingga mereka semakin indah dan menawan. Mereka kembali ke keluarga mereka dengan penampilan yang lebih indah dan menawan, keluarga-keluarga mereka berkata pada mereka: 'Demi Allah, kau semakin indah dan menawan setelah kami.' mereka berkata: 'Kalian juga, demi Allah, lebih indah dan menawan setelah kami.\""},"4704":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ جَمِيعًا عَنْ ابْنِ عُلَيَّةَ وَاللَّفْظُ لِيَعْقُوبَ قَالَا حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنْ مُحَمَّدٍ قَالَإِمَّا تَفَاخَرُوا وَإِمَّا تَذَاكَرُوا الرِّجَالُ فِي الْجَنَّةِ أَكْثَرُ أَمْ النِّسَاءُ فَقَالَ أَبُو هُرَيْرَةَ أَوَ لَمْ يَقُلْ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ زُمْرَةٍ تَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَالَّتِي تَلِيهَا عَلَى أَضْوَإِ كَوْكَبٍ دُرِّيٍّ فِي السَّمَاءِ لِكُلِّ امْرِئٍ مِنْهُمْ زَوْجَتَانِ اثْنَتَانِ يُرَى مُخُّ سُوقِهِمَا مِنْ وَرَاءِ اللَّحْمِ وَمَا فِي الْجَنَّةِ أَعْزَبُحَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ قَالَ اخْتَصَمَ الرِّجَالُ وَالنِّسَاءُ أَيُّهُمْ فِي الْجَنَّةِ أَكْثَرُ فَسَأَلُوا أَبَا هُرَيْرَةَ فَقَالَ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ ابْنِ عُلَيَّةَ","id":"Telah menceritakan kepada kami [Amru An Naqid] dan [Ya'qub bin Ibrahim Ad Dauraqi] semuanya dari [Ibnu Ulaiyah], teks milik Ya'qub, keduanya berkata: Telah menceritakan kepada kami [Isma'il bin Ulaiyah] telah mengkhabarkan kepada kami [Ayub] dari [Muhammad] berkata: Mungkin mereka saling membangga-banggakan diri atau menyebut-nyebut bahwa kaum lelaki lebih banyak disurga dari pada kaum wanita, lalu [Abu Hurairah] berkata: Bukankah Abu Al Qasim Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya golongan pertama yang masuk surga wujudnya seperti bulan di malam purnama, golongan selanjutnya wujudnya seperti bintang paling terang di langit dan setiap lelaki diantara mereka memiliki dua istri, tulang betis keduanya terlihat dari baik daging dan disurga tidak ada orang bujang.\" Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Ayub] dari [Ibnu Sirin] berkata: Kaum lelaki dan perempuan berbantah-bantahan siapa diantara mereka yang terbanyak disurga, mereka bertanya kepada Abu Hurairah lalu ia menjawab: Abu Al Qasim Shallallahu 'alaihi wa Salam bersabda seperti hadits Ibnu Ulaiyah."},"4705":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ حَدَّثَنَا أَبُو زُرْعَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَنْ يَدْخُلُ الْجَنَّةَ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِقُتَيْبَةَ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ زُمْرَةٍ يَدْخُلُونَ الْجَنَّةَ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَالَّذِينَ يَلُونَهُمْ عَلَى أَشَدِّ كَوْكَبٍ دُرِّيٍّ فِي السَّمَاءِ إِضَاءَةً لَا يَبُولُونَ وَلَا يَتَغَوَّطُونَ وَلَا يَمْتَخِطُونَ وَلَا يَتْفُلُونَ أَمْشَاطُهُمْ الذَّهَبُ وَرَشْحُهُمْ الْمِسْكُ وَمَجَامِرُهُمْ الْأَلُوَّةُ وَأَزْوَاجُهُمْ الْحُورُ الْعِينُ أَخْلَاقُهُمْ عَلَى خُلُقِ رَجُلٍ وَاحِدٍ عَلَى صُورَةِ أَبِيهِمْ آدَمَ سِتُّونَ ذِرَاعًا فِي السَّمَاءِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari [Umarah bin Al Qa'qa'] telah menceritakan kepada kami [Abu Zur'ah] berkata: Aku mendengar [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Orang pertama yang masuk surga.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Zuhair bin Harb], teks milik Qutaibah, keduanya berkata: Telah menceritakan kepada kami [Jarir] dari [Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya golongan pertama yang masuk surga wujudnya seperti bulan di malam purnama, golongan selanjutnya wujudnya seperti bintang paling terang di langit, mereka tidak kencing, tidak berak, tidak ingusan dan tidak meludah, sisir mereka emas, keringat mereka minyak kesturi, tempat bara api mereka kayu wangi, istri-istri mereka bidadari, postur mereka sama seperti wujud ayah mereka, Adam, enampuluh dzira' di langit.\""},"4706":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ زُمْرَةٍ تَدْخُلُ الْجَنَّةَ مِنْ أُمَّتِي عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ ثُمَّ الَّذِينَ يَلُونَهُمْ عَلَى أَشَدِّ نَجْمٍ فِي السَّمَاءِ إِضَاءَةً ثُمَّ هُمْ بَعْدَ ذَلِكَ مَنَازِلُ لَا يَتَغَوَّطُونَ وَلَا يَبُولُونَ وَلَا يَمْتَخِطُونَ وَلَا يَبْزُقُونَ أَمْشَاطُهُمْ الذَّهَبُ وَمَجَامِرُهُمْ الْأَلُوَّةُ وَرَشْحُهُمْ الْمِسْكُ أَخْلَاقُهُمْ عَلَى خُلُقِ رَجُلٍ وَاحِدٍ عَلَى طُولِ أَبِيهِمْ آدَمَ سِتُّونَ ذِرَاعًاقَالَ ابْنُ أَبِي شَيْبَةَ عَلَى خُلُقِ رَجُلٍ و قَالَ أَبُو كُرَيْبٍ عَلَى خَلْقِ رَجُلٍ و قَالَ ابْنُ أَبِي شَيْبَةَ عَلَى صُورَةِ أَبِيهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya golongan pertama dari ummatku yang masuk surga wujudnya seperti bulan di malam purnama, golongan selanjutnya wujudnya seperti bintang paling terang di langit, setelah itu mereka bertingkat-tingkat, mereka tidak kencing, tidak berak, dan tidak meludah, sisir mereka emas, tempat bara api mereka kayu wangi dan keringat mereka minyak kesturi, postur mereka sama seperti wujud ayah mereka, Adam, enampuluh dzira'.\" Ibnu Abi Syaibah menyebutkan dalam riwayatnya: Seperti postur satu orang. Abu Kuraib menyebutkan dalam riwayatnya: Seperti postur satu orang. Ibnu Abi Syaibah menyebutkan dalam riwayatnya: Seperti wujud ayah mereka."},"4707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ زُ��ْرَةٍ تَلِجُ الْجَنَّةَ صُوَرُهُمْ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ لَا يَبْصُقُونَ فِيهَا وَلَا يَمْتَخِطُونَ وَلَا يَتَغَوَّطُونَ فِيهَا آنِيَتُهُمْ وَأَمْشَاطُهُمْ مِنْ الذَّهَبِ وَالْفِضَّةِ وَمَجَامِرُهُمْ مِنْ الْأَلُوَّةِ وَرَشْحُهُمْ الْمِسْكُ وَلِكُلِّ وَاحِدٍ مِنْهُمْ زَوْجَتَانِ يُرَى مُخُّ سَاقِهِمَا مِنْ وَرَاءِ اللَّحْمِ مِنْ الْحُسْنِ لَا اخْتِلَافَ بَيْنَهُمْ وَلَا تَبَاغُضَ قُلُوبُهُمْ قَلْبٌ وَاحِدٌ يُسَبِّحُونَ اللَّهَ بُكْرَةً وَعَشِيًّا","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] berkata: Inilah yang diceritakan [Abu Hurairah] kepada kami dari Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut beberapa hadits, diantaranya: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya golongan pertama yang masuk surga wujudnya seperti bulan di malam purnama, mereka tidak meludah tidak ingusan dan tidak berak didalamnya, bejana dan sisir mereka dari emas dan perak, tempat bara api mereka kayu wangi, keringat mereka minyak kesturi, masing-masing dari mereka memiliki dua istri, tulang betis keduanya terlihat dari balik kulit karena keindahannya, tidak ada perselisihan diantara mereka, hati mereka tidak saling benci, hati mereka sama, mereka memahasucikan Allah dipagi dan disore hari.\""},"4708":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِعُثْمَانَ قَالَ عُثْمَانُ حَدَّثَنَا و قَالَ إِسْحَقُ أَخْبَرَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَهْلَ الْجَنَّةِ يَأْكُلُونَ فِيهَا وَيَشْرَبُونَ وَلَا يَتْفُلُونَ وَلَا يَبُولُونَ وَلَا يَتَغَوَّطُونَ وَلَا يَمْتَخِطُونَ قَالُوا فَمَا بَالُ الطَّعَامِ قَالَ جُشَاءٌ وَرَشْحٌ كَرَشْحِ الْمِسْكِ يُلْهَمُونَ التَّسْبِيحَ وَالتَّحْمِيدَ كَمَا تُلْهَمُونَ النَّفَسَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ كَرَشْحِ الْمِسْكِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], teks milik Utsman. Berkata Utsman: telah menceritakan kepada kami, sedangkan Ishaq berkata: Telah mengkhabarkan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya penghuni surga makan dan minum didalamnya, mereka tidak meludah, tidak kencing, tidak berak dan tidak ingusan.\" Mereka bertanya: Bagaimana dengan makanannya? Beliau menjawab: \"Sendawa dan keringat seperti keringat minyak kesturi, mereka diilhami tasbih dan tahmid seperti kalian diilhami nafas.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dengan sanad ini hingga sabda beliau: \"Seperti keringat minyak kesturi.\""},"4709":{"ar":"و حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَحَجَّاجُ بْنُ الشَّاعِرِ كِلَاهُمَا عَنْ أَبِي عَاصِمٍ قَالَ حَسَنٌ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ أَهْلُ الْجَنَّةِ فِيهَا وَيَشْرَبُونَ وَلَا يَتَغَوَّطُونَ وَلَا يَمْتَخِطُونَ وَلَا يَبُولُونَ وَلَكِنْ طَعَامُهُمْ ذَاكَ جُشَاءٌ كَرَشْحِ الْمِسْكِ يُلْهَمُونَ التَّسْبِيحَ وَالْحَمْدَ كَمَا تُلْهَمُونَ النَّفَسَقَالَ وَفِي حَدِيثِ حَجَّاجٍ طَعَامُهُمْ ذَلِكَ و حَدَّثَنِي سَعِيدُ بْنُ يَحْيَى الْأُمَوِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ وَيُلْهَمُونَ التَّسْبِيحَ وَالتَّكْبِيرَ كَمَا تُلْهَمُونَ النَّفَسَ","id":"Telah menceritakan kepadaku [Al Hasan bin Ali Al Hulwani] dan [Hajjaj bin Asy Sya'ir] keduanya dari [Abu Ashim] berkata [Hasan]: telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] telah mengkhabarkan kepadaku [Abu Az Zubair] ia mendengar [Jabir bin Abdullah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Penghuni surga makan dan minum didalamnya, mereka berak, tidak ingusan dan tidak kencing, tapi makanan mereka itu (menjadi) sendawa, keringat seperti keringat minyak kesturi, mereka diilami tasbih dan tahmid seperti kalian diilhami nafas.\" Ia berkata: Disebutkan dalam hadits Hajjaj: Makanan mereka itu. Telah menceritakan kepadaku [Sa'id bin Yahya Al Umawi] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Abu Az Zubair] dari [Jabir] dari nabi Shallallahu 'alaihi wa Salam sepertinya, hanya saja ia menyebutkan: Mereka diilami tasbih dan takbir seperti kalian diilhami nafas.\""},"4710":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَدْخُلُ الْجَنَّةَ يَنْعَمُ لَا يَبْأَسُ لَا تَبْلَى ثِيَابُهُ وَلَا يَفْنَى شَبَابُهُ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit bin Abu Rafi'] dari [Abu Rafi'] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa masuk surga, ia bersenang-senang dan tidak bersedih, pakaiannya tidak usang dan kemudaannya tidak lenyap.\""},"4711":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِإِسْحَقَ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ قَالَ الثَّوْرِيُّ فَحَدَّثَنِي أَبُو إِسْحَقَ أَنَّ الْأَغَرَّ حَدَّثَهُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُنَادِي مُنَادٍ إِنَّ لَكُمْ أَنْ تَصِحُّوا فَلَا تَسْقَمُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَحْيَوْا فَلَا تَمُوتُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَشِبُّوا فَلَا تَهْرَمُوا أَبَدًا وَإِنَّ لَكُمْ أَنْ تَنْعَمُوا فَلَا تَبْأَسُوا أَبَدًا فَذَلِكَ قَوْلُهُ عَزَّ وَجَلَّ{ وَنُودُوا أَنْ تِلْكُمْ الْجَنَّةُ أُورِثْتُمُوهَا بِمَا كُنْتُمْ تَعْمَلُونَ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abdu bin Humaid], teks milik Ishaq, keduanya berkata: telah mengkhabarkan kepada kami [Abdurrazzaq] berkata: Berkata [Ats Tsauri] telah menceritakan kepadaku [Abu Ishaq] bahwa [Al Aghar] telah menceritakan kepadanya dari [Abu Sa'id Al Khudri] dan [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Penyeru menyerukan: Sesungguhnya kalian hidup dan tidak mati selamanya, kalian sehat dan tidak sakit selamanya, kalian muda dan tidak tua selamanya, kalian bersenang-senang dan tidak akan bersedih selamanya. Itulah firmanNya 'azza wajalla:; Dan Itulah surga yang diwariskan kepada kamu disebabkan amal-amal yang dahulu kamu kerjakan.\" (Az Zukhruuf: 72) "},"4712":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ عَنْ أَبِي قُدَامَةَ وَهُوَ الْحَارِثُ بْنُ عُبَيْدٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلْمُؤْمِنِ فِي الْجَنَّةِ لَخَيْمَةً مِنْ لُؤْلُؤَةٍ وَاحِدَةٍ مُجَوَّفَةٍ طُولُهَا سِتُّونَ مِيلًا لِلْمُؤْمِنِ فِيهَا أَهْلُونَ يَطُوفُ عَلَيْهِمْ الْمُؤْمِنُ فَلَا يَرَى بَعْضُهُمْ بَعْضًا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dari [Abu Qudamah Al Harits bin Ubaid] dari [Abu Imran Al Juwaini] dari [Abu Bakr bin Abdullah bin Qais] dari [ayahnya] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya orang mu`min disurga memiliki tenda dari satu mutiara berlubang, panjangnya enampuluh mil. Orang mu`min memiliki keluarga didalamnya. Orang mu`min mengelilingi mereka tapi mereka tidak saling melihat satu sama lain.\""},"4713":{"ar":"و حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْجَنَّةِ خَيْمَةٌ مِنْ لُؤْلُؤَةٍ مُجَوَّفَةٍ عَرْضُهَا سِتُّونَ مِيلًا فِي كُلِّ زَاوِيَةٍ مِنْهَا أَهْلٌ مَا يَرَوْنَ الْآخَرِينَ يَطُوفُ عَلَيْهِمْ الْمُؤْمِنُ","id":"Telah menceritakan kepadaku [Abu Ghassan Al Misma'i] telah menceritakan kepada kami [Abu Abdushshamad] telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Abu Bakr bin Abdullah bin Qais] dari [ayahnya] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya disurga ada tenda dari mutiara berlubang, lebarnya enampuluh mil. Setiap sudutnya ada keluarga, mereka tidak melihat yang lain, orang mu`min mengelilingi mereka.\""},"4714":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى بْنِ قَيْسٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْمَةُ دُرَّةٌ طُولُهَا فِي السَّمَاءِ سِتُّونَ مِيلًا فِي كُلِّ زَاوِيَةٍ مِنْهَا أَهْلٌ لِلْمُؤْمِنِ لَا يَرَاهُمْ الْآخَرُونَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Hammam] dari [Abu Imran Al Juwaini] dari [Abu Bakr bin Abu Musa bin Qais] dari [ayahnya] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Kemah mutiara, panjangnya dilangit enampuluh mil, setiap sudutnya ada keluarga milik orang mu`min, yang lain tidak bisa melihat mereka.\""},"4715":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَعَلِيُّ بْنُ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيْحَانُ وَجَيْحَانُ وَالْفُرَاتُ وَالنِّيلُ كُلٌّ مِنْ أَنْهَارِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah], [Abdullah bin Numair] dan [Ali bin Mushir] dari [Ubaidulah bin Umar]. Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Ubaidullah] dari [Khabab bin Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saihan, Jaihan, Furat dan Nil semuanya termasuk sungai-sungai surga.\""},"4716":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ اللَّيْثِيُّ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنَا أَبِي عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ الْجَنَّةَ أَقْوَامٌ أَفْئِدَتُهُمْ مِثْلُ أَفْئِدَةِ الطَّيْرِ","id":"Telah menceritakan kepada kami [Hajjaj bin Asy Sya'ir] telah menceritakan kepada kami [Abu An Nadhr bin Al Qasim Al Laitsi] telah menceritakan kepada kami [Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Abu Salamah] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Beberapa kaum masuk surga, hati mereka seperti hati burung.\""},"4717":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا بِهِ أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَ��َرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَقَ اللَّهُ عَزَّ وَجَلَّ آدَمَ عَلَى صُورَتِهِ طُولُهُ سِتُّونَ ذِرَاعًا فَلَمَّا خَلَقَهُ قَالَ اذْهَبْ فَسَلِّمْ عَلَى أُولَئِكَ النَّفَرِ وَهُمْ نَفَرٌ مِنْ الْمَلَائِكَةِ جُلُوسٌ فَاسْتَمِعْ مَا يُجِيبُونَكَ فَإِنَّهَا تَحِيَّتُكَ وَتَحِيَّةُ ذُرِّيَّتِكَ قَالَ فَذَهَبَ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَالُوا السَّلَامُ عَلَيْكَ وَرَحْمَةُ اللَّهِ قَالَ فَزَادُوهُ وَرَحْمَةُ اللَّهِ قَالَ فَكُلُّ مَنْ يَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ آدَمَ وَطُولُهُ سِتُّونَ ذِرَاعًا فَلَمْ يَزَلْ الْخَلْقُ يَنْقُصُ بَعْدَهُ حَتَّى الْآنَ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] berkata: Inilah yang diceritakan oleh [Abu Hurairah] kepada kami dari Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut beberapa hadits diantaranya: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah 'azza wajalla menciptakan Adam seperti wujudnya, panjangnya enampuluh dzira'. Setelah menciptakannya, Allah berfirman: 'Pergilah lalu ucapkan salam pada mereka itu, mereka adalah kelompok malaikat yang tengah duduk lalu dengarkan jawaban mereka, itulah salammu dan salam keturunanmu.\" Beliau bersabda: \"Adam pergi lalu mengucapkan: 'ASSLAAMU'ALAIKUM? ' Mereka menjawab: 'ASSALAAMU 'ALAIKA WA RAHMATULLAAH'.\" Beliau bersabda: \"Mereka menambahi: 'WA RAHMATULLAAH'.\" Beliau bersabda: \"Setiap orang yang masuk surga wujudnya seperti Adam, panjangnya enampuluh dzira' dan setelahnya (Adam) postur tubuh (manusia) terus berkurang hingga sekarang.\""},"4718":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ الْعَلَاءِ بْنِ خَالِدٍ الْكَاهِلِيِّ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِجَهَنَّمَ يَوْمَئِذٍ لَهَا سَبْعُونَ أَلْفَ زِمَامٍ مَعَ كُلِّ زِمَامٍ سَبْعُونَ أَلْفَ مَلَكٍ يَجُرُّونَهَا","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [ayahku] dari [Al Ala` bin Khalid Al Kahili] dari [Syaqiq] dari [Abdullah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada hari itu neraka jahannam didatangkan, ia mempunyai tujuh puluh ribu tali kekang, setiap tali kekang terdapat tujuh puluh ribu malaikat yang akan menyeretnya.\""},"4719":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَارُكُمْ هَذِهِ الَّتِي يُوقِدُ ابْنُ آدَمَ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ حَرِّ جَهَنَّمَ قَالُوا وَاللَّهِ إِنْ كَانَتْ لَكَافِيَةً يَا رَسُولَ اللَّهِ قَالَ فَإِنَّهَا فُضِّلَتْ عَلَيْهَا بِتِسْعَةٍ وَسِتِّينَ جُزْءًا كُلُّهَا مِثْلُ حَرِّهَاحَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي الزِّنَادِ غَيْرَ أَنَّهُ قَالَ كُلُّهُنَّ مِثْلُ حَرِّهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman Al Hizami] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] nabi Shallallahu 'alaihi wa Salam bersabda: \"Api kalian ini yang dinyalakan oleh anak cucu Adam adalah satu dari tujuh puluh bagian panasnya neraka jahanam.\" Mereka berkata: Bila seperti itu niscaya sudah cukup wahai Rasulullah. beliau bersabda: \"Sesungguhnya ditambahi enampuluh sembilan bagian, masing-masing seperti panasnya.\" Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam seperti hadits Abu Az ZInad, hanya saja ia menyebutkan dalam riwayatnya: Semuannya seperti panasnya."},"4720":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ سَمِعَ وَجْبَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَدْرُونَ مَا هَذَا قَالَ قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ هَذَا حَجَرٌ رُمِيَ بِهِ فِي النَّارِ مُنْذُ سَبْعِينَ خَرِيفًا فَهُوَ يَهْوِي فِي النَّارِ الْآنَ حَتَّى انْتَهَى إِلَى قَعْرِهَاو حَدَّثَنَاه مُحَمَّدُ بْنُ عَبَّادٍ وَابْنُ أَبِي عُمَرَ قَالَا حَدَّثَنَا مَرْوَانُ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ بِهَذَا الْإِسْنَادِ وَقَالَ هَذَا وَقَعَ فِي أَسْفَلِهَا فَسَمِعْتُمْ وَجْبَتَهَا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Khalaf bin Khalifah] telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] berkata: Kami bersama nabi Shallallahu 'alaihi wa Salam tiba-tiba beliau mendengar suara sesuatu yang jatuh berdebuk, nabi Shallallahu 'alaihi wa Salam bertanya: \"Tahukah kalian apa itu?\" kami menjawab: Allah dan rasulNya lebih tahu. Beliau bersabda: \"Itu adalah batu yang dilemparkan ke neraka sejak tujuhpuluh tahun, ia jatuh ke neraka sekarang hingga mencapai keraknya.\" Telah menceritakannya kepada kami [Muhammad bin Abbad] dan [Ibnu Abi Umar] keduanya berkata: Telah menceritakan kepada kami [Marwan] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] dengan sanad ini, ia berkata: \"Ia (batu) jatuh ke paling bawahnya lalu kalian mendengar debukannya.\""},"4721":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ قَالَ قَتَادَةُ سَمِعْتَ أَبَا نَضْرَةَ يُحَدِّثُ عَنْ سَمُرَةَأَنَّهُ سَمِعَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْهُمْ مَنْ تَأْخُذُهُ النَّارُ إِلَى كَعْبَيْهِ وَمِنْهُمْ مَنْ تَأْخُذُهُ إِلَى حُجْزَتِهِ وَمِنْهُمْ مَنْ تَأْخُذُهُ إِلَى عُنُقِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban bin Abdurrahman] berkata: Berkata [Qatadah]: Aku mendengar [Abu An Nadhrah] menceritakan dari [Samurah], ia mendengar nabi Allah bersabda: \"Sesungguhnya diantara mereka ada yang terkena api neraka hingga mata kakinya, ada yang terkena api neraka hingga tempat ikat pinggang dan ada yang terkena api neraka hingga leher.\""},"4722":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ يَعْنِي ابْنَ عَطَاءٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا نَضْرَةَ يُحَدِّثُ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْهُمْ مَنْ تَأْخُذُهُ النَّارُ إِلَى كَعْبَيْهِ وَمِنْهُمْ مَنْ تَأْخُذُهُ النَّارُ إِلَى رُكْبَتَيْهِ وَمِنْهُمْ مَنْ تَأْخُذُهُ النَّارُ إِلَى حُجْزَتِهِ وَمِنْهُمْ مَنْ تَأْخُذُهُ النَّارُ إِلَى تَرْقُوَتِهِحَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدٌ بِهَذَا الْإِسْنَادِ وَجَعَلَ مَكَانَ حُجْزَتِهِ حِقْوَيْهِ","id":"Telah menceritakan kepada kami [Amru bin Zurarah] telah mengkhabarkan kepada kami [Abdulwahab bin Atha`] dari [Sa'id] dari [Qatadah] berkata: Aku mendengar [Abu Nadhrah] menceritakan dari [Samurah bin Jundub] nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya diantara mereka ada yang terkena api neraka hingga mata kakinya, ada yang terkena api neraka hingga lutut, ada yang terkena api neraka hingga tempat ikat pinggang dan ada yang terkena api neraka hingga tulang selangka.\" Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata: Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Sa'id] dengan sanad ini, ia mengganti HUJZATIHI (tempat pengikat pinggang) dengan HIQWAIHI (pinggang)."},"4723":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنِي وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَحَاجَّتْ النَّارُ وَالْجَنَّةُ فَقَالَتْ النَّارُ أُوثِرْتُ بِالْمُتَكَبِّرِينَ وَالْمُتَجَبِّرِينَ وَقَالَتْ الْجَنَّةُ فَمَا لِي لَا يَدْخُلُنِي إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ وَعَجَزُهُمْ فَقَالَ اللَّهُ لِلْجَنَّةِ أَنْتِ رَحْمَتِي أَرْحَمُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَقَالَ لِلنَّارِ أَنْتِ عَذَابِي أُعَذِّبُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَلِكُلِّ وَاحِدَةٍ مِنْكُمْ مِلْؤُهَا فَأَمَّا النَّارُ فَلَا تَمْتَلِئُ فَيَضَعُ قَدَمَهُ عَلَيْهَا فَتَقُولُ قَطْ قَطْ فَهُنَالِكَ تَمْتَلِئُ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ الْهِلَالِيُّ حَدَّثَنَا أَبُو سُفْيَانَ يَعْنِي مُحَمَّدَ بْنَ حُمَيْدٍ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّتْ الْجَنَّةُ وَالنَّارُ وَاقْتَصَّ الْحَدِيثَ بِمَعْنَى حَدِيثِ أَبِي الزِّنَادِ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Syababah] telah menceritakan kepadaku [Warqa`] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Surga dan neraka berbantah-bantahan. Neraka berkata: 'Orang-orang congkak dan sombong memasukiku. Surga berkata: Sedangkan aku, tidak ada yang memasukiku selain orang-orang lemah, tidak berguna dan tidak berkuasa. Lalu Allah berfirman kepada surga: 'Kau adalah rahmatKu, denganmu Aku merahmati siapa saja yang Aku kehendaki dari hamba-hambaKu.' Kemudian Allah berfirman kepada neraka: 'Kau adalah siksaKu, denganmu Aku menyiksa siapa pun yang Aku kehendaki dan masing-masing dari kalian berdua berisi penuh.' Sedangkan neraka tidak terisi penuh, lalu Allah meletakkan kakiNya kemudian neraka berkata: 'Cukup, cukup.' Saat itu neraka penuh dan sebagaiannya dihimpun pada sebagian yang lain.\" Telah menceritakan kepada kami [Abdullah bin Aun Al Hilali] telah menceritakan kepada kami [Abu Sufyan Muhammad bin Humaid] dari [Ma'mar] dari [Ayyub] dari [Ibnu Sirin] dari [Abu Hurairah] nabi Shallallahu 'alaihi wa Salam bersabda: \"Surga dan neraka berbantah-bantahan, \" ia menceritakan hadits yang semakna dengan hadits Abu Az Zinad."},"4724":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحَاجَّتْ الْجَنَّةُ وَالنَّارُ فَقَالَتْ النَّارُ أُوثِرْتُ بِالْمُتَكَبِّرِينَ وَالْمُتَجَبِّرِينَ وَقَالَتْ الْجَنَّةُ فَمَا لِي لَا يَدْخُلُنِي إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ وَغِرَّتُهُمْ قَالَ اللَّهُ لِلْجَنَّةِ إِنَّمَا أَنْتِ رَحْمَتِي أَرْحَمُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَقَالَ لِلنَّارِ إِنَّمَا أَنْتِ عَذَابِي أُعَذِّبُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَلِكُلِّ وَاحِدَةٍ مِنْكُمَا مِلْؤُهَا فَأَمَّا النَّارُ فَلَا تَمْتَلِئُ حَتَّى يَضَعَ اللَّهُ تَبَارَكَ وَتَعَالَى رِجْلَهُ تَقُولُ قَطْ قَطْ قَطْ فَهُنَالِكَ تَمْتَلِئُ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍ وَلَا يَظْلِمُ اللَّهُ مِنْ خَلْقِهِ أَحَدًا وَأَمَّا الْجَنَّةُ فَإِنَّ اللَّهَ يُنْشِئُ لَهَا خَلْقًاو حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِ��ِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَّتْ الْجَنَّةُ وَالنَّارُ فَذَكَرَ نَحْوَ حَدِيثِ أَبِي هُرَيْرَةَ إِلَى قَوْلِهِ وَلِكِلَيْكُمَا عَلَيَّ مِلْؤُهَا وَلَمْ ��َذْكُرْ مَا بَعْدَهُ مِنْ الزِّيَادَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] berkata: Inilah yang diceritakan [Abu Hurairah] kepada kami dari Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut beberapa hadits, diantaranya: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Surga dan neraka berbantah-bantahan. Neraka berkata: 'Orang-orang congkak dan sombong memasukiku. Surga berkata: Sedangkan aku, tidak ada yang memasukiku selain orang-orang lemah, tidak berguna dan budak. Lalu Allah berfirman kepada surga: 'Kau adalah rahmatKu, denganmu Aku merahmati siapa saja yang Aku kehendaki dari hamba-hambaKu.' Kemudian Allah berfirman kepada neraka: 'Kau adalah siksaKu, denganmu Aku menyiksa siapa pun yang Aku kehendaki dan masing-masing dari kalian berdua berisi penuh.' Sedangkan neraka tidak terisi penuh, lalu Allah meletakkan kakiNya kemudian neraka berkata: 'Cukup, cukup, cukup.' Saat itu neraka penuh dan sebagaiannya dihimpun pada sebagaian yang lain dan Allah tidak menzhalimi seorang pun dari makhlukNya. Sedangkan surga, Allah menciptakan penghuninya.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Surga dan neraka berbantah-bantahan, \" ia menyebut seperti hadits Abu Hurairah hingga sabda beliau: \"Masing-masing dari kalian berdua wajib Aku penuhi\" dan tidak menyebut tambahan setelahnya."},"4725":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ جَهَنَّمُ تَقُولُ هَلْ مِنْ مَزِيدٍ حَتَّى يَضَعَ فِيهَا رَبُّ الْعِزَّةِ تَبَارَكَ وَتَعَالَى قَدَمَهُ فَتَقُولُ قَطْ قَطْ وَعِزَّتِكَ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارِ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ شَيْبَانَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik] nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Neraka jahanam selalu berkata: 'Masih adakah tambahan? ' hingga Rabb pemilik keagungan Tabaraka wa Ta'ala meletakkan kakiNya lalu neraka berkata: 'Cukup, cukuip, demi keagunganMu.' Sebagaiannya dihimpun pada sebagaian yang lain.\" Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdushshamad bin Abdulwarits] telah menceritakan kepada kami [Aban bin Yazid Al Aththar] telah menceritakan kepada kami [Qatadah] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam seperti makna hadits Syaiban."},"4726":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ أَخْبَرَنَا ثَابِتٌ قَالَ سَمِعْتُ أَنَسًا يَقُولُاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَبْقَى مِنْ الْجَنَّةِ مَا شَاءَ اللَّهُ أَنْ يَبْقَى ثُمَّ يُنْشِئُ اللَّهُ تَعَالَى لَهَا خَلْقًا مِمَّا يَشَاءُ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengkhabarkan kepada kami [Tsabit] berkata: Aku mendengar [Anas] berkata: Dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Surga tersisa seperti yang dikehendaki Allah kemudian Allah menciptakan makhluk untuknya dari sesuatu yang Ia kehendaki.\""},"4727":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَتَقَارَبَا فِي اللَّفْظِ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاءُ بِالْمَوْتِ يَوْمَ الْقِيَامَةِ كَأَنَّهُ كَبْشٌ أَمْلَحُ زَادَ أَبُو كُرَيْبٍ فَيُوقَفُ بَيْنَ الْجَنَّةِ وَالنَّارِ وَاتَّفَقَا فِي بَاقِي الْحَدِيثِ فَيُقَالُ يَا أَهْلَ الْجَنَّةِ هَلْ تَعْرِفُونَ هَذَا فَيَشْرَئِبُّونَ وَيَنْظُرُونَ وَيَقُولُونَ نَعَمْ هَذَا الْمَوْتُ قَالَ وَيُقَالُ يَا أَهْلَ النَّارِ هَلْ تَعْرِفُونَ هَذَا قَالَ فَيَشْرَئِبُّونَ وَيَنْظُرُونَ وَيَقُولُونَ نَعَمْ هَذَا الْمَوْتُ قَالَ فَيُؤْمَرُ بِهِ فَيُذْبَحُ قَالَ ثُمَّ يُقَالُ يَا أَهْلَ الْجَنَّةِ خُلُودٌ فَلَا مَوْتَ وَيَا أَهْلَ النَّارِ خُلُودٌ فَلَا مَوْتَ قَالَ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَأَنْذِرْهُمْ يَوْمَ الْحَسْرَةِ إِذْ قُضِيَ الْأَمْرُ وَهُمْ فِي غَفْلَةٍ وَهُمْ لَا يُؤْمِنُونَ }وَأَشَارَ بِيَدِهِ إِلَى الدُّنْيَاحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُدْخِلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ قِيلَ يَا أَهْلَ الْجَنَّةِ ثُمَّ ذَكَرَ بِمَعْنَى حَدِيثِ أَبِي مُعَاوِيَةَ غَيْرَ أَنَّهُ قَالَ فَذَلِكَ قَوْلُهُ عَزَّ وَجَلَّ وَلَمْ يَقُلْ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ أَيْضًا وَأَشَارَ بِيَدِهِ إِلَى الدُّنْيَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib], teksnya hampir sama, keduanya berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kematian didatangkan pada hari kiamat seperti kambing kelabu -Abu Kuraib menambahkan: Lalu didirikan diantara surga dan nerakah, sedangkan keseluruhan hadits berikutnya sama- kemudian dikatakan: Wahai penduduk surga, apa kalian mengetahui ini? Mereka melihat dengan mendongak, mereka menjawab: 'Ya, itu adalah kematian.' Kematian dibaringkan lalu disembelih kemudian dikatakan kepada penduduk neraka: 'Wahai penghuni neraka, apa kalian mengetahui ini? ' Mereka melihat dengan mendongak, mereka menjawab: 'Ya, ' itu adalah kematian'.\" Beliau bersabda: \"Lalu kematian diperintahkan disembelih, setelah itu dikatakan: 'Wahai penduduk surga, kekal tidak ada ada kematian dan wahai penduduk neraka, kekal tidak ada kematian'.\" Setelah itu beliau membaca: \"Dan berilah mereka peringatan tentang hari penyesalan, (yaitu) ketika segala perkara telah diputus dan mereka dalam kelalaian dan mereka tidak (pula) beriman.\" (Maryam: 39) beliau menunjuk tangan beliau ke dunia. Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila penduduk surga dimasukkan surga dan penduduk neraka dimasukkan neraka, dikatakan: 'Wahai penduduk surga, \" lalu ia menyebut seperti makna hadits Abu Mu'aiwyah, hanya saja ia menyebutkan: Itulah firman Allah 'azza wajalla, tidak menyebut: Setelah itu Rasulullah Shallallahu 'alaihi wa Salam membaca, ia juga tidak menyebut: Beliau menunjuk tangan beliau ke dunia."},"4728":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدِ بْنِ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَارَ أَهْلُ الْجَنَّةِ إِلَى الْجَنَّةِ وَصَارَ أَهْلُ النَّارِ إِلَى النَّارِ أُتِيَ بِالْمَوْتِ حَتَّى يُجْعَلَ بَيْنَ الْجَنَّةِ وَالنَّارِ ثُمَّ يُذْبَحُ ثُمَّ يُنَادِي مُنَادٍ يَا أَهْلَ الْجَنَّةِ لَا مَوْتَ وَيَا أَهْلَ النَّارِ لَا مَوْتَ فَيَزْدَادُ أَهْلُ الْجَنَّةِ فَرَحًا إِلَى فَرَحِهِمْ وَيَزْدَادُ أَهْلُ النَّارِ حُزْنًا إِلَى حُزْنِهِمْ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] dan [Harmalah bin Yahya] keduanya berkata: Telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Umar bin Muhammad bin Zaid bin Abdullah bin Umar bin Al Khathtahab] bahwa [bapaknya] telah menceritakan kepadanya dari [Abdullah bin Umar] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila penghuni surga menempati surga dan penghuni neraka menempati neraka, kematian didatangkan hingga diletakkan diantara surga dan neraka, setelah itu disembelih lalu penyeru menyerukan: 'Wahai penghuni surga, tidak ada kematian dan wahai penghuni neraka, tidak ada kematian.' Penghuni surga semakin senang dan penghuni neraka semakin sedih'.\""},"4729":{"ar":"حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ هَارُونَ بْنِ سَعْدٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضِرْسُ الْكَافِرِ أَوْ نَابُ الْكَافِرِ مِثْلُ أُحُدٍ وَغِلَظُ جِلْدِهِ مَسِيرَةُ ثَلَاثٍ","id":"Telah menceritakan kepadaku [Suraij bin Yunus] telah menceritakan kepada kami [Humaid bin Abdurrahman] dari [Al Hasan bin Shalih] dari [Harun bin Sa'ad] dari [Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Gigi geraham orang kafir atau gigi taring orang kafir seperti gunung Uhud dan tebalnya kulit orang kafir sejauh perjalanan tiga (hari).\" "},"4730":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَأَحْمَدُ بْنُ عُمَرَ الْوَكِيعِيُّ قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَيَرْفَعُهُ قَالَ مَا بَيْنَ مَنْكِبَيْ الْكَافِرِ فِي النَّارِ مَسِيرَةُ ثَلَاثَةِ أَيَّامٍ لِلرَّاكِبِ الْمُسْرِعِوَلَمْ يَذْكُرْ الْوَكِيعِيُّ فِي النَّارِ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Ahmad bin Umar Al Waki'i] berkata: Telah menceritakan kepada kami [Ibnu Fudhail] dari [ayahnya] dari [Abu Hazim] dari [Abu Hurairah] ia memarfu'kan hadits ini, ia berkata: Di neraka jarak antara kedua pundak orang kafir ialah sejauh tiga hari perjalanan seorang penunggang yang menunggangi kendaraannya dengan cepat.\" Al Waki'I tidak menyebutkan: \"Di neraka.\""},"4731":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ كُلُّ جَوَّاظٍ زَنِيمٍ مُتَكَبِّرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] berkata: Aku mendengar [Haritsah bin Wahab Al Khuza'i] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Maukah kalian aku beritahu penghuni surga? Setiap orang lemah dan diperlemah. Andai ia telah bersumpah atas nama Allah pasti Allah akan menunaikannya. Maukah kalian aku beritahu penghuni neraka? Setiap orang congkak, hina dan sombong.\" "},"4732":{"ar":"حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُبَّ أَشْعَثَ مَدْفُوعٍ بِالْأَبْوَابِ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ","id":"Telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepadaku [Hafsh bin Maisarah] dari [Al Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Berapa banyak orang kusut dan tertolak dipintu-pintu yang seandainya bersumpah atas nama Allah, pasti Allah tunaikan.\""},"4733":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا مُوسَى بْنُ أَعْيَنَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أُسَامَةَ كُلُّهُمْ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ وَاللَّفْظُ لَهُ حَدّ��ثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا قَيْسٌ قَالَ سَمِعْتُ مُسْتَوْرِدًا أَخَا بَنِي فِهْرٍ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا الدُّنْيَا فِي الْآخِرَةِ إِلَّا مِثْلُ مَا يَجْعَلُ أَحَدُكُمْ إِصْبَعَهُ هَذِهِوَأَشَارَ يَحْيَى بِالسَّبَّابَةِ فِي الْيَمِّ فَلْيَنْظُرْ بِمَ تَرْجِعُ وَفِي حَدِيثِهِمْ جَمِيعًا غَيْرَ يَحْيَى سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَلِكَ وَفِي حَدِيثِ أَبِي أُسَامَةَ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ أَخِي بَنِي فِهْرٍ وَفِي حَدِيثِهِ أَيْضًا قَالَ وَأَشَارَ إِسْمَعِيلُ بِالْإِبْهَامِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris]. Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku] dan [Muhammad bin Bisyr]. Telah menceritakan kepada kami [Yahya bin Yahya] telah mengkhabarkan kepada kami [Musa bin A'yan]. Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Usamah], semuanya dari [Isma'il bin Abu Khalid]. Telah menceritakan kepadaku [Muhammad bin Hatim], teks miliknya, telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Qais] berkata: Aku mendengar [Mustaurid] salah seorang dari bani Fihr berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Demi Allah, tidaklah dunia di akhirat kecuali seperti sesuatu yang dijadikan oleh jari salah seorang dari kalian -Yahya berisyarat dengan jari telunjuk di laut- maka perhatikanlah apa yang dibawa.\" Disebutkan dalam mereka semua selain Yahya: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Itu.\" Disebutkan dalam hadits Abu Usamah dari Al Mustaurad bin Syaddad dari bani Firh, juga dalam haditsnya disebutkan: Rasulullah Shallallahu 'alaihi wa Salam bersabda dan Isma'il berisyarat dengan jari jempol."},"4734":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حَاتِمِ بْنِ أَبِي صَغِيرَةَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ حُفَاةً عُرَاةً غُرْلًا قُلْتُ يَا رَسُولَ اللَّهِ النِّسَاءُ وَالرِّجَالُ جَمِيعًا يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ الْأَمْرُ أَشَدُّ مِنْ أَنْ يَنْظُرَ بَعْضُهُمْ إِلَى بَعْضٍو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَاتِمِ بْنِ أَبِي صَغِيرَةَ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ فِي حَدِيثِهِ غُرْلًا","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hatim bin Abu Shaghirah] telah menceritakan kepadaku [Ibnu Abi Malikah] dari [Al Qasim bin Muhammad] dari [Aisyah] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Manusia dikumpulkan pada hari kiamat dalam keadaan tidak beralas kaki, telanjang dan kulup.\" Aku bertanya: Wahai Rasulullah, wanita-wanita dan lelaki-lelaki semua saling melihat satu sama lain? Beliau menjawab: \"Wahai Aisyah, permasalahnnya lebih sulit dari saling melihat satu sama lain.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Numair] keduanya berkata: Telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Hatim bin Abu Shaghirah] dengan sanad ini dan ia tidak menyebutkan dalam haditsnya: Kulup."},"4735":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَهُوَ يَقُولُ إِنَّكُمْ مُلَاقُو اللَّهِ مُشَاةً حُفَاةً عُرَاةً غُرْلًاوَلَمْ يَذْكُرْ زُهَيْرٌ فِي حَدِيثِهِ يَخْطُبُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], [Zuhair bin Harb], [Ishaq bin Ibrahim] dan [Ibnu Abi Umar], berkata [Ishaq]: telah mengkhabarkan kepada kami, sementara yang lain berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia mendengar nabi Shallallahu 'alaihi wa Salam berkhutbah, beliau bersabda: \"Sesungguhnya kalian akan menemui Allah dengan berjalan kaki, tidak beralas kaki, telanjang dan kulup.\" Zuhair tidak menyebutkan dalam haditsnya: Berkhutbah."},"4736":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي كِلَاهُمَا عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا بِمَوْعِظَةٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تُحْشَرُونَ إِلَى اللَّهِ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }أَلَا وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ عَلَيْهِ السَّلَام أَلَا وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ فَلَمَّا تَوَفَّيْتَنِي كُنْتَ أَنْتَ الرَّقِيبَ عَلَيْهِمْ وَأَنْتَ عَلَى كُلِّ شَيْءٍ شَهِيدٌ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }قَالَ فَيُقَالُ لِي إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْوَفِي حَدِيثِ وَكِيعٍ وَمُعَاذٍ فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki']. Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku], keduanya dari [Syu'bah]. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar], teks milik Ibnu Al Mutsanna, keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri berkhutbah menyampaikan suatu nasehat ditengah-tengah kami, beliau bersabda: \"Wahai sekalian manusia, sesungguhnya kalian dikumpulkan menuju Allah dalam keadaan tidak beralas kaki, telanjang dan kulup 'Sebagaimana Kami telah memulai panciptaan pertama begitulah kami akan mengulanginya. Itulah suatu janji yang pasti kami tepati; Sesungguhnya kamilah yang akan melaksanakannya.' (Al Anbiyaa`: 104) Ingat, sesungguhnya makhluk pertama yang diberi pakaian pada hari kiamat adalah Ibrahim 'alaihis salaam. Ingat, sesungguhnya beberapa orang dari ummatku akan didatangkan lalu mereka diambil ke golongan kiri, aku berkata: 'Wahai Rabb, sahabat-sahabatku.' Dikatakan: 'Sesungguhnya engkau tidak tahu apa yang mereka buat-buat sepeninggalmu.' Lalu aku mengucapkan seperti perkataan seorang hamba shalih: 'Aku menjadi saksi atas mereka selagi aku bersama mereka namun tatkala Engkau wafatkan aku, Engkaulah yang mengawasi mereka dan Engkau Maha menyaksikan terhadap segala sesuatu. Jika Engkau siksa mereka maka sesungguhnya mereka adalah hambaMu.' (Al Maa`idah: 117-118) lalu dijawab: Mereka senantiasa kembali ke belakang (murtad) sejak kau tinggalkan mereka.\" Disebutkan dalam hadits Waki' dan Mu'adz: Lalu dikatakan: \"Sesungguhnya kau tidak tahu apa yang mereka buat-buat sepeninggalmu.\""},"4737":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ قَالَا جَمِيعًا حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْشَرُ النَّاسُ عَلَى ثَلَاثِ طَرَائِقَ رَاغِبِينَ رَاهِبِينً وَاثْنَانِ عَلَى بَعِيرٍ وَثَلَاثَةٌ عَلَى بَعِيرٍ وَأَرْبَعَةٌ عَلَى بَعِيرٍ وَعَشَرَةٌ عَلَى بَعِيرٍ وَتَحْشُرُ بَقِيَّتَهُمْ النَّارُ تَبِيتُ مَعَهُمْ حَيْثُ بَاتُوا وَتَقِيلُ مَعَهُمْ حَيْثُ قَالُوا وَتُصْبِحُ مَعَهُمْ حَيْثُ أَصْبَحُوا وَتُمْسِي مَعَهُمْ حَيْثُ أَمْسَوْا","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ahmad bin Ishaq]. Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] keduanya berkata: Telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Thawus] dari [ayahnya] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Manusia dibangkitkan atas tiga kelompok, ada yang dalam keadaan senang ada pula yang merasa ketakutan. Ada dua orang yang menunggangi satu onta, ada tiga orang yang menunggangi satu onta, ada empat orang yang menunggangi satu onta bahkan ada sepuluh orang yang menunggangi satu onta, lalu sisanya dikumpulkan oleh api yang selalu menyertai mereka pada malam dan siang.\" Mereka berkata: \"Pada pagi dan sore hari.\""},"4738":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا يَحْيَى يَعْنُونَ ابْنَ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَ يَقُومُ النَّاسُ لِرَبِّ الْعَالَمِينَ }قَالَ يَقُومُ أَحَدُهُمْ فِي رَشْحِهِ إِلَى أَنْصَافِ أُذُنَيْهِوَفِي رِوَايَةِ ابْنِ الْمُثَنَّى قَالَ يَقُومُ النَّاسُ لَمْ يَذْكُرْ يَوْمَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ الْمُسَيَّبِيُّ حَدَّثَنَا أَنَسٌ يَعْنِي ابْنَ عِيَاضٍ ح و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ كِلَاهُمَا عَنْ مُوسَى بْنِ عُقْبَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ وَعِيسَى بْنُ يُونُسَ عَنْ ابْنِ عَوْنٍ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ جَعْفَرِ بْنِ يَحْيَى حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنِي أَبُو نَصْرٍ التَّمَّارُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ ح و حَدَّثَنَا الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ كُلُّ هَؤُلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ غَيْرَ أَنَّ فِي حَدِيثِ مُوسَى بْنِ عُقْبَةَ وَصَالِحٍ حَتَّى يَغِيبَ أَحَدُهُمْ فِي رَشْحِهِ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb], [Muhammad bin Al Mutsanna] dan [Ubaidullah bin Sa'id] mereka berkata: Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah] telah mengkhabarkan kepadaku [Nafi'] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam: \"(Yaitu) hari (ketika) manusia berdiri menghadap rabb semesta alam\" (Al Muthaffiffiin: 6) beliau bersabda: \"Salah seorang dari mereka berdiri di dalam keringatnya hingga ke pertengahan telinganya.\" Disebutkan dalam riwayat Ibnu Al Mutsanna: Beliau bersabda: \"Manusia berdiri\" tanpa menyebut: Pada hari. Telah menceritakan kepada kami [Muhammad bin Ishaq AL Musayyibi] telah menceritakan kepada kami [Anas bin Iyadh]. Telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepada kami [Hafsh bin Maisarah] keduanya dari [Musa bin Uqbah]. Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dan [Isa bin Yunus] dari [Ibnu Aun]. Telah menceritakan kepadaku [Abdullah bin Ja'far bin Yahya] telah menceritakan kepada kami [Ma'nu] telah menceritakan kepada kami [Malik]. Telah menceritakan kepadaku [Abu Nashr At Tammar] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub]. Telah menceritakan kepada kami [Al Hulwani] dan [Abdu bin Humaid] dari [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih], semuanya dari [Nafi'] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam dengan makna hadits Abdullah dari Nafi', hanya saja dalam hadits Musa bin Uqbah dan Shalih disebutkan: \"Hingga salah seorang dari mereka terbenam dalam keringatnya hingga pertengahan telinganya.\""},"4739":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَرَقَ يَوْمَ الْقِيَامَةِ لَيَذْهَبُ فِي الْأَرْضِ سَبْعِينَ بَاعًا وَإِنَّهُ لَيَبْلُغُ إِلَى أَفْوَاهِ النَّاسِ أَوْ إِلَى آذَانِهِمْ يَشُكُّ ثَوْرٌ أَيَّهُمَا قَالَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdulaziz bin Muhammad] dari [Tsaur] dari [Abu Al Ghaits] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya keringat pada hari kiamat menyebar di tanah seluas tujuh puluh depa dan sesungguhnya ia mencapai mulut-mulut manusia atau hingga telinga-telinga mereka.\" Tsaur ragu mana yang disampaikan Rasulullah Shallallahu 'alaihi wa Salam."},"4740":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى أَبُو صَالِحٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرٍ حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ حَدَّثَنِي الْمِقْدَادُ بْنُ الْأَسْوَدِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تُدْنَى الشَّمْسُ يَوْمَ الْقِيَامَةِ مِنْ الْخَلْقِ حَتَّى تَكُونَ مِنْهُمْ كَمِقْدَارِ مِيلٍ قَالَ سُلَيْمُ بْنُ عَامِرٍ فَوَاللَّهِ مَا أَدْرِي مَا يَعْنِي بِالْمِيلِ أَمَسَافَةَ الْأَرْضِ أَمْ الْمِيلَ الَّذِي تُكْتَحَلُ بِهِ الْعَيْنُ قَالَ فَيَكُونُ النَّاسُ عَلَى قَدْرِ أَعْمَالِهِمْ فِي الْعَرَقِ فَمِنْهُمْ مَنْ يَكُونُ إِلَى كَعْبَيْهِ وَمِنْهُمْ مَنْ يَكُونُ إِلَى رُكْبَتَيْهِ وَمِنْهُمْ مَنْ يَكُونُ إِلَى حَقْوَيْهِ وَمِنْهُمْ مَنْ يُلْجِمُهُ الْعَرَقُ إِلْجَامًا قَالَ وَأَشَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ إِلَى فِيهِ","id":"Telah menceritakan kepada kami [Al Hakam bin Musa Abu Shalih] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Abdurrahman bin Jabir] telah menceritakan kepadaku [Sulaim bin Amir] telah menceritakan kepadaku [Al Miqdad bin Al Aswad] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Pada hari kiamat, matahari di dekatkan ke manusia hingga sebatas satu mil -berkata Sulaim bin Amir: Demi Allah, aku tidak tahu apakah beliau memaksudkan jarak bumi ataukah mil yang dipakai bercalak mata- lalu mereka berada dalam keringat sesuai amal perbuatan mereka, di antara mereka ada yang berkeringat hingga tumitnya, ada yang berkeringat hingga lututnya, ada yang berkeringat hingga pinggang dan ada yang benar-benar tenggelam oleh keringat.\" Al Miqdad berkata: Rasulullah Shallallahu 'alaihi wa Salam menunjuk dengan tangan ke mulut beliau."},"4741":{"ar":"حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارِ بْنِ عُثْمَانَ وَاللَّفْظُ لِأَبِي غَسَّانَ وَابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍ الْمُجَاشِعِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَاتَ يَوْمٍ فِي خُطْبَتِهِ أَلَا إِنَّ رَبِّي أَمَرَنِي أَنْ أُعَلِّمَكُمْ مَا جَهِلْتُمْ مِمَّا عَلَّمَنِي يَوْمِي هَذَا كُلُّ مَالٍ نَحَلْتُهُ عَبْدًا حَلَالٌ وَإِنِّي خَلَقْتُ عِبَادِي حُنَفَاءَ كُلَّهُمْ وَإِنَّهُمْ أَتَتْهُمْ الشَّيَاطِينُ فَاجْتَالَتْهُمْ عَنْ دِينِهِمْ وَحَرَّمَتْ عَلَيْهِمْ مَا أَحْلَلْتُ لَهُمْ وَأَمَرَتْهُمْ أَنْ يُشْرِكُوا بِي مَا لَمْ أُنْزِلْ بِهِ سُلْطَانًا وَإِنَّ اللَّهَ نَظَرَ إِلَى أَهْلِ الْأَرْضِ فَمَقَتَهُمْ عَرَبَهُمْ وَعَجَمَهُمْ إِلَّا بَقَايَا مِنْ أَهْلِ الْكِتَابِ وَقَالَ إِنَّمَا بَعَثْتُكَ لِأَبْتَلِيَكَ وَأَبْتَلِيَ بِكَ وَأَنْزَلْتُ عَلَيْكَ كِتَابًا لَا يَغْسِلُهُ الْمَاءُ تَقْرَؤُهُ نَائِمًا وَيَقْظَانَ وَإِنَّ اللَّهَ أَمَرَنِي أَنْ أُحَرِّقَ قُرَيْشًا فَقُلْتُ رَبِّ إِذًا يَثْلَغُوا رَأْسِي فَيَدَعُوهُ خُبْزَةً قَالَ اسْتَخْرِجْهُمْ كَمَا اسْتَخْرَجُوكَ وَاغْزُهُمْ نُغْزِكَ وَأَنْفِقْ فَسَنُنْفِقَ عَلَيْكَ وَابْعَثْ جَيْشًا نَبْعَثْ خَمْسَةً مِثْلَهُ وَقَاتِلْ بِمَنْ أَطَاعَكَ مَنْ عَصَاكَ قَالَ وَأَهْلُ الْجَنَّةِ ثَلَاثَةٌ ذُو سُلْطَانٍ مُقْسِطٌ مُتَصَدِّقٌ مُوَفَّقٌ وَرَجُلٌ رَحِيمٌ رَقِيقُ الْقَلْبِ لِكُلِّ ذِي قُرْبَى وَمُسْلِمٍ وَعَفِيفٌ مُتَعَفِّفٌ ذُو عِيَالٍ قَالَ وَأَهْلُ النَّارِ خَمْسَةٌ الضَّعِيفُ الَّذِي لَا زَبْرَ لَهُ الَّذِينَ هُمْ فِيكُمْ تَبَعًا لَا يَبْتَغُونَ أَهْلًا وَلَا مَالًا وَالْخَائِنُ الَّذِي لَا يَخْفَى لَهُ طَمَعٌ وَإِنْ دَقَّ إِلَّا خَانَهُ وَرَجُلٌ لَا يُصْبِحُ وَلَا يُمْسِي إِلَّا وَهُوَ يُخَادِعُكَ عَنْ أَهْلِكَ وَمَالِكَ وَذَكَرَ الْبُخْلَ أَوْ الْكَذِبَ وَالشِّنْظِيرُ الْفَحَّاشُوَلَمْ يَذْكُرْ أَبُو غَسَّانَ فِي حَدِيثِهِ وَأَنْفِقْ فَسَنُنْفِقَ عَلَيْكَ و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ فِي حَدِيثِهِ كُلُّ مَالٍ نَحَلْتُهُ عَبْدًا حَلَالٌ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ صَاحِبِ الدَّسْتَوَائِيِّ حَدَّثَنَا قَتَادَةُ عَنْ مُطَرِّفٍ عَنْ عِيَاضِ بْنِ حِمَارٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ ذَاتَ يَوْمٍ وَسَاقَ الْحَدِيثَ وَقَالَ فِي آخِرِهِ قَالَ يَحْيَى قَالَ شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ مُطَرِّفًا فِي هَذَا الْحَدِيثِ و حَدَّثَنِي أَبُو عَمَّارٍ حُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ عَنْ مَطَرٍ حَدَّثَنِي قَتَادَةُ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍ أَخِي بَنِي مُجَاشِعٍ قَالَ قَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ خَطِيبًا فَقَالَ إِنَّ اللَّهَ أَمَرَنِي وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ هِشَامٍ عَنْ قَتَادَةَ وَزَادَ فِيهِ وَإِنَّ اللَّهَ أَوْحَى إِلَيَّ أَنْ تَوَاضَعُوا حَتَّى لَا يَفْخَرَ أَحَدٌ عَلَى أَحَدٍ وَلَا يَبْغِ أَحَدٌ عَلَى أَحَدٍ وَقَالَ فِي حَدِيثِهِ وَهُمْ فِيكُمْ تَبَعًا لَا يَبْغُونَ أَهْلًا وَلَا مَالًا فَقُلْتُ فَيَكُونُ ذَلِكَ يَا أَبَا عَبْدِ اللَّهِ قَالَ نَعَمْ وَاللَّهِ لَقَدْ أَدْرَكْتُهُمْ فِي الْجَاهِلِيَّةِ وَإِنَّ الرَّجُلَ لَيَرْعَى عَلَى الْحَيِّ مَا بِهِ إِلَّا وَلِيدَتُهُمْ يَطَؤُهَا","id":"Telah menceritakan kepadaku [Abu Ghassan Al Misma'i], [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar bin Utsman], teks milik Ghassan dan Ibnu Al Mutsanna, keduanya berkata: Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Mutharrif bin Abdullah bin Asy Syakhir] dari [Iyadh bin Himar Al Mujasyi'i] Rasulullah Shallallahu 'alaihi wa Salam bersabda pada suatu hari dalam khutbah beliau: \"Sesungguhnya Rabbku memerintahkanku untuk mengajarkan yang tidak kalian ketahui yang Ia ajarkan padaku pada hari ini: 'Semua harta yang Aku berikan pada hamba itu halal, sesungguhnya Aku menciptakan hamba-hambaKu dalam keadaan lurus semuanya, mereka didatangi oleh setan lalu dijauhkan dari agama mereka, setan mengharamkan yang Aku halalkan pada mereka dan memerintahkan mereka agar menyekutukanKu yang tidak Aku turunkan kuasanya.' Sesungguhnya Allah memandang penduduk bumi lalu Allah membenci mereka, arab maupun ajam, kecuali sisa-sisa dari ahli kitab, Ia berfirman: 'Sesungguhnya aku mengutusmu untuk mengujiMu dan denganMu Aku menguji, Aku menurunkan kitab padamu yang tidak basah oleh air, kau membacanya dalam keadaan tidur dan terjaga.' Sesungguhnya Allah memerintahkanku untuk membakar kaum Quraisy lalu aku berkata: 'Wahai Rabb, kalau begitu mereka akan memecahkan kepalaku lalu mereka membiarkannya menjamur.' Ia berfirman: 'Usirlah mereka sebagaimana mereka mengusirmu, perangilah mereka niscaya Kami akan membantumu, berinfaklah niscaya Kami akan menggantinya, utuslah bala tentara niscaya Kami akan mengirim lima kali sepertinya, perangilah orang yang mendurhakaimu bersama orang yang menaatimu.\" Beliau meneruskan: \"Penghuni surga itu ada tiga; pemilik kekuasaan yang sederhana, derma dan penolong, seorang yang berbelas kasih, berhati lunak kepada setiap kerabat dan orang muslim yang sangat menjaga diri dan memiliki tanggungan.\" Beliau meneruskan: \"Penghuni neraka ada lima; orang lemah yang tidak memiliki kekuatan, yaitu para pengikut ditengah-tengah kalian, mereka tidak mencari keluarga dan juga harta, pengkhianat yang tidak samar baginya ketamakan meski tidak jelas kecuali ia pasti mengkhianatinya, orang yang dipagi dan disore harinya selalu menipumu pada keluarga dan hartamu.\" Beliau menyebut kebakhilan, kedustaan dan akhlak yang buruk. Abu Ghassan dalam haditsnya tidak menyebut: Berinfaklah niscaya Aku ganti. Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna Al Anazi] telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Sa'id] dari [Qatadah] dengan sanad ini, dalam haditsnya ia tidak menyebut: \"Semua harta yang Aku berikan pada hamba itu halal.\" Telah menceritakan kepadaku [Abdurrahman bin Bisyr Al Abdi] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam], teman Ad Dastuwa'I, telah menceritakan kepada kami [Qatadah] dari [Mutharrif] dari [Iyadh bin Himar] para suatu hari Rasulullah Shallallahu 'alaihi wa Salam berkhutbah, ia menyebutkan hadits dan diakhirnya ia menyebutkan: Yahya berkata: Syu'bah berkata: Dari Qatadah berkata: Aku mendengar Mutharrif dalam hadits ini. telah menceritakan kepadaku [Abu Ammar Husain bin Huraits] telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Al Husain] dari [Mathar] telah menceritakan kepadaku [Qatadah] dari [Mutharrif bin Abdullah bin Asy Syakhir] dari [Iyadh bin Himar] dari bani Mujasyi', ia berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri berkhutbah pada suatu hari ditengah-tengah kami lalu beliau bersabda: \"Sesungguhnya Allah memerintahkanku\" ia menyebut hadits seperti hadits Hisyam dari Qadatah, dalam haditsnya ia menambah: \"Dan Allah mewahyukan kepadaku agar kalian saling merendah diri agar tidak ada seorang pun yang berbangga diri pada yang lain dan agar tidak seorang pun berlalu lalim pada yang lain.\" Ia (Iyadh) menyebutkan dalam haditsnya: Dan mereka adalah para pengikut ditengah-tengah kalian, mereka tidak mencari keluarga atau harta.\" aku bertanya: Seperti itukah wahai Abu Abdullah? Ia menjawab: Ya, demi Allah, aku menjumpai mereka dimasa jahiliyah, seseorang menggembala di suatu perkampungan, disana tidak ada seorang pun selain budak wanitanya, ia menggaulinya."},"4742":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَدَكُمْ إِذَا مَاتَ عُرِضَ عَلَيْهِ مَقْعَدُهُ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ أَهْلِ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ أَهْلِ النَّارِ يُقَالُ هَذَا مَقْعَدُكَ حَتَّى يَبْعَثَكَ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] berkata: Aku meriwayatkan dari [Malik] dengan membaca, dari [Nafi'] dari [Ibnu Umar] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya salah seorang dari kalian bila meninggal dunia, tempatnya diperlihatkan pada pagi dan sore hari, bila termasuk penghuni surga, ia termasuk penghuni surga dan bila termasuk penghuni neraka, ia termasuk penghuni neraka. Dikatakan: 'Inilah tempatmu hingga Allah membangkitkanmu kepadanya pada hari kiamat'.\""},"4743":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَاتَ الرَّجُلُ عُرِضَ عَلَيْهِ مَقْعَدُهُ بِالْغَدَاةِ وَالْعَشِيِّ إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَالْجَنَّةُ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَالنَّارُ قَالَ ثُمَّ يُقَالُ هَذَا مَقْعَدُكَ الَّذِي تُبْعَثُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengkhabarkan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] berkata: Nabi Shallallahu 'alaihi wa Salam bersabda: \"Bila seseorang meninggal dunia, tempatnya diperlihatkan pada pagi dan sore hari, bila termasuk penghuni surga, ia termasuk penghuni surga dan bila termasuk penghuni neraka, ia termasuk penghuni neraka. Dikatakan: 'Inilah tempatmu yang akan kau tuju pada hari kiamat'.\""},"4744":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ جَمِيعًا عَنْ ابْنِ عُلَيَّةَ قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ وَأَخْبَرَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ أَبُو سَعِيدٍ وَلَمْ أَشْهَدْهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ حَدَّثَنِيهِ زَيْدُ بْنُ ثَابِتٍ قَالَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَائِطٍ لِبَنِي النَّجَّارِ عَلَى بَغْلَةٍ لَهُ وَنَحْنُ مَعَهُ إِذْ حَادَتْ بِهِ فَكَادَتْ تُلْقِيهِ وَإِذَا أَقْبُرٌ سِتَّةٌ أَوْ خَمْسَةٌ أَوْ أَرْبَعَةٌ قَالَ كَذَا كَانَ يَقُولُ الْجُرَيْرِيُّ فَقَالَ مَنْ يَعْرِفُ أَصْحَابَ هَذِهِ الْأَقْبُرِ فَقَالَ رَجُلٌ أَنَا قَالَ فَمَتَى مَاتَ هَؤُلَاءِ قَالَ مَاتُوا فِي الْإِشْرَاكِ فَقَالَ إِنَّ هَذِهِ الْأُمَّةَ تُبْتَلَى فِي قُبُورِهَا فَلَوْلَا أَنْ لَا تَدَافَنُوا لَدَعَوْتُ اللَّهَ أَنْ يُسْمِعَكُمْ مِنْ عَذَابِ الْقَبْرِ الَّذِي أَسْمَعُ مِنْهُ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ تَعَوَّذُوا بِاللَّهِ مِنْ عَذَابِ النَّارِ قَالُوا نَعُوذُ بِاللَّهِ مِنْ عَذَابِ النَّارِ فَقَالَ تَعَوَّذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ قَالُوا نَعُوذُ بِاللَّهِ مِنْ عَذَابِ الْقَبْرِ قَالَ تَعَوَّذُوا بِاللَّهِ مِنْ الْفِتَنِ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ قَالُوا نَعُوذُ بِاللَّهِ مِنْ الْفِتَنِ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ قَالَ تَعَوَّذُوا بِاللَّهِ مِنْ فِتْنَةِ الدَّجَّالِ قَالُوا نَعُوذُ بِاللَّهِ مِنْ فِتْنَةِ الدَّجَّالِ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Abu Bakr bin Abu Syaibah], semuanya dari [Ibnu Ulaiyah] berkata [Ibnu Ayyub]: Telah menceritakan kepada kami [Ibnu Ulaiyah] berkata. Telah mengkhabarkan kepada kami [Sa'id Al Jurairi] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] dari [Zaid bin Tsabit] berkata Abu Sa'id: Aku tidak menyaksikannya dari nabi Shallallahu 'alaihi wa Salam, tapi Zaid bin Tsabit menceritakannya kepadaku, ia berkata: Saat nabi Shallallahu 'alaihi wa Salam berada di kebun milik bani An Najjar, beliau menunggangi bighal milik beliau dan kami bersama beliau, tiba-tiba bighal menyimpang hingga hampir melemparkan beliau, ternyata ada enam, lima atau empat kuburan -ia berkata: Seperti inilah yang dikatakan Al Jurairi- lalu beliau bertanya: \"Siapa yang mengetahui penghuni-penghuni kubuan ini?\" seseorang menjawab: Saya. Beliau bertanya: \"Kapan mereka meninggal?\" ia menjawab: Mereka meninggal dimasa kesyirikan. Beliau bersabda: \"Sesungguhnya ummat ini diuji dikuburnya. Andai kalian tidak berlarian, niscaya aku berdoa kepada Allah agar memperdengarkan adzab kubur pada kalian seperti aku dengar.\" Setelah itu beliau menghadapkan wajah ke arah kami lalu bersabda: \"Berlindunglah diri kepada Allah dari adzab neraka.\" mereka berkata: Kami berlindung diri kepada Allah dari adzab neraka.\" beliau bersabda: \"Berlindunglah diri kepada Allah dari adzab kubur.\" mereka berkata: Kami berlindung diri kepada Allah dari adzab kubur.\" Beliau bersabda: \"Berlindunglah diri kepada Allah dari fitnah-fitnah yang nampak dan yang teresmbunyi.\" Mereka berkata: Kami berlindung diri kepada Allah dari fitnah-fitnah yang nampak dan yang tersembunyi.\" Beliau bersabda: \"Berlindunglah diri kepada Allah dari fitnahnya Dajjal.\" mereka berkata: Kami berlindung diri kepada Allah dari fitnahnya Dajjal.\""},"4745":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ لَا تَدَافَنُوا لَدَعَوْتُ اللَّهَ أَنْ يُسْمِعَكُمْ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] nabi Shallallahu 'alaihi wa Salam bersabda: \"Andai kalian tidak berlarian, niscaya aku berdoa kepada Allah agar memperdengarkan adzab kubur pada kalian.\""},"4746":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ كُلُّهُمْ عَنْ شُعْبَةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ جَمِيعًا عَنْ يَحْيَى الْقَطَّانِ وَاللَّفْظُ لِزُهَيْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ عَنْ الْبَرَاءِ عَنْ أَبِي أَيُّوبَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ فَسَمِعَ صَوْتًا فَقَالَ يَهُودُ تُعَذَّبُ فِي قُبُورِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki']. Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku]. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far], semuanya dari [Syu'bah] dari [Aun bin Abu Juhaifah]. Telah menceritakan kepadaku [Zuhair bin Harb], [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], semuanya dari [Yahya Al Qaththan] dan teksnya milik Zuhair, telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Aun bin Abu Juhaifah] dari [ayahnya] dari [Al Bara`] dari [Abu Ayyub] berkata: Rasulullah Shallallahu 'alaihi wa Salam pergi setelah matahari terbenam lalu beliau mendengar suara, beliau bersabda: \"Orang-orang Yahudi disiksa dikuburnya.\""},"4747":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ إِنَّهُ لَيَسْمَعُ قَرْعَ نِعَالِهِمْ قَالَ يَأْتِيهِ مَلَكَانِ فَيُقْعِدَانِهِ فَيَقُولَانِ لَهُ مَا كُنْتَ تَقُولُ فِي هَذَا الرَّجُلِ قَالَ فَأَمَّا الْمُؤْمِنُ فَيَقُولُ أَشْهَدُ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ قَالَ فَيُقَالُ لَهُ انْظُرْ إِلَى مَقْعَدِكَ مِنْ النَّارِ قَدْ أَبْدَلَكَ اللَّهُ بِهِ مَقْعَدًا مِنْ الْجَنَّةِ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَرَاهُمَا جَمِيعًاقَالَ قَتَادَةُ وَذُكِرَ لَنَا أَنَّهُ يُفْسَحُ لَهُ فِي قَبْرِهِ سَبْعُونَ ذِرَاعًا وَيُمْلَأُ عَلَيْهِ خَضِرًا إِلَى يَوْمِ يُبْعَثُونَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban bin Abdurrahman] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik] berkata: Nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya hamba bila telah diletakkan dikuburnya dan teman-temannya telah meninggalkannya, ia mendengar derap sandal mereka.\" Beliau bersabda: \"Dua malaikat mendatanginya, keduanya mendudukkannya lalu bertanya padanya: 'Apa yang dulu kau katakan tentang orang ini?\" beliau bersabda: \"Orang mu`min menjawab: 'Aku bersaksi bahwa ia adalah hamba dan utusan Allah.\" Beliau bersabda: \"Lalu dikatakan padanya: 'Lihatlah tempatmu dineraka, Allah telah menggantikannya dengan tempat disurga.\" Nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Lalu ia melihat keduanya.\" Qadatah berkata: Disebutkan bagi kami bahwa kuburnya dipalangkan seluas tujuhpuluh dzira' dipenuhi oleh tanaman hijau hingga hari manusia dibangkitkan."},"4748":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ إِذَا وُضِعَ فِي قَبْرِهِ إِنَّهُ لَيَسْمَعُ خَفْقَ نِعَالِهِمْ إِذَا انْصَرَفُواحَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا عَبْدُ الْوَهَّابِ يَعْنِي ابْنَ عَطَاءٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ إِذَا وُضِعَ فِي قَبْرِهِ وَتَوَلَّى عَنْهُ أَصْحَابُهُ فَذَكَرَ بِمِثْلِ حَدِيثِ شَيْبَانَ عَنْ قَتَادَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Minhal Adh Dharir] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya mayit bila telah diletakkan dikuburnya, ia mendengar derapan sandal mereka saat mereka pulang.\" Telah menceritakan kepadaku [Amru bin Zurarah] telah mengkhabarkan kepada kami [Abdulwahhab bin Atho`] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Bila ia diletakkan dikuburnya dan teman-temannya pulang.\" Ia menyebut seperti hadits Syaiban dari Qatadah."},"4749":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَأَبُو بَكْرِ بْنُ نَافِعٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنُونَ ابْنَ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ خَيْثَمَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ نَزَلَتْ فِي عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abi Syaibah], [Muhammad bin Al Mutsanna] dan [Abu Bakr bin Nafi'], mereka berkata: Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [ayahnya] dari [Khaitsamah] dari [Al Bara` bin Azib]: \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Ibrahim: 27) ia berkata: Turun berkenaan dengan adzab kubur."},"4750":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا بُدَيْلٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ أَبِي هُرَيْرَةَ قَالَإِذَا خَرَجَتْ رُوحُ الْمُؤْمِنِ تَلَقَّاهَا مَلَكَانِ يُصْعِدَانِهَا قَالَ حَمَّادٌ فَذَكَرَ مِنْ طِيبِ رِيحِهَا وَذَكَرَ الْمِسْكَ قَالَ وَيَقُولُ أَهْلُ السَّمَاءِ رُوحٌ طَيِّبَةٌ جَاءَتْ مِنْ قِبَلِ الْأَرْضِ صَلَّى اللَّهُ عَلَيْكِ وَعَلَى جَسَدٍ كُنْتِ تَعْمُرِينَهُ فَيُنْطَلَقُ بِهِ إِلَى رَبِّهِ عَزَّ وَجَلَّ ثُمَّ يَقُولُ انْطَلِقُوا بِهِ إِلَى آخِرِ الْأَجَلِ قَالَ وَإِنَّ الْكَافِرَ إِذَا خَرَجَتْ رُوحُهُ قَالَ حَمَّادٌ وَذَكَرَ مِنْ نَتْنِهَا وَذَكَرَ لَعْنًا وَيَقُولُ أَهْلُ السَّمَاءِ رُوحٌ خَبِيثَةٌ جَاءَتْ مِنْ قِبَلِ الْأَرْضِ قَالَ فَيُقَالُ انْطَلِقُوا بِهِ إِلَى آخِرِ الْأَجَلِ قَالَ أَبُو هُرَيْرَةَ فَرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَيْطَةً كَانَتْ عَلَيْهِ عَلَى أَنْفِهِ هَكَذَا","id":"Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Budail] dari [Abdullah bin Syaqiq] dari [Abu Hurairah] berkata: Apabila roh orang mukmin telah keluar dari jasadnya, ia akan ditemui oleh dua malaikat yang akan membawanya naik, lalu Hammad berkata dan menyebutkan baunya yang harum seraya berkata: Baunya seperti minyak wangi, dan para penghuni langit berkata: Telah datang roh yang baik dari bumi, semoga Allah mendo'akanmu dan mendo'akan jasad yang telah kau tinggali. Lalu ia dibawa menghadap Rabbnya 'azza wajalla. Kemudian ia berkata: Bawalah ia sampai ke tempat yang paling akhir (yakni Sidratul Muntaha). Dan sesungguhnya orang kafir apabila rohnya telah keluar daripadanya. Hammad berkata: ia menyebutkan baunya yang busuk dan cercaan yang ditujukan kepadanya, lalu para penghuni langit berkata: Telah datang satu roh yang buruk dari bumi. Ia berkata: lalu dikatakan: bawalah ia hingga sampai ke tempat yang paling akhir (yakni sijiin) Abu Hurairah berkata: Rasulullah shallallahu 'alaihi wasallam meletakkan kain tipis yang ada padanya pada hidung beliau seperti ini."},"4751":{"ar":"حَدَّثَنِي إِسْحَقُ بْنُ عُمَرَ بْنِ سَلِيطٍ الْهُذَلِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ قَالَ قَالَ أَنَسٌ كُنْتُ مَعَ عُمَرَ ح و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ وَاللَّفْظُ لَهُ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا مَعَ عُمَرَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَتَرَاءَيْنَا الْهِلَالَ وَكُنْتُ رَجُلًا حَدِيدَ الْبَصَرِ فَرَأَيْتُهُ وَلَيْسَ أَحَدٌ يَزْعُمُ أَنَّهُ رَآهُ غَيْرِي قَالَ فَجَعَلْتُ أَقُولُ لِعُمَرَ أَمَا تَرَاهُ فَجَعَلَ لَا يَرَاهُ قَالَ يَقُولُ عُمَرُ سَأَرَاهُ وَأَنَا مُسْتَلْقٍ عَلَى فِرَاشِي ثُمَّ أَنْشَأَ يُحَدِّثُنَا عَنْ أَهْلِ بَدْرٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُرِينَا مَصَارِعَ أَهْلِ بَدْرٍ بِالْأَمْسِ يَقُولُ هَذَا مَصْرَعُ فُلَانٍ غَدًا إِنْ شَاءَ اللَّهُ قَالَ فَقَالَ عُمَرُ فَوَالَّذِي بَعَثَهُ بِالْحَقِّ مَا أَخْطَئُوا الْحُدُودَ الَّتِي حَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجُعِلُوا فِي بِئْرٍ بَعْضُهُمْ عَلَى بَعْضٍ فَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَهَى إِلَيْهِمْ فَقَالَ يَا فُلَانَ بْنَ فُلَانٍ وَيَا فُلَانَ بْنَ فُلَانٍ هَلْ وَجَدْتُمْ مَا وَعَدَكُمْ اللَّهُ وَرَسُولُهُ حَقًّا فَإِنِّي قَدْ وَجَدْتُ مَا وَعَدَنِي اللَّهُ حَقًّا قَالَ عُمَرُ يَا رَسُولَ اللَّهِ كَيْفَ تُكَلِّمُ أَجْسَادًا لَا أَرْوَاحَ فِيهَا قَالَ مَا أَنْتُمْ بِأَسْمَعَ لِمَا أَقُولُ مِنْهُمْ غَيْرَ أَنَّهُمْ لَا يَسْتَطِيعُونَ أَنْ يَرُدُّوا عَلَيَّ شَيْئًا","id":"Telah menceritakan kepadaku [Ishaq bin Umar bin Salith Al Hudzali] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] berkata: [Anas] berkata: Aku bersama [Umar]. Telah menceritakan kepada kami [Syaiban bin Farrukh], teks miliknya, telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin Malik] berkata: Kami bersama [Umar] diantara Makkah dan Madinah, kami melihat hilal, aku adalah orang yang berpenglihatan tajam, aku melihatnya, tapi tiadk seorang pun mengira bahwa tidak ada melihatnya selainku. Anas berkata: Aku berkata kepada Umar: Apa kau tidak melihatnya? Ia tidak melihatnya, ia berkata: Aku akan melihatnya dengan berbaring di atas hamparanku. Lalu ia menceritakan kepada kami tentang tentara-tentara Badar, ia berkata: Rasulullah Shallallahu 'alaihi wa Salam memperlihatkan tempat kematian tentara-tentara Badar kemarin, beliau bersabda: \"Ini tempat kematian fulan besok, insya Allah.\" Anas berkata: Umar berkata: Demi Dzat yang mengutusnya dengan kebenaran, mereka tidak melenceng dari batasan yang ditentukan Rasulullah Shallallahu 'alaihi wa Salam.\" Ia berkata: Mereka ditempatkan dilubang tanah satu sama lain, lalu Rasulullah Shallallahu 'alaihi wa Salam bergegas hingga tiba menemui mereka, beliau memanggil: \"Hai fulan bin fulan, hai fulan bin fulan, apakah kalian mendapatkan kebenaran janji Allah dan rasulNya, sesungguhnya aku telah menemukan kebenaran janji Allah yang dijanjikan padaku.\" Umar berkata: Wahai Rasulullah, bagaimana Tuan berbicara dengan jasad-jasad tidak bernyawa? Beliau bersabda: \"Kalian tidak lebih mendengar ucapanku melebihi mereka, hanya saja mereka tidak bisa menjawabku sedikit pun.\""},"4752":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ حُجْرٍ جَمِيعًا عَنْ إِسْمَعِيلَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حُوسِبَ يَوْمَ الْقِيَامَةِ عُذِّبَ فَقُلْتُ أَلَيْسَ قَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }فَقَالَ لَيْسَ ذَاكِ الْحِسَابُ إِنَّمَا ذَاكِ الْعَرْضُ مَنْ نُوقِشَ الْحِسَابَ يَوْمَ الْقِيَامَةِ عُذِّبَحَدَّثَنِي أَبُو الرَّبِيعِ الْعَتَكِيُّ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Hujr], semuanya dari [Isma'il] berkata [Abu Bakar]: telah menceritakan kepada kami [Ibnu Ulaiyah] dari [Ayyub] dari [Abdullah bin Abu Malikah] dari [Aisyah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa dihisab pada hari kiamat, ia disiksa.\" Aku berkata: Bukankah Allah 'azza wajalla berfirman: \"Maka dia akan diperiksa dengan pemeriksaan yang mudah.\" (Al Insyiqaaq: 8) beliau menjawab: \"Itu bukan hisab, itu hanya pemaparan. Barangsiapa dibantah (saat) penghisaban pada hari kiamat, ia disiksa.\" Telah menceritakan kepadaku [Abu Ar Rabi' Al Ataki] dan [Abu Kamil] keduanya bekata: Telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dengan sanad ini dengan matan serupa."},"4753":{"ar":"و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرِ بْنِ الْحَكَمِ الْعَبْدِيُّ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ الْقَطَّانَ حَدَّثَنَا أَبُو يُونُسَ الْقُشَيْرِيُّ حَدَّثَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ أَحَدٌ يُحَاسَبُ إِلَّا هَلَكَ قُلْتُ يَا رَسُولَ اللَّهِ أَلَيْسَ اللَّهُ يَقُولُ{ حِسَابًا يَسِيرًا }قَالَ ذَاكِ الْعَرْضُ وَلَكِنْ مَنْ نُوقِشَ الْحِسَابَ هَلَكَو حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنِي يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نُوقِشَ الْحِسَابَ هَلَكَ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ أَبِي يُونُسَ","id":"Telah menceritakan kepadaku [Abdurrahman bin Bisyr bin Al Hakam Al Abdi] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] telah menceritakan kepada kami [Abu Yunus Al Qusyairi] telah menceritakan kepada kami [Ibnu Abi Mulaikah] dari [Al Qasim] dari [Aisyah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seseorang dihisab melaikan ia pasti binasa.\" Aku bertanya: Wahai Rasulullah, bukankah Allah berfirman: \"Maka dia akan diperiksa dengan pemeriksaan yang mudah.\" (Al Insyiqaaq: 8) beliau menjawab: \"Itu adalah pemeriksaan, tapi orang yang dibantah (saat) penghisaban, ia binasa.\" Telah menceritakan kepadaku [Abdurrahman bin Bisyr] telah menceritakan kepadaku [Yahya Al Qaththan] dari [Utsman bin Al Aswad] dari [Ibnu Abi Mulaikah] dari [Aisyah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa dibantah (saat) penghisaban, ia binasa.\" Lalu ia menyebut seperti hadits Abu Yunus."},"4754":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَحْيَى بْنُ زَكَرِيَّاءَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ وَفَاتِهِ بِثَلَاثٍ يَقُولُ لَا يَمُوتَنَّ أَحَدُكُمْ إِلَّا وَهُوَ يُحْسِنُ بِاللَّهِ الظَّنَّو حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ وَأَبُو مُعَاوِيَةَ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengkhabarkan kepada kami [Yahya bin Zakariya] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda tiga hari sebelum beliau wafat: \"Jangalah salah seorang dari kalian meninggal dunia kecuali ia berbaik sangka kepada Allah.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir]. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah]. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Isa bin Yunus] dan [Abu Mu'awiyah] semuanya dari [Al A'masy] dengan sanad ini dengan matan serupa."},"4755":{"ar":"و حَدَّثَنِي أَبُو دَاوُدَ سُلَيْمَانُ بْنُ مَعْبَدٍ حَدَّثَنَا أَبُو النُّعْمَانِ عَارِمٌ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا وَاصِلٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ مَوْتِهِ بِثَلَاثَةِ أَيَّامٍ يَقُولُ لَا يَمُوتَنَّ أَحَدُكُمْ إِلَّا وَهُوَ يُحْسِنُ الظَّنَّ بِاللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepadaku [Abu Dawud Sulaiman bin Ma'bad] telah menceritakan kepada kami [Abu An Nu'man Arim] telah menceritakan kepada kami [Mahdi bin Maimun] telah menceritakan kepada kami [Washil] dari [Abu Az Zubair] dari [Jabir bin Abdullah Al Anshari] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda tiga hari sebelum beliau wafat: \"Jangalah salah seorang dari kalian meninggal dunia kecuali ia berbaik sangka kepada Allah 'azza wajalla.\""},"4756":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُبْعَثُ كُلُّ عَبْدٍ عَلَى مَا مَاتَ عَلَيْهِحَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ سَمِعْتُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Utsman bin Abu Syaibah] keduanya berkata: telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Setiap hamba dibangkitkan di atas kondisi saat ia meninggal.\" Telah menceritakan kepada kami [Abu Bakr bin Nafi'] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Al A'masy] dengan sanad ini dengan matan serupa. Ia berkata: Dari nabi Shallallahu 'alaihi wa Salam dan tidak menyebut: Aku mendengar."},"4757":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَرَادَ اللَّهُ بِقَوْمٍ عَذَابًا أَصَابَ الْعَذَابُ مَنْ كَانَ فِيهِمْ ثُمَّ بُعِثُوا عَلَى أَعْمَالِهِمْ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya At Tujini] telah mengkhabarkan kepada kami [Ibnu Wahb] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Hamzah bin Abdullah bin Umar] bahwa [Abdullah bin Umar] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila Allah hendak mengadzab suatu kaum, adzab menimpa orang yang ada ditengah-tengah mereka lalu mereka dibangkitkan berdasarkan amal-amal mereka.\""},"4758":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَيْقَظَ مِنْ نَوْمِهِ وَهُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ سُفْيَانُ بِيَدِهِ عَشَرَةً قُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخَبَثُحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَسَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَزُهَيْرُ بْنُ حَرْبٍ وَابْنُ أَبِي عُمَرَ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ وَزَادُوا فِي الْإِسْنَادِ عَنْ سُفْيَانَ فَقَالُوا عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ","id":"Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari [Zainab binti Ummu Salamah] dari [Ummu Habibah] dari [Zainab binti Jahsy] nabi Shallallahu 'alaihi wa Salam bangun tidur dan beliau mengucapkan: \"LAA ILAAHA ILLALLAAH, celakalah bangsa arab dari keburukan yang mendekat, saat ini penghalang Ya'juj dan Ma'juj telah terbuka seperti ini -Sufyan dan lainnya melekatkan kesepuluh jarinya- aku (Zainab) bertanya: Wahai Rasulullah, apakah kita akan dibinasakan sementara ditengah-tengah kami ada orang-orang shalih? Beliau menjawab: \"Ya, bila kekejian banyak (menyebar).\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], [Sa'id bin Amru Al Asy'atsi], [Zuhair bin Harb] dan [Ibnu Abi Umar], mereka berkata: Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dengan sanad ini. mereka menambahkan dalam sanad Sufyan, mereka berkata: Dari [Zainab binti Abu Salamah] dari [Habibah] dari [Ummu Habibah] dari [Zainab binti Jahsy]."},"4759":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَ بِنْتَ أَبِي سُفْيَانَ أَخْبَرَتْهَا أَنَّ زَيْنَبَ بِنْتَ جَحْشٍ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَزِعًا مُحْمَرًّا وَجْهُهُ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَحَلَّقَ بِإِصْبَعِهِ الْإِبْهَامِ وَالَّتِي تَلِيهَا قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخَبَثُو حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ ح و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ كِلَاهُمَا عَنْ ابْنِ شِهَابٍ بِمِثْلِ حَدِيثِ يُونُسَ عَنْ الزُّهْرِيِّ بِإِسْنَادِهِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengkhabarkan kepada kami [Ibnu Wahb] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Urwah bin Az Zubair] bahwa [Zainab binti Abu Salamah] telah mengkhabarkan kepadanya bahwa [Ummu Habibah binti Abu Sufyan] telah mengkhabarkan kepadanya bahwa [Zainab binti Jahsy], istri nabi Shallallahu 'alaihi wa Salam, telah mengkhabarkan kepadanya, ia berkata: Pada suatu hari Rasulullah Shallallahu 'alaihi wa Salam keluar dalam keadaan takut dan wajah beliau memerah, beliau mengucapkan: \"LAA ILAAHA ILLALLAAH, celakalah bangsa arab dari keburukan yang mendekat, saat ini penghalang Ya'juj dan Ma'juj telah terbuka seperti ini -beliau melekatkan jari jempol dan jari telunjuk- ia (Zainab) bertanya: Wahai Rasulullah, apakah kita akan dibinasakan sementara ditengah-tengah kami ada orang-orang shalih? Beliau menjawab: \"Ya, bila kekejian banyak (menyebar).\" Telah menceritakan kepadaku [Abdulmalik bin Syu'aib bin Al Laits] telah menceritakan kepadaku [ayahku] dari [kakekku] telah menceritakan kepadaku [Uqail bin Khalid]. Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih], keduanya dari [Ibnu Syihab] seperti hadits Yunus dari Az Zuhri dengan sanadnya."},"4760":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ وُهَيْبٌ بِيَدِهِ تِسْعِينَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ahmad bin Ishaq] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Thawus] dari [ayahnya] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Saat ini penghalang Ya'juj dan Ma'juj telah terbuka seperti ini.\" Wuhaib menghitung dengan tangannya sebanyak sembilanpuluh."},"4761":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِقُتَيْبَةَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ قَالَ دَخَلَ الْحَارِثُ بْنُ أَبِي رَبِيعَةَ وَعَبْدُ اللَّهِ بْنُ صَفْوَانَ وَأَنَا مَعَهُمَا عَلَى أُمِّ سَلَمَةَ أُمِّ الْمُؤْمِنِينَ فَسَأَلَاهَا عَنْ الْجَيْشِ الَّذِي يُخْسَفُ بِهِ وَكَانَ ذَلِكَ فِي أَيَّامِ ابْنِ الزُّبَيْرِ فَقَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُوذُ عَائِذٌ بِالْبَيْتِ فَيُبْعَثُ إِلَيْهِ بَعْثٌ فَإِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِهِمْ فَقُلْتُ يَا رَسُولَ اللَّهِ فَكَيْفَ بِمَنْ كَانَ كَارِهًا قَالَ يُخْسَفُ بِهِ مَعَهُمْ وَلَكِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ عَلَى نِيَّتِهِ وَقَالَ أَبُو جَعْفَرٍ هِيَ بَيْدَاءُ الْمَدِينَةِحَدَّثَنَاه أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِهِ قَالَ فَلَقِيتُ أَبَا جَعْفَرٍ فَقُلْتُ إِنَّهَا إِنَّمَا قَالَتْ بِبَيْدَاءَ مِنْ الْأَرْضِ فَقَالَ أَبُو جَعْفَرٍ كَلَّا وَاللَّهِ إِنَّهَا لَبَيْدَاءُ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], [Abu Bakr bin Abu Syaibah] dan [Ishaq bin Ibrahim], teks milik Qutaibah, berkata Ishaq: telah mengkhabarkan kepada kami dan yang lain berkata: Telah menceritakan kepada kami [Jarir] dari [Abdulaziz bin Rufai'] dari [Ubaidullah bin Al Qibthiyyah] berkata: Al Harits bin Abu Rabi'ah dan Abdullah bin Shafwan bertamu ke kediaman [Ummu Salamah], Ummul Mu`minin, aku bersama keduanya, keduanya bertanya tentang tentara yang dibenamkan ke bumi dan itu terjadi dimasa Ibnu Az Zubair. Ia menjawab: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Seseorang berlindung di baitulah lalu pasukan dikirim menemuinya, mereka berada disalah satu padang pasir lalu mereka dibenamkan.\" Aku bertanya: Wahai Rasulullah, lalu bagaimana dengan orang yang benci? Beliau menjawab: \"Ia dibenamkan bersama mereka, tapi ia dibangkitkan pada hari kiamat berdasarkan niatnya.\" Abu Ja'far berkata: Itu di tanah lapang Madinah. Telah menceritakannya kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdulaziz bin Rufai'] dengan sanad ini, dan dalam haditsnya disebutkan: Ia berkata: Lalu aku bertemu dengan Abu Ja'far, aku berkata: Sesungguhnya Ummu Salamah hanya mengatakan disalah satu padang pasir. Abu Ja'far berkata: Tidak, demi Allah sesungguhnya itu adalah padang pasir Madinah."},"4762":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِعَمْرٍو قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ سَمِعَ جَدَّهُ عَبْدَ اللَّهِ بْنَ صَفْوَانَ يَقُولُ أَخْبَرَتْنِي حَفْصَةُأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَؤُمَّنَّ هَذَا الْبَيْتَ جَيْشٌ يَغْزُونَهُ حَتَّى إِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ يُخْسَفُ بِأَوْسَطِهِمْ وَيُنَادِي أَوَّلُهُمْ آخِرَهُمْ ثُمَّ يُخْسَفُ بِهِمْ فَلَا يَبْقَى إِلَّا الشَّرِيدُ الَّذِي يُخْبِرُ عَنْهُمْ فَقَالَ رَجُلٌ أَشْهَدُ عَلَيْكَ أَنَّكَ لَمْ تَكْذِبْ عَلَى حَفْصَةَ وَأَشْهَدُ عَلَى حَفْصَةَ أَنَّهَا لَمْ تَكْذِبْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Amru An Naqid] dan [Ibnu Abi Umar], teks milik Amru, keduanya berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Umaiyah bin Shafwan] ia mendengar [kakeknya, Abdullah bin Shawan] berkata: telah mengkhabarkan kepadaku [Hafshah] bahwa ia mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Baitullah ini akan dituju oleh suatu tentara untuk diperangi, saat mereka tiba disuatu padang pasir bumi, mereka dibenamkan dibagian tengah-tengahnya. Bagian depan memanggil bagian belakang lalu mereka semua dibenamkan, tidak ada yang tersisa selain seseorang yang melepaskan diri yang mengkhabarkan tentang mereka. Seseorang berkata: Aku bersaksi padamu bahwa kau tidak berdusta atas nama Hafshah dan aku bersaksi untuk Hafshah bahwa ia tidak berdusta nama nabi Shallallahu 'alaihi wa Salam."},"4763":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ حَدَّثَنَا الْوَلِيدُ بْنُ صَالِحٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ عَبْدِ الْمَلِكِ الْعَامِرِيِّ عَنْ يُوسُفَ بْنِ مَاهَكَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ صَفْوَانَ عَنْ أُمِّ الْمُؤْمِنِينَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَعُوذُ بِهَذَا الْبَيْتِ يَعْنِي الْكَعْبَةَ قَوْمٌ لَيْسَتْ لَهُمْ مَنَعَةٌ وَلَا عَدَدٌ وَلَا عُدَّةٌ يُبْعَثُ إِلَيْهِمْ جَيْشٌ حَتَّى إِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِهِمْ قَالَ يُوسُفُ وَأَهْلُ الشَّأْمِ يَوْمَئِذٍ يَسِيرُونَ إِلَى مَكَّةَ فَقَالَ عَبْدُ اللَّهِ بْنُ صَفْوَانَ أَمَا وَاللَّهِ مَا هُوَ بِهَذَا الْجَيْشِقَالَ زَيْدٌ وَحَدَّثَنِي عَبْدُ الْمَلِكِ الْعَامِرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ الْحَارِثِ بْنِ أَبِي رَبِيعَةَ عَنْ أُمِّ الْمُؤْمِنِينَ بِمِثْلِ حَدِيثِ يُوسُفَ بْنِ مَاهَكَ غَيْرَ أَنَّهُ لَمْ يَذْكُرْ فِيهِ الْجَيْشَ الَّذِي ذَكَرَهُ عَبْدُ اللَّهِ بْنُ صَفْوَانَ","id":"Telah menceritakan kepadaku [Muhammad bin Hatim bin Maimun] telah menceritakan kepada kami [Al Walid bin Shalih] telah menceritakan kepada kami [Ubaidullah bin Amru] telah menceritakan kepada kami [Zaid bin Abu Unaisah] dari [Abdulmalik Al Amiri] dari [Yusuf bin Mahak] telah mengkhabarkan kepadaku [Abdullah bin Shafwan] dari [Ummul Mu`minin] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Suatu kaum akan berlindung di rumah ini -maksud beliau baitullah- mereka tidak memiliki pelindung, jumlah atau pun senjata. Suatu tentara dikirim untuk (menyerang) mereka. Saat berada di suatu padang pasir bumi, mereka dibenamkan dibumi.\" Yusus berkata: Saat itu penduduk Syam tengah bepergian menuju Makkah. Abdullah bin Shafwan berkata: Demi Allah, mereka bukan tentara yang dimaksud. Zaid berkata: Telah menceritakan kepadaku [Abdulmalik Al Amiri] dari [Abdurrahman bin Sabith] dari [Al Harits bin Abu Rabi'ah] dari [Ummul Mu`minin] seperti hadits Yusuf bin Mahak, hanya saja ia tidak menyebutkan tentara yang disebut Abdullah bin Shafwan."},"4764":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْقَاسِمُ بْنُ الْفَضْلِ الْحُدَّانِيُّ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَنَّ عَائِشَةَ قَالَتْعَبَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنَامِهِ فَقُلْنَا يَا رَسُولَ اللَّهِ صَنَعْتَ شَيْئًا فِي مَنَامِكَ لَمْ تَكُنْ تَفْعَلُهُ فَقَالَ الْعَجَبُ إِنَّ نَاسًا مِنْ أُمَّتِي يَؤُمُّونَ بِالْبَيْتِ بِرَجُلٍ مِنْ قُرَيْشٍ قَدْ لَجَأَ بِالْبَيْتِ حَتَّى إِذَا كَانُوا بِالْبَيْدَاءِ خُسِفَ بِهِمْ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ الطَّرِيقَ قَدْ يَجْمَعُ النَّاسَ قَالَ نَعَمْ فِيهِمْ الْمُسْتَبْصِرُ وَالْمَجْبُورُ وَابْنُ السَّبِيلِ يَهْلِكُونَ مَهْلَكًا وَاحِدًا وَيَصْدُرُونَ مَصَادِرَ شَتَّى يَبْعَثُهُمْ اللَّهُ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Al Qasim bin Al Fadhll Al Huddani] dari [Muhammad bin Ziyad] dari [Abdullah bin Zubair] bahwa [Aisyah] berkata: Suatu ketika Rasulullah shallallahu 'alaihi wasallam pernah bergerak-gerak dalam tidurnya, kami berkata: Wahai Rasulullah, dalam tidurmu engkau telah melakukan sesuatu yang belum pernah engkau lakukan sebelumnya. Beliau bersabda: \"Aneh, sesungguhnya ada beberapa orang dari umatku yang menuju Baitullah (untuk menyerang) seseorang Quraisy yang berlindung ke Baitullah. Saat mereka telah sampai di padang pasir, merekapun dibenamkan.\" Kami berkata: Wahai Rasulullah, sesungguhnya jalan menyatukan banyak orang. Beliau menjawab: \"Ya\", di antara mereka ada yang memang sengaja menuju ke sana, ada yang terpaksa, bahkan ada yang hanya kebetulan sedang berjalan bersama mereka. Mereka semua dibinasakan sekaligus, akan tetapi mereka dibangkitkan dengan cara yang berbeda-beda. Allah membangkitkan mereka semua sesuai dengan niat mereka masing-masing.\""},"4765":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي شَيْبَةَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُسَامَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْرَفَ عَلَى أُطُمٍ مِنْ آطَامِ الْمَدِينَةِ ثُمَّ قَالَ هَلْ تَرَوْنَ مَا أَرَى إِنِّي لَأَرَى مَوَاقِعَ الْفِتَنِ خِلَالَ بُيُوتِكُمْ كَمَوَاقِعِ الْقَطْرِو حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], [Amru bin An Naqid], [Ishaq bin Ibrahim] dan [Ibnu Abi Umar], teks milik Ibnu Abi Syaibah. Berkata Ishaq: telah mengkhabarkan kepada kami, sedangkan yang lain berkata: telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dar [Usamah] nabi Shallallahu 'alaihi wa Salam naik ke salah satu benteng Madinah lalu beliau bertanya: \"Apa kalian melihat yang aku lihat? Sesungguhnya aku melihat tempat-tempat terjadinya fitnah disela-sela rumah kalian seperti tempat jatuhnya hujan.\" Telah menceritakan kepada kami [Abdu bin Humaid] telah mengkhabarkan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan sanad ini dengan matan serupa."},"4766":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ وَالْحَسَنُ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي ابْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ فِتَنٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي مَنْ تَشَرَّفَ لَهَا تَسْتَشْرِفُهُ وَمَنْ وَجَدَ فِيهَا مَلْجَأً فَلْيَعُذْ بِهِحَدَّثَنَا عَمْرٌو النَّاقِدُ وَالْحَسَنُ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُطِيعِ بْنِ الْأَسْوَدِ عَنْ نَوْفَلِ بْنِ مُعَاوِيَةَ مِثْلَ حَدِيثِ أَبِي هُرَيْرَةَ هَذَا إِلَّا أَنَّ أَبَا بَكْرٍ يَزِيدُ مِنْ الصَّلَاةِ صَلَاةٌ مَنْ فَاتَتْهُ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ","id":"Telah menceritakan kepadaku [Amru An Naqid], [Al Hasan Al Hulwani] dan [Abdu bin Humaid] berkata Abdu: telah mengkhabarkan kepadaku, sedangkan yang lain berkata: telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku [Ibnu Al Musayyib] da [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Akan terjadi fitnah-fintah, orang duduk saat itu lebih baik dari orang yang berdiri, orang yang berdiri saat itu lebi baik dari orang yang berjalan dan orang yang berjalan saat itu lebih baik dari orang yang berlari-lari kecil, barangsiapa menceburkan dirinya pada fitnah-fitnah itu, ia akan kalah dan barangsiapa menemukan tempat berlindung saat itu, hendaklah berlindung.\" Telah menceritakan kepada kami [Amru An Naqid], [Al Hasan Al Hulwani] dan [Abdu bin Humaid], berkata Abdu: telah mengkhabarkan kepadaku, sedangkan yang lain berkata: telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Shiyab] telah menceritakan kepadaku [Abu Bakr bin Abdurrahman] dari [Abdurrahman bin Muthi' bin Al Aswad] dari [Naufal bin Mu'awiyah] seperti hadits [Abu Hurairah] ini, hanya saja Abu Bakar menambahkan dalam riwayatnya: Di antara beberapa shalat, ada satu shalat, barangsiapa meninggalkannya, seolah-olah keluarga dan hartanya ditinggalkan."},"4767":{"ar":"حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ فِتْنَةٌ النَّائِمُ فِيهَا خَيْرٌ مِنْ الْيَقْظَانِ وَالْيَقْظَانُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ السَّاعِي فَمَنْ وَجَدَ مَلْجَأً أَوْ مَعَاذًا فَلْيَسْتَعِذْ","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] telah mengkhabarkan kepada kami [Abu Dawud Ath Thayalisi] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [ayahnya] dari [Abu Salamah] dari [Abu Hurairah] berkata: Nabi Shallallahu 'alaihi wa Salam bersabda: \"Akan terjadi fitnah, orang tidur saat itu lebih baik dari orang terjaga, orang terjaga saat itu lebih baik dari orang yang berdiri dan orang yang berdiri saat itu lebih baik dari orang yang berjalan cepat. Barangsiapa menemukan tempat berlindung, hendaklah berlindung.\""},"4768":{"ar":"حَدَّثَنِي أَبُو كَامِلٍ الْجَحْدَرِيُّ فُضَيْلُ بْنُ حُسَيْنٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عُثْمَانُ الشَّحَّامُ قَالَ انْطَلَقْتُ أَنَا وَفَرْقَدٌ السَّبَخِيُّ إِلَى مُسْلِمِ بْنِ أَبِي بَكْرَةَ وَهُوَ فِي أَرْضِهِ فَدَخَلْنَا عَلَيْهِ فَقُلْنَا هَلْ سَمِعْتَ أَبَاكَ يُحَدِّثُ فِي الْفِتَنِ حَدِيثًا قَالَ نَعَمْ سَمِعْتُ أَبَا بَكْرَةَ يُحَدِّثُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ فِتَنٌ أَلَا ثُمَّ تَكُونُ فِتْنَةٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْمَاشِي فِيهَا وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي إِلَيْهَا أَلَا فَإِذَا نَزَلَتْ أَوْ وَقَعَتْ فَمَنْ كَانَ لَهُ إِبِلٌ فَلْيَلْحَقْ بِإِبِلِهِ وَمَنْ كَانَتْ لَهُ غَنَمٌ فَلْيَلْحَقْ بِغَنَمِهِ وَمَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَلْحَقْ بِأَرْضِهِ قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَرَأَيْتَ مَنْ لَمْ يَكُنْ لَهُ إِبِلٌ وَلَا غَنَمٌ وَلَا أَرْضٌ قَالَ يَعْمِدُ إِلَى سَيْفِهِ فَيَدُقُّ عَلَى حَدِّهِ بِحَجَرٍ ثُمَّ لِيَنْجُ إِنْ اسْتَطَاعَ النَّجَاءَ اللَّهُمَّ هَلْ بَلَّغْتُ اللَّهُمَّ هَلْ بَلَّغْتُ اللَّهُمَّ هَلْ بَلَّغْتُ قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ أُكْرِهْتُ حَتَّى يُنْطَلَقَ بِي إِلَى أَحَدِ الصَّفَّيْنِ أَوْ إِحْدَى الْفِئَتَيْنِ فَضَرَبَنِي رَجُلٌ بِسَيْفِهِ أَوْ يَجِيءُ سَهْمٌ فَيَقْتُلُنِي قَالَ يَبُوءُ بِإِثْمِهِ وَإِثْمِكَ وَيَكُونُ مِنْ أَصْحَابِ النَّارِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ كِلَاهُمَا عَنْ عُثْمَانَ الشَّحَّامِ بِهَذَا الْإِسْنَادِ حَدِيثُ ابْنِ أَبِي عَدِيٍّ نَحْوَ حَدِيثِ حَمَّادٍ إِلَى آخِرِهِ وَانْتَهَى حَدِيثُ وَكِيعٍ عِنْدَ قَوْلِهِ إِنْ اسْتَطَاعَ النَّجَاءَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","id":"Telah menceritakan kepadaku [Abu Kamil Al Jahdari Fudhail bin Husain] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Utsman Asy Syahham] berkata: Aku pergi bersama Farqad As Sabakhi untuk menemui [Muslim bin Abu Bakrah] di kawasannya. Kami memasuki kediamannya lalu kami bertanya: Apakah kau mendengar ayahmu menceritakan suatu hadits tentang tentang fitnah? Ia menjawab: Ya, aku pernah mendengar [Abu Bakrah] menceritakan, ia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya akan terjadi fitnah-fitnah, ingat, setelah itu terjadi fitnah, orang duduk saat itu lebih baik dari pada yang berjalan dan yang berjalan saat itu lebih baik dari yang berlari kecil menujunya. Ingat, bila fitnah terjadi, barangsiapa memiliki unta, hendaklah menyusul dengan untanya, barangsiapa memiliki kambing, hendaklah menyusul dengan kambingnya dan barangsiapa memiliki tanah, hendaklah menyusul dengan tanahnya.\" Seseorang bertanya: Wahai Rasulullah, menurut Tuan bagaimana dengan orang yang tidak memiliki onta, kambing atau tanah? Beliau menjawab: \"Ia berpegangan pada pedangnya lalu memukulkan bagian tajamnya ke batu kemudian hendaklah menyelamatkan diri bila mampu. Ya Allah, apakah telah aku sampaikan, Ya Allah, apakah telah aku sampaikan, Ya Allah, apakah telah aku sampaikan?\" seseorang bertanya: Wahai Rasulullah, menurut Tuan bagaimana bila aku dipaksa hingga aku dibawa menuju salah satu dari kedua kubu atau salah satu dari dua kelompok lalu seseorang menebasku dengan pedangnya atau anak panah menimpaku lalu membunuhku? Beliau menjawab: \"Ia datang membawa dosanya dan dosamu dan ia termasuk penghuni neraka.\" telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: Telah menceritakan kepada kami [Waki']. Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abi Adi] keduanya dari [Utsman Asy Syahham] dengan sanad ini hadits Ibnu Abi Adi seperti hadits Hamad hingga akhirnya. Hadits Waki' sampai pada sabda: \"Bila mampu menyelamatkan diri, \" dan tidak menyebut setelahnya."},"4769":{"ar":"حَدَّثَنِي أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ وَيُونُسَ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَ خَرَجْتُ وَأَنَا أُرِيدُ هَذَا الرَّجُلَ فَلَقِيَنِي أَبُو بَكْرَةَ فَقَالَ أَيْنَ تُرِيدُ يَا أَحْنَفُ قَالَ قُلْتُ أُرِيدُ نَصْرَ ابْنِ عَمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي عَلِيًّا قَالَ فَقَالَ لِي يَا أَحْنَفُ ارْجِعْ فَإِنِّيسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قَالَ فَقُلْتُ أَوْ قِيلَ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ قَدْ أَرَادَ قَتْلَ صَاحِبِهِ","id":"Telah menceritakan kepadaku [Abu Kamil Fudhail bin Husain Al Jahdari] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dan [Yunus] dari [Al Hasan] dari [Al Ahnaf bin Qais] berkata: Aku pergi untuk menemui orang ini lalu [Abu Bakrah] menemuiku, ia bertanya: Kamu mau kemana wahai Ahnaf? Aku menjawab: Aku hendak menemui Nashr putra paman Rasulullah Shallallahu 'alaihi wa Salam -maksudnya Ali. Lalu ia berkata: Wahai Ahnaf, kembalilah karena aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila dua orang muslim berhadapan dengan pedang, pembunuh dan yang terbunuh ada dineraka.\" Aku berkata: Atau dikatakan: Wahai Rasulullah, ia yang membunuh (pantas masuk neraka), lalu bagaimana dengan yang terbunuh? Beliau menjawab: \"Sesungguhnya ia ingin membunuh kawannya.\" "},"4770":{"ar":"و حَدَّثَنَاه أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ وَيُونُسَ وَالْمُعَلَّى بْنِ زِيَادٍ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِو حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ مِنْ كِتَابِهِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ أَبِي كَامِلٍ عَنْ حَمَّادٍ إِلَى آخِرِهِ","id":"Telah menceritakannya kepada kami [Ahmad bin Abdah Adh Dhabi] telah menceritakan kepada kami [Hammad] dari [Ayyub], [Yunus] dan [Al Mu'ala bin Ziyad] dari [Al Hasan] dari [Al Ahnaf bin Qais] dari [Abu Bakrah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Bila dua orang muslim berhadapan dengan pedang, pembunuh dan yang terbunuh ada dineraka.\" Telah menceritakan kepadaku [Hajjaj bin Asy Sya'ir] telah menceritakan kepada kami [Abdurrazzaq] dari kitabnya, telah mengkhabarkan kepada kami [Ma'mar] dari [Ayyub] dengan sanad ini seperti hadits Abu Kamil dari Hammad hingga akhir."},"4771":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا الْمُسْلِمَانِ حَمَلَ أَحَدُهُمَا عَلَى أَخِيهِ السِّلَاحَ فَهُمَا عَلَى جُرْفِ جَهَنَّمَ فَإِذَا قَتَلَ أَحَدُهُمَا صَاحِبَهُ دَخَلَاهَا جَمِيعًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaiba] telah menceritakan kepada kami [Ghundar] dari [Syu'bah]. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata: telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Rib'I bin Hirasy] dari [Abu Bakrah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Bila ada dua orang muslim yang salah satunya membawa pedang (untuk menyerang) saudaranya, keduanya berada ditepi neraka jahanam, bila salah satunya membunuh kawannya, kedua-duanya masuk neraka jahanam.\""},"4772":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَقْتَتِلَ فِئَتَانِ عَظِيمَتَانِ وَتَكُونُ بَيْنَهُمَا مَقْتَلَةٌ عَظِيمَةٌ وَدَعْوَاهُمَا وَاحِدَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] berkata: Inilah yang diceritakan [Abu Hurairah] dari Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut beberapa hadits diantaranya; Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga dua kubu besar berperang, terjadi perang besar diantara keduanya dan seruan keduanya sama.\""},"4773":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَكْثُرَ الْهَرْجُ قَالُوا وَمَا الْهَرْجُ يَا رَس��ولَ اللَّهِ قَالَ الْقَتْلُ الْقَتْلُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiama tidak terjadi hingga banyak (terjadi) haraj.\" Mereka bertanya: Apa itu haraj, wahai Rasulullah? beliau menjawab: \"Pembunuhan, pembunuhan.\""},"4774":{"ar":"حَدَّثَنَا أَبُو الرَّبِيعِ الْعَتَكِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ كِلَاهُمَا عَنْ حَمَّادِ بْنِ زَيْدٍ وَاللَّفْظُ لِقُتَيْبَةَ حَدَّثَنَا حَمَّادٌ عَنْ أَيَّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ زَوَى لِي الْأَرْضَ فَرَأَيْتُ مَشَارِقَهَا وَمَغَارِبَهَا وَإِنَّ أُمَّتِي سَيَبْلُغُ مُلْكُهَا مَا زُوِيَ لِي مِنْهَا وَأُعْطِيتُ الْكَنْزَيْنِ الْأَحْمَرَ وَالْأَبْيَضَ وَإِنِّي سَأَلْتُ رَبِّي لِأُمَّتِي أَنْ لَا يُهْلِكَهَا بِسَنَةٍ عَامَّةٍ وَأَنْ لَا يُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ سِوَى أَنْفُسِهِمْ فَيَسْتَبِيحَ بَيْضَتَهُمْ وَإِنَّ رَبِّي قَالَ يَا مُحَمَّدُ إِنِّي إِذَا قَضَيْتُ قَضَاءً فَإِنَّهُ لَا يُرَدُّ وَإِنِّي أَعْطَيْتُكَ لِأُمَّتِكَ أَنْ لَا أُهْلِكَهُمْ بِسَنَةٍ عَامَّةٍ وَأَنْ لَا أُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ سِوَى أَنْفُسِهِمْ يَسْتَبِيحُ بَيْضَتَهُمْ وَلَوْ اجْتَمَعَ عَلَيْهِمْ مَنْ بِأَقْطَارِهَا أَوْ قَالَ مَنْ بَيْنَ أَقْطَارِهَا حَتَّى يَكُونَ بَعْضُهُمْ يُهْلِكُ بَعْضًا وَيَسْبِي بَعْضُهُمْ بَعْضًاو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى زَوَى لِي الْأَرْضَ حَتَّى رَأَيْتُ مَشَارِقَهَا وَمَغَارِبَهَا وَأَعْطَانِي الْكَنْزَيْنِ الْأَحْمَرَ وَالْأَبْيَضَ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ أَيُّوبَ عَنْ أَبِي قِلَابَةَ","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Al Ataki] dan [Qutaibah bin Sa'id], keduanya dari [Hammad bin Zaid] dan teksnya milik Qutaibah, telah menceritakan kepada kami [Hammad] dari [Ayub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah menghimpun bumi untukku lalu aku melihat timur dan baratnya dan sesungguhnya kekuasaan ummatku akan mencapai yang dihimpunkan untukku, aku diberi dua harta simpanan; merah dan putih, dan sesungguhnya aku meminta Rabbku untuk ummatku agar tidak dibinasakan oleh kekeringan menyeluruh, agar Ia tidak memberi kuasa musuh untuk menguasai mereka selain diri mereka sendiri lalu menyerang perkumpulan mereka, dan sesungguhnya Rabbku berfirman: 'Hai Muhammad, sesungguhnya Aku bila menentukan takdir tidak bisa dirubah, sesungguhnya Aku memberikan untuk umatmu agar tidak dibinasakan oleh kekeringan menyeluruh, Aku tidak memberi kuasa musuh untuk menyerang mereka selain diri mereka sendiri lalu mereka menyerang perkumpulan mereka meski mereka dikepung dari segala penjurunya hingga sebagaian dari mereka membinasakan sebagaian lainnya dan saling menawan satu sama lain.\" Telah menceritakan kepadaku [Zuhair bin Harb], [Ishaq bin Ibrahim], [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], berkata Ishaq: Telah mengkhabarkan kepada kami, sedangkan yang lain berkata: telah menceritakan kepada kami [Mu'adz bin Hiysam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Abu Qilabah] dari [Abu Asma` Ar Rahabi] dari [Tsauban] bahwa nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah menghimpun bumi untukku hingga aku melihat timur dan baratnya, dan Ia memberiku dua harta simpanan; merah dan putih.\" Selanjutnya ia menyebut seperti hadits Ayyub dari Abu Qilabah."},"4775":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ ذَاتَ يَوْمٍ مِنْ الْعَالِيَةِ حَتَّى إِذَا مَرَّ بِمَسْجِدِ بَنِي مُعَاوِيَةَ دَخَلَ فَرَكَعَ فِيهِ رَكْعَتَيْنِ وَصَلَّيْنَا مَعَهُ وَدَعَا رَبَّهُ طَوِيلًا ثُمَّ انْصَرَفَ إِلَيْنَا فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلْتُ رَبِّي ثَلَاثًا فَأَعْطَانِي ثِنْتَيْنِ وَمَنَعَنِي وَاحِدَةً سَأَلْتُ رَبِّي أَنْ لَا يُهْلِكَ أُمَّتِي بِالسَّنَةِ فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يُهْلِكَ أُمَّتِي بِالْغَرَقِ فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يَجْعَلَ بَأْسَهُمْ بَيْنَهُمْ فَمَنَعَنِيهَاو حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ الْأَنْصَارِيُّ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِ أَنَّهُ أَقْبَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَائِفَةٍ مِنْ أَصْحَابِهِ فَمَرَّ بِمَسْجِدِ بَنِي مُعَاوِيَةَ بِمِثْلِ حَدِيثِ ابْنِ نُمَيْرٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. Telah menceritakan kepada kami [Ibnu Numair] dan teksnya milik Ibnu Numair, telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Utsman bin Hakim] telah mengkhabarkan kepadaku [Amir bin Sa'ad] dar [ayahnya], pada suatu hari, Rasulullah Shallallahu 'alaihi wa Salam pulang dari tempat tinggi hingga saat beliau melintasi masjid bani Mu'awiyah, beliau masuk lalu shalat dua rakaat, kami shalat bersama beliau. Beliau berdoa lama sekali kepada Rabbnya, setelah itu beliau menemui kami, nabi Shallallahu 'alaihi wa Salam bersabda: \"Aku meminta tiga (hal) pada Rabbku, Ia mengabulkan dua (hal) dan menolakku satu (hal). Aku meminta Rabbku agar tidak membinasakan ummatku dengan kekeringan, Ia mengabulkannya untukku, aku memintaNya agar tidak membinasakan ummatku dengan banjir, Ia mengabulkannya untukku dan aku memintaNya agar tidak membuat penyerangan diantara sesama mereka lalu Ia menolaknya.\" Telah menceritakannya kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Utsman bin Hakim Al Anshari] telah mengkhabarkan kepadaku [Amir bin Sa'ad] dari [ayahnya] ia pulang bersama Rasulullah Shallallahu 'alaihi wa Salam dalam sekelompok sahabat-sahabat beliau, beliau melintasi masjid bani Mu'awiyah, seperti hadits Ibnu Numair."},"4776":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا إِدْرِيسَ الْخَوْلَانِيَّ كَانَ يَقُولُاقَالَ حُذَيْفَةُ بْنُ الْيَمَانِ وَاللَّهِ إِنِّي لَأَعْلَمُ النَّاسِ بِكُلِّ فِتْنَةٍ هِيَ كَائِنَةٌ فِيمَا بَيْنِي وَبَيْنَ السَّاعَةِ وَمَا بِي إِلَّا أَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَرَّ إِلَيَّ فِي ذَلِكَ شَيْئًا لَمْ يُحَدِّثْهُ غَيْرِي وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ يُحَدِّثُ مَجْلِسًا أَنَا فِيهِ عَنْ الْفِتَنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَعُدُّ الْفِتَنَ مِنْهُنَّ ثَلَاثٌ لَا يَكَدْنَ يَذَرْنَ شَيْئًا وَمِنْهُنَّ فِتَنٌ كَرِيَاحِ الصَّيْفِ مِنْهَا صِغَارٌ وَمِنْهَا كِبَارٌقَالَ حُذَيْفَةُ فَذَهَبَ أُولَئِكَ الرَّهْطُ كُلُّهُمْ غَيْرِي","id":"Telah menceritakan kepada kami [Harmalah bin Yahya At Tujibi] telah mengkhabarkan kepada kami [Ibnu Wahb] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Abu Idris Al Khaulani] berkata: [Hudzaifah bin Al Yaman] berkata: Demi Allah, sesungguhnya aku adalah orang yang paling tahu tentang fitnah yang terjadi antara aku hingga kiamat. Itu karena Rasulullah Shallallahu 'alaihi wa Salam memberitahukan sesuatu tentang hal itu secara rahasia, beliau tidak menceritakannya pada selainku, tapi Rasulullah Shallallahu 'alaihi wa Salam bercerita tentang fitnah kepada majlis dimana aku berada disana, Rasulullah Shallallahu 'alaihi wa Salam bersabda, beliau menghitung fitnah-fitnah, diantaranya ada tiga fitnah yang hampir tidak meninggalkan apa pun, ada fitnah-fitnah seperti angin musim panas, ada yang kecil dan ada yang besar. Hudzaifah berkata: Lalu mereka pergi semua kecuali aku."},"4777":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ عُثْمَانُ حَدَّثَنَا و قَالَ إِسْحَقُ أَخْبَرَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَامًا مَا تَرَكَ شَيْئًا يَكُونُ فِي مَقَامِهِ ذَلِكَ إِلَى قِيَامِ السَّاعَةِ إِلَّا حَدَّثَ بِهِ حَفِظَهُ مَنْ حَفِظَهُ وَنَسِيَهُ مَنْ نَسِيَهُ قَدْ عَلِمَهُ أَصْحَابِي هَؤُلَاءِ وَإِنَّهُ لَيَكُونُ مِنْهُ الشَّيْءُ قَدْ نَسِيتُهُ فَأَرَاهُ فَأَذْكُرُهُ كَمَا يَذْكُرُ الرَّجُلُ وَجْهَ الرَّجُلِ إِذَا غَابَ عَنْهُ ثُمَّ إِذَا رَآهُ عَرَفَهُو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ إِلَى قَوْلِهِ وَنَسِيَهُ مَنْ نَسِيَهُ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], berkata Utsman: Telah menceritakan kepada kami, sedangan Ishaq berkata: Telah mengkhabarkan kepada kami [Jarir] dari [Al A'masy] dari [Syaqiq] dari [Hudzaifah] berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri ditengan-tengah kami, beliau memberitahukan kepada kami apa saja yang terjadi hingga hari kiamat, yang menghafalnya hafal dan yang melupakannya lupa. Para sahabatku mengetahuinya dan ada sesuatu yang terlupakan olehku, aku memikirkannya kemudian aku ingat seperti seseorang teringat pada wajah orang lain bila pergi meninggalkannya, bila ia melihatnya, ia mengenalinya.\" Telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] dan [Waki'] dari [Sufyan] dari [Al A'masy] dengan sanad ini sampai perkataannya: Dan yang melupakannya lupa. Ia tidak menyebut selanjutnya."},"4778":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ حُذَيْفَةَ أَنَّهُ قَالَأَخْبَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا هُوَ كَائِنٌ إِلَى أَنْ تَقُومَ السَّاعَةُ فَمَا مِنْهُ شَيْءٌ إِلَّا قَدْ سَأَلْتُهُ إِلَّا أَنِّي لَمْ أَسْأَلْهُ مَا يُخْرِجُ أَهْلَ الْمَدِينَةِ مِنْ الْمَدِينَةِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي وَهْبُ بْنُ جَرِيرٍ أَخْبَرَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah]. Telah menceritakan kepadaku [Abu Bakr bin Nafi'] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Adi bin Tsabit] dari [Abdullah bin Yazid] dari [Hudzaifah] ia berkata: Telah mengkhabarkan kepadaku Rasulullah Shallallahu 'alaihi wa Salam apa yang akan terjadi hingga kiamat. Segala sesuatunya telah aku tanyakan kepada beliau, hanya saja kau tidak menanyakan apa yang mengusir penduduk Madinah dari Madinah. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Wahb bin Jarir] telah mengkhabarkan kepada kami [Syu'bah] dengan sanad ini dengan matan serupa."},"4779":{"ar":"و حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَحَجَّاجُ بْنُ الشَّاعِرِ جَمِيعًا عَنْ أَبِي عَاصِمٍ قَالَ حَجَّاجٌ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا عَزْرَةُ بْنُ ثَابِتٍ أَخْبَرَنَا عِلْبَاءُ بْنُ أَحْمَرَ حَدَّثَنِي أَبُو زَيْدٍ يَعْنِي عَمْرَو بْنَ أَخْطَبَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ وَصَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى حَضَرَتْ الظُّهْرُ فَنَزَلَ فَصَلَّى ثُمَّ صَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى حَضَرَتْ الْعَصْرُ ثُمَّ نَزَلَ فَصَلَّى ثُمَّ صَعِدَ الْمِنْبَرَ فَخَطَبَنَا حَتَّى غَرَبَتْ الشَّمْسُ فَأَخْبَرَنَا بِمَا كَانَ وَبِمَا هُوَ كَائِنٌ فَأَعْلَمُنَا أَحْفَظُنَا","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim Ad Dauraqi] dan [Hajjaj bin Asy Sya'ir] semuanya dari [Abu Ashim] berkata [Hajjaj]: telah menceritakan kepada kami [Abu Ashim] telah mengkhabarkan kepada kami [Azrah bin Tsabit] telah mengkhabarkan kepada kami [Ilba` bin Ahmar] telah menceritakan kepadaku [Abu Zaid Amru bin Akhthab] berkata: Rasulullah Shallallahu 'alaihi wa Salam shalat fajar bersama kami, beliau naik mimbar lalu berkhutbah hingga waktu zhuhur tiba, beliau turun lalu naik mimbar kemudian berkhutbah hingga tiba waktu ashar, beliau turun lalu shalat, setelah itu beliau naik mimbar kemudian berkhutbah hingga matahari terbenam, beliau memberitahukan apa yang telah terjadi dan apa yang akan terjadi. Yang paling tahu diantara kami adalah yang paling hafal."},"4780":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَمُحَمَّدُ بْنُ الْعَلَاءِ أَبُو كُرَيْبٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ قَالَ ابْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَكُنَّا عِنْدَ عُمَرَ فَقَالَ أَيُّكُمْ يَحْفَظُ حَدِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتْنَةِ كَمَا قَالَ قَالَ فَقُلْتُ أَنَا قَالَ إِنَّكَ لَجَرِيءٌ وَكَيْفَ قَالَ قَالَ قُلْتُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَمَالِهِ وَنَفْسِهِ وَوَلَدِهِ وَجَارِهِ يُكَفِّرُهَا الصِّيَامُ وَالصَّلَاةُ وَالصَّدَقَةُ وَالْأَمْرُ بِالْمَعْرُوفِ وَالنَّهْيُ عَنْ الْمُنْكَرِ فَقَالَ عُمَرُ لَيْسَ هَذَا أُرِيدُ إِنَّمَا أُرِيدُ الَّتِي تَمُوجُ كَمَوْجِ الْبَحْرِ قَالَ فَقُلْتُ مَا لَكَ وَلَهَا يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ بَيْنَكَ وَبَيْنَهَا بَابًا مُغْلَقًا قَالَ أَفَيُكْسَرُ الْبَابُ أَمْ يُفْتَحُ قَالَ قُلْتُ لَا بَلْ يُكْسَرُ قَالَ ذَلِكَ أَحْرَى أَنْ لَا يُغْلَقَ أَبَدًا قَالَ فَقُلْنَا لِحُذَيْفَةَ هَلْ كَانَ عُمَرُ يَعْلَمُ مَنْ الْبَابُ قَالَ نَعَمْ كَمَا يَعْلَمُ أَنَّ دُونَ غَدٍ اللَّيْلَةَ إِنِّي حَدَّثْتُهُ حَدِيثًا لَيْسَ بِالْأَغَالِيطِ قَالَ فَهِبْنَا أَنْ نَسْأَلَ حُذَيْفَةَ مَنْ الْبَابُ فَقُلْنَا لِمَسْرُوقٍ سَلْهُ فَسَأَلَهُ فَقَالَ عُمَرُو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا يَحْيَى بْنُ عِيسَى كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ أَبِي مُعَاوِيَةَ وَفِي حَدِيثِ عِيسَى عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ سَمِعْتُ حُذَيْفَةَ يَقُولُ و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ وَالْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَ قَالَ عُمَرُ مَنْ يُحَدِّثُنَا عَنْ الْفِتْنَةِ وَاقْتَصَّ الْحَدِيثَ بِنَحْوِ حَدِيثِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Muhammad bin Al Ala` Abu Kuraib] dari [Abu Mu'awiyah] berkata [Ibnu Al Ala`] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Hudzaifah] berkata: Kami berada di kediaman Umar lalu ia bertanya: Siapa diantara kalian yang hafal hadits Rasulullah shallallahu 'alaihi wasallam tentang fitnah seperti yang beliau sabdakan? Hudzaifah bin Al Yaman menjawab: Aku. Umar berkata: Sesungguhnya kau gegabah, apa yang beliau sampaikan? Aku (Hudzaifah bin Al Yaman) berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Fitnah seseorang terhadap keluarga, harta dan tetangganya yang (dosanya) bisa dihapus dengan shalat, sedekah, memerintahkan kebaikan dan mencegah kemungkaran.\" Umar berkata: Bukan itu yang aku maksud, tapi fitnah yang bergelombang layaknya samudera. Aku berkata: Kau tidak bermasalah dengannya wahai Amirul Mu`minin, sesungguhnya diantaramu dengan fitnah itu ada pintu yang tertutup. Umar bertanya: Apakah pintunya didobrak atau dibuka? Hudzaifah menjawab: Didobrak. Umar berkata: Kalau begitu layak tidak tertutup selamanya. Kami bertanya kepada Hudzaifah: Apakah Umar tahu siapakah pintu itu? Hudzaifah menjawab: Ya, seperti halnya ia tahu bahwa yang menghalangi hari ini dan hari esok adalah malam hari. Aku menceritakan suatu hadits yang tidak keliru padanya. Kami berkata kepada Masruq: Tanyakan padanya. Ia pun bertanya lalu ia menjawab: Umar. Telah menceritakannya kepada kami [Abu Bakar bin Abi Syaibah] dan [Abu Sa'id Al Asyaj] berkata telah menceritakan kepadaku [Waki'] dan telah menceritakan kepadaku [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir]. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Isa bin Yunus]. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Yahya bin Isa], semuanya dari [Al A'masy] dan sanad ini seperti hadits Abu Mu'awiyah. Disebutkan dalam hadits Isa dari Al A'masy dari Syaqiq: Ia berkata: Aku mendengar Hudzaifah berkata. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Jami' bin Abu Rasyid] dan [Al A'masy] dari [Abu Wa`il] dari [Hudzaifah] berkata: Umar berkata: Siapa yang mau menceritakan kepada kami tentang fitnah, lalu ia menceritakan hadits seperti hadits mereka."},"4781":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ حَاتِمٍ قَالَا حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ قَالَ جُنْدُبٌ جِئْتُ يَوْمَ الْجَرَعَةِ فَإِذَا رَجُلٌ جَالِسٌ فَقُلْتُلَيُهْرَاقَنَّ الْيَوْمَ هَاهُنَا دِمَاءٌ فَقَالَ ذَاكَ الرَّجُلُ كَلَّا وَاللَّهِ قُلْتُ بَلَى وَاللَّهِ قَالَ كَلَّا وَاللَّهِ قُلْتُ بَلَى وَاللَّهِ قَالَ كَلَّا وَاللَّهِ إِنَّهُ لَحَدِيثُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِيهِ قُلْتُ بِئْسَ الْجَلِيسُ لِي أَنْتَ مُنْذُ الْيَوْمِ تَسْمَعُنِي أُخَالِفُكَ وَقَدْ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَنْهَانِي ثُمَّ قُلْتُ مَا هَذَا الْغَضَبُ فَأَقْبَلْتُ عَلَيْهِ وَأَسْأَلُهُ فَإِذَا الرَّجُلُ حُذَيْفَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Hatim] keduanya berkata: Telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Ibnu Abun] dari [Muhammad] berkata: [Jundub] berkata: Saat terjadi peristiwa Jara'ah (nama tempat didekat Kufah) ternyata ada seseorang yang tengah duduk, aku berkata: Hari ini, darah akan bertumpahan disini. Orang itu berkata: Tidak, demi Allah. Aku berkata: Ya, demi Allah. Orang itu berkata: Tidak, demi Allah. Aku berkata: Ya, demi Allah. Itu adalah hadits Rasulullah Shallallahu 'alaihi wa Salam yang beliau sampaikan kepadaku. Aku berkata: Kau adalah teman terburukku sejak hari ini, kau mendengarku aku menyelisihimu padahal aku pernah mendengar dari Rasulullah Shallallahu 'alaihi wa Salam, karena itu jangan kau larang aku. Setelah itu aku berkata: Kenapa marah? Aku menghampirinya lalu bertanya padanya, ternyata ia adalah [Hudzaifah]."},"4782":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ الْقَارِيَّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَحْسِرَ الْفُرَاتُ عَنْ جَبَلٍ مِنْ ذَهَبٍ يَقْتَتِلُ النَّاسُ عَلَيْهِ فَيُقْتَلُ مِنْ كُلِّ مِائَةٍ تِسْعَةٌ وَتِسْعُونَ وَيَقُولُ كُلُّ رَجُلٍ مِنْهُمْ لَعَلِّي أَكُونُ أَنَا الَّذِي أَنْجُوو حَدَّثَنِي أُمَيَّةُ بْنُ بِسْطَامَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ عَنْ سُهَيْلٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَزَادَ فَقَالَ أَبِي إِنْ رَأَيْتَهُ فَلَا تَقْرَبَنَّهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qari`] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga Furat mengumpulkan emas dari gunung, orang-orang berperang karenanya. Setiap seratus orang, sembilanpuluh sembilan diantaranya terbunuh dan setiap orang diantara mereka berkata: Siapa tahu akulah orang yang selamat.\" Telah menceritakan kepadaku [Umaiyah bin Bistham] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] dari [Suhail] dengan sanad ini dengan matan serupa. Ayahku berkata: Bila kau melihatnya, jangan mendekat."},"4783":{"ar":"حَدَّثَنَا أَبُو مَسْعُودٍ سَهْلُ بْنُ عُثْمَانَ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ السَّكُونِيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ كَنْزٍ مِنْ ذَهَبٍ فَمَنْ حَضَرَهُ فَلَا يَأْخُذْ مِنْهُ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Mas'ud Sahl bin Utsman] telah menceritakan kepada kami [Uqbah bin Khalid As Sakuni] dari [Ubaidullah] dari [Khubaib bin Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hampir saja Furat mengumpulkan harta simpanan dari emas, barangsiapa menghadirinya, jangan mengambil apa pun.\""},"4784":{"ar":"حَدَّثَنَا سَهْلُ بْنُ عُثْمَانَ حَدَّثَنَا عُقْبَةُ بْنُ خالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَمَنْ حَضَرَهُ فَلَا يَأْخُذْ مِنْهُ شَيْئًا","id":"Telah menceritakan kepada kami [Sahl bin Utsman] telah menceritakan kepada kami [Uqbah bin Khalid] dari [Ubaidullah] dari [Abu Az Zinad] dari [Abdurrahman Al A'raj] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hampir saja Furat mengumpulkan harta simpanan dari emas, barangsiapa menghadirinya, jangan mengambil apa pun.\""},"4785":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ فُضَيْلُ بْنُ حُسَيْنٍ وَأَبُو مَعْنٍ الرَّقَاشِيُّ وَاللَّفْظُ لِأَبِي مَعْنٍ قَالَا حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ قَالَ كُنْتُ وَاقِفًا مَعَ أُبَيِّ بْنِ كَعْبٍ فَقَالَ لَا يَزَالُ النَّاسُ مُخْتَلِفَةً أَعْنَاقُهُمْ فِي طَلَبِ الدُّنْيَا قُلْتُ أَجَلْ قَالَ إِنِّيسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَإِذَا سَمِعَ بِهِ النَّاسُ سَارُوا إِلَيْهِ فَيَقُولُ مَنْ عِنْدَهُ لَئِنْ تَرَكْنَا النَّاسَ يَأْخُذُونَ مِنْهُ لَيُذْهَبَنَّ بِهِ كُلِّهِ قَالَ فَيَقْتَتِلُونَ عَلَيْهِ فَيُقْتَلُ مِنْ كُلِّ مِائَةٍ تِسْعَةٌ وَتِسْعُونَقَالَ أَبُو كَامِلٍ فِي حَدِيثِهِ قَالَ وَقَفْتُ أَنَا وَأُبَيُّ بْنُ كَعْبٍ فِي ظِلِّ أُجُمِ حَسَّانَ","id":"Telah menceritakan kepada kami [Abu Kamil Fudhail bin Husain] dan [Abu Ma'nu Ar Raqasyi], teks milik Abu Ma'nu, keduanya berkata: Telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Abdulhamid bin Ja'far] telah mengkhabarkan kepadaku [ayahku] dari [Sulaiman bin Yasar] dari [Abdullah bin Al Harits bin Naufal] berkata: Aku pernah istirahat bersama [Ubai bin Ka'ab]. Ia berkata: Orang-orang terus sibuk mencari dunia. Aku menjawab: Benar. Ia berkata: Aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hampir saja Furat mengumpulkan harta simpanan dari emas. Saat mendengarnya, orang-orang menghampirinya lalu orang yang didekatnya berkata: 'Bila kita biarkan orang-orang mengambilnya, mereka akan menghabiskan semuanya.\" Beliau bersabda: \"Mereka berperang karenanya, dari setiap seratus orang, sembilanpuluh sembilannya terbunuh.\" Abu Kamil berkata dalam haditsnya: Ia berkata: Aku dan Ubai bin Ka'ab istirahat di bawah naungan kebun Hassan."},"4786":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ يَعِيشَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِعُبَيْدٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ آدَمَ بْنِ سُلَيْمَانَ مَوْلَى خَالِدِ بْنِ خَالِدٍ حَدَّثَنَا زُهَيْرٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنَعَتْ الْعِرَاقُ دِرْهَمَهَا وَقَفِيزَهَا وَمَنَعَتْ الشَّأْمُ مُدْيَهَا وَدِينَارَهَا وَمَنَعَتْ مِصْرُ إِرْدَبَّهَا وَدِينَارَهَا وَعُدْتُمْ مِنْ حَيْثُ بَدَأْتُمْ وَعُدْتُمْ مِنْ حَيْثُ بَدَأْتُمْ وَعُدْتُمْ مِنْ حَيْثُ بَدَأْتُمْ شَهِدَ عَلَى ذَلِكَ لَحْمُ أَبِي هُرَيْرَةَ وَدَمُهُ","id":"Telah menceritakan kepada kami [Ubaid bin Ya'isy] dan [Ishaq bin Ibrahim] teks milik Ubaid, keduanya berkata: Telah menceritakan kepada kami [Yahya bin Adam bin Sulaiman] maua Khalid bin Khalid, telah menceritakan kepada kami [Zuhair] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Irak menahan dirham dan takarannya, Syam menahan mud dan dinarnya, Mesir menahan timbangan dan dinarnya, kalian kembali seperti sedia kala, kalian kembali seperti sedia kala, kalian kembali seperti sedia kala.\" Abu Hurairah berkata: Daging dan darah Abu Hurairah menyaksikannya."},"4787":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَنْزِلَ الرُّومُ بِالْأَعْمَاقِ أَوْ بِدَابِقٍ فَيَخْرُجُ إِلَيْهِمْ جَيْشٌ مِنْ الْمَدِينَةِ مِنْ خِيَارِ أَهْلِ الْأَرْضِ يَوْمَئِذٍ فَإِذَا تَصَافُّوا قَالَتْ الرُّومُ خَلُّوا بَيْنَنَا وَبَيْنَ الَّذِينَ سَبَوْا مِنَّا نُقَاتِلْهُمْ فَيَقُولُ الْمُسْلِمُونَ لَا وَاللَّهِ لَا نُخَلِّي بَيْنَكُمْ وَبَيْنَ إِخْوَانِنَا فَيُقَاتِلُونَهُمْ فَيَنْهَزِمُ ثُلُثٌ لَا يَتُوبُ اللَّهُ عَلَيْهِمْ أَبَدًا وَيُقْتَلُ ثُلُثُهُمْ أَفْضَلُ الشُّهَدَاءِ عِنْدَ اللَّهِ وَيَفْتَتِحُ الثُّلُثُ لَا يُفْتَنُونَ أَبَدًا فَيَفْتَتِحُونَ قُسْطَنْطِينِيَّةَ فَبَيْنَمَا هُمْ يَقْتَسِمُونَ الْغَنَائِمَ قَدْ عَلَّقُوا سُيُوفَهُمْ بِالزَّيْتُونِ إِذْ صَاحَ فِيهِمْ الشَّيْطَانُ إِنَّ الْمَسِيحَ قَدْ خَلَفَكُمْ فِي أَهْلِيكُمْ فَيَخْرُجُونَ وَذَلِكَ بَاطِلٌ فَإِذَا جَاءُوا الشَّأْمَ خَرَجَ فَبَيْنَمَا هُمْ يُعِدُّونَ لِلْقِتَالِ يُسَوُّونَ الصُّفُوفَ إِذْ أُقِيمَتْ الصَّلَاةُ فَيَنْزِلُ عِيسَى ابْنُ مَرْيَمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّهُمْ فَإِذَا رَآهُ عَدُوُّ اللَّهِ ذَابَ كَمَا يَذُوبُ الْمِلْحُ فِي الْمَاءِ فَلَوْ تَرَكَهُ لَانْذَابَ حَتَّى يَهْلِكَ وَلَكِنْ يَقْتُلُهُ اللَّهُ بِيَدِهِ فَيُرِيهِمْ دَمَهُ فِي حَرْبَتِهِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Mu'alla bin Manhsur] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami [Suhail] dari [ayahnya] dari [Abu Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak akan terjadi hari kiamat hingga bangsa Romawi turun ke medan perang di suatu tempat bernama A'maq atau Dabiq, sehingga ada sekelompok pasukan dari Madinah yang keluar menghadapi mereka. Mereka adalah sebaik-baik penduduk bumi ketika itu. Dan tatkala mereka berhadapan, pasukan Romawi berkata: 'Biarkanlah kami memerangi orang-orang yang menawan kami! ' Kaum muslimin menjawab: 'Tidak, demi Allah, kami tidak akan membiarkan kalian memerangi saudara-saudara kami.' Maka terjadilah peperangan antara mereka. Lalu ada sepertiga yang kalah dimana Allah tidak akan mengampuni dosa mereka untuk selamanya, dan sepertiga lagi terbunuh sebagai sebaik-baik para syuhada' di sisi Allah, dan sepertiga lagi Allah memberikan kemenangan kepada mereka. Mereka tidak akan ditimpa sebuah fitnah untuk selamanya, lalu selanjutnya mereka menaklukkan kostantinopel. Dan ketika mereka sedang membagi-bagi harta rampasan perang dan tengah menggantungkan pedang-pedang mereka pada pohon zaitun, tiba-tiba setan meneriaki mereka 'Sesungguhnya Al Masih telah muncul di tengah-tengah keluarga kalian, ' merekapun berhamburan keluar, dan ternyata itu hanyalah kebohongan belaka. Ketika mereka mendatangi Syam, ia muncul. Dan ketika mereka sedang mempersiapkan peperangan dan sedang merapikan barisan, tiba-tiba datanglah waktu shalat, dan turunlah Nabi Isa bin Maryam Shallallahu 'alaihi wa Salam, lalu ia mengimami mereka. Dan apabila musuh Allah (Dajjal) melihatnya, niscaya ia akan meleleh sebagaimana garam yang mencair di dalam air, meskipun seandainya saja ia membiarkannya nantinya ia juga akan meleleh lalu binasa akan tetapi Allah menginginkan ia membunuhnya dengan tangannya lalu memperlihatkan kepada mereka darahnya yang berada di ujung tombaknya.\""},"4788":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي مُوسَى بْنُ عُلَيٍّ عَنْ أَبِيهِ قَالَ قَالَ الْمُسْتَوْرِدُ الْقُرَشِيُّ عِنْدَ عَمْرِو بْنِ الْعَاصِسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَقُومُ السَّاعَةُ وَالرُّومُ أَكْثَرُ النَّاسِ فَقَالَ لَهُ عَمْرٌو أَبْصِرْ مَا تَقُولُ قَالَ أَقُولُ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ لَئِنْ قُلْتَ ذَلِكَ إِنَّ فِيهِمْ لَخِصَالًا أَرْبَعًا إِنَّهُمْ لَأَحْلَمُ النَّاسِ عِنْدَ فِتْنَةٍ وَأَسْرَعُهُمْ إِفَاقَةً بَعْدَ مُصِيبَةٍ وَأَوْشَكُهُمْ كَرَّةً بَعْدَ فَرَّةٍ وَخَيْرُهُمْ لِمِسْكِينٍ وَيَتِيمٍ وَضَعِيفٍ وَخَامِسَةٌ حَسَنَةٌ جَمِيلَةٌ وَأَمْنَعُهُمْ مِنْ ظُلْمِ الْمُلُوكِ","id":"Telah menceritakan kepada kami [Abdulmalik bin Syu'aib bin Al Laits] telah menceritakan kepadaku [Abdullah bin Wahab] telah mengkhabarkan kepadaku [Al Laits bin Sa'ad] telah menceritakan kepadaku [Musa bin Ali] dar [ayahnya] berkata: [Al Mustaudir Al Qurasy] berkata didekat Amru bin Al Ash: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat terjadi dan Romawi adalah manusia yang paling banyak.\" Amru berkata: Perhatikan ucapanmu. Ia berkata: Aku mengatakan yang aku dengar dari Rasulullah Shallallahu 'alaihi wa Salam. Ia berkata: Bila kau katakan demikian, pada diri mereka terdapat empat hal; mereka adalah orang-orang yang paling sabar saat terjadi fitnah, paling cepat miskin saat terjadi musibah, paling cepat menyerang setelah mundur, dan yang terbaik dari mereka terhadap orang miskin, anak yatim dan orang lemah. Yang kelima adalah yang menawan dan cantik serta paling tahan terhadap kelaliman para raja."},"4789":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي أَبُو شُرَيْحٍ أَنَّ عَبْدَ الْكَرِيمِ بْنَ الْحَارِثِ حَدَّثَهُ أَنَّ الْمُسْتَوْرِدَ الْقُرَشِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَقُومُ السَّاعَةُ وَالرُّومُ أَكْثَرُ النَّاسِ قَالَ فَبَلَغَ ذَلِكَ عَمْرَو بْنَ الْعَاصِ فَقَالَ مَا هَذِهِ الْأَحَادِيثُ الَّتِي تُذْكَرُ عَنْكَ أَنَّكَ تَقُولُهَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ الْمُسْتَوْرِدُ قُلْتُ الَّذِي سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ عَمْرٌو لَئِنْ قُلْتَ ذَلِكَ إِنَّهُمْ لَأَحْلَمُ النَّاسِ عِنْدَ فِتْنَةٍ وَأَجْبَرُ النَّاسِ عِنْدَ مُصِيبَةٍ وَخَيْرُ النَّاسِ لِمَسَاكِينِهِمْ وَضُعَفَائِهِمْ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya At Tujibi] telah menceritakan kepada kami [Abdullah bin Wahab] telah menceritakan kepadaku [Abu Syuraih] bahwa [Abdulkarim bin Al Harits] menceritakan padanya bahwa [Al Mustaurid Al Qurasy] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat terjadi dan Romawi adalah manusia yang paling banyak.\" Kata-kata ini terdengar oleh Amru bin Al Ash, ia berkata: Ucapan-ucapan apa yang disebut darimu bahwa kau mengatakannya dari Rasulullah Shallallahu 'alaihi wa Salam? Al Mustaurid berkata padanya: Aku katakan yang aku dengar dari Rasulullah Shallallahu 'alaihi wa Salam. Amru berkata: Bila kau katakan demikian, mereka adalah orang-orang paling sabar saat terjadi fitnah, paling kuat saat terjadi musibah dan yang terbaik terhadap orang-orang miskin dan orang-orang lemah."},"4790":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ حُجْرٍ كِلَاهُمَا عَنْ ابْنِ عُلَيَّةَ وَاللَّفْظُ لِابْنِ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي قَتَادَةَ الْعَدَوِيِّ عَنْ يُسَيْرِ بْنِ جَابِرٍ قَالَ هَاجَتْ رِيحٌ حَمْرَاءُ بِالْكُوفَةِ فَجَاءَ رَجُلٌ لَيْسَ لَهُ هِجِّيرَى إِلَّا يَا عَبْدَ اللَّهِ بْنَ مَسْعُودٍ جَاءَتْ السَّاعَةُ قَالَ فَقَعَدَ وَكَانَ مُتَّكِئًا فَقَالَ إِنَّ السَّاعَةَ لَا تَقُومُ حَتَّى لَا يُقْسَمَ مِيرَاثٌ وَلَا يُفْرَحَ بِغَنِيمَةٍ ثُمَّ قَالَ بِيَدِهِ هَكَذَا وَنَحَّاهَا نَحْوَ الشَّأْمِ فَقَالَ عَدُوٌّ يَجْمَعُونَ لِأَهْلِ الْإِسْلَامِ وَيَجْمَعُ لَهُمْ أَهْلُ الْإِسْلَامِ قُلْتُ الرُّومَ تَعْنِي قَالَ نَعَمْ وَتَكُونُ عِنْدَ ذَاكُمْ الْقِتَالِ رَدَّةٌ شَدِيدَةٌ فَيَشْتَرِطُ الْمُسْلِمُونَ شُرْطَةً لِلْمَوْتِ لَا تَرْجِعُ إِلَّا غَالِبَةً فَيَقْتَتِلُونَ حَتَّى يَحْجُزَ بَيْنَهُمْ اللَّيْلُ فَيَفِيءُ هَؤُلَاءِ وَهَؤُلَاءِ كُلٌّ غَيْرُ غَالِبٍ وَتَفْنَى الشُّرْطَةُ ثُمَّ يَشْتَرِطُ الْمُسْلِمُونَ شُرْطَةً لِلْمَوْتِ لَا تَرْجِعُ إِلَّا غَالِبَةً فَيَقْتَتِلُونَ حَتَّى يَحْجُزَ بَيْنَهُمْ اللَّيْلُ فَيَفِيءُ هَؤُلَاءِ وَهَؤُلَاءِ كُلٌّ غَيْرُ غَالِبٍ وَتَفْنَى الشُّرْطَةُ ثُمَّ يَشْتَرِطُ الْمُسْلِمُونَ شُرْطَةً لِلْمَوْتِ لَا تَرْجِعُ إِلَّا غَالِبَةً فَيَقْتَتِلُونَ حَتَّى يُمْسُوا فَيَفِيءُ هَؤُلَاءِ وَهَؤُلَاءِ كُلٌّ غَيْرُ غَالِبٍ وَتَفْنَى الشُّرْطَةُ فَإِذَا كَانَ يَوْمُ الرَّابِعِ نَهَدَ إِلَيْهِمْ بَقِيَّةُ أَهْلِ الْإِسْلَامِ فَيَجْعَلُ اللَّهُ الدَّبْرَةَ عَلَيْهِمْ فَيَقْتُلُونَ مَقْتَلَةً إِمَّا قَالَ لَا يُرَى مِثْلُهَا وَإِمَّا قَالَ لَمْ يُرَ مِثْلُهَا حَتَّى إِنَّ الطَّائِرَ لَيَمُرُّ بِجَنَبَاتِهِمْ فَمَا يُخَلِّفُهُمْ حَتَّى يَخِرَّ مَيْتًا فَيَتَعَادُّ بَنُو الْأَبِ كَانُوا مِائَةً فَلَا يَجِدُونَهُ بَقِيَ مِنْهُمْ إِلَّا الرَّجُلُ الْوَاحِدُ فَبِأَيِّ غَنِيمَةٍ يُفْرَحُ أَوْ أَيُّ مِيرَاثٍ يُقَاسَمُ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ سَمِعُوا بِبَأْسٍ هُوَ أَكْبَرُ مِنْ ذَلِكَ فَجَاءَهُمْ الصَّرِيخُ إِنَّ الدَّجَّالَ قَدْ خَلَفَهُمْ فِي ذَرَارِيِّهِمْ فَيَرْفُضُونَ مَا فِي أَيْدِيهِمْ وَيُقْبِلُونَ فَيَبْعَثُونَ عَشَرَةَ فَوَارِسَ طَلِيعَةًقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ أَسْمَاءَهُمْ وَأَسْمَاءَ آبَائِهِمْ وَأَلْوَانَ خُيُولِهِمْ هُمْ خَيْرُ فَوَارِسَ عَلَى ظَهْرِ الْأَرْضِ يَوْمَئِذٍ أَوْ مِنْ خَيْرِ فَوَارِسَ عَلَى ظَهْرِ الْأَرْضِ يَوْمَئِذٍقَالَ ابْنُ أَبِي شَيْبَةَ فِي رِوَايَتِهِ عَنْ أُسَيْرِ بْنِ جَابِرٍ و حَدَّثَنِي مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي قَتَادَةَ عَنْ يُسَيْرِ بْنِ جَابِرٍ قَالَ كُنْتُ عِنْدَ ابْنِ مَسْعُودٍ فَهَبَّتْ رِيحٌ حَمْرَاءُ وَسَاقَ الْحَدِيثَ بِنَحْوِهِ وَحَدِيثُ ابْنِ عُلَيَّةَ أَتَمُّ وَأَشْبَعُ و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدٌ يَعْنِي ابْنَ هِلَالٍ عَنْ أَبِي قَتَادَةَ عَنْ أُسَيْرِ بْنِ جَابِرٍ قَالَ كُنْتُ فِي بَيْتِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَالْبَيْتُ مَلْآنُ قَالَ فَهَاجَتْ رِيحٌ حَمْرَاءُ بِالْكُوفَةِ فَذَكَرَ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Hujr] keduanya dari [Ibnu Ulaiyah] dan teksnya milik Hujr, telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Humaid bin Hilal] dari [Abu Qatadah Al Adawi] dari [Yasir bin Jabir] berkata: Angin merah bergejolak di Kufah lalu seseorang datang, ia tidak memiliki kebiasaan lain selain berkata: Wahai [Abdullah bin Mas'ud], kiamat telah tiba. Yasir berkata: Ibnu Mas'ud duduk setelah sebelumnya bersandar lalu berkata: Kiamat tidak terjadi hingga harta warisan tidak dibagi dan harta rampasan tidak membuat senang. Setelah itu ia berisyarat dengan tangannya seperti ini, ia menunjuk ke arah Syam lalu berkata: Musuh berkumpul untuk kaum muslimin dan kaum muslimin pun berkumpul untuk (menghadapi) mereka. Aku berkata: Romawi maksudmu? Ia menjawab: Ya, saat perang itu terjadi serangan besar-besaran. Kaum muslimin mengirim sekelompok pasukan agar mati, tidak kembali kecuali dalam keadaan menang. Mereka menyerang hingga malam hari lalu masing-masing dari kedua kubu kembali, masing-masing tidak menang dan sekelompok pasukan itu pun lenyap. Kaum muslimin mengirim sepasukan untuk mati, agar tidak kembali kecuali dalam keadaan menang. Mereka menyerang hingga malam hari lalu masing-masing dari kedua kubu kembali, masing-masing tidak menang dan sekelompok pasukan itu pun lenyap. Kaum muslimin mengirim sepasukan untuk mati, agar tidak kembali kecuali dalam keadaan menang. Mereka menyerang hingga malam hari lalu masing-masing dari kedua kubu kembali, masing-masing tidak menang dan sekelompok pasukan itu pun lenyap. Pada hari keempat, sisa kaum muslimin yang masih ada maju lalu Allah menjadikan kekalahan atas mereka. Mereka membunuh banyak pasukan, mungkin ia berkata: Tidak terlihat sepertinya, atau mengatakan: Tidak terlihat sepertinya (LAM YURAA MITSLUHAA atau LAM YURA MITSLUHAA), hingga burung-burung berterbangan melintasi segala penjuru mereka dan tidaklah melintasi mereka melainkan pasti tersungkur mati. Satu kabilah menghitung, tadinya berjumlah seratus orang tapi mereka hanya menjumpai satu orang saja, lalu harta rampasan perang mana yang bisa membuat senang atau harta peninggalan mana yang bisa dibagikan. Saat mereka seperti itu, mereka tiba-tiba mendengar serangan lebih besar darinya kemudian orang yang berteriak mendatangi mereka bahwa Dajjal telah mengganti mereka dikeluarga mereka lalu mereka membuang yang ada ditangan mereka kemudian pulang, setelah itu mereka mengirim sepuluh tentara berkuda ke depan. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya aku mengetahui nama-nama mereka, nama-nama ayah mereka dan warna kuda mereka. Mereka adalah tentara berkuda terbaik di muka bumi saat itu atau diantara tentara berkuda yang terbaik di atas bumi saat itu.\" [Ibnu Abi Syaibah] berkata dalam riwayatnya: Dari Usair bin Jabir. Telah menceritakan kepadaku [Muhammad bin Ubaid Al Ghubari] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Humaid bin Hilal] dari [Abu Qatadah] dari [Yusair bin Jabir] berkata: Aku pernah berada di dekat [Ibnu Mas'ud] lalu angin merah bergejolak, ia menyebut hadits serupa. Hadits Ibnu Ulaiyah lebih lengkap. Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid bin Hilal] dari [Abu Qatadah] dari [Asir bin Jabir] berkata: Aku berada di kediaman [Abdullah bin Mas'ud] dan rumahnya penuh dengan orang, ia berkata: Angin merah bergejolak di Kufah, lalu ia menyebut seperti hadits Ibnu Ulaiyah."},"4791":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ نَافِعِ بْنِ عُتْبَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ قَالَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمٌ مِنْ قِبَلِ الْمَغْرِبِ عَلَيْهِمْ ثِيَابُ الصُّوفِ فَوَافَقُوهُ عِنْدَ أَكَمَةٍ فَإِنَّهُمْ لَقِيَامٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ قَالَ فَقَالَتْ لِي نَفْسِي ائْتِهِمْ فَقُمْ بَيْنَهُمْ وَبَيْنَهُ لَا يَغْتَالُونَهُ قَالَ ثُمَّ قُلْتُ لَعَلَّهُ نَجِيٌّ مَعَهُمْ فَأَتَيْتُهُمْ فَقُمْتُ بَيْنَهُمْ وَبَيْنَهُ قَالَ فَحَفِظْتُ مِنْهُ أَرْبَعَ كَلِمَاتٍ أَعُدُّهُنَّ فِي يَدِي قَالَ تَغْزُونَ جَزِيرَةَ الْعَرَبِ فَيَفْتَحُهَا اللَّهُ ثُمَّ فَارِسَ فَيَفْتَحُهَا اللَّهُ ثُمَّ تَغْزُونَ الرُّومَ فَيَفْتَحُهَا اللَّهُ ثُمَّ تَغْزُونَ الدَّجَّالَ فَيَفْتَحُهُ اللَّهُقَالَ فَقَالَ نَافِعٌ يَا جَابِرُ لَا نَرَى الدَّجَّالَ يَخْرُجُ حَتَّى تُفْتَحَ الرُّومُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Abdulmalik bin Umair] dari [Jabir bin Samurah] dari [Nafi' bin Utbah] berkata: Kami bersama Rasulullah Shallallahu 'alaihi wa Salam dalam suatu peperangan. Ia berkata: Suatu kaum mendatangi nabi Shallallahu 'alaihi wa Salam dari maghrib, mereka mengenakan baju wool, mereka menemui beliau didekat suatu bukit. Mereka berdiri sementara Rasulullah Shallallahu 'alaihi wa Salam duduk. Ia (Nafi') berkata: Hatiku berkata: Datangilah mereka dan berdirilah diantara mereka dan Rasulullah Shallallahu 'alaihi wa Salam agar mereka tidak menyerang beliau lalu aku berkata: Mungkin beliau berbicara lirih dengan mereka. Aku mendatangi mereka lalu aku berdiri diantara mereka dan beliau. Aku menghafal empat kalimat dari beliau, aku menghitungnya dengan tanganku. Beliau bersabda: \"Kalian akan memerangi jazirah arab lalu Allah menaklukkannya, setelah itu Persia lalu Allah menaklukkannya, kemudian kalian memerangi Romawi lalu Allah menaklukkannya, selanjutnya kalian memerangi Dajjal lalu Allah menaklukkannya.\" Kemudian Nafi' berkata: Hai Jabir, kami tidak berpendapat Dajjal muncul hingga Romawi ditaklukkan. "},"4792":{"ar":"حَدَّثَنَا أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ الْمَكِّيُّ وَاللَّفْظُ لِزُهَيْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ الْغِفَارِيِّ قَالَاطَّلَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا وَنَحْنُ نَتَذَاكَرُ فَقَالَ مَا تَذَاكَرُونَ قَالُوا نَذْكُرُ السَّاعَةَ قَالَ إِنَّهَا لَنْ تَقُومَ حَتَّى تَرَوْنَ قَبْلَهَا عَشْرَ آيَاتٍ فَذَكَرَ الدُّخَانَ وَالدَّجَّالَ وَالدَّابَّةَ وَطُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا وَنُزُولَ عِيسَى ابْنِ مَرْيَمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَأَجُوجَ وَمَأْجُوجَ وَثَلَاثَةَ خُسُوفٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَآخِرُ ذَلِكَ نَارٌ تَخْرُجُ مِنْ الْيَمَنِ تَطْرُدُ النَّاسَ إِلَى مَحْشَرِهِمْ","id":"Telah menceritakan kepada kami [Abu Khaitsamah Zuhair bin Harb], [Ishaq bin Ibrahim] dan [Ibnu Abi Umar Al Makki] teks milik Zuhair, berkata Ishaq: telah mengkhabarkan kepada kami, sedangkan yang lain berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Furat Al Qazzaz] dari [Abu Ath Thufail] dari [Hudzaifah bin Asid Al Ghifari] berkata: Rasulullah Shallallahu 'alaihi wa Salam menghampiri kami saat kami tengah membicarakan sesuatu, beliau bertanya: \"Apa yang kalian bicarakan?\" Kami menjawab: Kami membicarakan kiamat. Beliau bersabda: \"Kiamat tidaklah terjadi hingga kalian melihat sepuluh tanda-tanda sebelumnya.\" Beliau menyebut kabut, Dajjal, binatang, terbitnya matahari dari barat, turunnya Isa bin Maryam Shallallahu 'alaihi wa Salam, ya'juj dan ma'juj, tiga longsor; longsor di timur, longsor di barat dan longsor di jazirah arab dan yang terakhir adalah api muncul dari Yaman menggiring manusia menuju tempat perkumpulan mereka."},"4793":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ حُذَيْفَةَ بْنِ أَسِيدٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غُرْفَةٍ وَنَحْنُ أَسْفَلَ مِنْهُ فَاطَّلَعَ إِلَيْنَا فَقَالَ مَا تَذْكُرُونَ قُلْنَا السَّاعَةَ قَالَ إِنَّ السَّاعَةَ لَا تَكُونُ حَتَّى تَكُونَ عَشْرُ آيَاتٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ فِي جَزِيرَةِ الْعَرَبِ وَالدُّخَانُ وَالدَّجَّالُ وَدَابَّةُ الْأَرْضِ وَيَأْجُوجُ وَمَأْجُوجُ وَطُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَنَارٌ تَخْرُجُ مِنْ قُعْرَةِ عَدَنٍ تَرْحَلُ النَّاسَقَالَ شُعْبَةُ وَحَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ مِثْلَ ذَلِكَ لَا يَذْكُرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ أَحَدُهُمَا فِي الْعَاشِرَةِ نُزُولُ عِيسَى ابْنِ مَرْيَمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ الْآخَرُ وَرِيحٌ تُلْقِي النَّاسَ فِي الْبَحْرِ و حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ فُرَاتٍ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ يُحَدِّثُ عَنْ أَبِي سَرِيحَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غُرْفَةٍ وَنَحْنُ تَحْتَهَا نَتَحَدَّثُ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ قَالَ شُعْبَةُ وَأَحْسِبُهُ قَالَ تَنْزِلُ مَعَهُمْ إِذَا نَزَلُوا وَتَقِيلُ مَعَهُمْ حَيْثُ قَالُوا قَالَ شُعْبَةُ وَحَدَّثَنِي رَجُلٌ هَذَا الْحَدِيثَ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ وَلَمْ يَرْفَعْهُ قَالَ أَحَدُ هَذَيْنِ الرَّجُلَيْنِ نُزُولُ عِيسَى ابْنِ مَرْيَمَ و قَالَ الْآخَرُ رِيحٌ تُلْقِيهِمْ فِي الْبَحْرِ و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ بْنُ عَبْدِ اللَّهِ الْعِجْلِيُّ حَدَّثَنَا شُعْبَةُ عَنْ فُرَاتٍ قَالَ سَمِعْتُ أَبَا الطُّفَيْلِ يُحَدِّثُ عَنْ أَبِي سَرِيحَةَ قَالَ كُنَّا نَتَحَدَّثُ فَأَشْرَفَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِ مُعَاذٍ وَابْنِ جَعْفَرٍ و قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي الطُّفَيْلِ عَنْ أَبِي سَرِيحَةَ بِنَحْوِهِ قَالَ وَالْعَاشِرَةُ نُزُولُ عِيسَى ابْنِ مَرْيَمَ قَالَ شُعْبَةُ وَلَمْ يَرْفَعْهُ عَبْدُ الْعَزِيزِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Ambari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Furat Al Qazzaz] dari [Abu Ath Thufail] dari [Abu Sarihah Hudzaifah bin Usaid] berkata: Nabi Shallallahu 'alaihi wa Salam berada di kamar sementara kami berada dibawah, beliau melihat kami dari atas lalu bertanya: \"Apa yang kalian bicarakan?\" Kami menjawab: Kiamat. Beliau bersabda: \"Kiamat tidaklah terjadi hingga kalian melihat sepuluh tanda-tanda; longsor di timur, longsor di barat dan longsor di jazirah arab, kabut, Dajjal, binatang bumi, Ya'juj dan Ma'juj, terbitnya matahari dari barat dan api muncul dari dasar lembah Aden yang menggiring manusia.\" Syu'bah berkata: Telah menceritakan kepadaku [Abdulaziz bin Rufai'] dari [Abu Ath Thufail] dari [Abu Sarihah] seperti itu, ia tidak menyebut nabi Shallallahu 'alaihi wa Salam. Salah satu dari keduanya berkata tentang tanda-tanda yang kesepuluh: Turunnya Isa bin Maryam Shallallahu 'alaihi wa Salam. Yang lain menyebut: Angin yang melemparkan manusia ke lautan. Telah menceritakannya kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Furat] berkata: Aku mendengar [Abu Ath Thufail] menceritakan dari [Abu Sarihah] berkata: Rasulullah Shallallahu 'alaihi wa Salam berada di kamar sementara kami ada dibawahnya, kami tengah berbincang-bincang, ia menyebut hadits serupa. Syu'bah berkata: Aku kira beliau bersabda: \"(Api) menempati dimana pun mereka berada dan bersama mereka saat tidur siang.\" Syu'bah berkata: Telah menceritakan kepadaku [seseorang] hadits ini dari [Abu Ath Thufail] dari [Abu Sarihah] dan ia tidak memarfu'kannya. Salah satu dari kedua orang ini berkata: Turunnya Isa bin Maryam. Yang lain menyebut: Angin yang melemparkan mereka ke laut. Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu An Nu'man Al Hakim bin Abdullah Al Ijli] telah menceritakan kepada kami [Syu'bah] dari [Furat] berkata: Aku mendengar [Abu Ath Thufail] menceritakan dari [Abu Sarihah], ia berkata: Kami tengah berbincang-bincang lalu Rasulullah Shallallahu 'alaihi wa Salam melihat kami dari atas, seperti hadits Mu'adz dan Ibnu Ja'far. Ibnu Mutsanna berkata: telah menceritakan kepada kami [Abu An Nu'man Al Hakam bin Abdullah] telah menceritakan kepada kami [Syu'bah] dari [Abdulaziz bin Rufai'] dari [Abu Ath Thufail] dari [Abu Sarihah] sepertinya, ia berkata: Dan (tanda-tanda) yang kesepuluh adalah turunnya Isa bin Maryam. Syu'bah berkata: Abdulaziz tidak memarfu'kannya."},"4794":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ح و حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنَا أَبِي عَنْ جَدِّي حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ قَالَ ابْنُ الْمُسَيَّبِ أَخْبَرَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَخْرُجَ نَارٌ مِنْ أَرْضِ الْحِجَازِ تُضِيءُ أَعْنَاقَ الْإِبِلِ بِبُصْرَى","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengkhabarkan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Ibnu Al Musayyib] bahwa [Abu Hurairah] diberi khabar Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda. Telah menceritakan kepadaku [Abdulmalik bin Syu'aib bin Al Laits] telah menceritakan kepada kami [ayahku] dari [kakekku] telah menceritakan kepadaku [Uqail bin Khalid] dari [Ibnu Syihab] bekata: Berkata [Ibnu Al Musayyib]: telah mengkhabarkan kepadaku [Abu Hurairah] bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak akan terjadi hari kiamat hingga keluar sebuah api dari bumi Hijaz yang menerangi leher seekor onta yang berada di Bushro.\" (kota di Syam, pent.) "},"4795":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبْلُغُ الْمَسَاكِنُ إِهَابَ أَوْ يَهَابَقَالَ زُهَيْرٌ قُلْتُ لِسُهَيْلٍ فَكَمْ ذَلِكَ مِنْ الْمَدِينَةِ قَالَ كَذَا وَكَذَا مِيلًا","id":"Telah menceritakan kepadaku [Amru An Naqid] telah menceritakan kepada kami [Al Aswad bin Amir] telah menceritakan kepada kami [Zuhair] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Rumah-rumah tempat tinggal itu akan sampai ke daerah Ihab atau Yahab.\" Zuhair berkata: Aku bertanya kepada Suhail: Seberapa jauh jarak (Ihab atau Yahab) dari kota Madinah? Ia menjawab: sekian dan sekian mil."},"4796":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَتْ السَّنَةُ بِأَنْ لَا تُمْطَرُوا وَلَكِنْ السَّنَةُ أَنْ تُمْطَرُوا وَتُمْطَرُوا وَلَا تُنْبِتُ الْأَرْضُ شَيْئًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kemarau itu bukannya kalian tida dihujani, tapi kemarau adalah kalian dihujani dan dihujani tapi bumi tidak menumbuhkan apa pun.\""},"4797":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسْتَقْبِلُ الْمَشْرِقِ يَقُولُ أَلَا إِنَّ الْفِتْنَةَ هَاهُنَا أَلَا إِنَّ الْفِتْنَةَ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits]. Telah menceritakan kepadaku [Muhammad bin Rumh] telah mengkhabarkan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] ia mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda sementara beliau menghadap timur: \"Ingat, sesungguhnya fitnah itu disini, sesungguhnya fitnah itu disini dari arah terbitnya tanduk setan.\""},"4798":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ كُلُّهُمْ عَنْ يَحْيَى الْقَطَّانِ قَالَ الْقَوَارِيرِيُّ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عِنْدَ بَابِ حَفْصَةَ فَقَالَ بِيَدِهِ نَحْوَ الْمَشْرِقِ الْفِتْنَةُ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ قَالَهَا مَرَّتَيْنِ أَوْ ثَلَاثًاو قَالَ عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ فِي رِوَايَتِهِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ بَابِ عَائِشَةَ","id":"Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] dan [Muhammad bin Al Mutsanna]. Telah menceritakan kepada kami [Ubaidullah bin Sa'id], semuanya dari [Yahya Al Qaththan] berkata [Al Qawariri]: telah menceritakan kepadaku [Yahya bin Sa'id] dari [Ubaidullah bin Umar] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] Rasulullah Shallallahu 'alaihi wa Salam berdiri di dekat pintu Hafshah lalu berisyarat dengan tangan beliau ke arah timur, beliau bersabda: \"Fitnah itu disini, dari tempat terbitnya tanduk setan.\" Beliau mengucapkannya dua atau tiga kali. Ubaidullah bin Sa'id berkata dalam riwayatnya: Rasulullah Shallallahu 'alaihi wa Salam berdiri di dekat pintu Aisyah."},"4799":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ مُسْتَقْبِلُ الْمَشْرِقِ هَا إِنَّ الْفِتْنَةَ هَاهُنَا هَا إِنَّ الْفِتْنَةَ هَاهُنَا هَا إِنَّ الْفِتْنَةَ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengkhabarkan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [ayahnya] Rasulullah Shallallahu 'alaihi wa Salam bersabda dan beliau menghadap ke timur: \"Ingat, sesungguhnya fitnah itu disini, Ingat, sesungguhnya fitnah itu disini, Ingat, sesungguhnya fitnah itu disini, dari arah terbitnya tanduk setan.\""},"4800":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْتِ عَائِشَةَ فَقَالَ رَأْسُ الْكُفْرِ مِنْ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ يَعْنِي الْمَشْرِقَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Ikrimah bin Ammar] dari [Salim] dari [Ibnu Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam keluar dari rumah Aisyah lalu bersabda: \"Induk kekufuran dari sini, tempat terbitnya tandu setan.\" Maksud beliau dari arah timur."},"4801":{"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ سُلَيْمَانَ أَخْبَرَنَا حَنْظَلَةُ قَالَ سَمِعْتُ سَالِمًا يَقُولُ سَمِعْتُ ابْنَ عُمَرَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِيَدِهِ نَحْوَ الْمَشْرِقِ وَيَقُولُ هَا إِنَّ الْفِتْنَةَ هَاهُنَا هَا إِنَّ الْفِتْنَةَ هَاهُنَا ثَلَاثًا حَيْثُ يَطْلُعُ قَرْنَا الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ishaq bin Sulaiman] telah mengkhabarkan kepada kami [Hanzhalah] berkata: Aku mendengar [Salim] berkata: Aku mendengar [Ibnu Umar] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda seraya menunjuk dengan tangan ke arah timur: \"Ingat, sesungguhnya fitnah itu disini, Ingat, sesungguhnya fitnah itu disini, -sebanyak tiga kali- dari arah terbitnya dua tanduk setan.\""},"4802":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ أَبَانَ وَوَاصِلُ بْنُ عَبْدِ الْأَعْلَى وَأَحْمَدُ بْنُ عُمَرَ الْوَكِيعِيُّ وَاللَّفْظُ لِابْنِ أَبَانَ قَالُوا حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ يَقُولُا يَا أَهْلَ الْعِرَاقِ مَا أَسْأَلَكُمْ عَنْ الصَّغِيرَةِ وَأَرْكَبَكُمْ لِلْكَبِيرَةِ سَمِعْتُ أَبِي عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْفِتْنَةَ تَجِيءُ مِنْ هَاهُنَا وَأَوْمَأَ بِيَدِهِ نَحْوَ الْمَشْرِقِ مِنْ حَيْثُ يَطْلُعُ قَرْنَا الشَّيْطَانِ وَأَنْتُمْ يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ وَإِنَّمَا قَتَلَ مُوسَى الَّذِي قَتَلَ مِنْ آلِ فِرْعَوْنَ خَطَأً فَقَالَ اللَّهُ عَزَّ وَجَلَّ لَهُ{ وَقَتَلْتَ نَفْسًا فَنَجَّيْنَاكَ مِنْ الْغَمِّ وَفَتَنَّاكَ فُتُونًا }قَالَ أَحْمَدُ بْنُ عُمَرَ فِي رِوَايَتِهِ عَنْ سَالِمٍ لَمْ يَقُلْ سَمِعْتُ","id":"Telah menceritakan kepada kami [Abdullah bin Umar bin Aban], [Washil bin Abdula'la] dan [Ahmad bin Umar Al Waki'i], teks milik Ibnu Aban, mereka berkata: Telah menceritakan kepada kami [Ibnu Fudhail] dari [ayahnya] berkata: Aku mendengar [Salim bin Abdullah bin Umar] berkata: Wahai penduduk Irak, aku tidak bertanya tentang masalah kecil dan aku tidak mendorong kalian untuk masalah besar, aku pernah mendengar ayahku, [Abdullah bin Umar] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya fitnah itu muncul disini -ia menunjukkan tangannya ke arah timur- dari arah terbitnya dua tanduk setan. Kalian saling menebas leher satu sama lain. Musa hanya membunuh orang yang ia bunuh berasal dari keluarga Fir'aun itu karena tidak sengaja lalu Allah 'azza wajalla berfirman padanya: 'Dan kamu pernah membunuh seorang manusia, lalu kami selamatkan kamu dari kesusahan dan Kami telah mencobamu dengan beberapa cobaan.\" (Thaahaa: 40) Ahmad bin Umar berkata dalam riwayatnya: Dari Salim, ia tidak menyebut: Aku telah mendengar. "},"4803":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنَا و قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَضْطَرِبَ أَلَيَاتُ نِسَاءِ دَوْسٍ حَوْلَ ذِي الْخَلَصَةِ وَكَانَتْ صَنَمًا تَعْبُدُهَا دَوْسٌ فِي الْجَاهِلِيَّةِ بِتَبَالَةَ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abdu bin Humaid], berkata Abdu: Telah mengkhabarkan kepada kami, sementara Ibnu Rafi' berkata: Telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyib] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga wanita-wanita lemah Daus bergerak-gerak sekitar Dzil Khalashah.\" Ia adalah patung yang disembah Daus dimasa jahiliyah di Tabalah."},"4804":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ وَأَبُو مَعْنٍ زَيْدُ بْنُ يَزِيدَ الرَّقَاشِيُّ وَاللَّفْظُ لِأَبِي مَعْنٍ قَالَا حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ الْأَسْوَدِ بْنِ الْعَلَاءِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَذْهَبُ اللَّيْلُ وَالنَّهَارُ حَتَّى تُعْبَدَ اللَّاتُ وَالْعُزَّى فَقُلْتُ يَا رَسُولَ اللَّهِ إِنْ كُنْتُ لَأَظُنُّ حِينَ أَنْزَلَ اللَّهُ{ هُوَ الَّذِي أَرْسَلَ رَسُولَهُ بِالْهُدَى وَدِينِ الْحَقِّ لِيُظْهِرَهُ عَلَى الدِّينِ كُلِّهِ وَلَوْ كَرِهَ الْمُشْرِكُونَ }أَنَّ ذَلِكَ تَامًّا قَالَ إِنَّهُ سَيَكُونُ مِنْ ذَلِكَ مَا شَاءَ اللَّهُ ثُمَّ يَبْعَثُ اللَّهُ رِيحًا طَيِّبَةً فَتَوَفَّى كُلَّ مَنْ فِي قَلْبِهِ مِثْقَالُ حَبَّةِ خَرْدَلٍ مِنْ إِيمَانٍ فَيَبْقَى مَنْ لَا خَيْرَ فِيهِ فَيَرْجِعُونَ إِلَى دِينِ آبَائِهِمْو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو بَكْرٍ وَهُوَ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari] dan [Abu Ma'nu Zaid bin Yazid Ar Raqasyi] teks milik Abu Ma'nu, keduanya berkata: Telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Abdulhamid bin Ja'far] dari [Al Aswad bin Al Ala`] dari [Abu Salamah] dari [Aisyah] berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malam dan siang itu tidak akan lenyap hingga Laata dan 'Uzza disembah.\" Aku berkata: Wahai Rasulullah, aku mengira hal itu ketika Allah menurunkan ayat: \"Dialah yang Telah mengutus RasulNya (dengan membawa) petunjuk (Al Quran) dan agama yang benar untuk dimenangkanNya atas segala agama, walaupun orang-orang musyrikin tidak menyukai\" (At Taubah: 33) bahwa ia telah sempurna. Beliau bersabda: \"Sesungguhnya hal itu akan terjadi dengan kehendak Allah, kemudian Dia akan mengirim sebuah angin yang lembut hingga Dia mewafatkan setiap orang yang di dalam hatinya terdapat keimanan meski hanya sebesar biji sawi, lalu yang tersisa hanyalah orang-orang yang di dalam dirinya tidak ada kebaikan sedikitpun sehingga mereka kembali kepada agama nenek moyang mereka.\" Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dengan sanad ini dengan matan serupa. "},"4805":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ فِيمَا قُرِئَ عَلَيْهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَمُرَّ الرَّجُلُ بِقَبْرِ الرَّجُلِ فَيَقُولُ يَا لَيْتَنِي مَكَانَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] dalam Rasulullah yang dibacakan padanya dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga seseorang melintasi makam seseorang lalu ia berkata: Andai aku menggantinya.\""},"4806":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ مُحَمَّدِ بْنِ أَبَانَ بْنِ صَالِحٍ وَمُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ وَاللَّفْظُ لِابْنِ أَبَانَ قَالَا حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِي إِسْمَعِيلَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَذْهَبُ الدُّنْيَا حَتَّى يَمُرَّ الرَّجُلُ عَلَى الْقَبْرِ فَيَتَمَرَّغُ عَلَيْهِ وَيَقُولُ يَا لَيْتَنِي كُنْتُ مَكَانَ صَاحِبِ هَذَا الْقَبْرِ وَلَيْسَ بِهِ الدِّينُ إِلَّا الْبَلَاءُ","id":"Telah menceritakan kepada kami [Abdullah bin Umar bin Muhammad bin Aban bin Shalih] dan [Muhammad bin Yazid Ar Rifa'i] teks milik Aban, keduanya berkata: Telah menceritakan kepada kami [Ibnu Fudhail] dari [Abu Isma'il] dari [Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Demi Dzat yang jiwaku ada ditanganNya, dunia tidak akan lenyap hingga seseorang melintasi kuburan lalu berhenti di atasnya dan berkata: 'Andai saja aku adalah penghuni kuburan ini, ' sementara ia tidak memiliki agama selain cobaan'.\""},"4807":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ أَبَانَ وَوَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِي إِسْمَعِيلَ الْأَسْلَمِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَذْهَبُ الدُّنْيَا حَتَّى يَأْتِيَ عَلَى النَّاسِ يَوْمٌ لَا يَدْرِي الْقَاتِلُ فِيمَ قَتَلَ وَلَا الْمَقْتُولُ فِيمَ قُتِلَ فَقِيلَ كَيْفَ يَكُونُ ذَلِكَ قَالَ الْهَرْجُ الْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِوَفِي رِوَايَةِ ابْنِ أَبَانَ قَالَ هُوَ يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي إِسْمَعِيلَ لَمْ يَذْكُرْ الْأَسْلَمِيَّ","id":"Telah menceritakan kepada kami [Abdullah bin Umar bin Aban] dan [Washil bin Abdula'la], keduanya berkata: telah menceritakan kepada kami [Muhammad bin Fudlai] dari [Abu Isma'il Al Aslami] dari [Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, dunia tidak akan lenyap hingga suatu masa mendatangi manusia dimana orang yang membunuh tidak mengerti karena alasan apa ia membunuh dan orang yang terbunuh juga tidak mengerti atas dasar apa ia dibunuh.\" Dikatakan: Bagaimana itu terjadi? Beliau menjawab: \"Pembunuhan, orang yang membunuh dan yang dibunuh ada dineraka.\" Disebutkan dalam riwayat Ibnu Aban: Ia berkata: Ia adalah Yazid bin Kaisan dari Abu Isma'il, ia tidak menyebut: Al Aslami."},"4808":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَرِّبُ الْكَعْبَةَ ذُو السُّوَيْقَتَيْنِ مِنْ الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Abi Umar], teks milik Abu Bakr, keduanya berkata: Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ziyad bin Sa'ad] dari [Az Zuhri] dari [Sa'id] ia mendengar [Abu Hurairah] berkata: Dari nabi Shallallahu 'alaihi wa Salam: Dzus Suwaiqatain dari Habasyah meruntuhkan ka'bah. "},"4809":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذُو السُّوَيْقَتَيْنِ مِنْ الْحَبَشَةِ يُخَرِّبُ بَيْتَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdulaziz Ad Darawardi] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dzus Suwaiqatain dari Habasyah meruntuhkan rumah Allah 'azza wajalla.\""},"4810":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ الْعَبْدِيُّ حَدَّثَنَا عَبْدُ الْكَبِيرِ بْنُ عَبْدِ الْمَجِيدِ أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْحَكَمِ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَذْهَبُ الْأَيَّامُ وَاللَّيَالِي حَتَّى يَمْلِكَ رَجُلٌ يُقَالُ لَهُ الْجَهْجَاهُقَالَ مُسْلِم هُمْ أَرْبَعَةُ إِخْوَةٍ شَرِيكٌ وَعُبَيْدُ اللَّهِ وَعُمَيْرٌ وَعَبْدُ الْكَبِيرِ بَنُو عَبْدِ الْمَجِيدِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar Al Abdi] telah menceritakan kepada kami [Abdulkabir bin Abdulmajid Abu Bakr Al Hanafi] telah menceritakan kepada kami [Abdulhamid bin Ja'far] berkata: Aku mendengar [Umar bin Al Hakam] menceritakan dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Siang dan malam itu tidak akan lenyap (terjadi kiamat) sampai ada seorang lelaki bernama Jahjah menjadi penguasa.\" Muslim berkata: Mereka empat bersaudara; Syarik, Ubaidillah, Umair dan Abdul Kabir dari bani Abdul Majid."},"4811":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي عُمَرَ وَاللَّفْظُ لِابْنِ أَبِي عُمَرَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaiba] dan [Ibnu Abi Umar], teks milik Ibnu Abi Umar, keduanya berkata: Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] nabi Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga kalian memerangi kaum, wajah-wajah mereka seperti perisai ditambal dan kiamat tidak akan terjadi hingga kalian memerangi suatu kaum bersandalkan rambut.\""},"4812":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا صِغَارَ الْأَعْيُنِ ذُلْفَ الْآنُفِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] sampai kepada nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Kiamat tidak terjadi hingga kalian memerangi kaum bersandalkan rambut dan hingga kalian memerangi kaum bermata sipit berhidung kecil.\""},"4813":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يُقَاتِلَ الْمُسْلِمُونَ التُّرْكَ قَوْمًا وُجُوهُهُمْ كَالْمَجَانِّ الْمُطْرَقَةِ يَلْبَسُونَ الشَّعَرَ وَيَمْشُونَ فِي الشَّعَرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga kaum muslimin memerangi Turki, kaum dengan wajah seperti perisai ditambal, mereka berbaju rambut dan berjalan mengenakan rambut.\""},"4814":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ وَأَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُقَاتِلُونَ بَيْنَ يَدَيْ السَّاعَةِ قَوْمًا نِعَالُهُمْ الشَّعَرُ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ حُمْرُ الْوُجُوهِ صِغَارُ الْأَعْيُنِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dan [Abu Usamah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dihadapan kiamat, kalian memerangi suatu kaum, sandal mereka rambut, wajah mereka seperti perisai ditambal, berwajah merah dan bermata sipit.\""},"4815":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِعُثْمَانَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَرْنَا بِصِبْيَانٍ فِيهِمْ ابْنُ صَيَّادٍ فَفَرَّ الصِّبْيَانُ وَجَلَسَ ابْنُ صَيَّادٍ فَكَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرِهَ ذَلِكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرِبَتْ يَدَاكَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ لَا بَلْ تَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ ذَرْنِي يَا رَسُولَ اللَّهِ حَتَّى أَقْتُلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْ الَّذِي تَرَى فَلَنْ تَسْتَطِيعَ قَتْلَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim], teks milik Utsman, berkata Ishaq: telah mengkhabarkan kepada kami, sementara Utsman berkata: telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] berkata: Kami bersama Rasulullah Shallallahu 'alaihi wa Salam, kami melintasi anak-anak, diantara mereka ada Ibnu Shayyad. Anak-anak lari sementara Ibnu Shayyad duduk, sepertinya Rasulullah Shallallahu 'alaihi wa Salam membenci hal itu lalu nabi Shallallahu 'alaihi wa Salam bertanya padanya: \"Beruntunglah kamu, apa kau bersaksi bahwa aku utusan Allah?\" ia menjawab: Tidak, tapi kau bersaksi bahwa aku utusan Allah. Umar bin Al Khaththab berkata: Biarkan aku membunuhnya wahai Rasulullah. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila yang kau lihat seperti itu, kau tidak akan mampu membunuhnya.\""},"4816":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّ بِابْنِ صَيَّادٍ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَبَأْتُ لَكَ خَبِيئًا فَقَالَ دُخٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ دَعْنِي فَأَضْرِبَ عُنُقَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُ فَإِنْ يَكُنْ الَّذِي تَخَافُ لَنْ تَسْتَطِيعَ قَتْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], [Ishaq bin Ibrahim] dan [Abu Kuraib], teks milik Abu Kuraib, berkata Ibnu Numair: telah menceritakan kepada kami, sedangkan yang lain berkata: Telah mengkhabarkan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] berkata: Kami berjalan bersama nabi Shallallahu 'alaihi wa Salam lalu beliau melintasi Ibnu Shayyad, Rasulullah Shallallahu 'alaihi wa Salam bersabda padanya: \"Aku menyembunyikan sesuatu untukmu.\" Ia berkata: Asap. Lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Menyingkirlah, kau tidak akan melampaui kemampuanmu.\" Lalu Umar berkata: Wahai Rasulullah, biarkan aku menebas lehernya. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Biarkan dia, bila dia orang yang kau takuti, kau tidak akan mampu membunuhnya.\""},"4817":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَلَقِيَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ فِي بَعْضِ طُرُقِ الْمَدِينَةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ هُوَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمَنْتُ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ مَا تَرَى قَالَ أَرَى عَرْشًا عَلَى الْمَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَى عَرْشَ إِبْلِيسَ عَلَى الْبَحْرِ وَمَا تَرَى قَالَ أَرَى صَادِقَيْنِ وَكَاذِبًا أَوْ كَاذِبَيْنِ وَصَادِقًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُبِسَ عَلَيْهِ دَعُوهُحَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا أَبُو نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ لَقِيَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَ صَائِدٍ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ وَابْنُ صَائِدٍ مَعَ الْغِلْمَانِ فَذَكَرَ نَحْوَ حَدِيثِ الْجُرَيْرِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Salim bin Nuh] dari [Al Jurairi] dari [Abu Nadhrah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam, Abu Bakar dan Umar berpapasan dengannya (Ibnu Shayyad) disalah satu jalanan Madinah lalu Rasulullah Shallallahu 'alaihi wa Salam bertanya padanya: \"Apa kau bersaksi bahwa aku utusan Allah?\" ia balik bertanya: Apa kau bersaksi bahwa aku utusan Allah? Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku beriman kepada Allah, malaikat dan kitab-kitabNya.\" Beliau bertanya: \"Apa yang kau lihat?\" ia menjawab: Aku melihat singgasana di atas air. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kau melihat singgasana iblis di atas laut.\" Beliau bertanya: \"Apa yang kau lihat?\" ia menjawab: Dua orang yang jujur dan seorang pendusta, atau dua orang pendusta dan seorang yang juju. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ia dikaburkan, biarkanlah dia.\" Telah menceritakan kepada kami [Yahya bin Hubaib] dan [Muhammad bin Abdula'la], keduanya berkata: Telah menceritakan kepada kami [Mu'tamir] berkata: Aku mendengar [ayahku] berkata: Telah menceritakan kepada kami [Abu Nadhrah] dari [Jabir bin Abdullah] berkata: Nabi Allah subhanahu wata'ala Rasulullah Shallallahu 'alaihi wa Salam bertemu Ibnu Shayyad, beliau bersama Abu Bakar dan Umar, sementara Ibnu Shayyad bersama anak-anak, ia menyebut seperti hadits Al Jurairi."},"4818":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا دَاوُدُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَصَحِبْتُ ابْنَ صَائِدٍ إِلَى مَكَّةَ فَقَالَ لِي أَمَا قَدْ لَقِيتُ مِنْ النَّاسِ يَزْعُمُونَ أَنِّي الدَّجَّالُ أَلَسْتَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَا يُولَدُ لَهُ قَالَ قُلْتُ بَلَى قَالَ فَقَدْ وُلِدَ لِي أَوَلَيْسَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ الْمَدِينَةَ وَلَا مَكَّةَ قُلْتُ بَلَى قَالَ فَقَدْ وُلِدْتُ بِالْمَدِينَةِ وَهَذَا أَنَا أُرِيدُ مَكَّةَ قَالَ ثُمَّ قَالَ لِي فِي آخِرِ قَوْلِهِ أَمَا وَاللَّهِ إِنِّي لَأَعْلَمُ مَوْلِدَهُ وَمَكَانَهُ وَأَيْنَ هُوَ قَالَ فَلَبَسَنِي","id":"Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] dan [Muhammad bin Al Mutsanna], keduanya berkata: Telah menceritakan kepada kami [Abdula'la] telah menceritakan kepada kami [Dawud] dari [Abu An Nadhrah] dari [Abu Sa'id Al Khudri] berkata: Aku menemani Ibnu Shayyad ke Makkah, ia berkata padaku: Aku bertemu dengan sebagaian orang, mereka mengiraku Dajjal. Bukankah kau pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda bahwa ia tidak punya anak? Abu Sa'id berkata: Aku menjawab: Benar. Ibnu Shayyad berkata: Sedangkan aku punya anak. Dan bukankah kau pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal tidak bisa memasuki Madinah dan Makkah, Abu Sa'id berkata: Aku menjawab: Benar. Ibnu Shayyad berkata: Sementara aku dilahirkan di Madinah dan sekarang ini aku hendak ke Makkah. Abu Sa'id berkata: Setelah itu ia berkata padaku diakhir perkataannya: Ingat, demi Allah aku mengetahui kelahiran, tempat dan dimana ia (Dajjal) berada. Abu Sa'id berkata: Ia mengacaukanku."},"4819":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ لِي ابْنُ صَائِدٍ وَأَخَذَتْنِي مِنْهُ ذَمَامَةٌ هَذَا عَذَرْتُ النَّاسَ مَا لِي وَلَكُمْ يَا أَصْحَابَ مُحَمَّدٍ أَلَمْ يَقُلْ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ يَهُودِيٌّ وَقَدْ أَسْلَمْتُ قَالَ وَلَا يُولَدُ لَهُ وَقَدْ وُلِدَ لِي وَقَالَ إِنَّ اللَّهَ قَدْ حَرَّمَ عَلَيْهِ مَكَّةَ وَقَدْ حَجَجْتُ قَالَ فَمَا زَالَ حَتَّى كَادَ أَنْ يَأْخُذَ فِيَّ قَوْلُهُ قَالَ فَقَالَ لَهُ أَمَا وَاللَّهِ إِنِّي لَأَعْلَمُ الْآنَ حَيْثُ هُوَ وَأَعْرِفُ أَبَاهُ وَأُمَّهُ قَالَ وَقِيلَ لَهُ أَيَسُرُّكَ أَنَّكَ ذَاكَ الرَّجُلُ قَالَ فَقَالَ لَوْ عُرِضَ عَلَيَّ مَا كَرِهْتُ","id":"Telah menceritakan kepada kami [Yahya bin Hubaib] dan [Muhammad bin Abdula'la], keduanya berkata: Telah menceritakan kepada kami [Mu'tamir] berkata: Aku mendengar [ayahku] menceritakan dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] berkata: Ibnu Sha'id berkata padaku, aku merasa menghargainya: Aku memaafkan orang-orang. Apa urusan kalian denganku, wahai sahabat-sahabat Muhammad, bukankah nabi Allah Shallallahu 'alaihi wa Salam mengatakan bahwa ia (Dajjal) adalah Yahudi, sementara aku telah masuk Islam. Ia meneruskan: Ia (Dajjal) tidak punya anak, sementara aku punya. Ia meneruskan: Allah mengharamkannya (Dajjal) Makkah dan Madinah, sementara aku telah menunaikan haji. Abu Sa'id berkata: Ia terus berbicara hingga perkataannya menarikku, ia berkata: Ingat, demi Allah sesungguhnya aku tahu dimana sekarang ia (Dajjal) berada, aku mengetahui ayah dan ibunya. Abu Sa'id berkata: Ada yang berkata padanya: Apa kau suka bahwa kau adalah orang itu (Dajjal)? Ia menjawab: Bila ia diperlihatkan padaku, aku tidak benci."},"4820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ أَخْبَرَنِي الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ خَرَجْنَا حُجَّاجًا أَوْ عُمَّارًا وَمَعَنَا ابْنُ صَائِدٍ قَالَ فَنَزَلْنَا مَنْزِلًا فَتَفَرَّقَ النَّاسُ وَبَقِيتُ أَنَا وَهُوَ فَاسْتَوْحَشْتُ مِنْهُ وَحْشَةً شَدِيدَةً مِمَّا يُقَالُ عَلَيْهِ قَالَ وَجَاءَ بِمَتَاعِهِ فَوَضَعَهُ مَعَ مَتَاعِي فَقُلْتُ إِنَّ الْحَرَّ شَدِيدٌ فَلَوْ وَضَعْتَهُ تَحْتَ تِلْكَ الشَّجَرَةِ قَالَ فَفَعَلَ قَالَ فَرُفِعَتْ لَنَا غَنَمٌ فَانْطَلَقَ فَجَاءَ بِعُسٍّ فَقَالَ اشْرَبْ أَبَا سَعِيدٍ فَقُلْتُ إِنَّ الْحَرَّ شَدِيدٌ وَاللَّبَنُ حَارٌّ مَا بِي إِلَّا أَنِّي أَكْرَهُ أَنْ أَشْرَبَ عَنْ يَدِهِ أَوْ قَالَ آخُذَ عَنْ يَدِهِ فَقَالَ أَبَا سَعِيدٍ لَقَدْ هَمَمْتُ أَنْ آخُذَ حَبْلًا فَأُعَلِّقَهُ بِشَجَرَةٍ ثُمَّ أَخْتَنِقَ مِمَّا يَقُولُ لِي النَّاسُ يَا أَبَا سَعِيدٍ مَنْ خَفِيَ عَلَيْهِ حَدِيثُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا خَفِيَ عَلَيْكُمْ مَعْشَرَ الْأَنْصَارِ أَلَسْتَ مِنْ أَعْلَمِ النَّاسِ بِحَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ قَدْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ كَافِرٌ وَأَنَا مُسْلِمٌ أَوَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ عَقِيمٌ لَا يُولَدُ لَهُ وَقَدْ تَرَكْتُ وَلَدِي بِالْمَدِينَةِ أَوَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْمَدِينَةَ وَلَا مَكَّةَ وَقَدْ أَقْبَلْتُ مِنْ الْمَدِينَةِ وَأَنَا أُرِيدُ مَكَّةَ قَالَ أَبُو سَعِيدٍ الْخُدْرِيُّ حَتَّى كِدْتُ أَنْ أَعْذِرَهُ ثُمَّ قَالَ أَمَا وَاللَّهِ إِنِّي لَأَعْرِفُهُ وَأَعْرِفُ مَوْلِدَهُ وَأَيْنَ هُوَ الْآنَ قَالَ قُلْتُ لَهُ تَبًّا لَكَ سَائِرَ الْيَوْمِ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Salim bin Nuh] telah mengkhabarkan kepadaku [Al Jurairi] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] berkata: Kami pergi menunaikan haji atau umrah, Ibnu Sha'id bersama kami. kami singgah disuatu tempat, orang-orang berpencar dan yang tersisa hanya aku dan dia, aku sangat tidak senang padanya karena yang dikatakan orang-orang tentang dia. Ia membawa barang-barang perbekalannya lalu diletakkan bersamaan dengan barang-barangku. Aku berkata: Panas sekali, andai kau meletakkanya di bawah pohon itu. Abu Sa'id berkata: Ia melakukannya. Abu Sa'id berkata: Lalu seekor kambing diangkat, ia pergi lalu datang dengan membawa gelas. Ia berkata: Minumlah wahai Abu Sa'id. Aku berkata: Panas sekali, susu itu juga panas. Tidak ada apa-apa denganku selain hanya karena aku tidak suka minum dari tangannya -atau ia berkata: Aku mengambil dari tangannya. Lalu Abu Sha'id berkata: Wahai Abu Sa'id, aku ingin mengambil tali lalu aku gantungkan dipohon kemudian aku gantung diri karena yang dikatakan banyak orang terhadapku. Wahai Abu Sa'id, siapa yang tidak mengetahui hadits Rasulullah Shallallahu 'alaihi wa Salam, kalian wahai kaum Anshar, tidaklah samar bagi kalian. Bukankah kalian termasuk yang paling tahu hadits Rasulullah Shallallahu 'alaihi wa Salam? Bukankah beliau pernah bersabda bahwa ia (Dajjal) kafir sementara aku muslim, bukankah Rasulullah Shallallahu 'alaihi wa Salam bersabda bahwa ia (Dajjal) mandul sementara aku punya anak? Dan aku tinggalkan ayahku di Madinah. Bukankah Rasulullah Shallallahu 'alaihi wa Salam pernah bersabda bahwa ia (Dajjal) tidak bisa memasuki Madinah dan Makkah sementara aku telah meninggalkan Madinah dan sekarang aku hendak ke Makkah? Abu Sa'id Al Khudri berkata: Hampir saja aku menerima alasannya (Abu Sha'id). Setelah itu ia berkata: Ingat, demi Allah aku mengetahuinya (Dajjal), aku mengetahui kelahirannya dan dimana sekarang ia berada. Abu Sa'id berkata: Aku berkata padanya: Celakalah kau sepanjang hari ini."},"4821":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ مُفَضَّلٍ عَنْ أَبِي مَسْلَمَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنِ صَائِدٍ مَا تُرْبَةُ الْجَنَّةِ قَالَ دَرْمَكَةٌ بَيْضَاءُ مِسْكٌ يَا أَبَا الْقَاسِمِ قَالَ صَدَقْتَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Bisyr bin Mufadhdhal] dari [Abu Maslamah] dari [Abu Nadhrah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam bertanya kepada Ibnu Sha'id: \"Debu surga itu apa?\" ia menjawab: Debu lembut putih (seharum) kesturi, wahai Abu Al Qasim. Beliau bersabda: \"Kau benar.\""},"4822":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَرَأَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَحْلِفُ بِاللَّهِ أَنَّ ابْنَ صَائِدٍ الدَّجَّالُ فَقُلْتُ أَتَحْلِفُ بِاللَّهِ قَالَ إِنِّي سَمِعْتُ عُمَرَ يَحْلِفُ عَلَى ذَلِكَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُنْكِرْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Ambari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Ibrahim] dari [Muhammad bin Al Munkadir] berkata: Aku pernah melihat [Jabir bin Abdillah] bersumpah dengan nama Allah bahwa sesungguhnya Ibnu Sha`id itu Dajjal. Lalu aku berkata: Apakah kamu bersumpah dengan nama Allah? Ia menjawab: Sungguh aku pernah mendengar Umar bersumpah atas hal itu di depan Nabi Shallallahu 'alaihi wa Salam dan beliau tidak mengingkarinya."},"4823":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ حَرْمَلَةَ بْنِ عِمْرَانَ التُّجِيبِيُّ أَخْبَرَنِي ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ عُمَرَ بْنَ الْخَطَّابِ انْطَلَقَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ قِبَلَ ابْنِ صَيَّادٍ حَتَّى وَجَدَهُ يَلْعَبُ مَعَ الصِّبْيَانِ عِنْدَ أُطُمِ بَنِي مَغَالَةَ وَقَدْ قَارَبَ ابْنُ صَيَّادٍ يَوْمَئِذٍ الْحُلُمَ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَهْرَهُ بِيَدِهِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنِ صَيَّادٍ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَنَظَرَ إِلَيْهِ ابْنُ صَيَّادٍ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ فَقَالَ ابْنُ صَيَّادٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَرَفَضَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ آمَنْتُ بِاللَّهِ وَبِرُسُلِهِ ثُمَّ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاذَا تَرَى قَالَ ابْنُ صَيَّادٍ يَأْتِينِي صَادِقٌ وَكَاذِبٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِّطَ عَلَيْكَ الْأَمْرُ ثُمَّ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ خَبَأْتُ لَكَ خَبِيئًا فَقَالَ ابْنُ صَيَّادٍ هُوَ الدُّخُّ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ ذَرْنِي يَا رَسُولَ اللَّهِ أَضْرِبْ عُنُقَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْهُ فَلَنْ تُسَلَّطَ عَلَيْهِ وَإِنْ لَمْ يَكُنْهُ فَلَا خَيْرَ لَكَ فِي قَتْلِهِ وَقَالَ سَالِمُ بْنُ عَبْدِ اللَّهِ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ انْطَلَقَ بَعْدَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُبَيُّ بْنُ كَعْبٍ الْأَنْصَارِيُّ إِلَى النَّخْلِ الَّتِي فِيهَا ابْنُ صَيَّادٍ حَتَّى إِذَا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخْلَ طَفِقَ يَتَّقِي بِجُذُوعِ النَّخْلِ وَهُوَ يَخْتِلُ أَنْ يَسْمَعَ مِنْ ابْنِ صَيَّادٍ شَيْئًا قَبْلَ أَنْ يَرَاهُ ابْنُ صَيَّادٍ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُضْطَجِعٌ عَلَى فِرَاشٍ فِي قَطِيفَةٍ لَهُ فِيهَا زَمْزَمَةٌ فَرَأَتْ أُمُّ ابْنِ صَيَّادٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَّقِي بِجُذُوعِ النَّخْلِ فَقَالَتْ لِابْنِ صَيَّادٍ يَا صَافِ وَهُوَ اسْمُ ابْنِ صَيَّادٍ هَذَا مُحَمَّدٌ فَثَارَ ابْنُ صَيَّادٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَرَكَتْهُ بَيَّنَ قَالَ سَالِمٌ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ ذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي لَأُنْذِرُكُمُوهُ مَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَهُ قَوْمَهُ لَقَدْ أَنْذَرَهُ نُوحٌ قَوْمَهُ وَلَكِنْ أَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ تَعَلَّمُوا أَنَّهُ أَعْوَرُ وَأَنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَيْسَ بِأَعْوَرَقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي عُمَرُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ أَنَّهُ أَخْبَرَهُ بَعْضُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ حَذَّرَ النَّاسَ الدَّجَّالَ إِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ يَقْرَؤُهُ مَنْ كَرِهَ عَمَلَهُ أَوْ يَقْرَؤُهُ كُلُّ مُؤْمِنٍ وَقَالَ تَعَلَّمُوا أَنَّهُ لَنْ يَرَى أَحَدٌ مِنْكُمْ رَبَّهُ عَزَّ وَجَلَّ حَتَّى يَمُوتَ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ انْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ رَهْطٌ مِنْ أَصْحَابِهِ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ حَتَّى وَجَدَ ابْنَ صَيَّادٍ غُلَامًا قَدْ نَاهَزَ الْحُلُمَ يَلْعَبُ مَعَ الْغِلْمَانِ عِنْدَ أُطُمِ بَنِي مُعَاوِيَةَ وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ يُونُسَ إِلَى مُنْتَهَى حَدِيثِ عُمَرَ بْنِ ثَابِتٍ وَفِي الْحَدِيثِ عَنْ يَعْقُوبَ قَالَ قَالَ أُبَيٌّ يَعْنِي فِي قَوْلِهِ لَوْ تَرَكَتْهُ بَيَّنَ قَالَ لَوْ تَرَكَتْهُ أُمُّهُ بَيَّنَ أَمْرَهُ و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ وَسَلَمَةُ بْنُ شَبِيبٍ جَمِيعًا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِابْنِ صَيَّادٍ فِي نَفَرٍ مِنْ أَصْحَابِهِ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَهُوَ يَلْعَبُ مَعَ الْغِلْمَانِ عِنْدَ أُطُمِ بَنِي مَغَالَةَ وَهُوَ غُلَامٌ بِمَعْنَى حَدِيثِ يُونُسَ وَصَالِحٍ غَيْرَ أَنَّ عَبْدَ بْنَ حُمَيْدٍ لَمْ يَذْكُرْ حَدِيثَ ابْنِ عُمَرَ فِي انْطِلَاقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أُبَيِّ بْنِ كَعْبٍ إِلَى النَّخْلِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya bin Abdullah bin Harmalah bin Imran At Tujini] telah mengkhabarkan kepadaku [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] bahwa ia telah mengkhabarkan padanya bahwa [Abdullah bin Umar] telah mengkhabarkan kepadanya bahwa Umar bin Al Khaththab pergi bersama Rasulullah Shallallahu 'alaihi wa Salam dalam sebuah rombongan menuju Ibnu Shayyad hingga beliau menemukannya tengah bermain bersama anak-anak di dekat benteng bani Maghalah, saat itu Ibnu Shayyad hampir baligh, ia tidak sadar hingga Rasulullah Shallallahu 'alaihi wa Salam memukul punggunya dengan tangan beliau, setelah itu Rasulullah Shallallahu 'alaihi wa Salam bertanya kepada Ibnu Shayyad: \"Apa kau bersaksi bahwa aku utusan Allah?\" ibnu Shayyad memandang beliau lalu menjawab: Aku bersaksi bahwa Tuan adalah utusan kaum buta huruf. Ibnu Shayyad bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam: Apa Tuan bersaksi bahwa aku utusan Allah? Rasulullah Shallallahu 'alaihi wa Salam menolaknya lalu bersabda: \"Aku beriman kepada Allah dan para utusanNya.\" Setelah itu Rasulullah Shallallahu 'alaihi wa Salam bertanya: \"Apa yang kau lihat?\" Ibnu Shayyad menjawab: Seorang jujur dan seorang pendusta mendatangiku. Rasulullah Shallallahu 'alaihi wa Salam bersabda padanya: \"Masalahnya dikacaukan padamu.\" Setelah itu Rasulullah Shallallahu 'alaihi wa Salam berkata padanya: \"Aku menyembunyikan sesuatu untukmu.\" Ibnu Shayyad berkata: \"Asap.\" Lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda padanya: \"Menyingkirlah, kau tidak akan melampaui kemampuanmu.\" Umar bin Al Khaththab berkata: Biarkan aku menebas lehernya, wahai Rasulullah. Rasulullah Shallallahu 'alaihi wa Salam bersabda padanya: \"Bila ia seperti itu, kau tidak akan bisa menguasainya, bila tidak seperti itu, tidak ada baiknya bagimu membunuhnya.\" Salim bin Abdullah berkata: Aku mendengar Abdullah bin Umar bekata: Setelah itu Rasulullah Shallallahu 'alaihi wa Salam dan Ubai bin Ka'ab Al Anshari pergi menuju kebun kurma dimana Ibnu Shayyad berada hingga beliau memasuki kebun. Beliau langsung menjaga diri dengan pelepah kurma agar tidak memasang telinga supaya tidak mendengar apa pun yang dikatakan Ibnu Shayyad sebelum melihatnya. Rasulullah Shallallahu 'alaihi wa Salam melihatnya tengah berbaring di atas hamparan kain beludru miliknya. Ibu Ibnu Shayyad melihat Rasulullah Shallallahu 'alaihi wa Salam tengah menjaga diri dengan pelepah kurma, ibunya berkata padanya (Ibnu Shayyad): Hai Shaf -nama Ibnu Shayyad- ini Muhammad. Ibnu Shayyad langsung bangun, lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Andai kau membiarkannya menjelaskan.\" Salim berkata: Abdullah bin Umar berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri ditengah orang-orang, beliau memuja dan memuji dengan pujian yang layak baginya, setelah itu beliau menyebut Dajjal, beliau bersabda: \"Sesungguhnya aku mengingatkan kalian darinya. Tidak ada seorang nabi pun melainkan telah mengingatkan kaumnya dari Dajjal. Nuh telah mengingatkan kaumnya, namun aku akan menyebutkan suatu hal pada kalian yang belum pernah dikemukakan oleh seorang nabi pun kepada kaumnya: ketahuilah bahwa ia (Dajjal) buta sebalah matanya sedangkan Allah Tabaraka wa Ta'ala tidak buta sebelah mata.\" [Ibnu Syihab] berkata: telah mengkhabarkan kepadaku [Umar bin Tsabit Al Anshari] bahwa telah mengkhabarkan kepadanya [sebagaian sahabat Rasulullah Shallallahu 'alaihi wa Salam] bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda saat mengingatkan orang-orang terhadap Dajjal: \"Diantara kedua matanya tertulis KAFIR yang bisa dibaca oleh orang yang membenci perbuatannya atau bisa dibaca oleh setiap orang mu`min.\" Beliau bersabda: \"Ketahuilah, sesungguhnya tidak ada seorang pun dari kalian yang melihat Rabbnya 'azza wajalla hingga ia meninggal.\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] dan [Abdu bin Humaid] keduanya berkata: telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'id] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam pergi bersama beberapa sahabat beliau, diantara mereka ada Umar bin Al Khaththab, beliau bertemu dengan Ibnu Shayyad, seorang anak yang telah mendekati baligh, ia tengah bermain bersama anak-anak di dekat bentung bani Mu'awiyah. Ia menyebut hadits seperti hadits Yunus hingga akhir hadits Umar bin Tsabit. Disebutkan dalam hadits tersebut: Dari Ya'qub berkata: Ubai berkata tentang sabda Rasulullah Shallallahu 'alaihi wa Salam: \"Andai kau membiarkannya menjelaskan, \" yaitu andai ibunya membiarkannya (Ibnu Shayyad) tentu ia menjelaskan masalahnya. Telah menceritakan kepada kami [Abdu bin HUmaid] dan [Salamah bin Syabib], semuanya dari [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], Rasulullah Shallallahu 'alaihi wa Salam melewati Ibnu Shayyad bersama sahabat-sahabat beliau diantaranya Umar bin Al Khaththab, ia tengah bermain bersama anak-anak di dekat benteng bani Maghalah, ia (Ibnu Shayyad) adalah anak, dan seterusnya semakna dengan hadits Yunus dan Shalih, hanya saja Abdu bin Humaid tidak menyebut hadits Ibnu Umar tentang kepergian nabi Shallallahu 'alaihi wa Salam bersama Ubai bin Ka'ad menuju kebun kurma."},"4824":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا هِشَامٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَ لَقِيَ ابْنُ عُمَرَ ابْنَ صَائِدٍ فِي بَعْضِ طُرُقِ الْمَدِينَةِ فَقَالَ لَهُ قَوْلًا أَغْضَبَهُ فَانْتَفَخَ حَتَّى مَلَأَ السِّكَّةَ فَدَخَلَ ابْنُ عُمَرَ عَلَى حَفْصَةَ وَقَدْ بَلَغَهَا فَقَالَتْ لَهُ رَحِمَكَ اللَّهُ مَا أَرَدْتَ مِنْ ابْنِ صَائِدٍ أَمَا عَلِمْتَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا يَخْرُجُ مِنْ غَضْبَةٍ يَغْضَبُهَا","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Hisyam] dari [Ayyub] dari [Nafi'] berkata: [Ibnu Umar] bertemu Ibnu Sha'id disalah satu jalanan Madinah lalu Ibnu Umar mengucapkan kata-kata yang membuatnya marah, ia menggelembung hingga meamenuhi jalanan, lalu Ibnu Umar memasuki kediaman [Hafshah] dan berita itu telah sampai padanya. Hafshah berkata pada Ibnu Umar: Semoga Allah merahmatimu, apa yang kau inginkan dari Ibnu Sha'id? Bukankah kau tahu Rasulullah Shallallahu 'alaihi wa Salam pernah bersabda: \"Sesungguhnya ia keluar dari kemarahannya.\""},"4825":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الدَّجَّالَ بَيْنَ ظَهْرَانَيْ النَّاسِ فَقَالَ إِنَّ اللَّهَ تَعَالَى لَيْسَ بِأَعْوَرَ أَلَا وَإِنَّ الْمَسِيحَ الدَّجَّالَ أَعْوَرُ الْعَيْنِ الْيُمْنَى كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِئَةٌحَدَّثَنِي أَبُو الرَّبِيعِ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادٌ وَهُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ إِسْمَعِيلَ عَنْ مُوسَى بْنِ عُقْبَةَ كِلَاهُمَا عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dan [Muhammad bin Bisyr] keduanya berkata: Telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar]. Telah menceritakan kepada kami [Ibnu Numair], teks miliknya, telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] Rasulullah Shallallahu 'alaihi wa Salam menyebut Dajjal dihadapan orang-orang, beliau bersabda: \"Sesungguhnya Allah Ta'ala tidak buta sebelah mata dan sesungguhnya Al Masih Dajjal buta matanya yang kanan, matanya seperti anggur mencuat.\" Telah menceritakan kepadaku [Abu Ar Rabi'] dan [Abu Kamil] keduanya berkata: Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub]. Telah menceritakan kepada kami [Muhammad bin Abbad] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Musa bin Uqbah], keduanya dari [Nafi'] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"4826":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَ أُمَّتَهُ الْأَعْوَرَ الْكَذَّابَ أَلَا إِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ وَمَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف ر","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata: Aku mendengar [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang nabi pun melainkan telah mengingatkan umatnya dari si buta sebelah mata si pendusta. Ingat, sesungguhnya ia buta sebelah mata, sedangkan Rabb kalian tidak buta sebelah mata. Diantara kedua matanya tertulis K A F I R.\""},"4827":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الدَّجَّالُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف ر أَيْ كَافِرٌ","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] dan [Ibnu Basyar], teks milik Ibnu Al Mutsanna, keduanya berkata: Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik] nabi Allah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal, diantara kedua matanya tertulis K A F I R, yaitu kafir.\""},"4828":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالُ مَمْسُوحُ الْعَيْنِ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ ثُمَّ تَهَجَّاهَا ك ف ر يَقْرَؤُهُ كُلُّ مُسْلِمٍ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Abdulwarits] dari [Syu'aib bin Al Habhab] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal, matanya buta, diantara kedua matanya tertulis 'Kafir' -beliau mengeja K A F I R- setiap muslim bisa membacanya.\""},"4829":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَمُحَمَّدُ بْنُ الْعَلَاءِ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالُ أَعْوَرُ الْعَيْنِ الْيُسْرَى جُفَالُ الشَّعَرِ مَعَهُ جَنَّةٌ وَنَارٌ فَنَارُهُ جَنَّةٌ وَجَنَّتُهُ نَارٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair], [Muhammad bin Al Ala`] dan [Ishaq bin Ibrahim], berkata Ishaq: Telah mengkhabarkan kepada kami, sementara yang lain berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Hudzaifah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal, buta mata sebelah kanan, berambut ikal, bersamanya ada surga dan neraka, nerakanya adalah surga dan surganya adalah neraka.\""},"4830":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنَا أَعْلَمُ بِمَا مَعَ الدَّجَّالِ مِنْهُ مَعَهُ نَهْرَانِ يَجْرِيَانِ أَحَدُهُمَا رَأْيَ الْعَيْنِ مَاءٌ أَبْيَضُ وَالْآخَرُ رَأْيَ الْعَيْنِ نَارٌ تَأَجَّجُ فَإِمَّا أَدْرَكَنَّ أَحَدٌ فَلْيَأْتِ النَّهْرَ الَّذِي يَرَاهُ نَارًا وَلْيُغَمِّضْ ثُمَّ لْيُطَأْطِئْ رَأْسَهُ فَيَشْرَبَ مِنْهُ فَإِنَّهُ مَاءٌ بَارِدٌ وَإِنَّ الدَّجَّالَ مَمْسُوحُ الْعَيْنِ عَلَيْهَا ظَفَرَةٌ غَلِيظَةٌ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ يَقْرَؤُهُ كُلُّ مُؤْمِنٍ كَاتِبٍ وَغَيْرِ كَاتِبٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Abu Malik Al Asyja'i] dari [Rib'I bin Hirasy] dari [Hudzaifah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sungguh aku tahu apa yang ada bersama Dajjal, bersamanya ada dua sungai mengalir. Salah satunya secara kasat mata berupa air putih dan yang lainnya secara kasat mata berupa api yang bergejolak. Bila ada yang menjumpainya, hendaklah mendatangi surga yang ia lihat berupa api dan hendaklah menutup mata, kemudian hendaklah menundukkan kepala lalu meminumnya karena sesungguhnya itu adalah air dingin. Sesungguhnya Dajjal buta matanya, di atas matanya ada kulit tebal, diantara kedua matanya tertulis KAFIR yang bisa dibaca oleh setiap mu`min yang bisa baca tulis atau pun tidak.\""},"4831":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لَهُ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الدَّجَّالِ إِنَّ مَعَهُ مَاءً وَنَارًا فَنَارُهُ مَاءٌ بَارِدٌ وَمَاؤُهُ نَارٌ فَلَا تَهْلِكُواقَالَ أَبُو مَسْعُودٍ وَأَنَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah]. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], teks miliknya, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdulmalik bin Umair] dari [Rib'I bin Hirasy] dari [Hudzaifah] dari nabi Shallallahu 'alaihi wa Salam bersabda tentang Dajjal: \"Sesungguhnya bersamanya ada air dan api, apanya adalah air dingin dan airnya adalah api, karena itu janganlah kalian binasa.\" [Abu Mas'ud] berkata: Aku mendengarnya dari Rasulullah Shallallahu 'alaihi wa Salam."},"4832":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا شُعَيْبُ بْنُ صَفْوَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عُقْبَةَ بْنِ عَمْرٍو أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَانْطَلَقْتُ مَعَهُ إِلَى حُذَيْفَةَ بْنِ الْيَمَانِ فَقَالَ لَهُ عُقْبَةُ حَدِّثْنِي مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الدَّجَّالِ قَالَ إِنَّ الدَّجَّالَ يَخْرُجُ وَإِنَّ مَعَهُ مَاءً وَنَارًا فَأَمَّا الَّذِي يَرَاهُ النَّاسُ مَاءً فَنَارٌ تُحْرِقُ وَأَمَّا الَّذِي يَرَاهُ النَّاسُ نَارًا فَمَاءٌ بَارِدٌ عَذْبٌ فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَلْيَقَعْ فِي الَّذِي يَرَاهُ نَارًا فَإِنَّهُ مَاءٌ عَذْبٌ طَيِّبٌ فَقَالَ عُقْبَةُ وَأَنَا قَدْ سَمِعْتُهُ تَصْدِيقًا لِحُذَيْفَةَ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Syu'aib bin Shafwan] dari [Abdulmalik bin Umair] dari [Rib'I bin Hirays] dari [Uqbah bin Amru Abu Mas'ud Al Anshari] berkata: Aku pergi bersamanya untuk menemui [Hudzaifah bin Al Yaman], lalu Uqbah berkata padanya: Ceritakanlah kepadaku apa yang kau dengar dari Rasulullah Shallallahu 'alaihi wa Salam tentang Dajjal! Ia berkata: Dajjal muncul bersama air dan api. Yang dilihat manusia berupa air adalah api yang membakar dan yang dilihat manusia berupa api adalah air dingin tawar. Siapa pun diantara kalian yang menjumpainya, hendaklah memilih yang terlihat seperti api, karena sesungguhnya itu adalah air tawar yang baik. Uqbah berkata: Aku pernah mendengarnya, sebagai pembenaran untuk Hudzaifah."},"4833":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِابْنِ حُجْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا و قَالَ ابْنُ حُجْرٍ حَدَّثَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ قَالَاجْتَمَعَ حُذَيْفَةُ وَأَبُو مَسْعُودٍ فَقَالَ حُذَيْفَةُ لَأَنَا بِمَا مَعَ الدَّجَّالِ أَعْلَمُ مِنْهُ إِنَّ مَعَهُ نَهْرًا مِنْ مَاءٍ وَنَهْرًا مِنْ نَارٍ فَأَمَّا الَّذِي تَرَوْنَ أَنَّهُ نَارٌ مَاءٌ وَأَمَّا الَّذِي تَرَوْنَ أَنَّهُ مَاءٌ نَارٌ فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَأَرَادَ الْمَاءَ فَلْيَشْرَبْ مِنْ الَّذِي يَرَاهُ أَنَّهُ نَارٌ فَإِنَّهُ سَيَجِدُهُ مَاءًقَالَ أَبُو مَسْعُودٍ هَكَذَا سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","id":"Telah menceritakan kepada kami [Ali bin Hujr As Sa'di] dan [Ishaq bin Ibrahim], teks milik Ibnu Hujr, berkata Ishaq: Telah mengkhabarkan kepada kami, sementara Ibnu Hujr berkata: Telah menceritakan kepada kami [Jarir] dari [Al Mughirah] dari [Nu'aim bin Abu Hind] dari [Rib'I bin Hirasy] berkata: [Hudzaifah] dan [Abu Mas'ud] berkumpul, Hudzaifah berkata: Aku paling tahu ada yang ada bersama Dajjal, sesungguhnya bersamanya ada sungai dari air dan sungai dari api. Yang kalian lihat seperti api adalah air dan yang kalian lihat seperti air adalah api. Siapapun dari kalian yang menjumpainya lalu menginginkan air, hendalah minum dari sungai yang terlihat api karena ia akan menemukannya berupa air. Abu Mas'ud berkata: Seperti itu sabda yang aku dengar dari nabi Shallallahu 'alaihi wa Salam."},"4834":{"ar":"حَدَّثَنَا أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي يَحْيَى بْنُ جَابِرٍ الطَّائِيُّ قَاضِي حِمْصَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرٍ عَنْ أَبِيهِ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ أَنَّهُ سَمِعَ النَّوَّاسَ بْنَ سَمْعَانَ الْكِلَابِيَّ ح و حَدَّثَنِي مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ وَاللَّفْظُ لَهُ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ النَّوَّاسِ بْنِ سَمْعَانَ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالَ ذَاتَ غَدَاةٍ فَخَفَّضَ فِيهِ وَرَفَّعَ حَتَّى ظَنَنَّاهُ فِي طَائِفَةِ النَّخْلِ فَلَمَّا رُحْنَا إِلَيْهِ عَرَفَ ذَلِكَ فِينَا فَقَالَ مَا شَأْنُكُمْ قُلْنَا يَا رَسُولَ اللَّهِ ذَكَرْتَ الدَّجَّالَ غَدَاةً فَخَفَّضْتَ فِيهِ وَرَفَّعْتَ حَتَّى ظَنَنَّاهُ فِي طَائِفَةِ النَّخْلِ فَقَالَ غَيْرُ الدَّجَّالِ أَخْوَفُنِي عَلَيْكُمْ إِنْ يَخْرُجْ وَأَنَا فِيكُمْ فَأَنَا حَجِيجُهُ دُونَكُمْ وَإِنْ يَخْرُجْ وَلَسْتُ فِيكُمْ فَامْرُؤٌ حَجِيجُ نَفْسِهِ وَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ إِنَّهُ شَابٌّ قَطَطٌ عَيْنُهُ طَافِئَةٌ كَأَنِّي أُشَبِّهُهُ بِعَبْدِ الْعُزَّى بْنِ قَطَنٍ فَمَنْ أَدْرَكَهُ مِنْكُمْ فَلْيَقْرَأْ عَلَيْهِ فَوَاتِحَ سُورَةِ الْكَهْفِ إِنَّهُ خَارِجٌ خَلَّةً بَيْنَ الشَّأْمِ وَالْعِرَاقِ فَعَاثَ يَمِينًا وَعَاثَ شِمَالًا يَا عِبَادَ اللَّهِ فَاثْبُتُوا قُلْنَا يَا رَسُولَ اللَّهِ وَمَا لَبْثُهُ فِي الْأَرْضِ قَالَ أَرْبَعُونَ يَوْمًا يَوْمٌ كَسَنَةٍ وَيَوْمٌ كَشَهْرٍ وَيَوْمٌ كَجُمُعَةٍ وَسَائِرُ أَيَّامِهِ كَأَيَّامِكُمْ قُلْنَا يَا رَسُولَ اللَّهِ فَذَلِكَ الْيَوْمُ الَّذِي كَسَنَةٍ أَتَكْفِينَا فِيهِ صَلَاةُ يَوْمٍ قَالَ لَا اقْدُرُوا لَهُ قَدْرَهُ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا إِسْرَاعُهُ فِي الْأَرْضِ قَالَ كَالْغَيْثِ اسْتَدْبَرَتْهُ الرِّيحُ فَيَأْتِي عَلَى الْقَوْمِ فَيَدْعُوهُمْ فَيُؤْمِنُونَ بِهِ وَيَسْتَجِيبُونَ لَهُ فَيَأْمُرُ السَّمَاءَ فَتُمْطِرُ وَالْأَرْضَ فَتُنْبِتُ فَتَرُوحُ عَلَيْهِمْ سَارِحَتُهُمْ أَطْوَلَ مَا كَانَتْ ذُرًا وَأَسْبَغَهُ ضُرُوعًا وَأَمَدَّهُ خَوَاصِرَ ثُمَّ يَأْتِي الْقَوْمَ فَيَدْعُوهُمْ فَيَرُدُّونَ عَلَيْهِ قَوْلَهُ فَيَنْصَرِفُ عَنْهُمْ فَيُصْبِحُونَ مُمْحِلِينَ لَيْسَ بِأَيْدِيهِمْ شَيْءٌ مِنْ أَمْوَالِهِمْ وَيَمُرُّ بِالْخَرِبَةِ فَيَقُولُ لَهَا أَخْرِجِي كُنُوزَكِ فَتَتْبَعُهُ كُنُوزُهَا كَيَعَاسِيبِ النَّحْلِ ثُمَّ يَدْعُو رَجُلًا مُمْتَلِئًا شَبَابًا فَيَضْرِبُهُ بِالسَّيْفِ فَيَقْطَعُهُ جَزْلَتَيْنِ رَمْيَةَ الْغَرَضِ ثُمَّ يَدْعُوهُ فَيُقْبِلُ وَيَتَهَلَّلُ وَجْهُهُ يَضْحَكُ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ بَعَثَ اللَّهُ الْمَسِيحَ ابْنَ مَرْيَمَ فَيَنْزِلُ عِنْدَ الْمَنَارَةِ الْبَيْضَاءِ شَرْقِيَّ دِمَشْقَ بَيْنَ مَهْرُودَتَيْنِ وَاضِعًا كَفَّيْهِ عَلَى أَجْنِحَةِ مَلَكَيْنِ إِذَا طَأْطَأَ رَأْسَهُ قَطَرَ وَإِذَا رَفَعَهُ تَحَدَّرَ مِنْهُ جُمَانٌ كَاللُّؤْلُؤِ فَلَا يَحِلُّ لِكَافِرٍ يَجِدُ رِيحَ نَفَسِهِ إِلَّا مَاتَ وَنَفَسُهُ يَنْتَهِي حَيْثُ يَنْتَهِي طَرْفُهُ فَيَطْلُبُهُ حَتَّى يُدْرِكَهُ بِبَابِ لُدٍّ فَيَقْتُلُهُ ثُمَّ يَأْتِي عِيسَى ابْنَ مَرْيَمَ قَوْمٌ قَدْ عَصَمَهُمْ اللَّهُ مِنْهُ فَيَمْسَحُ عَنْ وُجُوهِهِمْ وَيُحَدِّثُهُمْ بِدَرَجَاتِهِمْ فِي الْجَنَّةِ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أَوْحَى اللَّهُ إِلَى عِيسَى إِنِّي قَدْ أَخْرَجْتُ عِبَادًا لِي لَا يَدَانِ لِأَحَدٍ بِقِتَالِهِمْ فَحَرِّزْ عِبَادِي إِلَى الطُّورِ وَيَبْعَثُ اللَّهُ يَأْجُوجَ وَمَأْجُوجَ وَهُمْ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ فَيَمُرُّ أَوَائِلُهُمْ عَلَى بُحَيْرَةِ طَبَرِيَّةَ فَيَشْرَبُونَ مَا فِيهَا وَيَمُرُّ آخِرُهُمْ فَيَقُولُونَ لَقَدْ كَانَ بِهَذِهِ مَرَّةً مَاءٌ وَيُحْصَرُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ حَتَّى يَكُونَ رَأْسُ الثَّوْرِ لِأَحَدِهِمْ خَيْرًا مِنْ مِائَةِ دِينَارٍ لِأَحَدِكُمْ الْيَوْمَ فَيَرْغَبُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ فَيُرْسِلُ اللَّهُ عَلَيْهِمْ النَّغَفَ فِي رِقَابِهِمْ فَيُصْبِحُونَ فَرْسَى كَمَوْتِ نَفْسٍ وَاحِدَةٍ ثُمَّ يَهْبِطُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ إِلَى الْأَرْضِ فَلَا يَجِدُونَ فِي الْأَرْضِ مَوْضِعَ شِبْرٍ إِلَّا مَلَأَهُ زَهَمُهُمْ وَنَتْنُهُمْ فَيَرْغَبُ نَبِيُّ اللَّهِ عِيسَى وَأَصْحَابُهُ إِلَى اللَّهِ فَيُرْسِلُ اللَّهُ طَيْرًا كَأَعْنَاقِ الْبُخْتِ فَتَحْمِلُهُمْ فَتَطْرَحُهُمْ حَيْثُ شَاءَ اللَّهُ ثُمَّ يُرْسِلُ اللَّهُ مَطَرًا لَا يَكُنُّ مِنْهُ بَيْتُ مَدَرٍ وَلَا وَبَرٍ فَيَغْسِلُ الْأَرْضَ حَتَّى يَتْرُكَهَا كَالزَّلَفَةِ ثُمَّ يُقَالُ لِلْأَرْضِ أَنْبِتِي ثَمَرَتَكِ وَرُدِّي بَرَكَتَكِ فَيَوْمَئِذٍ تَأْكُلُ الْعِصَابَةُ مِنْ الرُّمَّانَةِ وَيَسْتَظِلُّونَ بِقِحْفِهَا وَيُبَارَكُ فِي الرِّسْلِ حَتَّى أَنَّ اللِّقْحَةَ مِنْ الْإِبِلِ لَتَكْفِي الْفِئَامَ مِنْ النَّاسِ وَاللِّقْحَةَ مِنْ الْبَقَرِ لَتَكْفِي الْقَبِيلَةَ مِنْ النَّاسِ وَاللِّقْحَةَ مِنْ الْغَنَمِ لَتَكْفِي الْفَخِذَ مِنْ النَّاسِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ بَعَثَ اللَّهُ رِيحًا طَيِّبَةً فَتَأْخُذُهُمْ تَحْتَ آبَاطِهِمْ فَتَقْبِضُ رُوحَ كُلِّ مُؤْمِنٍ وَكُلِّ مُسْلِمٍ وَيَبْقَى شِرَارُ النَّاسِ يَتَهَارَجُونَ فِيهَا تَهَارُجَ الْحُمُرِ فَعَلَيْهِمْ تَقُومُ السَّاعَةُحَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ وَالْوَلِيدُ بْنُ مُسْلِمٍ قَالَ ابْنُ حُجْرٍ دَخَلَ حَدِيثُ أَحَدِهِمَا فِي حَدِيثِ الْآخَرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ بِهَذَا الْإِسْنَادِ نَحْوَ مَا ذَكَرْنَا وَزَادَ بَعْدَ قَوْلِهِ لَقَدْ كَانَ بِهَذِهِ مَرَّةً مَاءٌ ثُمَّ يَسِيرُونَ حَتَّى يَنْتَهُوا إِلَى جَبَلِ الْخَمَرِ وَهُوَ جَبَلُ بَيْتِ الْمَقْدِسِ فَيَقُولُونَ لَقَدْ قَتَلْنَا مَنْ فِي الْأَرْضِ هَلُمَّ فَلْنَقْتُلْ مَنْ فِي السَّمَاءِ فَيَرْمُونَ بِنُشَّابِهِمْ إِلَى السَّمَاءِ فَيَرُدُّ اللَّهُ عَلَيْهِمْ نُشَّابَهُمْ مَخْضُوبَةً دَمًا وَفِي رِوَايَةِ ابْنِ حُجْرٍ فَإِنِّي قَدْ أَنْزَلْتُ عِبَادًا لِي لَا يَدَيْ لِأَحَدٍ بِقِتَالِهِمْ","id":"Telah menceritakan kepada kami [Abu Khaitsamah Zuhair bin Harb] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepadaku [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Yahya bin Jabir Ath Tho`i] hakim Himsh, telah menceritakan kepadaku [Aburrahman bin Jubair] dari [ayahnya, Jubair bin Nufair Al Hadlrami] ia mendengar [An Nawwas bin Sam'an Al Kilabi]. Telah menceritakan kepadaku [Muhammad bin Mihran Ar Razi], teks miliknya, telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abdurrahman bin Yazid bin Jabir] dari [Yahya bin Jabir Ath Tha`i] dari [Abdurrahman bin Jubair bin Nufair] dari [ayahnya, Jubair bin Nufair] dari [An Nawwas bin Sam'an] berkata: Pada suatu pagi, Rasulullah Shallallahu 'alaihi wa Salam menyebut Dajjal, beliau melirihkan suara dan mengeraskannya hingga kami mengiranya berada disekelompok pohon kurma. Kami pergi meninggalkan Rasulullah Shallallahu 'alaihi wa Salam lalu kami kembali lagi, beliau mengetahui hal itu pada kami lalu beliau bertanya: \"Kenapa kalian?\" kami menjawab: wahai Rasulullah, Tuan menyebut Dajjal pada suatu pagi, Tuan melirihkan dan mengeraskan suara hingga kami mengiranya ada disekelompok pohon kurma, beliau bersabda: \"Selain Dajjal yang lebih aku khawatirkan pada kalian, bila ia muncul dan aku berada ditengah-tengah kalian, aku akan mengalahkannya, bukan kalian dan bila ia muncul dan aku sudah tidak ada ditengah-tengah kalian, maka setiap orang adalah pembela dirinya sendiri dan Allah adalah penggantiku atas setiap muslim, ia adalah pemuda ikal, matanya menonjol, mirip 'Abdu Al 'Uzza bin Qathan. Siapa pun diantara kalian yang melihatnya hendaklah membaca permulaan surat Al Kahfi, ia muncul diantara Syam dan 'Irak lalu banyak membuat kerusakan dikanan dan dikiri, wahai hamba-hamba Allah, teguhlah kalian.\" Kami bertanya: Berapa lama ia tinggal di bumi? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Empat puluh hari, satu hari seperti setahun, satu hari seperti sebulan, satu hari seperti satu pekan dan hari-hari lainnya seperti hari-hari kalian.\" Kami bertanya: Wahai Rasulullah, bagaimana menurut Tuan tentang satu hari yang seperti satu tahun, cukupkah bagi kami shalat sehari? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak, tapi perkirakanlah ukurannya.\" Kami bertanya: Wahai Rasulullah, bagaimana kecepatannya di bumi? Rasulullah Shallallahu 'alaihi wa Salam menjawab: Seperti hujan yang diakhiri angin. Ia mendatangi kaum dan menyeru mereka, mereka menerimanya, ia memerintahkan langit agar menurunkan hujan, langit lalu menurunkan hujan, ia memerintahkan bumi agar mengeluarkan tumbuh-tumbuhan, bumi lalu mengeluarkan tumbuh-tumbuhan lalu binatang ternak mereka pergi dengan punuk yang panjang, lambung yang lebar dan kantong susu yang berisi lalu kehancuran datang lalu ia berkata padanya: 'Keluarkan harta simpananmu.' Lalu harta simpanannya mengikutinya seperti lebah-lebah jantan. Kemudian ia memanggil seorang pemuda belia, ia menebasnya dengan pedang lalu memutusnya menjadi dua bagian lalu memanggilnya, ia datang memanggut-manggutkan wajahnya seraya tertawa, saat ia seperti itu, tiba-tiba 'Isa putra Maryam turun di sebelah timur Damaskus di menara putih dengan mengenakan dua baju berwantek za'faran seraya meletakkan kedua tangannya diatas sayap dua malaikat, bila ia menundukkan kepala, air menetas dan bila ia mengangkat kepala keringat bercucuran seperti mutiara, tidaklah orang kafir mencium bau dirinya kecuali mati dan bau nafasnya sejauh matanya memandang. Isa mencari Dajjal hingga menemuinya di pintu Ludd lalu membunuhnya. Setelah itu Isa putra Maryam mendatangi suatu kaum yang dijaga oleh Allah dari Dajjal. Ia mengusap wajah-wajah mereka dan menceritakan tingkatan-tingkatan mereka disurga. Saat mereka seperti itu, Allah mewahyukan padanya: 'Sesungguhnya Aku telah mengeluarkan hamba-hambaKu, tidak ada yang bisa memerangi mereka, karena itu giringlah hamba-hambaKu ke Thur. Allah mengirim Ya'juj dan Ma'juj, 'Dari segala penjuru mereka datang dengan cepat.' (Al Anbiyaa`: 96) Lalu yang terdepan melintasi danau Thabari dan minum kemudian yang belakang melintasi, mereka berkata: 'Tadi disini ada airnya.' nabi Allah Isa dan para sahabatnya dikepung hingga kepala kerbau milik salah seorang dari mereka lebih baik dari seratus dinar milik salah seorang dari kalian saat ini, lalu nabi Allah Isa dan para sahabatnya menginginkan Allah mengirimkan cacing di leher mereka lalu mereka mati seperti matinya satu jiwa, lalu 'Isa dan para sahabatnya datang, tidak ada satu sejengkal tempat pun melainkan telah dipenuhi oleh bangkai dan bau busuk darah mereka. Lalu Isa dan para sahabatnya berdoa kepada Allah lalu Allah mengirim burung seperti leher unta. Burung itu membawa mereka dan melemparkan mereka seperti yang dikehendaki Allah, lalu Allah mengirim hujan kepada mereka, tidak ada rumah dari bulu atau rumah dari tanah yang menghalangi turunnya hujan, hujan itu membasahi bumi hingga dan meninggalkan genangan dimana-mana. Allah memberkahi kesuburannya hingga hingga sekelompok manusia cukup dengan unta perahan, satu kabilah cukup dengan sapi perahan dan beberapa kerabat mencukupkan diri dengan kambing perahan. Saat mereka seperti itu, tiba-tiba Allah mengirim angin sepoi-sepoi lalu mencabut nyawa setiap orang mu`min dan muslim dibawah ketiak mereka, dan orang-orang yang tersisa adalah manusia-manusia buruk, mereka melakukan hubungan badan secara tenang-terangan seperti keledai kawin. Maka atas mereka itulah kiamat terjadi.\" Telah menceritakan kepada kami [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Abdullah bin Aburrahman bin Yazid bin Jabir] dan [Al Walid bin Muslim], berkata Ibnu Hujr: Hadits salah satunya membaur pada hadits yang lain. Dari [Abdurrahman bin Yazid bin Jabir] dengan sanad ini seperti yang telah kami sebutkan, tapi ia menambahkan setelah sabda beliau: \"Tadi disini ada airnya, \" \"Mereka berjalan hingga sampai gunung khamar, gunung Baitul Maqdis, mereka berkata: 'Kita telah membunuh orang-orang yang ada di bumi, ayo kita bunuh yang ada di langit.' Mereka pun melesakkan panah mereka ke langit lalu Allah membalikkan panah mereka bermerah darah.\" Disebutkan dalam riwayat Ibnu Hujr: \"Sesungguhnya Aku telah menurunkan hamba-hambaKu, tidak ada seorang pun yang bisa memerangi mereka.\""},"4835":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ وَالْحَسَنُ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ وَالسِّيَاقُ لِعَبْدٍ قَالَ حَدَّثَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا حَدِيثًا طَوِيلًا عَنْ الدَّجَّالِ فَكَانَ فِيمَا حَدَّثَنَا قَالَ يَأْتِي وَهُوَ مُحَرَّمٌ عَلَيْهِ أَنْ يَدْخُلَ نِقَابَ الْمَدِينَةِ فَيَنْتَهِي إِلَى بَعْضِ السِّبَاخِ الَّتِي تَلِي الْمَدِينَةَ فَيَخْرُجُ إِلَيْهِ يَوْمَئِذٍ رَجُلٌ هُوَ خَيْرُ النَّاسِ أَوْ مِنْ خَيْرِ النَّاسِ فَيَقُولُ لَهُ أَشْهَدُ أَنَّكَ الدَّجَّالُ الَّذِي حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَهُ فَيَقُولُ الدَّجَّالُ أَرَأَيْتُمْ إِنْ قَتَلْتُ هَذَا ثُمَّ أَحْيَيْتُهُ أَتَشُكُّونَ فِي الْأَمْرِ فَيَقُولُونَ لَا قَالَ فَيَقْتُلُهُ ثُمَّ يُحْيِيهِ فَيَقُولُ حِينَ يُحْيِيهِ وَاللَّهِ مَا كُنْتُ فِيكَ قَطُّ أَشَدَّ بَصِيرَةً مِنِّي الْآنَ قَالَ فَيُرِيدُ الدَّجَّالُ أَنْ يَقْتُلَهُ فَلَا يُسَلَّطُ عَلَيْهِقَالَ أَبُو إِسْحَقَ يُقَالُ إِنَّ هَذَا الرَّجُلَ هُوَ الْخَضِرُ عَلَيْهِ السَّلَام و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ","id":"Telah menceritakan kepadaku [Amru An Naqid], [Al Hasan Al Hulwani] dan [Abdulhamid bin Humaid], teks mereka hampir sama dan teks berikut milik Abdu, ia berkata: Telah menceritakan kepadaku, sementara yang lain berkata: Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Ubaidullah bin Abdullah bin Utbah] bahwa [Abu Sa'id Al Khudri] berkata: Telah menceritakan kepada kami Rasulullah Shallallahu 'alaihi wa Salam pada suatu hari cerita yang panjang tentang Dajjal, diantara yang beliau ceritakan kepada kami adalah: \"Ia mendatangi jalan di gunung Madinah -padahal Madinah diharamkan baginya- hingga tiba di sebagaian tanah setelah Madinah. Saat itu seorang manusia terbaik atau diantara yang terbaik menghadangnya, ia berkata, 'Aku bersaksi bahwa kau adalah Dajjal yang pernah diceritakan Rasulullah Shallallahu 'alaihi wa Salam kepada kami.' Dajjal berkata: 'Bagaimana menurutmu, bila aku membunuh orang ini lalu aku menghidupkannya kembali, apa kau masih meragukannya? ' mereka menjawab: 'Tidak.' Dajjal pun membunuhnya lalu menghidupkannya kembali. Saat menghidupkannya, ia berkata: 'Demi Allah, aku tidak pernah lebih memahamimu melebihi saat ini.' lalu Dajjal ingin membunuhnya tapi ia tidak mampu mengusainya'.\" Abu Ishaq berkata: Ada yang mengatakan bahwa orang itu adalah Khadhir 'alaihis Salam. Telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah mengkhabarkan kepada kami [Abu Al Yaman] telah mengkhabarkan kepada kami [Syu'aib] dari [Az Zuhri] dalam sanad ini dengan matan serupa."},"4836":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ قُهْزَاذَ مِنْ أَهْلِ مَرْوَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ أَبِي حَمْزَةَ عَنْ قَيْسِ بْنِ وَهْبٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ الدَّجَّالُ فَيَتَوَجَّهُ قِبَلَهُ رَجُلٌ مِنْ الْمُؤْمِنِينَ فَتَلْقَاهُ الْمَسَالِحُ مَسَالِحُ الدَّجَّالِ فَيَقُولُونَ لَهُ أَيْنَ تَعْمِدُ فَيَقُولُ أَعْمِدُ إِلَى هَذَا الَّذِي خَرَجَ قَالَ فَيَقُولُونَ لَهُ أَوَ مَا تُؤْمِنُ بِرَبِّنَا فَيَقُولُ مَا بِرَبِّنَا خَفَاءٌ فَيَقُولُونَ اقْتُلُوهُ فَيَقُولُ بَعْضُهُمْ لِبَعْضٍ أَلَيْسَ قَدْ نَهَاكُمْ رَبُّكُمْ أَنْ تَقْتُلُوا أَحَدًا دُونَهُ قَالَ فَيَنْطَلِقُونَ بِهِ إِلَى الدَّجَّالِ فَإِذَا رَآهُ الْمُؤْمِنُ قَالَ يَا أَيُّهَا النَّاسُ هَذَا الدَّجَّالُ الَّذِي ذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَيَأْمُرُ الدَّجَّالُ بِهِ فَيُشَبَّحُ فَيَقُولُ خُذُوهُ وَشُجُّوهُ فَيُوسَعُ ظَهْرُهُ وَبَطْنُهُ ضَرْبًا قَالَ فَيَقُولُ أَوَ مَا تُؤْمِنُ بِي قَالَ فَيَقُولُ أَنْتَ الْمَسِيحُ الْكَذَّابُ قَالَ فَيُؤْمَرُ بِهِ فَيُؤْشَرُ بِالْمِئْشَارِ مِنْ مَفْرِقِهِ حَتَّى يُفَرَّقَ بَيْنَ رِجْلَيْهِ قَالَ ثُمَّ يَمْشِي الدَّجَّالُ بَيْنَ الْقِطْعَتَيْنِ ثُمَّ يَقُولُ لَهُ قُمْ فَيَسْتَوِي قَائِمًا قَالَ ثُمَّ يَقُولُ لَهُ أَتُؤْمِنُ بِي فَيَقُولُ مَا ازْدَدْتُ فِيكَ إِلَّا بَصِيرَةً قَالَ ثُمَّ يَقُو��ُ يَا أَيُّهَا النَّاسُ إِنَّهُ لَا يَفْعَلُ بَعْدِي بِأَحَدٍ مِنْ النَّاسِ قَالَ فَيَأْخُذُهُ الدَّجَّالُ لِيَذْبَحَهُ فَيُجْعَلَ مَا بَيْنَ رَقَبَتِهِ إِلَى تَرْقُوَتِهِ نُحَاسًا فَلَا يَسْتَطِيعُ إِلَيْهِ سَبِيلًا قَالَ فَيَأْخُذُ بِيَدَيْهِ وَرِجْلَيْهِ فَيَقْذِفُ بِهِ فَيَحْسِبُ النَّاسُ أَنَّمَا قَذَفَهُ إِلَى النَّارِ وَإِنَّمَا أُلْقِيَ فِي الْجَنَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا أَعْظَمُ النَّاسِ شَهَادَةً عِنْدَ رَبِّ الْعَالَمِينَ","id":"Telah menceritakan kepadaku [Muhammad bin Abdullah bin Qahzadz] salah satu penduduk Marw, telah menceritakan kepada kami [Abdullah bin Utsman] dari [Abu Hamzah] dari [Qais bin Wahab] dari [Abu Al Waddak] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal muncul lalu seseorang dari kalangan kaum mu`minin menuju ke arahnya lalu bala tentara Dajjal yang bersenjata menemuinya, mereka bertanya: 'Kau mau kemana? ' mu`min itu menjawab: 'Hendak ke orang yang muncul itu.' Mereka bertanya: 'Apa kau tidak beriman ada tuhan kami? ' mu`min itu menjawab: 'Rabb kami tidaklah samar.' Mereka berkata: 'Bunuh dia.' Lalu mereka saling berkata satu sama lain: 'Bukankah tuhan kita melarang kalian membunuh seorang pun selain dia.' Mereka membawanya menuju Dajjal. Saat orang mu`min melihatnya, ia berkata, 'Wahai sekalian manusia, inilah Dajjal yang disebut oleh Rasulullah Shallallahu 'alaihi wa Salam.' Lalu Dajjal memerintahkan agar dibelah. Ia berkata, 'Ambil dan belahlahlah dia.' Punggung dan perutnya dipenuhi pukulan lalu Dajjal bertanya: 'Apa kau tidak beriman padaku? ' mu`min itu menjawab: 'Kau adalah Al Masih pendusta? ' lalu Dajjal memerintahkannya digergaji dari ujung kepala hingga pertengahan antara kedua kaki. Setelah itu Dajjal berjalan di antara dua potongan tubuh itu lalu berkata: 'Berdirilah, ' tubuh itu pun berdiri. Selanjutnya Dajjal bertanya padanya: 'Apa kau beriman padaku? ' ia menjawab: 'Aku semakin mengetahuimu.' Setelah itu Dajjal berkata: 'Wahai sekalian manusia, sesungguhnya tidak ada seorang pun yang dilakukan seperti ini setelahku.' Lalu Dajjal mengambilnya untuk disembelih, kemudian antara leher dan tulang selangkanya diberi perak, tapi Dajjal tidak mampu membunuhnya. Kemudian kedua tangan dan kaki orang itu diambil lalu dilemparkan, orang-orang mengiranya dilempari ke neraka, tapi sesungguhnya ia dilemparkan ke surga.\" Setelah itu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dia adalah manusia yang kesaksiannya paling agung disisi Rabb seluruh alam.\""},"4837":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ الْعَبْدِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ الرُّؤَاسِيُّ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَمَا سَأَلَ أَحَدٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّجَّالِ أَكْثَرَ مِمَّا سَأَلْتُ قَالَ وَمَا يُنْصِبُكَ مِنْهُ إِنَّهُ لَا يَضُرُّكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُمْ يَقُولُونَ إِنَّ مَعَهُ الطَّعَامَ وَالْأَنْهَارَ قَالَ هُوَ أَهْوَنُ عَلَى اللَّهِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Syihab bin Abbad Al Abdi] telah menceritakan kepada kami [Ibrahim bin Humaid Ar Ru`asi] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah] berkata: Tidak ada seorang pun yang lebih banyak bertanya tentang Dajjal kepada nabi Shallallahu 'alaihi wa Salam melebihiku. Beliau bertanya: \"Apa yang memberatkanmu darinya, sesungguhnya ia tidak membahayakanmu.\" aku menjawab: Wahai Rasulullah, sesungguhnya mereka mengatakan bahwa bersamanya ada makanan dan sungai. Beliau bersabda: \"Itu lebih mudah bagi Allah.\""},"4838":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ حَدَّثَنَا هُشَيْمٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَمَا سَأَلَ أَحَدٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّجَّالِ أَكْثَرَ مِمَّا سَأَلْتُهُ قَالَ وَمَا سُؤَالُكَ قَالَ قُلْتُ إِنَّهُمْ يَقُولُونَ مَعَهُ جِبَالٌ مِنْ خُبْزٍ وَلَحْمٍ وَنَهَرٌ مِنْ مَاءٍ قَالَ هُوَ أَهْوَنُ عَلَى اللَّهِ مِنْ ذَلِكَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أُسَامَةَ كُلُّهُمْ عَنْ إِسْمَعِيلَ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ إِبْرَاهِيمَ بْنِ حُمَيْدٍ وَزَادَ فِي حَدِيثِ يَزِيدَ فَقَالَ لِي أَيْ بُنَيَّ","id":"Telah menceritakan kepada kami [Suraij bin Yunus] telah menceritakan kepada kami [Husyaim] dari [Isma'il] dari [Qais] dari [Al Mughirah bin Syu'bah] berkata: Tidak ada seorang pun yang lebih banyak bertanya tentang Dajjal kepada nabi Shallallahu 'alaihi wa Salam melebihiku. Beliau bertanya: \"Apa pertanyaanmu?\" aku berkata: Sesungguhnya mereka mengatakan bahwa bersamanya ada gunung dari roti, daging dan sungai dari air. Beliau bersabda: \"Itu lebih mudah bagi Allah.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ibnu Numair] keduanya berkata: telah menceritakan kepada kami [Waki']. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Jarir]. Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan]. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun]. Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepadaku [Abu Usamah], semuanya dari [Isma'il] dengan sanad ini seperti hadits Ibrahim bin Humaid dan ia menambahkan dalam hadits Yazid: Beliau bersabda padaku: \"Wahai anakku!\""},"4839":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ قَالَ سَمِعْتُ يَعْقُوبَ بْنَ عَاصِمِ بْنِ عُرْوَةَ بْنِ مَسْعُودٍ الثَّقَفِيَّ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو وَجَاءَهُ رَجُلٌ فَقَالَ مَا هَذَا الْحَدِيثُ الَّذِي تُحَدِّثُ بِهِ تَقُولُ إِنَّ السَّاعَةَ تَقُومُ إِلَى كَذَا وَكَذَا فَقَالَ سُبْحَانَ اللَّهِ أَوْ لَا إِلَهَ إِلَّا اللَّهُ أَوْ كَلِمَةً نَحْوَهُمَا لَقَدْ هَمَمْتُ أَنْ لَا أُحَدِّثَ أَحَدًا شَيْئًا أَبَدًا إِنَّمَا قُلْتُ إِنَّكُمْ سَتَرَوْنَ بَعْدَ قَلِيلٍ أَمْرًا عَظِيمًا يُحَرَّقُ الْبَيْتُ وَيَكُونُ وَيَكُونُ ثُمَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ الدَّجَّالُ فِي أُمَّتِي فَيَمْكُثُ أَرْبَعِينَ لَا أَدْرِي أَرْبَعِينَ يَوْمًا أَوْ أَرْبَعِينَ شَهْرًا أَوْ أَرْبَعِينَ عَامًا فَيَبْعَثُ اللَّهُ عِيسَى ابْنَ مَرْيَمَ كَأَنَّهُ عُرْوَةُ بْنُ مَسْعُودٍ فَيَطْلُبُهُ فَيُهْلِكُهُ ثُمَّ يَمْكُثُ النَّاسُ سَبْعَ سِنِينَ لَيْسَ بَيْنَ اثْنَيْنِ عَدَاوَةٌ ثُمَّ يُرْسِلُ اللَّهُ رِيحًا بَارِدَةً مِنْ قِبَلِ الشَّأْمِ فَلَا يَبْقَى عَلَى وَجْهِ الْأَرْضِ أَحَدٌ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ خَيْرٍ أَوْ إِيمَانٍ إِلَّا قَبَضَتْهُ حَتَّى لَوْ أَنَّ أَحَدَكُمْ دَخَلَ فِي كَبَدِ جَبَلٍ لَدَخَلَتْهُ عَلَيْهِ حَتَّى تَقْبِضَهُ قَالَ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَيَبْقَى شِرَارُ النَّاسِ فِي خِفَّةِ الطَّيْرِ وَأَحْلَامِ السِّبَاعِ لَا يَعْرِفُونَ مَعْرُوفًا وَلَا يُنْكِرُونَ مُنْكَرًا فَيَتَمَثَّلُ لَهُمْ الشَّيْطَانُ فَيَقُولُ أَلَا تَسْتَجِيبُونَ فَيَقُولُونَ فَمَا تَأْمُرُنَا فَيَأْمُرُهُمْ بِعِبَادَةِ الْأَوْثَانِ وَهُمْ فِي ذَلِكَ دَارٌّ رِزْقُهُمْ حَسَنٌ عَيْشُهُمْ ثُمَّ يُنْفَخُ فِي الصُّورِ فَلَا يَسْمَعُهُ أَحَدٌ إِلَّا أَصْغَى لِيتًا وَرَفَعَ لِيتًا قَالَ وَأَوَّلُ مَنْ يَسْمَعُهُ رَجُلٌ يَلُوطُ حَوْضَ إِبِلِهِ قَالَ فَيَصْعَقُ وَيَصْعَقُ النَّاسُ ثُمَّ يُرْسِلُ اللَّهُ أَوْ قَالَ يُنْزِلُ اللَّهُ مَطَرًا كَأَنَّهُ الطَّلُّ أَوْ الظِّلُّ نُعْمَانُ الشَّاكُّ فَتَنْبُتُ مِنْهُ أَجْسَادُ النَّاسِ ثُمَّ يُنْفَخُ فِيهِ أُخْرَى فَإِذَا هُمْ قِيَامٌ يَنْظُرُونَ ثُمَّ يُقَالُ يَا أَيُّهَا النَّاسُ هَلُمَّ إِلَى رَبِّكُمْ{ وَقِفُوهُمْ إِنَّهُمْ مَسْئُولُونَ }قَالَ ثُمَّ يُقَالُ أَخْرِجُوا بَعْثَ النَّارِ فَيُقَالُ مِنْ كَمْ فَيُقَالُ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ قَالَ فَذَاكَ يَوْمَ{ يَجْعَلُ الْوِلْدَانَ شِيبًا }وَذَلِكَ{ يَوْمَ يُكْشَفُ عَنْ سَاقٍ }و حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ قَالَ سَمِعْتُ يَعْقُوبَ بْنَ عَاصِمِ بْنِ عُرْوَةَ بْنِ مَسْعُودٍ قَالَ سَمِعْتُ رَجُلًا قَالَ لِعَبْدِ اللَّهِ بْنِ عَمْرٍو إِنَّكَ تَقُولُ إِنَّ السَّاعَةَ تَقُومُ إِلَى كَذَا وَكَذَا فَقَالَ لَقَدْ هَمَمْتُ أَنْ لَا أُحَدِّثَكُمْ بِشَيْءٍ إِنَّمَا قُلْتُ إِنَّكُمْ تَرَوْنَ بَعْدَ قَلِيلٍ أَمْرًا عَظِيمًا فَكَانَ حَرِيقَ الْبَيْتِ قَالَ شُعْبَةُ هَذَا أَوْ نَحْوَهُ قَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ الدَّجَّالُ فِي أُمَّتِي وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ مُعَاذٍ وَقَالَ فِي حَدِيثِهِ فَلَا يَبْقَى أَحَدٌ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ إِيمَانٍ إِلَّا قَبَضَتْهُ قَالَ مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنِي شُعْبَةُ بِهَذَا الْحَدِيثِ مَرَّاتٍ وَعَرَضْتُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Ambari] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] berkata: Aku mendengar [Ya'qub bin Ashim bin Urwah bin Mas'ud Ats Tsaqafi] berkata: Aku mendengar [Abdullah bin Amru], seseorang mendatanginya lalu berkata: Hadits apa ini yang kau ceritakan, kau mengatakan bahwa kiamat terjadi hingga ini dan itu. Ia berkata: Subhaanallaah atau laa ilaaha illallaah atau kalimat serupa. Aku berkeinginan untuk tidak menceritakan apa pun pada siapa pun selamanya, aku hanya berkata bahwa kalian akan melihat hal besar yang membakar rumah sebentar lagi, akan terjadi ini dan itu. Setelah itu ia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal akan muncul ditengah-tengah ummatku lalu ia tinggal selama empatpuluh -aku tidak tahu apakah empatpuluh hari, bulan ataukah tahun- lalu Allah mengutus Isa bin Maryam seperti Urwah bin Mas'ud, ia mencari Dajjal dan membunuhnya. Setelah itu manusia tinggal selama tujuh tahun, tidak permusuhan diantara dua orang pun. Kemudian Allah mengirim angin sejuk dari arah Syam lalu tidak tersisa seorang yang dihatinya ada kebaikan atau keimanan seberat biji sawi pun yang tersisa kecuali mencabut nyawanya, hingga bila pun salah seorang dari kalian masuk ke dalam gunung pasti angin itu memasukinya lalu mencabut nyawanya.\" Ia berkata: Aku mendengarnya dari Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda: \"Yang tersisa hanya orang-orang buruk seperti ringannya burung (cepat melakukan keburukan, pent.) dan keinginan binatang buas (perilaku mereka seperti binatang buas dalam melakukan kelaliman terhadap sesama, pent.) mereka tidak mengenal kebaikan dan tidak memungkiri kemungkaran. Setan menggambarkan untuk mereka lalu berkata: 'Apa kalian tidak merespon? Mereka bertanya: 'Apa yang kau perintahkan pada kami? ' setan menyuruh mereka menyembah patung, mereka melakukannya. Rizki mereka lancar dan kehidupan mereka baik. Kemudian sangkakala ditiup, tidak ada seorang pun yang mendengarnya melainkan memiringkan leher dan mengangkat leher.\" Beliau bersabda: \"Orang pertama yang mendengarnya adalah seseorang yang tengah memperbaiki telaga untuk untanya.\" Beliau bersabda: \"Ia mati dan orang-orang pun mati. Setelah itu Allah mengirim -atau bersabda: Menurunkan- hujan seperti hujan rintik-rintik kemudian tubuh manusia bermunculan, 'Kemudian ditiup sangkakala itu sekali lagi Maka tiba-tiba mereka berdiri menunggu (putusannya masing-masing).\" (Az Zumar: 68) setelah itu beliau bersabda: \"Wahai sekalian manusia, kemarilah menuju Rabb kalian 'Dan tahanlah mereka (di tempat perhentian) Karena Sesungguhnya mereka akan ditanya.\" (Ash Shaaffaat: 24) selanjutnya beliau bersabda: \"Keluarkanlah utusan api.' Dikatakan: Dari berapa? Dijawab: Sembilanratus sembilanpuluh sembilan untuk setiap seribu.\" Beliau bersabda: \" Itulah 'hari yang menjadikan anak-anak beruban.' (Al Muzzammil: 17) dan itulah 'Hari betis disingkapkan'.\" (Al Qalam: 42) Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] berkata: Aku mendengar [Ya'qub bin Ashim bin Urwah bin Mas'ud] berkata: Aku mendengar seseorang berkata kepada Abdullah bin Amru: Kau mengatakan bahwa kiamat terjadi hingga ini dan itu. Ia berkata: Aku berkeinginan untuk tidak menceritakan apa pun pada siapa pun selamanya, aku hanya berkata bahwa kalian akan melihat hal besar yang membakar rumah sebentar lagi. Syu'bah mengatakan ini atau sepertinya. Abdullah bin Amru berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal muncul ditengah-tengah ummatku, \" ia menyebut hadits seperti hadits Mu'adz dan ia menyebutkan dalam haditsnya: \"Tidak tersisa seorang pun yang dihatinya ada keimanan seberat biji sawi melainkan nyawanya dicabut.\" [Muhammad bin Ja'far] berkata: telah menceritakan kepadaku [Syu'bah] hadits ini beberapa kali dan aku memaparkannya padanya."},"4840":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ حَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا لَمْ أَنْسَهُ بَعْدُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ الْآيَاتِ خُرُوجًا طُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا وَخُرُوجُ الدَّابَّةِ عَلَى النَّاسِ ضُحًى وَأَيُّهُمَا مَا كَانَتْ قَبْلَ صَاحِبَتِهَا فَالْأُخْرَى عَلَى إِثْرِهَا قَرِيبًاو حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا أَبُو حَيَّانَ عَنْ أَبِي زُرْعَةَ قَالَ جَلَسَ إِلَى مَرْوَانَ بْنِ الْحَكَمِ بِالْمَدِينَةِ ثَلَاثَةُ نَفَرٍ مِنْ الْمُسْلِمِينَ فَسَمِعُوهُ وَهُوَ يُحَدِّثُ عَنْ الْآيَاتِ أَنَّ أَوَّلَهَا خُرُوجًا الدَّجَّالُ فَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو لَمْ يَقُلْ مَرْوَانُ شَيْئًا قَدْ حَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا لَمْ أَنْسَهُ بَعْدُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَ بِمِثْلِهِ و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ قَالَ تَذَاكَرُوا السَّاعَةَ عِنْدَ مَرْوَانَ فَقَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِهِمَا وَلَمْ يَذْكُرْ ضُحًى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abdullah bin Amru] berkata: Aku menghafal suatu hadits dari Rasulullah Shallallahu 'alaihi wa Salam yang tidak aku lupakan sama sekali. Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya tanda-tanda pertama yang muncul adalah terbitnya matahari dari tempat tenggelamnya, keluarnya binatang-binatang dipagi hari atas manusia, mana saja diantara keduanya yang muncul terlebih dahulu, yang selanjutnya muncul sesaat setelahnya.\" Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Abu Hayyan] dari [Abu Zur'ah] berkata: Tiga orang muslim mendekati Marwan bin Al Hakam di Madinah, mereka mendengarnya menceritakan tentang tanda-tanda (kiamat), dan yang pertama muncul adalah Dajjal. [Abdullah bin Amru] berkata: Marwan tidak mengatakan apa pun. Aku menghafal suatu hadits dari Rasulullah Shallallahu 'alaihi wa Salam yang tidak aku lupakan sama sekali. Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda, ia menyebut hadits serupa. Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Hayyan] dari [Abu Zur'ah] berkata: Mereka menyebut-nyebut kiamat di kediaman Marwan lalu [Abdullah bin Amru] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda, seperti hadits mereka berdua tapi ia tidak menyebut: Di pagi hari."},"4841":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ وَحَجَّاجُ بْنُ الشَّاعِرِ كِلَاهُمَا عَنْ عَبْدِ الصَّمَدِ وَاللَّفْظُ لِعَبْدِ الْوَارِثِ بْنِ عَبْدِ الصَّمَدِ حَدَّثَنَا أَبِي عَنْ جَدِّي عَنْ الْحُسَيْنِ بْنِ ذَكْوَانَ حَدَّثَنَا ابْنُ بُرَيْدَةَ حَدَّثَنِي عَامِرُ بْنُ شَرَاحِيلَ الشَّعْبِيُّ شَعْبُ هَمْدَانَ أَنَّهُ سَأَلَ فَاطِمَةَ بِنْتَ قَيْسٍ أُخْتَ الضَّحَّاكِ بْنِ قَيْسٍ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ فَقَالَحَدِّثِينِي حَدِيثًا سَمِعْتِيهِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسْنِدِيهِ إِلَى أَحَدٍ غَيْرِهِ فَقَالَتْ لَئِنْ شِئْتَ لَأَفْعَلَنَّ فَقَالَ لَهَا أَجَلْ حَدِّثِينِي فَقَالَتْ نَكَحْتُ ابْنَ الْمُغِيرَةِ وَهُوَ مِنْ خِيَارِ شَبَابِ قُرَيْشٍ يَوْمَئِذٍ فَأُصِيبَ فِي أَوَّلِ الْجِهَادِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا تَأَيَّمْتُ خَطَبَنِي عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فِي نَفَرٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَطَبَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَوْلَاهُ أُسَامَةَ بْنِ زَيْدٍ وَكُنْتُ قَدْ حُدِّثْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّنِي فَلْيُحِبَّ أُسَامَةَ فَلَمَّا كَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أَمْرِي بِيَدِكَ فَأَنْكِحْنِي مَنْ شِئْتَ فَقَالَ انْتَقِلِي إِلَى أُمِّ شَرِيكٍ وَأُمُّ شَرِيكٍ امْرَأَةٌ غَنِيَّةٌ مِنْ الْأَنْصَارِ عَظِيمَةُ النَّفَقَةِ فِي سَبِيلِ اللَّهِ يَنْزِلُ عَلَيْهَا الضِّيفَانُ فَقُلْتُ سَأَفْعَلُ فَقَالَ لَا تَفْعَلِي إِنَّ أُمَّ شَرِيكٍ امْرَأَةٌ كَثِيرَةُ الضِّيفَانِ فَإِنِّي أَكْرَهُ أَنْ يَسْقُطَ عَنْكِ خِمَارُكِ أَوْ يَنْكَشِفَ الثَّوْبُ عَنْ سَاقَيْكِ فَيَرَى الْقَوْمُ مِنْكِ بَعْضَ مَا تَكْرَهِينَ وَلَكِنْ انْتَقِلِي إِلَى ابْنِ عَمِّكِ عَبْدِ اللَّهِ بْنِ عَمْرِو ابْنِ أُمِّ مَكْتُومٍ وَهُوَ رَجُلٌ مِنْ بَنِي فِهْرٍ فِهْرِ قُرَيْشٍ وَهُوَ مِنْ الْبَطْنِ الَّذِي هِيَ مِنْهُ فَانْتَقَلْتُ إِلَيْهِ فَلَمَّا انْقَضَتْ عِدَّتِي سَمِعْتُ نِدَاءَ الْمُنَادِي مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَادِي الصَّلَاةَ جَامِعَةً فَخَرَجْتُ إِلَى الْمَسْجِدِ فَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ فِي صَفِّ النِّسَاءِ الَّتِي تَلِي ظُهُورَ الْقَوْمِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ جَلَسَ عَلَى الْمِنْبَرِ وَهُوَ يَضْحَكُ فَقَالَ لِيَلْزَمْ كُلُّ إِنْسَانٍ مُصَلَّاهُ ثُمَّ قَالَ أَتَدْرُونَ لِمَ جَمَعْتُكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ إِنِّي وَاللَّهِ مَا جَمَعْتُكُمْ لِرَغْبَةٍ وَلَا لِرَهْبَةٍ وَلَكِنْ جَمَعْتُكُمْ لِأَنَّ تَمِيمًا الدَّارِيَّ كَانَ رَجُلًا نَصْرَانِيًّا فَجَاءَ فَبَايَعَ وَأَسْلَمَ وَحَدَّثَنِي حَدِيثًا وَافَقَ الَّذِي كُنْتُ أُحَدِّثُكُمْ عَنْ مَسِيحِ الدَّجَّالِ حَدَّثَنِي أَنَّهُ رَكِبَ فِي سَفِينَةٍ بَحْرِيَّةٍ مَعَ ثَلَاثِينَ رَجُلًا مِنْ لَخْمٍ وَجُذَامَ فَلَعِبَ بِهِمْ الْمَوْجُ شَهْرًا فِي الْبَحْرِ ثُمَّ أَرْفَئُوا إِلَى جَزِيرَةٍ فِي الْبَحْرِ حَتَّى مَغْرِبِ الشَّمْسِ فَجَلَسُوا فِي أَقْرُبْ السَّفِينَةِ فَدَخَلُوا الْجَزِيرَةَ فَلَقِيَتْهُمْ دَابَّةٌ أَهْلَبُ كَثِيرُ الشَّعَرِ لَا يَدْرُونَ مَا قُبُلُهُ مِنْ دُبُرِهِ مِنْ كَثْرَةِ الشَّعَرِ فَقَالُوا وَيْلَكِ مَا أَنْتِ فَقَالَتْ أَنَا الْجَسَّاسَةُ قَالُوا وَمَا الْجَسَّاسَةُ قَالَتْ أَيُّهَا الْقَوْمُ انْطَلِقُوا إِلَى هَذَا الرَّجُلِ فِي الدَّيْرِ فَإِنَّهُ إِلَى خَبَرِكُمْ بِالْأَشْوَاقِ قَالَ لَمَّا سَمَّتْ لَنَا رَجُلًا فَرِقْنَا مِنْهَا أَنْ تَكُونَ شَيْطَانَةً قَالَ فَانْطَلَقْنَا سِرَاعًا حَتَّى دَخَلْنَا الدَّيْرَ فَإِذَا فِيهِ أَعْظَمُ إِنْسَانٍ رَأَيْنَاهُ قَطُّ خَلْقًا وَأَشَدُّهُ وِثَاقًا مَجْمُوعَةٌ يَدَاهُ إِلَى عُنُقِهِ مَا بَيْنَ رُكْبَتَيْهِ إِلَى كَعْبَيْهِ بِالْحَدِيدِ قُلْنَا وَيْلَكَ مَا أَنْتَ قَالَ قَدْ قَدَرْتُمْ عَلَى خَبَرِي فَأَخْبِرُونِي مَا أَنْتُمْ قَالُوا نَحْنُ أُنَاسٌ مِنْ الْعَرَبِ رَكِبْنَا فِي سَفِينَةٍ بَحْرِيَّةٍ فَصَادَفْنَا الْبَحْرَ حِينَ اغْتَلَمَ فَلَعِبَ بِنَا الْمَوْجُ شَهْرًا ثُمَّ أَرْفَأْنَا إِلَى جَزِيرَتِكَ هَذِهِ فَجَلَسْنَا فِي أَقْرُبِهَا فَدَخَلْنَا الْجَزِيرَةَ فَلَقِيَتْنَا دَابَّةٌ أَهْلَبُ كَثِيرُ الشَّعَرِ لَا يُدْرَى مَا قُبُلُهُ مِنْ دُبُرِهِ مِنْ كَثْرَةِ الشَّعَرِ فَقُلْنَا وَيْلَكِ مَا أَنْتِ فَقَالَتْ أَنَا الْجَسَّاسَةُ قُلْنَا وَمَا الْجَسَّاسَةُ قَالَتْ اعْمِدُوا إِلَى هَذَا الرَّجُلِ فِي الدَّيْرِ فَإِنَّهُ إِلَى خَبَرِكُمْ بِالْأَشْوَاقِ فَأَقْبَلْنَا إِلَيْكَ سِرَاعًا وَفَزِعْنَا مِنْهَا وَلَمْ نَأْمَنْ أَنْ تَكُونَ شَيْطَانَةً فَقَالَ أَخْبِرُونِي عَنْ نَخْلِ بَيْسَانَ قُلْنَا عَنْ أَيِّ شَأْنِهَا تَسْتَخْبِرُ قَالَ أَسْأَلُكُمْ عَنْ نَخْلِهَا هَلْ يُثْمِرُ قُلْنَا لَهُ نَعَمْ قَالَ أَمَا إِنَّهُ يُوشِكُ أَنْ لَا تُثْمِرَ قَالَ أَخْبِرُونِي عَنْ بُحَيْرَةِ الطَّبَرِيَّةِ قُلْنَا عَنْ أَيِّ شَأْنِهَا تَسْتَخْبِرُ قَالَ هَلْ فِيهَا مَاءٌ قَالُوا هِيَ كَثِيرَةُ الْمَاءِ قَالَ أَمَا إِنَّ مَاءَهَا يُوشِكُ أَنْ يَذْهَبَ قَالَ أَخْبِرُونِي عَنْ عَيْنِ زُغَرَ قَالُوا عَنْ أَيِّ شَأْنِهَا تَسْتَخْبِرُ قَالَ هَلْ فِي الْعَيْنِ مَاءٌ وَهَلْ يَزْرَعُ أَهْلُهَا بِمَاءِ الْعَيْنِ قُلْنَا لَهُ نَعَمْ هِيَ كَثِيرَةُ الْمَاءِ وَأَهْلُهَا يَزْرَعُونَ مِنْ مَائِهَا قَالَ أَخْبِرُونِي عَنْ نَبِيِّ الْأُمِّيِّينَ مَا فَعَلَ قَالُوا قَدْ خَرَجَ مِنْ مَكَّةَ وَنَزَلَ يَثْرِبَ قَالَ أَقَاتَلَهُ الْعَرَبُ قُلْنَا نَعَمْ قَالَ كَيْفَ صَنَعَ بِهِمْ فَأَخْبَرْنَاهُ أَنَّهُ قَدْ ظَهَرَ عَلَى مَنْ يَلِيهِ مِنْ الْعَرَبِ وَأَطَاعُوهُ قَالَ لَهُمْ قَدْ كَانَ ذَلِكَ قُلْنَا نَعَمْ قَالَ أَمَا إِنَّ ذَاكَ خَيْرٌ لَهُمْ أَنْ يُطِيعُوهُ وَإِنِّي مُخْبِرُكُمْ عَنِّي إِنِّي أَنَا الْمَسِيحُ وَإِنِّي أُوشِكُ أَنْ يُؤْذَنَ لِي فِي الْخُرُوجِ فَأَخْرُجَ فَأَسِيرَ فِي الْأَرْضِ فَلَا أَدَعَ قَرْيَةً إِلَّا هَبَطْتُهَا فِي أَرْبَعِينَ لَيْلَةً غَيْرَ مَكَّةَ وَطَيْبَةَ فَهُمَا مُحَرَّمَتَانِ عَلَيَّ كِلْتَاهُمَا كُلَّمَا أَرَدْتُ أَنْ أَدْخُلَ وَاحِدَةً أَوْ وَاحِدًا مِنْهُمَا اسْتَقْبَلَنِي مَلَكٌ بِيَدِهِ السَّيْفُ صَلْتًا يَصُدُّنِي عَنْهَا وَإِنَّ عَلَى كُلِّ نَقْبٍ مِنْهَا مَلَائِكَةً يَحْرُسُونَهَا قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّ��ُ عَلَيْهِ وَسَلَّمَ وَطَعَنَ بِمِخْصَرَتِهِ فِي الْمِنْبَرِ هَذِهِ طَيْبَةُ هَذِهِ طَيْبَةُ هَذِهِ طَيْبَةُ يَعْنِي الْمَدِينَةَ أَلَا هَلْ كُنْتُ حَدَّثْتُكُمْ ذَلِكَ فَقَالَ النَّاسُ نَعَمْ فَإِنَّهُ أَعْجَبَنِي حَدِيثُ تَمِيمٍ أَنَّهُ وَافَقَ الَّذِي كُنْتُ أُحَدِّثُكُمْ عَنْهُ وَعَنْ الْمَدِينَةِ وَمَكَّةَ أَلَا إِنَّهُ فِي بَحْرِ الشَّأْمِ أَوْ بَحْرِ الْيَمَنِ لَا بَلْ مِنْ قِبَلِ الْمَشْرِقِ مَا هُوَ مِنْ قِبَلِ الْمَشْرِقِ مَا هُوَ مِنْ قِبَلِ الْمَشْرِقِ مَا هُوَ وَأَوْمَأَ بِيَدِهِ إِلَى الْمَشْرِقِ قَالَتْ فَحَفِظْتُ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ الْهُجَيْمِيُّ أَبُو عُثْمَانَ حَدَّثَنَا قُرَّةُ حَدَّثَنَا سَيَّارٌ أَبُو الْحَكَمِ حَدَّثَنَا الشَّعْبِيُّ قَالَ دَخَلْنَا عَلَى فَاطِمَةَ بِنْتِ قَيْسٍ فَأَتْحَفَتْنَا بِرُطَبٍ يُقَالُ لَهُ رُطَبُ ابْنِ طَابٍ وَأَسْقَتْنَا سَوِيقَ سُلْتٍ فَسَأَلْتُهَا عَنْ الْمُطَلَّقَةِ ثَلَاثًا أَيْنَ تَعْتَدُّ قَالَتْ طَلَّقَنِي بَعْلِي ثَلَاثًا فَأَذِنَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَعْتَدَّ فِي أَهْلِي قَالَتْ فَنُودِيَ فِي النَّاسِ إِنَّ الصَّلَاةَ جَامِعَةً قَالَتْ فَانْطَلَقْتُ فِيمَنْ انْطَلَقَ مِنْ النَّاسِ قَالَتْ فَكُنْتُ فِي الصَّفِّ الْمُقَدَّمِ مِنْ النِّسَاءِ وَهُوَ يَلِي الْمُؤَخَّرَ مِنْ الرِّجَالِ قَالَتْ فَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَخْطُبُ فَقَالَ إِنَّ بَنِي عَمٍّ لِتَمِيمٍ الدَّارِيِّ رَكِبُوا فِي الْبَحْرِ وَسَاقَ الْحَدِيثَ وَزَادَ فِيهِ قَالَتْ فَكَأَنَّمَا أَنْظُرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْوَى بِمِخْصَرَتِهِ إِلَى الْأَرْضِ وَقَالَ هَذِهِ طَيْبَةُ يَعْنِي الْمَدِينَةَ و حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَأَحْمَدُ بْنُ عُثْمَانَ النَّوْفَلِيُّ قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ غَيْلَانَ بْنَ جَرِيرٍ يُحَدِّثُ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ قَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمِيمٌ الدَّارِيُّ فَأَخْبَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ رَكِبَ الْبَحْرَ فَتَاهَتْ بِهِ سَفِينَتُهُ فَسَقَطَ إِلَى جَزِيرَةٍ فَخَرَجَ إِلَيْهَا يَلْتَمِسُ الْمَاءَ فَلَقِيَ إِنْسَانًا يَجُرُّ شَعَرَهُ وَاقْتَصَّ الْحَدِيثَ وَقَالَ فِيهِ ثُمَّ قَالَ أَمَا إِنَّهُ لَوْ قَدْ أُذِنَ لِي فِي الْخُرُوجِ قَدْ وَطِئْتُ الْبِلَادَ كُلَّهَا غَيْرَ طَيْبَةَ فَأَخْرَجَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى النَّاسِ فَحَدَّثَهُمْ قَالَ هَذِهِ طَيْبَةُ وَذَاكَ الدَّجَّالُ حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَعَدَ عَلَى الْمِنْبَرِ فَقَالَ أَيُّهَا النَّاسُ حَدَّثَنِي تَمِيمٌ الدَّارِيُّ أَنَّ أُنَاسًا مِ","id":"Telah menceritakan kepada kami [Abdulwarits bin Abdushshamad bin Abdulwaris] dan [Hajjaj bin Asy Sya'ir], keduanya dari [Abdushshamad], teks milik Abdulwarits bin Abdushshamad telah menceritakan kepada kami [ayahku] dari [kakekku] dari [Al Husain bin Dzakwan] telah menceritakan kepada kami [Ibnu Buraidah] telah menceritakan kepadaku [Amir bin Syarahil Asy Sya'bi] ia bertanya kepada [Fathimah binti Qais] saudari Adh Dhahhak bin Qais, ia salah satu wanita yang turut serta dalam hijrah pertama, ia berkata: Ceritakanlah suatu hadits padaku yang kau dengar Rasulullah Shallallahu 'alaihi wa Salam, jangan kau sandarkan pada siapa pun selain beliau. Fathimah berkata: Bila kau mau, aku akan menceritakannya. Ia berkata: Ya, ceritakanlah. Fathimah berkata: Aku menikah dengan Ibnu Al Mughirah, ia salah satu pemuda Quraisy terbaik saat itu. Ia meninggal dalam jihad pertama bersama Rasulullah Shallallahu 'alaihi wa Salam. Saat aku menjanda, Abdurrahman bin Auf melamarku bersama beberapa sahabat Rasulullah Shallallahu 'alaihi wa Salam lalu Rasulullah Shallallahu 'alaihi wa Salam melamarku untuk budak beliau yang telah dimedekakan, Usamah bin Zaid. Aku diberi tahu bahwa Rasulullah Shallallahu 'alaihi wa Salam pernah bersabda: \"Barangsiapa mencintaiku, hendaklah mencintai Usamah.\" Saat Rasulullah Shallallahu 'alaihi wa Salam berbicara padaku, aku menjawab: Terserah Tuan, nikahkan aku dengan siapa pun yang Tuan mau. Beliau bersabda: \"Pindahlah ke Ummu Syuraik.\" Ummu Syuraik adalah wanita kaya dari Anshar, sering memberi dana di jalan Allah dan sering disinggahi tamu. Aku menjawab: Baik. Beliau bersabda: \"Jangan, Ummu Syuraik adalah wanita yang banyak tamunya, aku tidak mau kerudungmu jatuh atau penutup betismu tersingkap lalu orang-orang melihat sebagaian yang tidak kau suka. Tapi pindahlah ke putra pamanmu, Abdullah bin Amru bin Ummu Kultsum.\" Ia adalah seseorang dari bani Fihr, Firh adalah Quraisy dimana Rasulullah Shallallahu 'alaihi wa Salam berasal. Aku pindah ke kediamannya. Saat masa iddahku selesai, aku mendengar penyeru Rasulullah Shallallahu 'alaihi wa Salam menyerukan shalat jamaah. Aku keluar ke masjid lalu shalat bersama Rasulullah Shallallahu 'alaihi wa Salam. Aku berada dishaf kaum wanita yang berada dibelakang kaum. Setelah Rasulullah Shallallahu 'alaihi wa Salam menyelesaikan shalat, beliau duduk di atas mimbar dan beliau tertawa, beliau bersabda: \"Hendaklah setiap orang tetap berada ditempatnya.\" Setelah itu beliau bertanya: \"Tahukah kalian, kenapa aku mengumpulkan kalian?\" mereka menjawab: Allah dan rasulNya lebih tahu. Beliau bersabda: \"Demi Allah, sesungguhnya aku tidak mengumpulkanmu karena harapan atau rasa takut, tapi aku mengumpulkan kalian karena Tamim Ad Dari dulunya orang nasrani lalu ia datang, berbaiat lalu masuk Islam.\" Ia menceritakan suatu hadits padaku, sama seperti hadits yang aku ceritakan kepada kalian tentang Masih Dajjal. Ia menceritakan kepadaku bahwa Dajjal naik perahu bersama tigapuluh orang dari Lakham dan Judzam. Gelombang mempermainkan mereka dilaut selama sebulan lalu mereka menepi ke suatu pulau dilautan hingga matahari tenggelam. Mereka duduk didekat perahu lalu masuk ke pulau. Seekor binatang menemui mereka, banyak bulunya, mereka tahu mana kemaluannya dan mana duburnya karena banyak bulunya. Mereka bertanya: Celakalah kau, apa kau ini? ia menjawab: Aku adalah jassaasah. Mereka bertanya: Apa itu jassaasah? Ia berkata: Wahai kaum, pergilah ke orang itu di ujung kampung, dia merindukan khabar kalian. Adh Dhahhak berkata: Saat ia menyebut nama seseorang pada kami, kami takut jangan-jangan ia setan. Kami segera pergi hingga memasuki perkampungan, ternyata disana ada orang terbesar yang pernah kami lihat, paling kuat dan tangannya terbelenggu dileher, antara lutut dan mata kakinya terbelenggu besi. Kami berkata: Celakalah kamu, apa kau ini? ia menjawab: Kalian telah mengetahuiku, maka beritahukan siapa kalian? Mereka menjawab: Kami dari arab, kami naik perahu. Saat gelombang menghebat, kami dipermainkan selama sebulan kemudian kami menepi ke pulaumu ini. kami duduk didekat perahu lalu kami masuk ke pulau. Seekor hewan menemui kami, bulunya lebat, tidak jelas mana kemaluannya dan mana duburnya karena banyaknya bulu. Kami bertanya: Celakalah kau, apa kau ini? ia menjawab: Aku adalah jassaasah. Kami bertanya: Apa itu jassaasah? Ia berkata: Wahai kaum, pergilah ke orang itu di ujung kampung, dia merindukan khabar kalian. Lalu kami segera menujumu dan kami takut padanya, kami tidak aman jangan-jangan ia setan. Ia berkata: Beritahukan padaku tentang kurma Baisan. Kami bertanya: Tentang apanya yang kau tanyakan? Ia berkata: Aku bertanya pada kalian tentang kurmanya, apakah sudah berbuah? Kami menjawab: Ya. Ia berkata: Ingat, ia hampir tidak membuahkan lagi. Ia berkata: Beritahukan padaku tentang danau Thabari. Kami bertanya: Tentang apanya yang kau tanyakan? Ia menjawab: Apakah ada airnya? Mereka menjawab: Airnya banyak. Ia berkata: Ingat, airnya hampir akan habis. Ia berkata: Beritahukan padaku tentang mata air Zughar. Mereka bertanya: Tentang apanya yang kau tanyakan? Ia berkata: Apakah disana ada airnya dan apakah penduduknya bercocok tanam dengan air itu? Kami menjawab: Ya, airnya banyak dan penduduknya bercocok tanam dengan air itu. Ia berkata: Beritahukan padaku tentang nabi orang-orang buta huruf, bagaimana keadaannya? Mereka menjawab: Ia telah muncul dari Makkah dan tinggal di Yatsrib. Ia bertanya: Apakah orang-orang arab memeranginya? Kami menjawab: Ya. Ia bertanya: Apa yang mereka lakukan terhadapnya? Lalu kami memberitahunya bahwa beliau menang atas bangsa arab di sebelahnya dan mereka menaatinya. Ia bertanya pada mereka: Itu sudah terjadi? Kami menjawab: Ya. Ia berkata: Ingat, sesungguhnya itu baik bagi mereka untuk menaatinya. Aku akan beritahukan pada kalian siapa aku. Aku adalah Al Masih dan aku sudah hampir diizinkan untuk keluar lalu aku akan keluar. Aku melintasi bumi, aku tidak membiarkan satu perkampungan pun kecuali aku singgahi selama empatpuluh hari kecuali Makkah dan Thaibah (Madinah), keduanya diharamkan bagiku. Setiap kali aku hendak memasuki salah satunya, malaikat membawa pedang kuat menghadangku menghalangiku dari tempat itu dan disetiap jalannya terdapat malaikat-malaikat penjaga.\" Fathimah berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda seraya memukulkan tongkat pendek beliau ke mimbar: \"Inilah Thaibah, inilah Thaibah, inilah Thaibah -maksud beliau Madinah. Ingat, apakah aku sudah menceritakannya pada kalian?\" mereka menjawab: Ya.\" Hadits Tamim membuatku heran, ceritanya sama seperti yang aku ceritakan pada kalian tentang Dajjal, Madinah dan Makkah. Ingat, sesungguhnya Dajjal ada dilautan Syam atau Yaman. Tidak, tapi dari arah timur. Ia tidak berada di arah timur, ia tidak berada di arah timur. Ia menunjukkan tangannya ke timur. Fathimah berkata: Aku menghafal ini dari Rasulullah Shallallahu 'alaihi wa Salam. Telah menceritakan kepada kami [Yahya bin Hubaib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits Al Hujaimi Abu Utsman] telah menceritakan kepada kami [Qurrah] telah menceritakan kepada kami [Sayyar Abu Al Hakam] telah menceritakan kepada kami [Asy Sya'bi] berkata: Kami memasuki kediaman [Fahtimah binti Qais]. Ia menyuguhkan kurma basah bernama kurma basah Ibnu Thab dan memberi kami minum tepung halus, lalu kami bertanya padanya tentang wanita yang ditalak tiga, dimanakah ia menunggu masa 'iddahnya? Ia menjawab: Suamiku menceraikanku talak tiga lalu nabi Shallallahu 'alaihi wa Salam mengizinkanku untuk menunggu masa 'iddahku bersama keluargaku. Ia berkata: Kemudian shalat jamaah diserukan. Aku pergi bersama orang-orang. Aku berada dishaf wanita terdepan, tepat berada dibelakang shaf terakhir kaum lelaki. Aku mendengar nabi Shallallahu 'alaihi wa Salam berkhutbah di atas mimbar, beliau bersabda: \"Sesungguhnya keturunan pamannya Tamim Ad Dari naik perahu, \" ia menyebut hadits dan ia menambahkan: Fathimah berkata: Sepertinya aku melihat nabi Shallallahu 'alaihi wa Salam menurunkan tongkat pendek beliau ke tanah, beliau bersabda: \"Inilah Thaibah\" maksud beliau Madinah. Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] dan [Ahmad bin Utsman An Naufali] keduanya berkata: Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [ayahku] berkata: Aku mendengar [Ghailan bin Jarir] menceritakan dari [Asy Sya'bi] dari [Fathimah binti Qais] berkata: Tamim Ad Dari mendatangi Rasulullah Shallallahu 'alaihi wa Salam lalu memberitahukan kepada beliau bahwa ia naik perahu lalu perahunya menggombang-ambingkannya hingga ia terdampar disuatu pulau. Ia masuk ke pulau untuk mencari air, ia bertemu seseorang yang menjulurkan rambutnya, ia menceritakan hadits ini. Ia menuturkan: Dajjal berkata: Ingat, bila aku diizinkan keluar, aku akan melalui seluruh negeri selain Thaibah. Rasulullah Shallallahu 'alaihi wa Salam membawa Tamim keluar ke hadapan orang-orang lalu menyampaikan pada mereka, beliau bersabda: \"Ini adalah Thaibah dan itu adalah Dajjal.\" Telah menceritakan kepadaku [Abu Bakr bin Ishaq] telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Mughirah Al Hizami] dari [Abu Az Zinad] dari [Asy Sya'bi] dari [Fathimah binti Qais], Rasulullah Shallallahu 'alaihi wa Salam duduk di atas mimbar lalu bersabda: \"Wahai sekalian manusia, Tamim Ad Dari telah menceritakan kepadaku bahwa beberapa orang dari kaumnya berada di perahu milik mereka. Perahunya pecah lalu sebagaian dari mereka naik di atas salah satu lembaran kayu perahunya, mereka pergi menuju salah satu pulau dilautan.\" Lalu beliau menyebutkan hadits ini."},"4842":{"ar":"حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنِي أَبُو عَمْرٍو يَعْنِي الْأَوْزَاعِيَّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ بَلَدٍ إِلَّا سَيَطَؤُهُ الدَّجَّالُ إِلَّا مَكَّةَ وَالْمَدِينَةَ وَلَيْسَ نَقْبٌ مِنْ أَنْقَابِهَا إِلَّا عَلَيْهِ الْمَلَائِكَةُ صَافِّينَ تَحْرُسُهَا فَيَنْزِلُ بِالسِّبْخَةِ فَتَرْجُفُ الْمَدِينَةُ ثَلَاثَ رَجَفَاتٍ يَخْرُجُ إِلَيْهِ مِنْهَا كُلُّ كَافِرٍ وَمُنَافِقٍو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَة�� عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَكَرَ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ فَيَأْتِي سِبْخَةَ الْجُرُفِ فَيَضْرِبُ رِوَاقَهُ وَقَالَ فَيَخْرُجُ إِلَيْهِ كُلُّ مُنَافِقٍ وَمُنَافِقَةٍ","id":"Telah menceritakan kepadaku [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Al Walid bin1 Muslim] telah menceritakan kepadaku [Abu Amru Al Auza'i] dari [Ishaq bin Abdullah bin Abu Thalhah] telah menceritakan kepadaku [Anas bin Malik] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada satu negeri pun melainkan akan dilewati Dajjal kecuali Makkah dan Madinah. Tidak ada satu jalannya pun kecuali ada malaikat-malaikat berbaris menjaganya yang datang membawa tanah lalu Madinah bergoncang tiga kali. Setiap orang kafir dan munafik keluar meninggalkannya (Madinah) untuk menghampirinya (Dajjal).\" Telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] dari [Hammad bin Salamah] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] Rasulullah Shallallahu 'alaihi wa Salam bersabda, ia menyebut hadits serupa, hanya saja ia mengatakan dalam haditsnya: \"Lalu ia mendatangi tanah tepi kemudian menempati bagian depannya.\" Dan berkata: \"Lalu setiap orang munafik lelaki dan perempuan keluar menghampirinya.\""},"4843":{"ar":"حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ عَمِّهِ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتْبَعُ الدَّجَّالَ مِنْ يَهُودِ أَصْبَهَانَ سَبْعُونَ أَلْفًا عَلَيْهِمْ الطَّيَالِسَةُ","id":"Telah menceritakan kepada kami [Manhsur bin Abu Muzahim] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Al Auza'i] dari [Ishaq bin Abdullah] dari [pamannya, Anas bin Malik] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dajjal diikuti Yahudi Ashbahan sebanyak tujuhpuluh ribu, mereka mengenakan jubah hijau.\""},"4844":{"ar":"حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَتْنِي أُمُّ شَرِيكٍأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَفِرَّنَّ النَّاسُ مِنْ الدَّجَّالِ فِي الْجِبَالِ قَالَتْ أُمُّ شَرِيكٍ يَا رَسُولَ اللَّهِ فَأَيْنَ الْعَرَبُ يَوْمَئِذٍ قَالَ هُمْ قَلِيلٌو حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepadaku [Harun bin Abdullah] telah menceritakan kepada kami [Hajjaj bin Muhammad] berkata: Berkata [Ibnu Juraij]: telah menceritakan kepadaku [Abu Az Zubair] ia mendengar [Jabir bin Abdullah] berkata: telah mengkhabarkan kepadaku [Ummu Syarik] bahwa ia mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Manusia akan lari dari Dajjal ke gunung.\" Ummu Syarik bertanya: Wahai Rasulullah, lalu dimana bangsa arab saat itu? Beliau menjawab: \"Mereka sedikit.\" Telah menceritakannya kepada kami [Muhammad bin Basyar] dan [Abdu bin Humaid], keduanya berkata: Telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dengan sanad ini."},"4845":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ الْمُخْتَارِ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ رَهْطٍ مِنْهُمْ أَبُو الدَّهْمَاءِ وَأَبُو قَتَادَةَ قَالُواكُنَّا نَمُرُّ عَلَى هِشَامِ بْنِ عَامِرٍ نَأْتِي عِمْرَانَ بْنَ حُصَيْنٍ فَقَالَ ذَاتَ يَوْمٍ إِنَّكُمْ لَتُجَاوِزُونِي إِلَى رِجَالٍ مَا كَانُوا بِأَحْضَرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنِّي وَلَا أَعْلَمَ بِحَدِيثِهِ مِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا بَيْنَ خَلْقِ آدَمَ إِلَى قِيَامِ السَّاعَةِ خَلْقٌ أَكْبَرُ مِنْ الدَّجَّالِو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ ثَلَاثَةِ رَهْطٍ مِنْ قَوْمِهِ فِيهِمْ أَبُو قَتَادَةَ قَالُوا كُنَّا نَمُرُّ عَلَى هِشَامِ بْنِ عَامِرٍ إِلَى عِمْرَانَ بْنِ حُصَيْنٍ بِمِثْلِ حَدِيثِ عَبْدِ الْعَزِيزِ بْنِ مُخْتَارٍ غَيْرَ أَنَّهُ قَالَ أَمْرٌ أَكْبَرُ مِنْ الدَّجَّالِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ahmad bin Ishaq Al Hadhrami] telah menceritakan kepada kami [Abdulaziz bin Al Mukhtar] telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari beberapa orang diantaranya [Abu Ad Dahma`] dan [Abu Qatadah], mereka berkata: Kami melintasi [Hisyam bin Amir] untuk menemui Imran bin Hushain. Pada suatu hari ia berkata: Sesungguhnya kalian melinasiku untuk menemui beberapa orang, mereka tidak lebih sering mendatangi Rasulullah Shallallahu 'alaihi wa Salam melebihiku dan mereka tidak lebih mengetahui hadits beliau melebihiku. Aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada wujud manusia sejak Adam diciptakan hingga terjadinya kiamat yang lebih besar dari Dajjal.\" Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] telah menceritakan kepada kami [Ubaidullah bin Amru] dari [Ayyub] dari [Humaid bin Hilal] dari [tiga orang] dari kaumnya, diantaranya [Abu Qatadah], mereka berkata: Kami melintasi [Hisyam bin Amir] untuk menemui Imran bin Hushain, seperti hadits Abdulaziz bin Mukhtar, hanya saja ia berkata dalam haditsnya: Perkara yang lebih besar dari Dajjal."},"4846":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَعِيلُ يَعْنُونَ ابْنَ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا بِالْأَعْمَالِ سِتًّا طُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا أَوْ الدُّخَانَ أَوْ الدَّجَّالَ أَوْ الدَّابَّةَ أَوْ خَاصَّةَ أَحَدِكُمْ أَوْ أَمْرَ الْعَامَّةِ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub], [Qutaibah bin Sa'id] dan [Ibnu Hujr] mereka berkata: Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Al Ala`] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Segeralah beramal sebelum (munculnya) enam (hal): terbitnya matahari dari barat, kabut, Dajjal, binatang, kekhususan salah seorang dari kalian (kematian) atau urusan umum (kiamat).\""},"4847":{"ar":"حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ زِيَادِ بْنِ رِيَاحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا بِالْأَعْمَالِ سِتًّا الدَّجَّالَ وَالدُّخَانَ وَدَابَّةَ الْأَرْضِ وَطُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا وَأَمْرَ الْعَامَّةِ وَخُوَيْصَّةَ أَحَدِكُمْو حَدَّثَنَاه زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Umaiyah bin Bistham Al Aisyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Ziyad bin Riyah] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Segeralah beramal sebelum (munculnya) enam (hal): terbitnya matahari dari barat, kabut, Dajjal, binatang, urusan umum (kiamat) dan kekhususan salah seorang dari kalian (kematian).\" Telah menceritakannya kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] keduanya berkata: Telah menceritakan kepada kami [Abdushshamad bin Abdulwarits] telah menceritakan kepada kami [Hammam] dari [Qatadah] dengan sanad ini dengan matan serupa."},"4848":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مُعَلَّى بْنِ زِيَادٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ مَعْقِلِ بْنِ يَسَارٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ الْمُعَلَّى بْنِ زِيَادٍ رَدَّهُ إِلَى مُعَاوِيَةَ بْنِ قُرَّةَ رَدَّهُ إِلَى مَعْقِلِ بْنِ يَسَارٍرَدَّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعِبَادَةُ فِي الْهَرْجِ كَهِجْرَةٍ إِلَيَّو حَدَّثَنِيهِ أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengkhabarkan kepada kami [Hammad bin Zaid] dari [Mu'alla bin Ziyad] dari [Mu'awiyah bin Qurrah] dari [Ma'qal bin Yasar] bahwa Rasulullah Shallallahu 'alaihi wa Salam. Telah menceritakannya kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad] dari [Al Mu'alla bin Ziyad] ia mengembalikannya ke [Mu'awiyah bin Qurrah] ia mengembalikannya ke [Ma'qal bin Yasar] ia mengembalikannya ke nabi Shallallahu 'alaihi wa Salam bersabda: \"Ibadah saat terjadi pembunuhan seperti hijrah menujuku.\" Telah menceritakannya kepadaku [Abu Kamil] telah menceritakan kepada kami [Hammad] dengan sanad ini dengan matan serupa."},"4849":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ إِلَّا عَلَى شِرَارِ النَّاسِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Syu'bah] dari [Ali bin Al Aqmar] dari [Abu Al Ahwash] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi kecuali atas manusia-manusia buruk.\""},"4850":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ وَعَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ أَنَّهُ سَمِعَ سَهْلًا يَقُولُاسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِإِصْبَعِهِ الَّتِي تَلِي الْإِبْهَامَ وَالْوُسْطَى وَهُوَ يَقُولُ بُعِثْتُ أَنَا وَالسَّاعَةُ هَكَذَا","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dan [Abdulaziz bin Abu Hazim] dari [Abu Hazim] dari [Sahal bin Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda. Telah menceritakan kepada kami [Qutaibah bin Sa'id], teks miliknya, telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] bahwa ia mendengar [Sahal] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam menunjuk dengan jari telunjuk dan jari tengah, beliau bersabda: \"Aku diutus dan kiamat seperti ini.\""},"4851":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِقَالَ شُعْبَةُ وَسَمِعْتُ قَتَادَةَ يَقُولُ فِي قَصَصِهِ كَفَضْلِ إِحْدَاهُمَا عَلَى الْأُخْرَى فَلَا أَدْرِي أَذَكَرَهُ عَنْ أَنَسٍ أَوْ قَالَهُ قَتَادَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] berkata: Aku mendengar [Qatadah] telah menceritakan kepada kami [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku diutus dan kiamat seperti dua (jari) ini.\" Syu'bah berkata: Aku mendengar Qatadah berkata dalam kisahnya: Seperti keutamaan salah satunya atas yang lain. Aku tidak tahu apakah ia menyebutkannya dari Anas ataukah Qatadah yang mengatakannya."},"4852":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ وَأَبَا التَّيَّاحِ يُحَدِّثَانِ أَنَّهُمَا سَمِعَا أَنَسًا يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ أَنَا وَالسَّاعَةُ هَكَذَا وَقَرَنَ شُعْبَةُ بَيْنَ إِصْبَعَيْهِ الْمُسَبِّحَةِ وَالْوُسْطَى يَحْكِيهِو حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا و حَدَّثَنَاه مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ حَمْزَةَ يَعْنِي الضَّبِّيَّ وَأَبِي التَّيَّاحِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِهِمْ","id":"Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] berkata: Aku mendengar [Qatadah] dan [Abu At Tayyah] menceritakan bahwa keduanya mendengar [Anas] menceritakan bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku diutus dan kiamat seperti ini.\" Syu'bah menyandingkan jari telunjuk dan jari tengah saat menceritakannya. Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [ayahku]. Telah menceritakan kepada kami [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata: Telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam dengan matan serupa. Telah menceritakannya kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi Adi] dar [Syu'bah] dari [Hamzah Adh Dhabbi] dan [Abu At Tayyah] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam seperti hadits mereka."},"4853":{"ar":"و حَدَّثَنَا أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ مَعْبَدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ قَالَ وَضَمَّ السَّبَّابَةَ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Abu Ghassan Al Misma'i] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] dari [Ma'bad] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku diutus dan kiamat seperti dua (jari) ini.\" Anas berkata: Beliau melekatkan jari telunjuk dan jari tengah."},"4854":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ الْأَعْرَابُ إِذَا قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلُوهُ عَنْ السَّاعَةِ مَتَى السَّاعَةُ فَنَظَرَ إِلَى أَحْدَثِ إِنْسَانٍ مِنْهُمْ فَقَالَ إِنْ يَعِشْ هَذَا لَمْ يُدْرِكْهُ الْهَرَمُ قَامَتْ عَلَيْكُمْ سَاعَتُكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata: Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya] dari [Aisyah] berkata: Orang-orang badui apabila mendatangi Rasulullah Shallallahu 'alaihi wa Salam, mereka bertanya mengenai hari kiamat: Kapan akan terjadi? Beliau melihat kepada orang paling muda di antara mereka dan bersabda: \"Apabila orang ini masih hidup dan ia belum tua, berarti kiamat kalian telah terjadi.\""},"4855":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَتَى تَقُومُ السَّاعَةُ وَعِنْدَهُ غُلَامٌ مِنْ الْأَنْصَارِ يُقَالُ لَهُ مُحَمَّدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَعِشْ هَذَا الْغُلَامُ فَعَسَى أَنْ لَا يُدْرِكَهُ الْهَرَمُ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] dari [Hammad bin Salamah] dari [Tsabit] dari [Anas] seseorang bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam kapan terjadinya kiamat dan didekatnya ada anak kecil dari Anshar bernama Muhammad, beliau menjawab: \"Bila anak ini masih hidup, mungkin ia tidak sampai tua hingga kiamat terjadi.\""},"4856":{"ar":"و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا مَعْبَدُ بْنُ هِلَالٍ الْعَنَزِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَتَى تَقُومُ السَّاعَةُ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُنَيْهَةً ثُمَّ نَظَرَ إِلَى غُلَامٍ بَيْنَ يَدَيْهِ مِنْ أَزْدِ شَنُوءَةَ فَقَالَ إِنْ عُمِّرَ هَذَا لَمْ يُدْرِكْهُ الْهَرَمُ حَتَّى تَقُومَ السَّاعَةُقَالَ قَالَ أَنَسٌ ذَاكَ الْغُلَامُ مِنْ أَتْرَابِي يَوْمَئِذٍ","id":"Telah menceritakan kepadaku [Hajjaj bin Asy Sya'ir] telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ma'bad bin Hilal Al Anazi] dari [Anas bin Malik], seseorang bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam kapan terjadinya kiamat. Beliau terdiam sejenak lalu melihat anak kecil dari Azd Syanu`ah yang ada didepan beliau, beliau menjawab: \"Bila anak ini masih hidup, ia tidak sampai tua hingga kiamat terjadi.\" Anas berkata: Anak itu sebayaku saat itu."},"4857":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَمَرَّ غُلَامٌ لِلْمُغِيرَةِ بْنِ شُعْبَةَ وَكَانَ مِنْ أَقْرَانِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يُؤَخَّرْ هَذَا فَلَنْ يُدْرِكَهُ الْهَرَمُ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Affan bin Muslim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] berkata: Anak Mughirah bin Syu'bah, sebayaku, melintasi lalu nabi Shallallahu 'alaihi wa Salam bersabda: \"Bila anak ini panjang umur, ia tidak sampai tua hingga kiamat terjadi.\""},"4858":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَقُومُ السَّاعَةُ وَالرَّجُلُ يَحْلُبُ اللِّقْحَةَ فَمَا يَصِلُ الْإِنَاءُ إِلَى فِيهِ حَتَّى تَقُومَ وَالرَّجُلَانِ يَتَبَايَعَانِ الثَّوْبَ فَمَا يَتَبَايَعَانِهِ حَتَّى تَقُومَ وَالرَّجُلُ يَلِطُ فِي حَوْضِهِ فَمَا يَصْدُرُ حَتَّى تَقُومَ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] sampai pada nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Kiamat terjadi sementara orang tengah memeras unta perahan, belum juga wadahnya sampai ke mulutnya hingga kiamat terjadi, dua orang saling berjual beli baju, belum juga keduanya berjual beli hingga kiamat terjadi dan seseorang memperbaiki telaganya, belum juga ia kembali hingga kiamat terjadi.\""},"4859":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ النَّفْخَتَيْنِ أَرْبَعُونَ قَالُوا يَا أَبَا هُرَيْرَةَ أَرْبَعُونَ يَوْمًا قَالَ أَبَيْتُ قَالُوا أَرْبَعُونَ شَهْرًا قَالَ أَبَيْتُ قَالُوا أَرْبَعُونَ سَنَةً قَالَ أَبَيْتُ ثُمَّ يُنْزِلُ اللَّهُ مِنْ السَّمَاءِ مَاءً فَيَنْبُتُونَ كَمَا يَنْبُتُ الْبَقْلُ قَالَ وَلَيْسَ مِنْ الْإِنْسَانِ شَيْءٌ إِلَّا يَبْلَى إِلَّا عَظْمًا وَاحِدًا وَهُوَ عَجْبُ الذَّنَبِ وَمِنْهُ يُرَكَّبُ الْخَلْقُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala`] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Antara dua tiupan sangkakala terdapat empat puluh.\" Mereka bertanya: Hai Abu Huraiarh? Empatpuluh harikah? Abu Hurairah berkata: Aku enggan menjawab. Mereka bertanya: Empatpuluh bulankah? Abu Hurairah berkata: Aku enggan menjawab. Mereka bertanya: Empatpuluh tahunkah? Abu Hurairah berkata: Aku enggan menjawab. Kemudian Allah menurunkan air dari langit lalu menumbuhkan seperti tumbuhnya tanaman. Ia berkata: Tidak ada seorang pun melainkan telah usang kecuali satu tulang, yaitu tulang ekor. Dari situlah manusia disusun pada hari kiamat."},"4860":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ ابْنِ آدَمَ يَأْكُلُهُ التُّرَابُ إِلَّا عَجْبَ الذَّنَبِ مِنْهُ خُلِقَ وَفِيهِ يُرَكَّبُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Mughirah Al Hizami] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Setiap anak cucu Adam dimakan tanah kecuali tulang ekor. Dari situlah ia diciptakan dari Disitulah ia disusun (kembali).\""},"4861":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْإِنْسَانِ عَظْمًا لَا تَأْكُلُهُ الْأَرْضُ أَبَدًا فِيهِ يُرَكَّبُ يَوْمَ الْقِيَامَةِ قَالُوا أَيُّ عَظْمٍ هُوَ يَا رَسُولَ اللَّهِ قَالَ عَجْبُ الذَّنَبِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] berkata: Inilah yang diceritakan oleh [Abu Hurairah] dari Rasulullah Shallallahu 'alaihi wa Salam, ia menyebut beberapa hadits diantaranya: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya pada diri manusia ada satu tulang yang tidak dimakan bumi selamanya. Padanyalah ia disusun (kembali) pada hari kiamat.\" Mereka bertanya: Tulang apa itu wahai Rasulullah? beliau menjawab: \"Tulang ekor.\""},"4862":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِالسُّوقِ دَاخِلًا مِنْ بَعْضِ الْعَالِيَةِ وَالنَّاسُ كَنَفَتَهُ فَمَرَّ بِجَدْيٍ أَسَكَّ مَيِّتٍ فَتَنَاوَلَهُ فَأَخَذَ بِأُذُنِهِ ثُمَّ قَالَ أَيُّكُمْ يُحِبُّ أَنَّ هَذَا لَهُ بِدِرْهَمٍ فَقَالُوا مَا نُحِبُّ أَنَّهُ لَنَا بِشَيْءٍ وَمَا نَصْنَعُ بِهِ قَالَ أَتُحِبُّونَ أَنَّهُ لَكُمْ قَالُوا وَاللَّهِ لَوْ كَانَ حَيًّا كَانَ عَيْبًا فِيهِ لِأَنَّهُ أَسَكُّ فَكَيْفَ وَهُوَ مَيِّتٌ فَقَالَ فَوَاللَّهِ لَلدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ هَذَا عَلَيْكُمْحَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ وَإِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ عَرْعَرَةَ السَّامِيُّ قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِيَانِ الثَّقَفِيَّ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّ فِي حَدِيثِ الثَّقَفِيِّ فَلَوْ كَانَ حَيًّا كَانَ هَذَا السَّكَكُ بِهِ عَيْبًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Ja'far] dari [ayahnya] dari [Jabir bin Abdullah], Rasulullah Shallallahu 'alaihi wa Salam melintas masuk ke pasar seusai pergi dari tempat-tempat tinggi sementara orang-orang berada disisi beliau. Beliau melintasi bangkai anak kambing dengan telinga melekat, beliau mengangkat telinganya lalu bersabda: \"Siapa diantara kalian yang mau membeli ini seharga satu dirham?\" mereka menjawab: Kami tidak mau memilikinya, untuk apa? Beliau bersabda: \"Apa kalian mau (bangkai) ini milik kalian?\" mereka menjawab: Demi Allah, andai masih hidup pun ada cacatnya karena telinganya menempel, lalu bagaimana halnya dalam keadaan sudah mati? Beliau bersabda: \"Demi Allah, dunia lebih hina bagi Allah melebihi (bangkai) ini bagi kalian.\" Telah menceritakan kepadaku [Muhammad bin Al Mutsanna Al Anazi] dan [Ibrahim bin Muhammad bin Ararah As Sami] keduanya berkata: telah menceritakan kepada kami [Abdulwahhab Ats Tsaqafi] dari [Ja'far] dari [ayahnya] dari [Jabir] dari nabi Shallallahu 'alaihi wa Salam sepertinya hanya saja dalam hadits Ats Tsaqafi disebutkan: Bila pun hidup, telinga yang menempel ini aib."},"4863":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقْرَأُ أَلْهَاكُمْ التَّكَاثُرُ قَالَ يَقُولُ ابْنُ آدَمَ مَالِي مَالِي قَال�� وَهَلْ لَكَ يَا ابْنَ آدَمَ مِنْ مَالِكَ إِلَّا مَا أَكَلْتَ فَأَفْنَيْتَ أَوْ لَبِسْتَ فَأَبْلَيْتَ أَوْ تَصَدَّقْتَ فَأَمْضَيْتَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَقَالَا جَمِيعًا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي كُلُّهُمْ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ قَالَ انْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ بِمِثْلِ حَدِيثِ هَمَّامٍ","id":"Telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Mutharrif] dari [ayahnya] berkata: Aku mendatangi nabi Shallallahu 'alaihi wa Salam dan beliau tengah membaca: \"Bermegah-megahan telah melalaikanmu.\" (At Takaatsur: 1), beliau bersabda: \"Anak cucu Adam berkata: 'Hartaku, hartaku'.\" Beliau meneruskan: \"Hartamu wahai anak cucu Adam tidak lain adalah yang kau makan lalu kau habiskan, yang kau kenakan lalu kau usangkan atau yang kau sedekahkan lalu kau habiskan.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata: telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan keduanya sama-sama berkata: Telah menceritakan kepada kami [Ibnu Abi Adi] dari [Sa'id]. Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [ayahku], semuanya dari [Qatadah] dari [Mutharrif] dari [ayahnya] berkata: Aku tiba dihadapan nabi Shallallahu 'alaihi wa Salam, lalu ia menyebut seperti hadits Hammam."},"4864":{"ar":"حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ الْعَبْدُ مَالِي مَالِي إِنَّمَا لَهُ مِنْ مَالِهِ ثَلَاثٌ مَا أَكَلَ فَأَفْنَى أَوْ لَبِسَ فَأَبْلَى أَوْ أَعْطَى فَاقْتَنَى وَمَا سِوَى ذَلِكَ فَهُوَ ذَاهِبٌ وَتَارِكُهُ لِلنَّاسِو حَدَّثَنِيهِ أَبُو بَكْرِ بْنُ إِسْحَقَ أَخْبَرَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي الْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepadaku [Hafsh bin Maisarah] dari [Al Ala`] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Manusia berkata, 'Hartaku, hartaku, ' sesungguhnya hartanya ada tiga: yang ia makan lalu ia habiskan, yang ia kenakan lalu ia usangkan atau yang ia berikan (sedekahkan) lalu ia miliki, selain itu akan lenyap dan akan ia tinggalkan untuk manusia'.\" Telah menceritakannya kepadaku [Abu Bakar bin Ishaq] telah mengkhabarkan kepada kami [Ibnu Abi Maryam] telah mengkhabarkan kepada kami [Muhammad bin Ja'far] telah mengkhabarkan kepadaku [Al Ala` bin Abdurrahman] dengan sanad ini dengan matan yang sama."},"4865":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ يَعْنِي ابْنَ حَرْمَلَةَ بْنِ عِمْرَانَ التُّجِيبِيَّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ أَنَّ عَمْرَو بْنَ عَوْفٍ وَهُوَ حَلِيفُ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ إِلَى الْبَحْرَيْنِ يَأْتِي بِجِزْيَتِهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَالَحَ أَهْلَ الْبَحْرَيْنِ وَأَمَّرَ عَلَيْهِمْ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ فَقَدِمَ أَبُو عُبَيْدَةَ بِمَالٍ مِنْ الْبَحْرَيْنِ فَسَمِعَتْ الْأَنْصَارُ بِقُدُومِ أَبِي عُبَيْدَةَ فَوَافَوْا صَلَاةَ الْفَجْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَتَعَرَّضُوا لَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَآهُمْ ثُمَّ قَالَ أَظُنُّكُمْ سَمِعْتُمْ أَنَّ أَبَا عُبَيْدَةَ قَدِمَ بِشَيْءٍ مِنْ الْبَحْرَيْنِ فَقَالُوا أَجَلْ يَا رَسُولَ اللَّهِ قَالَ فَأَبْشِرُوا وَأَمِّلُوا مَا يَسُرُّكُمْ فَوَاللَّهِ مَا الْفَقْرَ أَخْشَى عَلَيْكُمْ وَلَكِنِّي أَخْشَى عَلَيْكُمْ أَنْ تُبْسَطَ الدُّنْيَا عَلَيْكُمْ كَمَا بُسِطَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَتَنَافَسُوهَا كَمَا تَنَافَسُوهَا وَتُهْلِكَكُمْ كَمَا أَهْلَكَتْهُمْحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ كِلَاهُمَا عَنْ الزُّهْرِيِّ بِإِسْنَادِ يُونُسَ وَمِثْلِ حَدِيثِهِ غَيْرَ أَنَّ فِي حَدِيثِ صَالِحٍ وَتُلْهِيَكُمْ كَمَا أَلْهَتْهُمْ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya bin Abdullah bin Harmalah bin Imran At Tujibi] telah mengkhabarkan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] bahwa [Al Miswar bin Makhramah] telah mengkhabarkan kepadanya bahwa [Amru bin Auf] sekutu bagi Amir bin Lu`ai, turut serta dalam perang Badar bersama Rasulullah Shallallahu 'alaihi wa Salam, telah mengkhabarkan kepadanya bahwa Rasulullah Shallallahu 'alaihi wa Salam mengutus Abu Ubaidah bin Al Jarrah ke Bahrain membawa jizyahnya dan Rasulullah Shallallahu 'alaihi wa Salam membuat perjanjian damai dengan penduduk Bahrain, beliau mengangkat Al Ala` bin Al Hadlrami sebagai pemimpin mereka. lalu Abu Ubaidah datang membawa harta dari Bahrain dan kaum Anshar mendengar kedatangan Abu 'Ubaidah lalu mereka shalat fajar bersama Rasulullah Shallallahu 'alahi wa Salam, seusai shalat Rasulullah Shallallahu 'alahi wa Salam bergegas lalu mereka menghadang beliau, Rasulullah Shallallahu 'alahi wa Salam tersenyum saat melihat mereka, setelah itu beliau bersabda: \"Aku kira kalian mendengar bahwa Abu 'Ubaidah datang membawa sesuatu.\" Mereka berkata: Benar, wahai Rasulullah. Beliau bersabda: \"Bergembiralah dan berharaplah apa yang menggembirakan kalian, demi Allah bukan kemiskinan yang aku takutkan pada kalian, tapi aku takut dunia dibentangkan untuk kalian seperti halnya dibentangkan pada orang sebelum kalian, lalu kalian memperlombakannya sebagaimana mereka memperlombakannya lalu ia membinasakan kalian seperti halnya mereka.\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] dan [Abdu bin Humaid], semuanya dari [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih]. Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengkhabarkan kepada kami [Abu Al Yaman] telah mengkhabarkan kepada kami [Syu'aib] keduanya dari [Az Zuhri] dengan sanad Yunus seperti haditsnya, hanya saja disebutkan dalam hadits Shalih: \"Dan melalaikan kalian sebagaimana telah melalaikan mereka.\""},"4866":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ أَنَّ يَزِيدَ بْنَ رَبَاحٍ هُوَ أَبُو فِرَاسٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا فُتِحَتْ عَلَيْكُمْ فَارِسُ وَالرُّومُ أَيُّ قَوْمٍ أَنْتُمْ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ نَقُولُ كَمَا أَمَرَنَا اللَّهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ غَيْرَ ذَلِكَ تَتَنَافَسُونَ ثُمَّ تَتَحَاسَدُونَ ثُمَّ تَتَدَابَرُونَ ثُمَّ تَتَبَاغَضُونَ أَوْ نَحْوَ ذَلِكَ ثُمَّ تَنْطَلِقُونَ فِي مَسَاكِينِ الْمُهَاجِرِينَ فَتَجْعَلُونَ بَعْضَهُمْ عَلَى رِقَابِ بَعْضٍ","id":"Telah menceritakan kepada kami [Amru bin Sawwad Al Amiri] telah mengkhabarkan kepada kami [Abdullah bin Wahb] telah mengkhabarkan kepadaku [Amru bin Al Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya bahwa [Yazid bin Rabah Abu Firas] maula Abdullah bin Amru bin Al Ash telah menceritakan kepadanya dari [Abdullah bin Amru bin Al Ash] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Apabila Persia dan Romawi telah ditaklukkan untuk kalian, maka akan menjadi kaum seperti apakah kalian?\" Abdurrahman bin Auf menjawab: Kami akan mengucap yang diperintahkan Allah kepada kami. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bukan sebaliknya?!, kalian saling berlomba-lomba, saling menghasud, saling memutuskan hubungan, saling marah-marahan, dan sejenisnya, kemudian kalian akan pergi ke tempat orang-orang miskin dari kaum muhajirin lalu menjadikan sebahagian mereka sebagai pemimpin bagi sebahagian yang lain.\""},"4867":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوا إِلَى مَنْ أَسْفَلَ مِنْكُمْ وَلَا تَنْظُرُوا إِلَى مَنْ هُوَ فَوْقَكُمْ فَهُوَ أَجْدَرُ أَنْ لَا تَزْدَرُوا نِعْمَةَ اللَّهِقَالَ أَبُو مُعَاوِيَةَ عَلَيْكُمْ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir]. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah]. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] teks miliknya, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pandanglah orang yang berada dibawah kalian, jangan memandang yang ada di atas kalian, itu lebih laik membuat kalian tidak mengkufuri nikmat Allah.\""},"4868":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ ثَلَاثَةً فِي بَنِي إِسْرَائِيلَ أَبْرَصَ وَأَقْرَعَ وَأَعْمَى فَأَرَادَ اللَّهُ أَنْ يَبْتَلِيَهُمْ فَبَعَثَ إِلَيْهِمْ مَلَكًا فَأَتَى الْأَبْرَصَ فَقَالَ أَيُّ شَيْءٍ أَحَبُّ إِلَيْكَ قَالَ لَوْنٌ حَسَنٌ وَجِلْدٌ حَسَنٌ وَيَذْهَبُ عَنِّي الَّذِي قَدْ قَذِرَنِي النَّاسُ قَالَ فَمَسَحَهُ فَذَهَبَ عَنْهُ قَذَرُهُ وَأُعْطِيَ لَوْنًا حَسَنًا وَجِلْدًا حَسَنًا قَالَ فَأَيُّ الْمَالِ أَحَبُّ إِلَيْكَ قَالَ الْإِبِلُ أَوْ قَالَ الْبَقَرُ شَكَّ إِسْحَقُ إِلَّا أَنَّ الْأَبْرَصَ أَوْ الْأَقْرَعَ قَالَ أَحَدُهُمَا الْإِبِلُ وَقَالَ الْآخَرُ الْبَقَرُ قَالَ فَأُعْطِيَ نَاقَةً عُشَرَاءَ فَقَالَ بَارَكَ اللَّهُ لَكَ فِيهَا قَالَ فَأَتَى الْأَقْرَعَ فَقَالَ أَيُّ شَيْءٍ أَحَبُّ إِلَيْكَ قَالَ شَعَرٌ حَسَنٌ وَيَذْهَبُ عَنِّي هَذَا الَّذِي قَدْ قَذِرَنِي النَّاسُ قَالَ فَمَسَحَهُ فَذَهَبَ عَنْهُ وَأُعْطِيَ شَعَرًا حَسَنًا قَالَ فَأَيُّ الْمَالِ أَحَبُّ إِلَيْكَ قَالَ الْبَقَرُ فَأُعْطِيَ بَقَرَةً حَامِلًا فَقَالَ بَارَكَ اللَّهُ لَكَ فِيهَا قَالَ فَأَتَى الْأَعْمَى فَقَالَ أَيُّ شَيْءٍ أَحَبُّ إِلَيْكَ قَالَ أَنْ يَرُدَّ اللَّهُ إِلَيَّ بَصَرِي فَأُبْصِرَ بِهِ النَّاسَ قَالَ فَمَسَحَهُ فَرَدَّ اللَّهُ إِلَيْهِ بَصَرَهُ قَالَ فَأَيُّ الْمَالِ أَحَبُّ إِلَيْكَ قَالَ الْغَنَمُ فَأُعْطِيَ شَاةً وَالِدًا فَأُنْتِجَ هَذَانِ وَوَلَّدَ هَذَا قَالَ فَكَانَ لِهَذَا وَادٍ مِنْ الْإِبِلِ وَلِهَذَا وَادٍ مِنْ الْبَقَرِ وَلِهَذَا وَادٍ مِنْ الْغَنَمِ قَالَ ثُمَّ إِنَّهُ أَتَى الْأَبْرَصَ فِي صُورَتِهِ وَهَيْئَتِهِ فَقَالَ رَجُلٌ مِسْكِينٌ قَدْ انْقَطَعَتْ بِيَ الْحِبَالُ فِي سَفَرِي فَلَا بَلَاغَ لِي الْيَوْمَ إِلَّا بِاللَّهِ ثُمَّ بِكَ أَسْأَلُكَ بِالَّذِي أَعْطَاكَ اللَّوْنَ الْحَسَنَ وَالْجِلْدَ الْحَسَنَ وَالْمَالَ بَعِيرًا أَتَبَلَّغُ عَلَيْهِ فِي سَفَرِي فَقَالَ الْحُقُوقُ كَثِيرَةٌ فَقَالَ لَهُ كَأَنِّي أَعْرِفُكَ أَلَمْ تَكُنْ أَبْرَصَ يَقْذَرُكَ النَّاسُ فَقِيرًا فَأَعْطَاكَ اللَّهُ فَقَالَ إِنَّمَا وَرِثْتُ هَذَا الْمَالَ كَابِرًا عَنْ كَابِرٍ فَقَالَ إِنْ كُنْتَ كَاذِبًا فَصَيَّرَكَ اللَّهُ إِلَى مَا كُنْتَ قَالَ وَأَتَى الْأَقْرَعَ فِي صُورَتِهِ فَقَالَ لَهُ مِثْلَ مَا قَالَ لِهَذَا وَرَدَّ عَلَيْهِ مِثْلَ مَا رَدَّ عَلَى هَذَا فَقَالَ إِنْ كُنْتَ كَاذِبًا فَصَيَّرَكَ اللَّهُ إِلَى مَا كُنْتَ قَالَ وَأَتَى الْأَعْمَى فِي صُورَتِهِ وَهَيْئَتِهِ فَقَالَ رَجُلٌ مِسْكِينٌ وَابْنُ سَبِيلٍ انْقَطَعَتْ بِيَ الْحِبَالُ فِي سَفَرِي فَلَا بَلَاغَ لِي الْيَوْمَ إِلَّا بِاللَّهِ ثُمَّ بِكَ أَسْأَلُكَ بِالَّذِي رَدَّ عَلَيْكَ بَصَرَكَ شَاةً أَتَبَلَّغُ بِهَا فِي سَفَرِي فَقَالَ قَدْ كُنْتُ أَعْمَى فَرَدَّ اللَّهُ إِلَيَّ بَصَرِي فَخُذْ مَا شِئْتَ وَدَعْ مَا شِئْتَ فَوَاللَّهِ لَا أَجْهَدُكَ الْيَوْمَ شَيْئًا أَخَذْتَهُ لِلَّهِ فَقَالَ أَمْسِكْ مَالَكَ فَإِنَّمَا ابْتُلِيتُمْ فَقَدْ رُضِيَ عَنْكَ وَسُخِطَ عَلَى صَاحِبَيْكَ","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Ishaq bin Abdullah bin Abu Thalhah] telah menceritakan kepadaku [Abdurrahman bin Abu Amrah] bahwa [Abu Hurairah] telah menceritakan kepadanya bahwa ia mendengar Nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya ada tiga orang dari bani israil ada yang kudisan, botak dan buta. Kemudian Allah ingin menguji mereka semua, lalu Dia mengutus malaikat datang menemui mereka. Lantas ia datang menemui orang yang mengidap penyakit kudisan seraya berkata: 'Apa yang paling kamu sukai? ' Ia menjawab: 'Warna kulit yang bagus, kulit yang mulus, serta sembuhnya penyakit kudisku ini.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Lalu iapun mengabulkannya, menyembuhkan penyakit kudisnya, dan diberikan kepadanya warna kulit yang bagus dan kulit yang mulus. Ia berkata: 'Harta apa yang paling kamu senangi? ' Ia menjawab: 'Onta atau sapi.' Ishaq ragu, akan tetapi yang jelas orang yang berpenyakit kudisan dan yang botak kepalanya itu salah satu dari keduanya mengatakan: 'Onta, ' dan yang lain mengatakan: 'Sapi.' Lalu ia memberikannya seekor onta yang sedang hamil tua seraya berkata: 'Semoga Allah memberkahimu dalam onta itu.' Selanjutnya ia mendatangi orang botak kepalanya seraya bertanya kepadanya: 'Apa yang paling kamu sukai? ' Ia menjawab: 'Rambut yang bagus dan sembuhnya penyakit yang membuatku dihina orang.' Lalu iapun mengabulkannya, menyembuhkan penyakitnya serta memberinya rambut yang bagus. Ia bertanya: 'Harta apa yang paling kamu inginkan? ' Ia menjawab: 'Sapi.' Lalu diberikanlah kepadanya seekor sapi yang sedang hamil lantas ia berkata: 'Semoga Allah memberkahimu dalam sapi itu.' Selanjutnya ia mendatangi orang yang buta matanya seraya berkata: 'Apa yang paling kamu senangi? ' Ia menjawab: 'Jika Allah mengembalikan penglihatanku hingga dengannya aku dapat melihat manusia.' Lalu iapun mengabulkannya dan Allah memulihkan penglihatannya. Ia bertanya: 'Harta apa yang paling kamu inginkan? ' Ia menjawab: 'Kambing.' Maka diberikanlah seekor kambing yang hendak beranak kepadanya, lalu tidak berapa lama kambing itupun melahirkan anaknya. Dengan begitu orang ini mempunyai sejumlah onta, yang ini mempunyai sejumlah sapi, dan yang itu mempunyai sejumlah kambing. Kemudian ia mendatangi orang yang (tadinya) kudisan untuk kedua kalinya dalam bentuk yang sesungguhnya, lantas berkata: 'Aku adalah seorang lelaki miskin yang sedang berada dalam perjalanan dan tidak mempunyai pekerjaan sehingga aku tidak mempunyai penghidupan kecuali dari Allah kemudian dari pemberianmu. Dengan nama Dzat yang telah memberimu warna kulit yang bagus, kulit yang mulus, serta memberimu harta berupa onta, aku memintamu untuk memberiku suatu pemberian agar aku dapat melanjutkan perjalananku. Iapun menjawab: 'Hak-hak itu sangat banyak.' Lalu ia berkata: 'Sepertinya aku mengenalmu, bukankah dulu kamu adalah seorang yang mengidap penyakit kudis yang mana para manusia selalu mengejekmu, dan kamu adalah seorang yang fakir lalu Allah memberikan (nikmatNya) kepadamu? ' Ia menjawab: 'Sesungguhnya aku mewarisi harta ini dari nenek moyangku yang kaya.' Iapun berkata: 'Jika kamu berdusta dalam ucapanmu itu, maka semoga saja Allah menjadikanmu seperti sediakala.' Selanjutnya ia mendatangi si botak dalam bentuk aslinya, lalu ia berkata kepadanya sebagaimana yang dikatakannya kepada orang pertama dan iapun menolaknya sebagaimana orang pertama menolaknya. Lalu ia berkata: 'Jika kamu berdusta dalam ucapanmu, maka semoga saja Allah akan menjadikanmu seperti sediakala.' Kemudian ia mendatangi orang (yang tadinya) buta matanya dalam bentuk aslinya seraya berkata: 'Aku adalah seorang lelaki miskin yang sedang berada dalam perjalanan, dalam perjalananku ini aku tidak mempunyai pekerjaan sehingga aku tidak mempunyai sumber penghidupan kecuali dari Allah kemudian dari pemberianmu. Demi Dzat yang telah mengembalikan penglihatanmu dan memberimu sejumlah kambing, kumohon berikanlah sesuatu kepadaku sehingga aku dapat melanjutkan perjalananku lagi.' Ia berkata: 'Dulu mataku buta lalu Allah menyembuhkannya, maka ambillah (hartaku) sesuka hatimu dan tinggallah apa yang tidak kau sukai. Sungguh Demi Allah, harta yang kau ambil tidak akan membuatku bersedih.' Maka ia berkata: 'Peliharalah hartamu karena sesungguhnya kalian sedang diuji. Kamu telah diridhai dan kedua temanmu telah dimurkai.\""},"4869":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ وَاللَّفْظُ لِإِسْحَقَ قَالَ عَبَّاسٌ حَدَّثَنَا و قَالَ إِسْحَقُ أَخْبَرَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا بُكَيْرُ بْنُ مِسْمَارٍ حَدَّثَنِي عَامِرُ بْنُ سَعْدٍ قَالَكَانَ سَعْدُ بْنُ أَبِي وَقَّاصٍ فِي إِبِلِهِ فَجَاءَهُ ابْنُهُ عُمَرُ فَلَمَّا رَآهُ سَعْدٌ قَالَ أَعُوذُ بِاللَّهِ مِنْ شَرِّ هَذَا الرَّاكِبِ فَنَزَلَ فَقَالَ لَهُ أَنَزَلْتَ فِي إِبِلِكَ وَغَنَمِكَ وَتَرَكْتَ النَّاسَ يَتَنَازَعُونَ الْمُلْكَ بَيْنَهُمْ فَضَرَبَ سَعْدٌ فِي صَدْرِهِ فَقَالَ اسْكُتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يُحِبُّ الْعَبْدَ التَّقِيَّ الْغَنِيَّ الْخَفِيَّ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abbas bin Abdulazhim] teks milik Ishaq, berkata Abbas telah menceritakan kepada kami, sementara Ishaq berkata: Telah mengkhabarkan kepada kami [Abu Bakr Al Hanafi] telah menceritakan kepada kami [Bukair bin Mismar] telah menceritakan kepadaku [Amir bin Sa'ad] berkata: [Sa'ad bin Abi Waqqash] tengah mengurus untanya lalu Ibnu Umar mendatanginya, saat Sa'ad melihatnya, Ibnu Umar berkata: Aku berlindung kepada Allah dari keburukan pengendara ini. ia turun lalu berkata pada Sa'ad berkata: Apa kau mengurus unta dan kambingmu sementara kau membiarkan orang-orang saling memperebuatkan kekuasaan diantara mereka? Saat memukul dadanya lalu berkata: Diam, aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah menyukai hamba yang bertakwa, berkecukupan dan menyendiri.\""},"4870":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ خَالِدِ بْنِ عُمَيْرٍ الْعَدَوِيِّ قَالَ خَطَبَنَا عُتْبَةُ بْنُ غَزْوَانَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ الدُّنْيَا قَدْ آذَنَتْ بِصَرْمٍ وَوَلَّتْ حَذَّاءَ وَلَمْ يَبْقَ مِنْهَا إِلَّا صُبَابَةٌ كَصُبَابَةِ الْإِنَاءِ يَتَصَابُّهَا صَاحِبُهَا وَإِنَّكُمْ مُنْتَقِلُونَ مِنْهَا إِلَى دَارٍ لَا زَوَالَ لَهَا فَانْتَقِلُوا بِخَيْرِ مَا بِحَضْرَتِكُمْ فَإِنَّهُ قَدْ ذُكِرَ لَنَاأَنَّ الْحَجَرَ يُلْقَى مِنْ شَفَةِ جَهَنَّمَ فَيَهْوِي فِيهَا سَبْعِينَ عَامًا لَا يُدْرِكُ لَهَا قَعْرًا وَ وَاللَّهِ لَتُمْلَأَنَّ أَفَعَجِبْتُمْ وَلَقَدْ ذُكِرَ لَنَا أَنَّ مَا بَيْنَ مِصْرَاعَيْنِ مِنْ مَصَارِيعِ الْجَنَّةِ مَسِيرَةُ أَرْبَعِينَ سَنَةً وَلَيَأْتِيَنَّ عَلَيْهَا يَوْمٌ وَهُوَ كَظِيظٌ مِنْ الزِّحَامِ وَلَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَنَا طَعَامٌ إِلَّا وَرَقُ الشَّجَرِ حَتَّى قَرِحَتْ أَشْدَاقُنَا فَالْتَقَطْتُ بُرْدَةً فَشَقَقْتُهَا بَيْنِي وَبَيْنَ سَعْدِ بْنِ مَالِكٍ فَاتَّزَرْتُ بِنِصْفِهَا وَاتَّزَرَ سَعْدٌ بِنِصْفِهَا فَمَا أَصْبَحَ الْيَوْمَ مِنَّا أَحَدٌ إِلَّا أَصْبَحَ أَمِيرًا عَلَى مِصْرٍ مِنْ الْأَمْصَارِ وَإِنِّي أَعُوذُ بِاللَّهِ أَنْ أَكُونَ فِي نَفْسِي عَظِيمًا وَعِنْدَ اللَّهِ صَغِيرًا وَإِنَّهَا لَمْ تَكُنْ نُبُوَّةٌ قَطُّ إِلَّا تَنَاسَخَتْ حَتَّى يَكُونَ آخِرُ عَاقِبَتِهَا مُلْكًا فَسَتَخْبُرُونَ وَتُجَرِّبُونَ الْأُمَرَاءَ بَعْدَنَاو حَدَّثَنِي إِسْحَقُ بْنُ عُمَرَ بْنِ سَلِيطٍ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ خَالِدِ بْنِ عُمَيْرٍ وَقَدْ أَدْرَكَ الْجَاهِلِيَّةَ قَالَ خَطَبَ عُتْبَةُ بْنُ غَزْوَانَ وَكَانَ أَمِيرًا عَلَى الْبَصْرَةِ فَذَكَرَ نَحْوَ حَدِيثِ شَيْبَانَ","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid bin Hilal] dari [Khalid bin Umair Al Adawi] berkata: [Utbah bin Ghazwan] berkhutbah, ia memuja dan memuji Allah, setelah itu berkata: Amma ba'du, sesungguhnya dunia telah memberitahukan akan lenyap dan tidak ada yang tersisa selain sisa seperti sisa air minum di bejana yang diminum oleh pemiliknya. Sesungguhnya kalian akan berpindah meninggalkannya menuju negeri yang tidak akan lenyap, karena itu pindahlah dengan membawa sesuatu yang terbaik yang ada dihadapan kalian karena telah disebutkan pada kami bahwa sebuah batu dilemparkan dari tepi neraka jahanam lalu jatuh ke dalamnya selama tujuhpuluh tahun belum juga mengenai dasarnya. Demi Allah, neraka jahanam itu akan dipenuhi. Apa kalian heran? Dan telah disebutkan kepada kami bahwa dua daun pintu diantara sekian pintu surga (seluas) perjalanan empatpuluh tahun, suatu hari nanti pintu itu akan penuh sesak. Aku pernah melihat diriku sebagai orang ketujuh dari tujuh orang yang bersama Rasulullah Shallallahu 'alaihi wa Salam, kami tidak memiliki makanan apa pun selain daun pepohonan hingga sudut mulut kami terluka, aku mengambil selimut lalu aku belah dua; untukku dan Sa'ad bin Malik. Separuhnya aku kenakan sarung dan separuhnya lagi dikenakan Sa'ad. Kini, setiap orang dari kami telah menjadi pemimpin salah satu wilayah dan sesungguhnya aku berlindung kepada Allah menjadi orang besar sementara disisi Allah kecil. Sesungguhnya tidak ada satu kenabian pun melainkan berseling-seling hingga akhirnya menjadi kerajaan. Kalian akan mengalaminya dan merasakan menjadi para pemimpin setelah kami. telah menceritakan kepadaku [Ishaq bin Umar bin Salith] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid bin Hilal] dari [Khalid bin Umair], ia menemui masa Jahilyah, ia berkata: [Utbah bin Ghazwan] berkhutbah, ia adalah pemimpin Bashrah. Khalid menyebut seperti hadits Syaiban."},"4871":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ قُرَّةَ بْنِ خَالِدٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ خَالِدِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ عُتْبَةَ بْنَ غَزْوَانَ يَقُولُالَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا طَعَامُنَا إِلَّا وَرَقُ الْحُبْلَةِ حَتَّى قَرِحَتْ أَشْدَاقُنَا","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Qurrah bin Khalid] dari [Humaid bin Hilal] dari [Khalid bin Umair] berkata: Aku mendengar [Utbah bin Ghazwan] berkata: Aku melihatku orang ketujuh dari tujuh orang bersama Rasulullah Shallallahu 'alaihi wa Salam, makanan kami tidak lain hanya dedaunan anggur hingga sudut mulut kami terluka.\""},"4872":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَعَلِيُّ بْنُ حُجْرٍ جَمِيعًا عَنْ إِسْمَعِيلَ قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِ الْحِجْرِ لَا تَدْخُلُوا عَلَى هَؤُلَاءِ الْقَوْمِ الْمُعَذَّبِينَ إِلَّا أَنْ تَكُونُوا بَاكِينَ فَإِنْ لَمْ تَكُونُوا بَاكِينَ فَلَا تَدْخُلُوا عَلَيْهِمْ أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَهُمْ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub], [Qutaibah bin Sa'id] dan [Ali bin Hujr], semuanya dari [Isma'il], berkata [Ibnu Ayyub]: telah menceritakan kepada kami [Isma'il bin Ja'far] telah mengkhabarkan kepadaku [Abdullah bin Dinar] ia mendengar [Abdullah bin Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda kepada para sahabat beliau yang tengah melintasi hijr (tempat kaum Tsamud, pent.): \"Jangan memasuki mereka kaum yang disiksa kecuali kalian menangis, bila kalian tidak menangis, jangan memasuki mereka karena kalian akan tertimpa seperti yang menimpa mereka.\""},"4873":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ وَهُوَ يَذْكُرُ الْحِجْرَ مَسَاكِنَ ثَمُودَ قَالَ سَالِمُ بْنُ عَبْدِ اللَّهِ إِنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَمَرَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْحِجْرِ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْخُلُوا مَسَاكِنَ الَّذِينَ ظَلَمُوا أَنْفُسَهُمْ إِلَّا أَنْ تَكُونُوا بَاكِينَ حَذَرًا أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَهُمْ ثُمَّ زَجَرَ فَأَسْرَعَ حَتَّى خَلَّفَهَا","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengkhabarkan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia menyebut hijr, tempat tinggal kaum Tsamud- berkata [Salim bin Abdullah] bahwa [Abdullah bin Umar] kami bersama Rasulullah Shallallahu 'alaihi wa Salam melintas di hijr, lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda kepada kami: \"Janganlah kalian memasuki tempat-tempat tinggal orang yang menzhalimi diri mereka sendiri kecuali kalian menangis karena khawatir kalian tertimpa seperti yang menimpa mereka.\" Beliau kemudian menghalau lalu cepat-cepat pergi hingga meninggalkan kami."},"4874":{"ar":"حَدَّثَنِي الْحَكَمُ بْنُ مُوسَى أَبُو صَالِحٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ النَّاسَ نَزَلُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْحِجْرِ أَرْضِ ثَمُودَ فَاسْتَقَوْا مِنْ آبَارِهَا وَعَجَنُوا بِهِ الْعَجِينَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُهَرِيقُوا مَا اسْتَقَوْا وَيَعْلِفُوا الْإِبِلَ الْعَجِينَ وَأَمَرَهُمْ أَنْ يَسْتَقُوا مِنْ الْبِئْرِ الَّتِي كَانَتْ تَرِدُهَا النَّاقَةُو حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ فَاسْتَقَوْا مِنْ بِئَارِهَا وَاعْتَجَنُوا بِهِ","id":"Telah menceritakan kepadaku [Al Hakam bin Musa Abu Shalih] telah menceritakan kepada kami [Syu'aib bin Ishaq] telah mengkhabarkan kepada kami [Ubaidullah] dari [Nafi'] bahwa [Abdullah bin Umar] telah mengkhabarkan kepadanya bahwa orang-orang singgah di hijr -kawasan Tsamud- bersama Rasulullah Shallallahu 'alaihi wa Salam, mereka minum dari sumur-sumurnya dan membuat adonan (dengan airnya) lalu Rasulullah Shallallahu 'alaihi wa Salam memerintahkan mereka agar menumpahkan yang mereka minum dan adonan yang mereka buat (dengan air itu) serta memerintahkan mereka agar minum dari sumur yang didatangi unta. telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] telah menceritakan kepada kami [Anas bin Iyadh] telah menceritakan kepadaku [Ubaidullah] dengan sanad ini dengan matan serupa hanya saja ia berkata dalam haditsnya: \"Minumlah dari sumurnya dan buatlah adonan dengan (air) nya.\""},"4875":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ وَأَحْسِبُهُ قَالَ وَكَالْقَائِمِ لَا يَفْتُرُ وَكَالصَّائِمِ لَا يُفْطِرُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Malik] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Orang yang membantu para janda dan orang-orang miskin seperti orang yang berjihad dijalan Allah -aku mengira beliau bersabda: Dan seperti orang yang shalat malam tidak lelah- dan seperti orang puasa tidak berbuka.\""},"4876":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ قَالَ سَمِعْتُ أَبَا الْغَيْثِ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَافِلُ الْيَتِيمِ لَهُ أَوْ لِغَيْرِهِ أَنَا وَهُوَ كَهَاتَيْنِ فِي الْجَنَّةِ وَأَشَارَ مَالِكٌ بِالسَّبَّابَةِ وَالْوُسْطَى","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Malik] dari [Tsaur bin Zaid Ad Dili] berkata: Aku mendengar [Abu Al Ghaits] menceritakan dari [Abu Hurariah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Orang yang menanggung anak yatim miliknya atau milik orang lain, aku dan dia seperti dua ini disurga.\" Malik mengisyaratkan jari telunjuk dan jari tengah."},"4877":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَأَحْمَدُ بْنُ عِيسَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو وَهُوَ ابْنُ الْحَارِثِ أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ عَاصِمَ بْنَ عُمَرَ بْنِ قَتَادَةَ حَدَّثَهُ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ الْخَوْلَانِيَّ يَذْكُرُأَنَّهُ سَمِعَ عُثْمَانَ بْنَ عَفَّانَ عِنْدَ قَوْلِ النَّاسِ فِيهِ حِينَ بَنَى مَسْجِدَ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ قَدْ أَكْثَرْتُمْ وَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى مَسْجِدًا قَالَ بُكَيْرٌ حَسِبْتُ أَنَّهُ قَالَ يَبْتَغِي بِهِ وَجْهَ اللَّهِ بَنَى اللَّهُ لَهُ مِثْلَهُ فِي الْجَنَّةِوَفِي رِوَايَةِ هَارُونَ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al Aili] dan [Ahmad bin Isa] keduanya berkata: telah menceritakan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Amru bin Al Harits] bahwa [Bukair] telah menceritakan kepadanya bahwa [Ashim bin Umar bin Qatadah] telah menceritakan kepadanya bahwa ia mendengar [Ubaidullah Al Khaulani] menyebutkan bahwa ia mendengar [Utsman bin Affan] saat orang-orang berkata tentang dia saat membangun masjid Rasulullah Shallallahu 'alaihi wa Salam: Sesungguhnya kalian memperbanyak, aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa membangun masjid -Bukair berkata: Aku mengiranya berkata: Karena mencari wajah Allah- maka Allah akan membangunkan sepertinya di surga.\" Disebutkan dalam riwayat Harun: \"Allah akan membangunkan rumah untuknya di surga.\""},"4878":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى كِلَاهُمَا عَنْ الضَّحَّاكِ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ مَحْمُودِ بْنِ لَبِيدٍأَنَّ عُثْمَانَ بْنَ عَفَّانَ أَرَادَ بِنَاءَ الْمَسْجِدِ فَكَرِهَ النَّاسُ ذَلِكَ وَأَحَبُّوا أَنْ يَدَعَهُ عَلَى هَيْئَتِهِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى مَسْجِدًا لِلَّهِ بَنَى اللَّهُ لَهُ فِي الْجَنَّةِ مِثْلَهُو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ وَعَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ كِلَاهُمَا عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِهِمَا بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] keduanya dari [Adh Dhahhak] berkata [Ibnu Al Mutsanna]: telah menceritakan kepada kami [Adh Dhahhak bin Makhald] telah mengkhabarkan kepada kami [Abdulhamid bin Ja'far] telah menceritakan kepadaku [ayahku] dari [Mahmud bin Labid] bahwa [Utsman bin Affan] hendak membangun masjid tapi orang-orang tidak menyukainya, mereka ingin masjid tetap seperti kondisinya. Lalu ia berkata: Aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa membangun masjid maka Allah akan membangunkan sepertinya di surga.\" Telah menceritakannya kepada kami [Ishaq bin Ibrahim Al Hadzhali] telah menceritakan kepada kami [Abu Bakr Al Hanafi] dan [Abdulmalik bin Ash Shabbah] keduanya dari [Abdulhamid bin Ja'far] dengan sanad ini, hanya saja dalam hadits keduanya disebutkan: \"Allah akan membangunkan rumah untuknya disurga.\""},"4879":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَجُلٌ بِفَلَاةٍ مِنْ الْأَرْضِ فَسَمِعَ صَوْتًا فِي سَحَابَةٍ اسْقِ حَدِيقَةَ فُلَانٍ فَتَنَحَّى ذَلِكَ السَّحَابُ فَأَفْرَغَ مَاءَهُ فِي حَرَّةٍ فَإِذَا شَرْجَةٌ مِنْ تِلْكَ الشِّرَاجِ قَدْ اسْتَوْعَبَتْ ذَلِكَ الْمَاءَ كُلَّهُ فَتَتَبَّعَ الْمَاءَ فَإِذَا رَجُلٌ قَائِمٌ فِي حَدِيقَتِهِ يُحَوِّلُ الْمَاءَ بِمِسْحَاتِهِ فَقَالَ لَهُ يَا عَبْدَ اللَّهِ مَا اسْمُكَ قَالَ فُلَانٌ لِلِاسْمِ الَّذِي سَمِعَ فِي السَّحَابَةِ فَقَالَ لَهُ يَا عَبْدَ اللَّهِ لِمَ تَسْأَلُنِي عَنْ اسْمِي فَقَالَ إِنِّي سَمِعْتُ صَوْتًا فِي السَّحَابِ الَّذِي هَذَا مَاؤُهُ يَقُولُ اسْقِ حَدِيقَةَ فُلَانٍ لِاسْمِكَ فَمَا تَصْنَعُ فِيهَا قَالَ أَمَّا إِذْ قُلْتَ هَذَا فَإِنِّي أَنْظُرُ إِلَى مَا يَخْرُجُ مِنْهَا فَأَتَصَدَّقُ بِثُلُثِهِ وَآكُلُ أَنَا وَعِيَالِي ثُلُثًا وَأَرُدُّ فِيهَا ثُلُثَهُو حَدَّثَنَاه أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ أَخْبَرَنَا أَبُو دَاوُدَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ حَدَّثَنَا وَهْبُ بْنُ كَيْسَانَ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ وَأَجْعَلُ ثُلُثَهُ فِي الْمَسَاكِينِ وَالسَّائِلِين�� وَابْنِ السَّبِيلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Zuhair bin Harb], teks milik Abu Bakr, keduanya berkata: Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Abdulaziz bin Abu Salamah] dari [Wahb bin Kaisan] dari [Ubaidullah bin Umair Al Laitsi] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Saat seseorang berada di suatu padang pasir, ia mendengar suara di awan: 'Siramilah kebun si fulan' lalu awan itu menjauh dan menuangkan air. Ternyata dikebun itu ada seseorang yang tengah mengurus air dengan sekopnya. Ia bertanya padanya: 'Wahai hamba Allah, siapa namamu? ' Ia menjawab: 'Fulan.' Sama seperti nama yang ia dengar dari awan. Ia bertanya: 'Hai hamba Allah, kenapa kau tanya namaku? ' ia menjawab: 'Aku mendengar suara di awan dimana inilah airnya. Awan itu berkata: 'Siramilah kebun si fulan, namamu. Apa yang kau lakukan dalam kebunmu? ' ia menjawab: 'Karena kau mengatakan seperti itu, aku melihat (hasil) yang keluar darinya, lalu aku sedekahkan sepertiganya, aku makan sepertiganya bersama keluargaku dan aku kembalikan sepertiganya ke kebun'.\" Telah menceritakannya kepada kami [Ahmad bin Abdah Adh Dhabbi] telah mengkhabarkan kepada kami [Abu Dawud] telah menceritakan kepada kami [Abdulaziz bin Abu Salamah] telah menceritakan kepada kami [Wahab bin Kaisan] dengan sanad ini, hanya saja ia berkata: \"Dan aku berikan sepertiganya untuk orang-orang miskin, peminta-minta dan Ibnu sabil.\""},"4880":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا رَوْحُ بْنُ الْقَاسِمِ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْقُوبَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى أَنَا أَغْنَى الشُّرَكَاءِ عَنْ الشِّرْكِ مَنْ عَمِلَ عَمَلًا أَشْرَكَ فِيهِ مَعِي غَيْرِي تَرَكْتُهُ وَشِرْكَهُ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Rauh bin Al Qasim] dari [Al Ala` bin Abdurrahman bin Ya'qub] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah Tabaraka wa Ta'ala berfirman: 'Aku adalah sekutu yang paling tidak memerlukan sekutu, barangsiapa melakukan suatu amalan dengan menyekutukanKu dengan selainKu, Aku meninggalkannya dan sekutunya'.\""},"4881":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنِي أَبِي عَنْ إِسْمَعِيلَ بْنِ سُمَيْعٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَمَّعَ سَمَّعَ اللَّهُ بِهِ وَمَنْ رَاءَى رَاءَى اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepadaku [ayahku] dari [Isma'il bin Sumai'] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa memperdengarkan (amalannya) niscaya Allah memperdengarkan dengannya dan barangsiapa memperlihatkan (amalannya) niscaya Allah memperlihatkan dengannya.\""},"4882":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ جُنْدُبًا الْعَلَقِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُسَمِّعْ يُسَمِّعْ اللَّهُ بِهِ وَمَنْ يُرَائِي يُرَائِي اللَّهُ بِهِو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْمُلَائِيُّ حَدَّثَنَا سُفْيَانُ بِهَذَا الْإِسْنَادِ وَزَادَ وَلَمْ أَسْمَعْ أَحَدًا غَيْرَهُ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ أَخْبَرَنَا سُفْيَانُ عَنْ الْوَلِيدِ بْنِ حَرْبٍ قَالَ سَعِيدٌ أَظُنُّهُ قَالَ ابْنُ الْحَارِثِ بْنِ أَبِي مُوسَى قَالَ سَمِعْتُ سَلَمَةَ بْنَ كُهَيْلٍ قَالَ سَمِعْتُ جُنْدُبًا وَلَمْ أَسْمَعْ أَحَدًا يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَهُ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ الثَّوْرِيِّ و حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الصَّدُوقُ الْأَمِينُ الْوَلِيدُ بْنُ حَرْبٍ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salamah bin Kuhail] berkata: Aku mendengar [Jundub Al Alaqi] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa memperdengarkan (amalannya) niscaya Allah memperdengarkan dengannya dan barangsiapa memperlihatkan (amalannya) niscaya Allah memperlihatkan dengannya.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Al Mula`i] telah menceritakan kepada kami [Sufyan] dengan sanad ini, ia menambahkan -dan aku tidak mendengar seorang pun selainnya mengatakan: Rasulullah Shallallahu 'alaihi wa Salam bersabda. Telah menceritakan kepada kami [Sa'id bin Amru Al Asy'atsi] telah mengkhabarkan kepada kami [Sufyan] dari [Al Walid bin Harb] berkata Sa'id: Aku kira ia berkata: Berkata Ibnu Al Harits bin Abu Musa: Aku mendengar [Salamah bin Kuhail] berkata: Aku mendengar [Jundub] dan aku tidak mendengar seorang pun selain dia berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda seperti hadits Ats Tsauri. Telah menceritakannya kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami Ash Shaduq Al Amin [Al Walid bin Harb] dengan sanad ini."},"4883":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْعَبْدَ لَيَتَكَلَّمُ بِالْكَلِمَةِ يَنْزِلُ بِهَا فِي النَّارِ أَبْعَدَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakru bin Mudlar] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari [Isa bin Thalhah] dari [Abu Hurairah] ia mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya hamba mengucapkan kalimat yang karenanya ia menempati neraka sejauh antara timur dan barat.\""},"4884":{"ar":"و حَدَّثَنَاه مُحَمَّدُ بْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مَا يَتَبَيَّنُ مَا فِيهَا يَهْوِي بِهَا فِي النَّارِ أَبْعَدَ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ","id":"Telah menceritakannya kepada kami [Muhammad bin Abu Umar Al Makki] telah menceritakan kepada kami [Abdulaziz Ad Darawardi] dari [Yazid bin Al Had] dari [Muhammad bin Ibrahim] dari [Isa bin Thalhah] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya hamba mengucapkan kalimat tanpa diteliti yang karenanya ia terlempar ke neraka sejauh antara timur dan barat.\""},"4885":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَ يَحْيَى وَإِسْحَقُ أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَ قِيلَ لَهُ أَلَا تَدْخُلُ عَلَى عُثْمَانَ فَتُكَلِّمَهُ فَقَالَ أَتَرَوْنَ أَنِّي لَا أُكَلِّمُهُ إِلَّا أُسْمِعُكُمْ وَاللَّهِ لَقَدْ كَلَّمْتُهُ فِيمَا بَيْنِي وَبَيْنَهُ مَا دُونَ أَنْ أَفْتَتِحَ أَمْرًا لَا أُحِبُّ أَنْ أَكُونَ أَوَّلَ مَنْ فَتَحَهُ وَلَا أَقُولُ لِأَحَدٍ يَكُونُ عَلَيَّ أَمِيرًا إِنَّهُ خَيْرُ النَّاسِ بَعْدَ مَاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُؤْتَى بِالرَّجُلِ يَوْمَ الْقِيَامَةِ فَيُلْقَى فِي النَّارِ فَتَنْدَلِقُ أَقْتَابُ بَطْنِهِ فَيَدُورُ بِهَا كَمَا يَدُورُ الْحِمَارُ بِالرَّحَى فَيَجْتَمِعُ إِلَيْهِ أَهْلُ النَّارِ فَيَقُولُونَ يَا فُلَانُ مَا لَكَ أَلَمْ تَكُنْ تَأْمُرُ بِالْمَعْرُوفِ وَتَنْهَى عَنْ الْمُنْكَرِ فَيَقُولُ بَلَى قَدْ كُنْتُ آمُرُ بِالْمَعْرُوفِ وَلَا آتِيهِ وَأَنْهَى عَنْ الْمُنْكَرِ وَآتِيهِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ كُنَّا عِنْدَ أُسَامَةَ بْنِ زَيْدٍ فَقَالَ رَجُلٌ مَا يَمْنَعُكَ أَنْ تَدْخُلَ عَلَى عُثْمَانَ فَتُكَلِّمَهُ فِيمَا يَصْنَعُ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], [Abu Bakr bin Abu Syaibah], [Muhammad bin Abdullah bin Numair], [Ishaq bin Ibrahim] dan [Abu Kuraib], teks milik Abu Kuraib, berkata [Yahya] dan [Ishaq]: Telah mengkhabarkan kepada kami, sedangkan yang lain berkata: Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Usamah bin Zaid] berkata: Dikatakan padanya: Bertamulah ke Utsman lalu berbicaralah padanya. Ia berkata: Apa kalian melihatku bahwa aku tidaklah berbicara kepadanya kecuali yang telah saya sampaikan kepada kalian, aku pernah berbicara berdua dengannya tentang sesuatu dimana saya tidak suka untuk memulainya, dan aku tidak berkata kepada siapa pun bahwa aku memiliki pemimpin, ia adalah orang terbaik setelah aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Seseorang didatangkan pada hari kiamat kemudian dilemparkan ke neraka hingga ususnya terburai keluar dan berputar-putar dineraka seperti keledai mengitari alat penumbuk gandumnya, kemudian penduduk neraka bertanya: 'Hai fulan! Apa yang menimpamu, bukankah dulu kau memerintahkan kebaikan dan mencegah kemungkaran? ' Ia menjawab: 'Benar, dulu saya memerintahkan kebaikan tapi saya tidak melakukannya dan saya melarang kemungkaran tapi saya melakukannya'.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] berkata: Kami berada dikediaman [Usamah bin Zaid] lalu seseorang berkata: Apa yang menghalangimu untuk bertamu ke Utsman lalu kau berbicara dengannya. Ia kemudian menyebut hadits serupa."},"4886":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ حَاتِمٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ حَدَّثَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ قَالَ سَالِمٌ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ أُمَّتِي مُعَافَاةٌ إِلَّا الْمُجَاهِرِينَ وَإِنَّ مِنْ الْإِجْهَارِ أَنْ يَعْمَلَ الْعَبْدُ بِاللَّيْلِ عَمَلًا ثُمَّ يُصْبِحُ قَدْ سَتَرَهُ رَبُّهُ فَيَقُولُ يَا فُلَانُ قَدْ عَمِلْتُ الْبَارِحَةَ كَذَا وَكَذَا وَقَدْ بَاتَ يَسْتُرُهُ رَبُّهُ فَيَبِيتُ يَسْتُرُهُ رَبُّهُ وَيُصْبِحُ يَكْشِفُ سِتْرَ اللَّهِ عَنْهُقَالَ زُهَيْرٌ وَإِنَّ مِنْ الْهِجَارِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb], [Muhammad bin Hatim] dan [Abdu bin Humaid], berkata Abdu: telah menceritakan kepadaku, sedang yang lain berkata: telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [keponakan Ibnu Syihab] dari [pamannya] berkata: [Salim] berkata: Saya mendengar [Abu Hurairah] berkata: Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap umatku dimaafkan kecuali orang-orang menampak-nampakkan (dosa) dan sesungguhnya diantara menampak-nampakkan (dosa) adalah seorang hamba yang melakukan amalan di waktu malam kemudian di waktu paginya telah ditutupi oleh Rabbnya lalu ia berkata: 'Wahai fulan semalam aku telah melakukan ini dan itu, ' padahal pada malam harinya (dosanya) Telah ditutupi oleh Rabbnya. Ia pun bermalam dalam keadaan (dosanya) Telah ditutupi oleh Rabbnya dan di pagi harinya ia menyingkap apa yang telah ditutup oleh Allah'.\" Zuhair berkata dan sesungguhnya termasuk dari Hijar (menampak-nampakkan dosa)."},"4887":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَفْصٌ وَهُوَ ابْنُ غِيَاثٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَعَطَسَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَانِ فَشَمَّتَ أَحَدَهُمَا وَلَمْ يُشَمِّتْ الْآخَرَ فَقَالَ الَّذِي لَمْ يُشَمِّتْهُ عَطَسَ فُلَانٌ فَشَمَّتَّهُ وَعَطَسْتُ أَنَا فَلَمْ تُشَمِّتْنِي قَالَ إِنَّ هَذَا حَمِدَ اللَّهَ وَإِنَّكَ لَمْ تَحْمَدْ اللَّهَو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي الْأَحْمَرَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepadaku [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Hafsh bin Giyats] dari [Sulaiman At Taimi] dari [Anas bin Malik] berkata: Dua orang bersin di dekat nabi Shallallahu 'alaihi wa Salam, salah satunya didoakan Rasulullah Shallallahu 'alaihi wa Salam tapi yang lain tidak, yang tidak didoakan berkata: Wahai Rasulullah, Tuan mendoakannya tapi tidak mendoakanku. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya ia memuji Allah sementara kamu tidak.\" telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Sulaiman At Taimi] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam dengan matan serupa."},"4888":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ قَالَدَخَلْتُ عَلَى أَبِي مُوسَى وَهُوَ فِي بَيْتِ بِنْتِ الْفَضْلِ بْنِ عَبَّاسٍ فَعَطَسْتُ فَلَمْ يُشَمِّتْنِي وَعَطَسَتْ فَشَمَّتَهَا فَرَجَعْتُ إِلَى أُمِّي فَأَخْبَرْتُهَا فَلَمَّا جَاءَهَا قَالَتْ عَطَسَ عِنْدَكَ ابْنِي فَلَمْ تُشَمِّتْهُ وَعَطَسَتْ فَشَمَّتَّهَا فَقَالَ إِنَّ ابْنَكِ عَطَسَ فَلَمْ يَحْمَدْ اللَّهَ فَلَمْ أُشَمِّتْهُ وَعَطَسَتْ فَحَمِدَتْ اللَّهَ فَشَمَّتُّهَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا عَطَسَ أَحَدُكُمْ فَحَمِدَ اللَّهَ فَشَمِّتُوهُ فَإِنْ لَمْ يَحْمَدْ اللَّهَ فَلَا تُشَمِّتُوهُ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] dan [Muhammad bin Abdullah bin Numair], teks milik Zuhair, keduanya berkata: Telah menceritakan kepada kami [Al Qasim bin Malik] dari [Ashim bin Kulaib] dari [Abu Burdah] berkata: Aku bertamu ke [Abu Musa] saat berada di rumah putri Al Fadhl bin Abbas, aku bersin tapi ia tidak mendoakanku, putri Al Fadhl bersin lalu ia mendoakannya. Aku kembali ke ibuku lalu aku memberitahukannya. Saat mendatanginya, ia berkata: Anakku bersin didekatmu tapi kau tidak mendoakannya, dan ia (putri Al Fadhl) bersin lalu kau mendoakannya. Abu Hurairah berkata: Putramu bersin dan tidak membaca hamdalah, karena itu aku tidak mendoakannya, sementara ia (putri Al Fadhl) bersin dan membaca hamdalah, karena itu aku mendoakannya. Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila salah seorang dari kalian bersin lalu memuji Allah, doakanlah dia tapi bila tidak memuji Allah, jangan didoakan.\""},"4889":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَطَسَ رَجُلٌ عِنْدَهُ فَقَالَ لَهُ يَرْحَمُكَ اللَّهُ ثُمَّ عَطَسَ أُخْرَى فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ مَزْكُومٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ikrimah bin Ammar] dari [Iyas bin Salamah bin Al Akwa'] dari [ayahnya]. Telah menceritakan kepada kami [Ishaq bin Ibrahim], teks miliknya, telah menceritakan kepada kami [Abu An Nadhr Hasyim bin Al Qasim] telah menceritakan kepada kami [Ikrimah bin Ammar] telah menceritakan kepadaku [Iyas bin Salamah bin Al Akwa'] bahwa [ayahnya] telah menceritakan kepadanya bahwa ia mendengar Rasulullah Shallallahu 'alaihi wa Salam mendoakan seseorang yang bersin didekat beliau: \"YARHAMUKALLAAH\" (semoga Allah merahmatimu) kemuidian ia bersin lagi lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ia pilek.\""},"4890":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَعَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ قَالُوا حَدَّثَنَا إِسْمَعِيلُ يَعْنُونَ ابْنَ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّثَاؤُبُ مِنْ الشَّيْطَانِ فَإِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَكْظِمْ مَا اسْتَطَاعَ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub], [Qutaibah bin Sa'id] dan [Ali bin Hujr As Sa'di] mereka berkata: Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Al Ala`] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Menguap itu dari setan, bila salah seorang dari kalian menguap hendaklah menahannya semampunya.\""},"4891":{"ar":"حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ مَالِكُ بْنُ عَبْدِ الْوَاحِدِ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ قَالَ سَمِعْتُ ابْنًا لِأَبِي سَعِيدٍ الْخُدْرِيِّ يُحَدِّثُ أَبِي عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَثَاوَبَ أَحَدُكُمْ فَلْيُمْسِكْ بِيَدِهِ عَلَى فِيهِ فَإِنَّ الشَّيْطَانَ يَدْخُلُ","id":"Telah menceritakan kepadaku [Abu Ghassan Al Misma'I Malik bin Abdulwahid] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] telah menceritakan kepada kami [Suhail bin Abu Shalih] berkata: Aku mendengar seorang [anak Abu Sa'id Al Khudri] menceritakan dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila salah seorang dari kalian menguap hendaklah ditutupi dengan tangannya karena sesungguhnya setan masuk.\""},"4892":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ سُهَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَثَاوَبَ أَحَدُكُمْ فَلْيُمْسِكْ بِيَدِهِ فَإِنَّ الشَّيْطَانَ يَدْخُلُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdulaziz] dari [Suhail] dari [Abdurrahman bin Abu Sa'id] dari [ayahnya] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila salah seorang dari kalian menguap hendaklah ditutupi dengan tangannya karena sesungguhnya setan masuk.\" "},"4893":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ ابْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَثَاوَبَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَكْظِمْ مَا اسْتَطَاعَ فَإِنَّ الشَّيْطَانَ يَدْخُلُو حَدَّثَنَاه عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ وَعَنْ ابْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَعِيدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ بِشْرٍ وَعَبْدِ الْعَزِيزِ","id":"Telah menceritakan kepadaku [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Suhail bin Abu Shalih] dari [Ibnu Abi Sa'id Al Khudri] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila salah seorang dari kalian menguap saat shalat, hendaklah ditahan semampunya karena sesungguhnya setan masuk.\" Telah menceritakannya kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [ayahnya] dan dari [Ibnu Abi Sa'id] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda seperti hadits Bisyr dan Abdulaziz."},"4894":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنَا و قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِقَتْ الْمَلَائِكَةُ مِنْ نُورٍ وَخُلِقَ الْجَانُّ مِنْ مَارِجٍ مِنْ نَارٍ وَخُلِقَ آدَمُ مِمَّا وُصِفَ لَكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] dan [Abdu bin Humaid], berkata Abdu: Telah mengkhabarkan kepada kami, sedangkan Ibnu Rafi' berkata: Telah menceritakan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Aisyah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Malaikat diciptakan dari cahaya, jin diciptakan dari api yang menyala-nyala dan Adam diciptakan dari sesuatu yang telah disebutkan (ciri-cirinya) untuk kalian.\""},"4895":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرُّزِّيُّ جَمِيعًا عَنْ الثَّقَفِيِّ وَاللَّفْظُ لِابْنِ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُقِدَتْ أُمَّةٌ مِنْ بَنِي إِسْرَائِيلَ لَا يُدْرَى مَا فَعَلَتْ وَلَا أُرَاهَا إِلَّا الْفَأْرَ أَلَا تَرَوْنَهَا إِذَا وُضِعَ لَهَا أَلْبَانُ الْإِبِلِ لَمْ تَشْرَبْهُ وَإِذَا وُضِعَ لَهَا أَلْبَانُ الشَّاءِ شَرِبَتْهُقَالَ أَبُو هُرَيْرَةَ فَحَدَّثْتُ هَذَا الْحَدِيثَ كَعْبًا فَقَالَ آنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ نَعَمْ قَالَ ذَلِكَ مِرَارًا قُلْتُ أَأَقْرَأُ التَّوْرَاةَ و قَالَ إِسْحَقُ فِي رِوَايَتِهِ لَا نَدْرِي مَا فَعَلَتْ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim], [Muhammad bin Al Mutsanna Al Anazi] dan [Muhammad bin Abdullah Ar Razi] semuanya dari [Ats Tsaqafi], teks milik ibnu Al Mutsanna, telah menceritakan kepada kami [Abdulwahhab] telah menceritakan kepada kami [Khalid] dari [Muhammad bin Sirin] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sekelompok ummat dari Bani Israil hilang, tidak diketahui kondisinya dan tidak ada yang memperlihatkannya selain seekor tikus. Bukankah kalian melihatnya bila susu unta diletakkan untuknya, ia tidak meminumnya dan bila susu kambing diletakkan untuknya, ia meminumnya?\" Abu Hurairah berkata: Lalu aku ceritakan hadits ini kepada Ka'ab, ia bertanya: Kau mendengarnya dari Rasulullah Shallallahu 'alaihi wa Salam? Ia menanyakannya berkali-kali. Aku berkata: Apa aku membaca Taurat? Ishaq berkata dalam riwayatnya: \"Kami tidak mengetahui kondisinya.\""},"4896":{"ar":"و حَدَّثَنِي أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَالْفَأْرَةُ مَسْخٌ وَآيَةُ ذَلِكَ أَنَّهُ يُوضَعُ بَيْنَ يَدَيْهَا لَبَنُ الْغَنَمِ فَتَشْرَبُهُ وَيُوضَعُ بَيْنَ يَدَيْهَا لَبَنُ الْإِبِلِ فَلَا تَذُوقُهُ فَقَالَ لَهُ كَعْبٌ أَسَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفَأُنْزِلَتْ عَلَيَّ التَّوْرَاةُ","id":"Telah menceritakan kepadaku [Abu Kuraib Muhammad bin Al Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Muhammad] dari [Abu Hurairah] berkata: Tikus adalah perubahan wujud, tanda-tandanya adalah bila susu kambing diletakkan di depannya, ia meminumnya dan bila susu unta diletakkan dihadapannya, ia tidak mengecapnya. Lalu Ka'ab bertanya padanya: Apa kau mendengarnya dari Rasulullah Shallallahu 'alaihi wa Salam? Abu Hurairah balik bertanya: Apakah Taurat diturunkan padaku? "},"4897":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُلْدَغُ الْمُؤْمِنُ مِنْ جُحْرٍ وَاحِدٍ مَرَّتَيْنِو حَدَّثَنِيهِ أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ ح و حَدَّثَ��ِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ حَاتِمٍ قَالَا حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Uqail] dari [Az Zuhri] dari [Ibnu Al Musayyib] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah orang mu`min tesengat dua kali dari lubang yang sama.\" Telah menceritakannya kepadaku [Abu Ath Thahir] dan [Harmalah bin Yahya] keduanya berkata: Telah mengkhabarkan kepada kami [Ibnu Wahab] dari [Yunus]. Telah menceritakan kepadaku [Zuhair bin Harb] dan [Muhammad bin Hatim] keduanya berkata: Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [keponakan Ibnu Syihab] dari [pamannya] dari [Ibnu Al Musayyib] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"4898":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الْأَزْدِيُّ وَشَيْبَانُ بْنُ فَرُّوخَ جَمِيعًا عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ وَاللَّفْظُ لِشَيْبَانَ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجَبًا لِأَمْرِ الْمُؤْمِنِ إِنَّ أَمْرَهُ كُلَّهُ خَيْرٌ وَلَيْسَ ذَاكَ لِأَحَدٍ إِلَّا لِلْمُؤْمِنِ إِنْ أَصَابَتْهُ سَرَّاءُ شَكَرَ فَكَانَ خَيْرًا لَهُ وَإِنْ أَصَابَتْهُ ضَرَّاءُ صَبَرَ فَكَانَ خَيْرًا لَهُ","id":"Telah menceritakan kepada kami [Haddab bin Khalid Al Azdi] dan [Syaiban bin Farrukh] semuanya dari [Sulaiman bin Al Mughirah] dan teksnya meriwayatkan milik Syaiban, telah menceritakan kepada kami [Sulaiman] telah menceritakan kepada kami [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"perkara orang mu`min mengagumkan, sesungguhnya semua perihalnya baik dan itu tidak dimiliki seorang pun selain orang mu`min, bila tertimpa kesenangan, ia bersyukur dan syukur itu baik baginya dan bila tertimpa musibah, ia bersabar dan sabar itu baik baginya.\""},"4899":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَمَدَحَ رَجُلٌ رَجُلًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ وَيْحَكَ قَطَعْتَ عُنُقَ صَاحِبِكَ قَطَعْتَ عُنُقَ صَاحِبِكَ مِرَارًا إِذَا كَانَ أَحَدُكُمْ مَادِحًا صَاحِبَهُ لَا مَحَالَةَ فَلْيَقُلْ أَحْسِبُ فُلَانًا وَاللَّهُ حَسِيبُهُ وَلَا أُزَكِّي عَلَى اللَّهِ أَحَدًا أَحْسِبُهُ إِنْ كَانَ يَعْلَمُ ذَاكَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid Al Hadzdza`] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] berkata: Seseorang memuji orang lain didekat nabi Shallallahu 'alaihi wa Salam lalu beliau bersabda: \"Cekalah kamu, kau memotong leher temanmu, kau memotong leher temanmu -berkali-kali- bila salah seorang dari kalian memuji temannya -tidak mustahil- hendaklah mengucapkan: 'Aku kira fulan, dan Allah yang menilainya, aku tidak menyucikan seorang pun atas Allah, aku mengiranya -bila ia mengetahuinya- seperti ini dan itu'.\""},"4900":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَبَّادِ بْنِ جَبَلَةَ بْنِ أَبِي رَوَّادٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ أَخْبَرَنَا غُنْدَرٌ قَالَ شُعْبَةُ حَدَّثَنَا عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذُكِرَ عِنْدَهُ رَجُلٌ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ مَا مِنْ رَجُلٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ مِنْهُ فِي كَذَا وَكَذَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَكَ قَطَعْتَ عُنُقَ صَاحِبِكَ مِرَارًا يَقُولُ ذَلِكَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ أَحَدُكُمْ مَادِحًا أَخَاهُ لَا مَحَالَةَ فَلْيَقُلْ أَحْسِبُ فُلَانًا إِنْ كَانَ يُرَى أَنَّهُ كَذَلِكَ وَلَا أُزَكِّي عَلَى اللَّهِ أَحَدًاو حَدَّثَنِيهِ عَمْرٌو النَّاقِدُ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ ح و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ يَزِيدَ بْنِ زُرَيْعٍ وَلَيْسَ فِي حَدِيثِهِمَا فَقَالَ رَجُلٌ مَا مِنْ رَجُلٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ مِنْهُ","id":"Telah menceritakan kepadaku [Muhammad bin Amru bin Abbad bin Habalah bin Abu Rawwad] telah menceritakan kepada kami [Muhammad bin Ja'far]. Telah menceritakan kepadaku [Abu Bakr bin nafi'] telah mengkhabarkan kepada kami [Ghundar] berkata: telah menceritakan kepada kami [Syu'bah] dari [Khalid Al Hadzdza`] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] dari nabi Shallallahu 'alaihi wa Salam, seseorang disebut-sebut disisi beliau lalu ada orang yang berkata: Wahai Rasulullah, tidak ada seorang pun setelah Rasulullah Shallallahu 'alaihi wa Salam yang lebih baik darinya dalam hal ini dan itu. Lalu nabi Shallallahu 'alaihi wa Salam bersabda: \"Tercelalah kamu, kau memotong leher temanmu, kau memotong leher temanmu, \" beliau mengucapkannya berkali-kali kemudian beliau bersabda: \"Bila salah seorang dari kalian memuji temannya -tidak mustahil- hendaklah mengucapkan: 'Aku kira fulan -bila ia melihat seperti itu- dan aku tidak menyucikan seorang pun atas Allah.\" Telah menceritakannya kepadaku [Amru An Naqid] telah menceritakannya kepada kami [Hasyim bin Al Qosim] telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Syababah bin Sawwar] keduanya dari [Syu'bah] dengan sanad ini seperti hadits Yazid bin Zurai', dalam hadits keduanya tidak disebutkan: Lalu orang itu berkata: Tidak ada seorang pun setelah Rasulullah Shallallahu 'alaihi wa Salam yang lebih baik darinya."},"4901":{"ar":"حَدَّثَنِي أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّاءَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُثْنِي عَلَى رَجُلٍ وَيُطْرِيهِ فِي الْمِدْحَةِ فَقَالَ لَقَدْ أَهْلَكْتُمْ أَوْ قَطَعْتُمْ ظَهْرَ الرَّجُلِ","id":"Telah menceritakan kepadaku [Abu Ja'far Muhammad bin Ash Shabbah] telah menceritakan kepada kami [Isma'il bin Zakariya] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] berkata: Nabi Shallallahu 'alaihi wa Salam mendengar seseorang memuji seseorang lainnya secara berlebihan lalu beliau bersabda: \"Kalian telah binasa -atau: Kalian telah memutuskan punggung seseorang.\""},"4902":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى جَمِيعًا عَنْ ابْنِ مَهْدِيٍّ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ حَبِيبٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ قَالَ قَامَ رَجُلٌ يُثْنِي عَلَى أَمِيرٍ مِنْ الْأُمَرَاءِ فَجَعَلَ الْمِقْدَادُ يَحْثِي عَلَيْهِ التُّرَابَ وَقَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَحْثِيَ فِي وُجُوهِ الْمَدَّاحِينَ التُّرَابَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] semuanya dari Ibnu Mahdi dan teksnya milik Ibnu Al Mutsanna keduanya berkata: Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Habib] dari [Mujahid] dari [Abu Ma'mar] berkata: Seseorang berdiri memuji salah seorang amir lalu [Al Miqdad] menaburkan tanah padanya dan berkata: Rasulullah Shallallahu 'alaihi wa Salam memerintahkan kami untuk menaburkan tanah dimuka orang yang memuji-muji."},"4903":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ أَنَّ رَجُلًا جَعَلَ يَمْدَحُ عُثْمَانَ فَعَمِدَ الْمِقْدَادُ فَجَثَا عَلَى رُكْبَتَيْهِ وَكَانَ رَجُلًا ضَخْمًا فَجَعَلَ يَحْثُو فِي وَجْهِهِ الْحَصْبَاءَ فَقَالَ لَهُ عُثْمَانُ مَا شَأْنُكَ فَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الْمَدَّاحِينَ فَاحْثُوا فِي وُجُوهِهِمْ التُّرَابَو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْأَشْجَعِيُّ عُبَيْدُ اللَّهِ بْنُ عُبَيْدِ الرَّحْمَنِ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الْأَعْمَشِ وَمَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ الْمِقْدَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar], teks milik Al Mutsanna, keduanya berkata: Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibraim] dari [Hammam bin Al Harits] bahwa seseorang memuji Utsman lalu [Al Miqdad] menghampirinya kemudian berlutut di atas kedua lututnya, setelah itu menaburkan pasir diwajahnya. Utsman berkata padanya: Kamu kenapa? Al Miqdad berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila kalian melihat orang-orang memuji, taburkan tanah diwajahnya.\" Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata\" Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur]. Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Al Asyja'I Ubaidullah bin Ubaidurrahman] dari [Sufyan Ats Tsauri] dari [Al A'masy] dan [Manshur] dari [Ibrahim] dari [Hammam] dari [Al Miqdaq] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"4904":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا صَخْرٌ يَعْنِي ابْنَ جُوَيْرِيَةَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَانِي فِي الْمَنَامِ أَتَسَوَّكُ بِسِوَاكٍ فَجَذَبَنِي رَجُلَانِ أَحَدُهُمَا أَكْبَرُ مِنْ الْآخَرِ فَنَاوَلْتُ السِّوَاكَ الْأَصْغَرَ مِنْهُمَا فَقِيلَ لِي كَبِّرْ فَدَفَعْتُهُ إِلَى الْأَكْبَرِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdhami] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Shakhr bin Juwairiyah] dari [Nafi'] bahwa [Abdullah bin Umar] telah menceritakan kepadanya bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku bermimpi bersiwak lalu dua orang menghelaku, salah satunya lebih tua dari yang lain, lalu aku memberikan siwak pada yang lebih muda dari keduanya, kemudian dikatakan padaku: '(Berikan pada) yang lebih tua.' Lalu aku menyerahkannya pada yang lebih tua'.\""},"4905":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا بِهِ سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ قَالَكَانَ أَبُو هُرَيْرَةَ يُحَدِّثُ وَيَقُولُ اسْمَعِي يَا رَبَّةَ الْحُجْرَةِ اسْمَعِي يَا رَبَّةَ الْحُجْرَةِ وَعَائِشَةُ تُصَلِّي فَلَمَّا قَضَتْ صَلَاتَهَا قَالَتْ لِعُرْوَةَ أَلَا تَسْمَعُ إِلَى هَذَا وَمَقَالَتِهِ آنِفًا إِنَّمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ حَدِيثًا لَوْ عَدَّهُ الْعَادُّ لَأَحْصَاهُ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakannya kepada kami [Sufyan bin Uyainah] dari [Hisyam] dari [ayahnya] berkata: Abu Hurairah menceritakan, ia berkata: Dengarkanlah wahai penghuni kamar, dengarlah wahai penghuni kamar. Sementara [Aisyah] tengah shalat. Setelah shalat, Aisyah berkata kepada Urwah: Apa kau tidak mendengarnya dan perkataannya itu baru saja. Nabi Shallallahu 'alaihi wa Salam hanya menyampaikan suatu hadits, bila seseorang menghitungnya pasti bisa."},"4906":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ الْأَزْدِيُّ حَدَّثَنَا هَمَّامٌ عَنْ زَيْدِ بْنِ أَ��ْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَكْتُبُوا عَنِّي وَمَنْ كَتَبَ عَنِّي غَيْرَ الْقُرْآنِ فَلْيَمْحُهُ وَحَدِّثُوا عَنِّي وَلَا حَرَجَ وَمَنْ كَذَبَ عَلَيَّ قَالَ هَمَّامٌ أَحْسِبُهُ قَالَ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Haddab bin Khalid Al Azdi] telah menceritakan kepada kami [Hammam] dari [Zaid bin Aslam] dari [Atho` bin Yasar] dari [Abu Sa'id Al Khudri] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Janganlah kalian menulis dariku, barangsiapa menulis dariku selain al-Qur'an hendaklah dihapus, dan ceritakanlah dariku dan tidak ada dosa. Barangsiapa berdusta atas (nama) ku -Hammam berkata: Aku kira ia (Zaid) berkata: dengan sengaja, maka henkdaklah menyiapkan tempatnya dari neraka.\""},"4907":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ مَلِكٌ فِيمَنْ كَانَ قَبْلَكُمْ وَكَانَ لَهُ سَاحِرٌ فَلَمَّا كَبِرَ قَالَ لِلْمَلِكِ إِنِّي قَدْ كَبِرْتُ فَابْعَثْ إِلَيَّ غُلَامًا أُعَلِّمْهُ السِّحْرَ فَبَعَثَ إِلَيْهِ غُلَامًا يُعَلِّمُهُ فَكَانَ فِي طَرِيقِهِ إِذَا سَلَكَ رَاهِبٌ فَقَعَدَ إِلَيْهِ وَسَمِعَ كَلَامَهُ فَأَعْجَبَهُ فَكَانَ إِذَا أَتَى السَّاحِرَ مَرَّ بِالرَّاهِبِ وَقَعَدَ إِلَيْهِ فَإِذَا أَتَى السَّاحِرَ ضَرَبَهُ فَشَكَا ذَلِكَ إِلَى الرَّاهِبِ فَقَالَ إِذَا خَشِيتَ السَّاحِرَ فَقُلْ حَبَسَنِي أَهْلِي وَإِذَا خَشِيتَ أَهْلَكَ فَقُلْ حَبَسَنِي السَّاحِرُ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أَتَى عَلَى دَابَّةٍ عَظِيمَةٍ قَدْ حَبَسَتْ النَّاسَ فَقَالَ الْيَوْمَ أَعْلَمُ آلسَّاحِرُ أَفْضَلُ أَمْ الرَّاهِبُ أَفْضَلُ فَأَخَذَ حَجَرًا فَقَالَ اللَّهُمَّ إِنْ كَانَ أَمْرُ الرَّاهِبِ أَحَبَّ إِلَيْكَ مِنْ أَمْرِ السَّاحِرِ فَاقْتُلْ هَذِهِ الدَّابَّةَ حَتَّى يَمْضِيَ النَّاسُ فَرَمَاهَا فَقَتَلَهَا وَمَضَى النَّاسُ فَأَتَى الرَّاهِبَ فَأَخْبَرَهُ فَقَالَ لَهُ الرَّاهِبُ أَيْ بُنَيَّ أَنْتَ الْيَوْمَ أَفْضَلُ مِنِّي قَدْ بَلَغَ مِنْ أَمْرِكَ مَا أَرَى وَإِنَّكَ سَتُبْتَلَى فَإِنْ ابْتُلِيتَ فَلَا تَدُلَّ عَلَيَّ وَكَانَ الْغُلَامُ يُبْرِئُ الْأَكْمَهَ وَالْأَبْرَصَ وَيُدَاوِي النَّاسَ مِنْ سَائِرِ الْأَدْوَاءِ فَسَمِعَ جَلِيسٌ لِلْمَلِكِ كَانَ قَدْ عَمِيَ فَأَتَاهُ بِهَدَايَا كَثِيرَةٍ فَقَالَ مَا هَاهُنَا لَكَ أَجْمَعُ إِنْ أَنْتَ شَفَيْتَنِي فَقَالَ إِنِّي لَا أَشْفِي أَحَدًا إِنَّمَا يَشْفِي اللَّهُ فَإِنْ أَنْتَ آمَنْتَ بِاللَّهِ دَعَوْتُ اللَّهَ فَشَفَاكَ فَآمَنَ بِاللَّهِ فَشَفَاهُ اللَّهُ فَأَتَى الْمَلِكَ فَجَلَسَ إِلَيْهِ كَمَا كَانَ يَجْلِسُ فَقَالَ لَهُ الْمَلِكُ مَنْ رَدَّ عَلَيْكَ بَصَرَكَ قَالَ رَبِّي قَالَ وَلَكَ رَبٌّ غَيْرِي قَالَ رَبِّي وَرَبُّكَ اللَّهُ فَأَخَذَهُ فَلَمْ يَزَلْ يُعَذِّبُهُ حَتَّى دَلَّ عَلَى الْغُلَامِ فَجِيءَ بِالْغُلَامِ فَقَالَ لَهُ الْمَلِكُ أَيْ بُنَيَّ قَدْ بَلَغَ مِنْ سِحْرِكَ مَا تُبْرِئُ الْأَكْمَهَ وَالْأَبْرَصَ وَتَفْعَلُ وَتَفْعَلُ فَقَالَ إِنِّي لَا أَشْفِي أَحَدًا إِنَّمَا يَشْفِي اللَّهُ فَأَخَذَهُ فَلَمْ يَزَلْ يُعَذِّبُهُ حَتَّى دَلَّ عَلَى الرَّاهِبِ فَجِيءَ بِالرَّاهِبِ فَقِيلَ لَهُ ارْجِعْ عَنْ دِينِكَ فَأَبَى فَدَعَا بِالْمِئْشَارِ فَوَضَعَ الْمِئْشَارَ فِي مَفْرِقِ رَأْسِهِ فَشَقَّهُ حَتَّى وَقَعَ شِقَّاهُ ثُمَّ جِيءَ بِجَلِيسِ الْمَلِكِ فَقِيلَ لَهُ ارْجِعْ عَنْ دِينِكَ فَأَبَى فَوَضَعَ الْمِئْشَارَ فِي مَفْرِقِ رَأْسِهِ فَشَقَّهُ بِهِ حَتَّى وَقَعَ شِقَّاهُ ثُمَّ جِيءَ بِالْغُلَامِ فَقِيلَ لَهُ ارْجِعْ عَنْ دِينِكَ فَأَبَى فَدَفَعَهُ إِلَى نَفَرٍ مِنْ أَصْحَابِهِ فَقَالَ اذْهَبُوا بِهِ إِلَى جَبَلِ كَذَا وَكَذَا فَاصْعَدُوا بِهِ الْجَبَلَ فَإِذَا بَلَغْتُمْ ذُرْوَتَهُ فَإِنْ رَجَعَ عَنْ دِينِهِ وَإِلَّا فَاطْرَحُوهُ فَذَهَبُوا بِهِ فَصَعِدُوا بِهِ الْجَبَلَ فَقَالَ اللَّهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ فَرَجَفَ بِهِمْ الْجَبَلُ فَسَقَطُوا وَجَاءَ يَمْشِي إِلَى الْمَلِكِ فَقَالَ لَهُ الْمَلِكُ مَا فَعَلَ أَصْحَابُكَ قَالَ كَفَانِيهِمُ اللَّهُ فَدَفَعَهُ إِلَى نَفَرٍ مِنْ أَصْحَابِهِ فَقَالَ اذْهَبُوا بِهِ فَاحْمِلُوهُ فِي قُرْقُورٍ فَتَوَسَّطُوا بِهِ الْبَحْرَ فَإِنْ رَجَعَ عَنْ دِينِهِ وَإِلَّا فَاقْذِفُوهُ فَذَهَبُوا بِهِ فَقَالَ اللَّهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ فَانْكَفَأَتْ بِهِمْ السَّفِينَةُ فَغَرِقُوا وَجَاءَ يَمْشِي إِلَى الْمَلِكِ فَقَالَ لَهُ الْمَلِكُ مَا فَعَلَ أَصْحَابُكَ قَالَ كَفَانِيهِمُ اللَّهُ فَقَالَ لِلْمَلِكِ إِنَّكَ لَسْتَ بِقَاتِلِي حَتَّى تَفْعَلَ مَا آمُرُكَ بِهِ قَالَ وَمَا هُوَ قَالَ تَجْمَعُ النَّاسَ فِي صَعِيدٍ وَاحِدٍ وَتَصْلُبُنِي عَلَى جِذْعٍ ثُمَّ خُذْ سَهْمًا مِنْ كِنَانَتِي ثُمَّ ضَعْ السَّهْمَ فِي كَبِدِ الْقَوْسِ ثُمَّ قُلْ بِاسْمِ اللَّهِ رَبِّ الْغُلَامِ ثُمَّ ارْمِنِي فَإِنَّكَ إِذَا فَعَلْتَ ذَلِكَ قَتَلْتَنِي فَجَمَعَ النَّاسَ فِي صَعِيدٍ وَاحِدٍ وَصَلَبَهُ عَلَى جِذْعٍ ثُمَّ أَخَذَ سَهْمًا مِنْ كِنَانَتِهِ ثُمَّ وَضَعَ السَّهْمَ فِي كَبْدِ الْقَوْسِ ثُمَّ قَالَ بِاسْمِ اللَّهِ رَبِّ الْغُلَامِ ثُمَّ رَمَاهُ فَوَقَعَ السَّهْمُ فِي صُدْغِهِ فَوَضَعَ يَدَهُ فِي صُدْغِهِ فِي مَوْضِعِ السَّهْمِ فَمَاتَ فَقَالَ النَّاسُ آمَنَّا بِرَبِّ الْغُلَامِ آمَنَّا بِرَبِّ الْغُلَامِ آمَنَّا بِرَبِّ الْغُلَامِ فَأُتِيَ الْمَلِكُ فَقِيلَ لَهُ أَرَأَيْتَ مَا كُنْتَ تَحْذَرُ قَدْ وَاللَّهِ نَزَلَ بِكَ حَذَرُكَ قَدْ آمَنَ النَّاسُ فَأَمَرَ بِالْأُخْدُودِ فِي أَفْوَاهِ السِّكَكِ فَخُدَّتْ وَأَضْرَمَ النِّيرَانَ وَقَالَ مَنْ لَمْ يَرْجِعْ عَنْ دِينِهِ فَأَحْمُوهُ فِيهَا أَوْ قِيلَ لَهُ اقْتَحِمْ فَفَعَلُوا حَتَّى جَاءَتْ امْرَأَةٌ وَمَعَهَا صَبِيٌّ لَهَا فَتَقَاعَسَتْ أَنْ تَقَعَ فِيهَا فَقَالَ لَهَا الْغُلَامُ يَا أُمَّهْ اصْبِرِي فَإِنَّكِ عَلَى الْحَقِّ","id":"Telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dulu, sebelum kalian ada seorang raja, ia memiliki tukang sihir, saat tukang sihir sudah tua, ia berkata kepada rajanya: 'Aku sudah tua, kirimlah seorang pemuda kepadaku untuk aku ajari sihir.' Lalu seorang pemuda datang padanya, ia mengajarkan sihir kepada pemuda itu. (Jarak) antara tukang sihir dan si raja terdapat seorang rahib. Si pemuda itu mendatangi rahib dan mendengar kata-katanya, ia kagum akan kata-kata si rahib itu sehingga bila datang ke si penyihir pasti dipukul, Pemuda itu mengeluhkan hal itu kepada si rahib, ia berkata: 'Bila tukang sihir hendak memukulmu, katakan: 'Keluargaku menahanku, ' dan bila kau takut pada keluargamu, katakan: 'Si tukang sihir menahanku.' Saat seperti itu, pada suatu hari ia mendekati sebuah hewan yang besar yang menghalangi jalanan orang, ia berkata, 'Hari ini aku akan tahu, apakah tukang sihir lebih baik ataukah pendeta lebih baik.' Ia mengambil batu lalu berkata: 'Ya Allah, bila urusan si rahib lebih Engkau sukai dari pada tukang sihir itu maka bunuhlah binatang ini hingga orang bisa lewat.' Ia melemparkan batu itu dan membunuhnya, orang-orang pun bisa lewat. Ia memberitahukan hal itu kepada si rahib. Si rahib berkata: 'Anakku, saat ini engkau lebih baik dariku dan urusanmu telah sampai seperti yang aku lihat, engkau akan mendapat ujian, bila kau mendapat ujian jangan menunjukkan padaku.' Si pemuda itu bisa menyembuhkan orang buta dan berbagai penyakit. Salah seorang teman raja yang buta lalu ia mendengarnya, ia mendatangi pemuda itu dengan membawa hadiah yang banyak, ia berkata: 'Sembuhkan aku dan kau akan mendapatkan yang aku kumpulkan disini.' Pemuda itu berkata: 'Aku tidak menyembuhkan seorang pun, yang menyembuhkan hanyalah Allah, bila kau beriman padaNya, aku akan berdoa kepadaNya agar menyembuhkanmu.' Teman si raja itu pun beriman lalu si pemuda itu berdoa kepada Allah lalu ia pun sembuh. Teman raja itu kemudian mendatangi raja lalu duduk didekatnya. Si raja berkata: 'Hai fulan, siapa yang menyembuhkan matamu? ' Orang itu menjawab: 'Rabbku.' Si raja berkata: 'Kau punya Rabb selainku? ' Orang itu berkata: 'Rabbku dan Rabbmu adalah Allah.' Si raja menangkapnya lalu menyiksanya hingga ia menunjukkan pada pemuda itu lalu pemuda itu didatangkan, Raja berkata: 'Hai anakku, sihirmu yang bisa menyembuhkan orang buta, sopak dan kau melakukan ini dan itu.' Pemuda itu berkata: 'Bukan aku yang menyembuhkan, yang menyembuhkan hanya Allah.' Si raja menangkapnya dan terus menyiksanya ia menunjukkan kepada si rahib. Si raja mendatangi si rahib, rahib pun didatangkan lalu dikatakan padanya: 'Tinggalkan agamamu.' Si rahib tidak mau lalu si raja meminta gergaji kemudian diletakkan tepat ditengah kepalanya hingga sebelahnya terkapar di tanah. Setelah itu teman si raja didatangkan dan dikatakan padanya: 'Tinggalkan agamamu.' Si rahib tidak mau lalu si raja meminta gergaji kemudian diletakkan tepat ditengah kepalanya hingga sebelahnya terkapar di tanah. Setelah itu pemuda didatangkan lalu dikatakan padanya: 'Tinggalkan agamamu.' Pemuda itu tidak mau. Lalu si raja menyerahkannya ke sekelompok tentaranya, raja berkata: 'Bawalah dia ke gunung ini dan ini, bawalah ia naik, bila ia mau meninggalkan agamanya (biarkanlah dia) dan bila tidak mau, lemparkan dari atas gunung.' Mereka membawanya ke puncak gunung lalu pemuda itu berdoa: 'Ya Allah, cukupilah aku dari mereka sekehendakMu.' Ternyata gunung mengguncang mereka dan mereka semua jatuh. Pemuda itu kembali pulang hingga tiba dihadapan raja. Raja bertanya: 'Bagaimana kondisi kawan-kawanmu? ' Pemuda itu menjawab: 'Allah mencukupiku dari mereka.' Lalu si raja menyerahkannya ke sekelompok tentaranya, raja berkata: 'Bawalah dia ke sebuah perahu lalu kirim ke tengah laut, bila ia mau meninggalkan agamanya (bawalah dia pulang) dan bila ia tidak mau meninggalkannya, lemparkan dia.' Mereka membawanya ke tengah laut lalu pemuda itu berdoa: 'Ya Allah, cukupilah aku dari mereka sekehendakMu.' Ternyata perahunya terbalik dan mereka semua tenggelam. Pemuda itu pulang hingga tiba dihadapan raja, raja bertanya: Bagaimana keadaan teman-temanmu? ' Pemuda itu menjawab: 'Allah mencukupiku dari mereka.' Setelah itu ia berkata kepada raja: 'Kau tidak akan bisa membunuhku hingga kau mau melakukan yang aku perintahkan, ' Raja bertanya: 'Apa yang kau perintahkan? ' Pemuda itu berkata: 'Kumpulkan semua orang ditanah luas lalu saliblah aku diatas pelepah, ambillah anak panah dari sarung panahku lalu ucapkan: 'Dengan nama Allah, Rabb pemuda ini.' Bila kau melakukannya kau akan membunuhku.' Akhirnya raja itu melakukannya. Ia meletakkan anak panah ditengah-tengah panah lalu melesakkannya seraya berkata: 'Dengan nama Allah, Rabb pemuda ini.' Anak panah di lesakkan ke pelipis pemuda itu lalu pemuda meletakkan tangannya ditempat panah menancap kemudian mati. Orang-orang berkata: 'Kami beriman dengan Rabb pemuda itu.' Kemudian didatangkank kepada raja dan dikatakan padanya: 'Tahukah kamu akan sesuatu yang kau khawatirkan, demi Allah kini telah menimpamu. Orang-orang beriman seluruhnya.' Si raja kemudian memerintahkan membuat parit di jalanan kemudian disulut api. Raja berkata: 'Siapa pun yang tidak meninggalkan agamanya, pangganglah didalamnya.' Mereka melakukannya hingga datanglah seorang wanita bersama anaknya, sepertinya ia hendak mundur agar tidak terjatuh dalam kubangan api lalu si bayi itu berkata: 'Ibuku, bersabarlah, sesungguhnya engkau berada diatas kebenaran.\""},"4908":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَمُحَمَّدُ بْنُ عَبَّادٍ وَتَقَارَبَا فِي لَفْظِ الْحَدِيثِ وَالسِّيَاقُ لِهَارُونَ قَالَا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ يَعْقُوبَ بْنِ مُجَاهِدٍ أَبِي حَزْرَةَ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ قَالَخَرَجْتُ أَنَا وَأَبِي نَطْلُبُ الْعِلْمَ فِي هَذَا الْحَيِّ مِنْ الْأَنْصَارِ قَبْلَ أَنْ يَهْلِكُوا فَكَانَ أَوَّلُ مَنْ لَقِينَا أَبَا الْيَسَرِ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ غُلَامٌ لَهُ مَعَهُ ضِمَامَةٌ مِنْ صُحُفٍ وَعَلَى أَبِي الْيَسَرِ بُرْدَةٌ وَمَعَافِرِيَّ وَعَلَى غُلَامِهِ بُرْدَةٌ وَمَعَافِرِيَّ فَقَالَ لَهُ أَبِي يَا عَمِّ إِنِّي أَرَى فِي وَجْهِكَ سَفْعَةً مِنْ غَضَبٍ قَالَ أَجَلْ كَانَ لِي عَلَى فُلَانِ ابْنِ فُلَانٍ الْحَرَامِيِّ مَالٌ فَأَتَيْتُ أَهْلَهُ فَسَلَّمْتُ فَقُلْتُ ثَمَّ هُوَ قَالُوا لَا فَخَرَجَ عَلَيَّ ابْنٌ لَهُ جَفْرٌ فَقُلْتُ لَهُ أَيْنَ أَبُوكَ قَالَ سَمِعَ صَوْتَكَ فَدَخَلَ أَرِيكَةَ أُمِّي فَقُلْتُ اخْرُجْ إِلَيَّ فَقَدْ عَلِمْتُ أَيْنَ أَنْتَ فَخَرَجَ فَقُلْتُ مَا حَمَلَكَ عَلَى أَنْ اخْتَبَأْتَ مِنِّي قَالَ أَنَا وَاللَّهِ أُحَدِّثُكَ ثُمَّ لَا أَكْذِبُكَ خَشِيتُ وَاللَّهِ أَنْ أُحَدِّثَكَ فَأَكْذِبَكَ وَأَنْ أَعِدَكَ فَأُخْلِفَكَ وَكُنْتَ صَاحِبَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْتُ وَاللَّهِ مُعْسِرًا قَالَ قُلْتُ آللَّهِ قَالَ اللَّهِ قُلْتُ آللَّهِ قَالَ اللَّهِ قُلْتُ آللَّهِ قَالَ اللَّهِ قَالَ فَأَتَى بِصَحِيفَتِهِ فَمَحَاهَا بِيَدِهِ فَقَالَ إِنْ وَجَدْتَ قَضَاءً فَاقْضِنِي وَإِلَّا أَنْتَ فِي حِلٍّ فَأَشْهَدُ بَصَرُ عَيْنَيَّ هَاتَيْنِ وَوَضَعَ إِصْبَعَيْهِ عَلَى عَيْنَيْهِ وَسَمْعُ أُذُنَيَّ هَاتَيْنِ وَوَعَاهُ قَلْبِي هَذَا وَأَشَارَ إِلَى مَنَاطِ قَلْبِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ مَنْ أَنْظَرَ مُعْسِرًا أَوْ وَضَعَ عَنْهُ أَظَلَّهُ اللَّهُ فِي ظِلِّهِ قَالَ فَقُلْتُ لَهُ أَنَا يَا عَمِّ لَوْ أَنَّكَ أَخَذْتَ بُرْدَةَ غُلَامِكَ وَأَعْطَيْتَهُ مَعَافِرِيَّكَ وَأَخَذْتَ مَعَافِرِيَّهُ وَأَعْطَيْتَهُ بُرْدَتَكَ فَكَانَتْ عَلَيْكَ حُلَّةٌ وَعَلَيْهِ حُلَّةٌ فَمَسَحَ رَأْسِي وَقَالَ اللَّهُمَّ بَارِكْ فِيهِ يَا ابْنَ أَخِي بَصَرُ عَيْنَيَّ هَاتَيْنِ وَسَمْعُ أُذُنَيَّ هَاتَيْنِ وَوَعَاهُ قَلْبِي هَذَا وَأَشَارَ إِلَى مَنَاطِ قَلْبِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ أَطْعِمُوهُمْ مِمَّا تَأْكُلُونَ وَأَلْبِسُوهُمْ مِمَّا تَلْبَسُونَ وَكَانَ أَنْ أَعْطَيْتُهُ مِنْ مَتَاعِ الدُّنْيَا أَهْوَنَ عَلَيَّ مِنْ أَنْ يَأْخُذَ مِنْ حَسَنَاتِي يَوْمَ الْقِيَامَةِ ثُمَّ مَضَيْنَا حَتَّى أَتَيْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فِي مَسْجِدِهِ وَهُوَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُشْتَمِلًا بِهِ فَتَخَطَّيْتُ الْقَوْمَ حَتَّى جَلَسْتُ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ فَقُلْتُ يَرْحَ��ُكَ اللَّهُ أَتُصَلِّي فِي ثَوْبٍ وَاحِدٍ وَرِدَاؤُكَ إِلَى جَنْبِكَ قَالَ فَقَالَ بِيَدِهِ فِي صَدْرِي هَكَذَا وَفَرَّقَ بَيْنَ أَصَابِعِهِ وَقَوَّسَهَا أَرَدْتُ أَنْ يَدْخُلَ عَلَيَّ الْأَحْمَقُ مِثْلُكَ فَيَرَانِي كَيْفَ أَصْنَعُ فَيَصْنَعُ مِثْلَهُ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِنَا هَذَا وَفِي يَدِهِ عُرْجُونُ ابْنِ طَابٍ فَرَأَى فِي قِبْلَةِ الْمَسْجِدِ نُخَامَةً فَحَكَّهَا بِالْعُرْجُونِ ثُمَّ أَقْبَلَ عَلَيْنَا فَقَالَ أَيُّكُمْ يُحِبُّ أَنْ يُعْرِضَ اللَّهُ عَنْهُ قَالَ فَخَشَعْنَا ثُمَّ قَالَ أَيُّكُمْ يُحِبُّ أَنْ يُعْرِضَ اللَّهُ عَنْهُ قَالَ فَخَشَعْنَا ثُمَّ قَالَ أَيُّكُمْ يُحِبُّ أَنْ يُعْرِضَ اللَّهُ عَنْهُ قُلْنَا لَا أَيُّنَا يَا رَسُولَ اللَّهِ قَالَ فَإِنَّ أَحَدَكُمْ إِذَا قَامَ يُصَلِّي فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قِبَلَ وَجْهِهِ فَلَا يَبْصُقَنَّ قِبَلَ وَجْهِهِ وَلَا عَنْ يَمِينِهِ وَلْيَبْصُقْ عَنْ يَسَارِهِ تَحْتَ رِجْلِهِ الْيُسْرَى فَإِنْ عَجِلَتْ بِهِ بَادِرَةٌ فَلْيَقُلْ بِثَوْبِهِ هَكَذَا ثُمَّ طَوَى ثَوْبَهُ بَعْضَهُ عَلَى بَعْضٍ فَقَالَ أَرُونِي عَبِيرًا فَقَامَ فَتًى مِنْ الْحَيِّ يَشْتَدُّ إِلَى أَهْلِهِ فَجَاءَ بِخَلُوقٍ فِي رَاحَتِهِ فَأَخَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَهُ عَلَى رَأْسِ الْعُرْجُونِ ثُمَّ لَطَخَ بِهِ عَلَى أَثَرِ النُّخَامَةِ فَقَالَ جَابِرٌ فَمِنْ هُنَاكَ جَعَلْتُمْ الْخَلُوقَ فِي مَسَاجِدِكُمْ سِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ بَطْنِ بُوَاطٍ وَهُوَ يَطْلُبُ الْمَجْدِيَّ بْنَ عَمْرٍو الْجُهَنِيَّ وَكَانَ النَّاضِحُ يَعْقُبُهُ مِنَّا الْخَمْسَةُ وَالسِّتَّةُ وَالسَّبْعَةُ فَدَارَتْ عُقْبَةُ رَجُلٍ مِنْ الْأَنْصَارِ عَلَى نَاضِحٍ لَهُ فَأَنَاخَهُ فَرَكِبَهُ ثُمَّ بَعَثَهُ فَتَلَدَّنَ عَلَيْهِ بَعْضَ التَّلَدُّنِ فَقَالَ لَهُ شَأْ لَعَنَكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا اللَّاعِنُ بَعِيرَهُ قَالَ أَنَا يَا رَسُولَ اللَّهِ قَالَ انْزِلْ عَنْهُ فَلَا تَصْحَبْنَا بِمَلْعُونٍ لَا تَدْعُوا عَلَى أَنْفُسِكُمْ وَلَا تَدْعُوا عَلَى أَوْلَادِكُمْ وَلَا تَدْعُوا عَلَى أَمْوَالِكُمْ لَا تُوَافِقُوا مِنْ اللَّهِ سَاعَةً يُسْأَلُ فِيهَا عَطَاءٌ فَيَسْتَجِيبُ لَكُمْ سِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَتْ عُشَيْشِيَةٌ وَدَنَوْنَا مَاءً مِنْ مِيَاهِ الْعَرَبِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَجُلٌ يَتَقَدَّمُنَا فَيَمْدُرُ الْحَوْضَ فَيَشْرَبُ وَيَسْقِينَا قَالَ جَابِرٌ فَقُمْتُ فَقُلْتُ هَذَا رَجُلٌ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ رَجُلٍ مَعَ جَابِرٍ فَقَامَ جَبَّارُ بْنُ صَخْرٍ فَانْطَلَقْنَا إِلَى الْبِئْرِ فَنَزَعْنَا فِي الْحَوْضِ سَجْلًا أَوْ سَجْلَيْنِ ثُمَّ مَدَرْنَاهُ ثُمَّ نَزَعْنَا فِيهِ حَتَّى أَفْهَقْنَاهُ فَكَانَ أَوَّلَ طَالِعٍ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَأْذَنَانِ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ فَأَشْرَعَ نَاقَتَهُ فَشَرِبَتْ شَنَقَ لَهَا فَشَجَتْ فَبَالَتْ ثُمَّ عَدَلَ بِهَا فَأَنَاخَهَا ثُمَّ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْحَوْضِ فَتَوَضَّأَ مِنْهُ ثُمَّ قُمْتُ فَتَوَضَّأْتُ مِنْ مُتَوَضَّإِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ جَبَّارُ بْنُ صَخْرٍ يَقْضِي حَاجَتَهُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ وَكَانَتْ عَلَيَّ بُرْدَةٌ ذَهَبْتُ أَنْ أُخَالِفَ بَيْنَ طَرَفَيْهَا فَلَمْ تَبْلُغْ لِي وَكَانَتْ لَهَا ذَبَاذِبُ فَنَكَّسْتُهَا ثُمَّ خَالَفْتُ بَيْنَ طَرَفَيْهَا ثُمَّ تَوَاقَصْتُ عَلَيْهَا ثُمَّ جِئْتُ حَتَّى قُمْتُ عَنْ يَسَارِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِيَدِي فَأَدَارَنِي حَتَّى أَقَامَنِي عَنْ يَمِينِهِ ثُمَّ جَاءَ جَبَّارُ بْنُ صَخْرٍ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَامَ عَنْ يَسَارِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْنَا جَمِيعًا فَدَفَعَنَا حَتَّى أَقَامَنَا خَلْفَهُ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُنِي وَأَنَا لَا أَشْعُرُ ثُمَّ فَطِنْتُ بِهِ فَقَالَ هَكَذَا بِيَدِهِ يَعْنِي شُدَّ وَسَطَكَ فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا جَابِرُ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ إِذَا كَانَ وَاسِعًا فَخَالِفْ بَيْنَ طَرَفَيْهِ وَإِذَا كَانَ ضَيِّقًا فَاشْدُدْهُ عَلَى حَقْوِكَ سِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قُوتُ كُلِّ رَجُلٍ مِنَّا فِي كُلِّ يَوْمٍ تَمْرَةً فَكَانَ يَمَصُّهَا ثُمَّ يَصُرُّهَا فِي ثَوْبِهِ وَكُنَّا نَخْتَبِطُ بِقِسِيِّنَا وَنَأْكُلُ حَتَّى قَرِحَتْ أَشْدَاقُنَا فَأُقْسِمُ أُخْطِئَهَا رَجُلٌ مِنَّا يَوْمًا فَانْطَلَقْنَا بِهِ نَنْعَشُهُ فَشَهِدْنَا أَنَّهُ لَمْ يُعْطَهَا فَأُعْطِيَهَا فَقَامَ فَأَخَذَهَا سِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَزَلْنَا وَادِيًا أَفْيَحَ فَذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي حَاجَتَهُ فَاتَّبَعْتُهُ بِإِدَاوَةٍ مِنْ مَاءٍ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرَ شَيْئًا يَسْتَتِرُ بِهِ فَإِذَا شَجَرَتَانِ بِشَاطِئِ الْوَادِي فَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى إِحْدَاهُمَا فَأَخَذَ بِغُصْنٍ مِنْ أَغْصَانِهَا فَقَالَ انْقَادِي عَلَيَّ بِإِذْنِ اللَّهِ فَانْقَادَتْ مَعَهُ كَالْبَعِيرِ الْمَخْشُوشِ الَّذِي يُصَانِعُ قَائِدَهُ حَتَّى أَتَى الشَّجَرَةَ الْأُخْرَى فَأَخَذَ بِغُصْنٍ مِنْ أَغْصَانِهَا فَقَالَ انْقَادِي عَلَيَّ بِإِذْنِ اللَّهِ فَانْقَادَتْ مَعَهُ كَذَلِكَ حَتَّى إِذَا كَانَ بِالْمَنْصَفِ مِمَّا بَيْنَهُمَا لَأَمَ بَيْنَهُمَا يَعْنِي جَمَعَهُمَا فَقَالَ الْتَئِمَا عَلَيَّ بِإِذْنِ اللَّهِ فَالْتَأَمَتَا قَالَ جَابِرٌ فَخَرَجْتُ أُحْضِرُ مَخَافَةَ أَنْ يُحِسَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُرْبِي فَيَبْتَعِدَ وَقَالَ مُحَمَّدُ بْنُ عَبَّادٍ فَيَتَبَعَّدَ فَجَلَسْتُ أُحَدِّثُ نَفْسِي فَحَانَتْ مِنِّي لَفْتَةٌ فَإِذَا أَنَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُقْبِلًا وَإِذَا الشَّجَرَتَانِ قَدْ افْتَرَقَتَا فَقَامَتْ كُلُّ وَاحِدَةٍ مِنْهُمَا عَلَى سَاقٍ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ وَقْفَةً فَقَالَ بِرَأْسِهِ هَكَذَا وَأَشَارَ أَبُو إِسْمَعِيلَ بِرَأْسِهِ يَمِينًا وَشِمَالًا ثُمَّ أَقْبَلَ فَ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Muhammad bin Abbad], matan hadits keduanya hampir sama dan pemaparan matan berikut milik Harun, keduanya berkata: Telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ya'qub bin Mujahid Abu Hazrah] dari [Ubadah bin Al Walid bin Ubadah bin Ash Shamit] berkata: Aku dan ayahku pergi menuntut ilmu di perkampungan Anshar ini sebelum mereka meninggal. Orang yang pertama kali kami temui adalah [Abu Al Yasar], sahabat Rasulullah Shallallahu 'alaihi wa Salam, ia bersama seorang budak miliknya, ia membawa sekumpulan lembaran, Abu Al Yasar mengenakan selimut Ma'afiri dan budaknya juga mengenakan selimut Ma'afiri. Ayahku berkata padanya: Hai pamanku, sesungguhnya aku melihat tanda bekas marah di wajahmu. Ia berkata: Benar. Fulan bin fulan memiliki hutang padaku, aku mendatangi keluarganya, aku mengucapkan salam lalu aku mengucapkan kata-kata lalu ia mereka berkata: Tidak. Kemudian seorang anak berperut buncit keluar, aku bertanya: Mana ayahmu? Ia berkata: Ia mendengar suaramu. Selanjutnya ibuku, Arikah, masuk lalu aku berkata: Keluarlah kemari, aku sudah tahu dimana kamu berada. Aku bertanya: Kenapa kau bersembunyi dariku? Ia menjawab: Aku, demi Allah, akan menceritakan padamu, aku tidak bohong, demi Allah, aku takut bercerita kepadamu lalu aku berdusta dan aku berjanji padamu lalu aku pungkiri. Kau adalah sahabat Rasulullah Shallallahu 'alaihi wa Salam dan aku, demi Allah, sedang susah. Aku mengucapkan: Allah. Ia menyahut: Allah. Aku mengucapkan: Allah. Ia menyahut: Allah. Aku mengucapkan: Allah. Ia menyahut: Allah. Lalu ia mengambil lembaran kemudian dihapus dengan tangannya, ia berkata: Bila kau punya uang, lunasilah dan bila tidak punya kau bebas. Penglihatan kedua mataku ini -ia meletakkan jari-jarinya ke kedua matanya- pendengaran kedua telingaku ini dan difahami oleh hatiku ini -ia menunjuk ke tempat hatinya- menyaksikan Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa menangguhkan orang susah atau membebaskannya dari (hutang) nya, Allah akan menaunginya dalam naunganNya.\" Ia berkata: Laku aku berkata padanya: Wahai paman, andai kau mengambil selimut budakmu, kau mengambil budak ma'afirimu, kau mengambil selimut ma'firinya dan kau berukan selimutmu padanya, tentu kau mengenakan perhiasan dan ia juga mengenakan perhiasan. Ia mengusap kepalaku lalu berdoa: Ya Allah, berkahilah ia. Wahai keponakanku, penglihatan kedua mataku ini -ia meletakkan jari-jarinya ke kedua matanya- pendengaran kedua telingaku ini dan difahami oleh hatiku ini -ia menunjuk ke tempat hatinya- menyaksikan Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Berilah mereka makan dari yang kalian makan dan berilah mereka pakaian dari yang kalian kenakan, \" aku memberinya barang-barang dunia itu lebih ringan bagiku dari pada ia mengambil kebaikan-kebaikanku pada hari kiamat. Kami pun pergi hingga mendatangi [Jabir bin Abdullah] dimasjidnya, ia tengah shalat mengenakan satu baju yang ia selimutkan. Aku melangkahi orang-orang hingga aku duduk diantara Jabir dan kiblat. Aku berkata padanya: Semoga Allah merahmatimu, kenapa kau shalat dengan satu baju dan selendangmu ke samping? Ia berisyarat dengan tangannya ke dadaku seperti ini -ia membentangkan jari-jarinya dan melengkungkannya, ia berkata: Aku ingin orang bodoh sepertimu menemuiku lalu melihat apa yang aku lakukan sehingga ia menyontohnya. Rasulullah Shallallahu 'alaihi wa Salam pernah mendatangi kami di masjid kami ini sementara beliau membawa dahan milik Ibnu Thab, beliau melihat dikiblat masjid ada dahak lalu beliau mengeriknya dengan dahan tersebut, setelah itu beliau menghadap ke arah kami lalu bertanya: \"Siapa diantara kalian yang mau Allah berpaling darinya?\" ia berkata: Kami tertunduk. Beliau bertanya lagi: \"Siapa diantara kalian yang mau Allah berpaling darinya?\" kami menjawab: Tidak, wahai Rasulullah. Beliau bersabda: \"Sesungguhnya salah seorang dari kalian bila shalat, Allah Tabaraka wa Ta'ala ada dihadapannya, karena itu jangan meludah ke arah wajahNya atau ke kanannya, hendaklah meludah ke kiri, dibawah kaki kirinya. Dan bila ia tidak bisa mengusai diri hingga didahului oleh ludah atau ingus, hendaklah melakukan dengan bajunya seperti ini\" beliau melipat baju beliau satu sama lain lalu bersabda: \"Perlihatkan minyak za'faran padaku.\" Lalu seorang pemuda kabilah bergegas ke keluarganya dengan cepat lalu datang membawa campuran minyak ditangannya, lalu Rasulullah Shallallahu 'alaihi wa Salam mengambilnya kemudian dioleskan di ujung pelepah kemudian digosokkan di sisa dahak. Jabir berkata: Dari situlah kalian memberi masjid kalian minyak wangi. Kami pernah berjalan bersama Rasulullah Shallallahu 'alaihi wa Salam dalam peperangan Buwath, beliau mencari Al Majdi bin Amru al Juhadi. Unta yang diberi minum dijaga oleh lima, enam dan tujuh orang, kemudian salah seorang penunggu unta dari Anshar mengelilingi unta miliknya, setelah itu unta diderumkan kemudian ia naik. Ia menggusah untanya tapi tetap saja diam, lalu ia berkata pada untanya: Hus, semoga Allah melaknatmu. Lalu Rasulullah Shallallahu 'alaihi wa Salam bertanya: \"Siapa yang melaknat untanya itu?\" ia menjawab: Saya, wahai Rasulullah. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Turunlah, jangan menyertai sesuatu yang terlaknat. Janganlah kalian mendoakan keburukan pada diri kalian, jangan mendoakan keburukan pada anak-anak kalian, jangan mendoakan keburukan pada harta-harta kalian, janganlah kalian menepati saat dikabulkannya doa dari Allah lalu Ia akan mengabulkan untuk kalian.\" Kami berjalan bersama Rasulullah Shallallahu 'alaihi wa Salam hingga sore hari. Kami mendekati salah satu perairan arab lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Siapa yang mau mendahului kami lalu memperbaiki sumur, setelah itu ia minum kemudian memberi kami minum\" Jabir berkata: Aku berdiri lalu berkata: Saya wahai Rasulullah. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Siapa lagi bersama Jabir?\" Jabbar bin Shakhr berdiri. Kami pergi ke sumur lalu kami menarik satu atau dua timba dari sumur. Kami turunkan lalu kami tarik hingga penuh air. Orang pertama yang menemui kami adalah Rasulullah Shallallahu 'alaihi wa Salam, beliau bertanya: \"Apa kalian berdua mengizinkan?\" kami menjawab: Ya, wahai Rasulullah. beliau menundukkan kepala unta beliau, unta beliau lalu minum, beliau memegangi tali kekangnya lalu unta beliau merenggangkan kaki kemudian kencing. Setelah itu beliau mengalihkannya dan menderumkannya. Kemudian Rasulullah Shallallahu 'alaihi wa Salam mendatangi sumur dan berwudhu. Aku pun berdiri lalu wudhu memakai sisa air wudhu Rasulullah Shallallahu 'alaihi wa Salam. Jabbar bin Shakhr kemudian pergi membuang hajat lalu Rasulullah Shallallahu 'alaihi wa Salam berdiri untuk shalat. Aku mengenakan selimut, aku hendak membentangkannya tapi tidak sampai. Selimut itu memiliki ujung lalu balik, setelah itu aku bentangkan diantara kedua ujungnya lalu aku himpit dengan leherku. Kemudian aku datang lalu berdiri disebelah kiri Rasulullah Shallallahu 'alaihi wa Salam. Beliau meraih tanganku lalu memutarku hingga menempatkanku disebelah kanan beliau. Setelah itu Jabbar bin Shakhr tiba. Ia wudhu lalu datang kemudian berdiri disebelah kiri Rasulullah Shallallahu 'alaihi wa Salam, lalu beliau meraih tangan kami lalu kami ditempatkan dibelakang beliau. Rasulullah Shallallahu 'alaihi wa Salam melihatku tapi aku tidak merasa, setelah itu baru aku mengerti lalu beliau berisyarat dengan tangan, maksud beliau ikatlah bagian tengahmu. Seusai shalat, Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hai Jabir!\" aku menyahut: Baik, wahai Rasulullah. Beliau bersabda: \"Bila (bajunya) lebar, bentangkan diantara dua ujungnya dan bila sempit, ikatlah di atas pinggangmu.\" Kami pernah berjalan bersama Rasulullah Shallallahu 'alaihi wa Salam dan makanan masing-masing orang dari kami setiap harinya adalah satu kurma. Beliau menghisap kemudian meletakkan dibaju beliau, dan kami menggerak-gerakkan pohon agar dedaunannya berguguran lalu kami memakannya hingga sudut mulut kami terluka. Aku bersumpah, ada seseorang diantara kami yang hilang pada suatu hari. Lalu kami pergi mencarinya kemudian kami mengangkatnya. Kami bersaksi untuknya bahwa ia belum diberi (jatah kurma) lalu ia diberi. Ia berdiri lalu mengambilnya. Kami pernah berjalan bersama Rasulullah Shallallahu 'alaihi wa Salam hingga kami singgah disuatu lembah yang luas. Rasulullah Shallallahu 'alaihi wa Salam pergi menuntaskan hajat, aku mengikuti beliau dari belakang dengan membawa seember air. Rasulullah Shallallahu 'alaihi wa Salam melihat-lihat, beliau tidak melihat apa pun untuk dijadikan penutup. Ternyata ada dua pohon ditepi lembah. Rasulullah Shallallahu 'alaihi wa Salam pergi mendekati salah satunya kemudian meraih sebagaian dahannya, beliau bersabda: \"Menunduklah untukku, dengan izin Allah.\" Dahan itu merunduk bersama beliau laksana unta bercocok hidung yang dibuat oleh pengendalinya, hingga beliau mendatangi pohon lain lalu meraih salah satu dahannya, beliau bersabda: \"Menunduklah untukku, dengan izin Allah.\" Dahan itu juga merunduk. Setelah beliau berada dipertengahan diantara keduanya, beliau menyatukan keduanya, beliau bersabda: \"Menyatulah untukku, dengan izin Allah.\" Keduanya pun menyatu. Jabir berkata: Aku pergi berlari dengan cepat karena khawatir Rasulullah Shallallahu 'alaihi wa Salam merasakan keberadaanku didekat beliau sehingga beliau akan menjauh. Muhammad bin Abbad berkata dalam riwayatnya: Beliau menjauh lalu aku duduk berbicara dengan diriku sendiri. Aku melirik kesamping ternyata Rasulullah Shallallahu 'alaihi wa Salam datang menghampiri dan ternyata kedua pohon itu telah memancar. Masing-masingnya berdiri di atas tonggaknya. Aku melihat Rasulullah Shallallahu 'alaihi wa Salam berdiri dan beliau berisyarat dengan kepala seperti ini -Abu Isma'il mengisyaratkan dengan kepalanya ke kanan dan ke kiri- setelah itu beliau datang. Sesampai dihadapanku, beliau bertanya: \"Hai Jabir, apa kau melihat tempatku berdiri?\" aku menjawab: Ya, wahai Rasulullah.\" beliau bersabda: \"Pergilah kekedua pohon itu lalu potonglah dahan masing-masingnya lalu bawalah kemari. Bila kau telah berada ditempatku berdiri, lepaskan satu dahan dari sebelah kananmu dan dahan lain dari sebelah kirimu.\" Jabir berkata: Aku berdiri lalu aku mengambil batu, aku memecahnya lalu aku menajamkannya hingga tajam, setelah aku aku mendatangi kedua pohon itu, aku potong dahan masing-masing dari kedua pohon itu. Aku kembali dengan menyeretnya hingga aku berdiri ditempat Rasulullah Shallallahu 'alaihi wa Salam berdiri. Aku melepas satu dahan dari sebelah kananku dan satu dahan lain dari sebelah kirimu, setelah itu aku menemui Rasulullah Shallallahu 'alaihi wa Salam, aku berkata: Aku sudah melakukannya wahai Rasulullah, lalu untuk apa itu? Beliau menjawab: \"Aku melintasi dua kuburan yang (penghuninya) tengah diadzab, dengan syafaatku, aku ingin meringankan keduanya selama kedua dahan itu masih basah.\" Lalu kami mendatangi tentara kemudian Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hai Jabir, serukan air wudhu!\" aku berkata: \"Air wudhu, air wudhu, air wudhu.\" Aku berkata: Wahai Rasulullah, aku tidak menemukan setetes air pun di kafilah. Ada seorang Anshar mendinginkan air untuk Rasulullah Shallallahu 'alaihi wa Salam dalam wadah miliknya yang telah kering di atas kayu-kayu gantungan wadah lalu beliau bersabda kepadaku: \"Pergilah ke fulan bin fulan Al Anshari lalu lihatlah apakah di wadahnya ada sedikit (air).\" Aku pergi menghampirinya lalu aku melihat wadahnya, aku tidak menemukan apa pun selain setetes air di ujung wadahnya, andai aku menuangnya tentu akan mengering. Setelah itu aku mendatangi Rasulullah Shallallahu 'alaihi wa Salam, aku berkata: Wahai Rasulullah, tidak menemuan kecuali hanya setetes air yang ada di ujung wadah, andai aku menuangnya tentu akan mengering. Beliau bersabda: \"Pergilah lalu bawalah kemari.\" Aku membawanya lalu beliau mengambilnya dengan tangan beliau. Beliau mengucapkan kata-kata yang tidak aku ketahui apa itu lalu beliau meraba dengan kedua tangan beliau, setelah itu beliau memberikannya padaku, beliau bersabda: \"Hai Jabir, serukan bejana besar.\" Aku menyerukan: Bejana besar, wahai kafilah. Lalu aku membawanya lalu aku letakkan di hadapan Rasulullah Shallallahu 'alaihi wa Salam, beliau mengisyaratkan ke bejana dengan tangan beliau seperti ini -Jabir membentangkan tangan lalu merentangkan jari-jarinya lalu diletakkan di dasar bejana. Beliau bersabda: \"Ambillah, hai Jabir lalu tuangankan padaku dan ucapkan: 'Bismillaah.\" Aku menuangkannya untuk beliau dan aku ucapkan: Bismillaah. Aku melihat air memancar diantara jari-jari Rasulullah Shallallahu 'alaihi wa Salam lalu bejana besar itu memancarkan air dan memutar hingga penuh, setelah itu beliau bersabda: \"Hai Jabir, serukan siapa yang butuh air.\" Jabir berkata: Orang-orang datang lalu minum hingga puas. Lalu aku berkata: Masih adakah yang memerlukan air? Lalu Rasulullah Shallallahu 'alaihi wa Salam mengangkat tangan beliau dari bejana besar itu dalam keadaan penuh air. Orang-orang mengeluh lapar kepada Rasulullah Shallallahu 'alaihi wa Salam lalu beliau bersabda: \"Semoga Allah memberi kalian makan.\" lalu kami pergi ke tepi pantai, air laut pasang lalu mementalkan seekor ikan lalu kami nyalakan api di sebelahnya, kami memasaknya dan memanggangnya lalu kami makan hingga kenyang. Jabir berkata: Aku, fulan dan fulan -ia menghitung hingga lima orang- memasuki tulang matanya, tidak seorang pun melihat kami hingga kami keluar. Kami mengambil salah satu alisnya kemudian kami melengkungkannya, setelah itu kami memanggil orang terbesar dalam kafilah, unta terbesar dalam kafilah dan pembonceng terbesar dalam kafilah, ia masuk dibawahnya tanpa menundukkan kepala."},"4909":{"ar":"حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُاجَاءَ أَبُو بَكْرٍ الصِّدِّيقُ إِلَى أَبِي فِي مَنْزِلِهِ فَاشْتَرَى مِنْهُ رَحْلًا فَقَالَ لِعَازِبٍ ابْعَثْ مَعِيَ ابْنَكَ يَحْمِلْهُ مَعِي إِلَى مَنْزِلِي فَقَالَ لِي أَبِي احْمِلْهُ فَحَمَلْتُهُ وَخَرَجَ أَبِي مَعَهُ يَنْتَقِدُ ثَمَنَهُ فَقَالَ لَهُ أَبِي يَا أَبَا بَكْرٍ حَدِّثْنِي كَيْفَ صَنَعْتُمَا لَيْلَةَ سَرَيْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ أَسْرَيْنَا لَيْلَتَنَا كُلَّهَا حَتَّى قَامَ قَائِمُ الظَّهِيرَةِ وَخَلَا الطَّرِيقُ فَلَا يَمُرُّ فِيهِ أَحَدٌ حَتَّى رُفِعَتْ لَنَا صَخْرَةٌ طَوِيلَةٌ لَهَا ظِلٌّ لَمْ تَأْتِ عَلَيْهِ الشَّمْسُ بَعْدُ فَنَزَلْنَا عِنْدَهَا فَأَتَيْتُ الصَّخْرَةَ فَسَوَّيْتُ بِيَدِي مَكَانًا يَنَامُ فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ظِلِّهَا ثُمَّ بَسَطْتُ عَلَيْهِ فَرْوَةً ثُمَّ قُلْتُ نَمْ يَا رَسُولَ اللَّهِ وَأَنَا أَنْفُضُ لَكَ مَا حَوْلَكَ فَنَامَ وَخَرَجْتُ أَنْفُضُ مَا حَوْلَهُ فَإِذَا أَنَا بِرَاعِي غَنَمٍ مُقْبِلٍ بِغَنَمِهِ إِلَى الصَّخْرَةِ يُرِيدُ مِنْهَا الَّذِي أَرَدْنَا فَلَقِيتُهُ فَقُلْتُ لِمَنْ أَنْتَ يَا غُلَامُ فَقَالَ لِرَجُلٍ مِنْ أَهْلِ الْمَدِينَةِ قُلْتُ أَفِي غَنَمِكَ لَبَنٌ قَالَ نَعَمْ قُلْتُ أَفَتَحْلُبُ لِي قَالَ نَعَمْ فَأَخَذَ شَاةً فَقُلْتُ لَهُ انْفُضْ الضَّرْعَ مِنْ الشَّعَرِ وَالتُّرَابِ وَالْقَذَى قَالَ فَرَأَيْتُ الْبَرَاءَ يَضْرِبُ بِيَدِهِ عَلَى الْأُخْرَى يَنْفُضُ فَحَلَبَ لِي فِي قَعْبٍ مَعَهُ كُثْبَةً مِنْ لَبَنٍ قَالَ وَمَعِي إِدَاوَةٌ أَرْتَوِي فِيهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَشْرَبَ مِنْهَا وَيَتَوَضَّأَ قَالَ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَرِهْتُ أَنْ أُوقِظَهُ مِنْ نَوْمِهِ فَوَافَقْتُهُ اسْتَيْقَظَ فَصَبَبْتُ عَلَى اللَّبَنِ مِنْ الْمَاءِ حَتَّى بَرَدَ أَسْفَلُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ اشْرَبْ مِنْ هَذَا اللَّبَنِ قَالَ فَشَرِبَ حَتَّى رَضِيتُ ثُمَّ قَالَ أَلَمْ يَأْنِ لِلرَّحِيلِ قُلْتُ بَلَى قَالَ فَارْتَحَلْنَا بَعْدَمَا زَالَتْ الشَّمْسُ وَاتَّبَعَنَا سُرَاقَةُ بْنُ مَالِكٍ قَالَ وَنَحْنُ فِي جَلَدٍ مِنْ الْأَرْضِ فَقُلْتُ يَا رَسُولَ اللَّهِ أُتِينَا فَقَالَ لَا تَحْزَنْ إِنَّ اللَّهَ مَعَنَا فَدَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَارْتَطَمَتْ فَرَسُهُ إِلَى بَطْنِهَا أُرَى فَقَالَ إِنِّي قَدْ عَلِمْتُ أَنَّكُمَا قَدْ دَعَوْتُمَا عَلَيَّ فَادْعُوَا لِي فَاللَّهُ لَكُمَا أَنْ أَرُدَّ عَنْكُمَا الطَّلَبَ فَدَعَا اللَّهَ فَنَجَا فَرَجَعَ لَا يَلْقَى أَحَدًا إِلَّا قَالَ قَدْ كَفَيْتُكُمْ مَا هَاهُنَا فَلَا يَلْقَى أَحَدًا إِلَّا رَدَّهُ قَالَ وَوَفَى لَنَاو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ ح و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ كِلَاهُمَا عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ اشْتَرَى أَبُو بَكْرٍ مِنْ أَبِي رَحْلًا بِثَلَاثَةَ عَشَرَ دِرْهَمًا وَسَاقَ الْحَدِيثَ بِمَعْنَى حَدِيثِ زُهَيْرٍ عَنْ أَبِي إِسْحَقَ و قَالَ فِي حَدِيثِهِ مِنْ رِوَايَةِ عُثْمَانَ بْنِ عُمَرَ فَلَمَّا دَنَا دَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاخَ فَرَسُهُ فِي الْأَرْضِ إِلَى بَطْنِهِ وَوَثَبَ عَنْهُ وَقَالَ يَا مُحَمَّدُ قَدْ عَلِمْتُ أَنَّ هَذَا عَمَلُكَ فَادْعُ اللَّهَ أَنْ يُخَلِّصَنِي مِمَّا أَنَا فِيهِ وَلَكَ عَلَيَّ لَأُعَمِّيَنَّ عَلَى مَنْ وَرَائِي وَهَذِهِ كِنَانَتِي فَخُذْ سَهْمًا مِنْهَا فَإِنَّكَ سَتَمُرُّ عَلَى إِبِلِي وَغِلْمَانِي بِمَكَانِ كَذَا وَكَذَا فَخُذْ مِنْهَا حَاجَتَكَ قَالَ لَا حَاجَةَ لِي فِي إِبِلِكَ فَقَدِمْنَا الْمَدِينَةَ لَيْلًا فَتَنَازَعُوا أَيُّهُمْ يَنْزِلُ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْزِلُ عَلَى بَنِي النَّجَّارِ أَخْوَالِ عَبْدِ الْمُطَّلِبِ أُكْرِمُهُمْ بِذَلِكَ فَصَعِدَ الرِّجَالُ وَالنِّسَاءُ فَوْقَ الْبُيُوتِ وَتَفَرَّقَ الْغِلْمَانُ وَالْخَدَمُ فِي الطُّرُقِ يُنَادُونَ يَا مُحَمَّدُ يَا رَسُولَ اللَّهِ يَا مُحَمَّدُ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] berkata: Aku mendengar [Al Bara` bin Azib] berkata: Abu Bakar Ash Shiddiq mendatangi ayahku di kediamannya lalu Abu Bakar membeli seekor hewan tunggangan, kemudian ia bekata kepada Azib: Utuslah putramu bersamaku untuk membawanya ke rumahku. Ayahku berkata padaku: Bawalah. Aku membawanya dan ayahku keluar bersamanya untuk membayar harganya. Ayahku berkata padanya: Hai [Abu Bakar], ceritakan padaku, apa yang kalian berdua lakukan dimalam saat kau berjalan bersama Rasulullah Shallallahu 'alaihi wa Salam? Abu Bakar berkata: Ya. Kami berjalan sepanjang malam hingga tengah siang. Jalanan sepi dan tidak ada seorang pun lewat hingga batu besar diangkat untuk kami, batu itu menaungi dan tidak terkena (sinar) matahari setelahnya. Kami singgah didekatnya lalu kami mendekati batu itu. Dengan tanganku, aku meratakan tempat untuk dipakai nabi Shallallahu 'alaihi wa Salam tidur di bawah naungan batu itu lalu au bentangkan pakaian dari bulu binatang diatasnya, aku katakan: Tidurlah, wahai Rasulullah, aku akan mengawasi disekitar Tuan untuk Tuan. Beliau pun tidur lalu aku pergi mengawasi sekitar beliau. Ternyata ada seorang penggembala kambing yang datang dengan membawa kambing-kambingnya ke batu besar, ia ingin berteduh seperti halnya kami. Aku bertanya: Kau milik siapa hai budak? Ia menjawab: Milik seseorang dari penduduk Madinah. Aku bertanya: Apa ada susu dikambingmu? Ia menjawab: Ya. Aku bertanya: Maukah kau memerah untukku? Ia menjawab: Ya. Ia mengambil sesekor kambing lalu membersihkan kantung susu dari bulu, tanah dan kotoran -Ia (Abu Ishaq) berkata: Aku melihat Al Bara` memukulkan tangannya pada tangan sebelahnya seraya membersihkan- lalu ia memerah untukku dalam gelas yang ada sedikit susunya. Abu Bakar berkata: Aku membawa wadah tempat nabi Shallallahu 'alaihi wa Salam minum dan wudhu. Ia berkata: Lalu aku mendatangi nabi Shallallahu 'alaihi wa Salam dan aku tidak membangunkan beliau, ternyata saat itu tepat beliau bangun lalu aku tungankan air ke susu hingga bagian bawahnya mendingin, kemudian aku berkata: Wahai Rasulullah, minumlah susu ini. Beliau minum hingga aku senang. Setelah itu beliau bersabda: \"Bukankah sudah waktunya pergi.\" Aku menyahut: Betul. Kami lalu pergi setelah matahari condong ke barat, sementara itu Suraqah bin Malik mengikuti kami saat kami berada di tanah tandus. Aku berkata: Wahai Rasulullah, kita didatangi. Beliau bersabda: \"Jangan bersedih, sesungguhnya Allah bersama kita.\" Lalu Rasulullah Shallallahu 'alaihi wa Salam mendoakan keburukan padanya hingga kudanya jatuh ke lumpur hingga sampai perut, lalu ia berkata: Aku tahu kalian berdua mendoakan keburukan padaku, sekarang berdoalah kepada Allah untukku, demi Allah aku akan akan mengabulkan permintaan kalian berdua. Lalu Allah berdoa kemudian Suraqah selamat lalu kembali. Tidaklah ia menemui seseorang melainkan berkata: Aku sudah mencukupi kalian, ia (Rasulullah Shallallahu 'alaihi wa Salam) tidak ada disini. Tidaklah ia menemui seorang pun melainkan mengembalikannya. Abu Bakar berkata: Ia menepati janjinya untuk kami. Telah menceritakannya kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Utsman bin Umar]. Telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [An Nadhr bin Syumail] keduanya dari [Isra`il bin Abu Ishaq] dari [Al Bara`] berkata: Abu Bakar membeli seekor hewan tunggangan dari ayahku sebesar tigabelas dirham, iamenyebut hadits dengan makna hadits Zuhair dari Abu Ishaq, dan ia menyebutkan dalam haditsnya dari Rasulullah Utsman bin Umar: Saat Suraqah bin Malik mendekat, Rasulullah Shallallahu 'alaihi wa Salam mendoakannya lalu kudanya terbenam ke dalam tanah hingga perutnya lalu Suraqah melompat dan berkata: Hai Muhammad, aku tahu ini adalah perbuatanmu, berdoalah kepada Allah untuk melepaskanku dari yang aku alami, dan untukmu aku akan membutakan orang yang ada dibelakangku. Ini sarung panahku, ambillah satu panah karena kau akan melintasi untaku dan budak-budakku ditempat ini dan ini, silahkan kau ambil yang kau perlukan. Beliau bersabda: \"Aku tidak memerlukan untamu.\" Kami tiga di Madinah pada malam hari lalu mereka berebutan siapa yang mempersinggahkan Rasulullah Shallallahu 'alaihi wa Salam. Beliau bersabda: \"Singgahlah di bani Najjar, paman-paman Abdul Muthallib, aku memuliakan mereka karena hal itu.\" Kaum lelaki dan wanita naik di atas rumah, anak-anak dan para pelayan menyebar di jalanan, mereka memanggil-manggil: Wahai Muhammad, wahai Rasulullah, wahai Muhammad, wahai Rasulullah."},"4910":{"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدِ بْنِ بُكَيْرٍ النَّاقِدُ وَالْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ حَدَّثَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ يَعْنُونَ ابْنَ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ وَهُوَ ابْنُ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ اللَّهَ عَزَّ وَجَلَّ تَابَعَ الْوَحْيَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ وَفَاتِهِ حَتَّى تُوُفِّيَ وَأَكْثَرُ مَا كَانَ الْوَحْيُ يَوْمَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Amru bin Muhammad bin Bukair An Naqid], [Al Hasan bin Ali Al Hulwani] dan [Abdu bin Humaid] berkata Abdu: telah menceritakan kepadaku, sementara yang lain berkata: Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih bin Kaisan] dari [Ibnu Syihab] berkata: Telah mengkhabarkan kepadaku [Anas bin Malik] bahwa Allah 'azza wajalla menyempurnakan wahyu atas Rasulullah Shallallahu 'alaihi wa Salam sebelum beliau wafat"},"4911":{"ar":"حَدَّثَنِي أَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَهُوَ ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍأَنَّ الْيَهُودَ قَالُوا لِعُمَرَ إِنَّكُمْ تَقْرَءُونَ آيَةً لَوْ أُنْزِلَتْ فِينَا لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ حَيْثُ أُنْزِلَتْ وَأَيَّ يَوْمٍ أُنْزِلَتْ وَأَيْنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أُنْزِلَتْ أُنْزِلَتْ بِعَرَفَةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفٌ بِعَرَفَةَقَالَ سُفْيَانُ أَشُكُّ كَانَ يَوْمَ جُمُعَةٍ أَمْ لَا يَعْنِي{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي }","id":"Telah menceritakan kepadaku [Abu Khaitsamah bin Harb] dan [Muhammad bin Al Mutsanna], teks milik Ibnu Al Mutsanna, keduanya berkata: Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thariq bin Syihab], orang-orang Yahudi berkata kepada [Umar]: Sesungguhnya kalian membaca suatu ayat yang seandainya diturunkan pada kami pasti kami jadikan hari itu sebagai hari raya: \"Sesungguhnya aku tahu saat ayat itu turun, pada hari apa ayat itu turun dan dimana Rasulullah Shallallahu 'alaihi wa Salam saat ayat itu turun. Ayat itu turun di Arafah saat Rasulullah Shallallahu 'alaihi wa Salam wuquf di Arafah. Sufyan berkata: Aku ragu apakah hari jum'at ataukah tidak, maksudnya: \"Pada hari ini telah Kusempurnakan untuk kamu agamamu dan telah Ku-cukupkan kepadamu nikmatKu.\" (Al Maa`idah: 3) "},"4912":{"ar":"و حَدَّثَنِي عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عُمَيْسٍ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَجَاءَ رَجُلٌ مِنْ الْيَهُودِ إِلَى عُمَرَ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ آيَةٌ فِي كِتَابِكُمْ تَقْرَءُونَهَا لَوْ عَلَيْنَا نَزَلَتْ مَعْشَرَ الْيَهُودِ لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا قَالَ وَأَيُّ آيَةٍ قَالَ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ الْيَوْمَ الَّذِي نَزَلَتْ فِيهِ وَالْمَكَانَ الَّذِي نَزَلَتْ فِيهِ نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ فِي يَوْمِ جُمُعَةٍ","id":"Telah menceritakan kepadaku [Abdu bin Humaid] telah mengkhabarkan kepada kami [Ja'far bin Aun] telah mengkhabarkan kepada kami [Abu Umais] dari [Qais bin Muslim] dari [Thariq bin Syihab] berkata: Seorang Yahudi mendatangi [Umar] lalu berkata: Wahai Amirul Mu`minin, ada satu ayat didalam kitab kalian yang kalian baca, andai ayat itu turun pada kami kaum Yahudi, pasti kami menjadikan hari itu sebagai hari. Umar bertanya: Ayat apa? Ia menjawab: \"Pada hari Ini telah Ku-sempurnakan untuk kamu agamamu, dan telah Ku-cukupkan kepadamu nikmatKu, dan telah Ku-ridhai Islam itu jadi agama bagimu.\" (Al Maa`idah: 3) Umar berkata: Sesungguhnya aku tahu hari dan tempat ayat ini diturunkan, ayat itu turun pada Rasulullah Shallallahu 'alaihi wa Salam di Arafah pada hari jum'at."},"4913":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ أَحْمَدُ بْنُ عَمْرِو بْنِ سَرْحٍ وَحَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ قَالَ أَبُو الطَّاهِرِ حَدَّثَنَا و قَالَ حَرْمَلَةُ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ قَوْلِ اللَّهِ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ مَثْنَى وَثُلَاثَ وَرُبَاعَ }قَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا تُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيَهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ وَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فِيهِنَّ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ وَمَا يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ فِي يَتَامَى النِّسَاءِ اللَّاتِي لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ وَالَّذِي ذَكَرَ اللَّهُ تَعَالَى أَنَّهُ{ يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ }الْآيَةُ الْأُولَى الَّتِي قَالَ اللَّهُ فِيهَا{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ فِي الْآيَةِ الْأُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }رَغْبَةَ أَحَدِكُمْ عَنْ الْيَتِيمَةِ الَّتِي تَكُونُ فِي حَجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا وَجَمَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّو حَدَّثَنَا الْحَسَنُ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ يَعْقُوبَ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَ عَنْ قَوْلِ اللَّهِ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى }وَسَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ يُونُسَ عَنْ الزُّهْرِيِّ وَزَادَ فِي آخِرِهِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ إِذَا كُنَّ قَلِيلَاتِ الْمَالِ وَالْجَمَالِ","id":"Telah menceritakan kepadaku [Abu Ath Thahir Ahmad bin Amru bin Sarh] dan [Harmalah bin Yahya At Tujibi] berkata Abu Ath Thahir: Telah menceritakan kepada kami, sedangkan Harmalah berkata: Telah mengkhabarkan kepada kami [Ibnu Wahab] telah mengkhabarkan kepadaku [Yunus] dari [Ibnu syihab] telah mengkhabarkan kepadaku [Urwah bin Zubair] bahwa ia bertanya kepada [Aisyah] tentang firman Allah: \"Dan jika kalian khawatir tidak berlaku adil dalam masalah anak-anak yatim maka nikahilah (wanita-wanita) yang baik bagi kalian dua, atau tiga, atau empat.\" (An Nisaa`: 3) Aisyah berkata: Wahai keponakanku, itu maksudnya adalah seorang anak wanita yatim yang berada di bawah pengawasan walinya (dan) ia ikut (dalam tanggungan) hartanya lalu ia sang wali terkagum dengan harta dan kecantikan anak yatim itu kemudian sang wali ingin menikahinya dengan (niatan) tidak adil di dalam maharnya agar ia memberikannya sesuatu yang semisal dengan apa yang diberikan kepada selain dia, lalu mereka dilarang untuk menikahi mereka kecuali untuk berlaku adil bagi mereka dan agar mereka menyampaikan mahar yang lebih tinggi dan mereka diperintahkan untuk menikahi wanita-wanita yang baik bagi mereka selain anak-anak yatim. Urwah berkata: Aisyah berkata: Kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah ayat ini tentang mereka (anak-anak yatim perempuan) lalu Allah 'azza wajalla menurunkan ayat: \"Dan mereka meminta fatwa kepadamu tentang wanita-wanita katakanlah: 'Allah yang berfatwa kepada kalian tentang mereka dan apa yang dibacakan atas kalian dalam Al Kitab tentang wanita-wanita yatim yang kalian tidak memberikan kepada mereka apa yang telah ditetapkan bagi mereka sedang kalian ingin menikahi mereka.\" (An Nisaa`: 127) Aisyah berkata: Dan yang disebutkan oleh Allah Ta'ala bahwasanya itu adalah yang dibacakan atas kalian dalam al-Qur'an pada ayat sebelumnya yang menyebutkan firman Allah: \"Dan jika kalian khawatir untuk tidak berbuat adil dalam masalah anak-anak yatim maka nikahilah wanita-wanita yang baik bagi kalian.\" (An Nisaa`: 3) Aisyah berkata: Dan firman Allah dalam ayat yang lain: \"Sedang kalian ingin menikahi mereka, \" (An Nisaa`: 127) adalah ketidaksukaan salah seorang di antara kalian terhadap wanita yatim yang berada di bawah pengawasan kalian sedang ia sedikit hartanya dan kurang cantik. Karena itu, mereka dilarang menikahi karena apa yang mereka sukai dari harta dan kecantikan wanita-wanita yatim kecuali dengan keadilan karena ketidaksukaan mereka pada wanita-wanita yatim. Telah menceritakan kepada kami [Al Hasan Al Hulwani] dan [Abdu bin Humaid] semuanya dari [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah mengkhabarkan kepadaku [Urwah] bahwa ia bertanya kepada [Aisyah] tentang firman Allah: \"Dan jika kalian khawatir untuk tidak berbuat adil terhadap wanita-wanita yatim, \" (An Nisaa`: 3) ia menyebutkan hadits tersebut seperti hadits Yunus dari Az Zuhri dan ia menambahkan di akhirnya: Karena ketidaksukaan mereka terhadap wanita-wanita yatim jika sedikit hartanya dan kurang cantik"},"4914":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قَوْله{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى }قَالَتْ أُنْزِلَتْ فِي الرَّجُلِ تَكُونُ لَهُ الْيَتِيمَةُ وَهُوَ وَلِيُّهَا وَوَارِثُهَا وَلَهَا مَالٌ وَلَيْسَ لَهَا أَحَدٌ يُخَاصِمُ دُونَهَا فَلَا يُنْكِحُهَا لِمَالِهَا فَيَضُرُّ بِهَا وَيُسِيءُ صُحْبَتَهَا فَقَالَ{ إِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }يَقُولُ مَا أَحْلَلْتُ لَكُمْ وَدَعْ هَذِهِ الَّتِي تَضُرُّ بِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya bekata: Telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Aisyah] tentang firman Allah: \"Dan jika kalian khawatir utnuk tidak berbuat adil terhadap wanita-wanita yatim, \" (An Nisaa`: 3) Ia berkata: (Ayat ini) turun berkenaan dengan seseorang, ia memiliki seorang wanita yatim, ia walinya dan ahli warisnya. Wanita yatim itu memiliki harta, ia tidak memiliki orang lain yang menyainginya selain dia. Ia tidak menikahinya karena hartanya sehingga itu akan membahayakannya dan memperburuk perawatannya. Lalu ia berkata: \"Dan jika kalian khawatir untuk tidak berbuat adil dalam masalah anak-anak yatim maka nikahilah wanita-wanita yang baik bagi kalian.\" (An Nisaa`: 3) Ia berkata: Aku tidak menghalalkan untuk kalian dan tinggalkan wanita ini yang berbahaya karenanya."},"4915":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قَوْله{ يَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ }الْآيَةَ قَالَتْ هِيَ الْيَتِيمَةُ الَّتِي تَكُونُ عِنْدَ الرَّجُلِ لَعَلَّهَا أَنْ تَكُونَ قَدْ شَرِكَتْهُ فِي مَالِهِ حَتَّى فِي الْعَذْقِ فَيَرْغَبُ يَعْنِي أَنْ يَنْكِحَهَا وَيَكْرَهُ أَنْ يُنْكِحَهَا رَجُلًا فَيَشْرَكُهُ فِي مَالِهِ فَيَعْضِلُهَا","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] telah mengkhabarkan kepada kami [Hisyam] dari [ayahnya] dari [Aisyah] tentang firmanNya: \"Dan mereka minta fatwa kepadamu tentang para wanita. Katakanlah: \"Allah memberi fatwa kepadamu tentang mereka.\" (An Nisaa`: 127) Aisyah berkata: Ia wanita yatim yang ada pada seseorang, mungkin ia menyertakan lelaki itu dalam hartanya hingga dalam tandan anggur, lalu ia ingin menikahinya, ia tidak mau menikahkannya dengan lelaki lain sehingga akan disertakan dalam hartanya lalu ia menyusahkannya."},"4916":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قَوْله{ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }قَالَتْ أُنْزِلَتْ فِي وَالِي مَالِ الْيَتِيمِ الَّذِي يَقُومُ عَلَيْهِ وَيُصْلِحُهُ إِذَا كَانَ مُحْتَاجًا أَنْ يَأْكُلَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam] dari [ayahnya] [Aisyah] tentang firmanNya: \"Dan barangsiapa yang miskin, maka bolehlah ia makan harta itu menurut yang patut.\" (An Nisaa`: 6) Aisyah berkata: (ayat ini) turun tentang wali hartanya anak yatim yang menjaganya dan memperbaikinya, ia boleh makan darinya jika membutuhkan."},"4917":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ إِذْ جَاءُوكُمْ مِنْ فَوْقِكُمْ وَمِنْ أَسْفَلَ مِنْكُمْ وَإِذْ زَاغَتْ الْأَبْصَارُ وَبَلَغَتْ الْقُلُوبُ الْحَنَاجِرَ }قَالَتْ كَانَ ذَلِكَ يَوْمَ الْخَنْدَقِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam] dari [ayahnya] dari [Aisyah] tentang firman Allah 'azza wajalla: \"(yaitu) ketika mereka datang kepadamu dari atas dan dari bawahmu, dan ketika tidak tetap lagi penglihatan(mu) dan hatimu naik menyesak sampai ke tenggorokan.\" (Al Ahzaab: 10) Ia berkata: Itu adalah perang khandaq."},"4918":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }الْآيَةَ قَالَتْ أُنْزِلَتْ فِي الْمَرْأَةِ تَكُونُ عِنْدَ الرَّجُلِ فَتَطُولُ صُحْبَتُهَا فَيُرِيدُ طَلَاقَهَا فَتَقُولُ لَا تُطَلِّقْنِي وَأَمْسِكْنِي وَأَنْتَ فِي حِلٍّ مِنِّي فَنَزَلَتْ هَذِهِ الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Aisyah]: \"Dan jika seorang wanita khawatir akan nusyuz atau sikap tidak acuh dari suaminya.\" (An Nisaa`: 128) Ia berkata: (ayat ini) turun berkenaan tentang wanita yang telah lama hidup bersama suaminya lalu ia (sang suami) ingin mencerainya, kemudian ia (sang istri) berkata: Janganlah engkau cerai daku dan pertahankan diriku dan engkau terbebas dariku, lalu turunlah ayat ini."},"4919":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ نَزَلَتْ فِي الْمَرْأَةِ تَكُونُ عِنْدَ الرَّجُلِ فَلَعَلَّهُ أَنْ لَا يَسْتَكْثِرَ مِنْهَا وَتَكُونُ لَهَا صُحْبَةٌ وَوَلَدٌ فَتَكْرَهُ أَنْ يُفَارِقَهَا فَتَقُولُ لَهُ أَنْتَ فِي حِلٍّ مِنْ شَأْنِي","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Aisyah] tentang firman Allah 'azza wajalla: \"Dan jika seorang wanita khawatir akan nusyuz atau sikap tidak acuh dari suaminya.\" (An Nisaa`: 128) Ia berkata: (ayat ini) turun berkenaan tentang wanita yang hidup bersama suaminya, mungkin ia tidak mau memperbanyak anak darinya, lalu ia (sang suami) ingin mencerainya, ia telah lama menemaninya dan telah punya anak, ia tidak ingin suaminya mencerainya lalu berkata: Engkau terbebas dari urusanku."},"4920":{"ar":"حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ أَنَّ ابْنَ مَسْعُودٍ قَالَمَا كَانَ بَيْنَ إِسْلَامِنَا وَبَيْنَ أَنْ عَاتَبَنَا اللَّهُ بِهَذِهِ الْآيَةِ{ أَلَمْ يَأْنِ لِلَّذِينَ آمَنُوا أَنْ تَخْشَعَ قُلُوبُهُمْ لِذِكْرِ اللَّهِ }إِلَّا أَرْبَعُ سِنِينَ","id":"Telah menceritakan kepadaku [Yunus bin Abdula'la Ash Shadafi] telah mengkhabarkan kepada kami [Abdulah bin Wahab] telah mengkhabarkan kepadaku [Amru bin Al Harits] dari [Sa'id bin Abu Hilal] dari [Aun bin Abdullah] dari [ayahnya] bahwasanya [Ibnu Mas'ud] berkata: Tidak ada selang waktu antara Islamnya kami dan ketika Allah menegur kami dengan ayat ini: \"Belumkah datang waktunya bagi orang-orang yang beriman, untuk tunduk hati mereka mengingat Allah.\" (Al Hadiid: 16) kecuali hanya empat tahun."},"4921":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ وَاللَّفْظُ لَهُ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ الْمَرْأَةُ تَطُوفُ بِالْبَيْتِ وَهِيَ عُرْيَانَةٌ فَتَقُولُ مَنْ يُعِيرُنِي تِطْوَافًا تَجْعَلُهُ عَلَى فَرْجِهَا وَتَقُولُ الْيَوْمَ يَبْدُو بَعْضُهُ أَوْ كُلُّهُفَمَا بَدَا مِنْهُ فَلَا أُحِلُّهُفَنَزَلَتْ هَذِهِ الْآيَةُ{ خُذُوا زِينَتَكُمْ عِنْدَ كُلِّ مَسْجِدٍ }","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far]. Telah menceritakan kepadaku [Abu Bakr bin Nafi'] teks miliknya, telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata: Dahulu wanita berthawaf di baitullah dalam keadaan telanjang lalu ia berkata: Siapa yang meminjamkan kepadaku baju yang ia kenakan di atas kemaluannya? dan saat ini ia berkata: Telah nampak sebagian atau seluruhnya, maka apa yang nampak darinya tidaklah aku menghalalkannya. Lalu turunlah ayat ini: \"Ambillah oleh kalian pakaian dan perhiasan kalian setiap memasuki masjid.\" (Al A'raaf: 31) "},"4922":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ وَاللَّفْظُ لِأَبِي كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَكَانَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ يَقُولُ لِجَارِيَةٍ لَهُ اذْهَبِي فَابْغِينَا شَيْئًا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُكْرِهُوا فَتَيَاتِكُمْ عَلَى الْبِغَاءِ إِنْ أَرَدْنَ تَحَصُّنًا لِتَبْتَغُوا عَرَضَ الْحَيَاةِ الدُّنْيَا وَمَنْ يُكْرِهْهُنَّ فَإِنَّ اللَّهَ مِنْ بَعْدِ إِكْرَاهِهِنَّ }لَهُنَّ{ غَفُورٌ رَحِيمٌ }","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] dari [Abu Mu'awiyah], teks milik Abu Kuraib, telah menceritakan kepada kami Abu Mu'awiyuah telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] berkata: Dahulu Abdullah bin Ubai bin Salul berkata kepada budak wanitanya: Pergilah dan melacurlah untuk kami. Maka Allah 'azza wajalla menurunkan ayat: \"Dan janganlah kamu paksa budak-budak wanitamu untuk melakukan pelacuran, sedang mereka sendiri mengingini kesucian, karena kamu hendak mencari keuntungan duniawi. dan barangsiapa yang memaksa mereka, maka sesungguhnya Allah adalah Maha Pengampun lagi Maha Penyayang (kepada mereka) sesudah mereka dipaksa itu.\" (An Nuur: 33)"},"4923":{"ar":"و حَدَّثَنِي أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍأَنَّ جَارِيَةً لِعَبْدِ اللَّهِ بْنِ أُبَيٍّ ابْنِ سَلُولَ يُقَالُ لَهَا مُسَيْكَةُ وَأُخْرَى يُقَالُ لَهَا أُمَيْمَةُ فَكَانَ يُكْرِهُهُمَا عَلَى الزِّنَى فَشَكَتَا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُكْرِهُوا فَتَيَاتِكُمْ عَلَى الْبِغَاءِ إِلَى قَوْلِهِ غَفُورٌ رَحِيمٌ }","id":"Telah menceritakan kepadaku [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir], budak wanita milik Abdullah bin Ubai bin Salul bernama Musaikah, ada juga yang menyebut Umaimah, dipaksa berzina lalu ia melaporkan hal itu kepada nabi Shallallahu 'alaihi wa Salam kemudian Allah menurunkan: \"Dan janganlah kamu paksa budak-budak wanitamu untuk melakukan pelacuran\" sampai \"Maha Pengampun lagi Maha Penyayang (kepada mereka) sesudah mereka dipaksa itu.\" (An Nuur: 33) "},"4924":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِفِي قَوْلِهِ عَزَّ وَجَلَّ{ أُولَئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ أَيُّهُمْ أَقْرَبُ }قَالَ كَانَ نَفَرٌ مِنْ الْجِنِّ أَسْلَمُوا وَكَانُوا يُعْبَدُونَ فَبَقِيَ الَّذِينَ كَانُوا يَعْبُدُونَ عَلَى عِبَادَتِهِمْ وَقَدْ أَسْلَمَ النَّفَرُ مِنْ الْجِنِّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Al A'masy] dari [Ibrahim] dari [Abu Ma'mar] dari [Abdullah] tentang firmanNya 'azza wajalla: \"Mereka itulah orang-orang yang selalu berdoa dan mencari kepada Rabb mereka wasilah manakah di antara mereka yang lebih dekat.\" (Al Israa`: 57) ia berkata: Segolongan jin masuk Islam dan mereka disembah, mereka yang menyembah tetap berada dalam peribadatan mereka, sementara segolongan dari jin telah masuk Islam."},"4925":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ الْعَبْدِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ{ أُولَئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ }قَالَ كَانَ نَفَرٌ مِنْ الْإِنْسِ يَعْبُدُونَ نَفَرًا مِنْ الْجِنِّ فَأَسْلَمَ النَّفَرُ مِنْ الْجِنِّ وَاسْتَمْسَكَ الْإِنْسُ بِعِبَادَتِهِمْ فَنَزَلَتْ{ أُولَئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ }و حَدَّثَنِيهِ بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Nafi' Al Abdi] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abu Ma'mar] dari [Abdullah]: \"Mereka itulah orang-orang yang selalu berdoa dan mencari kepada Rabb mereka wasilah manakah di antara mereka yang lebih dekat.\" (Al Israa`: 57) Abdullah berkata: Segolongan manusia menyembah segolongan jin lalu segolongan jin itu masuk Islam sementara segolongan manusia tetap berpegang teguh pada peribadatan mereka, lalu turun ayat: \"Mereka itulah orang-orang yang selalu berdoa dan mencari kepada Rabb mereka wasilah manakah di antara mereka yang lebih dekat.\" (Al Israa`: 57) Telah menceritakannya kepadaku [Bisyr bin Khalid] telah mengkhabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dengan sanad ini."},"4926":{"ar":"و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي أَبِي حَدَّثَنَا حُسَيْنٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ{ أُولَئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ }قَالَ نَزَلَتْ فِي نَفَرٍ مِنْ الْعَرَبِ كَانُوا يَعْبُدُونَ نَفَرًا مِنْ الْجِنِّ فَأَسْلَمَ الْجِنِّيُّونَ وَالْإِنْسُ الَّذِينَ كَانُوا يَعْبُدُونَهُمْ لَا يَشْعُرُونَ فَنَزَلَتْ{ أُولَئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ }","id":"Telah menceritakan kepadaku [Hajjaj bin Asy Sya'ir] telah menceritakan kepada kami [Abdushshamad bin Abdulwarits] telah menceritakan kepadaku [ayahku] telah menceritakan kepada kami [Husain] dari [Qatadah] dari [Abdullah bin Ma'bad Az ZImmani] dari [Abdullah bin Utbah] dari [Abdullah bin Mas'ud]: \"Mereka itulah orang-orang yang selalu berdoa dan mencari kepada Rabb mereka wasilah.\" (Al Israa`: 57) Ia berkata: Turun berkenaan dengan segolongan orang arab, mereka menyembah sekelompok jin lalu para jin itu masuk Islam sementara orang-orangnya tetap menyembah mereka tanpa mereka sadari. Kemudian turun ayat: \"Mereka itulah orang-orang yang selalu berdoa dan mencari kepada Rabb mereka wasilah.\" (Al Israa`: 57) "},"4927":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُطِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عَبَّاسٍ سُورَةُ التَّوْبَةِ قَالَ آلتَّوْبَةِ قَالَ بَلْ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنْ لَا يَبْقَى مِنَّا أَحَدٌ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ تِلْكَ سُورَةُ بَدْرٍ قَالَ قُلْتُ فَالْحَشْرُ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","id":"Telah menceritakan kepadaku [Abdullah bin Muthi'] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] berkata: Saya berkata kepada [Ibnu 'Abbas]: Surat At Taubah, ia berkata: Apa At Taubah? Ia berkata: Bahkan ia adalah Al Fadhilah (yang menyibak rahasia orang-orang munafik, pent.) yang masih turun dan dari mereka dan dari mereka hingga mereka mengira tiada seorangpun dari kita yang masih tersisa kecuali telah disebutkan di dalamnya. Ia berkata: Aku berkata: Surat Al Anfaal, ia (Ibnu Abbas) berkata: Itu adalah surat perang Badar. Ia berkata: Lalu aku berkata: Surat Al Hasyr, ia (Ibnu Abbas) berkata: Ia turun berkenaan dengan Bani Nadhir."},"4928":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ أَبِي حَيَّانَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ قَالَخَطَبَ عُمَرُ عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ أَلَا وَإِنَّ الْخَمْرَ نَزَلَ تَحْرِيمُهَا يَوْمَ نَزَلَ وَهِيَ مِنْ خَمْسَةِ أَشْيَاءَ مِنْ الْحِنْطَةِ وَالشَّعِيرِ وَالتَّمْرِ وَالزَّبِيبِ وَالْعَسَلِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ وَثَلَاثَةُ أَشْيَاءَ وَدِدْتُ أَيُّهَا النَّاسُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَهِدَ إِلَيْنَا فِيهَا الْجَدُّ وَالْكَلَالَةُ وَأَبْوَابٌ مِنْ أَبْوَابِ الرِّبَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Abu Hayyan] dari [Asy Sya'bi] dari [Ibnu Umar] berkata: [Umar] berkhutbah di atas mimbar Rasulullah shallallahu 'alaihi wasallam, ia memuja dan memuji Allah kemudian berkata: Amma ba'du, sesungguhnya khamar itu telah turun pengharamannya saat turun waktu itu dan khamar terdiri lima hal; dari gandum, tepung, kurma, anggur, dan madu, Khamar adalah segala sesuatu yang menutupi akal. Ada tiga hal yang aku ingin (sampaikan) wahai para manusia: Rasulullah shallallahu 'alaihi wasallam telah mewasiatkan kepada kita; (warisan) kakek, kalalah (orang mati yang tidak meniggalkan anak maupun orang tua) dan sekian dari beberapa pintu riba."},"4929":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ إِدْرِيسَ حَدَّثَنَا أَبُو حَيَّانَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولَأَمَّا بَعْدُ أَيُّهَا النَّاسُ فَإِنَّهُ نَزَلَ تَحْرِيمُ الْخَمْرِ وَهِيَ مِنْ خَمْسَةٍ مِنْ الْعِنَبِ وَالتَّمْرِ وَالْعَسَلِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ وَثَلَاثٌ أَيُّهَا النَّاسُ وَدِدْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَهِدَ إِلَيْنَا فِيهِنَّ عَهْدًا نَنْتَهِي إِلَيْهِ الْجَدُّ وَالْكَلَالَةُ وَأَبْوَابٌ مِنْ أَبْوَابِ الرِّبَاو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ كِلَاهُمَا عَنْ أَبِي حَيَّانَ بِهَذَا الْإِسْنَادِ بِمِثْلِ حَدِيثِهِمَا غَيْرَ أَنَّ ابْنَ عُلَيَّةَ فِي حَدِيثِهِ الْعِنَبِ كَمَا قَالَ ابْنُ إِدْرِيسَ وَفِي حَدِيثِ عِيسَى الزَّبِيبِ كَمَا قَالَ ابْنُ مُسْهِرٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah mengkhabarkan kepada kami [Ibnu Idris] telah menceritakan kepada kami [Abu Hayyan] dari [Asy Sya'bi] dari [Ibnu Umar] berkata: Aku mendengar [Umar bin Al Khaththab] berkhutbah di atas mimbar Rasulullah Shallallahu 'alaihi wa Salam, ia berkata: Amma ba'du, sesungguhnya telah turun pengharaman khamar dan khamar terdiri lima hal; anggur kurma, madu, tepung dan gandum. Khamar adalah segala sesuatu yang menutupi akal. Ada tiga hal yang aku ingin (sampaikan) wahai para manusia: Rasulullah shallallahu 'alaihi wasallam telah mewasiatkan kepada kita yang harus kita perhatikan; (warisan) kakek, kalalah (orang mati yang tidak meniggalkan anak maupun orang tua) dan sekian dari beberapa pintu riba. Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin Ulaiyah]. Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengkhabarkan kepada kami [Isa bin Yunus] keduanya dari [Abu Hayyan] dengan snad ini seperti hadits mereka berdua, hanya saja Ibnu Ulaiyah menyebutkan dalam haditsnya: Anggur. Seperti yang dikatakan oleh Ibnu Idris, dan dalam hadits Isa disebutkan: Kismis, seperti yang dikatakan Ibnu Mushir."},"4930":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَسَمِعْتُ أَبَا ذَرٍّ يُقْسِمُ قَسَمًا إِنَّ { هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ } إِنَّهَا نَزَلَتْ فِي الَّذِينَ بَرَزُوا يَوْمَ بَدْرٍ حَمْزَةُ وَعَلِيٌّ وَعُبَيْدَةُ بْنُ الْحَارِثِ وَعُتْبَةُ وَشَيْبَةُ ابْنَا رَبِيعَةَ وَالْوَلِيدُ بْنُ عُتْبَةَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ جَمِيعًا عَنْ سُفْيَانَ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَ سَمِعْتُ أَبَا ذَرٍّ يُقْسِمُ لَنَزَلَتْ { هَذَانِ خَصْمَانِ } بِمِثْلِ حَدِيثِ هُشَيْمٍ","id":"Telah menceritakan kepada kami [Amru bin Zurarah] telah menceritakan kepada kami [Husyaim] dari [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin Ubad] berkata: Saya telah mendengar [Abu Dzar] benar-benar bersumpah: \"Inilah dua golongan (golongan mukmin dan golongan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka.\" (Al Hajj: 19) sesungguhnya ia turun berkenaan orang-orang yang berbaris di hari Badar: Hamzah, Ali, Ubaidah bin Harits, Utbah, Syaibah putra dari Rabi'ah dan Al Walid bin Utbah. Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'], dan telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman], semuanya dari [Sufyan] dari [Abu Hasyim] dari [Abu Majliz] dari [Qais bin Ubad] berkata: Saya telah mendengar [Abu Dzar] bersumpah, sungguh \"Inilah dua golongan (golongan mukmin dan golongan kafir) yang bertengkar.\" (Al Hajj: 19) seperti hadits Husyaim."}};
